def _secrets_selfheal() -> list:
    """secrets.bat 密钥自愈（06y）：hub 若未经 env_config.bat 启动链拉起（看门狗直拉/开发期
    Start-Process 裸启），环境里没有云端密钥 → deepseek 全 401 → 静默回落本地模型，
    对话质量降级且无人察觉（实测 401 刷屏 + 多语种验收恒红）。启动时兜底：解析 secrets.bat
    的 set 行，把「环境缺失」的变量补进 os.environ——只补缺不覆盖（正规启动链注入的值优先），
    值不落日志。返回补上的变量名列表。"""
    healed = []
    try:
        sf = Path(_BASE) / "secrets.bat"
        if not sf.exists():
            return healed
        for ln in sf.read_text(encoding="utf-8", errors="replace").splitlines():
            m = re.match(r'^\s*set\s+"?([A-Za-z_][A-Za-z0-9_]*)=([^"]*)"?\s*$', ln)
            if not m:
                continue
            k, v = m.group(1), m.group(2).strip()
            if v and not os.environ.get(k):
                os.environ[k] = v
                healed.append(k)
    except Exception:
        pass
    return healed


_SECRETS_HEALED = _secrets_selfheal()

