_log_handler = logging.handlers.RotatingFileHandler(
    _LOG_DIR / "avatar_hub.log", maxBytes=1_000_000, backupCount=5, encoding='utf-8'
)
_log_handler.setFormatter(logging.Formatter(
    "%(asctime)s [%(levelname)s] [%(request_id)s] %(message)s", datefmt="%Y-%m-%d %H:%M:%S"
))
_request_id_ctx: ContextVar[str] = ContextVar('request_id', default='-')
class _RidFilter(logging.Filter):
    def filter(self, r: logging.LogRecord) -> bool:
        r.request_id = _request_id_ctx.get('-')
        return True
_log_handler.addFilter(_RidFilter())
_stream_handler = logging.StreamHandler()   # P5-4: 控制台日志也携带 request_id
_stream_handler.setFormatter(logging.Formatter(
    "%(asctime)s [%(levelname)s] [%(request_id)s] %(message)s", datefmt="%Y-%m-%d %H:%M:%S"
))
_stream_handler.addFilter(_RidFilter())

class _JsonlHandler(logging.Handler):
    """P8-4: 结构化 JSONL 日志，每行一个JSON对象，便于 Loki/ELK 接入"""
    def __init__(self, path: str):
        super().__init__()
        self._f = open(path, 'a', encoding='utf-8', buffering=1)  # line-buffered

    def emit(self, record: logging.LogRecord):
        try:
            self._f.write(json.dumps({
                "ts":         round(record.created, 3),
                "level":      record.levelname,
                "request_id": getattr(record, "request_id", "-"),
                "logger":     record.name,
                "msg":        record.getMessage(),
            }, ensure_ascii=False) + "\n")
        except Exception:
            pass

    def close(self):
        try: self._f.close()
        except Exception: pass
        super().close()

_jsonl_handler = _JsonlHandler(str(_LOG_DIR / "avatar_hub.jsonl"))
_jsonl_handler.setLevel(logging.INFO)
_jsonl_handler.addFilter(_RidFilter())

logging.basicConfig(level=logging.INFO, handlers=[_log_handler, _stream_handler, _jsonl_handler])
_logger = logging.getLogger("avatar_hub")

