# ── 子服务地址 ────────────────────────────────────────────────────
def _svc_url_list(key: str, default: str) -> list:
    """解析服务地址（支持多副本：逗号分隔→多卡 worker 池）。
    SVC_<KEY>=url1,url2 → 每个 url 一个 GPU 副本，Hub 按最少在途分发实现真并行。
    单值时退化为单副本（行为与改造前一致）。"""
    raw = os.environ.get("SVC_" + key.upper(), default)
    urls = [u.strip().rstrip("/") for u in raw.split(",") if u.strip()]
    return urls or [default.rstrip("/")]

def _svc_url(key: str, default: str) -> str:
    """服务地址支持环境变量覆盖：SVC_<KEY>=http://<远程机>:<端口>。
    用于三机分工：把 TTS/STT/faceswap 等指向 4090 机器，5090 专注实时视频，消除单卡算力抢占。
    例：set SVC_FISH_TTS=http://192.168.1.50:7855 set SVC_STT=http://192.168.1.50:7854
    多副本(逗号分隔)时取第一个作主地址(管理/预热路径用)，并发分发见 _svc_lease。"""
    return _svc_url_list(key, default)[0]

