_FISH_COMPAT_TTS = {"fish_speech": "fish_tts", "qwen3_tts": "qwen3_tts"}

def _fish_compat_svc(engine: str) -> str:
    """fish-契约兼容引擎 → 其服务键；非兼容引擎返回 ""。"""
