# ── 换脸契约兼容引擎 → 服务键 + 平滑模式（单一真相，对齐 TTS 的 _FISH_COMPAT_TTS）──────
#   所有换脸引擎共用 faceswap_api 的 /faceswap 契约（{source_image,target_image,smooth_mode,...}），
#   仅「实际加载的 ONNX 模型」与「时序平滑模式」不同：
#     - inswapper      → 服务键 faceswap (默认 128 基线，motion 平滑)
#     - hyperswap_256  → 服务键 faceswap2(若已部署高清副本)否则回退 faceswap；flow 光流平滑
#   新增同契约引擎只需在此登记一行 + engine_registry 注册，Hub 各调用点零改动。
_FACESWAP_COMPAT = {
    "inswapper":     {"svc": "faceswap",  "smooth_mode": ""},
    "hyperswap_256": {"svc": "faceswap2", "smooth_mode": "flow"},
}

def _faceswap_resolve(engine: str = "", profile: dict | None = None) -> tuple[str, str, str]:
    """解析换脸引擎 → (引擎名, 服务键, 平滑模式)。
    优先级：显式 engine > profile.faceswap_engine > 默认 inswapper。
    单实例部署（未显式配 SVC_FACESWAP2）下，高清引擎共用默认 faceswap 服务——
    由该服务经 FACESWAP_MODEL 决定实际加载哪个 ONNX；仅当显式部署了高清副本才路由到 faceswap2。"""
    eng = (engine or (profile or {}).get("faceswap_engine", "") or "inswapper").strip()
    if eng not in _FACESWAP_COMPAT:
        eng = "inswapper"
    spec = _FACESWAP_COMPAT[eng]
    svc = spec["svc"]
    if svc == "faceswap2" and not os.environ.get("SVC_FACESWAP2"):
        svc = "faceswap"          # 未部署独立高清副本 → 回退默认换脸服务（绝不指向不可达端口）
    return eng, svc, spec.get("smooth_mode", "")

