# ── P-Conc5: 多卡 worker 池（每卡一副本，最少在途分发，故障副本短暂摘除）────────
# 重型逐句 GPU 阶段(fish_tts/emotion_tts/lipsync/latentsync)若配置了多个副本地址
# (SVC_<KEY>=url1,url2)，则 Hub 把并发请求散到不同副本=不同 GPU，实现真并行而非排队等同一张卡。
# 单副本时 pick 恒返回该地址、仅维护一个在途计数器，行为与改造前完全一致(零回归)。
_SVC_FAIL_THRESH   = int(os.environ.get("SVC_FAIL_THRESH", "2"))      # 连续失败几次摘除
_SVC_FAIL_COOLDOWN = float(os.environ.get("SVC_FAIL_COOLDOWN", "15")) # 摘除冷却秒数
_SVC_PROBE_SEC     = float(os.environ.get("SVC_PROBE_SEC", "10"))     # 主动探活间隔(s)；0=关
# P-Harden1(2026-07-07 事故): 「挂死副本」检测——副本 /health 正常但工作请求永不归还
#   (GPU worker 死锁)时，探活发现不了，池会持续把新请求喂给黑洞。判据改用在途请求年龄：
#   最老在途超过该秒数 → 视为挂死，pick 规避 + healthy_size 不计(auto K 随之收缩)。
#   请求最终超时/完成归还后年龄自然回落 → 自动解除。0=关闭该检测。
_SVC_HUNG_INFLIGHT_S = float(os.environ.get("SVC_HUNG_INFLIGHT_SEC", "90"))


class _Replica:
    __slots__ = ("url", "inflight", "fails", "fail_until", "served", "probe_down",
                 "starts", "_tok", "hung_logged")
    def __init__(self, url: str):
        self.url = url
        self.inflight = 0       # 当前在途请求数（最少在途分发的依据）
        self.fails = 0          # 连续失败计数（被动摘除：真实请求失败累计）
        self.fail_until = 0.0   # 被动摘除到此时刻为止（time.time()）
        self.served = 0         # 累计已服务（观测）
        self.probe_down = False # 主动探活判定不可用（与被动摘除独立：server 活但推理坏时仍被动摘除）
        self.starts = {}        # P-Harden1: 在途请求开始时刻 token->monotonic（挂死副本检测）
        self._tok = 0
        self.hung_logged = False   # 挂死状态跳变只记一次日志

    def begin(self) -> int:
        """登记一笔在途请求，返回 token（lease 归还时用）。"""
        self._tok += 1
        self.starts[self._tok] = time.monotonic()
        return self._tok

    def end(self, tok: int):
        self.starts.pop(tok, None)

    def oldest_inflight_s(self) -> float:
        return (time.monotonic() - min(self.starts.values())) if self.starts else 0.0

    def is_hung(self) -> bool:
        return _SVC_HUNG_INFLIGHT_S > 0 and self.oldest_inflight_s() > _SVC_HUNG_INFLIGHT_S


_SVC_POOL_TIEBREAK = os.environ.get("SVC_POOL_TIEBREAK", "rr").strip().lower()   # rr|first


class _SvcPool:
    """单服务多副本负载均衡。单线程 asyncio 下 pick→inflight+=1 之间无 await，选择即原子。"""
    def __init__(self, name: str, urls: list):
        self.name = name
        self.replicas = [_Replica(u) for u in urls]
        self._rr = 0

    @property
    def size(self) -> int:
        return len(self.replicas)

    def _is_live(self, r: _Replica, now: float) -> bool:
        return r.fail_until <= now and not r.probe_down and not self._hung(r)

    def _hung(self, r: _Replica) -> bool:
        """P-Harden1: 在途悬挂检测 + 跳变日志（探活对「health 活/推理死」型挂死是盲的）。"""
        h = r.is_hung()
        if h and not r.hung_logged:
            r.hung_logged = True
            _logger.warning(f"[Hub] 副本疑似挂死(最老在途 {r.oldest_inflight_s():.0f}s 未归还)"
                            f" → 规避新请求: {self.name} {r.url}")
        elif not h and r.hung_logged:
            r.hung_logged = False
            _logger.info(f"[Hub] 副本在途已归还，解除挂死规避: {self.name} {r.url}")
        return h

    def pick(self) -> _Replica:
        now = time.time()
        live = [r for r in self.replicas if self._is_live(r, now)]
        pool = live or self.replicas               # 全摘除时仍尝试，绝不彻底拒绝
        m = min(r.inflight for r in pool)
        cands = [r for r in pool if r.inflight == m]
        # 平局(在途相同)时的分发策略：rr=轮转打散(同构卡默认，零回归)；
        # first=按 SVC_* 列表顺序取先者——异构池(5090主+4070热副本)用它让单路会话
        # 始终落快卡，只有真并发时才溢到副本(在途数不再平局，least-inflight 接管)。
        if _SVC_POOL_TIEBREAK == "first":
            r = cands[0]
        else:
            self._rr += 1                          # 并列副本轮转打散
            r = cands[self._rr % len(cands)]
        r.inflight += 1
        return r

    def healthy_size(self) -> int:
        """当前可用副本数（被动未摘除且探活未判 down）。供 auto K 随健康卡数伸缩。"""
        now = time.time()
        return sum(1 for r in self.replicas if self._is_live(r, now))

    def done(self, r: _Replica, ok: bool):
        r.inflight = max(0, r.inflight - 1)
        if ok:
            r.served += 1
            r.fails = 0
            r.fail_until = 0.0
        else:
            r.fails += 1
            if r.fails >= _SVC_FAIL_THRESH and self.size > 1:
                r.fail_until = time.time() + _SVC_FAIL_COOLDOWN

    def mark_health(self, r: _Replica, ok: bool):
        """主动探活结果。多副本时才据此摘除（单副本摘了也无处可去，留着当瓶颈）。
        仅控 probe_down，不动被动 fails/fail_until——server 活但推理坏的情形仍交被动摘除。"""
        r.probe_down = (not ok) and self.size > 1

    def snapshot(self) -> dict:
        now = time.time()
        return {"size": self.size,
                "healthy": self.healthy_size(),
                "replicas": [{"url": r.url, "inflight": r.inflight, "served": r.served,
                              "down": (r.fail_until > now) or r.probe_down,
                              "hung": r.is_hung(),                       # P-Harden1: 挂死规避中
                              "oldest_inflight_s": round(r.oldest_inflight_s(), 1)}
                             for r in self.replicas]}


_svc_pools: dict = {}

def _svc_pool(name: str) -> _SvcPool:
    p = _svc_pools.get(name)
    if p is None:
        urls = _svc_url_list(name, SERVICES.get(name, ""))
        # 授权软闸门：强制模式且授权不含「多副本」→ 收敛为单副本（多卡并发吞吐属 pro 能力）。
        # 默认不强制(AVATARHUB_LICENSE_ENFORCE!=1)=原样，零破坏；兑现启动日志「多副本将受限」的承诺。
        try:
            if (len(urls) > 1 and _license is not None
                    and _license.enforcing() and not _license.allowed("multi_replica")):
                _logger.info(f"[License] 授权不含多副本 → {name} 收敛为单副本（升级 pro 解锁多卡并发）。")
                urls = urls[:1]
        except Exception:
            pass
        p = _SvcPool(name, urls)
        _svc_pools[name] = p
    return p


class _svc_lease:
    """async with _svc_lease('fish_tts') as base: 请求 f'{base}/...'。
    选最少在途副本、维护在途计数、异常→记失败(供摘除)。单副本时 base==SERVICES[name]。"""
    __slots__ = ("name", "_pool", "_rep", "_tok")
    def __init__(self, name: str):
        self.name = name
        self._pool = _svc_pool(name)
        self._rep = None
        self._tok = 0
    async def __aenter__(self) -> str:
        self._rep = self._pool.pick()
        self._tok = self._rep.begin()   # P-Harden1: 登记在途开始时刻（挂死副本检测数据源）
        return self._rep.url
    async def __aexit__(self, exc_type, exc, tb):
        self._rep.end(self._tok)
        self._pool.done(self._rep, ok=(exc_type is None))
        return False


def _svc_pools_snapshot() -> dict:
    """多卡池全景（仅含已激活的池）。recommended_concurrency=最小【健康】卡数，供 K 对齐参考。"""
    snaps = {n: p.snapshot() for n, p in _svc_pools.items()}
    return {"pools": snaps,
            "recommended_concurrency": _recommended_concurrency_live()}


def _replica_urls(service: str) -> list:
    """该服务全部副本地址（与 _svc_lease 分发用的池一致）。预热须覆盖每张卡，否则
    多卡下非主副本首句要现载模型/编译(~33s)，被分发到时表现为偶发性首句巨延迟。"""
    return [r.url for r in _svc_pool(service).replicas]


def _recommended_concurrency_live() -> int:
    """据当前【健康】副本数推荐并发 K：取所有多卡池的健康副本数最小值(瓶颈)，至少 1。
    无多卡池→1（单卡）。卡挂→K 自动收，卡恢复→K 自动放（auto 模式联动 set_capacity）。"""
    multi = [p for p in _svc_pools.values() if p.size > 1]
    if not multi:
        return 1
    return max(1, min(p.healthy_size() for p in multi))


async def _svc_probe_once():
    """对所有多卡池的每个副本探活一次(GET /health)，更新 probe_down。
    用隔离的 health_pool（与业务流量分开，避免高并发打满共享池导致探测误报全掉线）。"""
    if health_pool is None:
        return
    async def _one(pool, r):
        ok = False
        try:
            resp = await health_pool.get(f"{r.url}/health", timeout=4.0)
            if resp.status_code == 200:
                try:
                    h = resp.json()
                    ok = bool(h.get("models_loaded", h.get("model_loaded", True)))
                except Exception:
                    ok = True       # 200 但无 JSON→视为活着
        except Exception:
            ok = False
        pool.mark_health(r, ok)
    tasks = [_one(pool, r) for pool in list(_svc_pools.values())
             if pool.size > 1 for r in pool.replicas]
    if tasks:
        await asyncio.gather(*tasks)


_svc_probe_task = None

async def _svc_health_loop():
    """周期探活 + auto 模式随健康卡数伸缩 K。卡挂 K 自动收(避免堆到活卡静默劣化)、
    卡恢复 K 自动放。SVC_PROBE_SEC<=0 关闭。"""
    while True:
        await asyncio.sleep(_SVC_PROBE_SEC)
        try:
            await _svc_probe_once()
            if _conv_admission is not None and CONV_MAX_CONCURRENT == -1:
                k = _recommended_concurrency_live()
                if k != _conv_admission.capacity:
                    _conv_admission.set_capacity(k)
                    _logger.info(f"[Hub] 池健康变化→自动并发 K={k}（=最小健康卡数）")
        except Exception as _e:
            try:
                _logger.debug(f"[Hub] 健康探活循环异常: {_e}")
            except Exception:
                pass

