_GUARD_FILE = Path(rf"{_BASE}\guard_blocklist.txt")

# ── 多 LLM 后端配置持久化（本地/局域网/云端，UI 可自由切换）──────────────
_LLM_BACKENDS_FILE = Path(rf"{_BASE}\llm_backends.json")

def _conv_read_llm_backends() -> dict:
    """读取多 LLM 后端清单 {default, backends:[{name,kind,label,base_url,model,api_key,keep_alive}]}。"""
    if _LLM_BACKENDS_FILE.exists():
        try:
            d = json.loads(_LLM_BACKENDS_FILE.read_text(encoding="utf-8"))
            if isinstance(d, dict) and isinstance(d.get("backends"), list):
                return d
        except Exception as _e:
            print(f"[Hub] llm_backends.json 解析失败(用默认): {_e}")
    return {"default": "", "backends": []}

def _conv_write_llm_backends(cfg: dict) -> None:
    """落盘多 LLM 后端清单（云端密钥若来自环境变量则不写明文）。"""
    try:
        ds_env = os.environ.get("CONV_DEEPSEEK_API_KEY", "")
        out = {"default": cfg.get("default", ""), "backends": []}
        for e in cfg.get("backends", []):
            e2 = dict(e)
            if ds_env and e2.get("api_key") == ds_env:
                e2["api_key"] = ""   # 环境变量注入的密钥不持久化明文
            out["backends"].append(e2)
        _LLM_BACKENDS_FILE.write_text(
            json.dumps(out, ensure_ascii=False, indent=2), encoding="utf-8")
    except Exception as _e:
        print(f"[Hub] llm_backends.json 写入失败: {_e}")

def _conv_read_guard_terms() -> list:
    """读取生产闸门敏感词：guard_blocklist.txt(每行一词,# 注释) + CONV_GUARD_BLOCKLIST 环境变量。"""
    terms = []
    if _GUARD_FILE.exists():
        for ln in _GUARD_FILE.read_text(encoding="utf-8").splitlines():
            ln = ln.strip()
            if ln and not ln.startswith("#"):
                terms.append(ln)
    env = os.environ.get("CONV_GUARD_BLOCKLIST", "")
    terms += [t.strip() for t in env.split(",") if t.strip()]
    return terms

try:
    import conversation as _conv
    # Phase9-4: 知识库持久化到 SQLite（重启不丢；失败则降级为内存）
    try:
        _conv.registry.kb = _conv.KnowledgeBase(db_path=rf"{_BASE}\avatar_kb.db")
        print(f"[Hub] 对话知识库已持久化({_conv.registry.kb.count()} 文档)")
    except Exception as _kbe:
        print(f"[Hub] 知识库持久化失败(降级内存): {_kbe}")

    # Phase9-8: 跨会话长期记忆持久化（按 user 隔离；重启不丢；失败降级内存）
    try:
        _conv.long_term = _conv.LongTermMemory(db_path=rf"{_BASE}\avatar_ltm.db")
        print(f"[Hub] 长期记忆已持久化({_conv.long_term.count()} 条)")
    except Exception as _lme:
        print(f"[Hub] 长期记忆持久化失败(降级内存): {_lme}")

    # Phase9-2: 启动时自动接入本地 OpenAI 兼容 LLM(Ollama/vLLM/LM Studio)为默认对话引擎。
    # 可达才接；env 覆盖：CONV_LLM_BASE_URL / CONV_LLM_MODEL / CONV_LLM_API_KEY。
    def _conv_warmup_llm(base, model, api_key, keep_alive):
        """后台预热：消除 70B 冷启首 token 长延迟，并按 keep_alive 常驻显存。"""
        import threading, time as _t
        def _run():
            # _GPU_RELEASED 在模块后段(~2490 行)才定义，而本线程于 import 早期就被拉起，
            # 存在竞态：新装机 import 尚未执行到定义处线程已跑到这——直接引用会 NameError
            # 杀死预热线程（198 全新安装实锤）。globals().get 兜底视为「未释放」。
            if globals().get("_GPU_RELEASED"):   # GPU 总开关已释放：不把 LLM 重新载入显存
                print("[Hub] LLM 预热跳过(GPU 显存已释放，等启用后再载入)")
                return
            t = _t.time()
            try:  # Ollama 原生：仅加载并常驻（不生成）
                rr = requests.post(f"{base}/api/generate",
                                   json={"model": model, "keep_alive": keep_alive}, timeout=600)
                if rr.status_code == 200:
                    print(f"[Hub] LLM 预热完成({model}, {int((_t.time()-t)*1000)}ms, keep_alive={keep_alive})")
                    return
            except Exception:
                pass
            try:  # 通用回退：极短 OpenAI 兼容请求触发载入
                h2 = {"Authorization": f"Bearer {api_key}"} if api_key else {}
                requests.post(f"{base}/v1/chat/completions", headers=h2,
                              json={"model": model, "max_tokens": 1, "stream": False,
                                    "messages": [{"role": "user", "content": "hi"}]}, timeout=600)
                print(f"[Hub] LLM 预热完成(通用回退, {int((_t.time()-t)*1000)}ms)")
            except Exception as e:
                print(f"[Hub] LLM 预热跳过: {e}")
        threading.Thread(target=_run, daemon=True).start()

    # ── 多 LLM 后端：本地(Ollama) / 局域网 / 云端(DeepSeek…) 可自由切换 ──
    # 配置持久化到 llm_backends.json（UI 增删改即时落盘，重启自动恢复）。
    def _conv_register_backend(e: dict, *, default: bool = False):
        """按配置项注册一个 OpenAI 兼容对话后端（含 kind/label/keep_alive 元信息）。"""
        be = _conv.OpenAICompatLLM(
            e["base_url"], e["model"], e.get("api_key", ""),
            keep_alive=e.get("keep_alive", ""),
            kind=e.get("kind", "local"), label=e.get("label", ""))
        be.name = e.get("name") or e["model"]
        _conv.registry.register_llm(be, default=default)
        return be

    def _conv_seed_llm_config() -> dict:
        """首次运行的默认多后端清单：本地 32B(默认) + 本地 70B + 云端 DeepSeek。"""
        return {
            "default": "qwen2.5-32b",
            "backends": [
                {"name": "qwen2.5-32b", "kind": "local", "label": "Qwen2.5-32B · 本地",
                 "base_url": "http://127.0.0.1:11434", "model": "qwen2.5:32b",
                 "api_key": "", "keep_alive": "30m"},
                {"name": "dolphin-70b", "kind": "local", "label": "Dolphin-Llama3-70B · 本地",
                 "base_url": "http://127.0.0.1:11434", "model": "dolphin-llama3:70b",
                 "api_key": "", "keep_alive": "30m"},
                {"name": "deepseek", "kind": "cloud", "label": "DeepSeek · 云端",
                 "base_url": "https://api.deepseek.com", "model": "deepseek-chat",
                 "api_key": "", "keep_alive": ""},
            ],
        }

    def _conv_setup_llms():
        cfg = _conv_read_llm_backends()
        if not cfg.get("backends"):
            cfg = _conv_seed_llm_config()
            _conv_write_llm_backends(cfg)
        # 云端密钥可由环境变量注入（不写入磁盘明文）：CONV_DEEPSEEK_API_KEY
        ds_key = os.environ.get("CONV_DEEPSEEK_API_KEY", "")
        for e in cfg["backends"]:
            if e.get("name") == "deepseek" and not e.get("api_key") and ds_key:
                e["api_key"] = ds_key
        default_name = cfg.get("default") or (cfg["backends"][0]["name"] if cfg["backends"] else "")
        registered = []
        for e in cfg["backends"]:
            try:
                _conv_register_backend(e, default=(e.get("name") == default_name))
                registered.append(e.get("name"))
            except Exception as _be:
                print(f"[Hub] LLM 后端注册失败 {e.get('name')}: {_be}")
        print(f"[Hub] 已注册对话后端: {registered} (default={_conv.registry.default_llm})")
        # 云端容灾：把每个云端后端包成 FailoverLLM(主=云端, 兜底=本地链)，
        # 云端超时/失败时自动切回本地模型，保证对话不断线。名称不变，UI/切换无感。
        try:
            _fail_to = float(os.environ.get("CONV_FAILOVER_TIMEOUT", "12"))
            _fb_to = float(os.environ.get("CONV_FAILOVER_LOCAL_TIMEOUT", "45"))
            _locals = [_conv.registry._llm[n] for n in registered
                       if n in _conv.registry._llm
                       and getattr(_conv.registry._llm[n], "kind", "local") == "local"
                       and not n.startswith("mock")]
            for n in list(registered):
                be = _conv.registry._llm.get(n)
                if be is None or getattr(be, "kind", "local") != "cloud":
                    continue
                wrapped = _conv.FailoverLLM(be, _locals, name=n,
                                            first_token_timeout=_fail_to,
                                            fallback_timeout=_fb_to)
                _conv.registry._llm[n] = wrapped   # 同名替换，default/切换无感
            if _locals:
                print(f"[Hub] 云端容灾已启用：云端首响>{_fail_to}s 自动切本地兜底 "
                      f"{[getattr(b,'name','?') for b in _locals]} (本地冷启≤{_fb_to}s)")
            else:
                print("[Hub] 云端容灾：未发现可用本地兜底引擎（仅云端运行）")
        except Exception as _fe:
            print(f"[Hub] 云端容灾包装跳过: {_fe}")
        # 仅预热「本地且可达」的默认后端，避免云端/未拉取模型的无谓等待 + 控显存
        d = next((e for e in cfg["backends"] if e.get("name") == _conv.registry.default_llm), None)
        if d and d.get("kind") == "local":
            try:
                if requests.get(f"{d['base_url'].rstrip('/')}/v1/models", timeout=3).status_code == 200:
                    _conv_warmup_llm(d["base_url"].rstrip("/"), d["model"],
                                     d.get("api_key", ""), d.get("keep_alive", "30m"))
            except Exception:
                print(f"[Hub] 默认本地 LLM 暂不可达，跳过预热（首次请求时再加载）")
    _conv_setup_llms()

    def _conv_llm_keepwarm():
        """活动驱动的 LLM 保活心跳：消除会话期内的冷启动(实测冷启首 token ~3.6s/14B)。
        仅在「最近有对话活动」时周期性 ping 当前默认本地 LLM，刷新 ollama 常驻计时；
        长期真闲置则停止 ping → 模型自然卸载，把显存让给其他 GPU 任务(faceswap 等)。
        CONV_LLM_KEEPWARM_SEC=0 关闭；CONV_LLM_KEEPWARM_WINDOW 控活跃窗口(秒)。"""
        import threading, time as _t
        interval = int(os.environ.get("CONV_LLM_KEEPWARM_SEC", "1200"))   # 20min < keep_alive 30m
        window = int(os.environ.get("CONV_LLM_KEEPWARM_WINDOW", "3600"))  # 末次活动后保活 1h
        if interval <= 0:
            print("[Hub] LLM 保活心跳已关闭(CONV_LLM_KEEPWARM_SEC=0)")
            return
        def _run():
            while True:
                _t.sleep(interval)
                try:
                    if _conv_last_active <= 0 or (_t.time() - _conv_last_active) > window:
                        continue  # 长期闲置：不再保活，任由模型卸载省显存
                    name = _conv.registry.default_llm
                    be = _conv.registry.get_llm(name) if name else None
                    if be is None or getattr(be, "kind", "local") != "local":
                        continue  # 云端后端无需保活
                    base = getattr(be, "base_url", "").rstrip("/")
                    model = getattr(be, "model", "")
                    ka = getattr(be, "keep_alive", "30m") or "30m"
                    if not base or not model:
                        continue
                    rr = requests.post(f"{base}/api/generate",
                                       json={"model": model, "keep_alive": ka}, timeout=120)
                    if rr.status_code == 200:
                        print(f"[Hub] LLM 保活刷新({model}, keep_alive={ka})")
                except Exception as _e:
                    print(f"[Hub] LLM 保活跳过: {_e}")
        threading.Thread(target=_run, daemon=True).start()
        print(f"[Hub] LLM 保活心跳已启用(间隔{interval}s, 活跃窗口{window}s)")
    _conv_llm_keepwarm()

    def _startup_lipsync_rewarm():
        """启动期有序预热：先等默认本地 LLM 真正载入显存(~17.8GB)，再触发 lipsync /warmup。
        消除「lipsync 自预热后被随后的 LLM 载入挤占→首轮对话口型冷启 ~33s」。
        CONV_STARTUP_REWARM=0 可关。"""
        import threading, time as _t
        if os.environ.get("CONV_STARTUP_REWARM", "1") == "0":
            return
        def _run():
            # 1) 等默认本地 LLM 在 ollama 侧载入显存(轮询 /api/ps)，最多 180s
            be = _conv.registry.get_llm(_conv.registry.default_llm) if _conv.registry.default_llm else None
            if be is not None and getattr(be, "kind", "local") == "local":
                base = getattr(be, "base_url", "").rstrip("/")
                model = getattr(be, "model", "")
                for _ in range(90):
                    try:
                        ps = requests.get(f"{base}/api/ps", timeout=5).json()
                        if any(m.get("name") == model and m.get("size_vram", 0) > 0
                               for m in ps.get("models", [])):
                            break
                    except Exception:
                        pass
                    _t.sleep(2)
            # 1b) 让 LLM 真跑一次极短生成，占住「推理工作区」显存(KV/激活)。
            #   仅 /api/generate 空载只加载权重，首次真实推理才扩张显存→会挤掉已预热的
            #   UNet 工作区。先把这块显存吃下，再预热 lipsync，热态才稳。
            if be is not None and getattr(be, "kind", "local") == "local":
                try:
                    requests.post(f"{getattr(be,'base_url','').rstrip('/')}/v1/chat/completions",
                                  json={"model": getattr(be, "model", ""), "stream": False,
                                        "max_tokens": 8,
                                        "messages": [{"role": "user", "content": "你好"}]},
                                  timeout=120)
                except Exception:
                    pass
            # 2+3) 等每个 lipsync 副本就绪 → 各自 warmup（多卡并行，每张卡 UNet/VAE 热态稳定）
            def _wait_warm(ls):
                ls = ls.rstrip("/")
                for _ in range(120):
                    try:
                        h = requests.get(f"{ls}/health", timeout=5).json()
                        if h.get("models_loaded"):
                            break
                    except Exception:
                        pass
                    _t.sleep(2)
                try:
                    r = requests.post(f"{ls}/warmup", timeout=180)
                    print(f"[Hub] 启动期 lipsync 重预热[{ls}]: {r.json() if r.status_code==200 else r.status_code}")
                except Exception as _e:
                    print(f"[Hub] 启动期 lipsync 重预热跳过[{ls}]: {_e}")
            _ws = [threading.Thread(target=_wait_warm, args=(u,), daemon=True)
                   for u in _replica_urls("lipsync")]
            for _w in _ws:
                _w.start()
            for _w in _ws:
                _w.join()
        threading.Thread(target=_run, daemon=True).start()
        print("[Hub] 启动期有序预热已排程(LLM 常驻 → lipsync 重预热)")
    _startup_lipsync_rewarm()

    def _conv_setup_stt():
        """注册真实 STT（Whisper 微服务 7854）并设为默认；服务未起也不影响 Hub 启动。
        7853 已被 singing_server 占用，STT 独立在 7854，避免端口冲突导致语音输入失效。"""
        try:
            base = os.environ.get("STT_BASE_URL", SERVICES.get("stt", "http://127.0.0.1:7854"))
            _conv.registry.register_stt(_conv.HTTPSTT(base), default=True)
            print(f"[Hub] STT 默认已设为 whisper_stt({base})")
        except Exception as _se:
            print(f"[Hub] STT 注册失败(保留 mock_stt): {_se}")
        # P2: 注册 Nemotron 3.5 流式 STT 为「可选引擎」（同 /transcribe 契约，复用 HTTPSTT）。
        #     不设默认——默认仍 whisper；前端在 Nemotron 在线时灰度默认选它，掉线则 _conv_prepare 门控回退。
        #     服务未起时也不影响 Hub 启动/默认链路（仅被显式选中时才用到）。
        try:
            nemo_base = os.environ.get("NEMO_STT_BASE_URL", SERVICES.get("nemo_stt", "http://127.0.0.1:7857"))
            _conv.registry.register_stt(_conv.HTTPSTT(nemo_base, name="nemotron_stt"))
            print(f"[Hub] STT 可选引擎已注册 nemotron_stt({nemo_base})")
        except Exception as _se:
            print(f"[Hub] nemotron_stt 注册失败(不影响默认链路): {_se}")
    _conv_setup_stt()

    def _conv_load_guard():
        """生产安全闸门：从文件 + 环境变量加载敏感词。"""
        terms = _conv_read_guard_terms()
        if terms:
            redact = os.environ.get("CONV_GUARD_REDACT", "1") != "0"
            _conv.registry.set_guard(_conv.KeywordGuard(terms, redact))
            print(f"[Hub] 生产安全闸门已加载({len(terms)} 词, redact={redact})")
    _conv_load_guard()

    def _conv_setup_embedder():
        """Phase9-5: 可选语义嵌入后端 → BM25+语义 混合检索（RRF）。
        默认关（CONV_EMBED_MODEL 为空）；配置且端点可达才启用，否则保持纯 BM25（零回归）。
        复用本机 Ollama（/v1/embeddings，先 `ollama pull bge-m3`）：
          CONV_EMBED_MODEL=bge-m3  [CONV_EMBED_BASE_URL=http://127.0.0.1:11434] [CONV_EMBED_API_KEY=]"""
        model = os.environ.get("CONV_EMBED_MODEL", "").strip()
        if not model:
            return
        base = (os.environ.get("CONV_EMBED_BASE_URL", "").strip()
                or "http://127.0.0.1:11434")
        api_key = os.environ.get("CONV_EMBED_API_KEY", "").strip()
        try:
            emb = _conv.OpenAICompatEmbedding(base, model, api_key)
            _probe = emb.embed(["数字人语义检索连通性探针"])   # 可达性 + 模型存在性探测
            if not _probe or not _probe[0]:
                raise RuntimeError("空向量返回")
            _conv.registry.set_embedder(emb)
            try:
                _conv.long_term.set_embedder(emb)   # 长期记忆同享语义召回/去重
            except Exception:
                pass
            _kb = _conv.registry.list().get("kb", {})
            print(f"[Hub] 语义混合检索已启用: {model}@{base} "
                  f"(dim={len(_probe[0])}, retriever={_kb.get('retriever')}, "
                  f"embedded={_kb.get('embedded_docs')}/{_kb.get('docs')})")
        except Exception as _ee:
            print(f"[Hub] 语义嵌入未启用(保持 BM25): {_ee}")
    _conv_setup_embedder()
except Exception as _ce:
    _conv = None
    print(f"[Hub] conversation 加载失败(降级): {_ce}")
