# ── 历史记录 SQLite ───────────────────────────────────────────────
import sqlite3 as _sqlite3

HISTORY_DB      = Path(rf"{_BASE}\history.db")
HISTORY_AUDIO   = Path(rf"{_BASE}\history_audio")
METRICS_FILE    = Path(rf"{_BASE}\metrics_snapshot.json")  # P16-2: 指标快照持久化
HISTORY_AUDIO.mkdir(exist_ok=True)
HISTORY_MAX_DAYS = 7
HISTORY_MAX_GB   = 1.0

def _db_conn():
    conn = _sqlite3.connect(str(HISTORY_DB), check_same_thread=False)
    conn.row_factory = _sqlite3.Row
    conn.execute("PRAGMA journal_mode=WAL")       # 并发读写不锁表
    conn.execute("PRAGMA synchronous=NORMAL")     # 写入速度和安全性平衡
    conn.execute("PRAGMA cache_size=-4096")       # 4MB 页面缓存
    return conn

def _init_history_db():
    with _db_conn() as conn:
        conn.execute("""
        CREATE TABLE IF NOT EXISTS speak_history (
            id         INTEGER PRIMARY KEY AUTOINCREMENT,
            ts         REAL    NOT NULL,
            profile    TEXT    NOT NULL,
            text       TEXT    NOT NULL,
            language   TEXT    DEFAULT 'zh-cn',
            audio_file TEXT    DEFAULT '',
            elapsed_ms INTEGER DEFAULT 0,
            rvc_applied INTEGER DEFAULT 0,
            starred    INTEGER DEFAULT 0,
            emotion    TEXT    DEFAULT 'neutral'
        )""")
        # 高频查询字段加索引
        conn.execute("CREATE INDEX IF NOT EXISTS idx_history_ts           ON speak_history(ts)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_history_profile      ON speak_history(profile)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_history_starred      ON speak_history(starred)")
        # 迁移安全地加入 emotion 列（老库兼容；新库建表已含）。
        # 必须先于下方 emotion 复合索引执行：全新机器首启建的是新库，若先建索引后补列，
        # 直接 no such column 崩死在 import（2026-07-12 在 198 全新安装实锤）。
        try:
            conn.execute("ALTER TABLE speak_history ADD COLUMN emotion TEXT DEFAULT 'neutral'")
        except Exception:
            pass  # 列已存在
        # P14-4: 复合索引覆盖高频过滤+分页组合（emotion过滤+ts排序 / profile过滤+ts排序）
        conn.execute("CREATE INDEX IF NOT EXISTS idx_history_emotion_ts   ON speak_history(emotion, ts DESC)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_history_profile_ts   ON speak_history(profile, ts DESC)")
        # P21-5: FTS5全文搜索虚拟表
        conn.execute("""
        CREATE VIRTUAL TABLE IF NOT EXISTS speak_history_fts USING fts5(
            text, profile, emotion,
            content='speak_history',
            content_rowid='id'
        )""")
        # 触发器：自动同步FTS索引
        conn.execute("""
        CREATE TRIGGER IF NOT EXISTS trg_history_insert AFTER INSERT ON speak_history BEGIN
            INSERT INTO speak_history_fts(rowid, text, profile, emotion)
            VALUES (NEW.id, NEW.text, NEW.profile, NEW.emotion);
        END""")
        conn.execute("""
        CREATE TRIGGER IF NOT EXISTS trg_history_delete AFTER DELETE ON speak_history BEGIN
            DELETE FROM speak_history_fts WHERE rowid=OLD.id;
        END""")
        conn.execute("""
        CREATE TRIGGER IF NOT EXISTS trg_history_update AFTER UPDATE ON speak_history BEGIN
            DELETE FROM speak_history_fts WHERE rowid=OLD.id;
            INSERT INTO speak_history_fts(rowid, text, profile, emotion)
            VALUES (NEW.id, NEW.text, NEW.profile, NEW.emotion);
        END""")
        # 初始数据回填（首次创建FTS表时）
        try:
            fts_count = conn.execute("SELECT COUNT(*) FROM speak_history_fts").fetchone()[0]
            if fts_count == 0:
                conn.execute("""
                    INSERT INTO speak_history_fts(rowid, text, profile, emotion)
                    SELECT id, text, profile, emotion FROM speak_history
                """)
        except Exception:
            pass
        conn.commit()

_init_history_db()

# 清理节流控制：最多每小时清理一次，避免每次写入都扫货文件系统
_CLEANUP_LOCK   = threading.Lock()
_last_cleanup_ts: float = 0.0
_CLEANUP_INTERVAL = 3600.0   # 秒

def _write_history(profile: str, text: str, language: str,
                   audio_b64: str, elapsed_ms: int, rvc_applied: bool,
                   incognito: bool = False, emotion: str = "neutral"):
    """写入一条历史记录（隐身模式跳过）。音频文件名用 UUID 防并发碰撞。
    P22-3: 自动去重 - 相同profile+text+emotion在24小时内合并更新
    UI-P0: 返回记录 id（去重时返回既有 id），供 speak 流在 saved 事件回传前端做「收藏」。"""
    if incognito:
        return None
    hist_id = None
    try:
        ts = time.time()
        audio_file = ""
        if audio_b64:
            fname = f"{uuid.uuid4().hex}.wav"   # UUID 防毫秒级并发碰撞
            fpath = HISTORY_AUDIO / fname
            fpath.write_bytes(base64.b64decode(audio_b64))
            audio_file = fname
        with _db_conn() as conn:
            # P22-3: 去重检查（24小时内相同profile+text+emotion）
            cutoff_ts = ts - 86400  # 24小时
            dup = conn.execute(
                "SELECT id, audio_file FROM speak_history WHERE profile=? AND text=? AND emotion=? AND ts > ?",
                (profile, text, emotion or "neutral", cutoff_ts)
            ).fetchone()
            if dup:
                # 更新现有记录（新音频覆盖旧音频，时间戳更新）
                old_audio = dup["audio_file"]
                conn.execute(
                    "UPDATE speak_history SET ts=?, audio_file=?, elapsed_ms=?, rvc_applied=? WHERE id=?",
                    (ts, audio_file, elapsed_ms, 1 if rvc_applied else 0, dup["id"])
                )
                hist_id = dup["id"]
                # 删除旧音频文件节省空间
                if old_audio and old_audio != audio_file:
                    old_path = HISTORY_AUDIO / old_audio
                    if old_path.exists():
                        old_path.unlink()
                _logger.debug(f"[History] 去重更新 id={dup['id']} ({profile}:{text[:20]}...)")
            else:
                cur = conn.execute("""
                    INSERT INTO speak_history
                    (ts, profile, text, language, audio_file, elapsed_ms, rvc_applied, emotion)
                    VALUES (?,?,?,?,?,?,?,?)
                """, (ts, profile, text, language, audio_file,
                      elapsed_ms, 1 if rvc_applied else 0, emotion or "neutral"))
                hist_id = cur.lastrowid
            conn.commit()
        _invalidate_stats_cache()   # 主动失效 stats 缓存
        # 节流清理：同一时间窗只清一次，不干扰正常写入
        global _last_cleanup_ts
        now = time.time()
        with _CLEANUP_LOCK:
            if now - _last_cleanup_ts > _CLEANUP_INTERVAL:
                _last_cleanup_ts = now
                do_cleanup = True
            else:
                do_cleanup = False
        if do_cleanup:
            # UI-P0: 清理改后台线程——写路径现处于 speak 流 done 事件之前（同步等待），
            # 不能被偶发的批量删文件拖慢；清理本身有节流锁，天然防并发重入。
            threading.Thread(target=_auto_cleanup_history, daemon=True).start()
        return hist_id
    except Exception as e:
        _logger.warning(f"[History] 写入失败: {e}")
        return None

def _auto_cleanup_history():
    """自动清理超期(>7天)或超量(>1GB)的历史，收藏不清理"""
    try:
        cutoff = time.time() - HISTORY_MAX_DAYS * 86400
        with _db_conn() as conn:
            rows = conn.execute(
                "SELECT id, audio_file FROM speak_history "
                "WHERE ts < ? AND starred=0", (cutoff,)).fetchall()
            for row in rows:
                if row["audio_file"]:
                    f = HISTORY_AUDIO / row["audio_file"]
                    if f.exists(): f.unlink()
            conn.execute("DELETE FROM speak_history WHERE ts < ? AND starred=0",
                         (cutoff,))
            conn.commit()
        # 超量检查
        total = sum(f.stat().st_size for f in HISTORY_AUDIO.glob("*.wav") if f.exists())
        if total > HISTORY_MAX_GB * 1024**3:
            with _db_conn() as conn:
                old = conn.execute(
                    "SELECT id, audio_file FROM speak_history "
                    "WHERE starred=0 ORDER BY ts ASC LIMIT 50").fetchall()
                for row in old:
                    if row["audio_file"]:
                        f = HISTORY_AUDIO / row["audio_file"]
                        if f.exists(): f.unlink()
                    conn.execute("DELETE FROM speak_history WHERE id=?", (row["id"],))
                conn.commit()
    except Exception as e:
        _logger.warning(f"[History] 自动清理失败: {e}")


async def _async_generate_preview(name: str):
    """角色保存后异步预生成试听音频，每个语言各一个。

    M2-D：改走对话同款合成 `_conv_synthesize`，支持 Fish-Speech 零样本克隆
    （旧实现只会调 XTTS/`_call_tts`，对 Fish 角色生成不出音→voice_preview 503）。
    """
    await asyncio.sleep(0.1)   # 让主请求先返回
    profile = _profiles.get(name, {})
    if not profile:
        return
    p = dict(profile)
    p["name"] = name
    lang_pref  = profile.get("rvc_settings", {}).get("preview_lang", "zh-cn")
    langs      = [lang_pref] + [l for l in ["zh-cn", "en"] if l != lang_pref]

    for lang in langs[:2]:   # 最多生成2个语言
        text     = _PREVIEW_TEXTS.get(lang, _PREVIEW_TEXTS["zh-cn"]).format(name=name)
        out_path = VOICE_PREVIEW_DIR / f"{name}_{lang}.wav"
        try:
            audio_b64 = await _conv_synthesize(
                text, p, language=lang, emotion="neutral",
                vc_engine="", watermark=None, _use_opener_cache=False)
            if audio_b64:
                import base64 as _b64
                out_path.write_bytes(_b64.b64decode(audio_b64))
                _logger.info(f"[Preview] 预生成功: {out_path.name}")
            else:
                _logger.warning(f"[Preview] 合成为空 {name}/{lang}")
        except Exception as e:
            _logger.warning(f"[Preview] 预生失败 {name}/{lang}: {e}")

# ── 全局 httpx 连接池 (P2-A) ──────────────────────────────────
http_pool: httpx.AsyncClient | None = None    # TTS/RVC 共享连接池
# 健康探测专用连接池：与业务流量(TTS/换脸/推流)隔离，避免高并发把共享池打满后
# 健康探测拿不到连接 → 短超时全部失败 → 误报"全服务掉线"(并误触发守护重启/UI 红)。
# 连接数设得大于探测目标数(~14)，确保所有探测都能立刻拿到连接、零排队。
health_pool: httpx.AsyncClient | None = None
_history_executor = ThreadPoolExecutor(max_workers=1, thread_name_prefix="history_writer")  # P5-6; P10-4: =1串行写，消除SQLite locked


def _aclient(**kwargs) -> "httpx.AsyncClient":
    """临时 httpx 客户端工厂：统一注入服务间共享令牌头（GPU 服务面加固）。
    调用方传入的 headers 会与令牌头合并（不覆盖令牌）。"""
    hdrs = app_config.service_headers(kwargs.pop("headers", None))
    return httpx.AsyncClient(headers=hdrs, **kwargs)


def _svc_req_headers(extra: dict = None) -> dict:
    """同步 requests 调用服务时的头（含共享令牌）。"""
    return app_config.service_headers(extra)

@asynccontextmanager
async def lifespan(app: FastAPI):
    global http_pool, health_pool
    # 备战起动：建立连接池
    http_pool = httpx.AsyncClient(
        timeout=httpx.Timeout(connect=5.0, read=70.0, write=30.0, pool=5.0),
        limits=httpx.Limits(max_connections=20, max_keepalive_connections=10,
                            keepalive_expiry=30),
        headers=app_config.service_headers(),     # GPU 服务面加固：携带共享令牌
    )
    health_pool = httpx.AsyncClient(
        timeout=httpx.Timeout(connect=2.0, read=3.0, write=3.0, pool=2.0),
        limits=httpx.Limits(max_connections=32, max_keepalive_connections=32,
                            keepalive_expiry=30),
        headers=app_config.service_headers(),     # GPU 服务面加固：携带共享令牌
    )
    # 后台清理任务：每小时清理一次过期历史
    async def _bg_cleanup():
        while True:
            await asyncio.sleep(3600)
            try:
                _auto_cleanup_history()
                _trash_auto_clean("hourly")   # 回收站超限自动清旧（策略开关在资产面板回收站页）
                _matting_cleanup_old()
            except Exception as exc:
                _logger.warning(f"[BgClean] 失败: {exc}")
    # P16-2: 每5分钟定期将指标快照写入磁盘
    async def _bg_metrics_save():
        while True:
            await asyncio.sleep(300)
            _save_metrics_snapshot()

    # P1 遥测：每日心跳 + 用量聚合（opt-in，默认关；telemetry_client 内部一天一条限频）。
    #   只报版本/edition/GPU/粗粒度计数，绝不含内容数据；未开启或模块缺失=完全空转。
    async def _bg_telemetry_daily():
        try:
            import telemetry_client as _tc
        except Exception:
            return
        await asyncio.sleep(45.0)      # 让子服务与角色先就绪
        while True:
            try:
                if _tc.usage_enabled():
                    gpus = []
                    try:
                        import pack_installer as _pi
                        gpus = _pi.detect_gpus()
                    except Exception:
                        gpus = []
                    g0 = gpus[0] if gpus else {}
                    ed = ""
                    try:
                        ed = (json.loads((Path(_BASE) / "runtime" / "installed.json").read_text(encoding="utf-8"))
                              .get("_edition", "")) if (Path(_BASE) / "runtime" / "installed.json").exists() else ""
                    except Exception:
                        ed = ""
                    _tc.heartbeat("hub", extra={"edition": ed, "gpu": g0.get("name", ""),
                                                "vram_gb": round(g0.get("total_mb", 0) / 1024)})
                    # 用量：角色数 + 换脸累计 + 是否在播（本地已有的廉价计数，日聚合上报）
                    counters = {"profiles": len(_profiles)}
                    try:
                        m = _get_perf_metrics() or {}
                        for k in ("swap_ok", "swap_fail"):
                            if k in m:
                                counters[k] = int(m.get(k, 0) or 0)
                    except Exception:
                        pass
                    _tc.report_usage("hub", counters)
            except Exception as _te:
                _logger.warning(f"[telemetry] 日报异常(忽略): {_te}")
            await asyncio.sleep(6 * 3600)     # 每 6 小时探一次，实际发送由客户端一天一条限频
    # L2-1: 服务健康自愈监控——周期探测 → 跳变记录 → 关键服务恢复回暖
    async def _bg_health_monitor():
        if _health_monitor is None:
            return
        interval = int(os.environ.get("HUB_HEALTH_MONITOR_INTERVAL", "20"))
        await asyncio.sleep(15.0)
        while True:
            try:
                h = await _health_fresh()       # 监控/自愈须用新鲜值，不吃 /health 的陈旧缓存
                svc_status = h.get("services", {})
                transitions = _observe_health(svc_status)
                for ev in transitions:
                    if ev["event"] == "down":
                        _logger.warning(f"[Heal] 服务掉线: {ev['service']}"
                                        f"{'（关键）' if ev['critical'] else ''}")
                    elif ev["event"] == "recover":
                        _logger.info(f"[Heal] 服务恢复: {ev['service']}")
                        if ev["critical"]:
                            await _self_heal_on_recover(ev["service"])
                # L4-1: 关键服务进程消失 → 进程级自动拉起（端口探测确认掉线后，带退避/熔断）
                # GPU 总开关「释放」期间暂停自愈：否则刚杀的 GPU 服务会被守护立刻重拉，释放不掉。
                if _SUPERVISOR_ON and _supervisor is not None and not _GPU_RELEASED:
                    _revived = []
                    for _csvc in _supervisor.SUPERVISED:
                        # 按模式临时挂起自愈：开播态下用不到的常驻引擎(如换脸模式的 ditto)登记在 _PARK_SUSPEND，
                        # 此处跳过其复活，让「开播泊车」停得住(省显存)；停播/切模式会清空挂起 → 自动恢复守护。
                        if _csvc in _PARK_SUSPEND:
                            continue
                        # is False = /health 明确掉线；is None = 该服务不在 /health 上报(如 monitor 手机中继 7878)，
                        # 也交 ensure_up 处理——它按端口探测且幂等(在线=noop)，否则这类服务永远不会被自愈拉起。
                        if svc_status.get(_csvc) is not True:
                            try:
                                res = await asyncio.to_thread(_supervisor.ensure_up, _csvc)
                                if res.get("action") == "launched":
                                    _revived.append(_csvc)
                                if res.get("action") in ("launched", "tripped", "launch_failed"):
                                    _logger.warning(f"[Sup] {_csvc}: {res}")
                            except Exception as _se:
                                _logger.warning(f"[Sup] {_csvc} 拉起异常: {_se}")
                    if _revived:
                        _warm_health_for(_revived)   # 自愈拉起的服务一就绪即刷缓存，rt_effective 尽快回 ditto
                # P4 音频自愈：推流中「变声服务(6242)掉线」→ 拉起(它未入看门狗守护，无人管=直播没声)。
                #   仅 autoheal 开；GPU 释放期同样暂停(与上面进程自愈一致，避免刚让渡又被拉起)。幂等+护栏，异常不外溢。
                if _AUTOHEAL_ON and not _GPU_RELEASED:
                    try:
                        await _audio_heal_tick(svc_status)
                    except Exception as _ae:
                        _logger.warning(f"[AudioHeal] tick 异常: {_ae}")
                # P-Silence 无人值守·直播静音告警：推流中 CABLE 持续无声 → 告警(纯通知，不自愈)。受告警总开关控，与前端 soundDiag 互补(网页关掉也能发现)。
                if _SH_ALERTS_ON and not _GPU_RELEASED:
                    try:
                        await _cable_silence_tick()
                    except Exception as _ce:
                        _logger.warning(f"[CableSilence] tick 异常: {_ce}")
            except Exception as exc:
                _logger.warning(f"[Heal] 监控循环异常: {exc}")
            await asyncio.sleep(interval)
    # L5-2: 显存自适应常驻——空闲且吃紧时让渡 LLM，下次对话自动重载
    async def _bg_vram_autopilot():
        if not _VRAM_AUTOPILOT_ON:
            return
        await asyncio.sleep(30.0)
        while True:
            await asyncio.sleep(30)
            try:
                perf = _get_perf_metrics()
                if perf.get("streaming"):          # 推流中绝不动 LLM
                    continue
                idle = time.time() - _LAST_ACTIVITY_TS
                if idle < _VRAM_IDLE_SEC:
                    continue
                p = _vram_pressure()
                if p["level"] not in ("high", "med"):
                    continue
                if _VRAM_STATE["llm_yielded"]:     # 已让渡，无需重复
                    continue
                if await _llm_yield_vram():
                    _VRAM_STATE.update(llm_yielded=True, last_action="idle_yield_llm",
                                       last_action_ts=time.time())
                    _VRAM_STATE["reclaims"] += 1
                    _logger.info(f"[VRAM] 空闲{int(idle)}s且{p['level']}压力→让渡LLM腾余量")
            except Exception as exc:
                _logger.warning(f"[VRAM] autopilot 异常: {exc}")

    # Phase#3: 运维指标落盘——周期把 ops 快照追加到 logs/ops_metrics.jsonl，留痕做趋势(/ops 看板可拉)
    async def _bg_ops_persist():
        if not _OPS_PERSIST_ON:
            return
        await asyncio.sleep(25.0)            # 启动后等服务起齐再开始采样
        while True:
            try:
                snap = await api_ops_snapshot()
                sup = snap.get("supervisor") or {}
                rec = {
                    "ts": int(time.time()),
                    "pressure": snap.get("pressure"),
                    "gpu": snap.get("gpu_util"),
                    "ram": snap.get("ram_percent"),
                    "down": [n for n, v in (snap.get("services") or {}).items()
                             if v is False and not (sup.get(n, {}) or {}).get("offloaded")],
                    "restarts": {n: (s or {}).get("restarts", 0) for n, s in sup.items()},
                    "tripped": [n for n, s in sup.items() if (s or {}).get("tripped")],
                    "tts": (snap.get("tts_channel") or {}).get("stats"),
                    "ttfa": (snap.get("metrics") or {}).get("perceived_ttfa_ms"),
                    "stream_health": _sh_stats_snapshot(),   # P3-C③ 开播健康累计(跳迁/丢脸/自愈次数)留痕做趋势
                    # P5.1: 人脸预计算就绪态留痕(紧凑摘要)——供 /ops 画 ETA / 真实失败率趋势，判断"是否变慢/劣化"
                    "face_prep": {k: (snap.get("face_prep") or {}).get(k)
                                  for k in ("settled", "real_fail_rate", "degraded_rate", "eta_s", "dur_p95_s")},
                }
                _ops_persist_append(rec)
            except Exception as exc:
                _logger.warning(f"[OpsPersist] 采样失败: {exc}")
            await asyncio.sleep(_OPS_PERSIST_SEC)

    # 跨机显存互斥：peer 租约心跳超时 → 自动回收显卡(重拉本机服务)，防 B 崩溃/掉线后 A 永久躺平。
    # 兼作启动对账：模块加载已 _gpu_lease_load() 承接上次未归还的租约；若其早已过期，这里 5s 内回收+engage。
    async def _bg_gpu_lease_reaper():
        global _GPU_LEASE
        while True:
            await asyncio.sleep(5)
            try:
                lz = _GPU_LEASE
                if not lz or _gpu_lease_active(lz):
                    continue
                holder = lz.get("holder")
                restore = lz.get("restore")
                age = int(time.time() - lz.get("ts", 0))
                _logger.warning(f"[GPU/Lease] peer {holder} 租约超时({age}s>{lz.get('ttl')}s)，自动回收显卡并恢复服务"
                                f"(恢复={restore if restore is not None else 'all'})")
                _GPU_LEASE = None
                _gpu_lease_save(None)
                _GPU_LAST.update(action="lease_expire", ts=time.time(), detail=f"peer {holder} 租约超时,自动回收")
                try:
                    await _gpu_engage_core("all", allow_when_leased=True, names=restore)
                except Exception as e:
                    _logger.warning(f"[GPU/Lease] 回收后拉起失败: {e}")
            except Exception as exc:
                _logger.warning(f"[GPU/Lease] reaper 异常: {exc}")

    # 开播健康守护（P3-C②③）：周期算「单一真相」裁决→跟踪跳迁写时间线/统计(默认零副作用，纯观测留痕)。
    #   HUB_AUTOHEAL=1 时叠加非破坏自愈：持续卡顿+显存紧→自动腾显存(停本模式未用引擎)，带驻留门槛/冷却/单回合一次。
    #   破坏类(重启)此处不做——留待下一步带「与浏览器去重的锁」，避免无人值守误重启正在直播的流。
    async def _bg_stream_health_watch():
        global _AH_RESTART_COUNT
        await asyncio.sleep(15.0)            # 等服务起齐，避免开机瞬态误判
        try:
            _swap_sess_reconcile()           # 上个宿主在播中猝死→断点半场转正入账(P7 三期)
        except Exception as exc:
            _logger.warning(f"[SwapSess] 对账异常: {exc}")
        prev = None
        since = time.time()
        episode: set = set()                 # 本「坏态回合」已做过的自愈动作（防回合内反复）
        cooldown: dict = {}                  # 动作 → 上次执行时刻（跨回合冷却）
        alerted = False                      # 当前是否已就「开播坏态」发过告警（恢复时清一次）
        _orph_n = 0                          # 孤儿流探测节流(idle 时每 ~30 tick 一次)
        while True:
            await asyncio.sleep(_SH_WATCH_SEC)
            try:
                v = _stream_health_now()
                st = v.get("state")
                now = time.time()
                # 孤儿流探测(2026-07-06p 发现4)：hub 无进程句柄但换脸控制口在应答=画面进程先于
                # hub 存在(重启丢句柄/外部脚本起的)→健康裁决恒 idle、观察自动化全盲。探出→
                # /realtime/status 带 orphan 旗标,前端横幅提示"一键开播接管"。仅探测不动流。
                if st == "idle":
                    _orph_n += 1
                    if _orph_n >= 30 or _ORPHAN_STREAM["seen"] is None:   # 启动首 tick 即探一次
                        _orph_n = 0
                        await _orphan_probe()
                elif _ORPHAN_STREAM["info"] is not None:
                    _ORPHAN_STREAM["info"] = None                          # 在播=受管,清旗标
                if st != prev:                               # 状态跳迁
                    if prev is not None:                     # 跳过启动基线(None→idle)，只记真实跳迁
                        _stream_health_event(prev, st, v, now - since)
                    prev, since, episode = st, now, set()
                dwell = now - since
                # 场次换脸质量采样(观察自动化)：在播每 tick 采 /swap/status，停播聚合落盘。
                # 独立 try：采样/落盘任何异常都不影响健康自愈主流程。
                try:
                    await _swap_sess_tick(st, now)
                except Exception as exc:
                    _logger.warning(f"[SwapSess] 采样异常: {exc}")
                if st == "idle":                             # 停播=新场次边界→归零自动重启预算
                    _AH_RESTART_COUNT = 0
                # 决策/执行分离(policy/mechanism)：纯函数 _sh_plan 依(状态,驻留)+护栏上下文定夺本 tick 做什么，
                # 守护只负责执行；同一套决策供 /api/heal/selftest 演练直接断言(无需真硬件/真等待)。
                # _vram_pressure 仅在 autoheal 开且卡顿时惰性取(与原行为一致，避免平时无谓查卡)。
                vram_level = ((_vram_pressure() or {}).get("level")) if (_AUTOHEAL_ON and st == "lag") else None
                plan = _sh_plan(st, dwell, autoheal_on=_AUTOHEAL_ON, alerts_on=_SH_ALERTS_ON,
                                alerted=alerted, episode=episode, cooldown=cooldown,
                                restart_count=_AH_RESTART_COUNT, now=now,
                                last_video_start_ts=_LAST_VIDEO_START_TS, vram_level=vram_level,
                                govern_on=_IDLE_LIVE_GOVERN)
                # Song-P6 空转直播治理（独立于 autoheal：僵尸直播饿死创作队列的风险恒在）：
                # 分钟级坏态驻留(自愈也没救回) → 自动停播 + 告警留痕。停播是安全动作(僵尸管线本就没内容)。
                if plan["stop_idle_live"]:
                    episode.add("stop_idle_live")
                    try:
                        stopped = False
                        if _realtime_proc is not None and _realtime_proc.poll() is None:
                            _realtime_proc.terminate()
                            stopped = True
                        _sched_note_stop("idle_live")   # P14-A1: 治理停播=有意停播，排班本场豁免（防僵尸复活循环）
                        _stream_health_event(st, st, v, dwell, action=f"idle_live_autostop({st})")
                        _SH_STATS["idle_live_stop"] = _SH_STATS.get("idle_live_stop", 0) + 1
                        _logger.warning(f"[StreamHeal] 空转直播治理：{st} 持续 {int(dwell/60)} 分钟"
                                        f"（无人上镜/画面死更）→ 自动停播 stopped={stopped}"
                                        f"——唱歌/MV 让路队列随之解锁")
                        await broadcast({"event": "idle_live_autostop", "state": st,
                                         "dwell_min": int(dwell / 60)})
                        try:
                            import alerts as _al
                            _al.raise_alert("idle_live", "空转直播已自动下播",
                                detail=f"画面{('停更' if st == 'stalled' else '持续无人上镜')}"
                                       f"≈{int(dwell/60)}分钟，已自动停播释放算力"
                                       f"（唱歌/MV 任务恢复排产）。误停请重新一键开播。",
                                level="error", source="空转直播治理")
                        except Exception:
                            pass
                    except Exception as exc:
                        _logger.warning(f"[StreamHeal] 空转直播停播失败: {exc}")
                # alerts联动（纯通知·安全；受 _SH_ALERTS_ON 控）：raise_alert 自带去抖(REFIRE_SEC 默认6h)，
                # alerted 旗标避免每 tick 重写状态；恢复(ok/idle)时清一次。
                if _SH_ALERTS_ON:
                    if plan["alert"]:
                        try:
                            import alerts as _al
                            _al.raise_alert("stream_health",
                                ("开播异常·换脸服务掉线" if st == "svc_down"
                                 else "开播异常·画面停更" if st == "stalled"
                                 else "开播异常·持续未检测到人脸"),
                                detail=f"状态={st} 持续≈{int(dwell)}s 失败率={v.get('fail_rate')}%",
                                level=plan["alert"], source="开播健康")
                        except Exception as e:
                            _logger.warning(f"[StreamHeal] 告警失败: {e}")
                        _stream_health_event(st, st, v, dwell, kind="alert",
                            action=("换脸服务掉线告警" if st == "svc_down"
                                    else "画面停更告警" if st == "stalled" else "持续无脸告警"))
                        alerted = True
                        if _ALERT_BEEP_ON:      # 本机蜂鸣：主播离机也听得见(页面告警看不见)
                            threading.Thread(target=_alert_beep, daemon=True).start()
                    elif plan["clear_alert"]:
                        try:
                            import alerts as _al
                            _al.clear_alert("stream_health", note=f"开播健康已恢复（{st}）")
                        except Exception:
                            pass
                        alerted = False
                if not _AUTOHEAL_ON:                          # 默认关：纯观测留痕+告警，零破坏副作用
                    continue
                # ① 非破坏自愈：持续卡顿且本机显存紧→腾掉本模式未用的重型引擎（不打断直播）
                if plan["free_vram"]:
                    episode.add("free_vram"); cooldown["free_vram"] = now
                    try:
                        r = await _gpu_free_unused_core()
                    except Exception as e:
                        r = {"ok": False, "error": str(e)}
                    if r.get("stopped_ok"):
                        _stream_health_event(st, st, v, dwell, action=f"auto_free_vram:{r.get('targets')}")
                        _logger.info(f"[StreamHeal] 持续卡顿{int(dwell)}s+显存紧→自动腾显存 {r.get('targets')}")
                # ② 破坏类自愈：持续无脸过久→自动换源重连(重启视频管线)。护栏(驻留/回合/上限/冷却/去重)已在
                #    _sh_plan 定夺；这里再进单飞锁 + 锁内复检去重，确保与浏览器自愈/手动重启不会撞车双重启。
                if plan["restart"]:
                    async with _AH_RESTART_LOCK:
                        if (time.time() - _LAST_VIDEO_START_TS) > _AH_RESTART_DEDUP:   # 锁内复检
                            episode.add("restart"); cooldown["restart"] = time.time()
                            _AH_RESTART_COUNT += 1
                            try:
                                rr = await _restart_video_pipeline_core(st)   # st=noface/stalled，原因如实透传
                            except Exception as e:
                                rr = {"ok": False, "detail": str(e)}
                            ok = bool(rr.get("ok"))
                            _stream_health_event(st, st, v, dwell,
                                action=f"auto_restart#{_AH_RESTART_COUNT}" + ("" if ok else "(失败)"))
                            _logger.warning(f"[StreamHeal] 持续坏态({st}){int(dwell)}s→自动换源重连 "
                                            f"#{_AH_RESTART_COUNT}/{_AH_RESTART_MAX} ok={ok} ({rr.get('detail')})")
                        else:
                            episode.add("restart")    # 别的来源刚重启→本回合让渡，不计数不打点
            except Exception as exc:
                _logger.warning(f"[StreamHeal] watch 异常: {exc}")

    threading.Thread(target=_trash_auto_clean, args=("startup",), daemon=True).start()  # 停机期积压的旧回收项开机即清
    threading.Thread(target=_matting_cleanup_old, daemon=True, name="matting-clean").start()
    _matting_warm_if_relevant("startup")      # 闸门:队列非空/近24h有任务才热,闲置不白占GPU
    try:
        _matting_adopt_orphans()              # 先收养重启前的孤儿任务(占住在跑位,防队列双跑)
    except Exception as _ae:
        _logger.warning(f"[Matting] 孤儿收养跳过: {_ae}")
    _matting_drain_soon(max_wait=5.0)         # 停机期攒下的队列,开机接着跑

    async def _bg_matting_reconcile():
        """录播增强队列对账器(30s)：兜底一切事件触发漏网——推流进程崩溃(而非
        正常 stop)、drain 线程等待超时、hub 收养孤儿流后停播等,队列永不卡死。
        统一走 drain_soon(含显存租约)，与事件触发路径行为一致。"""
        while True:
            await asyncio.sleep(30)
            try:
                if _matting_queue and not _matting_streaming() \
                        and not (_matting_proc and _matting_proc.poll() is None):
                    _matting_drain_soon(max_wait=5.0)
            except Exception:
                pass

    _bg_task      = asyncio.create_task(_bg_cleanup())
    _bg_matq      = asyncio.create_task(_bg_matting_reconcile())
    _bg_metrics   = asyncio.create_task(_bg_metrics_save())   # P16-2
    _bg_teleday   = asyncio.create_task(_bg_telemetry_daily())  # P1 每日心跳+用量(opt-in)
    _bg_health    = asyncio.create_task(_bg_health_monitor())  # L2-1
    _bg_vram      = asyncio.create_task(_bg_vram_autopilot())  # L5-2
    _bg_ops       = asyncio.create_task(_bg_ops_persist())     # Phase#3 运维指标落盘
    _bg_lease     = asyncio.create_task(_bg_gpu_lease_reaper())  # 跨机显存互斥：租约超时自动回收
    _bg_shwatch   = asyncio.create_task(_bg_stream_health_watch())  # P3-C②③ 开播健康守护+时间线
    _bg_stab      = asyncio.create_task(_bg_stability_sentinel())  # P12 稳定性哨兵(重启回归→告警)
    _bg_swapcore  = asyncio.create_task(_bg_swapcore_watch())      # P14 换脸核发布哨兵(512有新货→告警)
    _bg_devautosw = asyncio.create_task(_bg_dev_autoswitch())      # P6-1 设备缺席自动热切(默认关,开关持久化)
    _bg_devweekly = asyncio.create_task(_bg_devflow_weekly())      # P6-2 设备自愈漏斗周报(有 webhook 才发)
    _bg_reparch   = asyncio.create_task(_bg_report_archive())      # 看板v3 战报夜间归档(可回溯运营周志)
    _bg_dashqual  = asyncio.create_task(_bg_dashboard_quality_sentinel())  # 看板v4 听感/自然度告警外发
    _bg_reppush   = asyncio.create_task(_bg_report_push())         # 看板v6 日报卡片推送(有 webhook 才发)
    _bg_vpsync    = asyncio.create_task(_vp_sync_loop())            # P12 音色订阅定时同步(无订阅=空转极廉)
    _bg_livesched = asyncio.create_task(_bg_live_schedule())        # P14-A1 直播排班对账(无排班=空转极廉)
    # Song-P5: 任务持久化回载（重启续办）→ 后台对账（不靠前端轮询也收尾）+ MV 出片 worker
    try:
        await _song_store_hydrate()
    except Exception as _sse:
        _logger.warning(f"[SongStore] 回载异常(从空开始): {_sse}")
    _bg_songrec   = asyncio.create_task(_bg_song_reconcile())
    _bg_mvworker  = asyncio.create_task(_bg_mv_worker())

    # 全新装机：角色库为空则一次性播种「启动角色包」(占位形象+音色)，让开箱即有可用角色。
    #   幂等 + 尽力而为(异常不拦启动)；须在自动激活之前，好让下面挑到第一个示例角色。
    try:
        _seed_starter_profiles()
    except Exception as _sse:
        print(f"[Hub] 启动角色包播种调用异常(忽略): {_sse}")

    # 启动自动重激活：重启后立即预热最近激活的角色（开场白/垫话缓存 + spk/Fish/口型），
    #   使冷启后第一批对话即享垫话掩盖与缓存命中，而非要用户手动点一次「激活」。
    async def _auto_activate():
        if os.environ.get("HUB_AUTO_ACTIVATE", "1") != "1":
            return
        await asyncio.sleep(3.0)        # 让各 TTS/LLM 子服务先就绪
        target = ""
        try:
            if ACTIVE_PROFILE_FILE.exists():
                target = ACTIVE_PROFILE_FILE.read_text(encoding="utf-8").strip()
        except Exception:
            target = ""
        if target not in _profiles:     # 无记录/已删除 → 退回首个角色
            target = next(iter(_profiles), "")
        if not target:
            return
        try:
            await activate_profile(target, auto=True)   # P3: 机器激活不计"常用"
            print(f"[Hub] 启动自动激活角色: {target}（预合成垫话/缓存已排程）")
        except Exception as exc:
            print(f"[Hub] 启动自动激活失败: {exc}")

    async def _crl_poll_loop():
        """可选：周期在线拉取吊销名单（离线优先——未配置在线源则不启，零联网）。
        urllib 阻塞 → to_thread；best-effort，任何异常都不影响主进程；命中更新即时生效。"""
        if _license is None:
            return
        try:
            if not _license.crl_source_configured():   # 未配置在线源 → 不轮询（离线交付零联网）
                return
        except Exception:
            return
        try:
            interval = max(300, int(os.environ.get("AVATARHUB_CRL_POLL_SEC", "3600")))
        except Exception:
            interval = 3600
        print(f"[Hub][CRL] 已启用在线吊销名单轮询：每 {interval}s（离线优先，best-effort）")
        await asyncio.sleep(20.0)       # 启动后稍等，避开开机拥塞
        while True:
            try:
                r = await asyncio.to_thread(_license.fetch_crl_online)
                if r.get("applied"):
                    print(f"[Hub][CRL] 吊销名单已更新 updated={r.get('updated')} 来源={r.get('source')}")
                elif not r.get("ok") and r.get("error"):
                    print(f"[Hub][CRL] 拉取未成功(忽略): {r.get('error')}")
            except Exception as _ce:
                print(f"[Hub][CRL] 在线拉取异常(忽略): {_ce}")
            await asyncio.sleep(interval)

    async def _license_refresh_loop():
        """可选：周期按机器指纹在线刷新授权（管理后台续费/升档后自动生效，无需客户重输码）。
        与 CRL 同哲学的离线优先——仅在【已激活(有 license.key)且已配激活服务器】时启用；
        纯试用/开发机不联网。单调闸门在 license.refresh_online 内（背景刷新绝不降级）。
        best-effort：任何异常/联网失败都不影响主进程与既有授权。"""
        if _license is None:
            return
        try:
            if not _license.refresh_configured():   # 未激活或未配服务器 → 不刷（离线交付零联网）
                return
        except Exception:
            return
        try:
            interval = max(600, int(os.environ.get("AVATARHUB_LICENSE_REFRESH_SEC", "3600")))
        except Exception:
            interval = 3600
        print(f"[Hub][授权] 已启用授权在线刷新：每 {interval}s（续费/升档后台改动自动拉取生效）")
        await asyncio.sleep(30.0)       # 启动后稍等，避开开机拥塞（并让 CRL 先跑）
        while True:
            try:
                ok, res = await asyncio.to_thread(_license.refresh_online)
                if ok:
                    print(f"[Hub][授权] 已刷新到更优授权：{getattr(res, 'status', '')}/"
                          f"{getattr(res, 'edition', '')} · {getattr(res, 'message', '')}")
                    _lic_audit("在线刷新", True,
                               "档位 %s · 到期 %s" % (getattr(res, "edition", "?"),
                                ("永久" if not getattr(res, "expires_ts", 0)
                                 else time.strftime("%Y-%m-%d", time.localtime(res.expires_ts)))))
            except Exception as _re:
                print(f"[Hub][授权] 在线刷新异常(忽略): {_re}")
            await asyncio.sleep(interval)

    _opener_cache_load_all()        # 暖启：盘上开场白缓存先入内存，重启即享命中/垫话掩盖
    if _license is not None:        # 授权状态上报（仅日志，软降级不拦截）
        try:
            _rmsg = _license.trial_autorestore_if_due()   # P11 试签到期→开机自愈还原正式授权
            if _rmsg:
                print(f"[Hub] 授权: {_rmsg}")
                _lic_audit("自动还原", True, _rmsg)
            _ls = _license.load_state(force=True)
            _enf = "强制" if _license.enforcing() else "不强制(仅评估)"
            print(f"[Hub] 授权: {_ls.status}/{_ls.edition} · {_ls.message} · 模式={_enf} · 机器={_ls.this_machine}")
            if _license.enforcing() and not _ls.valid:
                print(f"[Hub][授权告警] 已开启强制且授权无效 → 高级能力(HD/多副本)将受限。")
        except Exception as _le:
            print(f"[Hub] 授权状态读取失败(按试用处理): {_le}")
    _bg_activate = asyncio.create_task(_auto_activate())
    _bg_crl = asyncio.create_task(_crl_poll_loop())   # 3-F: 可选在线吊销名单轮询（未配源=空转即退）
    _bg_licref = asyncio.create_task(_license_refresh_loop())   # 授权正向拉取：续费/升档后台改动自动生效（未激活/未配源=空转即退）
    # 身份放大 anchor：延迟推送(等换脸服务就绪)，让辨识度放大在开播前即可用
    def _delayed_anchor():
        try:
            time.sleep(20); _push_id_anchor_async()
        except Exception:
            pass
    threading.Thread(target=_delayed_anchor, daemon=True).start()
    await _conv_init_pool_aware_admission()   # P-Conc5/6: 池感知准入 + 多卡探活(auto K 自适应)
    if _audience is not None:                  # P-Conc8: 观众自动应答循环（默认空转，运行时可开）
        global _audience_auto_task, _wall_ws_task, _audience_persist_task
        _audience_state_load()                 # P-Conc13: 先回填上次现场（近 TTL 内重启不丢队列/正在作答卡）
        _audience_auto_task = asyncio.create_task(_audience_auto_loop())
        _wall_ws_task = asyncio.create_task(_wall_ws_loop())   # P-Conc9b: 公屏实时推送
        if _AUDIENCE_PERSIST_ACTIVE:           # P-Conc13: 周期落盘（脏检查，空闲零写）
            _audience_persist_task = asyncio.create_task(_audience_persist_loop())
    yield
    # 优雅关闭
    _bg_task.cancel()
    _bg_metrics.cancel()           # P16-2
    _bg_health.cancel()            # L2-1
    try:
        _bg_crl.cancel()           # 3-F: 停在线吊销名单轮询
    except Exception:
        pass
    if _svc_probe_task is not None:   # P-Conc6: 停多卡探活循环
        _svc_probe_task.cancel()
    if _audience_auto_task is not None:   # P-Conc8: 停观众自动应答循环
        _audience_auto_task.cancel()
    if _wall_ws_task is not None:         # P-Conc9b: 停公屏推送循环
        _wall_ws_task.cancel()
    if _audience_persist_task is not None:   # P-Conc13: 停周期落盘 + 关机前兜底最后一次
        _audience_persist_task.cancel()
        try:
            _audience_state_save(force=True)
        except Exception:
            pass
    _save_metrics_snapshot()       # P16-2: 关机前最后写盘
    await http_pool.aclose()
    if health_pool is not None:
        await health_pool.aclose()
    _history_executor.shutdown(wait=False)  # P5-6: 不阅待待完成的写入任务
    global _profiles_conn
    if _profiles_conn is not None:           # P7-4: 关闭持久连接
        _profiles_conn.close()
        _profiles_conn = None

app = FastAPI(title="AvatarHub", version="1.0", lifespan=lifespan)

# 崩溃匿名上报（P0 遥测，2026-07-13）：只挂未捕获异常钩子（栈签名级、脱敏、24h 去重、
# 默认开可关）；模块缺失/旧部署 = 完全无感。详见 telemetry_client.py 红线注释。
try:
    import telemetry_client as _tc
    _tc.install("hub")
except Exception:
    pass

# 联网注册（后台机器名单数据源）：启动后台上报一份机器管理信息（指纹/规格/版本/档位），
# 让厂商后台自动建档、保持 last_seen 新鲜。管理通道非内容，可 AVATARHUB_ADMIN_REGISTER=0 关。
try:
    import admin_client as _ac
    _ac.install("hub")
except Exception:
    pass

# CORS: 默认仅本机；生产可设环境变量 AVATARHUB_CORS_ORIGINS=http://192.168.1.x:9000
_CORS_ORIGINS = [o.strip() for o in os.environ.get(
    "AVATARHUB_CORS_ORIGINS",
    "http://127.0.0.1:9000,http://localhost:9000,http://127.0.0.1:3000,http://localhost:3000"
).split(",") if o.strip()]
app.add_middleware(CORSMiddleware,
                   allow_origins=_CORS_ORIGINS,
                   allow_methods=["GET", "POST", "PUT", "DELETE", "OPTIONS"],
                   allow_headers=["*"])
app.add_middleware(GZipMiddleware, minimum_size=1024)   # P3-D: 带宽节省

# Request-ID 中间件：透传/生成 X-Request-ID + 设入 ContextVar使日志自动携带 (P2-B/P4-C)
@app.middleware("http")
async def _request_id_middleware(request: Request, call_next):
    rid = request.headers.get("X-Request-ID") or uuid.uuid4().hex[:12]
    _request_id_ctx.set(rid)           # P4-C: 注入当前请求上下文
    response = await call_next(request)
    response.headers["X-Request-ID"] = rid
    return response

# ── 管理面鉴权（可选，默认关闭以兼容现网）──────────────────────────────
# 威胁模型：同局域网"其它机器"可任意改 /api/config、CRUD 角色、克隆声音、操纵服务。
# 设 AVATARHUB_API_TOKEN 后启用：写操作(POST/PUT/PATCH/DELETE) 与敏感读端点需令牌
# （cookie ah_token / 头 X-AH-Token / 查询 ah_token）。默认信任本机回环(127.0.0.1)，
# 使本机测试/脚本无需令牌即可工作；仅对"非回环来源"强制——精准封堵跨机攻击面。
# AVATARHUB_AUTH_TRUST_LOOPBACK=0 可关闭回环豁免（全量强制，用于验证/更严环境）。
def _read_api_token() -> str:
    """管理面令牌：优先 env AVATARHUB_API_TOKEN；否则回退 secrets/api_token.txt
    （harden.bat 生成后重启即启用，与子服务令牌同款「一键加固」体验）。二者皆无=不启用(零回归)。"""
    t = os.environ.get("AVATARHUB_API_TOKEN", "").strip()
    if t:
        return t
    try:
        f = Path(rf"{_BASE}\secrets\api_token.txt")
        if f.exists():
            return f.read_text(encoding="utf-8").strip()
    except Exception:
        pass
    return ""


_API_TOKEN = _read_api_token()
_AUTH_TRUST_LOOPBACK = os.environ.get("AVATARHUB_AUTH_TRUST_LOOPBACK", "1") != "0"
# 绑定地址：默认 0.0.0.0（局域网可达，兼容现网/手机端/多机）。设 AVATARHUB_BIND=127.0.0.1 →
# 仅本机可达，是「对外零暴露」的最强物理隔离（对外经反代/SSH 隧道）。安全体检据此判定暴露面。
_BIND_HOST = (os.environ.get("AVATARHUB_BIND", "").strip() or "0.0.0.0")
# 敏感读：会泄漏令牌/全量数据 或 等同管理动作(铸造分享链)的 GET 也要鉴权
_AUTH_SENSITIVE_GET = ("/api/config", "/api/share/ops_link",
                       "/api/share/ops_signlink", "/api/export_profiles",
                       "/api/clientlog/recent", "/api/selfcheck", "/api/ops/selfcheck",
                       "/api/security/posture")
# 纯公开前缀（含写操作也放行）：静态资源、分享只读页、购买/下单/下载前门
_AUTH_OPEN_PREFIX = ("/static", "/favicon", "/share/ops", "/order", "/pricing", "/download")
# 自带独立 token 的精确放行端点（只读看板数据 / 前端错误上报-只写不可读 / 购买前门下单）
_AUTH_OPEN_EXACT = {"/api/share/ops", "/api/auth/status", "/api/license/status", "/api/clientlog", "/api/ui/event",
                    "/api/order/plans", "/api/order/create", "/api/release/manifest"}
_LOOPBACK_HOSTS = {"127.0.0.1", "::1", "localhost", "::ffff:127.0.0.1"}


def _auth_required(method: str, path: str) -> bool:
    """该请求是否需要令牌（与来源无关，仅按方法+路径判定敏感性）。"""
    if method == "OPTIONS":
        return False
    if path in _AUTH_OPEN_EXACT:
        return False
    if any(path == p or path.startswith(p + "/") or path.startswith(p) for p in _AUTH_OPEN_PREFIX):
        return False
    if method in ("GET", "HEAD"):
        # 敏感读：精确匹配，避免前缀误伤（如 /api/share/ops_link 不应被 /api/share/ops 放行）
        return path in _AUTH_SENSITIVE_GET
    return True   # 其余所有写操作


@app.middleware("http")
async def _auth_middleware(request: Request, call_next):
    if _API_TOKEN:
        client_host = (request.client.host if request.client else "") or ""
        is_loopback = client_host in _LOOPBACK_HOSTS
        if not (is_loopback and _AUTH_TRUST_LOOPBACK):
            if _auth_required(request.method, request.url.path):
                import hmac as _h
                tok = (request.headers.get("X-AH-Token")
                       or request.cookies.get("ah_token")
                       or request.query_params.get("ah_token") or "")
                if not (tok and _h.compare_digest(str(tok), _API_TOKEN)):
                    return JSONResponse(
                        {"ok": False, "detail": "需要运维令牌（未授权）。请在看板设置令牌后重试。"},
                        status_code=401)
    return await call_next(request)


# ── 授权软着陆闸门（2026-07-13 商业化收口）───────────────────────────
# 试用/授权到期（且处于强制模式）时，只挡「生成新内容」的入口；资产读取/导出/
# 停止/配置/激活一律放行——到期不绑架数据，续费即恢复（软着陆哲学）。
# 用中间件而非逐端点装饰：生成入口后续增删时闸门自动覆盖同前缀路由，不怕遗漏。
_GEN_BLOCK_EXACT = {
    "/api/converse", "/api/converse/stream",   # 对话生成（其余 /api/converse/* 是配置/记忆管理，放行）
    "/api/tts_only", "/api/voice_clone",       # 纯 TTS 与克隆音创建
}
_GEN_BLOCK_PREFIX = (
    "/avatar/speak",            # 数字人开口全家（含 /stream /batch）
    "/api/stream_out/start", "/api/stream_out/quick_start",   # 开播（stop 永不挡）
)


@app.middleware("http")
async def _license_gate_middleware(request: Request, call_next):
    p = request.url.path
    if request.method == "POST" and (
            p in _GEN_BLOCK_EXACT or any(p.startswith(x) for x in _GEN_BLOCK_PREFIX)):
        try:
            blocked = _license is not None and _license.generation_blocked()
        except Exception:
            blocked = False    # 授权模块异常绝不误伤生产（fail-open：宁可漏挡不可错杀）
        if blocked:
            try:
                msg = _license.blocked_message()
            except Exception:
                msg = "授权已到期，请激活后继续使用。"
            return JSONResponse(
                {"ok": False, "error": "license_expired", "message": msg,
                 "action": "activate"},
                status_code=403)
    return await call_next(request)


def _ws_auth_ok(ws: WebSocket) -> bool:
    """WebSocket 握手鉴权：@app.middleware("http") **不覆盖 WS 握手**，故敏感控制面 WS
    须在 accept() 前显式校验。与 _auth_middleware 同策略：未设令牌→放行(零回归)；回环受信→放行；
    否则需 ah_token。浏览器 WS 无法设自定义头，故取 cookie ah_token / 查询 ah_token
    （同源页面的 cookie 会随 WS 握手自动带上，故设令牌后看板 /ui 的 WS 仍照常连）。"""
    if not _API_TOKEN:
        return True
    try:
        client_host = (ws.client.host if ws.client else "") or ""
    except Exception:
        client_host = ""
    if _AUTH_TRUST_LOOPBACK and client_host in _LOOPBACK_HOSTS:
        return True
    import hmac as _h
    try:
        tok = (ws.headers.get("X-AH-Token") or ws.cookies.get("ah_token")
               or ws.query_params.get("ah_token") or "")
    except Exception:
        tok = ""
    return bool(tok and _h.compare_digest(str(tok), _API_TOKEN))

# 托管 static 目录（前后端分离）
# [2026-07-16 缓存治理] StaticFiles 原样挂载不带 Cache-Control → 浏览器启发式缓存把旧
# hub.js/brand.css 粘住,与 no-store 的 /ui 新页面混载(实锤:侧栏渲染出字面 undefined、
# 顶栏 SVG 无样式变 300×150 黑块)。改为 no-cache：仍带 ETag,未变时 304 零流量,变了立即生效。
class _NoCacheStatic(StaticFiles):
    async def get_response(self, path, scope):
        resp = await super().get_response(path, scope)
        resp.headers["Cache-Control"] = "no-cache"
        return resp

STATIC_DIR = Path(rf"{_BASE}\static")
if STATIC_DIR.exists():
    app.mount("/static", _NoCacheStatic(directory=str(STATIC_DIR)), name="static")


# [2026-07-16 窗口图标] /favicon.ico 兜底：Edge/Chrome --app 应用窗口的任务栏/标题栏图标
# 取自页面 favicon 的位图版本；此前只有 SVG favicon 且 /favicon.ico 404，Chromium 光栅化
# 不到位图 → 全部窗口退化成 Edge 图标。优先 assets/app.ico（多尺寸，与桌面启动台同一母版），
# 缺失回退 static/app-icon-256.png；都没有才 404。/favicon 前缀已在鉴权白名单。
@app.get("/favicon.ico", include_in_schema=False)
def favicon_ico():
    ico = Path(rf"{_BASE}\assets\app.ico")
    if ico.exists():
        return FileResponse(str(ico), media_type="image/x-icon",
                            headers={"Cache-Control": "no-cache"})
    png = STATIC_DIR / "app-icon-256.png"
    if png.exists():
        return FileResponse(str(png), media_type="image/png",
                            headers={"Cache-Control": "no-cache"})
    return Response(status_code=404)

# ── WebSocket 连接池 (P3-C: set+gather 并发安全) ───────────────────
ws_clients: set[WebSocket] = set()

# P22-2: 长任务进度存储（批量/视频等耗时任务）
_task_progress: dict[str, dict] = {}  # {task_id: {"type": "batch|video", "total": N, "done": M, ...}}

async def broadcast(data: dict):
    if not ws_clients:
        return
    clients = list(ws_clients)          # snapshot 防止迭代期间并发修改

    async def _safe_send(ws: WebSocket):
        """P6-1: 单条发送加超时，慢/断线客户端不阻塞其余推送"""
        try:
            await asyncio.wait_for(ws.send_json(data), timeout=3.0)
        except Exception as e:
            return e

    results = await asyncio.gather(*[_safe_send(ws) for ws in clients],
                                   return_exceptions=True)
    for ws, r in zip(clients, results):
        if isinstance(r, Exception):
            ws_clients.discard(ws)

async def broadcast_task_progress(task_id: str, progress: dict):
    """P22-2: 推送长任务进度到所有WebSocket客户端"""
    _task_progress[task_id] = {**progress, "task_id": task_id, "ts": time.time()}
    await broadcast({"event": "task_progress", **progress, "task_id": task_id})

# ── 角色数据 ──────────────────────────────────────────────────────
_profiles: dict = {}        # { name: {face_b64, voice_name, hair_style, description} }
_active_profile: str = ""   # 当前激活的角色名
_profiles_version: int = 0  # 每次 profiles 变更时递增（WS实时同步用）
# P13: /activate 幂等防抖状态。手机页等客户端会把激活打成连发(实测 12s 内 9 次)，
#   每次全量跑预热链(切脸+跨机 spk/fish 预热+开场白缓存重载+口型预计算) →
#   Hub RAM 高水位棘轮 + 远端 TTS 被预热请求挤占。同角色+配置版本未变+窗口内
#   的重复激活直接短路。角色内容变更会 bump _profiles_version → 天然穿透防抖。
_ACTIVATE_LAST: dict = {}   # {"key": (name, profiles_version), "ts": monotonic}
_ACTIVATE_DEBOUNCE_S = float(os.environ.get("AVATARHUB_ACTIVATE_DEBOUNCE_S", "30"))
_PROFILES_LOCK = asyncio.Lock()  # P3-A: 防并发写保护
_TTS_LOCK = asyncio.Lock()

# B1: 角色「活体/口型人脸」预计算就绪态。首激活新角色要 ~17s(landmark+LivePortrait+latent)，
# 此前是静默后台跑→前端像「卡住」。这里显性化 preparing/ready/failed，激活时广播 + 端点可查，
# 前端可显示「数字人准备中…」并在 face_ready 事件到达后解除。磁盘缓存命中的角色直接 ready(秒级)。
_face_ready: dict[str, str] = {}
# B1+: 人脸预计算 ETA 自校准（EMA of 实测耗时，秒），驱动前端确定性进度条。冷启动给经验默认 ~18s。
_face_prep_eta_s: float = 18.0
# P-Harden2(2026-07-07 事故): 激活路径预计算预算——依赖服务挂死时预计算可悬挂 300s+120s 串行超时，
# UI 停在「准备中 92%」像死机。超预算即先转 failed(reason=timeout)：前端立刻解除准备中、
# 按静态口型运行并给「重试」；预计算本体后台继续跑，跑成再自动补翻 ready(下次激活/首句即热)。
_FACE_PREP_BUDGET_S = float(os.environ.get("AVATARHUB_FACE_PREP_BUDGET_S", "60"))
# P4: 记住每个角色最近一次失败归因(service_off/error)，供 /api/profile/ready 轮询兜底回填——
# 让"刷新页面/WS 重连"后仍能立即渲染正确降级态(静态口型 vs 可重试)，而非等下次激活事件。
_face_fail_reasons: dict[str, str] = {}
# P5: 就绪态可观测——自启动以来的人脸预计算统计(计数/耗时分布/归因)，接入 /api/metrics 与 /ops。
# 关键设计：真实失败率只计 error(真异常)；service_off(刻意降级)透明计数但不拉高失败率、不触发告警，
# 与前端「去恐慌化」一致——否则本部署会显示 ~100% "失败率"，运营徒增虚警。
_face_stats: dict = {"ready": 0, "failed": 0, "fail_reasons": {}, "durations": deque(maxlen=200)}


async def _set_face_ready(name: str, state: str, **extra):
    """更新角色就绪态并广播(WS)。state: preparing/ready/failed。
    extra: 富字段(如 elapsed_s)——供前端渲染确定性进度 / 后端自校准 ETA。"""
    _face_ready[name] = state
    # P4: 落地失败归因(供刷新后轮询回填)；就绪则清除历史失败痕迹。
    if state == "failed":
        _face_fail_reasons[name] = extra.get("reason", "")
    elif state == "ready":
        _face_fail_reasons.pop(name, None)
    # P5: 终态计数(本函数是所有 ready/failed 的唯一入口，且均在事件循环上执行——无需加锁)。
    if state == "ready":
        _face_stats["ready"] += 1
        _es = extra.get("elapsed_s")
        if isinstance(_es, (int, float)) and _es > 0:
            _face_stats["durations"].append(float(_es))
    elif state == "failed":
        _face_stats["failed"] += 1
        _r = extra.get("reason") or "unknown"
        _face_stats["fail_reasons"][_r] = _face_stats["fail_reasons"].get(_r, 0) + 1
    try:
        await broadcast({"event": "face_ready", "name": name, "state": state, **extra})
    except Exception:
        pass


def _face_fail_reason() -> str:
    """人脸预计算失败归因：lipsync 未受监管(实时换脸模式，故意不起)→ service_off(预期降级，前端不报错)；
    否则 error(真异常，值得重试)。让"预期降级"讲成正常态、仅对真异常告警并提供重试。"""
    return "service_off" if os.environ.get("HUB_SUP_LIPSYNC", "1") == "0" else "error"


async def _face_fail_reason_live() -> str:
    """P-Harden2: 失败归因先在线探测——lipsync 可达却失败 = 真异常(error，前端亮黄标+可重试)。
    此前只看 HUB_SUP_LIPSYNC 开关：服务明明在跑但挂死/超时，也被讲成 service_off(「正常降级」绿标)，
    真故障被压成不吓人的样子，排障被误导(2026-07-07 切角色卡死事故)。探测失败再回退静态判定。"""
    try:
        if health_pool is not None:
            r = await health_pool.get(f"{SERVICES['lipsync']}/health", timeout=3.0)
            if r.status_code == 200:
                return "error"
    except Exception:
        pass
    return _face_fail_reason()


def _face_prep_metrics() -> dict:
    """人脸预计算可观测快照(自启动累计)。real_fail_rate 计 error+timeout(真异常)——service_off 是刻意降级，
    不应拉高失败率/触发告警(与前端「去恐慌化」一致)；service_off 单列为 degraded_rate 透明可见。
    dur_p50/p95 来自最近成功就绪的实测耗时(EMA 给不了分位)，供容量规划。"""
    durs = sorted(_face_stats["durations"])

    def _pct(p):
        if not durs:
            return None
        i = min(len(durs) - 1, max(0, int(round((p / 100.0) * (len(durs) - 1)))))
        return round(durs[i], 1)

    reasons = dict(_face_stats["fail_reasons"])
    ready = _face_stats["ready"]
    failed = _face_stats["failed"]
    settled = ready + failed
    # P-Harden2: timeout(预算超时) 与 error 一样是真异常，计入真实失败率
    real_fail = reasons.get("error", 0) + reasons.get("timeout", 0)
    return {
        "ready": ready,
        "failed": failed,
        "fail_reasons": reasons,
        "settled": settled,
        "preparing_now": sum(1 for v in _face_ready.values() if v == "preparing"),
        "eta_s": round(_face_prep_eta_s, 1),
        "dur_p50_s": _pct(50),
        "dur_p95_s": _pct(95),
        "dur_samples": len(durs),
        "real_fail_rate": round(real_fail / settled, 3) if settled else 0.0,
        "degraded_rate": round(reasons.get("service_off", 0) / settled, 3) if settled else 0.0,
    }

# ── 角色敏感数据静置加密（生物特征合规）────────────────────────────────
# voice_b64/face_b64 等真人生物特征明文存库属隐私高危。开启后整条 profile JSON 以
# Fernet(AES128-CBC+HMAC) 加密落盘；内存仍为明文，所有消费方零改动。
# 开关：设 AVATARHUB_ENCRYPT_PROFILES=1 或 AVATARHUB_SECRET_KEY 即启用（默认关，兼容现网）。
# 密钥优先级：env AVATARHUB_SECRET_KEY > secrets/profile_key.key（首启自动生成并持久化）。
# ⚠️ 密钥丢失将无法解密已加密数据——请单独备份 secrets/profile_key.key！
_ENC_MARKER = "enc:fernet:v1:"
_PROFILE_KEY_FILE = Path(rf"{_BASE}\secrets\profile_key.key")


def _resolve_profile_cipher():
    want = os.environ.get("AVATARHUB_ENCRYPT_PROFILES", "").strip().lower() in ("1", "true", "yes", "on")
    env_key = os.environ.get("AVATARHUB_SECRET_KEY", "").strip()
    if not (want or env_key):
        return None
    try:
        from cryptography.fernet import Fernet
    except Exception as e:
        _logger.error("[Crypto] 已请求加密但 cryptography 不可用：%s（降级明文）" % e)
        return None
    key = env_key
    if not key:
        try:
            if _PROFILE_KEY_FILE.exists():
                key = _PROFILE_KEY_FILE.read_text(encoding="utf-8").strip()
            else:
                key = Fernet.generate_key().decode("ascii")
                _PROFILE_KEY_FILE.parent.mkdir(parents=True, exist_ok=True)
                _PROFILE_KEY_FILE.write_text(key, encoding="utf-8")
                _logger.warning("[Crypto] 已生成角色加密密钥 secrets/profile_key.key —— 请单独备份，丢失将无法解密！")
        except Exception as e:
            _logger.error("[Crypto] 密钥加载/生成失败：%s（降级明文）" % e)
            return None
    try:
        return Fernet(key.encode("ascii") if isinstance(key, str) else key)
    except Exception as e:
        _logger.error("[Crypto] 密钥无效：%s（降级明文）" % e)
        return None


_PROFILE_CIPHER = _resolve_profile_cipher()
if _PROFILE_CIPHER is not None:
    _logger.info("[Crypto] 角色敏感数据静置加密：已启用")


def _enc_blob(s: str) -> str:
    """加密一条 profile JSON（未启用则原样返回，保持明文兼容）。"""
    if _PROFILE_CIPHER is None:
        return s
    try:
        return _ENC_MARKER + _PROFILE_CIPHER.encrypt(s.encode("utf-8")).decode("ascii")
    except Exception as e:
        _logger.error("[Crypto] 加密失败，回退明文：%s" % e)
        return s


def _dec_blob(s: str) -> str:
    """解密；明文(历史/未开启)原样返回；已加密但无密钥则报错(失败关闭，绝不当明文用)。"""
    if not isinstance(s, str) or not s.startswith(_ENC_MARKER):
        return s
    if _PROFILE_CIPHER is None:
        raise RuntimeError("角色数据已加密但未配置密钥：请设 AVATARHUB_SECRET_KEY 或恢复 secrets/profile_key.key")
    return _PROFILE_CIPHER.decrypt(s[len(_ENC_MARKER):].encode("ascii")).decode("utf-8")


def _is_encrypted_blob(s) -> bool:
    return isinstance(s, str) and s.startswith(_ENC_MARKER)


def _profile_key_bytes():
    """返回当前角色加密所用的原始 Fernet 密钥（用于黄金包/导出件同密钥加密）；
    未启用加密则返回 None（导出保持明文，向后兼容）。"""
    if _PROFILE_CIPHER is None:
        return None
    env_key = os.environ.get("AVATARHUB_SECRET_KEY", "").strip()
    if env_key:
        return env_key
    try:
        if _PROFILE_KEY_FILE.exists():
            return _PROFILE_KEY_FILE.read_text(encoding="utf-8").strip()
    except Exception:
        pass
    return None


# ── Profiles SQLite 持久化层 (P5-2) ─────────────────────────────────────
_profiles_conn: _sqlite3.Connection | None = None  # P7-4: 模块级单例连接

def _profiles_db_conn() -> _sqlite3.Connection:
    """P7-4: 持久连接单例，避免每次CRUD重建~0.5ms的连接开销"""
    global _profiles_conn
    if _profiles_conn is None:
        _profiles_conn = _sqlite3.connect(str(PROFILES_DB), check_same_thread=False)
        _profiles_conn.execute("PRAGMA journal_mode=WAL")
        _profiles_conn.execute("PRAGMA synchronous=NORMAL")
    return _profiles_conn

def _init_profiles_db():
    """P5-2: 创建 profiles 表，WAL 模式，自动从 JSON 迁移"""
    with _profiles_db_conn() as conn:
        conn.execute("""
            CREATE TABLE IF NOT EXISTS profiles (
                name       TEXT PRIMARY KEY,
                data       JSON NOT NULL,
                updated_at REAL NOT NULL
            )
        """)
        conn.commit()

def _save_profile(name: str) -> bool:
    """P5-2: 单条 UPSERT，替代全量 JSON 重写；P6-2: 返回 bool，失败时回退 version"""
    global _profiles_version
    _profiles_version += 1
    data = _enc_blob(json.dumps(_profiles[name], ensure_ascii=False))
    try:
        with _profiles_db_conn() as conn:
            conn.execute(
                "INSERT OR REPLACE INTO profiles (name, data, updated_at) VALUES (?,?,?)",
                (name, data, time.time())
            )
            conn.commit()
        return True
    except Exception as e:
        _profiles_version -= 1  # P6-2: DB失败则回退版本号
        print(f"[Hub] 单条保存角色失败: {e}")
        return False

def _delete_profile_db(name: str) -> bool:
    """P5-2: 单条 DELETE；P6-2: 返回 bool，失败回退 version"""
    global _profiles_version
    _profiles_version += 1
    try:
        with _profiles_db_conn() as conn:
            conn.execute("DELETE FROM profiles WHERE name=?", (name,))
            conn.commit()
        return True
    except Exception as e:
        _profiles_version -= 1
        print(f"[Hub] 删除角色DB失败: {e}")
        return False

def _rename_profile_db(old_name: str, new_name: str) -> bool:
    """P5-2: 重命名单事务 DELETE+INSERT；P6-2: 返回 bool，失败回退 version"""
    global _profiles_version
    _profiles_version += 1
    data = _enc_blob(json.dumps(_profiles[new_name], ensure_ascii=False))
    try:
        with _profiles_db_conn() as conn:
            conn.execute("DELETE FROM profiles WHERE name=?", (old_name,))
            conn.execute(
                "INSERT OR REPLACE INTO profiles (name, data, updated_at) VALUES (?,?,?)",
                (new_name, data, time.time())
            )
            conn.commit()
        return True
    except Exception as e:
        _profiles_version -= 1
        print(f"[Hub] 重命名角色DB失败: {e}")
        return False

# ── P3: 角色「会话级」使用台账（常用音色自动置顶的数据源）────────────────
# 与 /api/profiles/stats(speak_history 逐句计数)刻意分开：一次长通话会写几百句
# speak_history，逐句口径下"常用"永远被最近一次长通话垄断。这里只记会话级动作：
# 激活一次/同传开播一次/通话中切换一次 = 各 +1，才是"用户常拿哪个声音干活"的真信号。
_USAGE_FILE = Path(rf"{_BASE}\profile_usage.json")
_usage_lock = threading.Lock()
_usage_data: dict | None = None


def _usage_all() -> dict:
    """{角色名: {n, ts, k}}；进程内缓存，首访加载。"""
    global _usage_data
    if _usage_data is None:
        try:
            _usage_data = (json.loads(_USAGE_FILE.read_text(encoding="utf-8"))
                           if _USAGE_FILE.exists() else {})
        except Exception as e:
            _logger.warning(f"[usage] profile_usage.json 解析失败，从零开始: {e}")
            _usage_data = {}
    return _usage_data


def _usage_save():
    try:
        _USAGE_FILE.write_text(json.dumps(_usage_all(), ensure_ascii=False, indent=1),
                               encoding="utf-8")
    except Exception as e:
        _logger.warning(f"[usage] 台账写盘失败(计数仍在内存): {e}")


# P5: 指数衰减（Redis LFU 同款思路）。不衰减的话"常用"是终身荣誉榜：
# 半年前狂用 50 次的角色永远压着最近天天用的新角色。周 ×0.9 ≈ 半衰期 6.6 周，
# 连续衰减(按秒折算)避免周边界跳变。
_USAGE_DECAY = 0.9
_WEEK_S = 7 * 86400.0


def _usage_eff(e: dict, now: float | None = None) -> float:
    """衰减后的有效使用次数。存储 n 是"截至 ts 时刻"的值，读取时按距今时长打折。"""
    n = float(e.get("n", 0) or 0)
    ts = float(e.get("ts", 0) or 0)
    if n <= 0 or ts <= 0:
        return max(n, 0.0)
    dt = max(0.0, (now or time.time()) - ts)
    return n * (_USAGE_DECAY ** (dt / _WEEK_S))


def _usage_bump(name: str, kind: str):
    spk = (_profiles.get(name) or {}).get("voicepack_spk") or ""
    if spk:
        _vp_stat_bump(spk, "use")   # P13: 音色库出身的角色，使用量回流运营报表
    with _usage_lock:
        d = _usage_all()
        e = d.setdefault(name, {"n": 0})
        now = time.time()
        # 先把旧账衰减到"现在"再 +1：若只刷新 ts 不折算，一年前攒的 50 次会原地复活
        e["n"] = round(_usage_eff(e, now) + 1, 3)
        e["ts"] = now
        e["k"] = kind          # 最近一次动作类型（排查用，不参与排序）
        # 顺手清掉衰减到近零的死条目（台账就几十条，遍历代价可忽略）
        for k in [k for k, v in d.items() if k != name and _usage_eff(v, now) < 0.05]:
            d.pop(k, None)
        _usage_save()


def _usage_n(name: str) -> float:
    """有效使用次数（含时间衰减）。1 位小数：排序有区分度，前端取整展示。"""
    e = _usage_all().get(name)
    if not e:
        return 0
    v = _usage_eff(e)
    return round(v, 1) if v >= 0.05 else 0


def _usage_rename(old: str, new: str):
    """角色改名时台账跟随（丢了会导致改名后"常用"清零，明星迁移那批就白攒了）。"""
    with _usage_lock:
        d = _usage_all()
        if old in d and new not in d:
            d[new] = d.pop(old)
            _usage_save()


def _usage_drop(name: str):
    with _usage_lock:
        if _usage_all().pop(name, None) is not None:
            _usage_save()


def _save_profiles() -> bool:
    """P5-2: 批量导入用的全量刷新（事务封装）；P7-2: 返回bool，失败回退version"""
    global _profiles_version
    _profiles_version += 1
    try:
        with _profiles_db_conn() as conn:
            conn.execute("DELETE FROM profiles")
            for name, p in _profiles.items():
                conn.execute(
                    "INSERT INTO profiles (name, data, updated_at) VALUES (?,?,?)",
                    (name, _enc_blob(json.dumps(p, ensure_ascii=False)), time.time())
                )
            conn.commit()
        return True
    except Exception as e:
        _profiles_version -= 1
        print(f"[Hub] 批量保存角色失败: {e}")
        return False

def _load_profiles():
    """P5-2: 从cSQLite加载，SQLite不存在时从 JSON 自动迁移"""
    global _profiles
    _init_profiles_db()
    try:
        with _profiles_db_conn() as conn:
            rows = conn.execute(
                "SELECT name, data FROM profiles ORDER BY name"
            ).fetchall()
        if rows:
            _profiles = {}
            plain_names = []          # 当前在库里仍是明文、需加密迁移的角色
            for name, data in rows:
                try:
                    _profiles[name] = json.loads(_dec_blob(data))
                except Exception as de:
                    print(f"[Hub] 角色 {name} 解密/解析失败，已跳过: {de}")
                    continue
                if _PROFILE_CIPHER is not None and not _is_encrypted_blob(data):
                    plain_names.append(name)
            print(f"[Hub] 从cSQLite加载 {len(_profiles)} 个角色")
            if plain_names:           # 一次性把存量明文加密落盘（read时解密、write时加密）
                for n in plain_names:
                    _save_profile(n)
                print(f"[Crypto] 已将 {len(plain_names)} 个存量明文角色加密迁移落盘")
            return
    except Exception as e:
        print(f"[Hub] SQLite加载失败，尝试JSON迁移: {e}")
    # fallback: 自动从 JSON 迁移
    if PROFILES_FILE.exists():
        try:
            _profiles = json.loads(PROFILES_FILE.read_text(encoding='utf-8'))
            print(f"[Hub] 从JSON迁移 {len(_profiles)} 个角色 → SQLite")
            _save_profiles()  # 迁移写入 SQLite
            PROFILES_FILE.rename(PROFILES_FILE.with_suffix('.json.migrated'))
        except Exception as e:
            print(f"[Hub] JSON加载失败: {e}")
            _profiles = {}

_load_profiles()


STARTER_DIR = Path(_BASE) / "data" / "starter_profiles"
_STARTER_MARK = Path(_BASE) / "data" / ".starter_seeded"


def _seed_starter_profiles():
    """全新装机播种「启动角色包」：仅当角色库为空且未播种过时，把 data/starter_profiles/
    里的占位形象+音色一次性写入角色库，让同传/换脸开箱即有可用角色(消灭『无音色样本』)。
    幂等：写库后落 data/.starter_seeded 标记；用户删光示例角色也不会被重新灌回。
    尽力而为——任何异常都不拦启动。占位素材，正式发布可用授权素材替换同名文件。"""
    try:
        if _profiles:                       # 已有角色(老用户升级/已用过) → 不注入示例
            return
        if _STARTER_MARK.exists():           # 播种过一次就不再来(尊重用户后来删空的选择)
            return
        manifest = STARTER_DIR / "starter_profiles.json"
        if not manifest.exists():
            return
        spec = json.loads(manifest.read_text(encoding="utf-8"))
        seeded = []
        for item in (spec.get("profiles") or []):
            name = (item.get("name") or "").strip()
            if not name or name in _profiles:
                continue
            try:
                wav = STARTER_DIR / item.get("voice", "")
                voice_b64 = base64.b64encode(wav.read_bytes()).decode() if wav.is_file() else ""
                ref_text = ""
                rtf = item.get("ref_text_file", "")
                if rtf and (STARTER_DIR / rtf).is_file():
                    ref_text = (STARTER_DIR / rtf).read_text(encoding="utf-8").strip()
                face = STARTER_DIR / item.get("face", "")
                face_b64 = base64.b64encode(face.read_bytes()).decode() if face.is_file() else ""
                if not voice_b64 and not face_b64:
                    continue                 # 素材都缺 → 跳过这条，别建空角色
                _profiles[name] = {
                    "description":     item.get("description", ""),
                    "face_b64":        face_b64,
                    "face_gallery_b64": [],
                    "voice_name":      "",
                    "voice_b64":       voice_b64,
                    "fish_tts_params": {"reference_text": ref_text},
                    "hair_style":      "",
                    "rvc_model":       "",
                    "rvc_settings":    {},
                    "rvc_strict_mode": True,
                    "lipsync_engine":  "",
                    "faceswap_engine": "",
                    "dfm_model":       "",
                    "tts_engine":      item.get("tts_engine", ""),
                    "idle_video":      "",
                    "body_video":      "",
                    "thumbnail_b64":   _generate_thumbnail(face_b64),
                    "created_at":      time.time(),
                    "_starter":        True,   # 出厂示例标记(供 UI 折叠/区分)
                }
                if _save_profile(name):
                    seeded.append(name)
                else:
                    _profiles.pop(name, None)
            except Exception as ie:
                print(f"[Hub] 启动角色包·播种「{name}」失败(跳过): {ie}")
        if seeded:
            try:
                _STARTER_MARK.parent.mkdir(parents=True, exist_ok=True)
                _STARTER_MARK.write_text(str(spec.get("seed_tag") or "starter_v1"),
                                         encoding="utf-8")
            except Exception:
                pass
            print(f"[Hub] 启动角色包已播种 {len(seeded)} 个示例角色: {', '.join(seeded)}")
    except Exception as e:
        print(f"[Hub] 启动角色包播种异常(忽略): {e}")


def _sweep_test_orphan_profiles():
    """P14-1: 启动清扫 e2e 测试残留角色（`_e2e` 前缀=各 E2E 套件的临时占位约定）。
    实锤（2026-07-07）：Hub 被 watchdog/bat 重启打断 E2E 后，`_e2e换声测试` 等残留
    随暖启复活混进真角色库——声测矩阵扫到必假红、还会被 OpenerCache/Preview 白白预热。
    任何测试都不跨 Hub 重启存活，启动时见 `_e2e*` 即孤儿，直接清。"""
    orphans = [n for n in list(_profiles.keys()) if n.startswith("_e2e")]
    for n in orphans:
        _profiles.pop(n, None)
        try:
            _delete_profile_db(n)
        except Exception:
            pass
    if orphans:
        print(f"[Hub] 启动清扫 e2e 残留角色 {len(orphans)} 个: {'、'.join(orphans)}")
    try:   # 上次激活的若正是孤儿，清掉记录避免重启后自动激活一个不存在的角色
        if (ACTIVE_PROFILE_FILE.exists()
                and ACTIVE_PROFILE_FILE.read_text(encoding="utf-8").strip().startswith("_e2e")):
            ACTIVE_PROFILE_FILE.unlink()
    except Exception:
        pass


def _backfill_created_at():
    """⑮：为缺少 created_at 的已有角色用 DB updated_at 回填（一次性迁移）。"""
    missing = [n for n, p in _profiles.items() if not p.get("created_at")]
    if not missing:
        return
    try:
        with _profiles_db_conn() as conn:
            rows = conn.execute(
                "SELECT name, updated_at FROM profiles"
            ).fetchall()
        ts_map = {r[0]: r[1] for r in rows}
    except Exception:
        ts_map = {}
    now = time.time()
    for n in missing:
        _profiles[n]["created_at"] = ts_map.get(n, now)
        _save_profile(n)
    print(f"[Hub] created_at 回填 {len(missing)} 个角色")


_sweep_test_orphan_profiles()
_backfill_created_at()

# ── 缩略图生成 ─────────────────────────────────────────────────────
# 启动时为缺少缩略图的已有角色回填
def _backfill_thumbnails():
    updated_names = []
    for name, p in _profiles.items():
        if p.get("face_b64") and not p.get("thumbnail_b64"):
            thumb = _generate_thumbnail(p["face_b64"])
            if thumb:
                p["thumbnail_b64"] = thumb
                updated_names.append(name)
    if updated_names:
        for n in updated_names:       # P5-2: 只更新确实缺缩略图的那些记录
            _save_profile(n)
        print(f"[Hub] 回填 {len(updated_names)} 个角色缩略图")


def _generate_thumbnail(face_b64: str, size: int = 80) -> str:
    """从人脸 base64 生成小缩略图 JPEG"""
    if not face_b64:
        return ""
    try:
        import io as _io
        from PIL import Image as _Image
        raw = face_b64.split(",", 1)[-1] if "," in face_b64 else face_b64
        img = _Image.open(_io.BytesIO(base64.b64decode(raw)))
        img.thumbnail((size, size))
        buf = _io.BytesIO()
        img.save(buf, format="JPEG", quality=55)
        return base64.b64encode(buf.getvalue()).decode()
    except Exception as e:
        print(f"[Hub] 缩略图生成失败: {e}")
        return ""

_backfill_thumbnails()

# ── 子服务健康检查（并行，最长 2 秒）─────────────────────────────────
_SVC_CACHE: dict = {"data": {}, "ts": 0.0}  # P5-1: TTL缓存，避免WS每次心跳重复阻塞
_SVC_CACHE_TTL = 3.0                         # 心跳间隔5s，3s TTL足够覆盖
_SVC_CACHE_LOCK = threading.Lock()           # P8-1: 单飞锁，防缓存击凲（同时N个请求全触发）

def check_services() -> dict:
    status = {name: False for name in SERVICES}

    def probe(name, url):
        try:
            # RVC API 没有 /health，用 /inputDevices 检测
            endpoint = "/inputDevices" if name == "rvc" else "/health"
            r = requests.get(f"{url}{endpoint}", timeout=1.5)
            status[name] = r.status_code == 200
        except Exception:
            status[name] = False

    threads = [threading.Thread(target=probe, args=(n, u), daemon=True)
               for n, u in SERVICES.items()]
    for t in threads:
        t.start()
    for t in threads:
        t.join(timeout=2)
    return status

def check_services_cached() -> dict:
    """P5-1: 带TTL缓存的健康检查；P8-1: double-checked locking防缓存击穿"""
    now = time.time()
    if _SVC_CACHE["data"] and now - _SVC_CACHE["ts"] < _SVC_CACHE_TTL:
        return _SVC_CACHE["data"]          # fast path: 无锁命中
    with _SVC_CACHE_LOCK:                  # P8-1: 只有第一个线程触发探测
        if _SVC_CACHE["data"] and time.time() - _SVC_CACHE["ts"] < _SVC_CACHE_TTL:
            return _SVC_CACHE["data"]      # 其余线程等锁后命中已刷新的缓存
        result = check_services()
        _SVC_CACHE["data"] = result
        _SVC_CACHE["ts"] = time.time()
    return result

# ── 输入防护常量 (P10-1 / P11-A) ────────────────────────────────────
_B64_LIMIT        = 7_000_000  # P10-1: 5MB二进制≈6.67MB base64，防JSON炸内存
_TEXT_LIMIT       = 2_000      # P10-1: TTS单次文本上限，超长请分段
_BATCH_ITEM_LIMIT = 50         # P11-A1: 单批最多50条，防gather创建海量Task+信号量积压
# P11-A2: profile name 白名单正则（防路径遍历；允许汉字/字母/数字/下划线/连字符/空格，1-64字符）
_PROFILE_NAME_RE  = re.compile(r'^[\w\u4e00-\u9fa5][\w\u4e00-\u9fa5\-\s]{0,62}[\w\u4e00-\u9fa5]$'
                               r'|^[\w\u4e00-\u9fa5]$')

def _check_profile_name(name: str) -> None:
    """P11-A2: 校验 profile name，不合法则 raise HTTPException(400)"""
    if not name or not _PROFILE_NAME_RE.match(name):
        raise HTTPException(400, f"角色名称不合法（1-64字符，仅允许汉字/字母/数字/下划线/连字符/空格）: {name!r}")

