# ── UD1: 决策①读数基线化 ─────────────────────────────────────────
#   实锤：_PERSIST_KEYS 让 speak_total/stream_sse_total 从 P16-2 起终身累积，
#   而「🤖 自动」选项 2026-07-06 才上线——emotion_auto_rate 分母含大量 auto 出现前的历史，
#   结构性低估（现值 156 次打底，本周全用 auto 也只能到 ~11%，永远够不到 30% 阈值）。
#   修法：首次调用时把四个计数器快照成基线，决策①只看「基线以来」的增量。
BASELINE_FILE = Path(rf"{_BASE}\metrics_baseline.json")
_D1_KEYS = ("speak_total", "stream_sse_total", "speak_emotion_auto",
            "emotion_auto_miss", "stream_sse_emotion")

def _d1_baseline(force: bool = False):
    """决策①基线：惰性建立、计数器倒退（/api/metrics/reset、清档）时自动重打。
    force=True 供「重新起算」用——扩词表/改检测规则后旧读数失真，从当下重计。"""
    try:
        if not force and BASELINE_FILE.exists():
            b = json.loads(BASELINE_FILE.read_text(encoding="utf-8"))
            if all(_metrics.get(k, 0) >= b.get(k, 0) for k in _D1_KEYS):
                return b
            # 计数器比基线还小 = 中途被 reset 过，旧基线失效 → 落到重打
        b = {k: _metrics.get(k, 0) for k in _D1_KEYS}
        b["date"] = time.strftime("%Y-%m-%d")
        b["ts"] = time.time()
        BASELINE_FILE.write_text(json.dumps(b), encoding="utf-8")
        return b
    except Exception:
        return {**{k: 0 for k in _D1_KEYS}, "date": "", "ts": time.time()}

def _d1_block():
    """决策①读数块（/metrics 与设置页共用的单一真相，verdict 判定不下放前端）。
    拍板规则：满 7 天 且 auto 使用率 ≥30% 且 误判 <20% → 默认情感切「🤖 自动」。"""
    b = _d1_baseline()
    auto_s  = max(0, _metrics["speak_emotion_auto"] - b.get("speak_emotion_auto", 0))
    total_s = max(0, (_metrics["speak_total"] + _metrics["stream_sse_total"])
                     - (b.get("speak_total", 0) + b.get("stream_sse_total", 0)))
    miss_s  = max(0, _metrics["emotion_auto_miss"] - b.get("emotion_auto_miss", 0))
    days    = max(0.0, (time.time() - b.get("ts", time.time())) / 86400)
    rate    = auto_s / max(total_s, 1)
    miss_r  = (miss_s / auto_s) if auto_s else 0.0
    if total_s < 20:                    verdict = "sample_low"
    elif auto_s and miss_r > 0.2:       verdict = "miss_high"
    elif rate >= 0.30 and days >= 7:    verdict = "pass"
    elif rate >= 0.30:                  verdict = "pass_wait"
    else:                               verdict = "watch"
    return {"baseline_date": b.get("date", ""), "days": round(days, 1),
            "auto_since": auto_s, "total_since": total_s, "miss_since": miss_s,
            "stream_emo_since": max(0, _metrics["stream_sse_emotion"] - b.get("stream_sse_emotion", 0)),
            "auto_rate": round(rate, 3), "miss_rate": round(miss_r, 3), "verdict": verdict}

