@app.get("/api/qr")
def api_qr(data: str = ""):
    """离线生成二维码 PNG（分享海报内嵌用）。"""
    data = (data or "").strip()
    if not data:
        return JSONResponse({"ok": False, "detail": "缺少 data"}, 400)
    try:
        import qrcode
        import io as _io
        img = qrcode.make(data)
        buf = _io.BytesIO()
        img.save(buf, format="PNG")
        from fastapi.responses import Response
        return Response(content=buf.getvalue(), media_type="image/png",
                        headers={"Cache-Control": "public, max-age=3600"})
    except Exception as e:
        return JSONResponse({"ok": False, "detail": f"二维码生成失败: {e}"}, 500)


# ── M3-②：OG 社交卡封面（服务端 1200×630，供爬虫抓取，磁盘缓存） ──
COVER_DIR = Path(rf"{_BASE}\share_covers")
COVER_DIR.mkdir(exist_ok=True)
_FONT_REG = r"C:\Windows\Fonts\msyh.ttc"
_FONT_BOLD = r"C:\Windows\Fonts\msyhbd.ttc"


def _cover_font(bold: bool, size: int):
    from PIL import ImageFont
    for path in ([_FONT_BOLD, _FONT_REG] if bold else [_FONT_REG, _FONT_BOLD]):
        try:
            return ImageFont.truetype(path, size)
        except Exception:
            continue
    try:
        return ImageFont.truetype(r"C:\Windows\Fonts\simhei.ttf", size)
    except Exception:
        return ImageFont.load_default()


def _cover_wrap(draw, text, x, y, max_w, font, fill, lh, max_lines):
    line, lines = "", []
    for ch in text:
        if draw.textlength(line + ch, font=font) > max_w and line:
            lines.append(line)
            line = ch
            if len(lines) >= max_lines:
                line = ""
                break
        else:
            line += ch
    if line:
        lines.append(line)
    for i, l in enumerate(lines[:max_lines]):
        draw.text((x, y + i * lh), l, font=font, fill=fill)


def _render_cover(name: str) -> bytes:
    from PIL import Image, ImageDraw
    import io as _io
    import base64 as _b64
    p = _profiles.get(name, {})
    W, H = 1200, 630
    img = Image.new("RGB", (W, H), (11, 15, 26))
    dr = ImageDraw.Draw(img)
    top, bot = (20, 29, 51), (11, 15, 26)
    for y in range(H):
        t = y / H
        dr.line([(0, y), (W, y)], fill=(int(top[0] + (bot[0] - top[0]) * t),
                                        int(top[1] + (bot[1] - top[1]) * t),
                                        int(top[2] + (bot[2] - top[2]) * t)))
    ax, ay, asz = 90, 135, 360
    thumb = p.get("face_b64", "") or p.get("thumbnail_b64", "") or ""
    if thumb:
        try:
            if "," in thumb:
                thumb = thumb.split(",", 1)[-1]
            av = Image.open(_io.BytesIO(_b64.b64decode(thumb))).convert("RGBA").resize((asz, asz))
            mask = Image.new("L", (asz, asz), 0)
            ImageDraw.Draw(mask).rounded_rectangle([0, 0, asz, asz], radius=40, fill=255)
            img.paste(av, (ax, ay), mask)
        except Exception:
            pass
    dr.rounded_rectangle([ax, ay, ax + asz, ay + asz], radius=40, outline=(79, 122, 255), width=4)
    tx = 520
    dr.text((tx, 150), name, font=_cover_font(True, 76), fill=(255, 255, 255))
    qa = p.get("quality_axes") or {}
    cos = qa.get("cosine", 0) or 0
    if cos > 0:
        pct = round(cos * 100)
        gold = cos >= 0.75
        btxt = ("★ 金标 · " if gold else "") + f"音色相似度 {pct}%"
        bf = _cover_font(True, 40)
        bw = dr.textlength(btxt, font=bf)
        bx, by = tx, 278
        if gold:
            dr.rounded_rectangle([bx, by, bx + bw + 44, by + 62], radius=31, fill=(245, 158, 11))
            dr.text((bx + 22, by + 8), btxt, font=bf, fill=(58, 36, 0))
        else:
            dr.rounded_rectangle([bx, by, bx + bw + 44, by + 62], radius=31, fill=(22, 42, 30))
            dr.text((bx + 22, by + 8), btxt, font=bf, fill=(74, 222, 128))
    slog = p.get("description") or "真人音色克隆 · 点开听我说一句"
    _cover_wrap(dr, slog, tx, 384, 600, _cover_font(False, 34), (159, 176, 216), 46, 2)
    dr.text((90, 562), "AvatarHub · 真人音色克隆 · 实时语音对话",
            font=_cover_font(False, 26), fill=(124, 141, 176))
    out = _io.BytesIO()
    img.save(out, format="PNG")
    return out.getvalue()


@app.get("/api/share/cover")
def api_share_cover(profile: str = "", regen: bool = False):
    """OG 社交卡封面 PNG（1200×630），按角色磁盘缓存。"""
    name = (profile or "").strip()
    if not name or name not in _profiles:
        return JSONResponse({"ok": False, "detail": "角色不存在"}, 404)
    try:
        _check_profile_name(name)
        out_path = COVER_DIR / f"{name}.png"
        if regen or not out_path.exists():
            out_path.write_bytes(_render_cover(name))
        from fastapi.responses import Response
        return Response(content=out_path.read_bytes(), media_type="image/png",
                        headers={"Cache-Control": "public, max-age=3600"})
    except Exception as e:
        return JSONResponse({"ok": False, "detail": f"封面生成失败: {e}"}, 500)


@app.get("/profiles/{name}/idle_loop")
async def profile_idle_loop(name: str):
    """待机循环视频：LivePortrait 活体基底 MP4（需口型服务已 precompute）。"""
    _check_profile_name(name)
    if name not in _profiles:
        raise HTTPException(404, "角色不存在")
    face_b64 = _profiles[name].get("face_b64", "")
    if not face_b64:
        raise HTTPException(404, "该角色未绑定人脸")
    import base64 as _b64
    face_bytes = _b64.b64decode(face_b64)
    fid = await _lipsync_ensure_face(SERVICES["lipsync"], face_bytes)
    if not fid:
        raise HTTPException(503, "人脸预计算失败")
    ls = SERVICES.get("lipsync", "http://127.0.0.1:8090").rstrip("/")
    try:
        r = await http_pool.get(f"{ls}/lipsync/idle_loop/{fid}", timeout=120)
        if r.status_code == 404:
            raise HTTPException(404, "无活体循环（需多帧 LivePortrait 基底）")
        if r.status_code != 200:
            raise HTTPException(502, f"口型服务 HTTP {r.status_code}")
        from fastapi.responses import Response
        return Response(content=r.content, media_type="video/mp4",
                        headers={"Cache-Control": "public, max-age=3600"})
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(503, f"待机视频生成失败: {e}")


@app.get("/profiles/{name}/preview")
def profile_preview(name: str):
    """一键预览：用角色的人脸换脸到默认照片上"""
    _check_profile_name(name)  # P14-A2
    if name not in _profiles:
        raise HTTPException(404, "角色不存在")
    profile = _profiles[name]
    face_b64 = profile.get("face_b64", "")
    if not face_b64:
        return JSONResponse({"ok": False, "detail": "该角色未绑定人脸图"})
    import base64 as _b64
    # 按优先级查找有脸的目标图
    target_candidates = [
        Path(rf"{_BASE}\source_face.jpg"),
        Path(rf"{_BASE}\faces\默认.jpg"),
        Path(rf"{_BASE}\target.jpg"),
    ]
    target_b64 = ""
    for tp in target_candidates:
        if tp.exists():
            target_b64 = _b64.b64encode(tp.read_bytes()).decode()
            break
    if not target_b64:
        # 无目标图则直接返回源人脸作为预览
        return {"ok": True, "preview_image": face_b64, "elapsed_ms": 0, "mode": "face_only"}
    _fs_eng, _fs_svc, _fs_smooth = _faceswap_resolve(profile=profile)
    _fs_body = {"source_image": face_b64, "target_image": target_b64}
    if _fs_smooth:
        _fs_body["smooth_mode"] = _fs_smooth
    try:
        r = requests.post(f"{SERVICES[_fs_svc]}/faceswap",
            json=_fs_body, headers=_svc_req_headers(), timeout=30)
        if r.status_code == 200 and r.json().get("result_image"):
            return {"ok": True, "preview_image": r.json().get("result_image", ""),
                    "elapsed_ms": r.json().get("elapsed_ms", 0), "mode": "faceswap",
                    "engine": _fs_eng}
        # 换脸失败(如目标图无脸)，回退返回源人脸
        return {"ok": True, "preview_image": face_b64, "elapsed_ms": 0, "mode": "face_only"}
    except Exception as e:
        # 服务不可达也回退
        return {"ok": True, "preview_image": face_b64, "elapsed_ms": 0, "mode": "face_only"}

@app.delete("/profiles/{name}")
async def delete_profile(name: str):
    _check_profile_name(name)  # P14-A2
    if name not in _profiles:
        raise HTTPException(404, "角色不存在")
    async with _PROFILES_LOCK:
        if name not in _profiles:
            raise HTTPException(404, "角色不存在")
        old_data = _profiles.pop(name)
        if not _delete_profile_db(name):   # P6-2: DB失败回滚
            _profiles[name] = old_data
            raise HTTPException(500, "角色删除失败，请重试")
    await broadcast({"event": "profile_deleted", "name": name})
    _push_id_anchor_async()          # 角色库变动→刷新人群 anchor(身份放大基准)
    _usage_drop(name)                # P3: 台账同步清理，防幽灵条目累积
    # 阶段12：随角色清掉存照与出片历史（尽力而为，失败不影响删除结果）
    try:
        _body_photo_path(name).unlink(missing_ok=True)
        import shutil as _sh
        _sh.rmtree(_LOOK_HIST_ROOT / name, ignore_errors=True)
    except Exception:
        pass
    return {"ok": True}

async def _preload_rvc_bg(pth_path: str):
    """P4-E: 激活角色时后台预热RVC模型，减少首次说话延迟。
    修复①：/preload 契约是 {pth_paths: [..]}（列表），此前发 {pth_path: str} → 每次都 422，预热从未生效；
    修复②：相对 id 先解析成绝对路径，引擎才能 torch.load。"""
    try:
        resolved = _rvc_resolve_pth(pth_path)
        r = await http_pool.post(f"{RVC_API}/preload",
                                 json={"pth_paths": [resolved]}, timeout=10)
        if r.status_code == 200:
            _logger.info(f"[Hub] RVC 预热已入队: {resolved}")
        else:
            _logger.warning(f"[Hub] RVC 预热被拒 HTTP {r.status_code}: {resolved}")
    except Exception as e:
        _logger.debug(f"[Hub] RVC 预热跳过: {e}")

@app.post("/profiles/{name}/activate")
async def activate_profile(name: str, auto: bool = False):
    """auto=True 表示机器发起（启动自动重激活等），不计入使用台账——
    否则重启越勤的环境，被自动激活的角色越会虚假霸榜「常用」。"""
    global _active_profile
    _check_profile_name(name)  # P13-A2: URL路径参数也需白名单（防路径遍历探测）
    if name not in _profiles:  # 快速前置检查
        raise HTTPException(404, "角色不存在")
    # P13: 幂等防抖——同角色+配置版本未变+窗口内的重复激活直接短路，
    #   不重跑昂贵预热链(切脸/跨机 spk+fish 预热/开场白缓存重载/口型预计算)。
    #   实测手机页会把激活打成连发(12s 内 9 次)，每发全量预热 → RAM 高水位棘轮
    #   + 远端 TTS 被预热挤占。固定窗口(不滑动)：窗口过后重新全量，保留
    #   「再点一次=手动重试预热」的恢复语义；改角色内容会 bump 版本号穿透防抖。
    _akey = (name, _profiles_version)
    if (_active_profile == name and _ACTIVATE_LAST.get("key") == _akey
            and time.monotonic() - _ACTIVATE_LAST.get("ts", 0.0) < _ACTIVATE_DEBOUNCE_S):
        return {"ok": True, "active": name,
                "face_ready": _face_ready.get(name, "ready"),
                "face_eta_s": round(_face_prep_eta_s, 1), "deduped": True}
    async with _PROFILES_LOCK:  # P4-A/P5-3: 防竞态 + 锁内抷贝快照
        if name not in _profiles:
            raise HTTPException(404, "角色不存在")
        _active_profile = name
        p = dict(_profiles[name])  # P5-3: 锁内浅拷贝，防并发改写导致读到旧数据
    _ACTIVATE_LAST["key"] = _akey
    _ACTIVATE_LAST["ts"] = time.monotonic()
    if not auto:
        _usage_bump(name, "activate")   # P3: 会话级使用台账（防抖之后，连发不重计）
    try:                            # 持久化最近激活角色，供重启后自动重激活
        ACTIVE_PROFILE_FILE.write_text(name, encoding="utf-8")
    except Exception:
        pass

    # 切换换脸服务的激活人脸（后台线程 fire-and-forget：离线服务不再阻塞 /activate 响应与事件循环）
    # C-3: 启用发型定妆的角色优先推定妆脸
    # 2026-07-09: 激活脸+直播妆容一并推送(直连 /faceswap_raw 通道以引擎粘滞态为源脸/妆容真相)
    if _profile_swap_face(p):
        _push_active_face_makeup_async(name)
        # 多照片源脸：有 gallery 附图则预注册平均 embedding（直播链路用 source_key 享用；无附图=不打扰）
        _register_avg_face_async(name)
        # P9-3: 后台预计算该头像的口型人脸（检测+解析+VAE 编码 + 触发 face_alignment
        #   按尺寸的一次性编译，实测首句若现编译会卡 ~33s）。激活时提前做，用户开口即热。
        try:
            import hashlib as _hl
            _face_bytes = base64.b64decode(p["face_b64"])
            _fid = "ph_" + _hl.sha1(_face_bytes).hexdigest()[:16]
            # 磁盘/内存缓存已命中(任一副本)→ 直接 ready，避免无谓的「准备中」闪烁
            _cached = any(k[1] == _fid for k in _ls_precomputed)
            _face_ready[name] = "ready" if _cached else "preparing"

            async def _prep_face(nm=name, fb=_face_bytes):
                global _face_prep_eta_s
                _t0 = time.monotonic()
                # P-Harden2: 预计算放独立任务 + 预算封顶。超预算不取消本体(shield)——它继续后台跑，
                # 跑成落缓存并补翻 ready；UI 侧则立刻拿到 failed(timeout) 解除「准备中」悬挂。
                _ens = asyncio.create_task(_lipsync_ensure_face(SERVICES["lipsync"], fb))
                _ens.add_done_callback(
                    lambda t: t.exception() if not t.cancelled() else None)
                try:
                    fid = await asyncio.wait_for(asyncio.shield(_ens), timeout=_FACE_PREP_BUDGET_S)
                    _dt = time.monotonic() - _t0
                    if fid:
                        # 用实测耗时 EMA 自校准 ETA（钳制 4~40s，抗首编译/异常抖动）
                        _face_prep_eta_s = max(4.0, min(40.0, 0.6 * _face_prep_eta_s + 0.4 * _dt))
                        await _set_face_ready(nm, "ready", elapsed_s=round(_dt, 1))
                    else:
                        await _set_face_ready(nm, "failed", elapsed_s=round(_dt, 1),
                                              reason=await _face_fail_reason_live())
                except asyncio.TimeoutError:
                    await _set_face_ready(nm, "failed",
                                          elapsed_s=round(time.monotonic() - _t0, 1),
                                          reason="timeout")

                    def _late_ready(t, nm=nm, _t0=_t0):
                        # 后台预计算迟到成功 → 补翻 ready(带 late 标记)，缓存已热，重试/下次激活秒过
                        if t.cancelled() or t.exception() is not None:
                            return
                        if t.result():
                            asyncio.ensure_future(_set_face_ready(
                                nm, "ready",
                                elapsed_s=round(time.monotonic() - _t0, 1), late=True))
                    _ens.add_done_callback(_late_ready)
                except Exception:
                    await _set_face_ready(nm, "failed", reason=await _face_fail_reason_live())

            _ft = asyncio.create_task(_prep_face())
            _ft.add_done_callback(
                lambda t: t.exception() if not t.cancelled() else None)
        except Exception:
            _face_ready[name] = "ready"   # 无脸/异常不阻塞，按就绪处理(走静态回退)

    # S2: 按角色下发 DFM 整脸换模型——有绑定→热切到该 .dfm（该角色=换该明星，辨识度终极档）；
    #     无绑定→切回通用换脸(default)，防上一个 DFM 角色的模型残留污染本角色。独立于人脸推送
    #     （DFM-only 角色可无 face_b64）；fire-and-forget，远端旧版无 /model/reload 时静默跳过。
    _push_dfm_model_async(name, p)

    # P9-9: 后台预注册该角色音色的 zero-shot spk，缓存说话人特征抽取结果，
    #   消除首轮首句的 onnx 抽取开销(实测克隆路径省 ~290ms/句) → 压低 TTFA。
    if p.get("voice_b64"):
        def _prewarm_spk(vb64=p["voice_b64"]):
            for _u in _replica_urls("emotion_tts"):    # 多卡：每张卡都注册说话人
                try:
                    requests.post(f"{_u}/v1/tts/register_spk",
                        json={"reference_audio_b64": vb64},
                        headers=_svc_req_headers(), timeout=30)
                except Exception:
                    pass
        threading.Thread(target=_prewarm_spk, daemon=True).start()

    # Fish-Speech 多段参考预热：把融合参考(或单段)按内容哈希预编码进缓存，
    #   使首句合成跳过参考编码 → 直接压低融合场景下的 TTFA。
    _prewarm_svc = _fish_compat_svc(p.get("tts_engine", ""))   # fish_tts / qwen3_tts / ""
    if _prewarm_svc:
        _fr = p.get("fish_refs") or []
        if not _fr and p.get("voice_b64"):
            _ftp = p.get("fish_tts_params") or {}
            _fr = [{"voice_b64": p["voice_b64"], "text": _ftp.get("reference_text", "")}]
        # 情绪参考音也并入预热集合：首个情绪句直接命中缓存，避免切参考时 TTFA 抖升
        _emo_all = []
        for _segs in (p.get("emotion_refs") or {}).values():
            _emo_all.extend(_segs or [])
        _prewarm_set = _fr + _emo_all
        if _prewarm_set:
            def _prewarm_fish(refs=_prewarm_set, svc=_prewarm_svc):
                _payload = {"references": [{"audio_b64": r.get("voice_b64", ""),
                                           "text": r.get("text", "")} for r in refs
                                          if r.get("voice_b64")]}
                for _u in _replica_urls(svc):   # 多卡：每张卡都载模型+预编码参考
                    try:
                        requests.post(f"{_u}/v1/refs/prewarm",
                            json=_payload, headers=_svc_req_headers(), timeout=90)
                    except Exception:
                        pass
            threading.Thread(target=_prewarm_fish, daemon=True).start()

    # P9-10: 后台预合成常见开场白，对话首句命中即 0ms → 感知 TTFA≈0。
    #   无条件运行(用 _conv_synthesize 同一路径，有/无 voice_b64 都与运行时一致)。
    #   延迟启动，等 spk 预热(若有)落地，避免首条预合成付抽取代价。
    _pc_snapshot = dict(p)
    _pc_snapshot.setdefault("name", name)   # 与 converse 侧 profile 的 name 对齐(缓存分桶键)
    async def _precompute_bg():
        await asyncio.sleep(2.0)
        await _precompute_openers(_pc_snapshot)
    _pt = asyncio.create_task(_precompute_bg())
    _pt.add_done_callback(
        lambda t: t.exception() if not t.cancelled() else None)

    # 切换发型（后台线程 fire-and-forget：离线服务不再阻塞激活响应）
    if p.get("hair_style"):
        def _switch_hair(style=p["hair_style"]):
            try:
                requests.post(f"{SERVICES['hair']}/hair_styles/activate",
                    json={"name": style},
                    headers=_svc_req_headers(), timeout=5)
            except Exception:
                pass
        threading.Thread(target=_switch_hair, daemon=True).start()

    # 自动切换 RVC 模型（fire-and-forget，不阻塞）——使用角色自身的 rvc_settings
    if p.get("rvc_model"):
        _rvc_cfg = p.get("rvc_settings", {})
        def _push_rvc(cfg=_rvc_cfg, model=_rvc_resolve_pth(p["rvc_model"])):
            try:
                requests.post(f"{SERVICES['rvc']}/config",
                    json={"pth_path": model,
                          "f0method":    cfg.get("f0method",    "rmvpe"),
                          "f0up_key":    cfg.get("pitch",       0),
                          "threhold":    cfg.get("threhold",    -60),
                          "index_rate":  cfg.get("index_rate",  0.5),
                          "protect":     cfg.get("protect",     0.33),
                          "rms_mix_rate":cfg.get("rms_mix_rate",0.25),
                          "is_half":     True},
                    headers=_svc_req_headers(), timeout=5)
            except Exception:
                pass
        threading.Thread(target=_push_rvc, daemon=True).start()
        _t = asyncio.create_task(_preload_rvc_bg(p["rvc_model"]))  # P4-E: 后台异步预热
        _t.add_done_callback(  # P9-2: 静默吞掉CancelledError，防泄漏告警
            lambda t: t.exception() if not t.cancelled() else None)

    # vcam 待机同步：激活即把该角色的待机帧/真人半身循环推给虚拟摄像头。
    #   此前激活不推待机，依赖别处设置 → vcam 一旦重启，待机会回落默认头像直到下次切换角色；
    #   现在"激活=待机画面正确"，且 vcam 重启后重激活即自愈。
    if _vcam_enabled and p.get("face_b64"):
        async def _push_idle(fb=p["face_b64"]):
            try:
                await _vcam_set_idle(base64.b64decode(fb))
            except Exception:
                pass
        _it = asyncio.create_task(_push_idle())
        _it.add_done_callback(
            lambda t: t.exception() if not t.cancelled() else None)

    _logger.info(f"角色激活: {name} (voice={p.get('voice_name')}, rvc={p.get('rvc_model')})")
    await broadcast({"event": "profile_activated", "name": name,
                     "description":  p.get("description", ""),
                     "face_ready":   _face_ready.get(name, "ready"),
                     "face_eta_s":   round(_face_prep_eta_s, 1),
                     "rvc_settings": p.get("rvc_settings", {})})
    return {"ok": True, "active": name, "face_ready": _face_ready.get(name, "ready"),
            "face_eta_s": round(_face_prep_eta_s, 1)}


@app.get("/api/profile/ready")
def api_profile_ready(name: str = ""):
    """角色「活体口型人脸」预计算就绪态(轮询兜底；实时优先用 WS face_ready 事件)。
    name 省略=当前激活角色。state: preparing/ready/failed/unknown。"""
    nm = name or _active_profile
    state = _face_ready.get(nm, "unknown" if nm else "")
    return {"ok": True, "name": nm, "state": state,
            "eta_s": round(_face_prep_eta_s, 1),
            "reason": _face_fail_reasons.get(nm, "") if state == "failed" else "",  # P4: 失败归因随态回传→刷新后前端复原正确降级徽标
            "ready": state in ("ready", "unknown")}   # unknown(老角色/未追踪)按就绪处理，不挡用户


@app.post("/profiles/{name}/usage_bump")
def profile_usage_bump(name: str, body: dict = Body(default={})):
    """P3: 会话级使用+1（同传开播/通话中切换等由调用方上报；激活在 /activate 内自动记）。"""
    _check_profile_name(name)
    if name not in _profiles:
        raise HTTPException(404, "角色不存在")
    kind = str(body.get("kind") or "use")[:24]
    _usage_bump(name, kind)
    return {"ok": True, "name": name, "n": _usage_n(name)}


@app.get("/api/profiles/stats")
def get_profiles_stats():
    """P21-3: 统计各角色在speak_history中的使用次数"""
    try:
        with _db_conn() as conn:
            rows = conn.execute("""
                SELECT profile, COUNT(*) as cnt
                FROM speak_history
                WHERE profile IS NOT NULL AND profile != ''
                GROUP BY profile
            """).fetchall()
        return {"ok": True, "usage": {r["profile"]: r["cnt"] for r in rows}}
    except Exception as e:
        raise HTTPException(500, str(e))

@app.post("/profiles/{name}/clone")
async def clone_profile(name: str, body: dict = {}):
    """
    克隆/复制角色：基于现有角色创建副本。
    默认副本名为"原角色名_副本"，也可通过 new_name 参数指定。
    """
    _check_profile_name(name)  # P14-A2: 源角色名也需白名单
    if name not in _profiles:
        raise HTTPException(404, "角色不存在")
    source = _profiles[name]
    new_name = body.get("new_name", f"{name}_副本")
    _check_profile_name(new_name)  # P11-A2
    if new_name in _profiles:
        raise HTTPException(400, f"角色名 '{new_name}' 已存在")

    # 深拷贝角色数据
    import copy
    new_profile = copy.deepcopy(source)
    new_profile["description"] = f"复制自 {name}: {source.get('description', '')}"

    async with _PROFILES_LOCK:
        _profiles[new_name] = new_profile
        if not _save_profile(new_name):  # P6-2: DB失败回滚
            del _profiles[new_name]
            raise HTTPException(500, "角色克隆失败，请重试")
    _logger.info(f"角色克隆: {name} -> {new_name}")
    await broadcast({"event": "profile_created", "name": new_name, "cloned_from": name})
    return {"ok": True, "name": new_name, "source": name}


# ── 路由：角色编辑（部分更新）──────────────────────────────────────
@app.patch("/profiles/{name}")
async def patch_profile(name: str, body: dict):
    """部分更新角色：只传需要修改的字段，未传字段保持原值"""
    global _active_profile
    _check_profile_name(name)  # P14-A2
    # P10-1: 大字段上限，patch也可能携带新的 voice_b64/face_b64
    if len(body.get("face_b64",  "")) > _B64_LIMIT:
        raise HTTPException(413, "face_b64 超过 5MB 限制")
    if len(body.get("voice_b64", "")) > _B64_LIMIT:
        raise HTTPException(413, "voice_b64 超过 5MB 限制")
    if name not in _profiles:
        raise HTTPException(404, "角色不存在")

    # P7-1: 锁内取浅拷贝（含嵌套dict），在锁外修改副本，防并发PATCH互相覆盖
    async with _PROFILES_LOCK:
        if name not in _profiles:
            raise HTTPException(404, "角色不存在")
        p = dict(_profiles[name])
        p["rvc_settings"] = dict(p.get("rvc_settings", {}))

    changed = False

    for field in ("description", "voice_name", "hair_style", "rvc_model", "tts_engine",
                  "system_prompt", "lipsync_engine", "vc_engine", "faceswap_engine",
                  "dfm_model", "idle_video", "body_video", "makeup_style"):
        if field in body:
            p[field] = body[field]
            changed = True

    # C-5 直播妆容层配置（merge，不全量替换）：{enabled,lip_color,lip,blush_color,blush,eye_color,eye}
    if "live_makeup" in body and isinstance(body["live_makeup"], dict):
        _lmk = dict(p.get("live_makeup", {}))
        _lmk.update(body["live_makeup"])
        p["live_makeup"] = _lmk
        changed = True

    # M3-④：原声对比授权开关（落地页 AB 暴露真人参考音前的显式 opt-in）
    if "allow_reference_preview" in body:
        p["allow_reference_preview"] = bool(body["allow_reference_preview"])
        changed = True

    # rvc_settings 支持部分更新（merge，不是全量替换）
    if "rvc_settings" in body and isinstance(body["rvc_settings"], dict):
        p["rvc_settings"].update(body["rvc_settings"])
        changed = True

    # fish_tts_params 支持部分更新（merge，保留未传字段如 reference_text）
    if "fish_tts_params" in body and isinstance(body["fish_tts_params"], dict):
        _fp = dict(p.get("fish_tts_params", {}))
        _fp.update(body["fish_tts_params"])
        p["fish_tts_params"] = _fp
        changed = True

    # filler_phrases 角色专属垫话（全量替换；传空列表=恢复全局默认）
    if "filler_phrases" in body and isinstance(body["filler_phrases"], list):
        p["filler_phrases"] = [s for s in body["filler_phrases"]
                               if isinstance(s, str) and s.strip()]
        changed = True

    # opener_phrases 角色专属开场白（全量替换；传空列表=恢复全局默认）
    if "opener_phrases" in body and isinstance(body["opener_phrases"], list):
        p["opener_phrases"] = [s for s in body["opener_phrases"]
                               if isinstance(s, str) and s.strip()]
        changed = True

    # probe_sentences 角色专属体检语料（全量替换；空列表=恢复默认通用句）
    if "probe_sentences" in body and isinstance(body["probe_sentences"], list):
        p["probe_sentences"] = [s for s in body["probe_sentences"]
                                if isinstance(s, str) and s.strip()]
        changed = True

    # voice_b64 单独处理
    voice_changed = False
    if "voice_b64" in body and body["voice_b64"]:
        p["voice_b64"] = body["voice_b64"]
        changed = True
        voice_changed = True

    if "voice_name" in body and body["voice_name"] != p.get("voice_name"):
        voice_changed = True  # voice_name 已在上面字段循环中更新

    # 解绑声音：仅显式 clear_voice=true 才同时清空 voice_b64/voice_name
    # （不给 voice_b64 空串赋清空语义——历史前端会随手带空串，易误清克隆参考音）
    if body.get("clear_voice"):
        if p.get("voice_b64") or p.get("voice_name"):
            p["voice_b64"] = ""
            p["voice_name"] = ""
            changed = True
            voice_changed = True

    # face_b64 变更时重新生成缩略图
    if "face_b64" in body and body["face_b64"]:
        p["face_b64"] = body["face_b64"]
        p["thumbnail_b64"] = _generate_thumbnail(body["face_b64"])
        changed = True

    # face_gallery_b64 多照片源脸集（全量替换；空列表=清空回单照）；激活角色即时重注册平均
    if "face_gallery_b64" in body and isinstance(body["face_gallery_b64"], list):
        p["face_gallery_b64"] = [b for b in body["face_gallery_b64"] if b][:8]
        changed = True
        if name == _active_profile:
            _register_avg_face_async(name)

    # 支持重命名（移动到新 key）
    new_name = body.get("new_name", "").strip()
    if new_name and new_name != name:
        _check_profile_name(new_name)  # P11-A2
        if new_name in _profiles:
            raise HTTPException(400, f"角色名「{new_name}」已存在")
        async with _PROFILES_LOCK:
            _saved_active = _active_profile
            original = _profiles.pop(name)       # P7-1: 弹出原始数据备用回滚
            _profiles[new_name] = p              # P7-1: 写入修改后的副本
            if _active_profile == name:
                _active_profile = new_name
            if not _rename_profile_db(name, new_name):  # P6-2: DB失败回滚
                _profiles.pop(new_name, None)
                _profiles[name] = original       # P7-1: 还原原始数据
                _active_profile = _saved_active
                raise HTTPException(500, "角色重命名失败，请重试")
        for _nm in (name, new_name):   # M3-④：失效新旧两份 OG 封面缓存
            try:
                (COVER_DIR / f"{_nm}.png").unlink(missing_ok=True)
            except Exception:
                pass
        _usage_rename(name, new_name)   # P3: 使用台账跟随改名，"常用"不清零
        await broadcast({"event": "profile_renamed", "old": name, "new": new_name})
        return {"ok": True, "name": new_name, "renamed": True}

    if changed:
        async with _PROFILES_LOCK:
            if name not in _profiles:            # P7-1: 防并发删除
                raise HTTPException(404, "角色已被并发删除")
            _profiles[name] = p                  # P7-1: 原子写回修改后的副本
            if not _save_profile(name):          # P6-2: DB失败回滚
                raise HTTPException(500, "角色更新失败，请重试")
        try:                                     # M3-④：资料变更→失效 OG 封面缓存
            (COVER_DIR / f"{name}.png").unlink(missing_ok=True)
        except Exception:
            pass
        # P4-D: voice变更时删除旧preview缓存并重新生成（解绑后无声则只清缓存，不空跑合成）
        if voice_changed:
            for lang in ("zh-cn", "en", "ja", "ko"):
                stale = VOICE_PREVIEW_DIR / f"{name}_{lang}.wav"
                stale.unlink(missing_ok=True)
            if p.get("voice_b64") or p.get("voice_name"):
                asyncio.create_task(_async_generate_preview(name))
        if "opener_phrases" in body or "filler_phrases" in body:
            _pc = dict(_profiles[name]); _pc["name"] = name
            asyncio.create_task(_precompute_openers(_pc))
        await broadcast({"event": "profile_updated", "name": name})
    return {"ok": True, "name": name}

# ── 路由：RVC 模型列表 ────────────────────────────────────────────
# ── RVC 模型缓存 ───────────────────────────────────────────────────
_rvc_cache: dict = {"models": [], "indices": [], "ts": 0.0}
_RVC_CACHE_TTL = 30.0

RVC_WEIGHTS_DIR = Path(rf"{_BASE}\Retrieval-based-Voice-Conversion-WebUI\assets\weights")
RVC_INDICES_DIR = Path(rf"{_BASE}\Retrieval-based-Voice-Conversion-WebUI\assets\indices")
RVC_LOGS_DIR    = Path(rf"{_BASE}\Retrieval-based-Voice-Conversion-WebUI\logs")

# P2-RA: 变声模型显示别名（编号男声 01-10号 → 沉香木/青铜钟…，频谱分桶+人工终审）。
# 只影响显示：rvc_model 绑定值/预设键/引擎路径全走原 rel_id，改 .pth 文件名才会断链，别名不会。
_RVC_ALIAS_FILE = Path(rf"{_BASE}\rvc_alias_map.json")
_rvc_alias_cache: dict = {"mtime": None, "data": {}}


def _rvc_aliases() -> dict:
    """{rel_id: {alias, note, bucket, ...}}；文件缺失/坏 JSON → 空表（显示回退文件名）。"""
    try:
        mt = _RVC_ALIAS_FILE.stat().st_mtime
    except OSError:
        return {}
    if _rvc_alias_cache["mtime"] != mt:
        try:
            d = json.loads(_RVC_ALIAS_FILE.read_text(encoding="utf-8"))
            _rvc_alias_cache["data"] = d.get("aliases") or {}
            _rvc_alias_cache["mtime"] = mt
        except Exception as e:
            _logger.warning(f"[rvc] rvc_alias_map.json 解析失败(显示回退文件名): {e}")
            return {}
    return _rvc_alias_cache["data"]


def _rvc_resolve_pth(model: str) -> str:
    """rvc_model（相对 id 或绝对路径）→ RVC 引擎可 torch.load 的绝对路径。
    引擎按自身 CWD 解析相对路径，而模型实际存放在 assets/weights/（可能嵌套一层）——
    相对 id 直传会 FileNotFound。此处统一在 hub 侧解析；解析不到原样返回（老的手填绝对路径不受影响）。"""
    m = (model or "").strip()
    if not m:
        return m
    p = Path(m)
    if p.is_absolute():
        return m
    rel = m.replace("/", os.sep)
    for base in (RVC_WEIGHTS_DIR, RVC_LOGS_DIR):
        cand = base / rel
        if cand.exists():
            return str(cand)
    return m

def _rvc_model_files() -> list:
    """扫出全部可用 RVC 模型：[(相对 weights 根的 id, Path)]。
    除根目录外还扫**一层子目录**（现场交付常把整个 weights 文件夹拷进 assets/weights/ →
    模型全躺在 weights/weights/*.pth，旧扫描只看根目录 → /rvc/models 恒空、前端下拉没得选）。
    相对路径 id 与 RVC 引擎解析兼容：get_vc 按 weight_root(=assets/weights) 拼接。"""
    out = []
    if RVC_WEIGHTS_DIR.exists():
        for f in sorted(RVC_WEIGHTS_DIR.glob("*.pth")):
            out.append((f.name, f))
        for sub in sorted(RVC_WEIGHTS_DIR.iterdir()):
            if sub.is_dir() and not sub.name.startswith("_"):
                for f in sorted(sub.glob("*.pth")):
                    out.append((f"{sub.name}/{f.name}", f))
    return out


@app.get("/rvc/models")
def rvc_models():
    """扫描 RVC weights/ 目录（含一层嵌套），30s缓存避免频繁磁盘IO"""
    global _rvc_cache
    now = time.time()
    if now - _rvc_cache["ts"] < _RVC_CACHE_TTL:
        return {"models": _rvc_cache["models"], "indices": _rvc_cache["indices"],
                "aliases": {k: v.get("alias") for k, v in _rvc_aliases().items()},
                "weights_dir": str(RVC_WEIGHTS_DIR), "cached": True,
                "hint": "将 .pth 文件放入 weights/ 目录即可使用"}

    pth_files = [rel for rel, _ in _rvc_model_files()]
    idx_files = []
    if RVC_INDICES_DIR.exists():
        idx_files = [f.name for f in RVC_INDICES_DIR.glob("*.index")]
    # 也扫描 logs 子目录
    logs_dir = Path(rf"{_BASE}\Retrieval-based-Voice-Conversion-WebUI\logs")
    if logs_dir.exists():
        for subdir in logs_dir.iterdir():
            if subdir.is_dir():
                pth_files += [f"{subdir.name}/{f.name}" for f in subdir.glob("*.pth")]
                idx_files += [f"{subdir.name}/{f.name}" for f in subdir.glob("*.index")]

    _rvc_cache = {"models": pth_files, "indices": idx_files, "ts": now}
    return {"models": pth_files, "indices": idx_files,
            "aliases": {k: v.get("alias") for k, v in _rvc_aliases().items()},
            "weights_dir": str(RVC_WEIGHTS_DIR), "cached": False,
            "hint": "将 .pth 文件放入 weights/ 目录即可使用"}

# ── 路由：声音列表（来自 TTS 服务）─────────────────────────────────
@app.get("/voices")
def list_voices():
    voices = []
    if VOICES_DIR.exists():
        voices = [f.stem for f in VOICES_DIR.glob("*.wav")]
    return {"voices": voices}


# ── 声音资产统一视图：声音库 + 克隆产物 + 引用关系 ───────────────────
# 克隆参考音以 voice_b64 内嵌进角色（无文件名外键），引用关系用**内容哈希**精确回算：
# clone_voice 返回的 b64 就是写进 voice_clones/ 的同一份字节，md5 相等即「该角色用的这个文件」。
# 删除=软删入 _trash/（克隆文件同时是水印/授权留痕的合规证据，不可抹掉）；声音库属 TTS 引擎资产，只读。
CLONE_ASSETS_DIR = Path(rf"{_BASE}\voice_clones")
_VA_TRASH_DIRNAME = "_trash"
_va_hash_cache: dict = {}   # 文件侧 {(name,size,mtime): md5} / 角色侧 {(profile,len): md5}


def _va_safe_wav(fname: str) -> str:
    """资产文件名白名单：拒绝路径穿越，只允许 .wav。"""
    if (not fname or fname != os.path.basename(fname) or fname.startswith(".")
            or "/" in fname or "\\" in fname or not fname.lower().endswith(".wav")):
        raise HTTPException(400, "非法文件名")
    return fname


def _va_resolve(asset_id: str) -> tuple:
    """'clone:<file>.wav' / 'lib:<file>.wav' → (kind, Path)；不存在→404。"""
    kind, _, fname = (asset_id or "").partition(":")
    if kind not in ("clone", "lib"):
        raise HTTPException(400, "非法资产 id（应为 clone:xx.wav / lib:xx.wav）")
    fname = _va_safe_wav(fname)
    path = (CLONE_ASSETS_DIR if kind == "clone" else VOICES_DIR) / fname
    if not path.exists():
        raise HTTPException(404, "声音文件不存在")
    return kind, path


def _va_file_md5(path: Path) -> str:
    import hashlib as _hl
    st = path.stat()
    key = ("f", path.name, st.st_size, int(st.st_mtime))
    if key not in _va_hash_cache:
        _va_hash_cache[key] = _hl.md5(path.read_bytes()).hexdigest()
    return _va_hash_cache[key]


def _va_profile_md5(pname: str, b64: str) -> str:
    import hashlib as _hl
    # 键必须取自内容本身（长度+首尾片段）：同名角色换绑「等长但不同」的克隆音（水印时间戳定长）
    # 若只按 (角色名,长度) 缓存会命中旧哈希 → 引用回算全空 → 被引用的文件被误判孤儿可删
    key = ("p", len(b64), b64[:24], b64[-24:])
    if key not in _va_hash_cache:
        try:
            _va_hash_cache[key] = _hl.md5(base64.b64decode(b64)).hexdigest()
        except Exception:
            _va_hash_cache[key] = ""
    return _va_hash_cache[key]


def _va_wav_duration(path: Path) -> float:
    """RIFF 头读时长（克隆文件尾部追加的水印字节不影响 data chunk 解析）。"""
    import wave as _wave
    try:
        with _wave.open(str(path)) as wf:
            fr = wf.getframerate()
            return round(wf.getnframes() / fr, 1) if fr else 0.0
    except Exception:
        return 0.0


@app.get("/api/voice_assets")
def api_voice_assets():
    """统一列出声音资产：克隆产物（voice_clones/）+ 声音库（alltalk voices），
    每条带时长/大小/创建时间/被哪些角色引用/是否孤儿；另附「角色内嵌参考音」的匹配对照。"""
    # 角色侧哈希索引：md5 → [角色名]（克隆参考音内嵌 b64，引用按内容哈希回算）
    emb_hash: dict = {}
    for pname, p in _profiles.items():
        b64 = p.get("voice_b64") or ""
        if b64:
            h = _va_profile_md5(pname, b64)
            if h:
                emb_hash.setdefault(h, []).append(pname)

    assets = []
    if CLONE_ASSETS_DIR.exists():
        for f in sorted(CLONE_ASSETS_DIR.glob("*.wav"), key=lambda x: -x.stat().st_mtime):
            refs = emb_hash.get(_va_file_md5(f), [])
            st = f.stat()
            assets.append({"id": f"clone:{f.name}", "kind": "clone", "name": f.name,
                           "size": st.st_size, "created_at": int(st.st_mtime),
                           "duration_s": _va_wav_duration(f),
                           "refs": refs, "orphan": not refs})
    if VOICES_DIR.exists():
        for f in sorted(VOICES_DIR.glob("*.wav")):
            refs = [pn for pn, p in _profiles.items() if p.get("voice_name") == f.stem]
            st = f.stat()
            assets.append({"id": f"lib:{f.name}", "kind": "lib", "name": f.name,
                           "size": st.st_size, "created_at": int(st.st_mtime),
                           "duration_s": _va_wav_duration(f),
                           "refs": refs, "orphan": False})   # 库文件属引擎资产，不按孤儿管理

    file_hashes = {_va_file_md5(f) for f in CLONE_ASSETS_DIR.glob("*.wav")} if CLONE_ASSETS_DIR.exists() else set()
    profile_embedded = []
    for pname, p in _profiles.items():
        b64 = p.get("voice_b64") or ""
        if b64:   # matched=False ⇒ 参考音只活在角色里（克隆文件被手工删过），提示用户导出备份
            profile_embedded.append({"profile": pname,
                                     "matched": _va_profile_md5(pname, b64) in file_hashes})
    if len(_va_hash_cache) > 500:   # 防长毛：条目带 size/mtime/len 作键，旧键不会命中
        _va_hash_cache.clear()
    return {"ok": True, "assets": assets, "profile_embedded": profile_embedded,
            "clone_dir": str(CLONE_ASSETS_DIR)}


@app.get("/api/voice_assets/{asset_id}/audio")
def api_voice_asset_audio(asset_id: str):
    """试听：直接回文件字节（克隆文件含尾部水印，浏览器按 RIFF 头正常播放）。"""
    _, path = _va_resolve(asset_id)
    return Response(content=path.read_bytes(), media_type="audio/wav",
                    headers={"Cache-Control": "no-store"})


@app.post("/api/voice_assets/bind")
async def api_voice_asset_bind(body: dict):
    """把资产绑定到角色（孤儿克隆音的找回通道）：
    clone → 读文件转 b64 走 PATCH（复用大小限制/试听重生成/广播等全部既有约束）；lib → 绑 voice_name。"""
    profile = str(body.get("profile") or "")
    if profile not in _profiles:
        raise HTTPException(404, "角色不存在")
    kind, path = _va_resolve(str(body.get("id") or ""))
    if kind == "clone":
        b64 = base64.b64encode(path.read_bytes()).decode()
        return await patch_profile(profile, {"voice_b64": b64, "voice_name": ""})
    return await patch_profile(profile, {"voice_name": path.stem})


@app.post("/api/voice_assets/rename")
def api_voice_asset_rename(body: dict):
    """重命名（仅克隆产物；引用按内容哈希回算，改名不影响任何角色）。"""
    kind, path = _va_resolve(str(body.get("id") or ""))
    if kind != "clone":
        raise HTTPException(400, "声音库文件属 TTS 引擎资产，不支持改名")
    new_raw = str(body.get("new_name") or "").strip()
    new_stem = "".join(c if c.isalnum() or c in "-_" else "_" for c in new_raw.removesuffix(".wav"))[:64]
    if not new_stem:
        raise HTTPException(400, "新名称为空或全是非法字符")
    target = CLONE_ASSETS_DIR / f"{new_stem}.wav"
    if target.exists():
        raise HTTPException(400, f"已存在同名文件 {target.name}")
    path.rename(target)
    return {"ok": True, "id": f"clone:{target.name}", "name": target.name}


@app.delete("/api/voice_assets/{asset_id}")
def api_voice_asset_delete(asset_id: str):
    """删除孤儿克隆音：仅无引用时允许；软删移入 _trash/（保留水印/授权证据链，可手工找回）。"""
    kind, path = _va_resolve(asset_id)
    if kind != "clone":
        raise HTTPException(400, "声音库文件属 TTS 引擎资产，不支持删除")
    h = _va_file_md5(path)
    refs = [pn for pn, p in _profiles.items()
            if (p.get("voice_b64") and _va_profile_md5(pn, p["voice_b64"]) == h)]
    if refs:
        raise HTTPException(400, f"仍被角色引用，不能删除：{'、'.join(refs)}")
    trash = CLONE_ASSETS_DIR / _VA_TRASH_DIRNAME
    trash.mkdir(exist_ok=True)
    target = trash / f"{int(time.time())}_{path.name}"
    path.rename(target)
    _trash_auto_clean("clone_soft_delete")   # 策略开启且超限 → 顺手清旧项
    return {"ok": True, "trashed": target.name}


@app.post("/api/voice_assets/purge_orphans")
def api_voice_assets_purge_orphans(body: dict = Body(default={})):
    """一键清孤儿：把无角色引用的克隆音批量移入回收站（巡检横幅入口；软删可还原）。
    引用判定与单条删除同一口径（内容哈希回算），被引用文件绝不会被碰。
    body.only=[文件名…] 可选：只在名单内清（定向清理/测试隔离），缺省=全部孤儿。"""
    only = body.get("only")
    only_set = None
    if only is not None:
        if not isinstance(only, list) or not all(isinstance(x, str) for x in only):
            raise HTTPException(400, "only 须为文件名数组")
        only_set = {os.path.basename(x) for x in only}
    emb_hashes = set()
    for pname, p in _profiles.items():
        b64 = p.get("voice_b64") or ""
        if b64:
            h = _va_profile_md5(pname, b64)
            if h:
                emb_hashes.add(h)
    moved = []
    if CLONE_ASSETS_DIR.exists():
        trash = CLONE_ASSETS_DIR / _VA_TRASH_DIRNAME
        for f in list(CLONE_ASSETS_DIR.glob("*.wav")):
            if only_set is not None and f.name not in only_set:
                continue
            if _va_file_md5(f) in emb_hashes:
                continue
            trash.mkdir(exist_ok=True)
            target = trash / f"{int(time.time())}_{f.name}"
            f.rename(target)
            moved.append(f.name)
    if moved:
        _trash_auto_clean("purge_orphans")
    return {"ok": True, "moved": len(moved), "names": moved}


# ═══════════════════════════════════════════════════════════════════════════
# 真人音色库（voice_pack_aishell3）：218 位录音棚真人参考音的只读素材包
# 架构：包=磁盘只读资产(index.json 一次构建)，不进 DB；导入=复制成普通角色。
# 已导入判定不用内容哈希(每次列表要解码 218 个 base64，纯浪费)，而是导入时在
# 角色上打 voicepack_spk 溯源标记：零开销、删角色后自动恢复"可导入"态。
# ═══════════════════════════════════════════════════════════════════════════
VOICEPACK_DIR = Path(rf"{_BASE}\voice_pack_aishell3")
# SSB=AISHELL-3 内置包；EXT=用户上新（P6 ingest）。同一正则也是路径遍历防线。
_VP_SPK_RE = re.compile(r"^(SSB|EXT)\d{4}$")
# P8 分层解锁（SaaS 预埋）：VP_TIER=featured_free → 长尾库只能试听不能导入（精选/上新/已导入不受限）。
# 默认空=全解锁，行为与历史完全一致；部署侧一个环境变量即可切付费墙形态。
_VP_TIER = os.environ.get("VP_TIER", "").strip().lower()
_VP_EXT_INDEX = VOICEPACK_DIR / "index_ext.json"     # 上新音色索引（与 index.json 同 schema + label/added_at）
_VP_EXT_TRASH = VOICEPACK_DIR / "_ext_trash"         # 上新软删回收目录
_vp_ext_lock = threading.Lock()                      # index_ext.json 读改写互斥
_vp_cache: dict = {"mtime": 0.0, "rows": None}

# 音高档按性别分别取包内三分位（2026-07-08 对 218 人实测：男 139/158Hz，女 229/252Hz）。
# 若用全局阈值，男声几乎全成"低音"、女声全成"明亮"，档位就没有筛选意义了。
_VP_F0_CUTS = {"male": (139.0, 158.0), "female": (229.0, 252.0)}
_VP_AGE_CN = {"A": "少年", "B": "青年", "C": "中年", "D": "中老年"}
_VP_ACCENT_CN = {"north": "北方口音", "south": "南方口音", "others": "其他口音"}
# 卖点一句话 = 音高档 × 风格 矩阵（说人话，不摆 Hz/dB 参数）
_VP_SCENE = {
    ("低音", "沉稳"): "厚重可信，适合知识讲解、品牌口播",
    ("低音", "自然"): "低沉耐听，适合长时间直播",
    ("低音", "活泼"): "有磁性又带劲，适合带货控场",
    ("中音", "沉稳"): "平稳清晰，适合客服、产品解说",
    ("中音", "自然"): "百搭自然，日常对话首选",
    ("中音", "活泼"): "亲和有活力，适合互动闲聊",
    ("明亮", "沉稳"): "清亮利落，适合功能讲解",
    ("明亮", "自然"): "明快干净，适合有声书、口播",
    ("明亮", "活泼"): "高能有感染力，适合气氛带动",
}


def _vp_band(gender: str, f0) -> str:
    if not f0:
        return ""    # 个别样本 F0 提取失败（如气声重）→ 不分档，不硬猜
    lo, hi = _VP_F0_CUTS.get(gender) or _VP_F0_CUTS["female"]
    return "低音" if f0 < lo else ("中音" if f0 <= hi else "明亮")


def _vp_style(iqr) -> str:
    """语调起伏(F0 四分位距)三分位：<39 沉稳 / 39-51 自然 / >51 活泼。"""
    if not iqr:
        return "自然"
    return "沉稳" if iqr < 39 else ("自然" if iqr <= 51 else "活泼")


def _vp_stars(snr, bw) -> int:
    """质量星级：信噪比(权 0.55) + 有效频宽(权 0.45) 归一加权。
    包内中位数(snr 62dB/bw 12.2kHz)约落 4 星，顶部干净样本 5 星。"""
    q = 0.55 * min(snr or 0, 80.0) / 80.0 + 0.45 * min(bw or 0, 14.0) / 14.0
    for cut, n in ((0.88, 5), (0.75, 4), (0.62, 3), (0.5, 2)):
        if q >= cut:
            return n
    return 1


_VP_PREVIEW_DIR = VOICEPACK_DIR / "_preview"   # 精选克隆试听（预生成，试听=所见即所得）
# 克隆试听台词：自证式文案——听的人立刻明白"这不是原声，是克隆效果"
_VP_PREVIEW_TEXT = "大家好，欢迎来到直播间。这就是我克隆后的声音，和真人几乎一模一样。"
# P4: 台词可配置。客户听"自己场景"的话术比通用欢迎词更有代入感（转化直接相关）。
_VP_TEXT_FILE = VOICEPACK_DIR / "preview_text.json"          # 当前生效台词（持久化）
_VP_PV_MANIFEST = _VP_PREVIEW_DIR / "manifest.json"          # {spk: 生成时台词md5} → 陈旧检测
_VP_TEXT_TEMPLATES = [
    {"id": "welcome",   "label": "通用欢迎",  "text": _VP_PREVIEW_TEXT},
    {"id": "sale",      "label": "直播带货",  "text": "家人们看过来，这款今天下单立减五十，数量不多，喜欢的抓紧时间拍，错过真没有了！"},
    {"id": "knowledge", "label": "知识讲解",  "text": "今天用三分钟，把这个知识点给你彻底讲透，记得点赞收藏，咱们马上开始。"},
    {"id": "service",   "label": "客服接待",  "text": "您好，很高兴为您服务。您反馈的问题我已经记录下来了，马上就为您处理。"},
]


def _vp_preview_text() -> str:
    try:
        if _VP_TEXT_FILE.exists():
            t = str(json.loads(_VP_TEXT_FILE.read_text(encoding="utf-8")).get("text") or "").strip()
            if t:
                return t
    except Exception as e:
        _logger.warning(f"[voicepack] preview_text.json 解析失败，用默认台词: {e}")
    return _VP_PREVIEW_TEXT


def _vp_text_md5() -> str:
    import hashlib as _hl
    return _hl.md5(_vp_preview_text().encode("utf-8")).hexdigest()


def _vp_pv_manifest() -> dict:
    try:
        if _VP_PV_MANIFEST.exists():
            return json.loads(_VP_PV_MANIFEST.read_text(encoding="utf-8"))
    except Exception:
        pass
    return {}


def _vp_featured() -> dict:
    """{spk: {title, tagline}}——精选橱窗人工命名（featured.json，人工维护）。"""
    f = VOICEPACK_DIR / "featured.json"
    if not f.exists():
        return {}
    try:
        return {r["spk"]: {"title": r.get("title") or "", "tagline": r.get("tagline") or ""}
                for r in json.loads(f.read_text(encoding="utf-8"))}
    except Exception as e:
        _logger.warning(f"[voicepack] featured.json 解析失败: {e}")
        return {}


# VN1 命名体系（2026-07-09）：全库人设名总表，tools/name_voice_pack.py 按特征词库生成，
# 人工可逐条改 json。显示名解析顺序 featured.title > names.title > label > 编号自动名——
# 文件缺失/损坏零影响（自动名兜底），删除即整体回退，这就是回滚方案。
_VP_NAMES_FILE = VOICEPACK_DIR / "names.json"


def _vp_names() -> dict:
    """{spk: {title, note, hl}}——title=人设名；note=名字的特征一句话（tooltip/审阅）；
    hl=全库量化亮点（拼进卡片卖点行，与性别/档位 chips 不重复）。"""
    if not _VP_NAMES_FILE.exists():
        return {}
    try:
        d = json.loads(_VP_NAMES_FILE.read_text(encoding="utf-8"))
        return d if isinstance(d, dict) else {}
    except Exception as e:
        _logger.warning(f"[voicepack] names.json 解析失败(回退编号自动名): {e}")
        return {}


def _vp_ext_rows_raw() -> list:
    """上新音色原始索引（与 index.json 同 schema，多 label/added_at 字段）。"""
    try:
        if _VP_EXT_INDEX.exists():
            return json.loads(_VP_EXT_INDEX.read_text(encoding="utf-8"))
    except Exception as e:
        _logger.warning(f"[voicepack] index_ext.json 解析失败: {e}")
    return []


def _vp_pv_migrate_legacy():
    """P6 一次性迁移：旧版预览是"每人一个 {spk}.wav 覆盖写"，台词一换全部重生成。
    改为 {spk}_{台词md5前8}.wav 按台词缓存后，切回旧台词零成本。存量文件按 manifest
    （没记录的按默认台词）补上哈希后缀，迁移后 manifest 退役。"""
    if not _VP_PREVIEW_DIR.exists():
        return
    import hashlib as _hl
    mf = _vp_pv_manifest()
    dflt = _hl.md5(_VP_PREVIEW_TEXT.encode("utf-8")).hexdigest()
    for f in _VP_PREVIEW_DIR.glob("*.wav"):
        if "_" in f.stem:            # 已是新命名
            continue
        md5 = mf.get(f.stem, dflt)
        try:
            f.rename(_VP_PREVIEW_DIR / f"{f.stem}_{md5[:8]}.wav")
        except Exception as e:
            _logger.warning(f"[voicepack] 预览迁移失败 {f.name}: {e}")


def _vp_pv_files() -> dict:
    """{spk: {台词md5前8, ...}}——一次 glob 建全表，避免 218 行逐个 exists()。"""
    out: dict = {}
    if _VP_PREVIEW_DIR.exists():
        for f in _VP_PREVIEW_DIR.glob("*_*.wav"):
            spk, _, ver = f.stem.rpartition("_")
            if spk:
                out.setdefault(spk, set()).add(ver)
    return out


def _vp_pv_gc():
    """P9: 预览目录总量治理。每音色 4 版 × 218 席会滚到数百 MB——超上限
    (VP_PV_CAP_MB，默认 400MB，0=关) 按 mtime 从旧到新清退；每个音色的最新版本
    受保护，保证"有过试听的音色永远有一条能播"（preview 接口的回退恰好取最新版）。"""
    try:
        cap = int(os.environ.get("VP_PV_CAP_MB", "400")) * 1024 * 1024
        if cap <= 0 or not _VP_PREVIEW_DIR.exists():
            return
        files = [(f, f.stat()) for f in _VP_PREVIEW_DIR.glob("*_*.wav")]
        total = sum(st.st_size for _, st in files)
        if total <= cap:
            return
        newest: dict = {}
        for f, st in files:
            spk = f.stem.rpartition("_")[0]
            if spk not in newest or st.st_mtime > newest[spk][1].st_mtime:
                newest[spk] = (f, st)
        protected = {f for f, _ in newest.values()}
        freed = n = 0
        for f, st in sorted((x for x in files if x[0] not in protected),
                            key=lambda x: x[1].st_mtime):
            if total - freed <= cap:
                break
            try:
                f.unlink()
                freed += st.st_size
                n += 1
            except Exception:
                pass                      # 正在被播放的文件删不动就留到下轮
        if n:
            _logger.info(f"[voicepack] 预览容量治理：清退 {n} 个旧版本 "
                         f"{freed // 1024}KB（总量超 {cap // 1024 // 1024}MB 上限）")
    except Exception as e:
        _logger.warning(f"[voicepack] 预览容量治理失败: {e}")


def _vp_rows() -> list:
    """包索引(内置+上新) → 展示行（含派生档位/星级/自动命名/精选标记）；按相关文件 mtime 缓存。"""
    idx = VOICEPACK_DIR / "index.json"
    if not idx.exists():
        return []
    fjs = VOICEPACK_DIR / "featured.json"
    # 缓存键 = 索引/上新索引/精选/命名表/预览目录/台词 mtime 之和：任一变化列表即时翻新
    mt = idx.stat().st_mtime + (fjs.stat().st_mtime if fjs.exists() else 0) \
        + (_VP_EXT_INDEX.stat().st_mtime if _VP_EXT_INDEX.exists() else 0) \
        + (_VP_NAMES_FILE.stat().st_mtime if _VP_NAMES_FILE.exists() else 0) \
        + (_VP_PREVIEW_DIR.stat().st_mtime if _VP_PREVIEW_DIR.exists() else 0) \
        + (_VP_TEXT_FILE.stat().st_mtime if _VP_TEXT_FILE.exists() else 0)
    if _vp_cache["rows"] is not None and _vp_cache["mtime"] == mt:
        return _vp_cache["rows"]
    _vp_pv_migrate_legacy()
    featured = _vp_featured()
    named = _vp_names()          # VN1: 全库人设名（featured 之外的 206 席）
    cur8 = _vp_text_md5()[:8]
    pv = _vp_pv_files()
    rows = []
    for r in json.loads(idx.read_text(encoding="utf-8")) + _vp_ext_rows_raw():
        spk = r.get("spk") or ""
        if not _VP_SPK_RE.match(spk):
            continue
        gender = r.get("gender") or ""
        band = _vp_band(gender, r.get("f0_med"))
        style = _vp_style(r.get("f0_iqr"))
        # 编号自动名（"低音沉稳男声 1136"）降级为最后兜底：显示名走 featured/names 人设名，
        # 编号只进 spk 字段（tooltip/搜索仍可按编号回查，防重名靠命名表唯一性校验）。
        name = f"{band}{style}{'男声' if gender == 'male' else '女声'} {spk[-4:]}"
        ft = featured.get(spk)
        nm = named.get(spk) or {}
        ext = spk.startswith("EXT")
        vers = pv.get(spk) or set()
        has_cur = cur8 in vers
        rows.append({
            "spk": spk, "gender": gender,
            "age": _VP_AGE_CN.get(r.get("age") or "", ""),
            "accent": _VP_ACCENT_CN.get(r.get("accent") or "", ""),
            "dur": r.get("dur"), "snr": r.get("snr"), "bw": r.get("bw"),
            "f0_med": r.get("f0_med"), "rate": r.get("rate"),
            "band": band, "style": style,
            "stars": _vp_stars(r.get("snr"), r.get("bw")),
            # 卖点行：精选 tagline > 命名表量化亮点(hl) > 上新占位 > 档位场景矩阵
            "scene": (ft or {}).get("tagline") or nm.get("hl") or ("我的上新音色" if ext else "") or _VP_SCENE.get((band, style)) or "自然真声，百搭好用",
            "name": (ft or {}).get("title") or nm.get("title") or (r.get("label") or "").strip() or name,
            "note": nm.get("note") or "",   # 名字的特征（卡片 tooltip 露档案号+由来）
            "featured": bool(ft),
            "ext": ext,
            "has_preview": bool(vers),
            # 陈旧=有预览但没有"当前台词"版本；服务端播报会回退最近版本，故仍可试听
            "pv_stale": bool(vers) and not has_cur,
            "pv_ver": cur8 if has_cur else (sorted(vers)[0] if vers else ""),
        })
        if ext:   # P7: 上新入库时 STT 离线会缺参考文本 → 卡片露"补转写"入口
            t = VOICEPACK_DIR / f"{spk}_ref.txt"
            rows[-1]["has_ref_text"] = bool(t.exists() and t.stat().st_size > 0)
    # 上新最前（自己的东西优先看到），精选次之，其余保持索引序（前端再按用户选择排）
    rows.sort(key=lambda r: (not r["ext"], not r["featured"]))
    _vp_cache.update(mtime=mt, rows=rows)
    return rows


def _vp_backfill_markers():
    """一次性回填：本功能上线前手工从包里建的角色（如"男声低音炮"）没有溯源标记，
    音色库会把同一真人显示成"可导入"→ 重复导入。按内容 md5 比对 wav 与角色内嵌音，
    命中即补 voicepack_spk。每进程只跑一次（结果落库，下次启动命中标记直接跳过）。"""
    if _vp_cache.get("backfilled"):
        return
    _vp_cache["backfilled"] = True
    import hashlib as _hl
    try:
        pack_md5 = {}
        for r in _vp_rows():
            f = VOICEPACK_DIR / f"{r['spk']}_ref.wav"
            if f.exists():
                pack_md5[_hl.md5(f.read_bytes()).hexdigest()] = r["spk"]
        taken = set(p.get("voicepack_spk") for p in _profiles.values())
        for pname, p in list(_profiles.items()):
            if p.get("voicepack_spk") or not p.get("voice_b64"):
                continue
            try:
                h = _hl.md5(base64.b64decode(p["voice_b64"])).hexdigest()
            except Exception:
                continue
            spk = pack_md5.get(h)
            if spk and spk not in taken:
                p["voicepack_spk"] = spk
                taken.add(spk)
                _save_profile(pname)
                _logger.info(f"[voicepack] 回填溯源标记：{pname} ← {spk}")
    except Exception as e:
        _logger.warning(f"[voicepack] 回填溯源标记失败(不影响功能): {e}")


def _vp_imported() -> dict:
    """{spk: 角色名}——扫角色的 voicepack_spk 标记（改名不丢，删角色即消失）。"""
    _vp_backfill_markers()
    return {p.get("voicepack_spk"): pname for pname, p in _profiles.items()
            if p.get("voicepack_spk")}


# ── P13: 音色运营埋点——试听/原声/导入/使用 按天计数（回答"哪些音色值得推"）────
# 外层按天、内层按音色：清旧是删整天，日趋势是取整天，两个高频操作都 O(1)。
# 计数在内存攒、10 秒节流落盘（试听是人手点的，丢秒级尾巴不心疼，不值得每次点击写盘）。
_VP_STATS_FILE = VOICEPACK_DIR / "stats.json"
_vp_stats_lock = threading.Lock()
_vp_stats_mem: dict | None = None
_vp_stats_wrote = 0.0
_VP_STATS_KEEP_D = 35


def _vp_stats() -> dict:
    global _vp_stats_mem
    if _vp_stats_mem is None:
        try:
            _vp_stats_mem = (json.loads(_VP_STATS_FILE.read_text(encoding="utf-8"))
                             if _VP_STATS_FILE.exists() else {})
        except Exception as e:
            _logger.warning(f"[voicepack] stats.json 解析失败，从零开始: {e}")
            _vp_stats_mem = {}
        _vp_stats_mem.setdefault("days", {})
        _vp_stats_mem.setdefault("tot", {})
    return _vp_stats_mem


def _vp_stats_flush(force: bool = False):
    """节流落盘 + 顺手清 35 天前的日桶（调用方须持 _vp_stats_lock）。"""
    global _vp_stats_wrote
    now = time.time()
    if not force and now - _vp_stats_wrote < 10:
        return
    d = _vp_stats()
    cutoff = time.strftime("%Y%m%d", time.localtime(now - _VP_STATS_KEEP_D * 86400))
    for day in [k for k in d["days"] if k < cutoff]:
        d["days"].pop(day, None)
    try:
        _VP_STATS_FILE.write_text(json.dumps(d, ensure_ascii=False), encoding="utf-8")
        _vp_stats_wrote = now
    except Exception as e:
        _logger.warning(f"[voicepack] stats 落盘失败: {e}")


def _vp_stat_bump(spk: str, kind: str):
    """kind: pv=克隆试听 au=原声试听 imp=导入 use=开播/激活使用。"""
    try:
        with _vp_stats_lock:
            d = _vp_stats()
            day = d["days"].setdefault(time.strftime("%Y%m%d"), {})
            row = day.setdefault(spk, {})
            row[kind] = int(row.get(kind, 0)) + 1
            tot = d["tot"].setdefault(spk, {})
            tot[kind] = int(tot.get(kind, 0)) + 1
            tot["last_" + kind] = round(time.time(), 1)
            if kind == "imp" and "first_imp" not in tot:
                tot["first_imp"] = round(time.time(), 1)
            _vp_stats_flush()
    except Exception as e:
        _logger.warning(f"[voicepack] 埋点失败 {spk}/{kind}: {e}")


def _vp_stats_window(days: int) -> dict:
    """近 N 天各音色计数合计：{spk: {pv,au,imp,use}}（含今天）。"""
    d = _vp_stats()
    lo = time.strftime("%Y%m%d", time.localtime(time.time() - (days - 1) * 86400))
    out: dict = {}
    for day, rows in d["days"].items():
        if day < lo:
            continue
        for spk, c in rows.items():
            t = out.setdefault(spk, {"pv": 0, "au": 0, "imp": 0, "use": 0})
            for k in ("pv", "au", "imp", "use"):
                t[k] += int(c.get(k, 0))
    return out


_VP_FAV_FILE = VOICEPACK_DIR / "favorites.json"


def _vp_favs() -> list:
    """收藏音色编号列表（服务端持久化：换浏览器/多端打开不丢，跟 localStorage 方案的差别）。"""
    try:
        if _VP_FAV_FILE.exists():
            return [s for s in json.loads(_VP_FAV_FILE.read_text(encoding="utf-8"))
                    if isinstance(s, str) and _VP_SPK_RE.match(s)]
    except Exception as e:
        _logger.warning(f"[voicepack] favorites.json 解析失败: {e}")
    return []


@app.get("/api/voicepack/preview_text")
def api_vp_preview_text_get():
    """P4: 克隆试听台词配置（模板列表 + 当前生效台词 + 陈旧预览计数）。"""
    text = _vp_preview_text()
    try:
        tid = json.loads(_VP_TEXT_FILE.read_text(encoding="utf-8")).get("template_id", "welcome") \
            if _VP_TEXT_FILE.exists() else "welcome"
    except Exception:
        tid = "welcome"
    if not any(t["text"] == text for t in _VP_TEXT_TEMPLATES):
        tid = "custom"
    stale_n = sum(1 for r in _vp_rows() if r.get("pv_stale"))
    return {"ok": True, "text": text, "template_id": tid, "templates": _VP_TEXT_TEMPLATES,
            "stale_n": stale_n, "text_md5": _vp_text_md5()[:8]}


@app.post("/api/voicepack/preview_text")
def api_vp_preview_text_set(body: dict = Body(default={})):
    """切换克隆试听台词（模板 id 或自定义 text）。切换后旧预览标为陈旧，需重生成。"""
    tid = str(body.get("template_id") or "").strip()
    custom = str(body.get("text") or "").strip()
    if tid:
        t = next((x for x in _VP_TEXT_TEMPLATES if x["id"] == tid), None)
        if not t:
            raise HTTPException(400, "未知模板")
        text, save_tid = t["text"], tid
    elif custom:
        if len(custom) < 8 or len(custom) > 120:
            raise HTTPException(400, "台词需 8~120 字")
        text, save_tid = custom, "custom"
    else:
        raise HTTPException(400, "需要 template_id 或 text")
    try:
        _VP_TEXT_FILE.write_text(json.dumps({"text": text, "template_id": save_tid},
                                            ensure_ascii=False, indent=2), encoding="utf-8")
    except Exception as e:
        raise HTTPException(500, f"台词保存失败: {e}")
    _vp_cache["mtime"] = 0
    stale_n = sum(1 for r in _vp_rows() if r.get("pv_stale"))
    return {"ok": True, "text": text, "template_id": save_tid, "stale_n": stale_n}


@app.get("/api/voicepack")
def api_voicepack():
    """真人音色库列表：全部派生字段 + 已导入映射（不含 ref_text，正文导入时才读）。
    use_n=对应导入角色的会话级使用次数（P3 常用自动置顶；请求时实算，不进 rows 缓存）。"""
    rows = _vp_rows()
    imp = _vp_imported()
    tier_on = _VP_TIER == "featured_free"
    out = [dict(r, imported=imp.get(r["spk"], ""),
                use_n=_usage_n(imp.get(r["spk"], "")),
                # P8: 锁=分层开 且 非精选/非上新/未导入（已导入的永远保留，不做"回收式"付费墙）
                locked=bool(tier_on and not r["featured"] and not r.get("ext")
                            and r["spk"] not in imp))
           for r in rows]
    return {"ok": True, "total": len(rows), "available": bool(rows),
            "favs": _vp_favs(),
            "ext_trash_n": len(_vp_ext_trash_items()),   # P7: 上新回收目录角标
            "tier": {"mode": _VP_TIER or "off",
                     "locked_n": sum(1 for r in out if r["locked"])},
            "dist_protected": bool(_VP_DIST_TOKEN),      # P11: UI 导出前知道要不要口令
            "subs_n": len(_vp_subs_load()["subs"]),      # P12: 订阅角标
            "rows": out}


@app.post("/api/voicepack/favs")
def api_voicepack_fav_set(body: dict = Body(default={})):
    """收藏/取消收藏一个音色（幂等）。body: {spk, fav:true/false}"""
    spk = str(body.get("spk") or "")
    if not _VP_SPK_RE.match(spk):
        raise HTTPException(400, "非法音色编号")
    favs = _vp_favs()
    want = bool(body.get("fav"))
    if want and spk not in favs:
        favs.append(spk)
    elif not want and spk in favs:
        favs.remove(spk)
    try:
        _VP_FAV_FILE.write_text(json.dumps(favs, ensure_ascii=False), encoding="utf-8")
    except Exception as e:
        raise HTTPException(500, f"收藏写入失败: {e}")
    return {"ok": True, "favs": favs}


