@app.post("/api/voicepack/{spk}/import")
async def api_voicepack_import(spk: str, body: dict = Body(default={})):
    """一键导入为角色（幂等：已导入直接回既有角色名，绝不产生副本）。
    参考音 base64 内嵌 + reference_text 进 fish_tts_params——与手工建角色同一数据形态，
    TTS/翻译/对话全链路零改动即可用。body.name 可选自定义角色名。"""
    if not _VP_SPK_RE.match(spk or ""):
        raise HTTPException(400, "非法音色编号")
    row = next((r for r in _vp_rows() if r["spk"] == spk), None)
    if row is None:
        raise HTTPException(404, "音色不在索引中")
    imp = _vp_imported()
    if spk in imp:
        return {"ok": True, "name": imp[spk], "already": True}
    # P8 分层：已导入的在上面直接放行（老用户资产不回收）；新导入只开放精选+自有上新
    if _VP_TIER == "featured_free" and not row["featured"] and not row.get("ext"):
        raise HTTPException(402, "该音色属于付费全库：当前套餐可导入精选与自有上新，"
                                 "全库试听不受限，升级后 218 位随心导入")
    wav = VOICEPACK_DIR / f"{spk}_ref.wav"
    if not wav.exists():
        raise HTTPException(404, "音色样本文件缺失")
    txt = VOICEPACK_DIR / f"{spk}_ref.txt"
    ref_text = txt.read_text(encoding="utf-8").strip() if txt.exists() else ""
    name = (body.get("name") or "").strip() or row["name"]
    _check_profile_name(name)
    async with _PROFILES_LOCK:
        if name in _profiles:      # 撞上手工建的同名角色 → 编号后缀避让一次
            name = f"{name} {spk[-4:]}"
            if name in _profiles:
                raise HTTPException(409, f"角色名冲突：{name}")
        _profiles[name] = {
            "description": (f"真人音色库 {spk} · {row['age']}"
                            f"{'男' if row['gender'] == 'male' else '女'}声 · "
                            f"{row['accent']} · {row['scene']}"),
            "face_b64": "", "face_gallery_b64": [],
            "voice_name": "",
            "voice_b64": base64.b64encode(wav.read_bytes()).decode(),
            "hair_style": "", "rvc_model": "", "rvc_settings": {},
            "rvc_strict_mode": True, "lipsync_engine": "", "faceswap_engine": "",
            "idle_video": "", "body_video": "", "thumbnail_b64": "",
            "created_at": time.time(),
            "fish_tts_params": {"reference_text": ref_text},
            "voicepack_spk": spk,
        }
        if not _save_profile(name):
            del _profiles[name]
            raise HTTPException(500, "角色保存失败，请重试")
    await broadcast({"event": "profile_created", "name": name})
    _vp_stat_bump(spk, "imp")    # P13: 导入转化计数
    asyncio.create_task(_async_generate_preview(name))      # 预生成试听（与手工建角色一致）
    asyncio.create_task(_async_seed_voice_quality(name))    # 声纹质量基线首点
    return {"ok": True, "name": name, "already": False}


@app.get("/api/voicepack/{spk}/preview")
def api_voicepack_preview(spk: str):
    """精选/上新克隆试听（P6 按台词哈希缓存）：优先当前台词版本，缺失回退最近版本
    （试听不至于 404，前端另有 pv_stale 提醒重生成）。"""
    if not _VP_SPK_RE.match(spk or ""):
        raise HTTPException(400, "非法音色编号")
    f = _VP_PREVIEW_DIR / f"{spk}_{_vp_text_md5()[:8]}.wav"
    if not f.exists():
        cands = sorted(_VP_PREVIEW_DIR.glob(f"{spk}_*.wav"),
                       key=lambda p: p.stat().st_mtime, reverse=True)
        if not cands:
            raise HTTPException(404, "该音色暂无克隆试听（精选/上新才预生成）")
        f = cands[0]
    try:
        os.utime(f)      # P10: 播放即触摸——容量治理(_vp_pv_gc)按 mtime 清退=真 LRU（最久没人听的先走）
    except Exception:
        pass
    _vp_stat_bump(spk, "pv")     # P13: 克隆试听计数
    return FileResponse(str(f), media_type="audio/wav", filename=f.name)


_vp_gen_lock = asyncio.Lock()   # 预生成串行闸：一次一批，防并发打爆 TTS


@app.post("/api/voicepack/gen_previews")
async def api_voicepack_gen_previews(body: dict = Body(default={})):
    """为精选音色批量预生成克隆试听（缺啥补啥，force=true 全量重生成）。
    走对话同款 _conv_synthesize(Fish 零样本克隆)——与实际开播效果同源，试听不骗人。
    通话进行中直接 503 让路（同传是硬实时，GPU 不能被批量合成抢）。"""
    if _vp_gen_lock.locked():
        raise HTTPException(409, "已有预生成任务在跑")
    # GPU 让路：与 _train_when_free.py 同一套语义——running=True 还要看"活动"。
    # 会话常被挂着忘停(2026-07-08 实测 stream_on 但计数 12s 零变化)，
    # 只认 running 位会让预生成永远等一个空会话；比对两次计数，动了才算真通话。
    try:
        async with _aclient(timeout=2) as _c:
            m1 = (await _c.get("http://127.0.0.1:7900/metrics")).json()
            if m1.get("running"):
                await asyncio.sleep(4)
                m2 = (await _c.get("http://127.0.0.1:7900/metrics")).json()
                s1, s2 = m1.get("stream") or {}, m2.get("stream") or {}
                if (s1.get("part"), s1.get("fin")) != (s2.get("part"), s2.get("fin")):
                    raise HTTPException(503, "同传通话进行中，暂不生成（稍后再点）")
    except HTTPException:
        raise
    except Exception:
        pass   # 同传服务没起 = 没有通话，放行
    force = bool(body.get("force"))
    # P6: 上新音色(EXT)与精选一样有克隆试听——自己传的声音更需要"听克隆效果"来验货
    want = body.get("spks") or [r["spk"] for r in _vp_rows() if r["featured"] or r.get("ext")]
    preview_text = _vp_preview_text()
    cur8 = _vp_text_md5()[:8]
    async with _vp_gen_lock:
        _VP_PREVIEW_DIR.mkdir(exist_ok=True)
        done, fail, skip = [], [], []
        for spk in want:
            if not _VP_SPK_RE.match(spk or ""):
                continue
            # P6 按台词哈希缓存：当前台词的版本已存在 = 直接命中（切回旧模板零重生成）
            out = _VP_PREVIEW_DIR / f"{spk}_{cur8}.wav"
            if out.exists() and not force:
                skip.append(spk)
                continue
            wav = VOICEPACK_DIR / f"{spk}_ref.wav"
            txt = VOICEPACK_DIR / f"{spk}_ref.txt"
            if not wav.exists():
                fail.append(spk)
                continue
            p = {"name": f"voicepack:{spk}", "tts_engine": "fish_speech",
                 "voice_b64": base64.b64encode(wav.read_bytes()).decode(),
                 "fish_tts_params": {"reference_text":
                                     txt.read_text(encoding="utf-8").strip() if txt.exists() else ""}}
            try:
                b64 = await _conv_synthesize(preview_text, p, language="zh-cn",
                                             emotion="neutral", vc_engine="",
                                             watermark=None, _use_opener_cache=False)
                if b64:
                    out.write_bytes(base64.b64decode(b64))
                    done.append(spk)
                    # 每人最多留 4 个台词版本（够 welcome/带货/讲解/自定义轮换），再多删最旧的
                    olds = sorted(_VP_PREVIEW_DIR.glob(f"{spk}_*.wav"),
                                  key=lambda f: f.stat().st_mtime, reverse=True)[4:]
                    for f in olds:
                        try:
                            f.unlink()
                        except Exception:
                            pass
                else:
                    fail.append(spk)
            except Exception as e:
                _logger.warning(f"[voicepack] 预生成失败 {spk}: {e}")
                fail.append(spk)
        _vp_pv_gc()              # P9: 批量生成后一次容量治理（LRU 清退超额旧版本）
        _vp_cache["mtime"] = 0   # 列表缓存失效 → has_preview/pv_stale 立即翻新
    return {"ok": True, "generated": done, "skipped": skip, "failed": fail, "text": preview_text}


# ═══ P6 音色上新：上传干声 → 体检/声学分析/ASR 转写 → EXT 编号入库 ═══════════
# 与 tools/_build_voice_pack.py 同一套分析口径（snr/bw/f0/语速），上新行和内置 218 人
# 同 schema 进同一张列表——档位/星级/排序/试听/导入全链路零特判。

def _vp_audio_stats(x, sr) -> dict:
    """单段音频声学体检：信噪比/有效频宽/削波率/F0 中位与四分位距。"""
    import numpy as np
    win = max(1, int(sr * 0.03)); hop = max(1, int(sr * 0.01))
    if x.size < win:
        db = np.array([20 * np.log10(float(np.sqrt(np.mean(x ** 2))) + 1e-9)])
    else:
        n = 1 + (x.size - win) // hop
        idx = np.arange(win)[None, :] + hop * np.arange(n)[:, None]
        db = 20 * np.log10(np.sqrt(np.mean(x[idx] ** 2, axis=1)) + 1e-9)
    voiced = db[db > db.max() - 35]
    snr = float(np.percentile(voiced, 90)) - float(np.percentile(db, 10))
    clip = float(np.mean(np.abs(x) > 0.985)) * 100
    nfft = 4096
    y = np.pad(x, (0, max(0, nfft - x.size)))
    nseg = max(1, y.size // nfft)
    spec = np.abs(np.fft.rfft(y[: nseg * nfft].reshape(nseg, nfft) * np.hanning(nfft), axis=1)).mean(axis=0)
    sdb = 20 * np.log10(spec + 1e-9); sdb -= sdb.max()
    freqs = np.fft.rfftfreq(nfft, 1 / sr)
    keep = np.where(sdb > -50)[0]
    bw = float(freqs[keep[-1]] / 1000) if keep.size else 0.0
    # F0 用自相关（60~420Hz）。44.1k 全速跑一帧要 1764² 次乘加，先抗混叠均值滤波+抽取
    # 到 ~15kHz——基频远低于折叠区，峰位不受影响，耗时降一个数量级。
    xf, sf_ = x, sr
    dec = max(1, int(sr // 15000))
    if dec > 1:
        xf = np.convolve(x, np.ones(dec) / dec, mode="same")[::dec]
        sf_ = sr / dec
    fwin = int(sf_ * 0.04); fhop = int(sf_ * 0.01)
    lo, hi = max(1, int(sf_ / 420)), int(sf_ / 60)
    f0s = []
    for i in range(0, xf.size - fwin, fhop):
        fr = xf[i:i + fwin]
        e = float(np.sqrt(np.mean(fr ** 2)))
        if e < 0.02:
            continue
        fr = fr - fr.mean()
        ac = np.correlate(fr, fr, "full")[fwin - 1:]
        if ac[0] <= 0:
            continue
        seg = ac[lo:hi]
        if seg.size == 0:
            continue
        k = int(np.argmax(seg)) + lo
        if ac[k] / ac[0] < 0.45:
            continue
        f0s.append(sf_ / k)
    if len(f0s) >= 10:
        f0_med = float(np.median(np.array(f0s)))
        f0_iqr = float(np.percentile(f0s, 75) - np.percentile(f0s, 25))
    else:
        f0_med = f0_iqr = None
    return dict(snr=round(snr, 1), bw=round(bw, 1), clip=round(clip, 3),
                f0_med=round(f0_med, 1) if f0_med else None,
                f0_iqr=round(f0_iqr, 1) if f0_iqr else None)


def _vp_ext_next_id() -> str:
    """下一个空闲 EXT 编号（含回收站占用——还原/追查时编号不撞车）。"""
    used = set()
    for r in _vp_ext_rows_raw():
        m = re.match(r"^EXT(\d{4})$", r.get("spk") or "")
        if m:
            used.add(int(m.group(1)))
    if _VP_EXT_TRASH.exists():
        for f in _VP_EXT_TRASH.iterdir():
            m = re.search(r"EXT(\d{4})", f.name)
            if m:
                used.add(int(m.group(1)))
    n = 1
    while n in used:
        n += 1
    return f"EXT{n:04d}"


async def _vp_gen_preview_one(spk: str):
    """上新后台补一条克隆试听（拿不到闸就算了，用户可点「补齐」按钮）。"""
    try:
        if _vp_gen_lock.locked():
            return
        wav = VOICEPACK_DIR / f"{spk}_ref.wav"
        if not wav.exists():
            return
        txt = VOICEPACK_DIR / f"{spk}_ref.txt"
        async with _vp_gen_lock:
            _VP_PREVIEW_DIR.mkdir(exist_ok=True)
            p = {"name": f"voicepack:{spk}", "tts_engine": "fish_speech",
                 "voice_b64": base64.b64encode(wav.read_bytes()).decode(),
                 "fish_tts_params": {"reference_text":
                                     txt.read_text(encoding="utf-8").strip() if txt.exists() else ""}}
            b64 = await _conv_synthesize(_vp_preview_text(), p, language="zh-cn",
                                         emotion="neutral", vc_engine="",
                                         watermark=None, _use_opener_cache=False)
            if b64:
                (_VP_PREVIEW_DIR / f"{spk}_{_vp_text_md5()[:8]}.wav").write_bytes(base64.b64decode(b64))
                _vp_pv_gc()
                _vp_cache["mtime"] = 0
    except Exception as e:
        _logger.warning(f"[voicepack] 上新试听补生成失败 {spk}: {e}")


@app.post("/api/voicepack/ingest")
async def api_voicepack_ingest(files: List[UploadFile] = File(...),
                               label: str = Form(""), gender: str = Form("auto")):
    """音色上新：传 1~8 段同一个人的干声（wav/flac/ogg/mp3），自动体检挑最干净的段
    拼 ~20s 参考音 + 声学分析 + ASR 转写，按 EXT 编号进音色库（与内置音色同等地位：
    档位/星级/试听/导入/收藏全可用）。质量太差直接拒收并说明原因，不让脏样本进库拉低克隆。"""
    import io as _io
    import numpy as np
    try:
        import soundfile as sf
    except ImportError:
        raise HTTPException(500, "服务器缺 soundfile 依赖，无法解析音频")
    if not files or len(files) > 8:
        raise HTTPException(400, "一次传 1~8 个音频文件（同一个人的干声）")
    label = (label or "").strip()[:24]
    clips, warns = [], []
    for uf in files:
        raw = await uf.read()
        if len(raw) > 30 * 1024 * 1024:
            warns.append(f"{uf.filename}: 超 30MB 跳过")
            continue
        try:
            x, sr = sf.read(_io.BytesIO(raw), dtype="float32", always_2d=True)
            x = x.mean(axis=1)
        except Exception:
            warns.append(f"{uf.filename}: 无法解析（支持 wav/flac/ogg/mp3）")
            continue
        if x.size < sr * 1.0:
            warns.append(f"{uf.filename}: 不足 1 秒跳过")
            continue
        x = x[: int(sr * 60)]                       # 单段最多取 60s，够挑了
        st = _vp_audio_stats(x, sr)
        clips.append(dict(fn=uf.filename, x=x, sr=sr, dur=x.size / sr, **st))
    if not clips:
        raise HTTPException(400, "没有可用音频。" + ("；".join(warns) if warns else ""))
    # 混采样率：只留总时长最长的那组（重采样引入的失真不值得，直接说清楚让用户重传）
    by_sr: dict = {}
    for c in clips:
        by_sr.setdefault(c["sr"], []).append(c)
    sr_pick = max(by_sr, key=lambda s: sum(c["dur"] for c in by_sr[s]))
    if len(by_sr) > 1:
        dropped = [c["fn"] for s, g in by_sr.items() if s != sr_pick for c in g]
        warns.append(f"采样率不一致，丢弃 {len(dropped)} 段: {'、'.join(dropped[:3])}")
    group = sorted(by_sr[sr_pick], key=lambda c: -c["snr"])
    sel, total = [], 0.0
    for c in group:
        if c["clip"] > 0.5:                        # 重削波段不进参考音
            warns.append(f"{c['fn']}: 削波严重({c['clip']:.1f}%)未选用")
            continue
        sel.append(c); total += c["dur"] + 0.25
        if total >= 25.0:
            break
    if not sel:
        sel = group[:3]
    y_total = sum(c["dur"] for c in sel)
    if y_total < 4.0:
        raise HTTPException(400, f"有效样本仅 {y_total:.1f} 秒，克隆至少要 4 秒（建议 10~30 秒干声）")
    gap = np.zeros(int(sr_pick * 0.25), dtype=np.float32)
    pieces = []
    for c in sel:
        pieces.append(c["x"]); pieces.append(gap)
    y = np.concatenate(pieces[:-1])[: int(sr_pick * 40)]     # 参考音上限 40s
    peak = float(np.abs(y).max()) or 1.0
    y = y * min(1.0, 0.9 / peak)
    st = _vp_audio_stats(y, sr_pick)
    if st["snr"] < 18:
        raise HTTPException(400, f"底噪太大（信噪比 {st['snr']:.0f}dB < 18dB），克隆会含混发闷。"
                                 "请在安静环境重录，或先降噪再传")
    if st["snr"] < 28:
        warns.append(f"信噪比 {st['snr']:.0f}dB 偏低，克隆音质可能打折（棚录参考 60dB+）")
    # ASR 转写做参考文本（Fish 带 reference_text 克隆更稳）。STT 不在线不挡上新。
    ref_text = ""
    try:
        buf = _io.BytesIO()
        sf.write(buf, y, sr_pick, format="WAV", subtype="PCM_16")
        async with _aclient(timeout=90) as c:
            r = await c.post(f"{SERVICES.get('stt', 'http://127.0.0.1:7854')}/transcribe",
                             files={"audio": ("ref.wav", buf.getvalue(), "application/octet-stream")},
                             data={"language": "auto"})
            if r.status_code == 200:
                ref_text = (r.json().get("text") or "").strip()[:500]
    except Exception as e:
        _logger.warning(f"[voicepack] 上新 ASR 转写失败(不影响入库): {e}")
    if not ref_text:
        warns.append("语音转写服务未在线，参考文本留空（克隆可用，但建议之后补齐更稳）")
    g = gender if gender in ("male", "female") else \
        (("male" if st["f0_med"] < 170 else "female") if st["f0_med"] else "female")
    speech_s = sum(c["dur"] for c in sel)
    with _vp_ext_lock:
        spk = _vp_ext_next_id()
        try:
            sf.write(str(VOICEPACK_DIR / f"{spk}_ref.wav"), y, sr_pick, subtype="PCM_16")
            (VOICEPACK_DIR / f"{spk}_ref.txt").write_text(ref_text, encoding="utf-8")
            rows = _vp_ext_rows_raw()
            rows.append(dict(spk=spk, split="ext", age="", gender=g, accent="",
                             sr=sr_pick, n_clips=len(sel), dur=round(y.size / sr_pick, 1),
                             snr=st["snr"], bw=st["bw"], clip=st["clip"],
                             f0_med=st["f0_med"], f0_iqr=st["f0_iqr"],
                             rate=round(len(ref_text) / speech_s, 2) if (ref_text and speech_s) else None,
                             ref_text=ref_text, label=label, added_at=time.time()))
            _VP_EXT_INDEX.write_text(json.dumps(rows, ensure_ascii=False, indent=1),
                                     encoding="utf-8")
        except Exception as e:
            for suf in ("_ref.wav", "_ref.txt"):     # 半成品不留盘
                try:
                    (VOICEPACK_DIR / f"{spk}{suf}").unlink(missing_ok=True)
                except Exception:
                    pass
            raise HTTPException(500, f"入库写盘失败: {e}")
    _vp_cache["mtime"] = 0
    asyncio.create_task(_vp_gen_preview_one(spk))    # 后台补克隆试听，不拖上传响应
    row = next((r for r in _vp_rows() if r["spk"] == spk), None)
    _logger.info(f"[voicepack] 上新入库 {spk} label={label!r} dur={y.size / sr_pick:.1f}s "
                 f"snr={st['snr']} clips={len(sel)}")
    return {"ok": True, "spk": spk, "row": row, "warns": warns}


@app.delete("/api/voicepack/{spk}")
def api_voicepack_ext_delete(spk: str):
    """删除上新音色（仅 EXT；内置包只读）。软删进 _ext_trash 可手工找回；
    已导入的角色内嵌了参考音副本，不受影响（仅"已入库"徽标消失）。"""
    if not re.match(r"^EXT\d{4}$", spk or ""):
        raise HTTPException(400, "只能删除上新音色（EXT 编号）")
    with _vp_ext_lock:
        rows = _vp_ext_rows_raw()
        keep = [r for r in rows if r.get("spk") != spk]
        if len(keep) == len(rows):
            raise HTTPException(404, "上新音色不存在")
        _VP_EXT_TRASH.mkdir(exist_ok=True)
        ts = int(time.time())
        # P7: 索引行随文件进回收目录——还原时按原样重建（名字/统计/转写一个不丢），
        # 不用对着 wav 重新分析猜。P8: 主打标记也随快照走，还原后 ⭐ 原样回来。
        try:
            row_gone = next(r for r in rows if r.get("spk") == spk)
            ftd = _vp_featured().get(spk)
            snap = dict(row_gone, **({"_featured": ftd} if ftd else {}))
            (_VP_EXT_TRASH / f"{ts}_{spk}.meta.json").write_text(
                json.dumps(snap, ensure_ascii=False, indent=1), encoding="utf-8")
        except Exception as e:
            _logger.warning(f"[voicepack] 上新软删存元数据失败(仍可还原,统计将重算): {e}")
        moved = []
        for f in [VOICEPACK_DIR / f"{spk}_ref.wav", VOICEPACK_DIR / f"{spk}_ref.txt",
                  *(_VP_PREVIEW_DIR.glob(f"{spk}_*.wav") if _VP_PREVIEW_DIR.exists() else [])]:
            if f.exists():
                try:
                    f.rename(_VP_EXT_TRASH / f"{ts}_{f.name}")
                    moved.append(f.name)
                except Exception as e:
                    _logger.warning(f"[voicepack] 上新软删移文件失败 {f.name}: {e}")
        _VP_EXT_INDEX.write_text(json.dumps(keep, ensure_ascii=False, indent=1),
                                 encoding="utf-8")
    favs = _vp_favs()
    if spk in favs:
        favs.remove(spk)
        try:
            _VP_FAV_FILE.write_text(json.dumps(favs, ensure_ascii=False), encoding="utf-8")
        except Exception:
            pass
    ftf = VOICEPACK_DIR / "featured.json"        # P8: 主打标记随删（快照里已备份，还原会带回）
    try:
        if ftf.exists():
            lst = json.loads(ftf.read_text(encoding="utf-8"))
            keep_ft = [x for x in lst if x.get("spk") != spk]
            if len(keep_ft) != len(lst):
                ftf.write_text(json.dumps(keep_ft, ensure_ascii=False, indent=1), encoding="utf-8")
    except Exception as e:
        _logger.warning(f"[voicepack] 删除时清主打标记失败: {e}")
    _vp_cache["mtime"] = 0
    imported = _vp_imported().get(spk, "")
    return {"ok": True, "spk": spk, "moved": moved, "imported_profile": imported}


@app.post("/api/voicepack/{spk}/feature")
def api_voicepack_feature(spk: str, body: dict = Body(default={})):
    """P8: 上新音色设/撤「主打」。写 featured.json（与内置精选同一张表零特判）：
    卡片打 ⭐ 徽标 + 卖点可自定义；导入成角色后，同传下拉自动升入 ⭐精选组。
    仅 EXT 可操作——内置 12 席是产品运营位，用户侧不动。"""
    if not re.match(r"^EXT\d{4}$", spk or ""):
        raise HTTPException(400, "仅上新音色支持设主打")
    row = next((r for r in _vp_rows() if r["spk"] == spk), None)
    if row is None:
        raise HTTPException(404, "音色不存在")
    want = bool(body.get("featured"))
    title = (str(body.get("title") or "")).strip()[:24]
    tagline = (str(body.get("tagline") or "")).strip()[:60]
    f = VOICEPACK_DIR / "featured.json"
    with _vp_ext_lock:                      # featured.json 读改写与删除/还原互斥
        try:
            lst = json.loads(f.read_text(encoding="utf-8")) if f.exists() else []
        except Exception:
            lst = []
        lst = [x for x in lst if x.get("spk") != spk]
        if want:
            lst.append({"spk": spk, "title": title or row["name"],
                        "tagline": tagline or row["scene"]})
        try:
            f.write_text(json.dumps(lst, ensure_ascii=False, indent=1), encoding="utf-8")
        except Exception as e:
            raise HTTPException(500, f"主打标记写入失败: {e}")
    _vp_cache["mtime"] = 0
    return {"ok": True, "spk": spk, "featured": want}


@app.post("/api/voicepack/{spk}/transcribe")
async def api_voicepack_transcribe(spk: str):
    """P7 补转写：上新时 STT 离线导致参考文本缺失的音色，STT 恢复后一键回填。
    连带三件事：索引行 ref_text/rate 更新、已导入角色的 reference_text 同步（仅补空值，
    不覆盖手工填写）、后台按参考文本重出克隆试听（Fish 带文本克隆更稳）。"""
    if not re.match(r"^EXT\d{4}$", spk or ""):
        raise HTTPException(400, "仅上新音色支持补转写（内置包自带转写）")
    wav = VOICEPACK_DIR / f"{spk}_ref.wav"
    if not wav.exists():
        raise HTTPException(404, "参考音不存在")
    try:
        async with _aclient(timeout=90) as c:
            r = await c.post(f"{SERVICES.get('stt', 'http://127.0.0.1:7854')}/transcribe",
                             files={"audio": ("ref.wav", wav.read_bytes(), "application/octet-stream")},
                             data={"language": "auto"})
            r.raise_for_status()
            text = (r.json().get("text") or "").strip()[:500]
    except Exception as e:
        raise HTTPException(502, f"语音转写服务不可用（启动 STT 后再试）: {e}")
    if not text:
        raise HTTPException(422, "转写结果为空——样本可能没有清晰人声")
    (VOICEPACK_DIR / f"{spk}_ref.txt").write_text(text, encoding="utf-8")
    with _vp_ext_lock:
        rows = _vp_ext_rows_raw()
        for r0 in rows:
            if r0.get("spk") == spk:
                r0["ref_text"] = text
                if r0.get("dur"):
                    r0["rate"] = round(len(text) / float(r0["dur"]), 2)
        _VP_EXT_INDEX.write_text(json.dumps(rows, ensure_ascii=False, indent=1),
                                 encoding="utf-8")
    prof_updated = ""
    pname = _vp_imported().get(spk)
    if pname and pname in _profiles:
        ftp = _profiles[pname].setdefault("fish_tts_params", {})
        if not (ftp.get("reference_text") or "").strip():
            ftp["reference_text"] = text
            if _save_profile(pname):
                prof_updated = pname
    _vp_cache["mtime"] = 0
    asyncio.create_task(_vp_gen_preview_one(spk))   # 带文本重出试听，覆盖旧的无文本版
    _logger.info(f"[voicepack] 补转写 {spk}: {len(text)} 字"
                 + (f"，已同步角色「{prof_updated}」" if prof_updated else ""))
    return {"ok": True, "spk": spk, "text": text, "profile_updated": prof_updated}


# P11: 分发口令（跨公网/不可信网段分发时设 VP_DIST_TOKEN；默认空=LAN 信任模型，行为不变）。
# 护的是 catalog/export/export_all 三个"往外发资产"的口子——导入侧不用改，口令随 URL 走。
_VP_DIST_TOKEN = os.environ.get("VP_DIST_TOKEN", "").strip()

_vp_sha_cache: dict = {}     # spk -> (wav mtime, sha256)——清单/去重共用，改动即失效


def _vp_wav_sha(spk: str) -> str:
    """EXT 参考音内容指纹（mtime 缓存）。清单曝光它=订阅端零下载判重的关键。"""
    f = VOICEPACK_DIR / f"{spk}_ref.wav"
    st = f.stat()
    hit = _vp_sha_cache.get(spk)
    if hit and hit[0] == st.st_mtime:
        return hit[1]
    import hashlib
    sha = hashlib.sha256(f.read_bytes()).hexdigest()
    _vp_sha_cache[spk] = (st.st_mtime, sha)
    return sha


def _vp_dist_check(token: str):
    if not _VP_DIST_TOKEN:
        return
    import hmac as _h
    if not (token and _h.compare_digest(str(token), _VP_DIST_TOKEN)):
        raise HTTPException(401, "分发口令不对或未带（URL 加 ?token=口令）")


def _vp_export_pack_bytes(spk: str, row: dict) -> bytes:
    """单音色 → 标准音色包 zip 字节（单导 / 整库打包共用）。"""
    import hashlib
    import io as _io
    import zipfile
    wb = (VOICEPACK_DIR / f"{spk}_ref.wav").read_bytes()
    txt = VOICEPACK_DIR / f"{spk}_ref.txt"
    tb = txt.read_text(encoding="utf-8").strip() if txt.exists() else ""
    meta = {"fmt": "avatarhub-voicepack/1", "exported_at": time.time(),
            "src_spk": spk, "row": row, "featured": _vp_featured().get(spk),
            "sha256_wav": hashlib.sha256(wb).hexdigest()}
    buf = _io.BytesIO()
    with zipfile.ZipFile(buf, "w", zipfile.ZIP_DEFLATED) as z:
        z.writestr("voice.wav", wb)
        z.writestr("voice.txt", tb)
        z.writestr("pack.json", json.dumps(meta, ensure_ascii=False, indent=1))
    return buf.getvalue()


@app.get("/api/voicepack/{spk}/export")
def api_voicepack_export(spk: str, token: str = ""):
    """P9: 上新音色打包导出——zip(参考音+转写+元数据+校验和)，跨机分发的包格式。
    仅 EXT：内置库是产品资产（分层解锁的锁对象），放开导出=绕过付费墙。"""
    _vp_dist_check(token)
    if not re.match(r"^EXT\d{4}$", spk or ""):
        raise HTTPException(400, "仅上新音色支持导出")
    row = next((r for r in _vp_ext_rows_raw() if r.get("spk") == spk), None)
    if row is None:
        raise HTTPException(404, "上新音色不存在")
    if not (VOICEPACK_DIR / f"{spk}_ref.wav").exists():
        raise HTTPException(404, "参考音文件缺失")
    from urllib.parse import quote
    data = _vp_export_pack_bytes(spk, row)
    name = f"voicepack_{(row.get('label') or '').strip() or spk}_{spk}.zip"
    _logger.info(f"[voicepack] 导出音色包 {spk} label={row.get('label')!r} {len(data) // 1024}KB")
    return Response(data, media_type="application/zip",
                    headers={"Content-Disposition":
                             f"attachment; filename=\"{spk}.zip\"; filename*=UTF-8''{quote(name)}"})


@app.get("/api/voicepack/export_all")
def api_voicepack_export_all(token: str = ""):
    """P11: 整库打包（新机开荒/U 盘场景）——外层 zip 装 N 个标准音色包 + bundle.json。
    内层已 deflate，外层 STORED 免二次压缩；导入侧自动识别 bundle 逐包入库（幂等）。"""
    _vp_dist_check(token)
    rows = [r for r in _vp_ext_rows_raw()
            if (VOICEPACK_DIR / f"{r.get('spk')}_ref.wav").exists()]
    if not rows:
        raise HTTPException(404, "还没有上新音色可打包")
    import io as _io
    import zipfile
    outer = _io.BytesIO()
    names = []
    with zipfile.ZipFile(outer, "w") as zo:
        for r in rows:
            spk = r["spk"]
            try:
                zo.writestr(f"packs/{spk}.zip", _vp_export_pack_bytes(spk, r),
                            compress_type=zipfile.ZIP_STORED)
                names.append({"spk": spk, "name": (r.get("label") or "").strip() or spk})
            except Exception as e:
                _logger.warning(f"[voicepack] 整库打包跳过 {spk}: {e}")
        zo.writestr("bundle.json", json.dumps(
            {"fmt": "avatarhub-voicebundle/1", "exported_at": time.time(), "packs": names},
            ensure_ascii=False, indent=1))
    fname = f"voicebundle_{_dt.date.today():%Y%m%d}_{len(names)}packs.zip"
    _logger.info(f"[voicepack] 整库打包 {len(names)} 包 {outer.tell() // 1024}KB")
    return Response(outer.getvalue(), media_type="application/zip",
                    headers={"Content-Disposition": f'attachment; filename="{fname}"'})


async def _vp_import_pack_bytes(raw: bytes) -> dict:
    """P9/P10: 音色包字节流入库（文件上传与 URL 拉取共用）。EXT 编号本机重新分配
    （编号是机器本地概念，不信包里带的）；校验和验证防损坏；同内容已在库=幂等回
    既有编号，跨机反复分发不产生副本；主打身份随包恢复。质量门不重跑——源头入库
    已体检，分发环节再拒收会让"总部调好→门店导入"的流程随机翻车。"""
    import hashlib
    import io as _io
    import zipfile
    if len(raw) > 64 * 1024 * 1024:
        raise HTTPException(400, "音色包超 64MB")
    try:
        z = zipfile.ZipFile(_io.BytesIO(raw))
        names = set(z.namelist())
        if not {"voice.wav", "pack.json"} <= names:
            raise ValueError("缺 voice.wav / pack.json")
        meta = json.loads(z.read("pack.json").decode("utf-8"))
        if str(meta.get("fmt") or "") != "avatarhub-voicepack/1":
            raise ValueError(f"包格式不识别: {meta.get('fmt')!r}")
        wb = z.read("voice.wav")
        tb = z.read("voice.txt").decode("utf-8").strip() if "voice.txt" in names else ""
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(400, f"音色包无法解析: {e}")
    if len(wb) > 30 * 1024 * 1024:
        raise HTTPException(400, "包内参考音超 30MB")
    sha = hashlib.sha256(wb).hexdigest()
    if meta.get("sha256_wav") and meta["sha256_wav"] != sha:
        raise HTTPException(400, "参考音校验和不符（包已损坏或被改动过）")
    for r in _vp_ext_rows_raw():          # 幂等去重：按内容哈希，不看编号
        try:
            if (VOICEPACK_DIR / f"{r.get('spk')}_ref.wav").exists() \
                    and _vp_wav_sha(r["spk"]) == sha:
                return {"ok": True, "spk": r["spk"], "already": True,
                        "row": next((x for x in _vp_rows() if x["spk"] == r["spk"]), None)}
        except Exception:
            pass
    try:
        import soundfile as sf
        x, sr = sf.read(_io.BytesIO(wb), dtype="float32", always_2d=True)
        x = x.mean(axis=1)
    except Exception:
        raise HTTPException(400, "包内参考音无法解码")
    if x.size < sr * 4.0:
        raise HTTPException(400, "包内参考音不足 4 秒")
    st = _vp_audio_stats(x, sr)           # 本机重算声学统计（不信包里带的数字）
    old = meta.get("row") or {}
    dur = x.size / sr
    g = old.get("gender") if old.get("gender") in ("male", "female") else \
        (("male" if st["f0_med"] < 170 else "female") if st["f0_med"] else "female")
    with _vp_ext_lock:
        spk = _vp_ext_next_id()
        try:
            (VOICEPACK_DIR / f"{spk}_ref.wav").write_bytes(wb)
            (VOICEPACK_DIR / f"{spk}_ref.txt").write_text(tb, encoding="utf-8")
            rows = _vp_ext_rows_raw()
            rows.append(dict(spk=spk, split="ext", age=old.get("age") or "", gender=g,
                             accent=old.get("accent") or "",
                             sr=int(sr), n_clips=int(old.get("n_clips") or 1),
                             dur=round(dur, 1), snr=st["snr"], bw=st["bw"], clip=st["clip"],
                             f0_med=st["f0_med"], f0_iqr=st["f0_iqr"],
                             rate=round(len(tb) / dur, 2) if tb else old.get("rate"),
                             ref_text=tb, label=str(old.get("label") or "").strip()[:24],
                             added_at=time.time(), src_pack=str(meta.get("src_spk") or "")))
            _VP_EXT_INDEX.write_text(json.dumps(rows, ensure_ascii=False, indent=1),
                                     encoding="utf-8")
        except Exception as e:
            for suf in ("_ref.wav", "_ref.txt"):
                try:
                    (VOICEPACK_DIR / f"{spk}{suf}").unlink(missing_ok=True)
                except Exception:
                    pass
            raise HTTPException(500, f"入库写盘失败: {e}")
    ftd = meta.get("featured")            # 主打身份随包走（总部定的主打，门店导入即生效）
    if isinstance(ftd, dict):
        ftf = VOICEPACK_DIR / "featured.json"
        with _vp_ext_lock:
            try:
                lst = json.loads(ftf.read_text(encoding="utf-8")) if ftf.exists() else []
                lst.append({"spk": spk,
                            "title": str(ftd.get("title") or "").strip()[:24] or (old.get("label") or spk),
                            "tagline": str(ftd.get("tagline") or "").strip()[:60]})
                ftf.write_text(json.dumps(lst, ensure_ascii=False, indent=1), encoding="utf-8")
            except Exception as e:
                _logger.warning(f"[voicepack] 导入包恢复主打标记失败: {e}")
    _vp_cache["mtime"] = 0
    asyncio.create_task(_vp_gen_preview_one(spk))
    row = next((r for r in _vp_rows() if r["spk"] == spk), None)
    _logger.info(f"[voicepack] 导入音色包 → {spk} label={old.get('label')!r} "
                 f"src={meta.get('src_spk')} dur={dur:.1f}s")
    return {"ok": True, "spk": spk, "already": False, "row": row}


async def _vp_import_any_bytes(raw: bytes) -> dict:
    """P11: zip 自动分流——bundle(整库包) 逐个内包入库并汇总；否则按单音色包走。"""
    import io as _io
    import zipfile
    if len(raw) > 256 * 1024 * 1024:
        raise HTTPException(400, "包超 256MB")
    try:
        z = zipfile.ZipFile(_io.BytesIO(raw))
        names = z.namelist()
    except Exception:
        raise HTTPException(400, "zip 无法解析")
    inner = [n for n in names if n.startswith("packs/") and n.endswith(".zip")]
    if not ("bundle.json" in names or inner):
        return await _vp_import_pack_bytes(raw)
    results = []
    for n in inner[:200]:
        try:
            d = await _vp_import_pack_bytes(z.read(n))
            results.append({"file": n, "ok": True, "spk": d["spk"],
                            "already": bool(d.get("already")),
                            "name": ((d.get("row") or {}).get("name")) or d["spk"]})
        except HTTPException as e:                     # 单包坏不拖累整车：逐包报告
            results.append({"file": n, "ok": False, "error": str(e.detail)})
        except Exception as e:
            results.append({"file": n, "ok": False, "error": str(e)})
    return {"ok": True, "bundle": results}


@app.post("/api/voicepack/import_pack")
async def api_voicepack_import_pack(file: UploadFile = File(...)):
    """P9/P11: 导入音色包或整库 bundle（自动识别）。逻辑见 _vp_import_any_bytes。"""
    return await _vp_import_any_bytes(await file.read())


@app.get("/api/voicepack/catalog")
def api_voicepack_catalog(request: Request, token: str = ""):
    """P10: 本机上新分发清单（作为分发源）。另一台机器在「从 URL 导入」里粘贴
    本地址（http://本机IP:9000/api/voicepack/catalog）即可看到全部上新并勾选导入。
    URL 用请求侧看到的 base——对方按它能访问到的地址回来拉包，不用猜本机网卡。
    P11: 设了分发口令时须带 ?token=，且下载地址内嵌口令（拿到清单 URL=拿到授权）。"""
    _vp_dist_check(token)
    base = str(request.base_url).rstrip("/")
    tok = f"?token={_VP_DIST_TOKEN}" if _VP_DIST_TOKEN else ""
    ft = _vp_featured()
    packs = []
    for r in _vp_ext_rows_raw():
        spk = r.get("spk") or ""
        if not (VOICEPACK_DIR / f"{spk}_ref.wav").exists():
            continue
        try:
            sha = _vp_wav_sha(spk)      # P12: 内容指纹随清单——订阅端零下载判"新/旧/已删"
        except Exception:
            sha = ""
        packs.append({"spk": spk, "name": (r.get("label") or "").strip() or spk,
                      "gender": r.get("gender") or "", "dur": r.get("dur"),
                      "featured": bool(ft.get(spk)), "sha256": sha,
                      "url": f"{base}/api/voicepack/{spk}/export{tok}"})
    return {"fmt": "avatarhub-catalog/1", "generated_at": time.time(), "packs": packs}


@app.post("/api/voicepack/import_url")
async def api_voicepack_import_url(body: dict = Body(default={})):
    """P10: 从 URL 导入。拉到 zip=直接入库；拉到分发清单 json=返回列表供前端勾选
    （逐条再走本端点导入）。LAN 工具、操作者即机器管理员——限 http/https 与体积
    上限即可，不做 IP 白名单这类过度设计。"""
    url = str(body.get("url") or "").strip()
    if not re.match(r"^https?://", url, re.I):
        raise HTTPException(400, "仅支持 http/https 地址")
    try:
        async with _aclient(timeout=120) as c:
            r = await c.get(url, follow_redirects=True)
            r.raise_for_status()
            raw = r.content
    except Exception as e:
        raise HTTPException(502, f"拉取失败: {e}")
    if len(raw) > 256 * 1024 * 1024:
        raise HTTPException(400, "内容超 256MB")
    if raw[:2] == b"PK":                    # zip 魔数 → 音色包/整库 bundle 自动分流入库
        return await _vp_import_any_bytes(raw)
    try:
        cat = json.loads(raw.decode("utf-8-sig"))
        if str(cat.get("fmt") or "") != "avatarhub-catalog/1":
            raise ValueError(cat.get("fmt"))
        packs = cat.get("packs") or []
    except Exception:
        raise HTTPException(400, "该地址既不是音色包 zip，也不是分发清单 json")
    from urllib.parse import urljoin
    out = []
    for p in packs[:200]:                   # 清单条数封顶，防手滑贴了个巨型 json
        u = urljoin(url, str(p.get("url") or ""))
        if not re.match(r"^https?://", u, re.I):
            continue
        out.append({"name": str(p.get("name") or p.get("spk") or "未命名")[:24],
                    "gender": str(p.get("gender") or ""), "dur": p.get("dur"),
                    "featured": bool(p.get("featured")), "url": u})
    return {"ok": True, "catalog": out}


# ── P12: 订阅式自动同步——门店贴一次总部清单地址，新上新自动进库 ────────────────
# 账本（ledger）是灵魂：记"同步过什么"的内容指纹。门店删掉的音色下次同步不会被塞回来
# （指纹还在账本），总部同一编号重录的新内容（新指纹）照常进来。清单带 sha256 时判重零下载。
_VP_SUBS_FILE = VOICEPACK_DIR / "subscriptions.json"
_vp_subs_lock = threading.Lock()      # subscriptions.json 读改写互斥
_vp_sync_lock = asyncio.Lock()        # 同步串行闸：手动/定时不叠跑


def _vp_subs_load() -> dict:
    try:
        if _VP_SUBS_FILE.exists():
            d = json.loads(_VP_SUBS_FILE.read_text(encoding="utf-8"))
            d.setdefault("subs", [])
            led = d.setdefault("ledger", {})
            led.setdefault("sha256", [])
            led.setdefault("urls", [])
            return d
    except Exception as e:
        _logger.warning(f"[voicepack] 订阅文件读取失败(按空处理): {e}")
    return {"subs": [], "ledger": {"sha256": [], "urls": []}}


def _vp_subs_save(d: dict):
    _VP_SUBS_FILE.write_text(json.dumps(d, ensure_ascii=False, indent=1), encoding="utf-8")


async def _vp_sync_catalog(url: str) -> dict:
    """同步一个订阅清单（调用方须持 _vp_sync_lock）。返回 {new, already, skip, fail, total}。
    判重次序：清单带指纹→查账本(删过的跳过)→查本地库(已有的只记账不下载)；无指纹→按 URL 记账。"""
    async with _aclient(timeout=30) as c:
        r = await c.get(url, follow_redirects=True)
        r.raise_for_status()
        raw = r.content
    if len(raw) > 8 * 1024 * 1024:
        raise ValueError("清单超 8MB，不像清单")
    cat = json.loads(raw.decode("utf-8-sig"))
    if str(cat.get("fmt") or "") != "avatarhub-catalog/1":
        raise ValueError(f"不是分发清单（fmt={cat.get('fmt')!r}）")
    from urllib.parse import urljoin
    data = _vp_subs_load()
    shas = set(data["ledger"]["sha256"])
    urls = set(data["ledger"]["urls"])
    local = set()                          # 本地在库指纹：手动导入过的只记账，不重复下载
    for r0 in _vp_ext_rows_raw():
        try:
            local.add(_vp_wav_sha(r0["spk"]))
        except Exception:
            pass
    new = already = skip = fail = 0
    for p in (cat.get("packs") or [])[:200]:
        u = urljoin(url, str(p.get("url") or ""))
        sha = str(p.get("sha256") or "")
        if not re.match(r"^https?://", u, re.I):
            continue
        if sha:
            if sha in shas:                # 账本见过（含门店已删的）→ 不回填
                skip += 1
                continue
            if sha in local:               # 在库但账本没记（手动导过）→ 补记账，零下载
                shas.add(sha)
                already += 1
                continue
        elif u in urls:                    # 清单没给指纹 → 退化按 URL 记账
            skip += 1
            continue
        try:
            async with _aclient(timeout=120) as c:
                rr = await c.get(u, follow_redirects=True)
                rr.raise_for_status()
            if len(rr.content) > 64 * 1024 * 1024:
                raise ValueError("包超 64MB")
            d = await _vp_import_pack_bytes(rr.content)
            if d.get("already"):
                already += 1
            else:
                new += 1
            if sha:
                shas.add(sha)
            else:
                urls.add(u)
        except HTTPException as e:
            fail += 1
            _logger.warning(f"[voicepack] 订阅同步单包失败 {u}: {e.detail}")
        except Exception as e:
            fail += 1
            _logger.warning(f"[voicepack] 订阅同步单包失败 {u}: {e}")
    res = {"new": new, "already": already, "skip": skip, "fail": fail,
           "total": len(cat.get("packs") or [])}
    with _vp_subs_lock:
        data = _vp_subs_load()             # 重载拿最新订阅表（同步中可能有人退订）
        data["ledger"]["sha256"] = sorted(shas)
        data["ledger"]["urls"] = sorted(urls)
        for s in data["subs"]:
            if s.get("url") == url:
                s["last_sync"] = time.time()
                s["last_result"] = res
        _vp_subs_save(data)
    if new:
        _logger.info(f"[voicepack] 订阅同步 {url}: 新入库 {new}，已在库 {already}，跳过 {skip}，失败 {fail}")
    return res


async def _vp_sync_loop():
    """P12: 定时自动同步（VP_SYNC_HOURS，默认 6 小时，0=仅手动）。起动缓 90s 让路。"""
    try:
        hrs = float(os.environ.get("VP_SYNC_HOURS", "6") or 6)
    except Exception:
        hrs = 6.0
    if hrs <= 0:
        return
    await asyncio.sleep(90)
    while True:
        try:
            subs = [s for s in _vp_subs_load()["subs"] if s.get("auto", True)]
            if subs and not _vp_sync_lock.locked():
                async with _vp_sync_lock:
                    for s in subs:
                        try:
                            await _vp_sync_catalog(s["url"])
                        except Exception as e:
                            _logger.warning(f"[voicepack] 定时同步失败 {s.get('url')}: {e}")
        except Exception as e:
            _logger.warning(f"[voicepack] 同步循环异常: {e}")
        await asyncio.sleep(hrs * 3600)


@app.get("/api/voicepack/subs")
def api_voicepack_subs():
    """订阅清单列表 + 同步状态（给上新面板的订阅管理用）。"""
    d = _vp_subs_load()
    try:
        hrs = float(os.environ.get("VP_SYNC_HOURS", "6") or 6)
    except Exception:
        hrs = 6.0
    return {"ok": True, "subs": d["subs"], "syncing": _vp_sync_lock.locked(),
            "auto_hours": hrs}


@app.post("/api/voicepack/subs")
async def api_voicepack_subs_add(body: dict = Body(default={})):
    """新增订阅并立即同步一轮（能当场看到"拉到了几个"）。同步占线就只登记，稍后自动跑。"""
    url = str(body.get("url") or "").strip()
    label = str(body.get("label") or "").strip()[:24]
    if not re.match(r"^https?://", url, re.I):
        raise HTTPException(400, "仅支持 http/https 清单地址")
    with _vp_subs_lock:
        data = _vp_subs_load()
        if any(s.get("url") == url for s in data["subs"]):
            raise HTTPException(409, "该清单已在订阅中")
        data["subs"].append({"url": url, "label": label, "added_at": time.time(),
                             "auto": True, "last_sync": 0, "last_result": None})
        _vp_subs_save(data)
    first = None
    if not _vp_sync_lock.locked():
        async with _vp_sync_lock:
            try:
                first = await _vp_sync_catalog(url)
            except Exception as e:
                # 首轮失败不回滚订阅（地址可能暂时不通，定时会重试），把原因带回去
                first = {"error": str(e)}
    _vp_cache["mtime"] = 0
    return {"ok": True, "url": url, "first_sync": first}


@app.post("/api/voicepack/subs/remove")
def api_voicepack_subs_remove(body: dict = Body(default={})):
    """退订（账本保留：已同步过的指纹不清，重新订阅也不会把删掉的音色塞回来）。"""
    url = str(body.get("url") or "").strip()
    with _vp_subs_lock:
        data = _vp_subs_load()
        keep = [s for s in data["subs"] if s.get("url") != url]
        if len(keep) == len(data["subs"]):
            raise HTTPException(404, "没有这条订阅")
        data["subs"] = keep
        _vp_subs_save(data)
    return {"ok": True, "url": url}


@app.post("/api/voicepack/subs/sync")
async def api_voicepack_subs_sync(body: dict = Body(default={})):
    """立即同步：指定 url 只同步一条，不指定同步全部。占线直接 409（别叠跑）。"""
    url = str(body.get("url") or "").strip()
    if _vp_sync_lock.locked():
        raise HTTPException(409, "已有同步在进行中")
    subs = _vp_subs_load()["subs"]
    targets = [s for s in subs if (not url or s.get("url") == url)]
    if not targets:
        raise HTTPException(404, "没有匹配的订阅")
    results = []
    async with _vp_sync_lock:
        for s in targets:
            try:
                results.append({"url": s["url"], "ok": True,
                                **(await _vp_sync_catalog(s["url"]))})
            except Exception as e:
                results.append({"url": s["url"], "ok": False, "error": str(e)})
    _vp_cache["mtime"] = 0
    return {"ok": True, "results": results}


# ── P13: 音色运营小报表——回答三个问题：哪些在火、哪些值得推、哪些占着位置没人用 ──
@app.get("/api/voicepack/report")
def api_voicepack_report():
    with _vp_stats_lock:
        _vp_stats_flush(force=True)          # 报表要新鲜数：先把内存里攒的落掉
        w7 = _vp_stats_window(7)
        w30 = _vp_stats_window(30)
        days_raw = dict(_vp_stats().get("days") or {})
        tot = {k: dict(v) for k, v in (_vp_stats().get("tot") or {}).items()}
    rows = {r["spk"]: r for r in _vp_rows()}
    imp = _vp_imported()

    # 14 天日趋势（含今天；空天补零，前端画迷你条不用对日期）
    series = []
    for i in range(13, -1, -1):
        day = time.strftime("%Y%m%d", time.localtime(time.time() - i * 86400))
        s = {"d": day[4:], "pv": 0, "au": 0, "imp": 0, "use": 0}
        for c in (days_raw.get(day) or {}).values():
            for k in ("pv", "au", "imp", "use"):
                s[k] += int(c.get(k, 0))
        series.append(s)

    def _brief(spk, c):
        r = rows.get(spk)
        return {"spk": spk, "name": (r or {}).get("name") or spk,
                "gone": r is None,                       # 已删但历史计数还在
                "featured": bool((r or {}).get("featured")),
                "ext": bool((r or {}).get("ext")),
                "imported": imp.get(spk) or "",
                "pv": c.get("pv", 0) + c.get("au", 0), "use": c.get("use", 0)}

    # 🔥 热度榜（7天）：使用权重 3 > 克隆试听 1 > 原声 0.5——越接近开播动作越值钱
    hot = sorted(({"score": round(c["use"] * 3 + c["pv"] + c["au"] * 0.5, 1), **_brief(s, c)}
                  for s, c in w7.items()),
                 key=lambda x: -x["score"])
    hot = [h for h in hot if h["score"] > 0 and not h["gone"]][:12]

    # 💡 值得推（7天）：试听热但还没导入——兴趣已证明，转化差一脚（给运营的进货清单）
    cand = sorted((_brief(s, c) for s, c in w7.items()
                   if not imp.get(s) and (c["pv"] + c["au"]) >= 2),
                  key=lambda x: -x["pv"])
    cand = [c for c in cand if not c["gone"]][:6]

    # 😴 沉睡资产（30天）：导入满 7 天、近 30 天零使用——占着角色位没产出，可考虑清退
    now = time.time()
    sleep_rows = []
    for spk, pname in imp.items():
        t = tot.get(spk) or {}
        if (t.get("first_imp") or now) > now - 7 * 86400:
            continue                          # 新导入的给 7 天成长期
        if (w30.get(spk) or {}).get("use", 0) == 0:
            sleep_rows.append({"spk": spk, "profile": pname,
                               "name": (rows.get(spk) or {}).get("name") or spk,
                               "last_use": t.get("last_use") or 0})
    sleep_rows.sort(key=lambda x: x["last_use"])

    # 漏斗（30天）：在库 → 有人试听 → 已导入 → 真在用
    n_lib = len(rows)
    n_pv = sum(1 for s, c in w30.items() if (c["pv"] + c["au"]) > 0 and s in rows)
    n_imp = len(imp)
    n_use = sum(1 for s, c in w30.items() if c["use"] > 0 and imp.get(s))
    t7 = {k: sum(c[k] for c in w7.values()) for k in ("pv", "au", "imp", "use")}
    today = series[-1] if series else {}

    subs = _vp_subs_load()["subs"]
    return {"ok": True,
            "funnel": {"lib": n_lib, "auditioned": n_pv, "imported": n_imp, "used": n_use},
            "sum7": {"listen": t7["pv"] + t7["au"], "imp": t7["imp"], "use": t7["use"]},
            "today": {"listen": (today.get("pv", 0) + today.get("au", 0)),
                      "imp": today.get("imp", 0), "use": today.get("use", 0)},
            "series": series, "hot": hot, "candidates": cand,
            "sleepers": sleep_rows[:8], "sleepers_n": len(sleep_rows),
            "subs": [{"label": s.get("label") or s.get("url"), "last_sync": s.get("last_sync"),
                      "last_result": s.get("last_result")} for s in subs]}


def _vp_ext_trash_items() -> list:
    """回收目录分组清单：一次删除的一批文件（同 时间戳_编号 前缀）算一项。"""
    items: dict = {}
    if _VP_EXT_TRASH.exists():
        for f in _VP_EXT_TRASH.iterdir():
            m = re.match(r"^(\d+)_(EXT\d{4})", f.name)
            if not m:
                continue
            it = items.setdefault(m.groups(), {"ts": int(m.group(1)), "spk": m.group(2),
                                               "files": [], "bytes": 0, "label": ""})
            it["files"].append(f.name)
            try:
                it["bytes"] += f.stat().st_size
            except Exception:
                pass
            if f.name.endswith(".meta.json"):
                try:
                    it["label"] = (json.loads(f.read_text(encoding="utf-8")).get("label") or "").strip()
                except Exception:
                    pass
    out = sorted(items.values(), key=lambda x: -x["ts"])
    for it in out:
        it["name"] = it["label"] or it["spk"]
    return out


@app.get("/api/voicepack/ext_trash")
def api_voicepack_ext_trash():
    """上新回收目录清单（P7：给 UI 还原/彻底删除用；此前只能进文件夹手工捞）。"""
    return {"ok": True, "items": _vp_ext_trash_items()}


@app.post("/api/voicepack/ext_trash/restore")
def api_voicepack_ext_trash_restore(body: dict = Body(default={})):
    """还原一项软删的上新音色：文件搬回 + 索引行按删除时存的元数据原样重建
    （P7 之前删的没存元数据 → 对着 wav 重算统计，label 丢失但音色完整可用）。"""
    ts, spk = str(body.get("ts") or ""), str(body.get("spk") or "")
    if not (ts.isdigit() and re.match(r"^EXT\d{4}$", spk)):
        raise HTTPException(400, "参数不合法")
    prefix = f"{ts}_{spk}"
    files = list(_VP_EXT_TRASH.glob(f"{prefix}*")) if _VP_EXT_TRASH.exists() else []
    if not files:
        raise HTTPException(404, "回收目录中没有该项")
    meta, ftd = None, None
    mf = _VP_EXT_TRASH / f"{prefix}.meta.json"
    if mf.exists():
        try:
            meta = json.loads(mf.read_text(encoding="utf-8"))
            ftd = meta.pop("_featured", None)    # P8: 主打标记单独回填 featured.json，不进索引行
        except Exception:
            meta = None
    with _vp_ext_lock:
        rows = _vp_ext_rows_raw()
        if any(r.get("spk") == spk for r in rows):
            raise HTTPException(409, f"编号 {spk} 已被在库音色占用，无法还原（先删或改用重传）")
        _VP_PREVIEW_DIR.mkdir(exist_ok=True)
        restored = []
        for f in files:
            if f.name.endswith(".meta.json"):
                continue
            orig = f.name[len(ts) + 1:]
            dest = (VOICEPACK_DIR if orig.endswith(("_ref.wav", "_ref.txt"))
                    else _VP_PREVIEW_DIR) / orig
            try:
                f.rename(dest)
                restored.append(orig)
            except Exception as e:
                _logger.warning(f"[voicepack] 回收还原移文件失败 {f.name}: {e}")
        if not (VOICEPACK_DIR / f"{spk}_ref.wav").exists():
            raise HTTPException(500, "参考音还原失败（文件可能已被占用）")
        if meta is None:
            # 旧软删无元数据：重算声学统计重建行（label 无从恢复）
            try:
                import io as _io
                import soundfile as sf
                x, sr = sf.read(str(VOICEPACK_DIR / f"{spk}_ref.wav"),
                                dtype="float32", always_2d=True)
                x = x.mean(axis=1)
                st = _vp_audio_stats(x, sr)
                txtf = VOICEPACK_DIR / f"{spk}_ref.txt"
                rtxt = txtf.read_text(encoding="utf-8").strip() if txtf.exists() else ""
                dur = round(x.size / sr, 1)
                meta = dict(spk=spk, split="ext", age="",
                            gender=("male" if (st["f0_med"] or 999) < 170 else "female"),
                            accent="", sr=sr, n_clips=1, dur=dur, snr=st["snr"],
                            bw=st["bw"], clip=st["clip"], f0_med=st["f0_med"],
                            f0_iqr=st["f0_iqr"],
                            rate=round(len(rtxt) / dur, 2) if (rtxt and dur) else None,
                            ref_text=rtxt, label="", added_at=time.time())
            except Exception as e:
                raise HTTPException(500, f"重建索引失败: {e}")
        rows.append(meta)
        _VP_EXT_INDEX.write_text(json.dumps(rows, ensure_ascii=False, indent=1),
                                 encoding="utf-8")
        if ftd:                                  # P8: ⭐ 主打身份随还原回归
            ftf = VOICEPACK_DIR / "featured.json"
            try:
                lst = json.loads(ftf.read_text(encoding="utf-8")) if ftf.exists() else []
                if not any(x.get("spk") == spk for x in lst):
                    lst.append(dict(spk=spk, title=ftd.get("title") or "",
                                    tagline=ftd.get("tagline") or ""))
                    ftf.write_text(json.dumps(lst, ensure_ascii=False, indent=1),
                                   encoding="utf-8")
            except Exception as e:
                _logger.warning(f"[voicepack] 还原主打标记失败(音色本体已还原): {e}")
    try:
        mf.unlink(missing_ok=True)
    except Exception:
        pass
    _vp_cache["mtime"] = 0
    row = next((r for r in _vp_rows() if r["spk"] == spk), None)
    return {"ok": True, "spk": spk, "restored": restored, "row": row}


@app.post("/api/voicepack/ext_trash/purge")
def api_voicepack_ext_trash_purge(body: dict = Body(default={})):
    """彻底删除回收目录一项（ts+spk）或全部（空参数）。不可逆，UI 侧已二次确认。"""
    ts, spk = str(body.get("ts") or ""), str(body.get("spk") or "")
    if ts or spk:
        if not (ts.isdigit() and re.match(r"^EXT\d{4}$", spk)):
            raise HTTPException(400, "参数不合法")
        pattern = f"{ts}_{spk}*"
    else:
        pattern = "*"
    n = 0
    if _VP_EXT_TRASH.exists():
        for f in _VP_EXT_TRASH.glob(pattern):
            try:
                f.unlink()
                n += 1
            except Exception as e:
                _logger.warning(f"[voicepack] 回收清理失败 {f.name}: {e}")
    return {"ok": True, "removed": n}


# ── RVC 变声模型资产：引用回算 + 绑定 + 孤儿软删（模型 55MB/个，是最大的磁盘资产）──
RVC_PRESETS_FILE = Path(rf"{_BASE}\rvc_model_presets.json")
_RVC_PRESET_KEYS = ("pitch", "index_rate", "f0method", "protect", "index_path",
                    "threhold", "rms_mix_rate")


def _rvc_presets_load() -> dict:
    if RVC_PRESETS_FILE.exists():
        try:
            return json.loads(RVC_PRESETS_FILE.read_text(encoding="utf-8"))
        except Exception:
            pass
    return {}


def _rvc_presets_get(rel_id: str) -> dict:
    raw = _rvc_presets_load().get(rel_id) or {}
    return {k: raw[k] for k in _RVC_PRESET_KEYS if k in raw}


def _rvc_presets_set(rel_id: str, settings: dict):
    allp = _rvc_presets_load()
    cleaned = {k: settings[k] for k in _RVC_PRESET_KEYS if k in settings}
    if cleaned:
        allp[rel_id] = cleaned
    else:
        allp.pop(rel_id, None)
    RVC_PRESETS_FILE.write_text(json.dumps(allp, ensure_ascii=False, indent=2), encoding="utf-8")


def _rvc_clean_settings(settings: dict) -> dict:
    """白名单 + 强类型化 RVC 参数（预设保存与试听参数覆盖共用；坏值直接 ValueError→400）。"""
    cleaned = {}
    for k in _RVC_PRESET_KEYS:
        if k not in settings:
            continue
        v = settings[k]
        try:
            if k in ("pitch", "threhold"):
                cleaned[k] = int(v)
            elif k in ("index_rate", "protect", "rms_mix_rate"):
                cleaned[k] = float(v)
            elif k in ("f0method", "index_path"):
                cleaned[k] = str(v)
        except (TypeError, ValueError):
            raise HTTPException(400, f"参数 {k} 类型非法：{v!r}")
    return cleaned


def _rvc_asset_refs(rel_id: str, abs_path: Path) -> list:
    """哪些角色绑定了这个模型：rvc_model 历史上存过裸文件名/相对 id/绝对路径，统一解析后比对。"""
    refs = []
    for pname, p in _profiles.items():
        m = (p.get("rvc_model") or "").strip()
        if not m:
            continue
        if m == rel_id or m == abs_path.name or Path(_rvc_resolve_pth(m)) == abs_path:
            refs.append(pname)
    return refs


@app.get("/api/rvc_assets")
def api_rvc_assets():
    """RVC 变声模型统一视图：全部 .pth（含一层嵌套）+ 被哪些角色引用 + 引擎在线位（试听按钮据此置灰）。"""
    assets = []
    aliases = _rvc_aliases()
    for rel_id, f in _rvc_model_files():
        st = f.stat()
        al = aliases.get(rel_id) or {}
        assets.append({"id": rel_id, "kind": "rvc", "name": f.name,
                       "alias": al.get("alias") or "",      # P2-RA: 显示别名（编号男声→特色名）
                       "alias_note": al.get("note") or "",
                       "size": st.st_size, "created_at": int(st.st_mtime),
                       "refs": _rvc_asset_refs(rel_id, f),
                       "preset": _rvc_presets_get(rel_id)})
    total = sum(a["size"] for a in assets)
    rvc_up = bool(((_HEALTH_CACHE.get("data") or {}).get("services") or {}).get("rvc"))
    return {"ok": True, "assets": assets, "total_bytes": total,
            "rvc_up": rvc_up, "weights_dir": str(RVC_WEIGHTS_DIR)}


# ── 变声试听：固定人声样本 → 指定模型 /convert → 出转换后音频（听了再绑）──────
_RVC_PREVIEW_CACHE: dict = {}     # {(rel_id, sample_key): audio_b64}；进程内缓存，模型/样本变则键变
_RVC_PREVIEW_SAMPLE_SEC = 6.0


def _wav_head_bytes(src, sec: float) -> bytes:
    """取 wav 前 sec 秒重打包（顺带丢掉克隆文件尾部的水印追加字节）。
    src 可以是 Path（磁盘样本）或 wav 字节（角色参考音 b64 解码后）。"""
    import wave as _wave
    import io as _io
    fh = _io.BytesIO(bytes(src)) if isinstance(src, (bytes, bytearray)) else str(src)
    with _wave.open(fh) as wf:
        fr = wf.getframerate()
        n = min(wf.getnframes(), int(fr * sec))
        params = (wf.getnchannels(), wf.getsampwidth(), fr)
        frames = wf.readframes(n)
    buf = _io.BytesIO()
    with _wave.open(buf, "wb") as out:
        out.setnchannels(params[0]); out.setsampwidth(params[1]); out.setframerate(params[2])
        out.writeframes(frames)
    return buf.getvalue()


def _rvc_preview_sample():
    """试听输入样本：优先最新克隆参考音（必是真人声），其次声音库样本。返回 (缓存键, wav字节)。"""
    cands = []
    if CLONE_ASSETS_DIR.exists():
        cands += sorted(CLONE_ASSETS_DIR.glob("*.wav"), key=lambda x: -x.stat().st_mtime)
    if VOICES_DIR.exists():
        cands += sorted(VOICES_DIR.glob("*.wav"))
    for f in cands:
        try:
            data = _wav_head_bytes(f, _RVC_PREVIEW_SAMPLE_SEC)
            if len(data) > 1000:
                return f"{f.name}:{int(f.stat().st_mtime)}", data
        except Exception:
            continue
    return None, None


@app.post("/api/rvc_assets/preview")
async def api_rvc_asset_preview(body: dict):
    """变声试听：样本人声过指定模型出 6s 音频。首次要冷加载模型（10-30s），之后命中引擎缓存秒回。
    body.settings 可携带未保存的滑条参数（调参闭环：拖滑条→试听→满意再存预设）。
    body.sample_profile 可指定用某角色的参考音当试听输入——听到的效果与该角色实际开播一致。"""
    rel_id = str(body.get("id") or "").strip()
    pairs = {rid: f for rid, f in _rvc_model_files()}
    if pairs.get(rel_id) is None:
        raise HTTPException(404, "模型文件不存在")
    sample_profile = str(body.get("sample_profile") or "").strip()
    if sample_profile:
        prof = _profiles.get(sample_profile)
        if prof is None:
            raise HTTPException(404, f"角色不存在：{sample_profile}")
        vb64 = prof.get("voice_b64") or ""
        if not vb64:
            raise HTTPException(400, f"角色「{sample_profile}」没有绑定参考音")
        try:
            wav = _wav_head_bytes(base64.b64decode(vb64), _RVC_PREVIEW_SAMPLE_SEC)
        except Exception:
            raise HTTPException(400, f"角色「{sample_profile}」参考音不是标准 wav，暂不支持做试听样本")
        sample_key = f"profile:{sample_profile}:{_va_profile_md5(sample_profile, vb64)}"
    else:
        sample_key, wav = _rvc_preview_sample()
    if not wav:
        raise HTTPException(400, "没有可用的样本人声：先在「声音克隆」录一段参考音")
    override = body.get("settings")
    if override is not None:
        if not isinstance(override, dict):
            raise HTTPException(400, "settings 须为对象")
        settings = _rvc_clean_settings(override)
    else:
        settings = _rvc_presets_get(rel_id)
    ck = (rel_id, sample_key, json.dumps(settings, sort_keys=True))
    hit = _RVC_PREVIEW_CACHE.get(ck)
    if hit:
        return {"ok": True, "audio_base64": hit, "cached": True}
    try:
        r0 = await http_pool.get(f"{RVC_API}/inputDevices", timeout=2.5)
        assert r0.status_code == 200
    except Exception:
        raise HTTPException(503, "RVC 变声引擎离线：到「开播」页启动变声后再试听")
    try:
        vr = await _vc_dispatch("rvc", base64.b64encode(wav).decode(), rel_id, settings)
    except Exception as e:
        raise HTTPException(502, f"变声转换失败：{e}")
    if vr.status_code != 200:
        raise HTTPException(502, f"变声转换失败 HTTP {vr.status_code}（模型可能损坏或引擎显存不足）")
    out = vr.audio_b64 or ""
    if not out:
        raise HTTPException(502, "变声转换返回空音频")
    if len(_RVC_PREVIEW_CACHE) > 100:
        _RVC_PREVIEW_CACHE.clear()
    _RVC_PREVIEW_CACHE[ck] = out
    return {"ok": True, "audio_base64": out, "cached": False}


@app.post("/api/rvc_assets/preset")
def api_rvc_asset_preset(body: dict):
    """保存变声模型的默认参数预设（绑定时自动带入角色 rvc_settings）。"""
    rel_id = str(body.get("id") or "").strip()
    pairs = {rid: f for rid, f in _rvc_model_files()}
    if rel_id not in pairs:
        raise HTTPException(404, "模型文件不存在")
    settings = body.get("settings") or {}
    if not isinstance(settings, dict):
        raise HTTPException(400, "settings 须为对象")
    _rvc_presets_set(rel_id, _rvc_clean_settings(settings))
    return {"ok": True, "id": rel_id, "preset": _rvc_presets_get(rel_id)}


@app.post("/api/rvc_assets/bind")
async def api_rvc_asset_bind(body: dict):
    """把变声模型绑定到角色（存相对 id，调用时经 _rvc_resolve_pth 解析）。
    绑定时默认合并该模型的参数预设到角色 rvc_settings（apply_preset=false 可跳过）。"""
    profile = str(body.get("profile") or "")
    if profile not in _profiles:
        raise HTTPException(404, "角色不存在")
    rel_id = str(body.get("id") or "").strip()
    if rel_id:
        matches = [rid for rid, _ in _rvc_model_files() if rid == rel_id]
        if not matches:
            raise HTTPException(404, "模型文件不存在")
    patch = {"rvc_model": rel_id}
    if rel_id and body.get("apply_preset", True):
        preset = _rvc_presets_get(rel_id)
        if preset:
            merged = dict(_profiles[profile].get("rvc_settings") or {})
            merged.update(preset)
            patch["rvc_settings"] = merged
    return await patch_profile(profile, patch)


@app.delete("/api/rvc_assets/{rel_id:path}")
def api_rvc_asset_delete(rel_id: str):
    """删除无引用的变声模型：软删移入 weights/_trash/（模型体积大，误删重下成本高）。"""
    pairs = {rid: f for rid, f in _rvc_model_files()}
    f = pairs.get(rel_id)
    if f is None:
        raise HTTPException(404, "模型文件不存在")
    refs = _rvc_asset_refs(rel_id, f)
    if refs:
        raise HTTPException(400, f"仍被角色引用，不能删除：{'、'.join(refs)}")
    trash = RVC_WEIGHTS_DIR / _VA_TRASH_DIRNAME
    trash.mkdir(exist_ok=True)
    target = trash / f"{int(time.time())}_{f.name}"
    f.rename(target)
    global _rvc_cache
    _rvc_cache = {"models": [], "indices": [], "ts": 0.0}   # 让 /rvc/models 缓存立即失效
    _trash_auto_clean("rvc_soft_delete")   # 模型 55MB/个，最容易顶爆阈值
    return {"ok": True, "trashed": target.name}


# ── 回收站自动清理策略：超限自动删 N 天前旧项（软删后钩子 + 启动/每小时兜底）──────
_TRASH_POLICY_FILE = Path(rf"{_BASE}\data\trash_policy.json")
# last_clean_* / total_cleaned = 透明化统计：自动清理干了什么要让人看得见，才敢放心开
_TRASH_POLICY_DEFAULT = {"auto_clean": False, "max_mb": 500, "older_days": 30,
                         "last_clean_ts": 0, "last_clean_n": 0, "total_cleaned": 0}


def _trash_policy_load() -> dict:
    try:
        d = json.loads(_TRASH_POLICY_FILE.read_text(encoding="utf-8"))
        return {**_TRASH_POLICY_DEFAULT, **d} if isinstance(d, dict) else dict(_TRASH_POLICY_DEFAULT)
    except Exception:
        return dict(_TRASH_POLICY_DEFAULT)


def _trash_auto_clean(source: str = "") -> int:
    """策略开启且回收站超限时，自动彻删 older_days 天前的旧项（近期删除永远保留当安全网）。
    在软删后 / 保存策略时 / 每小时兜底循环里调用；永不抛异常（清理失败不能影响主流程）。"""
    try:
        pol = _trash_policy_load()
        if not pol.get("auto_clean"):
            return 0
        total = 0
        for root_fn in _TRASH_ROOTS.values():
            root = root_fn()
            if root.exists():
                total += sum(f.stat().st_size for f in root.iterdir() if f.is_file())
        if total <= float(pol.get("max_mb", 500)) * 1024 * 1024:
            return 0
        cutoff = time.time() - float(pol.get("older_days", 30)) * 86400
        n = 0
        for root_fn in _TRASH_ROOTS.values():
            root = root_fn()
            if not root.exists():
                continue
            for f in list(root.iterdir()):
                if not f.is_file():
                    continue
                ts_prefix, _, _rest = f.name.partition("_")
                deleted_at = int(ts_prefix) if ts_prefix.isdigit() else int(f.stat().st_mtime)
                if deleted_at <= cutoff:
                    f.unlink()
                    n += 1
        if n:
            _logger.info(f"[TrashPolicy] 超限自动清理 {n} 项 {pol.get('older_days')} 天前旧项（{source or 'manual'}）")
            # 只记「真清了东西」的事件（每小时的无为检查不写盘）；策略行据此显示「上次自动清理」
            pol["last_clean_ts"] = int(time.time())
            pol["last_clean_n"] = n
            pol["total_cleaned"] = int(pol.get("total_cleaned") or 0) + n
            _TRASH_POLICY_FILE.parent.mkdir(parents=True, exist_ok=True)
            _TRASH_POLICY_FILE.write_text(json.dumps(pol, ensure_ascii=False, indent=2), encoding="utf-8")
        return n
    except Exception as e:
        _logger.warning(f"[TrashPolicy] 自动清理失败: {e}")
        return 0


@app.get("/api/trash_policy")
def api_trash_policy_get():
    return {"ok": True, "policy": _trash_policy_load()}


@app.post("/api/trash_policy")
def api_trash_policy_set(body: dict = Body(default={})):
    """保存自动清理策略；保存即执行一次（cleaned 回报当场清了多少，UI 可直接提示）。"""
    pol = _trash_policy_load()
    if "auto_clean" in body:
        pol["auto_clean"] = bool(body["auto_clean"])
    for k, lo, hi in (("max_mb", 1, 1024 * 100), ("older_days", 0, 3650)):
        if k in body:
            try:
                v = float(body[k])
            except (TypeError, ValueError):
                raise HTTPException(400, f"{k} 须为数字")
            if not (lo <= v <= hi):
                raise HTTPException(400, f"{k} 须在 {lo}~{hi} 之间")
            pol[k] = int(v) if float(v).is_integer() else v
    _TRASH_POLICY_FILE.parent.mkdir(parents=True, exist_ok=True)
    _TRASH_POLICY_FILE.write_text(json.dumps(pol, ensure_ascii=False, indent=2), encoding="utf-8")
    cleaned = _trash_auto_clean("policy_saved")
    # 清理可能更新了 last_clean_* 统计 → 回读，响应里给前端最新值
    return {"ok": True, "policy": _trash_policy_load(), "cleaned": cleaned}


# ── 资产回收站：列表 / 还原 / 彻底清空（声音克隆 + RVC 模型共用一套）──────────
_TRASH_ROOTS = {"clone": lambda: CLONE_ASSETS_DIR / _VA_TRASH_DIRNAME,
                "rvc":   lambda: RVC_WEIGHTS_DIR / _VA_TRASH_DIRNAME}


@app.get("/api/asset_health")
def api_asset_health():
    """轻量资产巡检：给角色库页横幅用（只回计数，不回列表；哈希走 _va_hash_cache，重复调用近零成本）。"""
    emb_hash: dict = {}
    unbacked = 0
    file_hashes = {_va_file_md5(f) for f in CLONE_ASSETS_DIR.glob("*.wav")} if CLONE_ASSETS_DIR.exists() else set()
    for pname, p in _profiles.items():
        b64 = p.get("voice_b64") or ""
        if not b64:
            continue
        h = _va_profile_md5(pname, b64)
        if h:
            emb_hash.setdefault(h, []).append(pname)
        if h not in file_hashes:
            unbacked += 1
    orphans = sum(1 for f in (CLONE_ASSETS_DIR.glob("*.wav") if CLONE_ASSETS_DIR.exists() else [])
                  if _va_file_md5(f) not in emb_hash)
    if len(_va_hash_cache) > 500:
        _va_hash_cache.clear()
    trash_n, trash_bytes = 0, 0
    trash_old_n, trash_old_bytes = 0, 0          # ≥30 天前删的（横幅可给「清 30 天前」精准动作）
    old_cutoff = time.time() - 30 * 86400
    for root_fn in _TRASH_ROOTS.values():
        root = root_fn()
        if root.exists():
            for f in root.iterdir():
                if f.is_file():
                    sz = f.stat().st_size
                    trash_n += 1
                    trash_bytes += sz
                    ts_prefix, _, _rest = f.name.partition("_")
                    deleted_at = int(ts_prefix) if ts_prefix.isdigit() else int(f.stat().st_mtime)
                    if deleted_at <= old_cutoff:
                        trash_old_n += 1
                        trash_old_bytes += sz
    return {"ok": True, "orphans": orphans, "unbacked": unbacked,
            "trash_n": trash_n, "trash_bytes": trash_bytes,
            "trash_old_n": trash_old_n, "trash_old_bytes": trash_old_bytes}


# ── 角色素材链路体检：断链（文件被删/改名/回收）在开播前就看得见，并给一键修复 ──────
@app.get("/api/profile_voice_health")
def api_profile_voice_health():
    """按角色查素材链路完整性——声音：内嵌参考音有无磁盘备份 / 声音库文件在不在 / 变声模型文件在不在；
    形象：待机循环视频 / 口型底视频指向的文件在不在（丢失时运行链路会静默回退单图形象，这里让它显形）。
    只查「断链」；音质好坏归 quality_axes 体检，两码事不混。哈希走 _va_hash_cache，全量一次调用近零成本。"""
    file_hashes = set()
    if CLONE_ASSETS_DIR.exists():
        file_hashes = {_va_file_md5(f) for f in CLONE_ASSETS_DIR.glob("*.wav")}
    lib_stems = {f.stem for f in VOICES_DIR.glob("*.wav")} if VOICES_DIR.exists() else set()
    rvc_ids = {rid for rid, _ in _rvc_model_files()}
    out = {}
    warn_n = bad_n = 0
    for name, p in _profiles.items():
        issues = []
        vb64 = p.get("voice_b64") or ""
        vname = p.get("voice_name") or ""
        if vb64:
            if _va_profile_md5(name, vb64) not in file_hashes:
                issues.append({"code": "voice_unbacked", "sev": "fragile", "fix": "backup_voice",
                               "text": "参考音只存在角色数据里，磁盘没有备份文件"})
        elif vname and vname not in lib_stems:
            issues.append({"code": "voice_lib_missing", "sev": "break", "fix": "rebind_voice",
                           "text": f"绑定的声音库文件 {vname}.wav 已不存在，说话会用引擎默认音"})
        rvc = (p.get("rvc_model") or "").strip()
        if rvc and rvc not in rvc_ids:
            issues.append({"code": "rvc_file_missing", "sev": "break", "fix": "fix_rvc",
                           "text": f"绑定的变声模型 {rvc} 文件已不存在（被删/改名/回收），变声不会生效"})
        # 形象链路（路线A 真人底视频）：字段存相对/绝对路径，文件没了运行时静默回退单图——体检让它显形
        for field, label, deg in (("idle_video", "待机循环视频", "待机会回退单图伪活体"),
                                  ("body_video", "口型底视频", "口型会回退单图合成")):
            rel = (p.get(field) or "").strip()
            if rel:
                pth = rel if os.path.isabs(rel) else os.path.join(os.getcwd(), rel)
                if not os.path.isfile(pth):
                    issues.append({"code": f"{field}_missing", "sev": "break", "fix": f"clear_{field}",
                                   "text": f"{label} {os.path.basename(rel)} 已不存在，{deg}"})
        level = ("bad" if any(i["sev"] == "break" for i in issues)
                 else "warn" if issues else "ok")
        if level == "bad":
            bad_n += 1
        elif level == "warn":
            warn_n += 1
        out[name] = {"level": level, "issues": issues}
    return {"ok": True, "profiles": out, "warn_n": warn_n, "bad_n": bad_n}


def _vh_backup_voice(name: str, p: dict) -> dict:
    """内嵌参考音落盘成克隆文件（内容哈希幂等：已有一致备份直接指认，不重复写）。
    返回 {file, existed}；无内嵌音/数据损坏抛 HTTPException。"""
    vb64 = p.get("voice_b64") or ""
    if not vb64:
        raise HTTPException(400, "该角色没有内嵌参考音，无需落盘备份")
    try:
        raw = base64.b64decode(vb64)
    except Exception:
        raise HTTPException(400, "参考音数据损坏，无法解码")
    h = _va_profile_md5(name, vb64)
    if CLONE_ASSETS_DIR.exists():
        for f in CLONE_ASSETS_DIR.glob("*.wav"):
            if _va_file_md5(f) == h:
                return {"file": f.name, "existed": True}
    safe = "".join(c if c.isalnum() or c in "-_" else "_" for c in name)[:48] or "profile"
    CLONE_ASSETS_DIR.mkdir(parents=True, exist_ok=True)
    # 文件名带内容哈希头6位：批量落盘时不同角色清洗后同名且同秒写盘也不会互相顶掉
    dest = CLONE_ASSETS_DIR / f"{safe}_ref_{int(time.time())}_{h[:6]}.wav"
    dest.write_bytes(raw)
    _logger.info(f"[VoiceHealth] 角色「{name}」内嵌参考音已落盘备份: {dest.name}")
    return {"file": dest.name, "existed": False}


@app.post("/api/profile_voice_repair")
async def api_profile_voice_repair(body: dict):
    """断链一键修复。action=backup_voice：单角色内嵌参考音落盘（进资产面板统一管理，内容哈希
    自动回算引用 → 落盘即显示"被该角色引用"）；backup_voice_all：全角色批量落盘（导入过一批
    角色包后一次点完，逐个点是折磨）；clear_idle_video / clear_body_video：清掉指向已消失文件的
    视频引用（运行链已在静默回退，清掉只是让配置与现实一致，卡片不再红）。
    换绑模型/重绑声音走既有 /api/rvc_assets/bind 与角色编辑，不重复造轮子。"""
    action = str(body.get("action") or "")
    if action == "backup_voice_all":
        # 幂等可重入：内容一致的跳过（existed），坏数据的记失败不中断整批
        done, failed = [], []
        for name, p in list(_profiles.items()):
            vb64 = p.get("voice_b64") or ""
            if not vb64:
                continue
            try:
                r = _vh_backup_voice(name, dict(p))
                done.append({"name": name, **r})
            except HTTPException as e:
                failed.append({"name": name, "err": e.detail})
        return {"ok": True, "done": done, "failed": failed,
                "backed_n": sum(1 for d in done if not d["existed"])}
    name = str(body.get("name") or "")
    p = _profiles.get(name)
    if p is None:
        raise HTTPException(404, "角色不存在")
    if action == "backup_voice":
        return {"ok": True, **_vh_backup_voice(name, dict(p))}
    if action in ("clear_idle_video", "clear_body_video"):
        field = action.removeprefix("clear_")
        await patch_profile(name, {field: ""})
        return {"ok": True, "cleared": field}
    raise HTTPException(400, "未知修复动作")


def _trash_resolve(kind: str, fname: str) -> Path:
    if kind not in _TRASH_ROOTS:
        raise HTTPException(400, "非法回收站类型")
    if (not fname or fname != os.path.basename(fname)
            or "/" in fname or "\\" in fname or fname.startswith(".")):
        raise HTTPException(400, "非法文件名")
    path = _TRASH_ROOTS[kind]() / fname
    if not path.exists():
        raise HTTPException(404, "回收站中无此文件")
    return path


@app.get("/api/asset_trash")
def api_asset_trash():
    """回收站列表：软删的克隆音 / RVC 模型，带原名与删除时间（文件名前缀即删除时刻）。"""
    items = []
    for kind, root_fn in _TRASH_ROOTS.items():
        root = root_fn()
        if not root.exists():
            continue
        for f in sorted(root.iterdir(), key=lambda x: -x.stat().st_mtime):
            if not f.is_file():
                continue
            ts_prefix, _, orig = f.name.partition("_")
            items.append({"kind": kind, "name": f.name,
                          "orig_name": orig or f.name,
                          "deleted_at": int(ts_prefix) if ts_prefix.isdigit() else int(f.stat().st_mtime),
                          "size": f.stat().st_size})
    return {"ok": True, "items": items,
            "total_bytes": sum(i["size"] for i in items)}


@app.get("/api/asset_trash/audio")
def api_asset_trash_audio(kind: str, name: str):
    """回收站克隆音试听直出：还原/彻删前先听一耳朵再决定（模型文件不是音频，不支持）。"""
    if kind != "clone":
        raise HTTPException(400, "只有克隆音支持试听")
    path = _trash_resolve(kind, name)
    return Response(content=path.read_bytes(), media_type="audio/wav")


@app.post("/api/asset_trash/restore")
def api_asset_trash_restore(body: dict):
    """还原：移回原目录。同名冲突三态：缺省→409 交 UI 决策；rename→加后缀共存；overwrite→顶替现有文件。
    改名不再静默发生——冲突必须由用户明确选择（覆盖可能顶掉正被角色引用的文件，必须知情）。"""
    kind = str(body.get("kind") or "")
    on_conflict = str(body.get("on_conflict") or "")
    if on_conflict not in ("", "rename", "overwrite"):
        raise HTTPException(400, "on_conflict 须为 rename / overwrite 或缺省")
    path = _trash_resolve(kind, str(body.get("name") or ""))
    ts_prefix, _, orig = path.name.partition("_")
    orig = orig if ts_prefix.isdigit() and orig else path.name
    dest_dir = path.parent.parent
    dest = dest_dir / orig
    renamed = False
    if dest.exists():
        if not on_conflict:
            raise HTTPException(409, f"原位置已存在同名文件 {orig}")
        if on_conflict == "rename":
            stem, suffix = os.path.splitext(orig)
            dest = dest_dir / f"{stem}_restored{int(time.time())}{suffix}"
            renamed = True
    os.replace(str(path), str(dest))   # overwrite 时顶替现有文件；其余场景 dest 必不存在，等价 rename
    if kind == "rvc":
        global _rvc_cache
        _rvc_cache = {"models": [], "indices": [], "ts": 0.0}
    return {"ok": True, "restored": dest.name, "renamed": renamed}


@app.post("/api/asset_trash/purge")
def api_asset_trash_purge(body: dict = Body(default={})):
    """彻底删除（不可逆）。四种粒度：body.name=单条；body.items=[{kind,name}…] 批量勾选；
    body.older_than_days=N 只清 N 天前删的（保留近期安全网）；都缺省=清空全部。
    删除时刻以文件名时间戳前缀为准（与列表口径一致）。"""
    kind = str(body.get("kind") or "")
    name = str(body.get("name") or "")
    if name:
        _trash_resolve(kind, name).unlink()
        return {"ok": True, "purged": 1}
    items = body.get("items")
    if items is not None:
        if not isinstance(items, list) or not all(isinstance(x, dict) for x in items):
            raise HTTPException(400, "items 须为 {kind,name} 对象数组")
        # 两段式：先全部解析校验（任一非法整批拒绝，不留一半），再统一删除
        paths = [_trash_resolve(str(x.get("kind") or ""), str(x.get("name") or "")) for x in items]
        for p in paths:
            p.unlink()
        return {"ok": True, "purged": len(paths)}
    if kind and kind not in _TRASH_ROOTS:
        raise HTTPException(400, "非法回收站类型")
    cutoff = None
    days = body.get("older_than_days")
    if days is not None:
        try:
            days = float(days)
        except (TypeError, ValueError):
            raise HTTPException(400, "older_than_days 须为数字")
        if days < 0:
            raise HTTPException(400, "older_than_days 须≥0")
        cutoff = time.time() - days * 86400
    n = 0
    roots = [_TRASH_ROOTS[kind]()] if kind else [fn() for fn in _TRASH_ROOTS.values()]
    for root in roots:
        if root.exists():
            for f in list(root.iterdir()):
                if not f.is_file():
                    continue
                if cutoff is not None:
                    ts_prefix, _, _rest = f.name.partition("_")
                    deleted_at = int(ts_prefix) if ts_prefix.isdigit() else int(f.stat().st_mtime)
                    if deleted_at > cutoff:
                        continue
                f.unlink()
                n += 1
    return {"ok": True, "purged": n}

# ── 路由：TTS 声音快速预听（不需要激活角色）──────────────────────
class QuickPreviewRequest(BaseModel):
    voice_name: str
    text:       str = "大家好，我是你们的数字人主播"
    language:   str = "zh-cn"

# 预听缓存：{voice_name: (audio_b64, timestamp)}，TTL = 5 分钟
_tts_preview_cache: dict = {}
_TTS_CACHE_TTL = 300.0

@app.post("/tts/quick_preview")
def tts_quick_preview(req: QuickPreviewRequest):
    """直接用 voice_name 合成短句，用于创建/编辑角色时试听。相同声音 5 分钟内命中缓存。"""
    voice_file = VOICES_DIR / f"{req.voice_name}.wav"
    if not voice_file.exists():
        raise HTTPException(400, f"声音文件不存在: {req.voice_name}.wav")
    # 命中缓存
    cached = _tts_preview_cache.get(req.voice_name)
    if cached:
        audio_b64, ts = cached
        if time.time() - ts < _TTS_CACHE_TTL:
            return {"ok": True, "audio_base64": audio_b64,
                    "voice": req.voice_name, "cached": True}
    try:
        r = requests.post(f"{SERVICES['tts']}/v1/audio/speech",
            json={"model": "xtts_v2", "input": req.text,
                  "voice": f"{req.voice_name}.wav", "language": req.language},
            headers=_svc_req_headers(), timeout=30)
        if r.status_code == 200:
            audio_b64 = base64.b64encode(r.content).decode()
            _tts_preview_cache[req.voice_name] = (audio_b64, time.time())
            return {"ok": True, "audio_base64": audio_b64,
                    "voice": req.voice_name, "cached": False}
        return {"ok": False, "detail": f"TTS返回 {r.status_code}"}
    except Exception as e:
        return {"ok": False, "detail": str(e)}

# ── 路由：摄像头枚举（DirectShow 快速扫描）──────────────────────
_cameras_cache: list = []
_cameras_cache_ts: float = 0.0

@app.get("/cameras")
def list_cameras():
    """扫描本机可用摄像头（索引 0-7），带设备名与分类(phone/other/output)，带 30s 缓存。
    P10：DirectShow 扫描会加载第三方虚拟摄像头 DLL(SplitCam 等,事件日志实锤过原生崩溃)，
    改走 dev_probe 子进程；探测崩了只这次列表拿不到，Hub 不再陪葬。失败沿用旧缓存。"""
    global _cameras_cache, _cameras_cache_ts
    if time.time() - _cameras_cache_ts < 30 and _cameras_cache:
        return {"cameras": _cameras_cache, "cached": True}
    r = _dev_probe(["cameras", "--max", "8"], timeout=30.0)
    if not r.get("ok"):
        if _cameras_cache:   # 降级：给旧名单好过给空(设备名单极少变)
            return {"cameras": _cameras_cache, "cached": True, "stale": True,
                    "error": r.get("detail", "")}
        return {"cameras": [], "error": r.get("detail", "")}
    _cameras_cache = r.get("cameras") or []
    _cameras_cache_ts = time.time()
    return {"cameras": _cameras_cache, "cached": False}

@app.get("/realtime/auto_source")
def realtime_auto_source():
    """预览自动选源决策（不启动推流）：返回会选用的视频源+原因+候选摄像头+建议麦克风。"""
    result = {"ok": True}
    try:
        import device_enum
        adb_path = rf"{_BASE}\scrcpy\scrcpy-win64-v3.1\adb.exe"
        try:
            adb_r = _subprocess.run([adb_path, "devices"], capture_output=True, text=True, timeout=5, creationflags=getattr(_subprocess, "CREATE_NO_WINDOW", 0))
            adb_ok = "\tdevice" in adb_r.stdout
        except Exception:
            adb_ok = False
        result["adb_android"] = adb_ok
        result.update(_pick_camera_source_safe(adb_ok, probe=True))   # P10: 子进程隔离
        result["relay"] = device_enum.check_monitor_phone_cam()       # 纯 HTTP，无原生栈
        result["cameras_annotated"] = _annotate_cameras_safe(probe=False)
        # 顺带给出建议手机麦克风
        try:
            inp = requests.get(f"{SERVICES['rvc']}/inputDevices", headers=_svc_req_headers(), timeout=5).json()
            names = inp if isinstance(inp, list) else inp.get("devices", inp)
            result["mic"] = device_enum.pick_mic(names if isinstance(names, list) else [])
        except Exception as _me:
            result["mic"] = {"device": None, "reason": f"rvc-unreachable:{_me}"}
    except Exception as e:
        result = {"ok": False, "detail": str(e)}
    return result

