@app.get("/api/monitor/status")
def api_monitor_status():
    """聚合手机无线终端(monitor_relay)状态，供 Hub 开播页展示。"""
    base = os.environ.get("MONITOR_URL", "http://127.0.0.1:7878").rstrip("/")
    _state = {"reachable": False}

    def _get(path: str, timeout: float = 1.0):
        try:
            r = requests.get(base + path, timeout=timeout).json()
            _state["reachable"] = True  # 任一探测连上即视为中继在线
            return r
        except Exception as e:
            return {"ok": False, "detail": str(e)}

    info = _get("/info", 0.8)
    health = _get("/health", 0.8)
    mic = _get("/mic/level", 0.8)
    cam = _get("/cam/status", 0.8)

    cap = health.get("capture") or {}
    mic_st = mic.get("status") or {}
    cam_st = cam.get("status") or {}
    cam_live = bool(cam_st.get("connected")) or (
        int(cam_st.get("peers") or 0) > 0 and int(cam_st.get("frames") or 0) > 0
    ) or float(cam_st.get("fps") or 0) > 0

    return {
        "reachable": _state["reachable"],
        "ok": bool(health.get("ok")),
        "base": base,
        "url": info.get("url") or "",
        "https_url": info.get("https_url") or "",
        "show_url": (info.get("url") or base + "/").rstrip("/") + "/show",
        "audio": {"ok": bool(cap.get("ok")), "dev": cap.get("dev") or "",
                  "clients": int(health.get("clients") or 0), "rms": cap.get("rms")},
        "mic": {"ok": bool(mic_st.get("ok")), "dev": mic_st.get("dev") or "",
                "level": mic_st.get("level") or 0, "frames": mic_st.get("frames") or 0,
                "taps": int(mic.get("taps") or 0)},
        "cam": {"ok": cam_live, "w": cam_st.get("w") or 0, "h": cam_st.get("h") or 0,
                "fps": cam_st.get("fps") or 0, "source": cam_st.get("source") or "",
                "url": cam.get("url_local") or ""},
    }


# P1-B 连接状态条·实时信号：音频电平从 monitor_relay 取，服务端缓存 ~1.2s → 多端高频轮询也≤1次/1.2s打到中继。
_SIGNAL_AUDIO_CACHE = {"ts": 0.0, "data": {"ok": False, "rms": 0.0, "dev": ""}}
# P1-F 广播馈线(CABLE)电平：直播时探 OBS 实际读的虚拟声卡电平 → 可信判「直播端是否真有声」。
_SIGNAL_CABLE_CACHE = {"ts": 0.0, "data": {"ok": False, "rms": 0.0, "dev": ""}}
_BROADCAST_DEV_CACHE = {"ts": 0.0, "token": ""}


def _broadcast_dev_token() -> str:
    """广播馈线设备名(=RVC 输出/OBS 读的虚拟声卡，如 'CABLE Input')的匹配 token，缓存 30s。
    取自 _pick_audio_devices().output(RVC优先，本地兜底)，去掉 API 后缀『 (MME)』只留设备标签；
    找不到回退 env HUB_BROADCAST_DEV 或 'CABLE Input'。rvc_devices() 是网络调用，故长缓存避免每次探针都打。"""
    now = time.time()
    if now - _BROADCAST_DEV_CACHE["ts"] < 30 and _BROADCAST_DEV_CACHE["token"]:
        return _BROADCAST_DEV_CACHE["token"]
    tok = ""
    try:
        p = _pick_audio_devices()
        out = (p.get("output") or "")
        # P2-1 护栏：pick 现在尊重用户偏好，偏好可能是监听耳机——但广播馈线探针只认直播声卡(CABLE)，
        # 否则会拿耳机当馈线测电平 → 假"直播无声"告警。偏好非 CABLE 时改从枚举里找 CABLE。
        if "cable" not in out.lower():
            outs = p.get("outputs") or []
            out = (next((d for d in outs if "cable input" in (d or "").lower()), "")
                   or next((d for d in outs if "cable" in (d or "").lower()), ""))
        tok = out.split(" (")[0].strip()   # 'CABLE Input (VB-Audio Virtual Cable) (MME)' → 'CABLE Input'
    except Exception:
        tok = ""
    if not tok:
        tok = os.environ.get("HUB_BROADCAST_DEV", "CABLE Input")
    _BROADCAST_DEV_CACHE.update(ts=now, token=tok)
    return tok


@app.get("/realtime/signal")
def realtime_signal():
    """P1-B 连接状态条·实时信号(轻量、可高频轮询~1s)：
      video: 活帧(fps>0 且数据新鲜)+ 开播健康态(读 realtime_status.json，极cheap)；
      audio: 输出电平 rms(取自 monitor_relay，服务端缓存 ~1.2s 防打爆)。
    任一侧异常都不影响另一侧、绝不抛错(前端据此做真信号显示，缺失回退设备名)。"""
    vid = {"live": False, "fps": 0.0, "state": "idle", "tone": "muted"}
    try:
        streaming = bool(_realtime_proc and _realtime_proc.poll() is None)
        metrics = {}
        try:
            _p = Path(rf"{_BASE}\realtime_status.json")
            if _p.exists():
                metrics = json.loads(_p.read_text(encoding="utf-8"))
        except Exception:
            metrics = {}
        fps = float(metrics.get("fps", 0) or 0)
        fresh = (time.time() - float(metrics.get("ts", 0) or 0)) < 10.0
        h = _stream_health_now()
        vid = {"live": bool(streaming and fresh and fps > 0), "fps": round(fps, 1),
               "state": h.get("state", "idle"), "tone": h.get("tone", "muted")}
    except Exception:
        pass
    aud = dict(_SIGNAL_AUDIO_CACHE["data"])
    try:
        if time.time() - _SIGNAL_AUDIO_CACHE["ts"] > 1.2:
            base = os.environ.get("MONITOR_URL", "http://127.0.0.1:7878").rstrip("/")
            try:
                r = requests.get(base + "/health", timeout=0.7).json()
                cap = r.get("capture") or {}
                aud = {"ok": bool(cap.get("ok")), "rms": float(cap.get("rms") or 0.0),
                       "dev": cap.get("dev") or ""}
            except Exception:
                aud = {"ok": False, "rms": 0.0, "dev": ""}
            _SIGNAL_AUDIO_CACHE.update(ts=time.time(), data=aud)   # 成败都刷 ts：失败也不至于每次都等 0.7s 超时
    except Exception:
        pass
    # P1-F 广播馈线电平(仅直播时探；未直播不开环回，省资源)：测 OBS 实际读的虚拟声卡(CABLE)有没有声。
    cable = dict(_SIGNAL_CABLE_CACHE["data"])
    try:
        streaming = bool(_realtime_proc and _realtime_proc.poll() is None)
        if not streaming:
            cable = {"ok": False, "rms": 0.0, "dev": ""}
            _SIGNAL_CABLE_CACHE.update(ts=time.time(), data=cable)
        elif time.time() - _SIGNAL_CABLE_CACHE["ts"] > 1.5:
            base = os.environ.get("MONITOR_URL", "http://127.0.0.1:7878").rstrip("/")
            try:
                r = requests.get(base + "/probe/level",
                                 params={"dev": _broadcast_dev_token()}, timeout=1.6).json()
                cable = {"ok": bool(r.get("ok")), "rms": float(r.get("rms") or 0.0),
                         "dev": r.get("dev") or ""}
            except Exception:
                cable = {"ok": False, "rms": 0.0, "dev": ""}
            _SIGNAL_CABLE_CACHE.update(ts=time.time(), data=cable)   # 成败都刷 ts，失败也不每次等超时
    except Exception:
        pass
    return {"video": vid, "audio": aud, "cable": cable, "ts": round(time.time(), 2)}

