# ── snapshot 辅助函数 ───────────────────────────────────────────
async def _get_snapshot_b64() -> str:
    try:
        with requests.get("http://127.0.0.1:8080/stream", stream=True, timeout=(1, 3)) as resp:
            buf = b""
            for chunk in resp.iter_content(chunk_size=8192):
                if not chunk:
                    continue
                buf += chunk
                s = buf.find(b'\xff\xd8')
                e = buf.find(b'\xff\xd9', s if s != -1 else 0)
                if s != -1 and e != -1:
                    return base64.b64encode(buf[s:e+2]).decode()
                if len(buf) > 300_000:
                    break
    except Exception:
        pass
    return ""

async def _get_snapshot_from_url_b64(url: str) -> str | None:
    try:
        def _read_first_frame():
            with requests.get(url, stream=True, timeout=(1.5, 3.0)) as r:
                r.raise_for_status()
                buf = bytearray()
                for chunk in r.iter_content(chunk_size=4096):
                    if not chunk:
                        continue
                    buf.extend(chunk)
                    start = buf.find(b"\xff\xd8")
                    end = buf.find(b"\xff\xd9", start + 2)
                    if start != -1 and end != -1:
                        return bytes(buf[start:end + 2])
                    if len(buf) > 2_000_000:
                        return None
            return None
        data = await asyncio.to_thread(_read_first_frame)
        return base64.b64encode(data).decode("ascii") if data else None
    except Exception:
        return None

def _crop_jpeg_black_border(data: bytes) -> bytes:
    try:
        import cv2
        import numpy as np
        img = cv2.imdecode(np.frombuffer(data, np.uint8), cv2.IMREAD_COLOR)
        if img is None:
            return data
        gray = cv2.cvtColor(img, cv2.COLOR_BGR2GRAY)
        mask = gray > 8
        ys, xs = np.where(mask)
        if xs.size < 1000 or ys.size < 1000:
            return data
        x1, x2 = int(xs.min()), int(xs.max()) + 1
        y1, y2 = int(ys.min()), int(ys.max()) + 1
        if (x2 - x1) < 20 or (y2 - y1) < 20:
            return data
        cropped = img[y1:y2, x1:x2]
        ok, jpg = cv2.imencode(".jpg", cropped, [cv2.IMWRITE_JPEG_QUALITY, 85])
        return jpg.tobytes() if ok else data
    except Exception:
        return data

async def _get_snapshot_from_url_bytes(url: str, crop_black: bool = False) -> bytes | None:
    b64 = await _get_snapshot_from_url_b64(url)
    if not b64:
        return None
    data = base64.b64decode(b64)
    return _crop_jpeg_black_border(data) if crop_black else data

