# ── 换脸预设：Hub 统一代理 realtime_stream 的 /swap/*（免开裸端口 8080 控制页）──────
#   realtime_stream 的画质/性能旋钮(PROC_W/ENHANCE/SMOOTH/SHARPEN/FPS/JPEG_Q)可运行时即时切换。
#   这里把它的 /swap/status、/swap/preset 收进 Hub /realtime/swap/*，让 /ops 面板一处管完；
#   探不到上游(未起/挂了) → 返回 up:False + 提示，前端显示「控制台未运行」而非 5xx 报错。
_RT_SWAP_BASE = os.environ.get("REALTIME_STREAM_URL", "http://127.0.0.1:8080").rstrip("/")


def _license_preset_gate(width: int, height: int, face_enhance: str):
    """P5 授权预设分层·服务端执行层的薄包装：决策核心在 license.preset_gate()
    （preset_ultra/preset_vocal 判定与授权状态同域，_license_test.py 可离线验收）。
    无 license 模块 → 原样放行（零破坏）。返回 (width, height, face_enhance, note)。"""
    if _license is None:
        return width, height, face_enhance, ""
    try:
        return _license.preset_gate(width, height, face_enhance)
    except Exception:
        return width, height, face_enhance, ""

# 换脸引擎能力缓存(gfpgan/codeformer 是否真可用)：供前端把「增强」下拉按真实能力过滤，
# 杜绝“选了 CodeFormer 但生产机没部署→引擎静默跳过增强”的信任硬伤(2026-07-05 P0)。30s 缓存。
_fs_caps_cache: dict = {"ts": 0.0, "data": {"ok": False}}

async def _faceswap_caps() -> dict:
    now = time.time()
    if now - _fs_caps_cache["ts"] < 30.0 and _fs_caps_cache["data"].get("ok"):
        return _fs_caps_cache["data"]
    try:
        r = await http_pool.get(f"{SERVICES['faceswap']}/health", timeout=2.5)
        j = r.json()
        d = {"ok": True, "gfpgan": bool(j.get("gfpgan")), "codeformer": bool(j.get("codeformer")),
             # gpen(2026-07-09 ONNX 轻精修)：健康包 gpen.model 非空=模型文件在位(懒加载,state 0 也算可用)
             "gpen": bool((j.get("gpen") or {}).get("model")),
             "model": j.get("swap_model", ""),
             "enh_concurrency": j.get("enh_concurrency"),
             "enh_pool": j.get("enh_pool") or {}}
    except Exception as e:
        d = {"ok": False, "error": str(e)[:80]}
    _fs_caps_cache["ts"] = now
    _fs_caps_cache["data"] = d
    return d

@app.get("/api/dfm/models")
async def api_dfm_models(live_only: bool = True):
    """S2: 代理换脸引擎 /model/available —— 供角色编辑「DFM 整脸换绑定」下拉用。
    默认 live_only=1 只给 GPU 实时可用的（绑到直播角色不卡帧）；live_only=0 给全量（离线出图）。"""
    try:
        r = await http_pool.get(f"{SERVICES['faceswap']}/model/available",
                                params={"live_only": int(live_only)}, timeout=6)
        j = r.json()
        j["engine_up"] = True
        # S7: 补 compliance 字段——生产引擎(.104)旧版 /model/available 不回该字段（本机副本新版会回）。
        #   Hub 侧用本地 registry 补齐（engine 已回则不覆盖），让「⚠需授权」标签今天就生效，免动 .104。
        # P2: cn/category 同样回填——旧版引擎清单只有英文文件名，下拉/对账全是 snake_case，
        #   用户不认识 jason_statham_320；本地 registry 是同一真相源，缺啥补啥（不覆盖引擎已回的）。
        try:
            if any(("compliance" not in m or not m.get("cn")) for m in (j.get("models") or [])):
                _reg = json.loads((Path(_BASE) / "dfm_workspace" / "dfm_registry.json").read_text(encoding="utf-8"))
                _ent = {e["file"].lower(): e for e in _reg.get("entries", [])}
                for m in j.get("models") or []:
                    e = _ent.get((m.get("model") or "").lower()) or {}
                    if "compliance" not in m:
                        m["compliance"] = e.get("compliance")
                    if not m.get("cn"):
                        m["cn"] = e.get("cn")
                    if not m.get("category"):
                        m["category"] = e.get("category")
        except Exception:
            pass
        return j
    except Exception as e:
        return {"ok": False, "engine_up": False, "n": 0, "models": [],
                "error": str(e)[:120], "hint": "换脸引擎未运行或为旧版（无 /model/available）"}


