@app.post("/api/dfm/prewarm")
async def api_dfm_prewarm(body: dict):
    """S2 预热：把某 DFM 角色预加载进换脸引擎 LRU（不改当前直播画面）。
    循证(.104/4070)：热切未缓存 DFM 阻塞 ~4.5s 且卡并发帧 ~2.8s(直播可见冻结)；命中 LRU 仅 ~16ms。
    故 operator 在角色编辑器「选中某 DFM」的一刻即后台调本接口预热 → 之后真正激活/上屏切换秒切无感。
    幂等、fire-and-forget 友好；引擎离线/旧版无端点 → 静默回 ok=False（前端不打扰）。"""
    model = (body.get("model") or "").strip()
    if not model:
        return {"ok": False, "skip": "empty"}
    try:
        r = await http_pool.post(f"{SERVICES['faceswap']}/model/prewarm",
                                 json={"model": model}, headers=_svc_req_headers(), timeout=30)
        return r.json()
    except Exception as e:
        return {"ok": False, "engine_up": False, "error": str(e)[:120]}


@app.post("/api/dfm/prewarm_hot")
async def api_dfm_prewarm_hot():
    """S4 一键预热「本场热角色」：活动角色 + 最常用角色的 DFM，按引擎 LRU 预算(cap-1)排队预热。
    计划在线程池算（含查引擎 cap 的短 HTTP，不堵事件循环），立即返回排队清单；
    加载在后台串行进行（每个 1~4.5s）。/realtime/start 开播时也自动触发同一逻辑。"""
    plan = await asyncio.to_thread(_plan_hot_dfms)
    _prewarm_dfm_list_async(plan, reason="手动一键预热")
    return {"ok": True, "queued": plan, "n": len(plan),
            "hint": ("已排队后台预热，完成后场内切换零冻结" if plan
                     else "没有绑定 DFM 的角色（或换脸引擎不可达）")}


def _dfm_registry_cn(model: str) -> str:
    """按文件名查本地 registry 的中文名（找不到回空串）。对账/横幅显示用，轻量到不值得缓存。"""
    try:
        _reg = json.loads((Path(_BASE) / "dfm_workspace" / "dfm_registry.json").read_text(encoding="utf-8"))
        key = (model or "").lower()
        for e in _reg.get("entries", []):
            if e.get("file", "").lower() == key:
                return e.get("cn") or ""
    except Exception:
        pass
    return ""


@app.get("/api/dfm/audit")
async def api_dfm_audit():
    """S5 DFM 库对账：逐一比对「角色绑定的 dfm_model」vs「换脸引擎库存」（/model/available live_only=0，
    含离线档；blocked 不在清单=视作不可绑）。背景：操作台库 112 个 ≠ 直播机 .104 库 46 个，
    绑定可指向直播机没有的模型——激活时引擎 404、旧逻辑会让**上一角色的明星脸继续挂着**（现已强制回退通用）。
    对账把这个坑前置到 UI：missing=库里没有(红/黄标)；offline_only=live_ok=False(直播会卡帧,仅离线出图)。"""
    issues, bindings = [], 0
    engine_up, lib_n = False, 0
    try:
        r = await http_pool.get(f"{SERVICES['faceswap']}/model/available",
                                params={"live_only": 0}, timeout=8)
        j = r.json()
        engine_up = True
        avail = {(e.get("model") or "").lower(): e for e in (j.get("models") or [])}
        lib_n = len(avail)
        for nm, p in list(_profiles.items()):
            mdl = (p.get("dfm_model") or "").strip()
            if not mdl:
                continue
            bindings += 1
            ent = avail.get(mdl.lower())
            if ent is None:
                # P2: missing 也带中文名——引擎清单里没有，从本地 registry 兜底查（横幅别只给 snake_case）
                issues.append({"profile": nm, "model": mdl, "status": "missing",
                               "cn": _dfm_registry_cn(mdl),
                               "hint": "引擎库无此模型（未部署到直播机/已下架）——激活将回退通用换脸"})
            elif ent.get("live_ok") is False:
                issues.append({"profile": nm, "model": mdl, "status": "offline_only",
                               "cn": ent.get("cn"),
                               "hint": f"仅离线档（GPU 换脸 ~{ent.get('gpu_swap_ms')}ms）——直播绑定会卡帧"})
    except Exception as e:
        return {"ok": False, "engine_up": False, "error": str(e)[:120],
                "issues": [], "n_bindings": 0, "library_n": 0}
    return {"ok": True, "engine_up": engine_up, "n_bindings": bindings,
            "library_n": lib_n, "issues": issues, "n_issues": len(issues)}


