async def realtime_output_aspect(name: str = ""):
    """切换输出画面比例(手机竖屏/横屏/方形)：
    ① 落 effect_cfg(单一真相，一键开播/自愈重启都按它，不再翻回横屏)；
    ② 若换脸在跑，热切 realtime_stream /output/aspect 即时生效(vcam 重开虚拟摄像头，无需重启)。"""
    nm = (name or "").strip().lower()
    if nm not in _ASPECT_WH:
        return {"ok": False, "error": f"未知比例:{name!r}", "presets": list(_ASPECT_WH)}
    # 持久化到 effect_cfg
    try:
        with _EFFECT_CFG_LOCK:
            cur = _effect_cfg_load()
            cur["outputAspect"] = nm
            w, h = _ASPECT_WH[nm]
            cur["videoWidth"], cur["videoHeight"] = w, h
            cur["_ts"] = int(time.time())
            _EFFECT_CFG_FILE.parent.mkdir(parents=True, exist_ok=True)
            _EFFECT_CFG_FILE.write_text(json.dumps(cur, ensure_ascii=False, indent=2), encoding="utf-8")
    except Exception as e:
        return {"ok": False, "error": f"保存比例失败:{str(e)[:80]}"}
    # 在播则热切
    live = False
    try:
        r = await http_pool.get(f"{_RT_SWAP_BASE}/output/aspect", params={"name": nm}, timeout=4.0)
        live = bool(r.json().get("ok"))
    except Exception:
        live = False
    return {"ok": True, "aspect": nm, "width": _ASPECT_WH[nm][0], "height": _ASPECT_WH[nm][1],
            "applied_live": live,
            "hint": ("已即时生效" if live else "已保存，下次开播生效(当前换脸未在跑)")}

