@app.get("/realtime/swap/away")
async def realtime_swap_away(style: str = "", text: str = "__keep__", image: str = "__keep__"):
    """代理离席画面热切(06u)：style=blur|image|off、text=角标文案(空串=撤角标)、image=品牌图。
    image 传 bg_images 内的裸文件名即可(hub 拼绝对路径,06v；带路径的绝对路径原样透传)。
    只透传显式给出的键(text/image 用哨兵区分"没传"与"清空")；持久默认走 /api/effect_cfg。"""
    params = {}
    if style.strip().lower() in ("blur", "image", "off"):
        params["style"] = style.strip().lower()
    if text != "__keep__":
        params["text"] = text
    if image != "__keep__":
        img = image.strip()
        if img and ("/" not in img) and ("\\" not in img) and (":" not in img):
            img = rf"{_BASE}\bg_images\{img}"
        params["image"] = img
    try:
        r = await http_pool.get(f"{_RT_SWAP_BASE}/swap/away", params=params, timeout=3.0)
        return r.json()
    except Exception as e:
        return {"ok": False, "up": False, "error": str(e)[:120],
                "hint": "实时换脸控制台未运行（已存的配置将在下次开播生效）"}


# 背景素材后缀白名单：静图走 PIL 校验；动图/视频走 OpenCV 解码校验（与 bg_replace
# 播放路径同引擎——能在这里打开就能在直播里播）。上限分开：视频天然大得多。
_BG_IMG_EXTS = (".jpg", ".jpeg", ".png", ".webp")
_BG_VID_EXTS = (".gif", ".mp4", ".webm", ".mov", ".avi", ".m4v")
_BG_IMG_MAX_MB = 15
_BG_VID_MAX_MB = 200


@app.get("/api/bg_images")
def api_bg_images():
    """bg_images 目录清单(hub 直读,不依赖 realtime_stream 存活)：虚拟背景与离席品牌图共用此目录。
    含动图/视频（虚拟背景可播；离席品牌图仅支持静图，由前端下拉过滤）。"""
    imgs = []
    try:
        d = Path(rf"{_BASE}\bg_images")
        if d.is_dir():
            imgs = sorted(fn.name for fn in d.iterdir()
                          if fn.suffix.lower() in _BG_IMG_EXTS + _BG_VID_EXTS)[:50]
    except Exception:
        pass
    return {"ok": True, "images": imgs}


def _bg_image_safe_name(filename: str) -> "tuple[str, str] | None":
    """上传文件名 → (清洗后主干, 小写后缀)。后缀不在白名单 → None。
    去路径成分防穿越；Windows 非法字符/控制符 → _；截长(effect_cfg awayImage 上限 120，留足余量)。"""
    name = os.path.basename((filename or "").replace("\\", "/")).strip()
    stem, ext = os.path.splitext(name)
    ext = ext.lower()
    if ext not in _BG_IMG_EXTS + _BG_VID_EXTS:
        return None
    stem = re.sub(r'[<>:"/\\|?*\x00-\x1f]', "_", stem).strip(" .")[:60] or "bg"
    return stem, ext


@app.post("/api/bg_images/upload")
async def api_bg_images_upload(file: UploadFile = File(...)):
    """上传背景素材进 bg_images 目录（虚拟背景与离席品牌图共用，传完即出现在下拉清单）。
    静图 jpg/png/webp（≤15MB，PIL 校验）；动图/视频 gif/mp4/webm/mov/avi（≤200MB，
    流式落盘防内存尖峰，OpenCV 解码校验——与直播播放同引擎）。重名自动加序号不覆盖。"""
    se = _bg_image_safe_name(file.filename or "")
    if se is None:
        raise HTTPException(400, "仅支持 jpg/jpeg/png/webp 图片，或 gif/mp4/webm/mov/avi 动图视频")
    stem, ext = se
    is_video = ext in _BG_VID_EXTS
    max_bytes = (_BG_VID_MAX_MB if is_video else _BG_IMG_MAX_MB) * 1024 * 1024

    d = Path(rf"{_BASE}\bg_images")
    d.mkdir(parents=True, exist_ok=True)
    tmp = d / f".upload_{uuid.uuid4().hex[:8]}{ext}.part"
    size = 0
    try:
        with open(tmp, "wb") as fout:
            while True:
                chunk = await file.read(1024 * 1024)
                if not chunk:
                    break
                size += len(chunk)
                if size > max_bytes:
                    raise HTTPException(400, f"文件过大，{'视频' if is_video else '图片'}请压到 "
                                             f"{_BG_VID_MAX_MB if is_video else _BG_IMG_MAX_MB}MB 以内")
                fout.write(chunk)
        if size == 0:
            raise HTTPException(400, "文件为空")

        note = ""
        if is_video:
            import cv2 as _cv2                       # 惰性导入,不拖慢 hub 启动
            cap = _cv2.VideoCapture(str(tmp))
            ok, fr = cap.read() if cap.isOpened() else (False, None)
            vw = int(cap.get(_cv2.CAP_PROP_FRAME_WIDTH) or 0)
            vh = int(cap.get(_cv2.CAP_PROP_FRAME_HEIGHT) or 0)
            cap.release()
            if not ok or fr is None:
                raise HTTPException(400, "视频/动图无法解码（文件损坏或编码不支持）")
            if vw > 1920 or vh > 1080:
                note = f"素材 {vw}×{vh} 偏大，直播中解码更耗 CPU，建议压到 1080p 以内"
        else:
            try:
                from PIL import Image as _Img
                with _Img.open(tmp) as im:
                    im.verify()
            except Exception:
                raise HTTPException(400, "图片无法解码（文件损坏或并非图片）")

        saved, i = f"{stem}{ext}", 1
        while (d / saved).exists():
            i += 1
            saved = f"{stem}_{i}{ext}"
        os.replace(tmp, d / saved)
    finally:
        if tmp.exists():
            try:
                tmp.unlink()
            except Exception:
                pass
    return {"saved": saved, "note": note, **api_bg_images()}


# ═ 录播增强（ADR-12-03 产品化）：MatAnyone 2 离线抠像任务管理 ═════════════════
# 单任务串行(独占 GPU)；tools/matting_offline.py 子进程执行,进度经 JSON 文件回传；
# 推流中/忙时自动入队，停播或上一任务完成后自动开跑；force=true 可越过推流闸门立即跑。
_MATTING_DIR = Path(rf"{_BASE}\logs\matting_offline")
_MATTING_UP_DIR = _MATTING_DIR / "uploads"
_MATTING_HIST_FILE = _MATTING_DIR / "_jobs.json"
_MATTING_QUEUE_FILE = _MATTING_DIR / "_queue.json"
_MATTING_IN_EXTS = (".mp4", ".mov", ".avi", ".m4v", ".webm")
_MATTING_MAX_MB = 2048
_MATTING_OUT_EXTS = (".mp4", ".mov")
_MATTING_RETAIN_DAYS = int(os.environ.get("MATTING_RETAIN_DAYS", "7"))
# 开跑前希望的空闲显存（1080p 长片 + 波动的舒适线；720p 实测 3G 亦可跑）
_MATTING_NEED_FREE_MB = int(os.environ.get("MATTING_NEED_FREE_MB", "6000"))
_matting_lock = threading.Lock()


def _matting_disk_gate(input_name: str, export: str) -> str:
    """磁盘水位闸门：按视频元数据估算产物体积,余量不足返回拦截文案(空串=放行)。
    ProRes 4444 实测 ≈0.61 B/像素·帧(彩排 1080p 2.76GB/3min),取 0.75 留裕量；
    mp4(com+pha) ≈0.03。拦截优于跑到一半写爆磁盘(产物残缺还拖垮系统盘)。"""
    import shutil as _sh
    try:
        reserve_gb = float(os.environ.get("MATTING_DISK_RESERVE_GB", "10"))
        import cv2 as _cv2
        cap = _cv2.VideoCapture(str(_MATTING_UP_DIR / input_name))
        if not cap.isOpened():
            return ""                      # 元数据读不出→不拦(开跑还有解码检查)
        w = int(cap.get(_cv2.CAP_PROP_FRAME_WIDTH) or 0)
        h = int(cap.get(_cv2.CAP_PROP_FRAME_HEIGHT) or 0)
        fps = cap.get(_cv2.CAP_PROP_FPS) or 25.0
        n = int(cap.get(_cv2.CAP_PROP_FRAME_COUNT) or 0)
        cap.release()
        if not (w and h and n) or not (1 <= fps <= 120):
            return ""
        ppf = w * h * n                    # 总像素·帧
        est_mb = ppf * (0.03 + (0.75 if export == "prores" else 0)) / 1048576
        free_mb = _sh.disk_usage(str(_MATTING_DIR)).free / 1048576
        if free_mb - est_mb < reserve_gb * 1024:
            need = est_mb + reserve_gb * 1024 - free_mb
            return (f"磁盘不够：预计产物 ~{est_mb / 1024:.1f}GB"
                    f"（{w}×{h}·{n / fps / 60:.0f}分钟{'·ProRes' if export == 'prores' else ''}），"
                    f"剩余 {free_mb / 1024:.1f}GB(需预留{reserve_gb:.0f}GB)。"
                    f"请清理 ~{need / 1024:.1f}GB" + ("，或不勾 ProRes" if export == "prores" else "") +
                    "，旧产物 7 天会自动清理")
    except Exception:
        pass
    return ""
_matting_proc: "Optional[_subprocess.Popen]" = None
_matting_job: dict = {}          # 当前/最近任务：id/input/bg/export/state/n/total/ms/eta_s/error/outputs/ts
_matting_hist: list = []         # 最近完成任务(≤10,持久化)
_matting_queue: list = []        # 待跑队列：[{input,bg,export,max_size,ts},…] 持久化
_matting_batch: list = []        # 自上次队列清空以来完成的任务(内存态,清空时汇总推送一次)

try:
    _matting_hist = json.loads(_MATTING_HIST_FILE.read_text(encoding="utf-8"))[:10]
except Exception:
    _matting_hist = []
try:
    _matting_queue = json.loads(_MATTING_QUEUE_FILE.read_text(encoding="utf-8"))[:20]
except Exception:
    _matting_queue = []


def _matting_streaming() -> bool:
    return bool(_realtime_proc and _realtime_proc.poll() is None)


def _matting_save_hist():
    try:
        _MATTING_DIR.mkdir(parents=True, exist_ok=True)
        _MATTING_HIST_FILE.write_text(
            json.dumps(_matting_hist[:10], ensure_ascii=False, indent=1), encoding="utf-8")
    except Exception:
        pass


def _matting_save_queue():
    try:
        _MATTING_DIR.mkdir(parents=True, exist_ok=True)
        _MATTING_QUEUE_FILE.write_text(
            json.dumps(_matting_queue[:20], ensure_ascii=False, indent=1), encoding="utf-8")
    except Exception:
        pass


def _matting_cleanup_old(days: int = None):
    """清理超过 N 天的录播增强产物(_com/_pha/_rgba/_com_noaudio)与 uploads 源片。
    历史里仍引用的产物、队列/在跑任务引用的源片不清。"""
    days = days if days is not None else _MATTING_RETAIN_DAYS
    if days <= 0:
        return 0
    keep = set()
    for j in _matting_hist + ([_matting_job] if _matting_job else []):
        for o in (j.get("outputs") or []):
            keep.add(os.path.basename(o))
    cutoff = time.time() - days * 86400
    n = 0
    try:
        _MATTING_DIR.mkdir(parents=True, exist_ok=True)
        for fn in _MATTING_DIR.iterdir():
            if not fn.is_file() or fn.name.startswith(("_", ".")):
                continue
            if fn.suffix.lower() not in _MATTING_OUT_EXTS:
                continue
            if not any(x in fn.name for x in ("_com", "_pha", "_rgba")):
                continue
            if fn.name in keep:
                continue
            if fn.stat().st_mtime >= cutoff:
                continue
            try:
                fn.unlink()
                n += 1
            except Exception:
                pass
        for pat in ("_com_noaudio.mp4", ".part"):
            for fn in _MATTING_DIR.glob(f"*{pat}"):
                if fn.stat().st_mtime < cutoff:
                    try:
                        fn.unlink()
                        n += 1
                    except Exception:
                        pass
        # uploads 源片同保留期清理：排队/在跑引用的除外（在跑文件被子进程占着句柄也删不动,双保险）
        busy = {q.get("input") for q in _matting_queue} | {_matting_job.get("input", "")}
        if _MATTING_UP_DIR.is_dir():
            for fn in _MATTING_UP_DIR.iterdir():
                if (fn.is_file() and fn.suffix.lower() in _MATTING_IN_EXTS
                        and fn.name not in busy and fn.stat().st_mtime < cutoff):
                    try:
                        fn.unlink()
                        n += 1
                    except Exception:
                        pass
    except Exception:
        pass
    if n:
        _logger.info(f"[Matting] 清理 {n} 个超过 {days} 天的旧文件(产物+源片)")
    return n


def _matting_gpu_free_mb() -> int:
    try:
        r = _subprocess.run(["nvidia-smi", "--query-gpu=memory.free", "--format=csv,noheader,nounits"],
                            capture_output=True, text=True, timeout=10,
                            creationflags=getattr(_subprocess, "CREATE_NO_WINDOW", 0))
        return int(r.stdout.strip().splitlines()[0])
    except Exception:
        return 1 << 30


# ── 显存租约：任务时按需腾挪，跑完自动复原（闲置基线的「填满保热」策略不动）──────
# 本机闲置约 29G 被有意填满(LLM 8h 常驻 + 双口型引擎热备,换首响低延迟)。录播增强要跑时
# 若空闲不足,按温和程度分级让位：① 卸 ollama LLM(下次对话自动重载,~10s 首响代价,常见
# 回收 ~10.7G)；② 仍不够再泊车非核心重型引擎(ditto/lipsync,记账)。队列清空后自动复原。
_matting_lease_lock = threading.Lock()
_MATTING_LEASE = {"llm": [], "parked": [], "ts": 0.0}


def _matting_vram_lease(need_mb: int = None) -> int:
    """确保空闲显存 ≥ need_mb，返回最终空闲值。仅在「不推流、即将开跑任务」时调用。
    先被动等 10s(推流/上个任务刚退,驱动归还显存需几秒)，再主动分级腾挪。"""
    need_mb = need_mb or _MATTING_NEED_FREE_MB
    with _matting_lease_lock:
        t0 = time.time()
        free = _matting_gpu_free_mb()
        while free < need_mb and time.time() - t0 < 10:
            time.sleep(2.0)
            free = _matting_gpu_free_mb()
        if free >= need_mb or _GPU_RELEASED:
            return free
        # ① 卸载 ollama 常驻(聊天兜底/翻译 LLM + 嵌入)。默认对话后端为云端,本地模型
        #    闲置时纯占位；真要用时 ollama 按请求自动重载。
        try:
            unloaded = _ollama_unload_all_sync()
            if unloaded:
                _MATTING_LEASE.update(llm=unloaded, ts=time.time())
                _logger.info(f"[Matting] 显存租约: 卸载 LLM {unloaded}")
                t1 = time.time()
                while time.time() - t1 < 15:
                    free = _matting_gpu_free_mb()
                    if free >= need_mb:
                        return free
                    time.sleep(2.0)
        except Exception as e:
            _logger.warning(f"[Matting] 显存租约: LLM 卸载失败 {e}")
        # ② 泊车非核心重型引擎（挂起自愈防复活;队列清空后 _matting_lease_restore 复原）
        for name in ("ditto", "lipsync"):
            if _supervisor is None or free >= need_mb:
                break
            try:
                _PARK_SUSPEND.add(name)
                if _supervisor.stop_any(name).get("ok"):
                    _MATTING_LEASE["parked"].append(name)
                    _MATTING_LEASE["ts"] = time.time()
                    _logger.info(f"[Matting] 显存租约: 泊车 {name}")
                    t2 = time.time()
                    while time.time() - t2 < 15 and free < need_mb:
                        time.sleep(2.0)
                        free = _matting_gpu_free_mb()
                else:
                    _PARK_SUSPEND.discard(name)
            except Exception:
                _PARK_SUSPEND.discard(name)
        return free      # 腾完仍不足也放行：子进程 --force,由队列串行天然限流


def _matting_lease_restore():
    """队列清空后复原租约：被泊引擎重新拉起(LLM 留给下次对话按需加载,不主动回填)。
    GPU 总开关处于释放态则不拉(尊重多机共卡)。hub 重启丢租约账本时,lipsync 由自愈
    拉回,ditto 由数字人模式启动流程按需拉起,不会卡死。"""
    with _matting_lease_lock:
        parked, _MATTING_LEASE["parked"] = _MATTING_LEASE["parked"], []
        _MATTING_LEASE["llm"] = []
        for name in parked:
            _PARK_SUSPEND.discard(name)
            if _GPU_RELEASED or _supervisor is None:
                continue
            try:
                _supervisor.launch_any(name)
                _logger.info(f"[Matting] 显存租约复原: 重启 {name}")
            except Exception:
                pass


def _matting_notify_batch():
    """队列清空时汇总推送本批结果(钉钉/企微 webhook 卡片 + Windows 托盘气泡兜底)。
    批量任务/停播自动接力常在无人值守时跑完,通知是「不用盯页面」的关键一环。
    全部为手动取消则不发(操作者在场)。MATTING_NOTIFY=0 关闭。尽力而为,不影响任务链路。"""
    global _matting_batch
    batch, _matting_batch = _matting_batch, []
    if os.environ.get("MATTING_NOTIFY", "1").strip().lower() in ("0", "false", "no", "off"):
        return
    real = [j for j in batch if j.get("state") in ("done", "error")]
    if not real:
        return
    try:
        ok = [j for j in real if j.get("state") == "done"]
        fails = [j for j in real if j.get("state") != "done"]
        ts_list = [float(j.get("ts") or 0) for j in real if j.get("ts")]
        end_list = [float(j.get("ended") or 0) for j in real if j.get("ended")]
        dur = ""
        if ts_list and end_list:
            mins, secs = divmod(max(0, int(max(end_list) - min(ts_list))), 60)
            dur = f"{mins}分{secs}秒" if mins else f"{secs}秒"
        lines = [f"### 🎬 录播增强完成 · {len(ok)}/{len(real)} 成功"]
        for j in real[:8]:
            if j.get("state") == "done":
                lines.append(f"- ✅ **{j.get('input', '?')}**: {j.get('n', 0)}帧 · "
                             f"{len(j.get('outputs') or [])}个产物")
            else:
                lines.append(f"- ❌ **{j.get('input', '?')}**: {str(j.get('error') or '未知错误')[:80]}")
        if len(real) > 8:
            lines.append(f"- …共 {len(real)} 个任务")
        if dur:
            lines.append(f"- **总耗时**: {dur} · 产物在「视觉效果 → 录播增强」下载")
        import alerts as _al
        _al.notify_event(f"录播增强完成 {len(ok)}/{len(real)} 成功",
                         detail=(f"总耗时{dur}" if dur else "") +
                                (f"，{len(fails)}个失败" if fails else ""),
                         level=("warn" if fails else "info"), source="matting",
                         links=[("打开控制台", _dash_public_base() + "/ui")],
                         md_body="\n".join(lines))
        _logger.info(f"[Matting] 批量完成通知已发({len(ok)}/{len(real)}成功)")
    except Exception as e:
        _logger.warning(f"[Matting] 批量完成通知失败: {e}")


_matting_last_warm = 0.0


def _matting_warm_async(reason: str = ""):
    """按需后台预热（限频 1h）：骨干权重进 torch hub 缓存 + 权重文件拉热进页缓存，
    首任务 loading 从 ~110s→~10s。推流中不打扰直播。"""
    global _matting_last_warm
    if time.time() - _matting_last_warm < 3600:
        return

    def _warm():
        global _matting_last_warm
        try:
            if _matting_streaming():
                return
            _matting_last_warm = time.time()
            _subprocess.run(
                [sys.executable, "-X", "utf8", rf"{_BASE}\tools\matting_offline.py", "--warm-only"],
                cwd=rf"{_BASE}", timeout=600,
                stdout=_subprocess.DEVNULL, stderr=_subprocess.DEVNULL,
                creationflags=getattr(_subprocess, "CREATE_NO_WINDOW", 0))
            _logger.info(f"[Matting] 模型预热完成({reason})")
        except Exception as e:
            _logger.warning(f"[Matting] 模型预热跳过: {e}")
    threading.Thread(target=_warm, daemon=True, name="matting-warm").start()


def _matting_warm_if_relevant(reason: str):
    """启动预热闸门：队列非空或近 24h 有任务痕迹才热——闲置机器不白占 GPU。
    （上传动作另有即时预热触发,不走此闸门）"""
    recent = bool(_matting_queue)
    if not recent:
        for h in _matting_hist[:5]:
            if time.time() - (h.get("ended") or h.get("ts") or 0) < 86400:
                recent = True
                break
    if recent:
        _matting_warm_async(reason)


def _matting_launch(body: dict) -> dict:
    """真正拉起子进程（调用方须已持 _matting_lock 且确认无在跑任务）。"""
    global _matting_proc, _matting_job
    inp = body["input"]
    gate = _matting_disk_gate(inp, body.get("export", "mp4"))
    if gate:      # 双保险：排队期间磁盘可能被别的任务吃掉,开跑前再验一次
        raise RuntimeError(gate)
    src = _MATTING_UP_DIR / inp
    bg = body.get("bg_path") or body.get("bg", "green")
    if bg not in ("green", "none") and not os.path.isabs(bg):
        bg = str(Path(rf"{_BASE}\bg_images") / os.path.basename(bg))
    export = body.get("export", "mp4")
    job_id = uuid.uuid4().hex[:8]
    prog_path = _MATTING_DIR / f"_prog_{job_id}.json"
    cmd = [sys.executable, "-X", "utf8", rf"{_BASE}\tools\matting_offline.py",
           "-i", str(src), "--bg", bg, "--export", export,
           "--suffix", job_id, "--progress-file", str(prog_path), "--force"]
    if int(body.get("max_size", 0) or 0) > 0:
        cmd += ["--max-size", str(int(body["max_size"]))]
    note = ""
    try:      # 训练争卡提示：实测 DFM 训练并行会把抠像拖慢 ~3x,标注出来免得用户以为坏了
        import psutil as _pu
        for p in _pu.process_iter(["cmdline"]):
            cl = " ".join(p.info.get("cmdline") or [])
            if "dfm_train" in cl or "labs_training" in cl:
                note = "检测到模型训练在跑，速度受影响(约慢3倍)"
                break
    except Exception:
        pass
    _matting_proc = _subprocess.Popen(
        cmd, cwd=rf"{_BASE}", stdout=_subprocess.DEVNULL, stderr=_subprocess.DEVNULL,
        creationflags=getattr(_subprocess, "CREATE_NO_WINDOW", 0))
    _matting_job = {"id": job_id, "input": inp,
                    "bg": os.path.basename(bg) if bg not in ("green", "none") else bg,
                    "export": export, "state": "loading", "n": 0, "total": 0,
                    "ms": 0, "eta_s": 0, "error": "", "outputs": [], "note": note,
                    "ts": round(time.time(), 1)}
    threading.Thread(target=_matting_watch, args=(_matting_proc, job_id, prog_path),
                     daemon=True, name=f"matting-{job_id}").start()
    return {"ok": True, "id": job_id}


def _matting_try_drain():
    """推流已停且无在跑任务 → 取队头自动开跑（停播/上一任务完成/对账器调用）。"""
    global _matting_queue, _matting_job
    with _matting_lock:
        if _matting_streaming():
            return False
        if _matting_proc and _matting_proc.poll() is None:
            return False
        if not _matting_queue:
            return False
        body = _matting_queue.pop(0)
        _matting_save_queue()
        try:
            _matting_launch(body)
            _logger.info(f"[Matting] 队列自动开跑: {body.get('input')}")
            return True
        except Exception as e:
            _matting_job = {"state": "error", "error": str(e)[:120], "input": body.get("input", "")}
            _logger.warning(f"[Matting] 队列开跑失败: {e}")
            return False


def _matting_drain_soon(max_wait: float = 90.0):
    """停播/任务收尾后的稳妥开跑：按证据等而不是盲睡——
    ① 等推流进程真正退出(≤max_wait,terminate 后 poll 有竞态)；
    ② 显存租约:被动等归还(10s)→不足再主动腾挪(卸LLM/泊车,见 _matting_vram_lease)；
    ③ 再取队首。腾不满也放行(子进程 --force,队列串行天然限流)。"""
    if not _matting_queue:
        return

    def _w():
        t0 = time.time()
        while time.time() - t0 < max_wait:
            if not _matting_streaming():
                break
            time.sleep(2.0)
        if _matting_streaming() or not _matting_queue:
            return          # 还在推流(如误触发/又开播了)→ 交给下次停播或对账器
        _matting_vram_lease()
        _matting_try_drain()

    threading.Thread(target=_w, daemon=True, name="matting-drain-soon").start()


def _matting_watch(proc: "_subprocess.Popen", job_id: str, prog_path: Path):
    """看护线程：进度文件 → _matting_job；进程退出 → 终态归档进历史。"""
    global _matting_proc
    while True:
        rc = proc.poll()
        try:
            p = json.loads(prog_path.read_text(encoding="utf-8"))
            if _matting_job.get("id") == job_id:
                _matting_job.update({k: p.get(k, _matting_job.get(k)) for k in
                                     ("state", "n", "total", "ms", "eta_s", "error", "outputs")})
        except Exception:
            pass
        if rc is not None:
            break
        time.sleep(1.0)
    if _matting_job.get("id") == job_id:
        st = _matting_job.get("state")
        if _matting_job.get("_cancelled"):
            _matting_job["state"] = "cancelled"
        elif st != "done":
            _matting_job["state"] = "error"
            if not _matting_job.get("error"):
                _matting_job["error"] = f"进程异常退出(rc={rc})"
        _matting_job["ended"] = round(time.time(), 1)
        _matting_hist.insert(0, {k: v for k, v in _matting_job.items() if not k.startswith("_")})
        del _matting_hist[10:]
        _matting_save_hist()
        _matting_batch.append(dict(_matting_hist[0]))
        with _matting_lock:
            _matting_proc = None
    try:
        prog_path.unlink()
    except Exception:
        pass
    if _matting_queue:
        _matting_drain_soon(max_wait=5.0)  # 本任务显存刚随子进程退出归还,稍候即可接力下一条
    else:
        _matting_notify_batch()            # 整条队列跑完:汇总推送本批结果(webhook+托盘气泡)
        _matting_lease_restore()           # 复原租约(重启被泊引擎)


class _MattingPidProc:
    """收养的孤儿任务进程句柄（hub 重启前拉起的子进程）：鸭子类型兼容 Popen 的
    poll()/terminate()，看护/取消/防双跑判断零改动复用。psutil 按创建时间识别
    PID 复用,不会误认新进程。"""

    def __init__(self, pid: int):
        import psutil
        self.pid = pid
        self._p = psutil.Process(pid)
        self.returncode = None

    def poll(self):
        if self.returncode is None:
            try:
                if self._p.is_running():
                    return None
            except Exception:
                pass
            self.returncode = 0      # 真实退出码不可得；终态以进度文件 state 为准
        return self.returncode

    def terminate(self):
        try:
            self._p.terminate()
        except Exception:
            pass


def _matting_adopt_orphans():
    """启动时收养孤儿：hub 崩溃/重启期间仍在跑的 matting 子进程 → 续接看护
    (防队列双跑抢卡,产物照常归档/通知)；停机期间已跑完的 → 从进度文件补录历史。"""
    global _matting_proc, _matting_job
    import psutil
    live = {}
    for p in psutil.process_iter(["pid", "cmdline"]):
        try:
            args = p.info["cmdline"] or []
        except Exception:
            continue
        if not any("matting_offline.py" in str(a) for a in args) or "--suffix" not in args:
            continue
        try:
            live[args[args.index("--suffix") + 1]] = {"pid": p.info["pid"], "args": args}
        except Exception:
            continue

    def _arg(args, key, default=""):
        try:
            return args[args.index(key) + 1]
        except (ValueError, IndexError):
            return default

    for f in sorted(_MATTING_DIR.glob("_prog_*.json")):
        jid = f.stem[len("_prog_"):]
        try:
            prog = json.loads(f.read_text(encoding="utf-8"))
        except Exception:
            prog = {}
        if jid in live:
            try:
                args = live[jid]["args"]
                bg = _arg(args, "--bg", "green")
                with _matting_lock:
                    if _matting_proc and _matting_proc.poll() is None:
                        continue          # 已有在跑任务(多孤儿只收最早的一个,其余任其跑完由下轮启动补录)
                    _matting_proc = _MattingPidProc(live[jid]["pid"])
                    _matting_job = {"id": jid, "input": os.path.basename(_arg(args, "-i")),
                                    "bg": os.path.basename(bg) if bg not in ("green", "none") else bg,
                                    "export": _arg(args, "--export", "mp4"),
                                    "state": prog.get("state", "running"),
                                    "n": prog.get("n", 0), "total": prog.get("total", 0),
                                    "ms": prog.get("ms", 0), "eta_s": prog.get("eta_s", 0),
                                    "error": "", "outputs": prog.get("outputs") or [],
                                    "ts": round(time.time(), 1), "adopted": True}
                    threading.Thread(target=_matting_watch, args=(_matting_proc, jid, f),
                                     daemon=True, name=f"matting-adopt-{jid}").start()
                _logger.info(f"[Matting] 收养孤儿任务 {jid}({_matting_job['input']}) pid={live[jid]['pid']}")
            except Exception as e:
                _logger.warning(f"[Matting] 收养 {jid} 失败: {e}")
        else:
            outs = prog.get("outputs") or []
            if prog.get("state") in ("done", "error") \
                    and not any(h.get("id") == jid for h in _matting_hist):
                stem = outs[0].split(f"_{jid}_")[0] if outs else "?"
                _matting_hist.insert(0, {
                    "id": jid, "input": stem, "state": prog["state"],
                    "n": prog.get("n", 0), "total": prog.get("total", 0),
                    "ms": prog.get("ms", 0), "error": prog.get("error", ""),
                    "outputs": outs, "ended": round(f.stat().st_mtime, 1), "adopted": True})
                del _matting_hist[10:]
                _matting_save_hist()
                _logger.info(f"[Matting] 补录停机期间结束的任务 {jid}({prog['state']})")
            try:
                f.unlink()
            except Exception:
                pass


@app.get("/api/matting/status")
def api_matting_status():
    """录播增强状态：当前任务(含进度)/队列/历史/是否推流中。"""
    running = bool(_matting_proc and _matting_proc.poll() is None)
    try:
        import shutil as _sh
        disk_free_gb = round(_sh.disk_usage(str(_MATTING_DIR)).free / (1 << 30), 1)
    except Exception:
        disk_free_gb = -1
    return {"ok": True, "running": running, "streaming": _matting_streaming(),
            "queue": list(_matting_queue), "disk_free_gb": disk_free_gb,
            "lease": {k: v for k, v in _MATTING_LEASE.items() if k != "ts"},
            "job": {k: v for k, v in _matting_job.items() if not k.startswith("_")},
            "history": _matting_hist[:10]}


@app.get("/api/matting/inputs")
def api_matting_inputs():
    """已上传待处理的录播清单（uploads 目录直读）。"""
    items = []
    try:
        if _MATTING_UP_DIR.is_dir():
            for fn in sorted(_MATTING_UP_DIR.iterdir()):
                if fn.suffix.lower() in _MATTING_IN_EXTS:
                    items.append({"name": fn.name, "mb": round(fn.stat().st_size / 1048576, 1)})
    except Exception:
        pass
    return {"ok": True, "inputs": items[:50]}


@app.post("/api/matting/upload")
async def api_matting_upload(file: UploadFile = File(...)):
    """上传录播视频(≤2GB,流式落盘)。只收 cv2 能开的常规封装,首帧解码校验。"""
    name = os.path.basename((file.filename or "").replace("\\", "/")).strip()
    stem, ext = os.path.splitext(name)
    ext = ext.lower()
    if ext not in _MATTING_IN_EXTS:
        raise HTTPException(400, "仅支持 mp4/mov/avi/m4v/webm 录播视频")
    stem = re.sub(r'[<>:"/\\|?*\x00-\x1f]', "_", stem).strip(" .")[:60] or "rec"
    _MATTING_UP_DIR.mkdir(parents=True, exist_ok=True)
    tmp = _MATTING_UP_DIR / f".up_{uuid.uuid4().hex[:8]}{ext}.part"
    size = 0
    try:
        with open(tmp, "wb") as fout:
            while True:
                chunk = await file.read(1024 * 1024)
                if not chunk:
                    break
                size += len(chunk)
                if size > _MATTING_MAX_MB * 1024 * 1024:
                    raise HTTPException(400, f"文件过大，请压到 {_MATTING_MAX_MB}MB 以内")
                fout.write(chunk)
        if size == 0:
            raise HTTPException(400, "文件为空")
        import cv2 as _cv2
        cap = _cv2.VideoCapture(str(tmp))
        ok, fr = cap.read() if cap.isOpened() else (False, None)
        cap.release()
        if not ok or fr is None:
            raise HTTPException(400, "视频无法解码（文件损坏或编码不支持）")
        saved, i = f"{stem}{ext}", 1
        while (_MATTING_UP_DIR / saved).exists():
            i += 1
            saved = f"{stem}_{i}{ext}"
        os.replace(tmp, _MATTING_UP_DIR / saved)
    finally:
        if tmp.exists():
            try:
                tmp.unlink()
            except Exception:
                pass
    _matting_warm_async("upload")      # 上传=马上要跑的强信号:提前拉热模型,点开跑时省加载
    return {"ok": True, "saved": saved, **api_matting_inputs()}


@app.post("/api/matting/start")
def api_matting_start(body: dict = Body(default={})):
    """开跑录播增强。推流中/忙时自动入队；force=true 越过推流闸门立即跑（仍串行）。"""
    global _matting_queue
    inp = os.path.basename(str(body.get("input", "")).replace("\\", "/"))
    src = _MATTING_UP_DIR / inp
    if not inp or inp.startswith(".") or not src.is_file() \
            or src.suffix.lower() not in _MATTING_IN_EXTS:
        raise HTTPException(400, "先上传/选择一个录播视频")
    bg = str(body.get("bg", "green")).strip() or "green"
    bg_path = bg
    if bg not in ("green", "none"):
        bgp = Path(rf"{_BASE}\bg_images") / os.path.basename(bg.replace("\\", "/"))
        if not bgp.is_file():
            raise HTTPException(400, f"背景素材不存在: {bg}")
        bg_path = str(bgp)
    export = "prores" if str(body.get("export", "")).lower() == "prores" else "mp4"
    gate = _matting_disk_gate(inp, export)
    if gate:
        raise HTTPException(400, gate)
    force = bool(body.get("force"))
    payload = {"input": inp,
               "bg": bg if bg in ("green", "none") else os.path.basename(bg),
               "bg_path": bg_path, "export": export,
               "max_size": int(body.get("max_size", 0) or 0)}
    with _matting_lock:
        busy = bool(_matting_proc and _matting_proc.poll() is None)
        streaming = _matting_streaming()
        if force and not busy:
            try:
                return _matting_launch(payload)
            except Exception as e:
                raise HTTPException(500, f"任务启动失败: {e}")
        if busy or (streaming and not force):
            _matting_queue.append({**payload, "ts": round(time.time(), 1)})
            del _matting_queue[20:]
            _matting_save_queue()
            pos = len(_matting_queue)
            if streaming:
                detail = f"已加入队列（第{pos}位），停播后自动开跑"
            elif busy:
                detail = f"已加入队列（第{pos}位），当前任务完成后自动开跑"
            else:
                detail = f"已加入队列（第{pos}位）"
            return {"ok": True, "queued": True, "position": pos, "detail": detail}
        # 空闲直跑前显存预检：不足则转入队 + 后台租约腾挪(卸闲置LLM/泊车)再自动开跑。
        # 腾挪要几秒到几十秒,放后台线程,API 即刻返回不卡前端。
        if _matting_gpu_free_mb() < _MATTING_NEED_FREE_MB:
            _matting_queue.append({**payload, "ts": round(time.time(), 1)})
            _matting_save_queue()
            _matting_drain_soon(max_wait=5.0)
            return {"ok": True, "queued": True, "position": len(_matting_queue),
                    "detail": "空闲显存不足，正在自动腾挪（卸载闲置模型），稍候自动开跑"}
        try:
            return _matting_launch(payload)
        except Exception as e:
            raise HTTPException(500, f"任务启动失败: {e}")


@app.post("/api/matting/cancel_queue")
def api_matting_cancel_queue(body: dict = Body(default={})):
    """清空队列，或按 index 移除一条（index 从 0 起）。"""
    global _matting_queue
    idx = body.get("index")
    with _matting_lock:
        if idx is None:
            _matting_queue.clear()
        else:
            try:
                _matting_queue.pop(int(idx))
            except (IndexError, ValueError, TypeError):
                return {"ok": False, "detail": "无效序号"}
        _matting_save_queue()
    return {"ok": True, "queue": list(_matting_queue)}


@app.post("/api/matting/cancel")
def api_matting_cancel():
    global _matting_proc
    with _matting_lock:
        if not (_matting_proc and _matting_proc.poll() is None):
            return {"ok": False, "detail": "没有在跑的任务"}
        _matting_job["_cancelled"] = True
        try:
            _matting_proc.terminate()
        except Exception as e:
            return {"ok": False, "detail": str(e)[:100]}
    return {"ok": True}


@app.get("/api/matting/download")
def api_matting_download(name: str):
    """取产物（仅 logs/matting_offline 根目录下的 mp4/mov,防目录穿越）。"""
    fn = os.path.basename((name or "").replace("\\", "/"))
    p = _MATTING_DIR / fn
    if not fn or fn.startswith((".", "_prog_")) or p.suffix.lower() not in _MATTING_OUT_EXTS \
            or not p.is_file():
        raise HTTPException(404, "产物不存在")
    mt = "video/quicktime" if p.suffix.lower() == ".mov" else "video/mp4"
    return FileResponse(str(p), media_type=mt, filename=fn)


@app.get("/realtime/swap/params")
async def realtime_swap_params(blend: str = "", threshold: str = "", smooth: str = "",
                               enhance: str = "__keep__", crossfade: str = "", out_q: str = ""):
    """代理换脸参数热更(P9)：融合/阈值/平滑/精修/交叉淡化/输出画质 在播即调即生效。
    只透传显式给出的键(enhance 合法值含空串=跟随档位，故用哨兵区分"没传")；校验在引擎侧做。"""
    params = {}
    for k, v in (("blend", blend), ("threshold", threshold), ("smooth", smooth),
                 ("crossfade", crossfade), ("out_q", out_q)):
        if str(v).strip() != "":
            params[k] = str(v).strip()
    if enhance != "__keep__":
        params["enhance"] = enhance.strip().lower()
    # P5 授权预设分层：在播热切 CodeFormer 同受闸门管（与开播路径同一杠杆，降级放行不拒绝）
    _lic_note = ""
    if params.get("enhance") == "codeformer":
        _w, _h, _enh, _lic_note = _license_preset_gate(0, 0, "codeformer")
        if _enh != "codeformer":
            params["enhance"] = _enh
    try:
        r = await http_pool.get(f"{_RT_SWAP_BASE}/swap/params", params=params, timeout=3.0)
        j = r.json()
        if _lic_note and isinstance(j, dict):
            j["lic_note"] = _lic_note
        return j
    except Exception as e:
        return {"ok": False, "up": False, "error": str(e)[:120],
                "hint": "实时换脸未运行（参数已存本地，下次开播生效）"}

