# ── P9 一键画质标定（2026-07-05 方案 P2 收口）────────────────────────────────
#   tools/swap_calibrate.py 此前只能命令行跑，标定出的 SWAP_AUTO_DOWN/UP_MS 还得手改
#   env_config.bat 才生效。这里包成 Hub 后台任务：开播页一键跑(子进程隔离,原生库崩溃
#   不带走 Hub)，建议阈值落 data/swap_calib.json，realtime_start 每次拉起视频管线时
#   自动注入(见 _video_env)——每台机器免手工得到专属自适应阈值。
_CALIB_FILE = Path(rf"{_BASE}\data\swap_calib.json")
_CALIB_JOB = {"running": False, "started": 0.0, "ended": 0.0, "ok": None,
              "detail": "", "phase": "", "log": deque(maxlen=14)}


def _swap_calib_load() -> dict:
    try:
        d = json.loads(_CALIB_FILE.read_text(encoding="utf-8"))
        return d if isinstance(d, dict) else {}
    except Exception:
        return {}


def _away_env_from_cfg(cfg: dict, bg_dir: str) -> dict:
    """06v 离席画面配置 → realtime_stream 环境变量(纯函数,可单测)。
    awayText 键存在即注入(空串=撤角标,是显式语义)；awayImage 为 bg_images 内文件名,
    这里拼绝对路径(realtime 侧收任意路径,归一化职责在 hub)；style=image 但没图→降 blur
    (启动就给确定行为,而非让 realtime 每帧发现图缺再退)。"""
    out = {}
    style = str(cfg.get("awayStyle") or "").strip().lower()
    text = cfg.get("awayText")
    img = str(cfg.get("awayImage") or "").strip()
    if img:
        out["SWAP_AWAY_IMAGE"] = os.path.join(bg_dir, img)
    if style in ("blur", "image", "off"):
        if style == "image" and not img:
            style = "blur"
        out["SWAP_AWAY_STYLE"] = style
    if text is not None:
        out["SWAP_AWAY_TEXT"] = str(text).strip()
    return out


# 输出比例预设 → (宽,高)。与 realtime_stream._ASPECT_PRESETS 对齐(手机竖屏为主)。
_ASPECT_WH = {
    "portrait916":    (720, 1280),   # 手机竖屏 9:16(视频通话/Telegram 全屏)
    "portrait34":     (720, 960),    # 手机竖屏 3:4
    "landscape169":   (1280, 720),   # 横屏 16:9
    "landscape169hd": (1920, 1080),  # 横屏 16:9 高清
    "square11":       (720, 720),    # 方形 1:1
}


def _resolved_output_aspect() -> str:
    """当前生效的输出比例名(effect_cfg 单一真相)。空/auto/非法 → ''(不强制)。"""
    try:
        a = str(_effect_cfg_load().get("outputAspect", "") or "").strip().lower()
        return a if a in _ASPECT_WH else ""
    except Exception:
        return ""


def _video_env() -> dict:
    """realtime_stream 子进程环境：有标定结果(data/swap_calib.json)就注入自适应阈值；
    有离席画面配置(effect_cfg,06v)就注入 SWAP_AWAY_*——重启不丢、多端同步。
    SWAP_CALIB_APPLY=0 为逃生门(回 env_config.bat 静态默认)；越界值视为脏数据忽略。"""
    env = os.environ.copy()
    try:
        if os.environ.get("SWAP_CALIB_APPLY", "1") == "1":   # 逃生门只管标定阈值,不连坐离席配置
            c = _swap_calib_load()
            down, up = int(c.get("down_ms") or 0), int(c.get("up_ms") or 0)
            if 200 <= down <= 5000 and 100 <= up < down:
                env["SWAP_AUTO_DOWN_MS"] = str(down)
                env["SWAP_AUTO_UP_MS"] = str(up)
    except Exception:
        pass
    try:
        env.update(_away_env_from_cfg(_effect_cfg_load(), rf"{_BASE}\bg_images"))
    except Exception:
        pass
    # 2026-07-09 P0-3 传输直连：把主引擎地址交给推流端 → 帧走 /faceswap_raw 二进制通道
    # (免 base64 膨胀 33% + Hub 代理一跳，实测省 ~60-90ms/帧)。引擎 404(未升级)/网络异常
    # 推流端自动回退 JSON 通道，容灾语义不变。SWAP_RAW_AUTO=0 关闭；显式 SWAP_API_RAW 优先。
    try:
        if os.environ.get("SWAP_RAW_AUTO", "1") != "0":
            env.setdefault("SWAP_API_RAW", SERVICES["faceswap"].rstrip("/"))
    except Exception:
        pass
    return env


def _calib_run(n: int, workers: int):
    """后台线程：跑标定子进程 → 解析产物 JSON → 建议阈值落盘。日志尾部进 job 供 UI 展示。"""
    t0 = time.time()
    try:
        cmd = [app_config.conda_python("facefusion"), "-X", "utf8",
               rf"{_BASE}\tools\swap_calibrate.py", "--n", str(n), "--workers", str(workers),
               "--tag", "auto"]
        p = _subprocess.Popen(cmd, cwd=_BASE, stdout=_subprocess.PIPE, stderr=_subprocess.STDOUT,
                              text=True, encoding="utf-8", errors="replace",
                              creationflags=getattr(_subprocess, "CREATE_NO_WINDOW", 0))
        for ln in p.stdout:
            ln = (ln or "").rstrip()
            if ln:
                _CALIB_JOB["log"].append(ln[:200])
                _CALIB_JOB["phase"] = ln[:120]
        rc = p.wait(timeout=120)
        if rc != 0:
            raise RuntimeError(f"标定进程退出码 {rc}: {list(_CALIB_JOB['log'])[-1] if _CALIB_JOB['log'] else '无输出'}")
        # 本次运行的产物 JSON = 最新的 *auto*.json 且 mtime 晚于任务启动时刻
        cands = sorted(Path(rf"{_BASE}\logs").glob("swap_calibration_*auto*.json"),
                       key=lambda x: x.stat().st_mtime, reverse=True)
        art = cands[0] if (cands and cands[0].stat().st_mtime >= t0 - 5) else None
        if art is None:
            raise RuntimeError("标定完成但未找到产物 JSON")
        data = json.loads(art.read_text(encoding="utf-8"))
        rec = data.get("recommend") or {}
        down, up = int(rec.get("down_ms") or 0), int(rec.get("up_ms") or 0)
        if not (200 <= down <= 5000 and 100 <= up < down):
            raise RuntimeError(f"建议阈值越界(down={down}, up={up})——引擎可能过载/掉CPU，换个时段再标")
        results = data.get("results") or {}
        calib = {"ts": int(time.time()), "down_ms": down, "up_ms": up,
                 "hd_mean_ms": rec.get("hd_mean_ms"),
                 "means": {k: (results.get(k) or {}).get("mean") for k in ("eco", "natural", "beauty", "hd")},
                 "n": n, "workers": workers, "artifact": art.name}
        _CALIB_FILE.parent.mkdir(parents=True, exist_ok=True)
        _CALIB_FILE.write_text(json.dumps(calib, ensure_ascii=False, indent=2), encoding="utf-8")
        _CALIB_JOB["ok"] = True
        _CALIB_JOB["detail"] = (f"降档>{down}ms · 回升<{up}ms（hd 并发均值 {rec.get('hd_mean_ms')}ms）"
                                f"已保存，下次开播自动生效")
        _logger.info(f"[SwapCalib] 标定完成: {calib}")
    except Exception as e:
        _CALIB_JOB["ok"] = False
        _CALIB_JOB["detail"] = str(e)[:300]
        _logger.warning(f"[SwapCalib] 标定失败: {e}")
    finally:
        _CALIB_JOB["ended"] = time.time()
        _CALIB_JOB["running"] = False
        _CALIB_JOB["phase"] = ""


@app.post("/api/swap/calibrate")
async def api_swap_calibrate(n: int = 20, workers: int = 3):
    """一键画质标定：对四个画质档打生产同形请求测时延分布 → 自适应阈值建议落盘。
    约 1~2 分钟；标定独占引擎，须停播、引擎在线、有激活角色(走生产代理路径注入角色脸)。"""
    if _CALIB_JOB["running"]:
        return {"ok": False, "detail": "标定已在进行中", "running": True}
    if _realtime_proc is not None and _realtime_proc.poll() is None:
        return {"ok": False, "detail": "请先停播再标定：标定会独占换脸引擎，在播时互相干扰、数据也不准"}
    caps = await _faceswap_caps()
    if not caps.get("ok"):
        return {"ok": False, "detail": f"换脸引擎离线，无法标定：{caps.get('error', '')}"}
    if not _active_profile:
        return {"ok": False, "detail": "请先激活一个角色：标定走生产同款换脸路径，需要角色脸"}
    n = max(8, min(60, int(n)))
    workers = max(1, min(4, int(workers)))
    _CALIB_JOB.update({"running": True, "started": time.time(), "ended": 0.0,
                       "ok": None, "detail": "", "phase": "启动标定进程…"})
    _CALIB_JOB["log"].clear()
    threading.Thread(target=_calib_run, args=(n, workers), daemon=True, name="swap-calib").start()
    return {"ok": True, "running": True, "eta_s": 90}


@app.get("/api/swap/calibrate/status")
def api_swap_calibrate_status():
    """标定任务状态 + 最近一次已保存的标定结果（开播注入的就是它）。
    P10 标定周期化：附 age_days/needs_calib 裁决(从未标定或超 14 天=建议重标)——
    引擎负载特征随驱动/温度/后台负载漂移，阈值该定期用实测刷新。"""
    j = dict(_CALIB_JOB)
    j["log"] = list(_CALIB_JOB["log"])
    j["elapsed_s"] = round(time.time() - _CALIB_JOB["started"], 1) if _CALIB_JOB["running"] else 0
    saved = _swap_calib_load()
    age_days = None
    if saved.get("ts"):
        age_days = round((time.time() - float(saved["ts"])) / 86400, 1)
    needs = (not saved.get("down_ms")) or (age_days is not None and age_days > 14)
    return {"ok": True, "job": j, "saved": saved,
            "age_days": age_days, "needs_calib": needs,
            "apply_on": os.environ.get("SWAP_CALIB_APPLY", "1") == "1"}

