async def _interp_download(path: str, params: dict):
    """透传下载：GET 上游 → 原样回 body + Content-Type + Content-Disposition；上游状态码一并透传。
    空值参数不下发(session 空=当前/最近会话)。上游不可达 → 503 明示同传未运行。"""
    try:
        clean = {k: v for k, v in params.items() if v not in (None, "")}
        r = await http_pool.get(f"{_INTERP_BASE}{path}", params=clean, timeout=8.0)
    except Exception as e:
        raise HTTPException(503, f"同传(LingoX)未运行：{str(e)[:120]}")
    headers = {}
    cd = r.headers.get("content-disposition")
    if cd:
        headers["Content-Disposition"] = cd
    return Response(content=r.content, status_code=r.status_code,
                    media_type=r.headers.get("content-type", "application/octet-stream"),
                    headers=headers)

