# ── 翻译质量与词表：Hub 代理 live_interpreter 的缓存/预热观测 + 词表 CSV 导入导出，让 /ops 一处观测+维护 ──
#   缓存/预热探上游(up:False 兜底)；CSV 导出走既有下载透传；导入/预热触发走 JSON POST 透传(原样回状态+体)。
async def _interp_post_json(path: str, payload: dict, timeout: float = 8.0):
    """透传 JSON POST 到 live_interpreter：原样回上游 JSON + 状态码(便于前端拿 detail/parsed/skipped)。
    上游不可达 → 503 明示同传未运行。"""
    try:
        r = await http_pool.post(f"{_INTERP_BASE}{path}", json=(payload or {}), timeout=timeout)
    except Exception as e:
        raise HTTPException(503, f"同传(LingoX)未运行：{str(e)[:120]}")
    try:
        body = r.json()
    except Exception:
        body = {"ok": False, "detail": (r.text or "")[:200]}
    return JSONResponse(body, status_code=r.status_code)

