@app.get("/interp/subtitle_overlay")
async def interp_subtitle_overlay(request: Request):
    """Phase B-2：OBS Browser Source 透明字幕页(代理 7900/overlay，query 原样透传)。"""
    qs = str(request.url.query)
    url = f"{_INTERP_BASE}/overlay" + (f"?{qs}" if qs else "")
    try:
        r = await http_pool.get(url, timeout=8.0)
        return HTMLResponse(r.text, status_code=r.status_code)
    except Exception as e:
        raise HTTPException(503, f"同传(LingoX)未运行：{str(e)[:120]}")

