async def _call_tts(voice_b64: str, voice_name: str, text: str, language: str):
    """P10-3/P13-B1: TTS 调用 + 最多2次重试（仅连接级错误；5xx 不重试，避免加剧过载）"""
    for attempt in range(3):  # P13-B1: 2→3，支持两次重试
        try:
            async with _TTS_LOCK:
                if voice_b64:
                    r = await http_pool.post(f"{SERVICES['tts']}/v1/audio/clone",
                        json={"text": text, "language": language,
                              "reference_audio_base64": voice_b64})
                else:
                    vname = voice_name or "female_01.wav"
                    r = await http_pool.post(f"{SERVICES['tts']}/v1/audio/speech",
                        json={"model": "xtts_v2", "input": text,
                              "voice": vname, "language": language})
            if attempt > 0:
                _metrics["tts_retry_total"] += 1  # P13-C1: 重试后成功计数
            return r
        except (httpx.ConnectError, httpx.ReadTimeout) as exc:
            if attempt == 2:
                raise  # 两次重试仍失败，向上传播
            _logger.warning(f"[TTS] 连接失败，自动重试({attempt+1}/2): {exc}")
            await asyncio.sleep(0.2 * (2 ** attempt))  # P12-B2: 0.2s→0.4s


async def _call_rvc(audio_b64: str, rvc_model: str, rvc_settings: dict):
    """P13-B2: RVC 调用 + 最多2次重试（鈥镜 _call_tts，仅连接级错误）"""
    rvc_model = _rvc_resolve_pth(rvc_model)   # 相对 id → 绝对路径（引擎按自身 CWD 解析会找不到）
    for attempt in range(3):
        try:
            r = await http_pool.post(f"{RVC_API}/convert", json={
                "audio_base64": audio_b64,
                "pth_path":     rvc_model,
                "index_path":   rvc_settings.get("index_path", ""),
                "pitch":        rvc_settings.get("pitch", 0),
                "index_rate":   rvc_settings.get("index_rate", 0.3),
                "f0method":     rvc_settings.get("f0method", "rmvpe"),
                "protect":      rvc_settings.get("protect", 0.33),
            }, timeout=30)
            if attempt > 0:
                _metrics["rvc_retry_total"] += 1  # P13-C1
            return r
        except (httpx.ConnectError, httpx.ReadTimeout) as exc:
            if attempt == 2:
                raise
            _logger.warning(f"[RVC] 连接失败，自动重试({attempt+1}/2): {exc}")
            await asyncio.sleep(0.2 * (2 ** attempt))


# ── Phase6-1: 变声(VC)适配器分发层 ─────────────────────────────────
# 统一的归一化变声结果（屏蔽不同后端的响应差异，保持调用方逻辑不变）。
class _VCResp:
    __slots__ = ("status_code", "audio_b64")
    def __init__(self, status_code: int, audio_b64: str = ""):
        self.status_code = status_code
        self.audio_b64 = audio_b64

# 具体适配器：把现有 RVC 包成 VCAdapter（零行为变化，仅委托 _call_rvc）。
if _engine_registry is not None:
    try:
        from engine_registry import VCAdapter as _VCAdapterBase

        class RvcAdapter(_VCAdapterBase):
            def capabilities(self) -> dict:
                return {"engine": "rvc", "realtime": True, "zero_shot": False}
            async def convert(self, audio_b64: str, *, target: str = "",
                              settings=None, **opts):
                r = await _call_rvc(audio_b64, target, settings or {})
                if r.status_code == 200:
                    return _VCResp(200, r.json().get("audio_base64", ""))
                return _VCResp(r.status_code, "")

        _engine_registry.attach_adapter("rvc", RvcAdapter())
    except Exception as _rae:
        print(f"[Hub] RvcAdapter 注册失败(降级用 _call_rvc): {_rae}")


async def _vc_dispatch(engine: str, audio_b64: str, model: str, settings: dict) -> _VCResp:
    """按引擎分发变声。已注册适配器→走适配器；rvc 无适配器→回退 _call_rvc；
    其它引擎缺适配器→明确报错（新引擎接入 = 实现并 attach 一个 VCAdapter）。"""
    adapter = _engine_registry.get_adapter(engine) if _engine_registry is not None else None
    if adapter is not None:
        return await adapter.convert(audio_b64, target=model, settings=settings)
    if engine == "rvc" or not engine:
        r = await _call_rvc(audio_b64, model, settings)
        if r.status_code == 200:
            return _VCResp(200, r.json().get("audio_base64", ""))
        return _VCResp(r.status_code, "")
    raise RuntimeError(f"变声引擎 '{engine}' 未实现适配器")


# ── Phase8: 口型(LipSync)适配器分发层 ──────────────────────────────
class _LSResp:
    __slots__ = ("status_code", "video_bytes")
    def __init__(self, status_code: int, video_bytes: bytes = b""):
        self.status_code = status_code
        self.video_bytes = video_bytes

# 进程内记录已在口型服务侧预计算过的人脸（按内容哈希），避免每句重复人脸检测(省 15-20s/句)
_ls_precomputed: set = set()
# 同一人脸的预计算 in-flight 锁：防「激活后台预计算」与「首句对话」并发重复触发
#   face_alignment 按尺寸的一次性编译(实测 ~33s)。并发调用复用同一次预计算。
_ls_precompute_locks: dict = {}
# P-Harden2(2026-07-07 事故): 预计算失败负缓存——失败(超时/异常/非200)后的冷却窗内，
# 同一 (副本,人脸) 不再重试预计算，直接走单图/原图回退。此前锁上排队的每个调用者轮到后
# 都各自烧满一轮超时(视频 300s + 单图 120s)，形成每 5 分钟一条失败日志的串行重试风暴，
# 期间句句延迟拉满。冷却到期自然恢复重试(服务修好后最多等一个窗口即自愈)。
_LS_PRECOMPUTE_FAIL_TTL_S = float(os.environ.get("AVATARHUB_PRECOMPUTE_FAIL_TTL_S", "180"))
_ls_precompute_failed_at: dict = {}   # (base, face_id) -> monotonic 最后失败时刻


class _LSPrecomputeCooldown(Exception):
    """预计算失败冷却窗内的短路信号（内部控制流，不代表新错误）。"""


def _ls_fail_recent(key) -> bool:
    ts = _ls_precompute_failed_at.get(key)
    if ts is None:
        return False
    if time.monotonic() - ts >= _LS_PRECOMPUTE_FAIL_TTL_S:
        _ls_precompute_failed_at.pop(key, None)
        return False
    return True


async def _lipsync_ensure_face(base: str, face_bytes: bytes) -> str:
    """确保该人脸已在口型服务(指定副本 base)侧预计算并缓存，返回 face_id（内容哈希）。
    幂等 + 并发安全：同一 (副本, face_id) 的并发调用串行化，只真正预计算一次。
    多副本(多卡)下按 base 区分——每张卡各自预计算一次，避免跨副本缓存误命中。
    路线A：激活角色挂了真人底视频(body_video)时，改用「视频底」预计算——口型贴到
    真人视频帧(真实头动/身体/背景)，返回视频 face_id；失败回退单图路径。"""
    import hashlib
    vpath = _active_profile_video("body_video")
    if vpath:
        try:
            with open(vpath, "rb") as _vf:
                vbytes = _vf.read()
            vfid = "vid_" + hashlib.sha1(vbytes).hexdigest()[:16]
            vkey = (base, vfid)
            if vkey in _ls_precomputed:
                return vfid
            if _ls_fail_recent(vkey):          # 冷却窗内不重试，直接回退单图
                raise _LSPrecomputeCooldown()
            vlock = _ls_precompute_locks.setdefault(vkey, asyncio.Lock())
            async with vlock:
                if vkey in _ls_precomputed:
                    return vfid
                if _ls_fail_recent(vkey):      # 排队等锁期间前一个调用者刚失败 → 不再各烧一轮超时
                    raise _LSPrecomputeCooldown()
                async with _aclient(timeout=300.0) as _cli:
                    r = await _cli.post(
                        f"{base}/lipsync/precompute_video",
                        files={"video": ("body.mp4", vbytes, "video/mp4")},
                        data={"face_id": vfid})
                if r.status_code == 200:
                    _ls_precomputed.add(vkey)
                    _ls_precompute_failed_at.pop(vkey, None)
                    _logger.info(f"[Hub] 视频底口型基底就绪 {vfid} ← {os.path.basename(vpath)}")
                    return vfid
                _ls_precompute_failed_at[vkey] = time.monotonic()
                _logger.warning(f"[Hub] 视频底预计算失败({r.status_code})，回退单图口型"
                                f"（{int(_LS_PRECOMPUTE_FAIL_TTL_S)}s 内不重试）")
        except _LSPrecomputeCooldown:
            pass                               # 静默回退单图：冷却期内属预期，不刷日志
        except Exception as _ve:
            try:
                _ls_precompute_failed_at[vkey] = time.monotonic()
            except NameError:
                pass                           # 读文件即失败时 vkey 未定义
            _logger.warning(f"[Hub] 视频底预计算异常({_ve})，回退单图口型"
                            f"（{int(_LS_PRECOMPUTE_FAIL_TTL_S)}s 内不重试）")
    fid = "ph_" + hashlib.sha1(face_bytes).hexdigest()[:16]
    key = (base, fid)
    if key in _ls_precomputed:
        return fid
    if _ls_fail_recent(key):                   # 冷却窗内不重试，调用方直接走原图/静态回退
        return ""
    lock = _ls_precompute_locks.setdefault(key, asyncio.Lock())
    async with lock:
        if key in _ls_precomputed:      # 等锁期间别的协程已完成
            return fid
        if _ls_fail_recent(key):        # 等锁期间别的协程刚失败 → 不再各烧一轮超时
            return ""
        try:
            async with _aclient(timeout=120.0) as _cli:
                r = await _cli.post(
                    f"{base}/lipsync/precompute_face",
                    files={"face": ("face.jpg", face_bytes, "image/jpeg")},
                    data={"face_id": fid})
            if r.status_code == 200:
                _ls_precomputed.add(key)
                _ls_precompute_failed_at.pop(key, None)
                return fid
            _ls_precompute_failed_at[key] = time.monotonic()
        except Exception as _pe:
            _ls_precompute_failed_at[key] = time.monotonic()
            print(f"[Hub] 人脸预计算失败(回退逐帧检测，{int(_LS_PRECOMPUTE_FAIL_TTL_S)}s 内不重试): {_pe}")
    return ""


async def _lipsync_call_service(audio_bytes: bytes, face_bytes: bytes,
                                fps: int = 25, batch_size: int = 8,
                                smooth=None, enhance: str = "",
                                timeout: float = 120.0) -> _LSResp:
    """内置 MuseTalk 服务调用。优先用 face_id 缓存（跳过人脸检测）；缓存未命中自动回退送原图。
    enhance='gfpgan' → 服务端在合成后过 GFPGAN 人脸增强（256 口型更清晰）。
    timeout: 逐句实时口型默认 120s 够用；MV 这种 15~30s 长音频一次合成要放宽（调用方传）。"""
    data = {"fps": fps, "batch_size": batch_size}
    if smooth is not None:          # Phase8: 时序平滑参数位（服务不支持时忽略该字段）
        data["smooth"] = smooth
    if enhance:                     # 实时 256 画质增强（MuseTalk 输出过 GFPGAN）
        data["enhance"] = enhance

    async with _svc_lease("lipsync") as base:   # P-Conc5: 多卡时本句口型落到某张空闲 GPU 副本
        fid = await _lipsync_ensure_face(base, face_bytes) if face_bytes else ""

        async def _post(use_cache: bool) -> _LSResp:
            files = {"audio": ("audio.wav", audio_bytes, "audio/wav")}
            d = dict(data)
            if use_cache and fid:
                d["face_id"] = fid
            else:
                files["face"] = ("face.jpg", face_bytes, "image/jpeg")
            async with _aclient(timeout=timeout) as _cli:
                r = await _cli.post(f"{base}/lipsync/generate", files=files, data=d)
            return _LSResp(r.status_code, r.content if r.status_code == 200 else b"")

        resp = await _post(use_cache=bool(fid))
        if resp.status_code != 200 and fid:   # 缓存可能因服务重启失效 → 丢弃并送原图重试
            _ls_precomputed.discard((base, fid))
            resp = await _post(use_cache=False)
        return resp

if _engine_registry is not None:
    try:
        from engine_registry import LipSyncAdapter as _LSAdapterBase

        class MuseTalkAdapter(_LSAdapterBase):
            def capabilities(self) -> dict:
                return {"engine": "musetalk", "realtime": True, "resolution": "256x256"}
            async def generate(self, audio_bytes: bytes, face_bytes: bytes,
                               *, fps: int = 25, batch_size: int = 8,
                               smooth=None, enhance: str = "", **opts):
                return await _lipsync_call_service(audio_bytes, face_bytes,
                                                   fps, batch_size, smooth, enhance)

        _engine_registry.attach_adapter("musetalk", MuseTalkAdapter())

        class LatentSyncAdapter(_LSAdapterBase):
            """离线高清(512)口型引擎。非实时；角色 lipsync_engine='latentsync' 时启用。"""
            BASE = os.environ.get("LATENTSYNC_URL", "http://127.0.0.1:8091")

            def capabilities(self) -> dict:
                return {"engine": "latentsync", "realtime": False, "resolution": "512x512"}

            async def generate(self, audio_bytes: bytes, face_bytes: bytes,
                               *, fps: int = 25, batch_size: int = 8, smooth=None, **opts):
                async with _aclient(timeout=600.0) as _cli:
                    r = await _cli.post(
                        f"{self.BASE}/lipsync/generate",
                        files={"audio": ("audio.wav", audio_bytes, "audio/wav"),
                               "face":  ("face.jpg",  face_bytes,  "image/jpeg")},
                        data={"fps": fps})
                return _LSResp(r.status_code, r.content if r.status_code == 200 else b"")

        # latentsync 非内置引擎，需先 register 描述符再挂适配器（attach 仅对已注册引擎生效）
        if not _engine_registry.attach_adapter("latentsync", LatentSyncAdapter()):
            from engine_registry import EngineDescriptor as _ED, KIND_LIPSYNC as _KLS
            _engine_registry.register(
                _ED(name="latentsync", kind=_KLS, backend="latentsync",
                    base_url=LatentSyncAdapter.BASE, builtin=False,
                    description="LatentSync 1.5 扩散口型（离线高清 512，非实时）",
                    capabilities={"realtime": False, "resolution": "512x512"}),
                LatentSyncAdapter())

        class EchoMimicAdapter(_LSAdapterBase):
            """EchoMimic 全脸音频驱动数字人（离线高清 512：整脸表情+头动，不是只动嘴）。
            输入单张人像 + 音频，端点契约同 latentsync(/lipsync/generate)。
            角色/请求 lipsync_engine='echomimic' 时启用。Apache-2.0 可商用。"""
            BASE = SERVICES.get("echomimic", "http://127.0.0.1:8095").rstrip("/")

            def capabilities(self) -> dict:
                return {"engine": "echomimic", "realtime": False, "full_face": True,
                        "resolution": "512x512", "license": "Apache-2.0"}

            async def generate(self, audio_bytes: bytes, face_bytes: bytes,
                               *, fps: int = 24, batch_size: int = 8, smooth=None,
                               steps: int = 6, **opts):
                data = {"fps": fps, "steps": steps}
                # 透传可选画幅/上下文参数（端点有默认值，缺省即可）
                for k in ("W", "H", "L", "cfg", "context_frames", "context_overlap", "seed"):
                    if k in opts and opts[k] is not None:
                        data[k] = opts[k]
                async with _aclient(timeout=1200.0) as _cli:
                    r = await _cli.post(
                        f"{self.BASE}/echomimic/generate",
                        files={"audio": ("audio.wav", audio_bytes, "audio/wav"),
                               "face":  ("face.jpg",  face_bytes,  "image/jpeg")},
                        data=data)
                return _LSResp(r.status_code, r.content if r.status_code == 200 else b"")

        # echomimic 已在 engine_registry 内置预注册 → 直接挂适配器
        if not _engine_registry.attach_adapter("echomimic", EchoMimicAdapter()):
            from engine_registry import EngineDescriptor as _ED2, KIND_LIPSYNC as _KLS2
            _engine_registry.register(
                _ED2(name="echomimic", kind=_KLS2, backend="echomimic",
                     base_url=EchoMimicAdapter.BASE, builtin=False,
                     description="EchoMimic 全脸音频驱动数字人（离线高清 512，非实时）",
                     capabilities={"realtime": False, "full_face": True,
                                   "resolution": "512x512", "license": "Apache-2.0"}),
                EchoMimicAdapter())

        class DittoAdapter(_LSAdapterBase):
            """Ditto 运动空间扩散·实时全脸说话头（口型+头动+表情+眨眼）。
            输入单张人像 + 音频，端点契约同 echomimic/latentsync(/lipsync/generate)。
            warm 后渲染 50-60fps、快于实时;PyTorch 后端避开 sm_120 的 TensorRT 坑。
            角色/请求 lipsync_engine='ditto' 时启用。Apache-2.0 可商用。"""
            BASE = SERVICES.get("ditto", "http://127.0.0.1:8096").rstrip("/")

            def capabilities(self) -> dict:
                return {"engine": "ditto", "realtime": True, "full_face": True,
                        "resolution": "512x512", "license": "Apache-2.0", "streaming": True}

            async def generate(self, audio_bytes: bytes, face_bytes: bytes,
                               *, fps: int = 25, batch_size: int = 8, smooth=None, **opts):
                # 实时对话路径默认 25 步扩散：实测 RTF≈1.0(基本实时)、画质与 50 步视觉等价;
                # 需更快可传 10(RTF≈0.84),需最高保真可传 50。standalone 端点默认仍 50。
                data = {"sampling_timesteps": opts.get("sampling_timesteps", 25)}
                # 透传其它可选参数（端点均有默认值，缺省即可）
                for k in ("online_mode", "fade_in", "fade_out", "crop_scale", "max_size"):
                    if k in opts and opts[k] is not None:
                        data[k] = opts[k]
                async with _aclient(timeout=600.0) as _cli:
                    r = await _cli.post(
                        f"{self.BASE}/ditto/generate",
                        files={"audio": ("audio.wav", audio_bytes, "audio/wav"),
                               "face":  ("face.jpg",  face_bytes,  "image/jpeg")},
                        data=data)
                return _LSResp(r.status_code, r.content if r.status_code == 200 else b"")

        # ditto 已在 engine_registry 内置预注册 → 直接挂适配器
        if not _engine_registry.attach_adapter("ditto", DittoAdapter()):
            from engine_registry import EngineDescriptor as _ED3, KIND_LIPSYNC as _KLS3
            _engine_registry.register(
                _ED3(name="ditto", kind=_KLS3, backend="ditto",
                     base_url=DittoAdapter.BASE, builtin=False,
                     description="Ditto 运动空间扩散·实时全脸说话头（512，快于实时）",
                     capabilities={"realtime": True, "full_face": True,
                                   "resolution": "512x512", "license": "Apache-2.0",
                                   "streaming": True}),
                DittoAdapter())
    except Exception as _lae:
        print(f"[Hub] LipSync 适配器注册失败(降级用内置调用): {_lae}")


# ── 口型高清档：默认引擎 + 健康门控（出片默认高清；服务没起来自动回落实时 musetalk）──────
#   AVATARHUB_LIPSYNC_DEFAULT：把高清档(latentsync/echomimic)设为「出片端点」默认引擎，零改角色配置。
#   仅作用于 /avatar/speak(/stream) 这类单次出片合成；实时对话/流式恒走 musetalk(除非角色显式配)，
#   避免一个全局开关把实时链路拖成 512 扩散。默认空=完全保持原行为(出片也走 musetalk)。
_LIPSYNC_DEFAULT_ENGINE = os.environ.get("AVATARHUB_LIPSYNC_DEFAULT", "").strip().lower()
# 实时基线：恒可用、无需服务存活探测（musetalk 走内置 lipsync 服务，缺席时上层各自有跳过兜底）。
_LIPSYNC_REALTIME_BASE = "musetalk"


def _lipsync_resolve(req_engine: str, profile: dict, *, allow_hd_default: bool = False) -> str:
    """口型引擎解析（单一真相）：请求 > 角色 > [出片默认档] > 内置默认(musetalk)。
    allow_hd_default=True 时（仅出片端点）才让 AVATARHUB_LIPSYNC_DEFAULT 兜底，实时路径不传以保持低延迟。"""
    eng = ((req_engine or "").strip()
           or (profile.get("lipsync_engine", "") or "").strip())
    if not eng and allow_hd_default and _LIPSYNC_DEFAULT_ENGINE:
        eng = _LIPSYNC_DEFAULT_ENGINE
    return eng or _default_engine("lipsync")


# ── 实时高清默认档：让「高清默认化」也覆盖实时/流式（默认空=保持 musetalk，零回归）──────────
#   AVATARHUB_LIPSYNC_RT_DEFAULT：把"快于实时"的高清引擎(ditto)设为 实时/流式 默认引擎，零改角色配置。
#   与出片默认(_LIPSYNC_DEFAULT_ENGINE)分离：出片可用慢扩散(latentsync)，实时只接受 RTF≲1 的引擎(ditto)，
#   避免一个开关把实时链路拖成离线扩散。默认空=完全保持原行为(实时走 musetalk)。
_LIPSYNC_RT_DEFAULT_ENGINE = os.environ.get("AVATARHUB_LIPSYNC_RT_DEFAULT", "").strip().lower()


# ── 实时口型「负载门控」：单卡满载/跨机抢显存时，重型 512 实时引擎(ditto)渲染越过实时(RTF>1)→掉帧。
#   A/B 实测(2026-06-30, 5090): ditto 空载 RTF≈0.91，被 fish-TTS 抢卡时升到 1.08(p95 1.17)；
#   musetalk(256) raw≈0.52 / +gfpgan≈0.82 仍有余量。故本卡满载时新会话自动回落 musetalk(raw)保实时。
#   与显存总开关(/api/gpu/release)同源动机：另一台机器占显存 → 本卡 free 降 → 自动让出重型引擎。
#   只在 ditto 确为实时默认档(deploy.env: AVATARHUB_LIPSYNC_RT_DEFAULT=ditto)时才可能生效，否则全程 no-op。
#   AVATARHUB_RT_LOADGATE=0 关；_VRAM=high|med|off 调灵敏度；_UTIL=N(>0)叠加 GPU 占用阈值(默认关，避免被本机自身在飞渲染误判)。
_RT_LOADGATE = os.environ.get("AVATARHUB_RT_LOADGATE", "1").strip().lower() not in ("0", "off", "false", "no", "")
_RT_LOADGATE_VRAM = os.environ.get("AVATARHUB_RT_LOADGATE_VRAM", "high").strip().lower()   # high|med|off
try:
    _RT_LOADGATE_UTIL = int(os.environ.get("AVATARHUB_RT_LOADGATE_UTIL", "0") or "0")       # GPU 占用% 阈值, 0=关
except Exception:
    _RT_LOADGATE_UTIL = 0
_RT_HEAVY_ENGINES = {"ditto"}   # 重型实时高清(512)引擎：满载时回落 _LIPSYNC_REALTIME_BASE(musetalk 256)
_VRAM_ORDER = {"low": 0, "med": 1, "high": 2}
_RT_GATE_LOG = {"state": None, "ts": 0.0}   # 门控状态变迁的节流日志(避免每请求每解析刷屏)


def _rt_overloaded(vram: dict | None = None) -> bool:
    """本卡是否「满载到重型实时引擎(512)会掉帧」：显存水位达阈值 或 GPU 占用达阈值(可选)。
    vram 可传入已取的显存快照复用(/health 已有)；不传则现取(_get_perf_metrics 自带 TTL 缓存,廉价)。
    默认仅按显存 high 判定——既覆盖跨机抢显存,又稳定(不受本机自身逐句渲染的瞬时占用抖动影响)。"""
    if not _RT_LOADGATE:
        return False
    try:
        need = _VRAM_ORDER.get(_RT_LOADGATE_VRAM)
        if need is not None:
            p = vram if vram is not None else _vram_pressure()
            lv = _VRAM_ORDER.get(p.get("level", "unknown"))
            if lv is not None and lv >= need:
                return True
        if _RT_LOADGATE_UTIL > 0:
            if _get_perf_metrics().get("gpu_util", -1) >= _RT_LOADGATE_UTIL:
                return True
    except Exception:
        pass
    return False


def _lipsync_loadgate(engine: str, vram: dict | None = None, services: dict | None = None) -> str:
    """重型实时高清引擎(ditto) + 本卡满载 → 回落 musetalk(256)保实时；其余原样返回(含已是 base 的情况)。
    安全网：回落落点 musetalk(服务键 'lipsync') 必须在线，否则「回落到未起的服务=零帧」反不如保留 ditto
    降级出帧(RTF 可能>1, 偶掉帧但仍连续)——故落点未就绪时不回落、转 WARN 提示运维拉起基线。
    日志按状态变迁节流(最多 ~30s 一条)，避免每请求 ×多次解析刷屏；常态(非重型)零开销直接返回。"""
    if engine not in _RT_HEAVY_ENGINES:
        return engine
    if _rt_overloaded(vram):
        now = time.time()
        # 落点判活：musetalk 的服务键是 'lipsync'(非 'musetalk')，且 _lipsync_ready_cached 对 base 恒真——
        # 不能用它判活，必须直读真实服务状态(取不到时保守认为可回落，不因判活失败而放弃门控)。
        base_up = True
        try:
            svc = services if services is not None else (_HEALTH_CACHE.get("data") or {}).get("services") or {}
            base_up = bool(svc.get("lipsync"))
        except Exception:
            base_up = True
        if not base_up:
            if _RT_GATE_LOG["state"] != "gated_nobase" or now - _RT_GATE_LOG["ts"] > 30:
                _logger.warning(f"[LipSync/RT] 满载需回落但落点 musetalk(lipsync) 未就绪 → 维持 {engine} 降级出帧"
                                f"（回落到未起服务=零帧；请「启用全部服务」或设 HUB_SUP_LIPSYNC=1 常驻基线）")
                _RT_GATE_LOG["state"] = "gated_nobase"; _RT_GATE_LOG["ts"] = now
            return engine
        if _RT_GATE_LOG["state"] != "gated" or now - _RT_GATE_LOG["ts"] > 30:
            _logger.info(f"[LipSync/RT] 负载门控回落 {engine}→{_LIPSYNC_REALTIME_BASE}"
                         f"（单卡满载, 防 512 渲染 RTF>1 掉帧; AVATARHUB_RT_LOADGATE=0 可关）")
            _RT_GATE_LOG["state"] = "gated"; _RT_GATE_LOG["ts"] = now
        return _LIPSYNC_REALTIME_BASE
    if _RT_GATE_LOG["state"] in ("gated", "gated_nobase"):
        _logger.info(f"[LipSync/RT] 负载缓解，恢复 {engine} 实时高清候选")
        _RT_GATE_LOG["state"] = "ok"; _RT_GATE_LOG["ts"] = time.time()
    return engine


def _lipsync_ready_cached(engine: str, services: dict | None = None) -> bool:
    """同步·读 /health 状态判活（不发探测）：供实时解析处零延迟使用。
    musetalk/空=实时基线恒就绪；其它引擎读 services[engine]（默认取健康缓存快照）；未命中→未就绪(保守回落)。
    services 显式传入时用它（如 _health_refresh 用本轮新鲜 status，避免读到上一快照而恒滞后一刷）。"""
    if not engine or engine == _LIPSYNC_REALTIME_BASE:
        return True
    try:
        if services is None:
            services = (_HEALTH_CACHE.get("data") or {}).get("services") or {}
        return bool(services.get(engine))
    except Exception:
        return False


def _lipsync_resolve_rt(req_engine: str, profile: dict, services: dict | None = None,
                        vram: dict | None = None) -> str:
    """实时/流式口型解析（单一真相）：请求 > 角色 > [实时高清默认档·仅当其服务在线] > 内置默认(musetalk)，
    再过「负载门控」：解析出的若是重型实时高清(ditto)且本卡满载 → 回落 musetalk(256)保实时(防 RTF>1 掉帧)。
    设了 AVATARHUB_LIPSYNC_RT_DEFAULT(如 ditto) 时，仅当该引擎 /health 在线才采用，否则回落 musetalk——
    把健康判定提前到解析处，让 vcam/串行化/分块等"按引擎"分支与最终引擎一致（避免选了 ditto 但服务没起、
    却仍走 ditto 专属分支再失败）。运行期再失败另有 _lipsync_dispatch 兜底。
    services：可传入本轮新鲜健康快照（不传=读缓存）；用于 /health 自身计算时消除"恒滞后一刷"。
    vram：可传入已取显存快照复用（/health 已有），供负载门控判定，避免重复取数。"""
    eng = ((req_engine or "").strip()
           or (profile.get("lipsync_engine", "") or "").strip())
    if not eng and _LIPSYNC_RT_DEFAULT_ENGINE:
        cand = _LIPSYNC_RT_DEFAULT_ENGINE
        if cand == _LIPSYNC_REALTIME_BASE or _lipsync_ready_cached(cand, services):
            eng = cand
    return _lipsync_loadgate(eng or _default_engine("lipsync"), vram, services)


async def _lipsync_engine_ready(engine: str) -> bool:
    """高清口型引擎是否就绪：musetalk/空=实时基线恒就绪；latentsync/echomimic/ditto 需其服务在线。
    优先读 /health 缓存(零额外探测)；缓存尚冷再做一次性 TCP 判活。未知/探不到 → 视为未就绪(保守回落)。"""
    if not engine or engine == _LIPSYNC_REALTIME_BASE:
        return True
    try:
        data = _HEALTH_CACHE.get("data")
        if data:
            return bool((data.get("services") or {}).get(engine))
        url = SERVICES.get(engine, "")
        return bool(url) and await _port_alive(url)
    except Exception:
        return False


async def _lipsync_dispatch(engine: str, audio_bytes: bytes, face_bytes: bytes,
                            *, fps: int = 25, batch_size: int = 8,
                            smooth=None, enhance: str = "") -> _LSResp:
    """按引擎分发口型生成。已注册适配器→走适配器；musetalk 无适配器→回退内置调用；
    其它引擎缺适配器→明确报错（新口型引擎接入 = 实现并 attach 一个 LipSyncAdapter）。
    enhance 仅对支持的实时引擎(musetalk)生效；latentsync 已是 512，忽略。
    健康门控：选了高清档(latentsync/echomimic/ditto)但其服务没起来 → 回落实时 musetalk(256)，
    不让「默认高清」在服务缺席时把整段口型静默掉；musetalk/空 恒就绪。"""
    if engine and engine != _LIPSYNC_REALTIME_BASE and not await _lipsync_engine_ready(engine):
        _logger.warning(f"[LipSync] 引擎 '{engine}' 未就绪(服务离线) → 健康门控回落 musetalk(256 实时)")
        engine = _LIPSYNC_REALTIME_BASE
        enhance = enhance or ""
    adapter = _engine_registry.get_adapter(engine) if _engine_registry is not None else None
    if adapter is not None:
        try:
            return await adapter.generate(audio_bytes, face_bytes,
                                          fps=fps, batch_size=batch_size, smooth=smooth,
                                          enhance=enhance)
        except Exception as _hd_err:
            # 运行期兜底：高清档(latentsync/echomimic/ditto)虽过了存活门控，但本次调用仍失败
            #   (偶发连接重置/渲染期异常/OOM)→ 回落实时 musetalk(256)，让本段口型有结果而非整段 500；
            #   musetalk 自身失败则照常上抛(它已是基线，无再可回落)。健康门控管"服务没起来"，此处管"起来了但这次挂了"。
            if engine and engine != _LIPSYNC_REALTIME_BASE:
                _logger.warning(f"[LipSync] 引擎 '{engine}' 运行期失败({type(_hd_err).__name__}: {_hd_err}) → 回落 musetalk(256)")
                return await _lipsync_call_service(audio_bytes, face_bytes, fps, batch_size,
                                                   smooth, "")
            raise
    if engine == "musetalk" or not engine:
        return await _lipsync_call_service(audio_bytes, face_bytes, fps, batch_size,
                                           smooth, enhance)
    raise RuntimeError(f"口型引擎 '{engine}' 未实现适配器")


async def _ditto_register_async(face_bytes: bytes, crop_scale: float = 2.3, max_size: int = 1920):
    """开口前预注册 ditto 头像(检测+裁剪+外观特征),写入服务端缓存。幂等、fire-and-forget。
    与 STT/LLM 首 token 重叠,使首句也跳过注册开销。失败静默(首句退化为现场注册)。"""
    base = SERVICES.get("ditto", "http://127.0.0.1:8096").rstrip("/")
    try:
        async with _aclient(timeout=30.0) as c:
            await c.post(f"{base}/ditto/register",
                         files={"face": ("face.jpg", face_bytes, "image/jpeg")},
                         data={"crop_scale": crop_scale, "max_size": max_size})
    except Exception as e:
        _logger.debug(f"[Ditto] prewarm skip: {e}")


# ── 虚拟摄像头(OBS Virtual Camera)推送：把数字人画面当系统摄像头输出 ────────
_VCAM_URL = os.environ.get("VCAM_URL", "http://127.0.0.1:7870")
_vcam_enabled = os.environ.get("AVATARHUB_VCAM", "0") == "1"


async def _vcam_push(video_bytes: bytes, audio_bytes: bytes = b""):
    """把一段口型视频(可带音频)入队到虚拟摄像头（fire-and-forget，失败静默）。
    带 audio 时虚拟摄像头开播即同步发声，供 OBS 桌面音频捕获，实现音视频合一。"""
    try:
        files = {"video": ("dh.mp4", video_bytes, "video/mp4")}
        if audio_bytes:
            files["audio"] = ("dh.wav", audio_bytes, "audio/wav")
        async with _aclient(timeout=15.0) as _cli:
            await _cli.post(f"{_VCAM_URL}/play", files=files)
    except Exception as _ve:
        _logger.debug(f"[VCam] push 跳过: {_ve}")


async def _vcam_set_idle(face_bytes: bytes):
    """设置虚拟摄像头空闲时显示的头像（角色激活时调用）。
    先即时设静态头像兜底，再后台异步推送真·活体待机循环（不阻塞 WebRTC 握手/首屏）。"""
    try:
        async with _aclient(timeout=10.0) as _cli:
            await _cli.post(f"{_VCAM_URL}/set_idle",
                            files={"face": ("face.jpg", face_bytes, "image/jpeg")})
    except Exception:
        pass
    try:
        asyncio.create_task(_vcam_set_idle_loop(face_bytes))
    except Exception:
        pass


def _active_profile_video(field: str) -> str:
    """取当前激活角色的视频素材路径(idle_video/body_video)，校验文件存在后返回绝对路径，否则空串。"""
    try:
        rel = dict(_profiles.get(_active_profile, {})).get(field, "") or ""
        if not rel:
            return ""
        pth = rel if os.path.isabs(rel) else os.path.join(os.getcwd(), rel)
        return pth if os.path.isfile(pth) else ""
    except Exception:
        return ""


async def _vcam_set_idle_loop(face_bytes: bytes):
    """后台：设置 vcam 待机循环。
    路线A 优先：若激活角色挂了真人半身待机视频(idle_video)，直接推真人循环视频(最真实)。
    否则回退：取 LivePortrait 活体循环(眨眼/转头)做伪活体待机(单图方案)。"""
    # ── 路线A：真人半身待机视频(最高优先级) ───────────────────────────
    real_idle = _active_profile_video("idle_video")
    if real_idle:
        try:
            with open(real_idle, "rb") as _f:
                _vid = _f.read()
            async with _aclient(timeout=30.0) as _cli:
                r = await _cli.post(f"{_VCAM_URL}/set_idle_loop",
                                    files={"loop": ("idle.mp4", _vid, "video/mp4")})
            if r.status_code == 200:
                _logger.info(f"[VCam] 真人半身待机循环已就绪 ← {os.path.basename(real_idle)}")
                return
            _logger.warning(f"[VCam] 真人待机推送失败({r.status_code})，回退活体循环")
        except Exception as _e:
            _logger.warning(f"[VCam] 真人待机异常({_e})，回退活体循环")
    # ── 回退：LivePortrait 伪活体循环(单图) ───────────────────────────
    try:
        fid = await _lipsync_ensure_face(SERVICES["lipsync"], face_bytes)
        if not fid:
            return
        ls = SERVICES.get("lipsync", "http://127.0.0.1:8090").rstrip("/")
        async with _aclient(timeout=180.0) as _cli:
            r = await _cli.get(f"{ls}/lipsync/idle_loop/{fid}")
            if r.status_code != 200 or not r.content:
                return  # 无多帧活体基底→vcam 自动回退呼吸/静态
            await _cli.post(f"{_VCAM_URL}/set_idle_loop",
                            files={"loop": ("idle.mp4", r.content, "video/mp4")})
        _logger.info("[VCam] 真·活体待机循环已就绪")
    except Exception as _e:
        _logger.debug(f"[VCam] idle_loop 跳过: {_e}")


async def _lipsync_stream_to_vcam(audio_bytes: bytes, face_bytes: bytes,
                                  *, fps: int = 25, seg_frames: int = 25,
                                  enhance: str = "") -> bool:
    """流式：让 MuseTalk 边生成边把无声小片段直推广播中枢，首帧≈首段(~1s)。
    整句音频挂第 0 段由中枢喂 WebRTC/OBS。返回是否成功(否则调用方回退整段路径)。
    enhance='gfpgan' → 流式 HD(同进程 GFPGAN bf16+GPU warp+整批增强)：生成18+批量增强~9
      ≈ 27ms/帧 < 40ms → 稳达 25fps 实时高清(实测 29ms/帧 SMOOTH);低延迟、画质更清晰。"""
    if enhance and _license is not None and not _license.allowed("hd"):
        # 授权软闸门：强制模式下无 HD 能力 → 降级标清直推（不报错、不中断对话）
        _logger.info("[License] 当前授权不含实时高清(HD) → 本句降级标清。升级 pro 解锁。")
        enhance = ""
    if enhance:
        fps = int(os.environ.get("HD_STREAM_FPS", "25"))
        seg_frames = fps
    try:
        async with _svc_lease("lipsync") as base:   # P-Conc5: 多卡时本句口型落到某张空闲 GPU 副本
            fid = await _lipsync_ensure_face(base, face_bytes) if face_bytes else ""
            data = {"fps": fps, "seg_frames": seg_frames,
                    "first_seg_frames": max(8, int(fps * 0.6)), "vcam_url": _VCAM_URL}
            if enhance:
                data["enhance"] = enhance
            files = {"audio": ("audio.wav", audio_bytes, "audio/wav")}
            if fid:
                data["face_id"] = fid
            else:
                files["face"] = ("face.jpg", face_bytes, "image/jpeg")
            async with _aclient(timeout=120.0) as _cli:
                r = await _cli.post(f"{base}/lipsync/generate_stream",
                                    files=files, data=data)
            return r.status_code == 200
    except Exception as _e:
        _logger.warning(f"[stream] 流式推流失败，回退整段: {_e}")
        return False


def _wav_duration_ms(wav_bytes: bytes) -> int:
    """从 WAV 头估算时长(ms)，失败返回 0(不影响主流程，仅用于 RTF 打点)。"""
    try:
        import wave as _wave, io as _io
        with _wave.open(_io.BytesIO(wav_bytes), "rb") as w:
            fr = w.getframerate() or 0
            nf = w.getnframes() or 0
            return int(nf / fr * 1000) if fr > 0 else 0
    except Exception:
        return 0


async def _ditto_stream_to_vcam(audio_bytes: bytes, face_bytes: bytes,
                                *, fps: int = 25, seg_frames: int = 25,
                                first_seg_frames: int = int(os.environ.get("DITTO_FIRST_SEG_FRAMES", "4")),
                                sampling_timesteps: int = 15,
                                stream_dit: bool = True) -> bool:
    """Ditto 流式：offline 逐窗 DiT(stream_dit)边渲染边把小段直推虚拟摄像头。
    长句(>~3.2s/多窗)首帧≈首窗 DiT(实测 −47%);短句单窗与整段等价。首段挂整句音频。
    扩散步数默认 15(实时路径,实测短句首段 ~1.1s,画质与 25 步视觉等价)。
    首段帧数默认 4(8097 A/B 实测 6→4 首段送达 −~75ms、长句 −10~18%;首段仍挂整句音频故无音画错位,
    渲染≈2×实时故无欠载;DITTO_FIRST_SEG_FRAMES 可调,想更激进可试 3)。观众感知首帧≈seg0 送达。
    返回是否成功(否则调用方回退整段)。"""
    base = SERVICES.get("ditto", "http://127.0.0.1:8096").rstrip("/")
    try:
        data = {"vcam_url": _VCAM_URL, "fps": fps, "seg_frames": seg_frames,
                "first_seg_frames": first_seg_frames,
                "sampling_timesteps": sampling_timesteps,
                "stream_dit": str(bool(stream_dit)).lower()}
        # 打点取证：音频时长→渲染耗时→RTF，确认走的是 Ditto 增强链(而非 2D 回退)
        _t0 = time.time()
        _aud_ms = _wav_duration_ms(audio_bytes)
        async with _aclient(timeout=120.0) as _cli:
            r = await _cli.post(
                f"{base}/ditto/generate_stream",
                files={"audio": ("audio.wav", audio_bytes, "audio/wav"),
                       "face":  ("face.jpg",  face_bytes,  "image/jpeg")},
                data=data)
        _ok = r.status_code == 200
        if _ok:
            _cost_ms = int((time.time() - _t0) * 1000)
            _rtf = (_cost_ms / _aud_ms) if _aud_ms > 0 else 0.0
            _ff_ms = _seg0_ms = None                       # 服务端回报的首帧渲染 / 首段送达耗时(A-1 首帧可观测)
            try:
                _j = r.json(); _ff_ms = _j.get("first_frame_ms"); _seg0_ms = _j.get("seg0_ms")
            except Exception:
                pass
            _logger.info(f"[Ditto/stream] 增强链 OK audio={_aud_ms}ms cost={_cost_ms}ms "
                         f"rtf={_rtf:.2f} first_frame={_ff_ms}ms seg0={_seg0_ms}ms (sharpen+blink+head+brow active)")
            try:
                _metrics["ditto_stream_cost_ms"].append(_cost_ms)
                _metrics["ditto_stream_rtf"].append(round(_rtf, 3))
                if _seg0_ms is not None:
                    _metrics["ditto_first_frame_ms"].append(_seg0_ms)   # 观众感知首帧≈首段送达 vcam
            except Exception:
                pass
        return _ok
    except Exception as _e:
        _logger.warning(f"[Ditto/stream] 流式推流失败，回退整段: {_e}")
        return False


# ── 路由：核心 — 声脸联动 ─────────────────────────────────────────
@app.post("/avatar/speak", response_model=SpeakResponse)
async def avatar_speak(req: SpeakRequest, request: Request):
    global _active_profile
    t0 = time.time()

    # P12-A2: 显式传入的 profile 名须通过白名单（_active_profile 写入时已校验）
    if req.profile:
        _check_profile_name(req.profile)

    # P10-1: 文本长度前置检查，超长请求在排队前就拒绝
    if len(req.text) > _TEXT_LIMIT:
        raise HTTPException(400, f"text 超过 {_TEXT_LIMIT} 字符限制，请分段发送")

    # P10-2: 锁内快照 profile，防 import_profiles 批量替换竞态（锁仅微秒级）
    async with _PROFILES_LOCK:
        profile_name = req.profile or _active_profile
        profile = dict(_profiles.get(profile_name, {}))
    voice_name = profile.get("voice_name", "")
    voice_b64  = profile.get("voice_b64", "")
    face_b64   = profile.get("face_b64", "")

    # ── Phase5: 解析并校验引擎选择（请求覆盖 > 角色配置 > 默认）────────
    sel_tts_engine = req.tts_engine or profile.get("tts_engine", "") or _default_engine("tts")
    sel_vc_engine  = req.vc_engine  or profile.get("vc_engine", "")  or _default_engine("vc")
    if _engine_registry is not None:
        if req.tts_engine and not _engine_registry.exists(req.tts_engine):
            raise HTTPException(400, {"error": f"未知 TTS 引擎: {req.tts_engine}",
                                      "available": _engine_registry.names("tts")})
        if req.vc_engine and not _engine_registry.exists(req.vc_engine):
            raise HTTPException(400, {"error": f"未知变声引擎: {req.vc_engine}",
                                      "available": _engine_registry.names("vc")})

    # P7-3: 并发限流，10s内无法获取信号量则返回503
    try:
        await asyncio.wait_for(_SPEAK_SEM.acquire(), timeout=10.0)
    except asyncio.TimeoutError:
        raise HTTPException(503, "服务繁忙，请稍后重试（并发超限）")

    audio_b64 = ""
    face_image = ""
    # ── Phase 4: auto 情感自动检测 ────────────────────────────────────
    _detected_emotion = None
    if req.emotion == "auto":
        try:
            from emotion_detector import detect_emotion as _det
            _detected_emotion = _det(req.text)
            req = req.model_copy(update={"emotion": _detected_emotion})
            _logger.info(f"[AutoEmotion] '{req.text[:30]}' -> {_detected_emotion}")
        except Exception as _e:
            _logger.warning(f"[AutoEmotion] 检测失败，降级neutral: {_e}")
            req = req.model_copy(update={"emotion": "neutral"})
    # ── TTS 引擎路由 ─────────────────────────────────────────────────
    # tts_engine 优先级: req.tts_engine > 角色配置 > 默认
    _sel_tts_eng = req.tts_engine or profile.get("tts_engine", "")
    _fish_svc    = _fish_compat_svc(_sel_tts_eng)   # fish/qwen3_tts… → 服务键；非兼容→""
    _use_fish_tts   = bool(_fish_svc)
    _use_emotion_tts = (not _use_fish_tts) and (
        (req.emotion and req.emotion != "neutral") or bool(req.instruct))
    if _use_emotion_tts and req.emotion not in VALID_EMOTIONS:
        _SPEAK_SEM.release()
        raise HTTPException(400, f"不支持的情感: {req.emotion}，可选: {sorted(VALID_EMOTIONS)}")
    t_tts0 = time.time()  # Phase5: TTS 阶段计时起点
    try:
        # Fish-Speech S2（最高质量零样本克隆，端口 7855）
        if _use_fish_tts:
            async def _call_fish_tts():
                # 读取角色预设中的 fish_tts_params（temperature/top_p 等）
                _ftp = profile.get("fish_tts_params") or {}
                payload = {"text": req.text, "language": req.language or "zh",
                           "return_base64": True}
                if req.instruct:
                    payload["instruct"] = req.instruct
                    ep = f"{SERVICES[_fish_svc]}/v1/tts/instruct"
                elif voice_b64:
                    ep = f"{SERVICES[_fish_svc]}/v1/tts/clone"
                    payload["reference_audio_b64"] = voice_b64
                    # reference_text 优先从 fish_tts_params 读取，未配置则空字符串
                    payload["reference_text"] = _ftp.get("reference_text", "") if _ftp else ""
                    # 透传调优参数（如角色未配置则使用 server 默认值）
                    if _ftp:
                        payload.update({
                            k: _ftp[k] for k in
                            ("temperature", "top_p", "repetition_penalty",
                             "chunk_length", "seed")
                            if k in _ftp
                        })
                else:
                    ep = f"{SERVICES[_fish_svc]}/v1/tts"
                return await http_pool.post(ep, json=payload, timeout=90)
            tts_coro = _call_fish_tts()
        # 情感模式：调用 emotion_tts_server (7852)
        elif _use_emotion_tts:
            async def _call_emotion_tts():
                payload = {
                    "text": req.text,
                    "emotion": req.emotion or "neutral",
                    "speed": 1.0,
                    "return_base64": True,
                }
                if req.instruct:
                    payload["instruct"] = req.instruct
                    ep = f"{SERVICES['emotion_tts']}/v1/tts/instruct"
                elif voice_b64:
                    # 克隆音色 + 情感
                    ep = f"{SERVICES['emotion_tts']}/v1/tts/clone"
                    payload["reference_audio_b64"] = voice_b64
                else:
                    ep = f"{SERVICES['emotion_tts']}/v1/tts"
                return await http_pool.post(ep, json=payload, timeout=60)
            tts_coro = _call_emotion_tts()
        else:
            # P10-3: 通过 _call_tts() 调用（含1次连接级重试）
            tts_coro = _call_tts(voice_b64, voice_name, req.text, req.language)

        if req.include_face and face_b64:
            tts_r, snap_b64 = await asyncio.gather(
                tts_coro, _get_snapshot_b64(), return_exceptions=True)
            if snap_b64 and not isinstance(snap_b64, Exception):
                try:
                    _, _fs_svc, _fs_smooth = _faceswap_resolve(profile=profile)
                    _fs_body = {"source_image": face_b64, "target_image": snap_b64}
                    if _fs_smooth:
                        _fs_body["smooth_mode"] = _fs_smooth
                    fs_r = await http_pool.post(f"{SERVICES[_fs_svc]}/faceswap",
                        json=_fs_body, timeout=30)
                    if fs_r.status_code == 200:
                        face_image = fs_r.json().get("result_b64", "")
                except Exception:
                    pass
        else:
            tts_r = await tts_coro

        if isinstance(tts_r, Exception):
            raise HTTPException(500, f"TTS 失败: {tts_r}")
        if _use_fish_tts or _use_emotion_tts:
            # fish_speech_server / emotion_tts_server 统一返回 JSON {"audio_base64":...}
            if tts_r.status_code == 200:
                audio_b64 = tts_r.json().get("audio_base64", "")
            else:
                err_detail = tts_r.text[:120] if hasattr(tts_r, 'text') else str(tts_r)
                _eng_name = (_sel_tts_eng or "FishTTS") if _use_fish_tts else "情感TTS"
                raise HTTPException(500, f"{_eng_name} HTTP {tts_r.status_code}: {err_detail}")
        elif voice_b64:
            if tts_r.status_code == 200:
                audio_b64 = tts_r.json().get("audio_base64", "")
            else:
                raise HTTPException(500, f"TTS clone HTTP {tts_r.status_code}")
        else:
            if tts_r.status_code == 200:
                audio_b64 = base64.b64encode(tts_r.content).decode()
            else:
                raise HTTPException(500, f"TTS HTTP {tts_r.status_code}: {tts_r.text[:120]}")
    except HTTPException:
        _metrics["tts_error"] += 1  # P9-4
        _SPEAK_SEM.release()  # P7-3: TTS异常退出释放
        raise
    except Exception as e:
        _metrics["tts_error"] += 1  # P9-4
        _SPEAK_SEM.release()  # P7-3
        raise HTTPException(500, f"TTS 失败: {e}")

    # Phase5: 记录 TTS 引擎延迟（情感模式归 cosyvoice，否则归选定 TTS 引擎）
    if _engine_registry is not None:
        _tts_ms = int((time.time() - t_tts0) * 1000)
        _tts_eng = (_sel_tts_eng if _use_fish_tts else
                    "cosyvoice" if _use_emotion_tts else sel_tts_engine)
        try:
            _engine_registry.record_latency(_tts_eng, _tts_ms)
        except Exception:
            pass

    # ── RVC 音色转换（若角色绑定了 rvc_model）─────────────────────
    rvc_model      = profile.get("rvc_model", "")
    rvc_settings   = profile.get("rvc_settings", {})
    strict_mode    = profile.get("rvc_strict_mode", True)
    rvc_applied    = False
    speak_warning  = ""
    rvc_ms         = 0  # P13-C2: RVC耗时，用于SlowSpeak日志定位瓶颈
    if rvc_model and audio_b64:
        t_rvc = time.time()
        try:
            # Phase6-1: 经 VC 适配器分发（rvc 走 RvcAdapter→_call_rvc，行为不变；
            # 未来 vc_engine=seedvc 等只需 attach 一个 VCAdapter 即可路由）
            rvc_r = await _vc_dispatch(sel_vc_engine, audio_b64, rvc_model, rvc_settings)
            rvc_ms = int((time.time() - t_rvc) * 1000)
            if rvc_r.status_code == 200:
                audio_b64   = rvc_r.audio_b64 or audio_b64
                rvc_applied = True
                if _engine_registry is not None:  # Phase5: 记录变声引擎延迟
                    try:
                        _engine_registry.record_latency(sel_vc_engine, rvc_ms)
                    except Exception:
                        pass
            else:
                err = f"RVC HTTP {rvc_r.status_code}"
                if strict_mode:
                    raise HTTPException(503, f"RVC 转换失败: {err}")
                speak_warning = f"⚠️ RVC未应用({err})，播放原始TTS音频"
        except HTTPException:
            _metrics["rvc_error"] += 1  # P9-4
            _SPEAK_SEM.release()  # P7-3
            raise
        except Exception as e:
            err = str(e)
            if strict_mode:
                _metrics["rvc_error"] += 1  # P9-4
                _SPEAK_SEM.release()  # P7-3
                raise HTTPException(503, f"RVC 服务不可达: {err}")
            speak_warning = f"⚠️ RVC未应用(服务不可达)，播放原始TTS音频"
            _logger.warning(f"[Hub] RVC 跳过: {err}")

    # ── LipSync 口型同步（若请求且角色有人脸）─────────────────────
    lipsync_video_b64 = ""
    if req.generate_lipsync and audio_b64 and face_b64:
        try:
            # Phase8: 经口型适配器分发（musetalk 走 MuseTalkAdapter→内置调用，行为不变）
            sel_ls_engine = _lipsync_resolve(req.lipsync_engine, profile, allow_hd_default=True)
            t_ls = time.time()
            ls_r = await _lipsync_dispatch(sel_ls_engine,
                                           base64.b64decode(audio_b64),
                                           base64.b64decode(face_b64))
            if ls_r.status_code == 200:
                _vb = _maybe_embed_video_c2pa(ls_r.video_bytes,
                                              model=sel_ls_engine, profile=profile_name)
                lipsync_video_b64 = base64.b64encode(_vb).decode()
                _logger.info(f"[LipSync] OK {len(ls_r.video_bytes)//1024}KB")
                if _engine_registry is not None:
                    try: _engine_registry.record_latency(sel_ls_engine,
                                                          int((time.time()-t_ls)*1000))
                    except Exception: pass
            else:
                _logger.warning(f"[LipSync] HTTP {ls_r.status_code}")
        except Exception as _le:
            _logger.warning(f"[LipSync] 跳过: {_le}")

    elapsed = int((time.time() - t0) * 1000)
    # P11-C1 + P12-C1 + P13-C2: 慢请求告警，rvc_ms用于定位TTS慢还是RVC慢
    if elapsed > 5000:
        _metrics["speak_slow_total"] += 1
        _logger.warning(f"[SlowSpeak] profile={profile_name} text={req.text[:20]!r} elapsed={elapsed}ms rvc_ms={rvc_ms}ms")

    # 隐身模式：Body字段 OR Header X-Incognito: true
    incognito = req.incognito or (
        request.headers.get("X-Incognito", "false").lower() == "true")

    # 指标收集
    _metrics["speak_total"] += 1
    if rvc_applied:  _metrics["speak_rvc_applied"] += 1
    if speak_warning: _metrics["speak_rvc_failed"] += 1
    _metrics["speak_latency_ms"].append(elapsed)  # P4-B: deque 自动滚动
    _b = _metrics["latency_buckets"]              # P5-5: 分桶计数
    _b[0 if elapsed < 500 else 1 if elapsed < 1000 else 2 if elapsed < 3000 else 3] += 1
    _track_event("huansheng", "huansheng.tts.chars_metered", {   # P4：任务级用量（单次合成请求聚合，非逐句）
        "chars": len(req.text), "voice_id": profile_name, "lang": req.language,
        "engine": (_sel_tts_eng if _use_fish_tts else
                   "cosyvoice" if _use_emotion_tts else sel_tts_engine)})

    # 异步写历史（非隐身模式）+ 完成后广播 history_updated
    _used_emotion = _detected_emotion or req.emotion
    _incognito = req.incognito
    async def _write_and_broadcast():
        await asyncio.get_running_loop().run_in_executor(
            _history_executor, _write_history,
            profile_name, req.text, req.language,
            audio_b64, elapsed, rvc_applied, _incognito, _used_emotion
        )
        if not _incognito:
            await broadcast({"event": "history_updated"})
    asyncio.create_task(_write_and_broadcast())
    _SPEAK_SEM.release()  # P7-3: 正常路径释放

    # ── Phase11: 输出内容凭证 + 不可见水印（合规默认开启，安全降级）──
    out_audio_b64 = audio_b64
    _wm_enabled = PROVENANCE_ENABLED if req.watermark is None else req.watermark
    if _wm_enabled and _provenance is not None and audio_b64:
        try:
            _raw = base64.b64decode(audio_b64)
            _res = _provenance.attach_credentials(
                _raw, model=(_sel_tts_eng if _use_fish_tts else
                             "cosyvoice" if _use_emotion_tts else sel_tts_engine),
                profile=profile_name, ai_generated=True,
                extra={"rvc_applied": rvc_applied, "vc_engine": sel_vc_engine})
            if _res.get("ok"):
                out_audio_b64 = base64.b64encode(_res["audio_bytes"]).decode()
        except Exception as _we:
            _logger.warning(f"[Provenance] 水印跳过: {_we}")

    return SpeakResponse(
        audio_base64=out_audio_b64, face_image=face_image,
        elapsed_ms=elapsed, rvc_applied=rvc_applied, warning=speak_warning,
        lipsync_video_b64=lipsync_video_b64,
        detected_emotion=_detected_emotion or ""
    )


@app.post("/avatar/speak/stream")
async def avatar_speak_stream(req: SpeakRequest, request: Request):
    """SSE 单句合成进度流：queued→tts_start→tts_done→[rvc_start→rvc_done]→done
    前端监听各阶段实时更新进度条，最终事件携带 audio_base64。"""

    def _sse(data: dict) -> str:
        return f"data: {json.dumps(data, ensure_ascii=False)}\n\n"

    async def _gen():
        # ── 前置校验 ──
        if req.profile:
            try: _check_profile_name(req.profile)
            except HTTPException as e:
                yield _sse({"phase": "error", "message": e.detail}); return
        if len(req.text) > _TEXT_LIMIT:
            yield _sse({"phase": "error", "message": f"text 超过 {_TEXT_LIMIT} 字符限制"}); return

        yield _sse({"phase": "queued"})

        async with _PROFILES_LOCK:
            profile_name = req.profile or _active_profile
            profile = dict(_profiles.get(profile_name, {}))
        voice_name = profile.get("voice_name", "")
        voice_b64  = profile.get("voice_b64",  "")
        face_b64   = profile.get("face_b64",   "")   # P10-4: lipsync 需要

        # 获取信号量（10s 超时）
        try:
            await asyncio.wait_for(_SPEAK_SEM.acquire(), timeout=10.0)
        except asyncio.TimeoutError:
            yield _sse({"phase": "error", "message": "服务繁忙，请稍后重试"}); return

        t0 = time.time()
        audio_b64 = ""; rvc_applied = False; speak_warning = ""
        elapsed_tts_ms = 0; elapsed_rvc_ms = 0
        lipsync_video_b64 = ""  # P10-4

        try:
            # ── TTS ──────────────────────────────────────────────────
            yield _sse({"phase": "tts_start"})
            t_tts = time.time()

            emotion = req.emotion
            detected_emotion = None
            if emotion == "auto":
                _metrics["speak_emotion_auto"] += 1   # UI-P0: auto 使用率（决策①数据）
                try:
                    from emotion_detector import detect_emotion as _det
                    detected_emotion = _det(req.text); emotion = detected_emotion
                except Exception:
                    emotion = "neutral"

            _use_emotion = (emotion and emotion != "neutral") or bool(req.instruct)
            try:
                if _use_emotion:
                    ep_payload = {"text": req.text, "emotion": emotion or "neutral",
                                  "speed": 1.0, "return_base64": True}
                    if req.instruct:
                        ep_payload["instruct"] = req.instruct
                        ep = f"{SERVICES['emotion_tts']}/v1/tts/instruct"
                    elif voice_b64:
                        ep = f"{SERVICES['emotion_tts']}/v1/tts/clone"
                        ep_payload["reference_audio_b64"] = voice_b64
                    else:
                        ep = f"{SERVICES['emotion_tts']}/v1/tts"
                    tts_r = await http_pool.post(ep, json=ep_payload, timeout=60)
                    if tts_r.status_code == 200:
                        audio_b64 = tts_r.json().get("audio_base64", "")
                    else:
                        raise Exception(f"情感TTS HTTP {tts_r.status_code}: {tts_r.text[:80]}")
                else:
                    tts_r = await _call_tts(voice_b64, voice_name, req.text, req.language)
                    if tts_r.status_code == 200:
                        audio_b64 = (tts_r.json().get("audio_base64", "") if voice_b64
                                     else base64.b64encode(tts_r.content).decode())
                    else:
                        raise Exception(f"TTS HTTP {tts_r.status_code}")
            except Exception as e:
                _metrics["tts_error"] += 1
                yield _sse({"phase": "error", "message": f"TTS 失败: {e}"}); return

            elapsed_tts_ms = int((time.time() - t_tts) * 1000)
            yield _sse({"phase": "tts_done", "elapsed_tts_ms": elapsed_tts_ms})

            # ── RVC (可选) ────────────────────────────────────────────
            rvc_model    = profile.get("rvc_model",    "")
            rvc_settings = profile.get("rvc_settings", {})
            strict_mode  = profile.get("rvc_strict_mode", True)
            # Phase6-6: 变声引擎解析（req 覆盖 > 角色配置 > 默认 rvc）
            sel_vc_engine = req.vc_engine or profile.get("vc_engine", "") or _default_engine("vc")

            if rvc_model and audio_b64:
                yield _sse({"phase": "rvc_start"})
                t_rvc = time.time()
                try:
                    rvc_r = await _vc_dispatch(sel_vc_engine, audio_b64, rvc_model, rvc_settings)
                    if rvc_r.status_code == 200:
                        audio_b64 = rvc_r.audio_b64 or audio_b64
                        rvc_applied = True
                    else:
                        err = f"HTTP {rvc_r.status_code}"
                        if strict_mode:
                            yield _sse({"phase": "error", "message": f"RVC 失败: {err}"}); return
                        speak_warning = f"⚠️ RVC未应用({err})"
                except Exception as e:
                    if strict_mode:
                        yield _sse({"phase": "error", "message": f"RVC 服务不可达: {e}"}); return
                    speak_warning = f"⚠️ RVC未应用(服务不可达)"
                elapsed_rvc_ms = int((time.time() - t_rvc) * 1000)
                if _engine_registry is not None and rvc_applied:
                    try: _engine_registry.record_latency(sel_vc_engine, elapsed_rvc_ms)
                    except Exception: pass
                yield _sse({"phase": "rvc_done",
                            "elapsed_rvc_ms": elapsed_rvc_ms, "rvc_applied": rvc_applied})

            # ── LipSync（可选）────────────────────────────────────────
            if req.generate_lipsync and audio_b64 and face_b64:
                yield _sse({"phase": "lipsync_start"})
                t_ls = time.time()
                try:
                    # Phase8: 经口型适配器分发（引擎: req 覆盖 > 角色配置 > 默认）
                    sel_ls_engine = _lipsync_resolve(req.lipsync_engine, profile, allow_hd_default=True)
                    ls_r = await _lipsync_dispatch(sel_ls_engine,
                                                   base64.b64decode(audio_b64),
                                                   base64.b64decode(face_b64))
                    if ls_r.status_code == 200:
                        _vb2 = _maybe_embed_video_c2pa(ls_r.video_bytes,
                                                       model=sel_ls_engine, profile=profile_name)
                        lipsync_video_b64 = base64.b64encode(_vb2).decode()
                        _logger.info(f"[LipSync/stream] OK {len(ls_r.video_bytes)//1024}KB")
                        if _engine_registry is not None:
                            try: _engine_registry.record_latency(
                                sel_ls_engine, int((time.time()-t_ls)*1000))
                            except Exception: pass
                    else:
                        _logger.warning(f"[LipSync/stream] HTTP {ls_r.status_code}")
                except Exception as _le:
                    _logger.warning(f"[LipSync/stream] 跳过: {_le}")
                elapsed_ls_ms = int((time.time() - t_ls) * 1000)
                yield _sse({"phase": "lipsync_done", "elapsed_lipsync_ms": elapsed_ls_ms})

            # ── 收尾 ─────────────────────────────────────────────────
            elapsed = int((time.time() - t0) * 1000)
            _metrics["speak_total"] += 1
            if rvc_applied:    _metrics["speak_rvc_applied"] += 1
            if speak_warning:  _metrics["speak_rvc_failed"]  += 1
            _metrics["speak_latency_ms"].append(elapsed)
            _b = _metrics["latency_buckets"]
            _b[0 if elapsed < 500 else 1 if elapsed < 1000 else 2 if elapsed < 3000 else 3] += 1
            if elapsed > 5000:
                _metrics["speak_slow_total"] += 1
                _logger.warning(f"[SlowSpeak/stream] profile={profile_name} text={req.text[:20]!r} "
                                f"elapsed={elapsed}ms rvc_ms={elapsed_rvc_ms}ms")

            _incognito = req.incognito or (
                request.headers.get("X-Incognito", "false").lower() == "true")
            _emo_final = detected_emotion or emotion or "neutral"

            # UI-P0: 历史写入照旧与响应流解耦（executor 线程一经启动必然写完，
            # 客户端断开也不丢历史；广播挂在 done_callback 上同样不依赖本生成器存活）。
            # 新增的只是：done 之后 shield 等待拿到 history_id，补发 saved 事件供「⭐ 收藏」。
            _hist_fut = asyncio.get_running_loop().run_in_executor(
                _history_executor, _write_history,
                profile_name, req.text, req.language,
                audio_b64, elapsed, rvc_applied, _incognito, _emo_final)
            if not _incognito:
                def _hist_done_cb(_fut):
                    try: asyncio.ensure_future(broadcast({"event": "history_updated"}))
                    except Exception: pass
                _hist_fut.add_done_callback(_hist_done_cb)

            # Phase11: 流式输出同样打内容凭证+水印（与 /avatar/speak 一致，合规）
            out_audio_b64 = audio_b64
            _wm_on = PROVENANCE_ENABLED if req.watermark is None else req.watermark
            if _wm_on and _provenance is not None and audio_b64:
                try:
                    _r = _provenance.attach_credentials(
                        base64.b64decode(audio_b64),
                        model=("cosyvoice" if _use_emotion else "xtts"),
                        profile=profile_name, ai_generated=True,
                        extra={"rvc_applied": rvc_applied, "stream": True})
                    if _r.get("ok"):
                        out_audio_b64 = base64.b64encode(_r["audio_bytes"]).decode()
                except Exception as _we:
                    _logger.warning(f"[Provenance/stream] 水印跳过: {_we}")

            yield _sse({"phase": "done", "audio_base64": out_audio_b64,
                        "elapsed_ms": elapsed, "elapsed_tts_ms": elapsed_tts_ms,
                        "elapsed_rvc_ms": elapsed_rvc_ms, "rvc_applied": rvc_applied,
                        "lipsync_video_b64": lipsync_video_b64,
                        "warning": speak_warning, "detected_emotion": detected_emotion or "",
                        # UI-P0: 前端据此显示「情感引擎/克隆引擎」路由，拆掉换情感音色变化的不透明感
                        "tts_route": "emotion" if _use_emotion else "clone"})

            # UI-P0: done 先发（音频立即可播）→ 历史落库回执 saved 携带 history_id。
            # shield：即便客户端提前断开导致本生成器被取消，写库任务也不受影响。
            try:
                hist_id = await asyncio.shield(_hist_fut)
            except asyncio.CancelledError:
                raise           # 客户端已断开：如实退出（executor 内写库不受影响）
            except Exception:
                hist_id = None
            if hist_id is not None and not _incognito:
                yield _sse({"phase": "saved", "history_id": hist_id})
        finally:
            _SPEAK_SEM.release()

    return StreamingResponse(
        _gen(), media_type="text/event-stream",
        headers={"X-Accel-Buffering": "no", "Cache-Control": "no-cache"})


# ── 批量配音 ──────────────────────────────────────────────────────
# 全局信号量：最多允许 2 个批量任务并发，防止 TTS 服务过载
_BATCH_SEMAPHORE = asyncio.Semaphore(2)
# P7-3: 单次 speak 并发限流（最多3路，防止GPU过载）
_SPEAK_SEM = asyncio.Semaphore(3)
# P12-2: stream_sse 每句 RVC 并发上限（多用户同时流式时不打爆 RVC）
_STREAM_RVC_SEM = asyncio.Semaphore(2)
# P22-1: /tts/stream_sse 首句是否走 fish 服务端子块流式（抢首块压 TTFA）；
#   出问题可置 0 退回整句路径（自带优雅兜底，默认开）。
_STREAM_SSE_FISH_SUBCHUNK = os.environ.get("STREAM_SSE_FISH_SUBCHUNK", "1") == "1"
# P22-1: 流式首句的 chunk_length（字节，0=不覆盖，默认关）。实测把首句按字节切小并不能
#   降 TTFA：fish 每次生成的瓶颈是首块 prefill/首 token 解码(0.4~1.2s 抖动，主要由参考 token
#   主导，与文本块长度近乎无关)，切小块反而增加段数、引入尾部离群。故默认 0；保留开关仅供
#   长首句(>chunk_length)场景调参。fish 端 _run_tts_stream 下限已放开到 20B(本值=0 时不触发)。
_STREAM_SSE_FISH_CHUNK_LEN = int(os.environ.get("STREAM_SSE_FISH_CHUNK_LEN", "0"))
# P22-1: 流式首块合并阈值(ms)——比对话档(300)更小，已生成的 PCM 更早转发→压 TTFA 尾分位。
#   只影响"何时转发"，不改 fish 生成质量。0=沿用对话纯音频档。
_STREAM_SSE_COALESCE_FIRST_MS = int(os.environ.get("STREAM_SSE_COALESCE_FIRST_MS", "180"))
# Phase7 流式首音「低延迟首块」灰度默认：把过长首句在标点处切出更短首块直接降 TTFA。
#   _split_first_for_ttfa 无合适切点时原样返回(绝不劣化、不静音)，故默认开(=灰度全量)；
#   单次请求传 low_latency:false 可覆盖、STREAM_SSE_LOW_LATENCY_DEFAULT=0 可一键全局关回旧行为。
_STREAM_SSE_LOW_LATENCY_DEFAULT = os.environ.get("STREAM_SSE_LOW_LATENCY_DEFAULT", "1") == "1"

# ── 对话会话准入/容量层 (P-Conc1) ──────────────────────────────────────
# 自托管单机的实时对话是 GPU 受限、本质串行：一张卡只能从容服务少量并发实时会话
# （实测 N=2 时第二路首音 882ms→4329ms，整轮串行翻倍）。准入层=显式容量契约：
# 放行 ≤ CONV_MAX_CONCURRENT 路实时会话，其余进入【公平队列】，期间向客户端推送
# `queue` 事件（位次 + 预计等待），而非静默把请求全堆到同一张卡上无界劣化。
# 默认 0=关闭（行为与改造前 100% 一致，零回归）；设为 N>0 即启用容量契约；多卡时调高。
# 设为 "auto" → 池感知：启动后按最小多卡池规模(=能真并行的卡数)自动定 K，加卡只需改 SVC_* 不必再调这里。
def _parse_cmc(raw: str) -> int:
    raw = (raw or "0").strip().lower()
    if raw == "auto":
        return -1                      # 哨兵：启动时据池规模解析
    try:
        return max(0, int(raw))
    except ValueError:
        return 0
CONV_MAX_CONCURRENT = _parse_cmc(os.environ.get("CONV_MAX_CONCURRENT", "0"))   # -1=auto, 0=关, N=固定
# 队列深度上限：0=不限；>0 时排队数超过该值的新会话直接优雅拒绝(busy)，
# 避免突发（如直播弹幕）把队列堆到天荒地老、ETA 失真。
CONV_MAX_QUEUE = max(0, int(os.environ.get("CONV_MAX_QUEUE", "0")))
# 非流式 /api/converse 的最长排队等待秒数；超时返回 429（流式走 SSE 队列、不受此限）。
CONV_WAIT_TIMEOUT = max(1.0, float(os.environ.get("CONV_WAIT_TIMEOUT", "30")))
_conv_recent_turn_ms = deque(maxlen=20)       # 近期整轮耗时 → 排队 ETA 估计
_QUEUE_PING_SEC = max(1.0, float(os.environ.get("CONV_QUEUE_PING_SEC", "2.0")))


class _ConvAdmission:
    """P-Conc2: 优先级感知的会话准入。容量满载时按 (优先级高→先到) 出队，
    主播控场指令(priority 高)插到观众弹幕前面。槽位经 future 交接，取消(排队中
    客户端断开)不泄漏槽位。单线程 asyncio 下所有状态变更不跨 await，无需锁。"""

    def __init__(self, capacity: int):
        self.capacity = max(1, capacity)
        self.active = 0
        self._heap: list = []      # [neg_priority, seq, future|None]
        self._seq = 0

    def set_capacity(self, n: int):
        """运行时调整容量（池感知自动定 K / 未来按健康卡数伸缩）。增大→立即唤醒等待者填满
        新槽位；减小→不动在途(自然耗尽)，仅约束后续 try_acquire。单线程内同步执行、无锁。"""
        n = max(1, int(n))
        grew = n > self.capacity
        self.capacity = n
        if grew:
            while self.active < self.capacity:
                before = self.active
                self._wake_next()
                if self.active == before:    # 无可唤醒者
                    break

    @property
    def waiting(self) -> int:
        return sum(1 for it in self._heap if it[2] is not None and not it[2].done())

    def try_acquire(self) -> bool:
        if self.active < self.capacity:
            self.active += 1
            return True
        return False

    def enqueue(self, priority: int) -> list:
        fut = asyncio.get_event_loop().create_future()
        self._seq += 1
        item = [-int(priority), self._seq, fut]   # 小根堆：负优先级→高优先在前；seq→同级 FIFO
        heapq.heappush(self._heap, item)
        return item

    def position(self, item: list) -> int:
        """该 item 在存活等待者中的名次(1=下一个被服务)。"""
        key = (item[0], item[1])
        rank = 1
        for it in self._heap:
            if it is item or it[2] is None or it[2].done():
                continue
            if (it[0], it[1]) < key:
                rank += 1
        return rank

    def _wake_next(self):
        while self._heap:
            it = heapq.heappop(self._heap)
            fut = it[2]
            if fut is None or fut.done():
                continue
            self.active += 1
            fut.set_result(True)
            return

    def release(self):
        if self.active > 0:
            self.active -= 1
        self._wake_next()

    def abandon(self, item: list):
        """排队中放弃(断开/出错)。若槽位已交接给本 item 则归还并唤醒下一个。"""
        fut = item[2]
        item[2] = None      # tombstone：_wake_next/position 会跳过
        if fut is not None and fut.done() and not fut.cancelled():
            if self.active > 0:
                self.active -= 1
            self._wake_next()


# auto(-1) 先以占位容量 1 建好；lifespan 内 _conv_init_pool_aware_admission 再据池规模定 K。
_conv_admission = _ConvAdmission(max(1, CONV_MAX_CONCURRENT)) if CONV_MAX_CONCURRENT != 0 else None


async def _conv_init_pool_aware_admission():
    """池感知准入：预建重型 GPU 池→多卡副本数即时可知；auto 模式据此定 K。
    必须从 lifespan 调用——本 app 用 lifespan 启动，@app.on_event('startup') 会被 Starlette 忽略。"""
    for _s in ("fish_tts", "emotion_tts", "lipsync"):
        try:
            _svc_pool(_s)                      # 预建池(从 SVC_* 解析副本)，幂等
        except Exception:
            pass
    if _conv_admission is not None and CONV_MAX_CONCURRENT == -1:
        cap = max(1, _recommended_concurrency_live())
        _conv_admission.set_capacity(cap)
        _logger.info(f"[Hub] 池感知准入：自动并发 K={cap}（=最小多卡池规模；单卡回退 1）")
    # 授权软闸门：强制模式下，并发会话数不超过授权档位 max_sessions（不报错，仅收敛容量）
    if _conv_admission is not None and _license is not None and _license.enforcing():
        _lic_max = _license.limit("max_sessions", _conv_admission.capacity)
        try:
            _lic_max = int(_lic_max)
        except Exception:
            _lic_max = _conv_admission.capacity
        if _lic_max >= 1 and _lic_max < _conv_admission.capacity:
            _conv_admission.set_capacity(_lic_max)
            _logger.info(f"[License] 授权档位限并发 K={_lic_max}（升级档位可提升）")
    # 多卡才需探活：单副本摘了也无处可去。启动后台健康循环，K 随健康卡数伸缩。
    global _svc_probe_task
    if _SVC_PROBE_SEC > 0 and _svc_probe_task is None and any(p.size > 1 for p in _svc_pools.values()):
        _svc_probe_task = asyncio.create_task(_svc_health_loop())
        _logger.info(f"[Hub] 多卡副本主动探活已启用（每 {int(_SVC_PROBE_SEC)}s，K 自适应）")


def _conv_eta_ms(position: int) -> int:
    """排队 ETA 粗估：位次 × 近期平均整轮耗时 / 并发度。空样本回退 8s。"""
    if not _conv_recent_turn_ms:
        avg = 8000.0
    else:
        avg = sum(_conv_recent_turn_ms) / len(_conv_recent_turn_ms)
    k = _conv_admission.capacity if _conv_admission else max(1, CONV_MAX_CONCURRENT)
    return int(avg * position / max(1, k))


def _conv_capacity_snapshot() -> dict:
    adm = _conv_admission
    return {"enabled": adm is not None,
            "max": (adm.capacity if adm else 0),
            "auto": CONV_MAX_CONCURRENT == -1,
            "max_queue": CONV_MAX_QUEUE,
            "active": adm.active if adm else 0,
            "waiting": adm.waiting if adm else 0,
            "avg_turn_ms": (int(sum(_conv_recent_turn_ms) / len(_conv_recent_turn_ms))
                            if _conv_recent_turn_ms else None),
            "gpu_pools": _svc_pools_snapshot(),      # P-Conc5: 多卡副本在途/摘除状态
            "streaming_tts": _streaming_tts_snapshot()}


async def _conv_admit_wait(priority: int = 0, max_wait: float | None = None) -> bool:
    """非流式准入（不能推 SSE，故阻塞式有界等待）。
    返回 True=可继续（若启用则已占槽，调用方负责 _conv_admission.release()）；
    返回 False=应拒绝（429/503）：队列已满或等待超时。准入未启用时恒 True（行为同改造前）。"""
    adm = _conv_admission
    if adm is None:
        return True
    if adm.try_acquire():
        return True
    if CONV_MAX_QUEUE > 0 and adm.waiting >= CONV_MAX_QUEUE:
        return False
    item = adm.enqueue(priority)
    fut = item[2]
    try:
        await asyncio.wait_for(asyncio.shield(fut), timeout=(max_wait or CONV_WAIT_TIMEOUT))
        return True
    except asyncio.TimeoutError:
        adm.abandon(item)
        return False
    except BaseException:        # 客户端断开/取消 → 退出队列不泄漏槽位，再抛出
        adm.abandon(item)
        raise

@app.post("/avatar/batch_dub")
async def avatar_batch_dub(
    file:     UploadFile = File(...),
    profile:  str        = Form(default=""),
    language: str        = Form(default="zh-cn"),
):
    """
    批量配音：上传.txt → 3路并发TTS → 打包zip下载
    优化：单httpx客户端复用连接池 / asyncio.Semaphore(3)并发 / 每行独立超时
    """
    import zipfile as _zf, io as _io

    content = await file.read()
    lines   = [l.strip() for l in content.decode('utf-8', errors='replace').splitlines()
               if l.strip()]
    if not lines:
        raise HTTPException(400, "文件为空或无有效行")
    if len(lines) > 500:
        raise HTTPException(400, f"超过最大行数限制500行，当前: {len(lines)}")

    profile_name = profile or _active_profile
    p            = _profiles.get(profile_name, {})
    voice_b64    = p.get("voice_b64", "")
    voice_name   = p.get("voice_name", "") or "female_01.wav"
    rvc_model    = p.get("rvc_model", "")
    rvc_settings = p.get("rvc_settings", {})

    _line_sem = asyncio.Semaphore(3)   # 单批内最多3路并发TTS

    async def _do_line(idx: int, line: str, client: httpx.AsyncClient):
        async with _line_sem:
            try:
                if voice_b64:
                    r = await client.post(f"{SERVICES['tts']}/v1/audio/clone",
                        json={"text": line, "language": language,
                              "reference_audio_base64": voice_b64},
                        timeout=90)
                    wav_bytes = (base64.b64decode(r.json().get("audio_base64",""))
                                 if r.status_code == 200 else b"")
                else:
                    r = await client.post(f"{SERVICES['tts']}/v1/audio/speech",
                        json={"model": "xtts_v2", "input": line,
                              "voice": voice_name, "language": language},
                        timeout=90)
                    wav_bytes = r.content if r.status_code == 200 else b""

                if rvc_model and wav_bytes:
                    try:
                        out = await rvc_client_post(rvc_model, rvc_settings,
                                                    base64.b64encode(wav_bytes).decode())
                        if out: wav_bytes = base64.b64decode(out)
                    except Exception:
                        pass
                safe = line[:20].replace(" ","_").replace("/","_")
                return (idx, f"{idx:04d}_{safe}.wav", wav_bytes, "")
            except Exception as exc:
                return (idx, f"{idx:04d}_error.txt", b"", str(exc))

    async with _BATCH_SEMAPHORE:
        _metrics["batch_dub_total"] += 1
        _metrics["batch_dub_lines_total"] += len(lines)
        async with _aclient(timeout=120) as client:
            results = await asyncio.gather(
                *[_do_line(i, l, client) for i, l in enumerate(lines, 1)])

    results = sorted(results, key=lambda x: x[0])
    _bd_chars = sum(len(l) for (_i, _f, _wb, _e), l in zip(results, lines) if _wb and not _e)
    if _bd_chars:
        _track_event("huansheng", "huansheng.tts.chars_metered", {   # P4：批级用量（整批一条，只计成功行）
            "chars": _bd_chars, "voice_id": profile_name, "lang": language, "engine": "xtts"})
    zip_buf = _io.BytesIO()
    with _zf.ZipFile(zip_buf, 'w', _zf.ZIP_DEFLATED) as zf:
        for _idx, fname, wav_bytes, err in results:
            zf.writestr(fname, f"Error: {err}" if err else wav_bytes)

    zip_buf.seek(0)
    return StreamingResponse(
        zip_buf,
        media_type="application/zip",
        headers={"Content-Disposition": 'attachment; filename="batch_dub.zip"'}
    )


async def rvc_client_post(pth_path: str, rvc_settings: dict, audio_b64: str) -> str:
    """RVC转换辅助函数，返回转换后 audio_base64 或 ''"""
    try:
        r = await http_pool.post(f"{RVC_API}/convert", json={
            "audio_base64": audio_b64,
            "pth_path":     _rvc_resolve_pth(pth_path),
            "index_path":   rvc_settings.get("index_path", ""),
            "pitch":        rvc_settings.get("pitch", 0),
            "index_rate":   rvc_settings.get("index_rate", 0.3),
            "f0method":     rvc_settings.get("f0method", "rmvpe"),
            "protect":      rvc_settings.get("protect", 0.33),
        }, timeout=30)
        if r.status_code == 200:
            return r.json().get("audio_base64", "")
    except Exception:
        pass
    return ""


# ── 历史记录 API ──────────────────────────────────────────────────
def _fts_safe_query(q: str) -> str:
    """把用户输入转成 FTS5 字面短语查询：每个空白分段加双引号（内部双引号翻倍）。
    P5 踩坑：唱歌历史带 [魔改]/[原创] 前缀，方括号是 MATCH 语法字符——裸传要么
    语法报错要么匹配不到；引号包裹后按字面 token 匹配，中英文都稳。"""
    parts = [p.replace('"', '""') for p in (q or "").split() if p]
    return " ".join(f'"{p}"' for p in parts) or '""'


@app.get("/api/history")
def get_history(limit: int = 20, offset: int = 0, profile: str = "",
               starred_only: bool = False, search: str = "", emotion: str = "",
               since_ts: float = 0.0, start_date: str = "", end_date: str = ""):
    """查询说话历史记录，支持分页/关键词/情感过滤/增量同步(since_ts)/日期范围(start_date,end_date YYYY-MM-DD)
    P21-5: 当提供search参数时，使用FTS5全文索引加速搜索"""
    try:
        params = []
        fts_mode = bool(search)  # P21-5: 有搜索关键词时启用FTS
        if fts_mode:
            # P21-5: FTS5 MATCH 搜索（BM25排序，支持中文分词）
            sql  = """SELECT h.id,h.ts,h.profile,h.text,h.language,h.audio_file,
                      h.elapsed_ms,h.rvc_applied,h.starred,h.emotion
                      FROM speak_history h
                      JOIN speak_history_fts fts ON h.id = fts.rowid
                      WHERE fts.speak_history_fts MATCH ?"""
            params.append(_fts_safe_query(search))  # P5: 用户输入按字面搜，不当 MATCH 语法解析
        else:
            sql  = "SELECT id,ts,profile,text,language,audio_file,elapsed_ms,rvc_applied,starred,emotion "
            sql += "FROM speak_history WHERE 1=1"
        # 附加过滤条件
        if profile:
            sql += " AND h.profile=?" if fts_mode else " AND profile=?"
            params.append(profile)
        if starred_only:
            sql += " AND h.starred=1" if fts_mode else " AND starred=1"
        if emotion:
            sql += " AND h.emotion=?" if fts_mode else " AND emotion=?"
            params.append(emotion)
        if since_ts > 0:
            sql += " AND h.ts > ?" if fts_mode else " AND ts > ?"
            params.append(since_ts)
        if start_date:
            ts0 = _dt.datetime.strptime(start_date, "%Y-%m-%d").timestamp()
            sql += " AND h.ts >= ?" if fts_mode else " AND ts >= ?"
            params.append(ts0)
        if end_date:
            ts1 = (_dt.datetime.strptime(end_date, "%Y-%m-%d") + _dt.timedelta(days=1)).timestamp()
            sql += " AND h.ts < ?" if fts_mode else " AND ts < ?"
            params.append(ts1)
        sql += " ORDER BY " + ("h.ts" if fts_mode else "ts") + " DESC LIMIT ? OFFSET ?"
        params.extend([limit, offset])
        with _db_conn() as conn:
            rows = conn.execute(sql, params).fetchall()
        result = []
        for r in rows:
            created_at = _dt.datetime.fromtimestamp(r["ts"]).strftime("%m-%d %H:%M")
            result.append({
                "id": r["id"], "ts": r["ts"],
                "created_at": created_at,
                "date": _dt.datetime.fromtimestamp(r["ts"]).strftime("%Y-%m-%d"),
                "profile": r["profile"], "text": r["text"],
                "language": r["language"], "elapsed_ms": r["elapsed_ms"],
                "rvc_applied": bool(r["rvc_applied"]),
                "starred": bool(r["starred"]),
                "emotion": r["emotion"] or "neutral",
                "has_audio": bool(r["audio_file"] and
                    (HISTORY_AUDIO / r["audio_file"]).exists()),
            })
        # 分页总数
        if fts_mode:
            count_sql = """SELECT COUNT(*) FROM speak_history h
                            JOIN speak_history_fts fts ON h.id = fts.rowid
                            WHERE fts.speak_history_fts MATCH ?"""
            count_params = [_fts_safe_query(search)]
        else:
            count_sql = "SELECT COUNT(*) FROM speak_history WHERE 1=1"
            count_params = []
        if profile:
            count_sql += " AND " + ("h.profile=?" if fts_mode else "profile=?")
            count_params.append(profile)
        if starred_only:
            count_sql += " AND " + ("h.starred=1" if fts_mode else "starred=1")
        if not fts_mode and search:  # 非FTS模式回退LIKE
            count_sql += " AND (text LIKE ? OR profile LIKE ?)"
            count_params.extend([f"%{search}%", f"%{search}%"])
        if emotion:
            count_sql += " AND " + ("h.emotion=?" if fts_mode else "emotion=?")
            count_params.append(emotion)
        if since_ts > 0:
            count_sql += " AND " + ("h.ts > ?" if fts_mode else "ts > ?")
            count_params.append(since_ts)
        if start_date:
            count_sql += " AND " + ("h.ts >= ?" if fts_mode else "ts >= ?")
            count_params.append(ts0)
        if end_date:
            count_sql += " AND " + ("h.ts < ?" if fts_mode else "ts < ?")
            count_params.append(ts1)
        with _db_conn() as conn2:
            total_count = conn2.execute(count_sql, count_params).fetchone()[0]
        return {"ok": True, "records": result, "count": len(result), "total_count": total_count}
    except Exception as e:
        raise HTTPException(500, str(e))


_stats_cache: dict = {}
_stats_cache_ts: float = 0.0
_STATS_CACHE_TTL = 30.0   # 30 秒缓存，避免大数据集全表扫描

@app.get("/api/history/stats")
def get_history_stats():
    """历史全量统计：今日/本周/总量/情感分布/平均耗时（30s 缓存）"""
    global _stats_cache, _stats_cache_ts
    now = time.time()
    # 缓存命中（日期边界每天至少一次自动失效）
    today_boundary = _dt.datetime.now().replace(hour=0, minute=0, second=0, microsecond=0).timestamp()
    if _stats_cache and (now - _stats_cache_ts) < _STATS_CACHE_TTL and _stats_cache_ts >= today_boundary:
        return _stats_cache
    try:
        today_ts = today_boundary
        week_ts  = today_ts - 6 * 86400
        with _db_conn() as conn:
            row = conn.execute("""
                SELECT
                  COUNT(*) AS total,
                  SUM(CASE WHEN ts >= ? THEN 1 ELSE 0 END) AS today,
                  SUM(CASE WHEN ts >= ? THEN 1 ELSE 0 END) AS week,
                  ROUND(AVG(elapsed_ms)) AS avg_elapsed_ms
                FROM speak_history
            """, (today_ts, week_ts)).fetchone()
            dist = conn.execute("""
                SELECT emotion, COUNT(*) AS cnt
                FROM speak_history
                WHERE emotion IS NOT NULL AND emotion != ''
                GROUP BY emotion ORDER BY cnt DESC LIMIT 8
            """).fetchall()
            # P20-2: 过去7天每日数量趋势（在同一连接内查询）
            week7_ts = today_ts - 6 * 86400
            daily_rows = conn.execute("""
                SELECT DATE(ts, 'unixepoch', 'localtime') AS day, COUNT(*) AS cnt
                FROM speak_history WHERE ts >= ?
                GROUP BY day ORDER BY day
            """, (week7_ts,)).fetchall()
        # 补全缺失日期（保证7个点）
        day_map = {r["day"]: r["cnt"] for r in daily_rows}
        daily_7 = []
        for i in range(6, -1, -1):
            d_ts = today_ts - i * 86400
            d_str = _dt.datetime.fromtimestamp(d_ts).strftime("%Y-%m-%d")
            daily_7.append([d_str[-5:], day_map.get(d_str, 0)])  # ["MM-DD", cnt]
        distribution = [[r["emotion"], r["cnt"]] for r in dist]
        max_cnt = distribution[0][1] if distribution else 1
        result = {
            "ok": True,
            "total":          row["total"]          or 0,
            "today":          row["today"]          or 0,
            "week":           row["week"]           or 0,
            "avg_elapsed_ms": int(row["avg_elapsed_ms"] or 0),
            "distribution":   distribution,
            "max_count":      max_cnt,
            "most_used":      distribution[0][0] if distribution else None,
            "daily_7":        daily_7,              # P20-2: 7天日历数据
        }
        _stats_cache = result
        _stats_cache_ts = now
        return result
    except Exception as e:
        raise HTTPException(500, str(e))


def _invalidate_stats_cache():
    """写入历史后主动使 stats 缓存失效"""
    global _stats_cache_ts
    _stats_cache_ts = 0.0


