@app.delete("/api/history")
def clear_history(keep_starred: bool = True):
    """清空历史记录（默认保留收藏）"""
    try:
        with _db_conn() as conn:
            if keep_starred:
                rows = conn.execute(
                    "SELECT audio_file FROM speak_history WHERE starred=0").fetchall()
                for r in rows:
                    if r["audio_file"]:
                        f = HISTORY_AUDIO / r["audio_file"]
                        if f.exists(): f.unlink()
                conn.execute("DELETE FROM speak_history WHERE starred=0")
            else:
                rows = conn.execute(
                    "SELECT audio_file FROM speak_history").fetchall()
                for r in rows:
                    if r["audio_file"]:
                        f = HISTORY_AUDIO / r["audio_file"]
                        if f.exists(): f.unlink()
                conn.execute("DELETE FROM speak_history")
            conn.commit()
        return {"ok": True, "keep_starred": keep_starred}
    except Exception as e:
        raise HTTPException(500, str(e))


@app.delete("/api/history/{record_id}")
def delete_history_record(record_id: int):
    """删除单条历史记录（含关联音频文件）"""
    try:
        with _db_conn() as conn:
            row = conn.execute(
                "SELECT audio_file FROM speak_history WHERE id=?", (record_id,)
            ).fetchone()
            if not row:
                raise HTTPException(404, "记录不存在")
            if row["audio_file"]:
                f = HISTORY_AUDIO / row["audio_file"]
                if f.exists():
                    f.unlink()
            conn.execute("DELETE FROM speak_history WHERE id=?", (record_id,))
            conn.commit()
        return {"ok": True, "id": record_id}
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(500, str(e))


@app.post("/api/history/export")
def export_history(body: dict):
    """
    按 ids 列表导出历史音频为 ZIP。
    请求体: {"ids": [1,2,3]}
    返回: application/zip
    """
    import zipfile as _zf, io as _io
    ids = body.get("ids", [])
    if not ids or len(ids) > 100:
        raise HTTPException(400, "ids 需要1~100个整数")
    try:
        with _db_conn() as conn:
            placeholders = ",".join("?" * len(ids))
            rows = conn.execute(
                f"SELECT id,profile,text,audio_file,emotion FROM speak_history WHERE id IN ({placeholders})",
                ids
            ).fetchall()
    except Exception as e:
        raise HTTPException(500, str(e))

    zip_buf = _io.BytesIO()
    export_ts = _dt.datetime.now().strftime("%Y-%m-%dT%H:%M:%S")
    manifest_items = []
    with _zf.ZipFile(zip_buf, 'w', _zf.ZIP_DEFLATED) as zf:
        for r in rows:
            f = HISTORY_AUDIO / r["audio_file"] if r["audio_file"] else None
            safe_text = (r["text"] or "")[:20].replace("/","_").replace("\\","_")
            fname = f"{r['id']:04d}_{r['profile']}_{safe_text}.wav"
            has_audio = bool(f and f.exists())
            if has_audio:
                zf.write(f, fname)
            else:
                placeholder = fname.replace(".wav", "_no_audio.txt")
                zf.writestr(placeholder, f"text: {r['text']}\nemotion: {r['emotion']}\nprofile: {r['profile']}")
                fname = placeholder
            manifest_items.append({  # P18-3: 元数据清单
                "id": r["id"], "profile": r["profile"],
                "emotion": r["emotion"], "text": r["text"],
                "filename": fname, "has_audio": has_audio,
            })
        # P18-3: 写入 manifest.json
        manifest = {"exported_at": export_ts, "total": len(manifest_items), "items": manifest_items}
        zf.writestr("manifest.json", json.dumps(manifest, ensure_ascii=False, indent=2))
    zip_buf.seek(0)
    return StreamingResponse(zip_buf, media_type="application/zip",
        headers={"Content-Disposition": 'attachment; filename="history_export.zip"'})


class SingRequest(BaseModel):
    lyrics:               str
    profile:              str   = ""
    language:             str   = "zh"
    speed:                float = 0.85
    emotion:              str   = "gentle"   # Sing-P0: 念白模式演绎风格（gentle/happy/sad/calm）
    reference_audio_b64:  str   = ""   # 可选：指定参考音色（覆盖角色音色）
    reference_text:       str   = ""

class SingResponse(BaseModel):
    audio_base64: str    = ""
    elapsed_ms:   int    = 0
    warning:      str    = ""
    engine_used:  str    = ""    # Sing-P0: "singing"=完整唱歌引擎 / "emotion_tts"=念白演绎（结构化，前端按此显示徽章）
    history_id:   Optional[int] = None   # Sing-P0: 已入历史的记录 id（产物不再刷新即丢）


_SING_TEXT_LIMIT = 1000                                   # Sing-P0: 歌词长度服务端防线（超时预算内的上限）
_SING_EMOTIONS   = {"gentle", "happy", "sad", "calm"}     # Sing-P0: 演绎风格白名单（越界回落 gentle）


@app.post("/avatar/sing", response_model=SingResponse)
async def avatar_sing(req: SingRequest):
    """
    唱歌/歌词演绎。优先 singing(7853) 完整唱歌引擎；离线时降级 EmotionTTS 念白模式。
    Sing-P0 (2026-07-06)：与 /avatar/speak 同权 —— 并发闸 + 水印凭证 + 历史入库；
    engine_used 结构化回传（降级不再伪装成功）；歌词长度/参考音频大小防线；演绎风格参数。
    """
    global _active_profile
    t0 = time.time()
    lyrics = (req.lyrics or "").strip()
    if not lyrics:
        raise HTTPException(400, "歌词不能为空")
    if len(lyrics) > _SING_TEXT_LIMIT:
        raise HTTPException(400, f"歌词超过 {_SING_TEXT_LIMIT} 字上限，请分段演绎")
    if req.reference_audio_b64 and len(req.reference_audio_b64) > _B64_LIMIT:
        raise HTTPException(400, "参考音频过大（上限约 5MB），请截取 3~30 秒片段")
    if req.profile:
        _check_profile_name(req.profile)
    emotion = req.emotion if req.emotion in _SING_EMOTIONS else "gentle"
    speed   = min(max(req.speed, 0.5), 1.5)

    async with _PROFILES_LOCK:
        profile_name = req.profile or _active_profile
        profile = dict(_profiles.get(profile_name, {}))
    voice_b64  = req.reference_audio_b64 or profile.get("voice_b64", "")

    # Sing-P0: 与 speak 同一并发闸，防止唱歌路径绕过 GPU 并发上限
    try:
        await asyncio.wait_for(_SPEAK_SEM.acquire(), timeout=10.0)
    except asyncio.TimeoutError:
        raise HTTPException(503, "服务繁忙，请稍后重试（并发超限）")

    audio_b64 = ""; warn = ""; engine_used = ""
    try:
        # 1) 完整唱歌引擎 singing(7853)
        try:
            payload = {
                "lyrics": lyrics,
                "text_lang": req.language,
                "speed": speed,
                "return_base64": True,
            }
            if voice_b64:
                payload["reference_audio_b64"] = voice_b64
            if req.reference_text:
                payload["reference_text"] = req.reference_text
            r = await http_pool.post(
                f"{SERVICES['singing']}/v1/tts/sing",
                json=payload, timeout=60
            )
            if r.status_code == 200:
                audio_b64 = r.json().get("audio_base64", "")
                engine_used = "singing"
            else:
                warn = f"singing HTTP {r.status_code}"
        except Exception as exc:
            warn = f"singing 服务不可达: {exc}"

        # 2) 降级：EmotionTTS 念白演绎（演绎风格由用户选择，不再写死 gentle）
        if not audio_b64:
            _logger.warning(f"[Sing] 降级到 EmotionTTS 念白: {warn}")
            fallback_payload = {
                "text": lyrics,
                "emotion": emotion,
                "speed": speed,
                "return_base64": True,
            }
            if voice_b64:
                fallback_payload["reference_audio_b64"] = voice_b64
                ep = f"{SERVICES['emotion_tts']}/v1/tts/clone"
            else:
                ep = f"{SERVICES['emotion_tts']}/v1/tts"
            try:
                r2 = await http_pool.post(ep, json=fallback_payload, timeout=60)
            except Exception as e2:
                raise HTTPException(503, f"唱歌引擎与念白引擎均不可达: {e2}")
            if r2.status_code != 200:
                raise HTTPException(502, f"念白引擎生成失败: HTTP {r2.status_code}")
            audio_b64 = r2.json().get("audio_base64", "")
            engine_used = "emotion_tts"
        if not audio_b64:
            raise HTTPException(502, "引擎返回了空音频，请稍后重试")
    finally:
        _SPEAK_SEM.release()

    elapsed = int((time.time() - t0) * 1000)
    _metrics["sing_total"] = _metrics.get("sing_total", 0) + 1
    if engine_used != "singing":
        _metrics["sing_degraded_total"] = _metrics.get("sing_degraded_total", 0) + 1

    # Sing-P0: 历史入库（emotion 记 'sing'，历史页可检索），完成后广播刷新
    hist_id = None
    try:
        hist_id = await asyncio.get_running_loop().run_in_executor(
            _history_executor, _write_history,
            profile_name, lyrics, req.language, audio_b64, elapsed, False, False, "sing")
        await broadcast({"event": "history_updated"})
    except Exception as _he:
        _logger.warning(f"[Sing] 历史入库跳过: {_he}")

    # Sing-P0: 输出内容凭证 + 不可见水印（与 /avatar/speak 同权，合规默认开启）
    out_b64 = audio_b64
    if PROVENANCE_ENABLED and _provenance is not None and audio_b64:
        try:
            _res = _provenance.attach_credentials(
                base64.b64decode(audio_b64),
                model=("gptsovits" if engine_used == "singing" else "cosyvoice"),
                profile=profile_name, ai_generated=True,
                extra={"mode": "sing", "emotion": emotion})
            if _res.get("ok"):
                out_b64 = base64.b64encode(_res["audio_bytes"]).decode()
        except Exception as _we:
            _logger.warning(f"[Provenance/sing] 水印跳过: {_we}")

    return SingResponse(audio_base64=out_b64, elapsed_ms=elapsed,
                        warning="" if engine_used == "singing" else warn,
                        engine_used=engine_used, history_id=hist_id)


# ══════════════════════════════════════════════════════════════════
#  Song-P1: AI 翻唱（YingMusic-SVC @ song_studio 7853）
#  管线：整曲上传 → 人声分离 → 零样本音色转换（自动升降调）→ 混音出品。
#  Hub 职责：上传编排 / 任务代理 / 完成时水印+历史+贴合度（产物三件套与 speak 同权）。
#  并发：不占 _SPEAK_SEM（分钟级任务会饿死对话链），GPU 串行由 song_studio 自己保证。
# ══════════════════════════════════════════════════════════════════

_SONG_UPLOAD_LIMIT = 40 * 1024 * 1024   # 整曲文件上限（解码前字节）
_SONG_TASKS: dict = {}                  # hub 侧任务登记：完成后处理标记+缓存结果


def _song_base() -> str:
    return SERVICES["singing"]


# ══════════════════════════════════════════════════════════════════
#  Song-P5: 任务持久化 + 断点续办
#  痛点（P4 真跑实锤）：登记表在内存，Hub 重启即失忆——引擎还在辛苦生成，
#  Hub 却不认识这单了；换声编排/收尾（水印+历史）永远不会发生。
#  方案：写穿式 SQLite（logs/song_tasks.db，WAL）。ref_b64 等大字段不落库
#  （收尾时按 ref_label 从角色表回取；上传参考音色的任务重启后诚实不评分）。
#  配合 _bg_song_reconcile 后台对账：不靠前端轮询也能推进/收尾任务。
# ══════════════════════════════════════════════════════════════════
_SONG_STORE_DB = Path(rf"{_BASE}\logs\song_tasks.db")
_SONG_STORE_LOCK = threading.Lock()
_SONG_TASK_TTL_S = 48 * 3600            # 与引擎产物 6h + MV 48h 对齐取宽
_SONG_STORE_SKIP = ("ref_b64",)         # 大字段不落库


def _song_store_conn():
    conn = _sqlite3.connect(str(_SONG_STORE_DB), check_same_thread=False)
    conn.execute("PRAGMA journal_mode=WAL")
    conn.execute("PRAGMA synchronous=NORMAL")
    return conn


def _init_song_store():
    try:
        with _SONG_STORE_LOCK, _song_store_conn() as conn:
            conn.execute("""
            CREATE TABLE IF NOT EXISTS song_tasks (
                kind    TEXT NOT NULL,          -- cover / create / mv
                tid     TEXT NOT NULL,
                data    TEXT NOT NULL,          -- json（不含 ref_b64 大字段）
                done    INTEGER NOT NULL DEFAULT 0,
                updated REAL NOT NULL,
                PRIMARY KEY (kind, tid))""")
    except Exception as e:
        _logger.warning(f"[SongStore] 初始化失败(持久化降级为内存): {e}")


def _task_persist(kind: str, tid: str, t: dict):
    """写穿：登记/状态跳变/收尾时各存一次（<10KB 行，WAL 亚毫秒级）。失败不外溢。"""
    try:
        slim = {k: v for k, v in t.items() if k not in _SONG_STORE_SKIP}
        blob = json.dumps(slim, ensure_ascii=False, default=str)
        with _SONG_STORE_LOCK, _song_store_conn() as conn:
            conn.execute(
                "INSERT OR REPLACE INTO song_tasks(kind,tid,data,done,updated) "
                "VALUES(?,?,?,?,?)",
                (kind, tid, blob, 1 if t.get("final") else 0, time.time()))
    except Exception as e:
        _logger.warning(f"[SongStore] persist {kind}/{tid} 失败: {e}")


def _task_unpersist(kind: str, tid: str):
    try:
        with _SONG_STORE_LOCK, _song_store_conn() as conn:
            conn.execute("DELETE FROM song_tasks WHERE kind=? AND tid=?", (kind, tid))
    except Exception:
        pass


def _song_store_load():
    """启动回载：未过期任务回登记表（Hub 重启续办）。过期行顺手清掉。"""
    out = {"cover": {}, "create": {}, "mv": {}}
    try:
        cutoff = time.time() - _SONG_TASK_TTL_S
        with _SONG_STORE_LOCK, _song_store_conn() as conn:
            conn.execute("DELETE FROM song_tasks WHERE updated < ?", (cutoff,))
            rows = conn.execute("SELECT kind,tid,data FROM song_tasks").fetchall()
        for kind, tid, blob in rows:
            try:
                if kind in out:
                    out[kind][tid] = json.loads(blob)
            except Exception:
                continue
    except Exception as e:
        _logger.warning(f"[SongStore] 回载失败(从空开始): {e}")
    return out


async def _task_refetch_ref(t: dict) -> str:
    """收尾评分/换声要参考音色：重启回载的任务 ref_b64 已剥离，按角色名回取。
    上传参考音色（ref_label 非角色名）回不了 → 返回空（评分诚实跳过）。"""
    if t.get("ref_b64"):
        return t["ref_b64"]
    label = t.get("ref_label") or t.get("profile") or ""
    async with _PROFILES_LOCK:
        v = dict(_profiles.get(label, {})).get("voice_b64", "")
    if v:
        t["ref_b64"] = v
    return v


# 收尾并发闸：前端轮询与后台对账可能同时看到 done——先到先收尾，后到复用缓存。
_FINALIZE_LOCKS: dict = {}


def _finalize_lock(tid: str) -> asyncio.Lock:
    lk = _FINALIZE_LOCKS.get(tid)
    if lk is None:
        lk = _FINALIZE_LOCKS[tid] = asyncio.Lock()
    return lk


async def _song_store_hydrate():
    """启动回载（lifespan 内调）：登记表回灌 + 未完 MV 重排队。"""
    _init_song_store()
    data = _song_store_load()
    for tid, t in data["cover"].items():
        t.setdefault("ref_b64", "")
        _SONG_TASKS.setdefault(tid, t)
    for tid, t in data["create"].items():
        t.setdefault("ref_b64", "")
        _ACE_TASKS.setdefault(tid, t)
    requeued = 0
    for tid, t in data["mv"].items():
        _MV_TASKS.setdefault(tid, t)
        if t.get("status") in ("queued", "waiting", "rendering"):
            # 渲染不可断点续：重启丢中间态，重头排队并如实告知
            t.update(status="queued", progress=0, cancel=False,
                     detail="Hub 重启，已重新排队")
            _task_persist("mv", tid, t)
            await _MV_QUEUE.put(tid)
            requeued += 1
    open_n = (sum(1 for x in _SONG_TASKS.values() if not x.get("final"))
              + sum(1 for x in _ACE_TASKS.values() if not x.get("final")))
    if open_n or requeued:
        _logger.info(f"[SongStore] 回载：cover={len(data['cover'])} create={len(data['create'])} "
                     f"mv={len(data['mv'])}（未完 {open_n}，MV 重排 {requeued}）——后台对账续办")


async def _song_reconcile_tick():
    """P5 对账：不靠前端轮询也推进任务——浏览器关了，歌照样出、历史照样入。
    复用各自的状态端点函数（与前端同源零分叉），收尾幂等靠 _finalize_lock。"""
    now = time.time()
    # 原创歌/魔改：gen→swap→final 全程推进
    for tid, t in list(_ACE_TASKS.items()):
        if t.get("final") or t.get("_gone"):
            if now - t.get("t0", now) > _SONG_TASK_TTL_S:
                _ACE_TASKS.pop(tid, None)
                _FINALIZE_LOCKS.pop(tid, None)
            continue
        if now - t.get("t0", now) < 6:
            continue                          # 刚提交的单让前端先跑，避免无谓抢锁
        try:
            st = await song_create_status(tid)
            t["_snap"] = {"status": st.get("status"), "progress": st.get("progress"),
                          "detail": st.get("detail", ""), "stage": st.get("stage"),
                          "ts": now}
        except HTTPException as e:
            if e.status_code == 404:
                # 引擎重启丢任务（引擎侧登记在内存）：如实标记，看板可见，TTL 后清
                t["_gone"] = True
                t["_snap"] = {"status": "error", "progress": 0, "ts": now,
                              "detail": "任务在引擎侧已丢失（引擎重启），请重新提交"}
                _logger.warning(f"[SongRecon] create/{tid} 引擎侧 404，标记丢失")
            # 503 引擎暂不可达：下个 tick 再试，不打日志（启动窗口很常见）
        except Exception as e:
            _logger.warning(f"[SongRecon] create/{tid} 推进异常: {e}")
    # 翻唱（含点歌台备歌/换声子任务）：完成即收尾入历史
    for tid, t in list(_SONG_TASKS.items()):
        if t.get("final") or t.get("_gone"):
            if now - t.get("t0", now) > _SONG_TASK_TTL_S:
                _SONG_TASKS.pop(tid, None)
                _FINALIZE_LOCKS.pop(tid, None)
            continue
        if now - t.get("t0", now) < 6:
            continue
        try:
            st = await song_task_status(tid)
            t["_snap"] = {"status": st.get("status"), "progress": st.get("progress"),
                          "detail": st.get("detail", ""), "ts": now}
        except HTTPException as e:
            if e.status_code == 404:
                t["_gone"] = True
                t["_snap"] = {"status": "error", "progress": 0, "ts": now,
                              "detail": "任务在引擎侧已丢失（引擎重启），请重新提交"}
                _logger.warning(f"[SongRecon] cover/{tid} 引擎侧 404，标记丢失")
        except Exception as e:
            _logger.warning(f"[SongRecon] cover/{tid} 推进异常: {e}")
    # MV：worker 自驱，这里只清过期终态
    for tid, t in list(_MV_TASKS.items()):
        if t.get("status") in ("done", "error", "cancelled") \
                and now - t.get("t0", now) > _SONG_TASK_TTL_S:
            _MV_TASKS.pop(tid, None)
            _task_unpersist("mv", tid)


async def _bg_song_reconcile():
    await asyncio.sleep(12.0)                 # 等引擎起来，别一开机就刷 503
    while True:
        try:
            await _song_reconcile_tick()
        except Exception as exc:
            _logger.warning(f"[SongRecon] tick 异常: {exc}")
        await asyncio.sleep(float(os.environ.get("SONG_RECONCILE_SEC", "8")))


@app.get("/api/song/tasks")
async def api_song_tasks(limit: int = 30):
    """P5 队列看板：唱歌三类任务（翻唱/原创魔改/MV）一屏可见。
    数据源=登记表+对账快照（8s 内新鲜），零引擎请求——看板刷不垮引擎。"""
    rows = []
    for tid, t in _ACE_TASKS.items():
        snap = t.get("_snap") or {}
        f = t.get("final") or {}
        rows.append({
            "tid": tid, "kind": t.get("mode", "create"), "song_name": t.get("song_name", ""),
            "stage": snap.get("stage") or t.get("stage"), "t0": t.get("t0"),
            "status": "done" if f else snap.get("status", "pending"),
            "progress": 100 if f else snap.get("progress", 0),
            "detail": "" if f else snap.get("detail", ""),
            "svc_swap": t.get("svc_swap"), "lora": t.get("lora") or "",   # P6 唱腔标
            "history_id": f.get("history_id"), "audio_url": f.get("audio_url", ""),
            "similarity": f.get("similarity"),
        })
    for tid, t in _SONG_TASKS.items():
        if str(t.get("mode", "")).endswith("_swap"):
            continue                          # 换声子任务由父任务行代表，不重复展示
        snap = t.get("_snap") or {}
        f = t.get("final") or {}
        rows.append({
            "tid": tid, "kind": "cover", "song_name": t.get("song_name", ""),
            "stage": None, "t0": t.get("t0"),
            "status": "done" if f else snap.get("status", "pending"),
            "progress": 100 if f else snap.get("progress", 0),
            "detail": "" if f else snap.get("detail", ""),
            "history_id": f.get("history_id"), "audio_url": f.get("audio_url", ""),
            "similarity": f.get("similarity"),
        })
    for tid, t in _MV_TASKS.items():
        f = t.get("final") or {}
        rows.append({
            "tid": tid, "kind": "mv", "song_name": t.get("song_name", ""),
            "stage": None, "t0": t.get("t0"),
            "status": t.get("status", "pending"), "progress": t.get("progress", 0),
            "detail": t.get("detail", ""),
            "seconds": t.get("seconds"), "url": f.get("url", ""),
        })
    rows.sort(key=lambda r: r.get("t0") or 0, reverse=True)
    open_n = sum(1 for r in rows if r["status"] not in ("done", "error", "cancelled"))
    return {"tasks": rows[:max(1, min(100, limit))], "open": open_n, "total": len(rows)}


# ── Song-P3/O6: 直播让路（单一真相）────────────────────────────────
# 唱歌重活(分离/SVC/MV 口型)与直播抢同一张卡。song_studio 每 5s 来问这里；
# yield=true 时引擎把任务挂起（GPU 一点不碰），信号消失自动继续。
# 判据：①换脸直播/同传会话(与 harden drill 同判据) ②数字人对话最近活跃 ③显存逼近 OOM
# ④运维手动挂起（/api/song/yield/hold，直播前手动清场用，也给 e2e 一个可控入口）。
_SONG_LIVE_YIELD = os.environ.get("SONG_LIVE_YIELD", "1") != "0"
_SONG_YIELD_CONV_WINDOW_S = float(os.environ.get("SONG_YIELD_CONV_WINDOW_S", "180"))
_SONG_YIELD_HOLD = {"on": False, "reason": "", "ts": 0.0}
_SONG_YIELD_CACHE = {"ts": 0.0, "st": None}   # 3s TTL：interpreter 探测最坏 2s，别拖垮轮询


def _song_yield_state() -> dict:
    now = time.time()
    if _SONG_YIELD_CACHE["st"] is not None and now - _SONG_YIELD_CACHE["ts"] < 3.0:
        return _SONG_YIELD_CACHE["st"]
    st = {"yield": False, "reason": "", "source": ""}
    if _SONG_YIELD_HOLD["on"]:
        st = {"yield": True, "reason": _SONG_YIELD_HOLD["reason"] or "运维手动挂起",
              "source": "hold"}
    elif _SONG_LIVE_YIELD:
        busy, why = _live_session_busy()
        if busy:
            st = {"yield": True, "reason": why, "source": "live"}
        elif _conv_last_active > 0 and (now - _conv_last_active) < _SONG_YIELD_CONV_WINDOW_S:
            st = {"yield": True, "reason": "数字人对话进行中", "source": "converse"}
        else:
            p = _vram_pressure()
            if p.get("level") == "high":
                st = {"yield": True, "reason": f"显存吃紧（剩 {p.get('free_mb')}MB）",
                      "source": "vram"}
    _SONG_YIELD_CACHE.update(ts=now, st=st)
    return st


@app.get("/api/song/yield")
def api_song_yield():
    """唱歌任务是否该给直播让路（song_studio 轮询；只读）。"""
    return _song_yield_state()


@app.post("/api/song/yield/hold")
def api_song_yield_hold(on: bool = True, reason: str = ""):
    """手动挂起/恢复唱歌重活（开播前清场用；写操作走 token 鉴权）。"""
    _SONG_YIELD_HOLD.update(on=bool(on), reason=(reason or "").strip()[:80],
                            ts=time.time())
    _SONG_YIELD_CACHE["st"] = None          # 立即生效，不等 TTL
    _logger.info(f"[Song/yield] 手动{'挂起' if on else '恢复'} {reason!r}")
    return {"ok": True, **_song_yield_state()}


@app.get("/api/song/health")
async def song_health():
    """翻唱引擎能力探测（前端唱歌页据此显示/隐藏翻唱模式，绝不假在线）。
    P4/F3: 同时探测原创歌引擎（ace_studio），create 能力独立上报。"""
    out = {"online": False, "engine": "", "capabilities": {}}
    try:
        r = await health_pool.get(f"{_song_base()}/health")
        if r.status_code == 200:
            d = r.json()
            if d.get("service") == "song_studio":
                out = {"online": True, "engine": d.get("engine", ""),
                       "capabilities": d.get("capabilities", {}),
                       "queue": d.get("queue", 0)}
            else:
                # 7853 被旧 singing_server 占用等情况：在线但无翻唱能力
                out = {"online": True, "engine": "unknown", "capabilities": {}}
    except Exception:
        pass
    create = {"online": False, "capabilities": {}}
    try:
        r2 = await health_pool.get(f"{_ace_base()}/health")
        if r2.status_code == 200:
            d2 = r2.json()
            if d2.get("service") == "ace_studio":
                create = {"online": True, "capabilities": d2.get("capabilities", {}),
                          "engine": d2.get("engine", ""),
                          "max_duration_s": d2.get("max_duration_s", 240),
                          "queue": d2.get("queue", 0)}
    except Exception:
        pass
    out["create"] = create
    return out


@app.post("/api/song/cover")
async def song_cover_submit(
    song: UploadFile = File(..., description="整曲音频（mp3/wav/m4a/flac）"),
    reference: Optional[UploadFile] = File(None, description="参考音色（可选，默认用角色克隆音）"),
    profile: str = Form(""),
    pitch: str = Form("auto"),          # "auto" 或 -12..12 的整数字符串
    quality: str = Form("standard"),    # standard=30步 / fine=50步
    dry_vocal: bool = Form(False),      # 上传的已是干声清唱 → 跳过分离
):
    """提交 AI 翻唱任务。返回 task_id，进度经 /api/song/task/{tid} 轮询。"""
    profile_name = profile or _active_profile
    if profile:
        _check_profile_name(profile)
    song_bytes = await song.read()
    if not song_bytes:
        raise HTTPException(400, "歌曲文件为空")
    if len(song_bytes) > _SONG_UPLOAD_LIMIT:
        raise HTTPException(400, f"歌曲文件超过 {_SONG_UPLOAD_LIMIT // (1024*1024)}MB 上限")

    # 参考音色：上传优先，否则角色克隆音（翻唱必须有目标音色，没有就人话报错）
    ref_b64 = ""
    ref_label = ""
    if reference is not None:
        ref_bytes = await reference.read()
        if len(ref_bytes) > 12 * 1024 * 1024:
            raise HTTPException(400, "参考音频过大（上限 12MB），请截取 3~30 秒")
        if ref_bytes:
            ref_b64 = base64.b64encode(ref_bytes).decode()
            ref_label = reference.filename or "上传音色"
    if not ref_b64:
        async with _PROFILES_LOCK:
            p = dict(_profiles.get(profile_name, {}))
        ref_b64 = p.get("voice_b64", "")
        ref_label = profile_name
    if not ref_b64:
        raise HTTPException(400, "还没有可用的目标音色：请先在克隆页给角色录一段声音，或直接上传一段 3~30 秒参考音频")

    try:
        pitch_shift = None if str(pitch).strip() in ("", "auto") else max(-12, min(12, int(pitch)))
    except ValueError:
        pitch_shift = None
    payload = {
        "song_b64": base64.b64encode(song_bytes).decode(),
        "reference_b64": ref_b64,
        "song_name": song.filename or "未命名歌曲",
        "pitch_shift": pitch_shift,
        "diffusion_steps": 50 if quality == "fine" else 30,
        "skip_separation": bool(dry_vocal),
        # P2/O2: 精细档同时提高分离重叠推理次数（TTA），和声重的歌人声更干净
        "sep_overlap": 4 if quality == "fine" else 0,
        # P3/O2: 精细档换 Mel-Band RoFormer 分离（引擎缺权重会自动回退 BS）
        "sep_model": "mel" if quality == "fine" else "auto",
    }
    try:
        async with _aclient(timeout=httpx.Timeout(connect=5.0, read=120.0,
                                                  write=120.0, pool=5.0)) as c:
            r = await c.post(f"{_song_base()}/v1/cover", json=payload)
    except Exception as e:
        raise HTTPException(503, f"翻唱引擎不可达：{e}")
    if r.status_code != 200:
        try:
            detail = r.json().get("detail", "")
        except Exception:
            detail = f"HTTP {r.status_code}"
        raise HTTPException(r.status_code, detail or "翻唱任务提交失败")
    tid = r.json().get("task_id", "")
    _SONG_TASKS[tid] = {
        "profile": profile_name, "song_name": payload["song_name"],
        "ref_b64": ref_b64, "ref_label": ref_label, "t0": time.time(),
        "processed": False, "final": None,
    }
    _task_persist("cover", tid, _SONG_TASKS[tid])     # P5: Hub 重启不失忆
    _metrics["song_cover_total"] = _metrics.get("song_cover_total", 0) + 1
    _logger.info(f"[Song] 翻唱任务提交 tid={tid} 歌曲={payload['song_name']!r} "
                 f"音色={ref_label!r} pitch={pitch_shift} steps={payload['diffusion_steps']}")
    return {"ok": True, "task_id": tid}


async def _song_finalize(tid: str, hub_t: dict, status: dict) -> dict:
    """任务完成的一次性收尾：取回成品 → 水印凭证 → 历史入库 → 人声贴合度。幂等。
    P5: 前端轮询与后台对账可能并发到达 → 收尾锁串行，后到者直接吃缓存。"""
    if hub_t.get("final"):
        return hub_t["final"]
    async with _finalize_lock(tid):
        if hub_t.get("final"):
            return hub_t["final"]
        return await _song_finalize_locked(tid, hub_t, status)


async def _song_finalize_locked(tid: str, hub_t: dict, status: dict) -> dict:
    result = status.get("result") or {}
    # 1) 取回成品与干声（干声用于贴合度评分，混音会被伴奏污染）
    async with _aclient(timeout=httpx.Timeout(connect=5.0, read=300.0,
                                              write=30.0, pool=5.0)) as c:
        r = await c.get(f"{_song_base()}/v1/task/{tid}/audio", params={"stem": "result"})
        r.raise_for_status()
        mix_bytes = r.content
        vocals_b64 = ""
        try:
            rv = await c.get(f"{_song_base()}/v1/task/{tid}/audio", params={"stem": "vocals"})
            if rv.status_code == 200:
                vocals_b64 = base64.b64encode(rv.content).decode()
        except Exception:
            pass

    # 2) 水印凭证（与 speak/sing 同权；失败安全降级为原音频）
    # P4/F3: 原创歌换声阶段复用本收尾——engine/mode/历史前缀由提交方在登记表里定制
    _engine = hub_t.get("engine_label", "yingmusic_svc")
    _mode = hub_t.get("mode", "cover")
    out_bytes = mix_bytes
    if PROVENANCE_ENABLED and _provenance is not None:
        try:
            _res = _provenance.attach_credentials(
                mix_bytes, model=_engine, profile=hub_t["profile"],
                ai_generated=True,
                extra={"mode": _mode, "song": hub_t["song_name"],
                       "pitch_shift": result.get("pitch_shift")})
            if _res.get("ok"):
                out_bytes = _res["audio_bytes"]
        except Exception as _we:
            _logger.warning(f"[Song] 水印跳过: {_we}")
    out_b64 = base64.b64encode(out_bytes).decode()

    # 3) 历史入库（emotion='sing' 与念白同一检索口径；文本带 [翻唱]/[原创] 前缀区分。
    #    调门写进文本：同曲不同 key 不被 24h 去重合并，用户可 A/B 保留两版）
    elapsed = int((time.time() - hub_t["t0"]) * 1000)
    _pitch = result.get("pitch_shift") or 0
    _tag = f"（调门{_pitch:+d}）" if _pitch else ""
    _prefix = hub_t.get("hist_prefix", "[翻唱]")
    hist_id = None
    try:
        hist_id = await asyncio.get_running_loop().run_in_executor(
            _history_executor, _write_history,
            hub_t["profile"], f"{_prefix} {hub_t['song_name']}{_tag}", "zh",
            out_b64, elapsed, False, False, "sing")
        await broadcast({"event": "history_updated"})
    except Exception as _he:
        _logger.warning(f"[Song] 历史入库跳过: {_he}")

    # 4) 人声贴合度（干声 vs 目标音色；campplus 余弦，与克隆页同一把尺）
    # P5: 重启回载的任务 ref_b64 已剥离 → 按角色名回取；回不了就诚实不评分
    similarity = None
    _ref = await _task_refetch_ref(hub_t)
    if vocals_b64 and _ref:
        try:
            import clone_scorer
            sc = await asyncio.to_thread(
                clone_scorer.score_similarity, _ref, vocals_b64)
            if sc.get("ok"):
                similarity = {"cosine": sc["cosine"], "label": sc["label"]}
        except Exception as _se:
            _logger.warning(f"[Song] 贴合度评分跳过: {_se}")

    final = {
        "engine_used": _engine,
        "history_id": hist_id,
        # audio.wav = 原始字节端点：<audio>/<a download> 直接可用（/audio 是 JSON+b64）
        "audio_url": f"/api/history/{hist_id}/audio.wav" if hist_id else "",
        "similarity": similarity,
        "pitch_shift": result.get("pitch_shift"),
        "duration_s": result.get("duration_s"),
        "timings": result.get("timings", {}),
        "elapsed_ms": result.get("elapsed_ms", elapsed),
        "rtf": result.get("rtf"),
        "singer": hub_t.get("ref_label", ""),
    }
    hub_t["final"] = final
    hub_t["processed"] = True
    hub_t["ref_b64"] = ""          # 释放内存（评分已完成）
    _task_persist("cover", tid, hub_t)                # P5: 终态落库
    _metrics["song_cover_done"] = _metrics.get("song_cover_done", 0) + 1
    _logger.info(f"[Song] 翻唱完成 tid={tid} hist={hist_id} "
                 f"sim={similarity and similarity.get('cosine')} rtf={final['rtf']}")
    return final


@app.get("/api/song/task/{tid}")
async def song_task_status(tid: str):
    """翻唱任务进度轮询；完成时做一次性收尾（水印+历史+贴合度）并缓存。"""
    hub_t = _SONG_TASKS.get(tid)
    if hub_t and hub_t.get("final"):
        return {"task_id": tid, "status": "done", "progress": 100,
                "detail": "", **hub_t["final"]}
    try:
        r = await http_pool.get(f"{_song_base()}/v1/task/{tid}")
    except Exception as e:
        raise HTTPException(503, f"翻唱引擎不可达：{e}")
    if r.status_code != 200:
        try:
            detail = r.json().get("detail", f"HTTP {r.status_code}")
        except Exception:
            detail = f"HTTP {r.status_code}"
        raise HTTPException(r.status_code, detail)
    status = r.json()
    if status.get("status") == "done" and hub_t is not None:
        try:
            final = await _song_finalize(tid, hub_t, status)
            return {"task_id": tid, "status": "done", "progress": 100,
                    "detail": "", **final}
        except Exception as e:
            _logger.exception(f"[Song] 收尾失败 tid={tid}")
            raise HTTPException(500, f"成品处理失败：{e}")
    if status.get("status") == "error":
        _metrics["song_cover_failed"] = _metrics.get("song_cover_failed", 0) + 1
    return status


@app.post("/api/song/task/{tid}/cancel")
async def song_task_cancel(tid: str):
    try:
        r = await http_pool.post(f"{_song_base()}/v1/task/{tid}/cancel")
        return r.json() if r.status_code == 200 else {"ok": False}
    except Exception as e:
        raise HTTPException(503, f"翻唱引擎不可达：{e}")


@app.get("/api/song/task/{tid}/stem/{stem}")
async def song_task_stem(tid: str, stem: str):
    """转发干声/成品试听（引擎产物 6h 内有效；历史里存的是水印成品）。"""
    if stem not in ("result", "vocals"):
        raise HTTPException(400, "stem 仅支持 result / vocals")
    try:
        async with _aclient(timeout=httpx.Timeout(connect=5.0, read=300.0,
                                                  write=30.0, pool=5.0)) as c:
            r = await c.get(f"{_song_base()}/v1/task/{tid}/audio", params={"stem": stem})
    except Exception as e:
        raise HTTPException(503, f"翻唱引擎不可达：{e}")
    if r.status_code != 200:
        raise HTTPException(r.status_code, "产物不存在或已清理")
    return Response(content=r.content, media_type="audio/wav")


# ══════════════════════════════════════════════════════════════════
#  Song-P4/F3: 原创歌（ACE-Step 整曲文本成曲）
#  风格标签 + 结构化歌词（LLM 可辅写）→ ace_studio 生成整曲；
#  可选「用角色声唱」：生成曲再过一遍翻唱管线换成角色音色 ——
#  第二阶段完全复用 song_studio + _song_finalize（水印/历史/贴合度零新代码）。
#  编排状态机在 _ACE_TASKS：stage=gen（生成中）→ swap（换声中）→ final。
# ══════════════════════════════════════════════════════════════════
_ACE_TASKS: dict = {}


def _ace_base() -> str:
    return SERVICES["ace_studio"]


class SongCreateBody(BaseModel):
    style:      str                        # 风格标签："pop, mandarin, female vocal, 90 bpm"
    lyrics:     str = ""                   # [verse]/[chorus] 结构化歌词；空=纯音乐
    duration_s: float = 60.0
    quality:    str = "turbo"              # turbo=27步(秒级) / fine=60步(更细腻)
    seed:       Optional[int] = None       # 固定种子可复现同一首
    profile:    str = ""
    svc_swap:   bool = False               # 生成后用角色克隆声重唱
    song_name:  str = ""
    # P5/F5 风格魔改：以历史成品（翻唱/原创/念白皆可）为参考，按新风格重新编曲演绎
    remix_of:   Optional[int] = None       # 历史记录 id；成曲长度跟随参考段
    remix_strength: float = 0.5            # 0~1：越高越贴原曲结构，越低越放飞
    # P6 唱腔 LoRA（音乐人格）：引擎 capabilities.loras 里上报的目录名；空=基座原声
    lora:       str = ""
    lora_weight: float = 1.0


@app.post("/api/song/create")
async def song_create_submit(req: SongCreateBody):
    """提交原创歌任务。返回 task_id，进度经 /api/song/create/{tid} 轮询。"""
    profile_name = req.profile or _active_profile
    if req.profile:
        _check_profile_name(req.profile)
    style = (req.style or "").strip()
    if not style:
        raise HTTPException(400, "风格标签不能为空（例：pop, mandarin, female vocal, 90 bpm）")

    # 换声要角色克隆音——没有就提交前人话报错，别等生成完才失败
    ref_b64 = ""
    if req.svc_swap:
        async with _PROFILES_LOCK:
            ref_b64 = dict(_profiles.get(profile_name, {})).get("voice_b64", "")
        if not ref_b64:
            raise HTTPException(400, f"角色「{profile_name}」还没有克隆声音，"
                                     f"请先在克隆页录一段，或去掉「用角色声唱」选项")

    name = (req.song_name or "").strip()
    if not name:
        # 默认取第一句歌词做名（去掉 [verse] 等结构标记）
        for ln in (req.lyrics or "").splitlines():
            ln = ln.strip()
            if ln and not ln.startswith("["):
                name = ln[:24]
                break
        name = name or "未命名原创歌"

    # P5/F5 风格魔改：取历史音频做 audio2audio 参考。整曲太长时按副歌窗截段
    # （成曲长度跟随参考段——复用 MV 的副歌探测，截最有记忆点的部分来魔改）。
    ref_song_b64 = ""
    want_s = max(10.0, min(240.0, req.duration_s))
    if req.remix_of is not None:
        try:
            with _db_conn() as conn:
                row = conn.execute("SELECT audio_file, text FROM speak_history WHERE id=?",
                                   (req.remix_of,)).fetchone()
        except Exception as e:
            raise HTTPException(500, str(e))
        if not row or not row["audio_file"]:
            raise HTTPException(404, "参考历史记录不存在或音频已清理")
        fpath = HISTORY_AUDIO / row["audio_file"]
        if not fpath.exists():
            raise HTTPException(404, "参考音频文件已清理，没法魔改了")
        wav = fpath.read_bytes()
        src_s = _wav_duration_ms(wav) / 1000.0
        if src_s > want_s + 2.0:
            st0 = _pick_chorus_start(wav, want_s)
            try:
                wav = _cut_wav_segment(wav, st0, want_s)
            except Exception as e:
                raise HTTPException(400, f"参考音频截段失败：{e}")
        else:
            want_s = max(10.0, min(240.0, src_s))
        ref_song_b64 = base64.b64encode(wav).decode()
        if not name or name == "未命名原创歌":
            name = ((row["text"] or "").split("] ", 1)[-1] or "魔改")[:24]

    payload = {
        "prompt": style,
        "lyrics": (req.lyrics or "").strip(),
        "duration_s": want_s,
        "steps": 60 if req.quality == "fine" else 27,
        "seed": req.seed,
        "song_name": name,
        "ref_b64": ref_song_b64,
        "ref_strength": max(0.05, min(0.95, req.remix_strength)),
        "lora": (req.lora or "").strip(),        # P6: 唱腔 LoRA（引擎侧校验就绪名单）
        "lora_weight": max(0.0, min(1.0, req.lora_weight)),
    }
    try:
        async with _aclient(timeout=httpx.Timeout(connect=5.0, read=60.0,
                                                  write=60.0, pool=5.0)) as c:
            r = await c.post(f"{_ace_base()}/v1/create", json=payload)
    except Exception as e:
        raise HTTPException(503, f"原创歌引擎不可达：{e}")
    if r.status_code != 200:
        try:
            detail = r.json().get("detail", "")
        except Exception:
            detail = f"HTTP {r.status_code}"
        raise HTTPException(r.status_code, detail or "原创歌任务提交失败")
    tid = r.json().get("task_id", "")
    _mode = "remix" if req.remix_of is not None else "create"
    _ACE_TASKS[tid] = {
        "stage": "gen", "profile": profile_name, "song_name": name,
        "style": style, "svc_swap": bool(req.svc_swap), "ref_b64": ref_b64,
        "t0": time.time(), "cover_tid": None, "final": None,
        "gen_result": None,
        "mode": _mode,                                   # P5/F5: 魔改与原创同链不同标
        "hist_prefix": "[魔改]" if _mode == "remix" else "[原创]",
        "remix_of": req.remix_of,
        "lora": (req.lora or "").strip(),                # P6: 唱腔人格留痕（看板/历史可溯）
    }
    _task_persist("create", tid, _ACE_TASKS[tid])        # P5: Hub 重启不失忆
    _metrics["song_create_total"] = _metrics.get("song_create_total", 0) + 1
    _logger.info(f"[Song/create] {'魔改' if _mode == 'remix' else '原创歌'}提交 tid={tid} "
                 f"名={name!r} 风格={style[:60]!r} 时长={payload['duration_s']}s "
                 f"换声={req.svc_swap} remix_of={req.remix_of}"
                 + (f" lora={req.lora}" if req.lora else ""))
    return {"ok": True, "task_id": tid}


# ── Song-P6 批量魔改（专辑化运营）：一首歌 × N 风格一键出 ────────────────────
class RemixBatchStyle(BaseModel):
    style: str                              # 风格标签串
    label: str = ""                         # 成品名后缀（如「摇滚」）；空=取风格首词


class SongRemixBatchBody(BaseModel):
    history_id: int                         # 参考历史成品
    styles: list[RemixBatchStyle]           # 1~6 组风格
    remix_strength: float = 0.5
    quality: str = "turbo"
    profile: str = ""
    song_name: str = ""                     # 基础名；空=取历史标题
    lora: str = ""                          # 可选唱腔 LoRA（全批生效）


@app.post("/api/song/remix_batch")
async def song_remix_batch(req: SongRemixBatchBody):
    """批量魔改：同一首参考歌，N 种风格各出一版（短视频矩阵素材流水线）。
    逐风格复用单条提交路径（副歌截段/校验/持久化零新代码）；引擎侧单工人
    串行消化，队列语义与让路协议天然生效。部分失败如实回报，不整批砸。"""
    if not req.styles:
        raise HTTPException(400, "至少给一组风格")
    if len(req.styles) > 6:
        raise HTTPException(400, "一批最多 6 个风格（引擎串行消化，太多会占住队列）")
    base_name = (req.song_name or "").strip()
    if not base_name:
        # 必须给每版起不同名：历史入库按(角色,文本)24h 去重，同名 N 版会互相覆盖只剩一条
        try:
            with _db_conn() as conn:
                row = conn.execute("SELECT text FROM speak_history WHERE id=?",
                                   (req.history_id,)).fetchone()
            base_name = (((row["text"] if row else "") or "").split("] ", 1)[-1]
                         or "魔改")[:20]
        except Exception:
            base_name = "魔改"
    tasks, errors = [], []
    seen_names: set = set()
    for i, s in enumerate(req.styles):
        style = (s.style or "").strip()
        if not style:
            errors.append({"idx": i, "error": "风格为空"})
            continue
        label = (s.label or "").strip() or style.split(",")[0].strip()[:12]
        name = f"{base_name}·{label}"
        if name in seen_names:                     # 重复风格标签 → 加序号保唯一
            name = f"{name}{i + 1}"
        seen_names.add(name)
        try:
            r = await song_create_submit(SongCreateBody(
                style=style, duration_s=30.0, quality=req.quality,
                profile=req.profile, song_name=name,
                remix_of=req.history_id,
                remix_strength=req.remix_strength,
                lora=req.lora))
            tasks.append({"task_id": r["task_id"], "label": label, "style": style,
                          "song_name": name})
        except HTTPException as he:
            errors.append({"idx": i, "label": label, "error": str(he.detail)})
        except Exception as e:
            errors.append({"idx": i, "label": label, "error": str(e)[:120]})
    if not tasks:
        raise HTTPException(400, f"整批提交失败：{errors}")
    _metrics["song_remix_batch"] = _metrics.get("song_remix_batch", 0) + 1
    _logger.info(f"[Song/remix_batch] hist={req.history_id} 提交 {len(tasks)}/{len(req.styles)} 风格"
                 + (f"（失败 {len(errors)}）" if errors else ""))
    return {"ok": True, "tasks": tasks, "errors": errors}


async def _ace_finalize_direct(tid: str, t: dict, result: dict) -> dict:
    """纯生成（不换声）的收尾：取回成品 → 水印 → 历史入库。幂等（收尾锁防
    前端轮询与后台对账并发）。没有参考歌手，不做贴合度评分（诚实：没有比较对象）。"""
    if t.get("final"):
        return t["final"]
    async with _finalize_lock(tid):
        if t.get("final"):
            return t["final"]
        return await _ace_finalize_direct_locked(tid, t, result)


def _lora_hist_tag(lora: str) -> str:
    """唱腔 LoRA 的历史文本标记：同名曲基座版/唱腔版是不同成品，不带标记会被
    24h 去重合并只剩一条（P5 已知边界）。短标可读：中文RAP官方包→（RAP腔）。"""
    if not lora:
        return ""
    return "（RAP腔）" if "rap" in lora.lower() else f"（{lora[:10]}腔）"


async def _ace_finalize_direct_locked(tid: str, t: dict, result: dict) -> dict:
    async with _aclient(timeout=httpx.Timeout(connect=5.0, read=300.0,
                                              write=30.0, pool=5.0)) as c:
        r = await c.get(f"{_ace_base()}/v1/task/{tid}/audio")
        r.raise_for_status()
        mix_bytes = r.content

    _mode = t.get("mode", "create")
    _prefix = t.get("hist_prefix", "[原创]")
    out_bytes = mix_bytes
    if PROVENANCE_ENABLED and _provenance is not None:
        try:
            _res = _provenance.attach_credentials(
                mix_bytes, model="ace_step", profile=t["profile"],
                ai_generated=True,
                extra={"mode": _mode, "song": t["song_name"],
                       "style": t.get("style", "")[:120]})
            if _res.get("ok"):
                out_bytes = _res["audio_bytes"]
        except Exception as _we:
            _logger.warning(f"[Song/create] 水印跳过: {_we}")
    out_b64 = base64.b64encode(out_bytes).decode()

    elapsed = int((time.time() - t["t0"]) * 1000)
    hist_id = None
    _ltag = _lora_hist_tag(t.get("lora") or result.get("lora") or "")
    try:
        hist_id = await asyncio.get_running_loop().run_in_executor(
            _history_executor, _write_history,
            t["profile"], f"{_prefix} {t['song_name']}{_ltag}", "zh",
            out_b64, elapsed, False, False, "sing")
        await broadcast({"event": "history_updated"})
    except Exception as _he:
        _logger.warning(f"[Song/create] 历史入库跳过: {_he}")

    final = {
        "engine_used": "ace_step",
        "history_id": hist_id,
        "audio_url": f"/api/history/{hist_id}/audio.wav" if hist_id else "",
        "similarity": None,
        "duration_s": result.get("duration_s"),
        "seed": result.get("seed"),
        "timings": result.get("timings", {}),
        "elapsed_ms": elapsed,
        "rtf": result.get("rtf"),
        "singer": "ACE-Step 原声",
        "lora": result.get("lora"),          # P6: 唱腔人格溯源（None=基座）
    }
    t["final"] = final
    _task_persist("create", tid, t)          # P5: 终态落库（重启回载不再重跑）
    _metrics["song_create_done"] = _metrics.get("song_create_done", 0) + 1
    _logger.info(f"[Song/create] {'魔改' if t.get('mode') == 'remix' else '原创歌'}完成 "
                 f"tid={tid} hist={hist_id} "
                 f"gen={result.get('timings', {}).get('generate_ms')}ms")
    return final


async def _ace_start_swap(tid: str, t: dict) -> None:
    """gen 完成 → 取回生成曲，提交换声（翻唱管线，参考=角色克隆音）。
    P5: 重启回载的任务 ref_b64 已剥离 → 按角色名回取（没有克隆音再人话报错）。"""
    ref_b64 = await _task_refetch_ref(t)
    if not ref_b64:
        raise RuntimeError(f"角色「{t.get('profile', '')}」的克隆声音取不到了"
                           f"（可能已删除），换声无法进行")
    async with _aclient(timeout=httpx.Timeout(connect=5.0, read=300.0,
                                              write=120.0, pool=5.0)) as c:
        r = await c.get(f"{_ace_base()}/v1/task/{tid}/audio")
        r.raise_for_status()
        song_b64 = base64.b64encode(r.content).decode()
        payload = {
            "song_b64": song_b64,
            "reference_b64": ref_b64,
            "song_name": t["song_name"],
            "pitch_shift": None,             # 自动升降调
            "diffusion_steps": 30,
            "sep_overlap": 0,
            "sep_model": "auto",
        }
        r2 = await c.post(f"{_song_base()}/v1/cover", json=payload)
    if r2.status_code != 200:
        try:
            detail = r2.json().get("detail", f"HTTP {r2.status_code}")
        except Exception:
            detail = f"HTTP {r2.status_code}"
        raise RuntimeError(f"换声提交失败：{detail}")
    cover_tid = r2.json().get("task_id", "")
    # 挂进翻唱登记表 → 收尾（水印/历史/贴合度）完全复用；前缀/引擎标记定制
    _SONG_TASKS[cover_tid] = {
        "profile": t["profile"],
        "song_name": f"{t['song_name']}{_lora_hist_tag(t.get('lora') or '')}（角色演唱）",
        "ref_b64": ref_b64, "ref_label": t["profile"], "t0": t["t0"],
        "processed": False, "final": None,
        "hist_prefix": t.get("hist_prefix", "[原创]"),   # P5/F5: 魔改换声=[魔改]
        "engine_label": "ace_step+yingmusic_svc",
        "mode": f"{t.get('mode', 'create')}_swap",
    }
    t["cover_tid"] = cover_tid
    t["ref_b64"] = ""                        # 已交接给翻唱登记表，释放一份
    t["stage"] = "swap"
    _task_persist("cover", cover_tid, _SONG_TASKS[cover_tid])
    _task_persist("create", tid, t)          # P5: 阶段跳变落库（重启续 swap 轮询）
    _logger.info(f"[Song/create] 生成完成 → 换声开始 tid={tid} cover={cover_tid}")


@app.get("/api/song/create/{tid}")
async def song_create_status(tid: str):
    """原创歌进度轮询：gen（生成 0~50%）→ swap（换声 50~100%，仅勾了换声）→ done。
    完成时收尾（水印+历史+贴合度）并缓存，与翻唱同权。"""
    t = _ACE_TASKS.get(tid)
    if t and t.get("final"):
        return {"task_id": tid, "status": "done", "progress": 100,
                "detail": "", "stage": t["stage"], **t["final"]}
    if t is None:
        raise HTTPException(404, "任务不存在或已过期")

    if t["stage"] == "gen":
        try:
            r = await http_pool.get(f"{_ace_base()}/v1/task/{tid}")
        except Exception as e:
            raise HTTPException(503, f"原创歌引擎不可达：{e}")
        if r.status_code != 200:
            try:
                detail = r.json().get("detail", f"HTTP {r.status_code}")
            except Exception:
                detail = f"HTTP {r.status_code}"
            raise HTTPException(r.status_code, detail)
        st = r.json()
        if st.get("status") == "error":
            _metrics["song_create_failed"] = _metrics.get("song_create_failed", 0) + 1
            return {"task_id": tid, "status": "error", "progress": 0,
                    "detail": st.get("detail", "生成失败"), "stage": "gen"}
        if st.get("status") == "cancelled":
            return {"task_id": tid, "status": "cancelled", "progress": 0,
                    "detail": "已取消", "stage": "gen"}
        if st.get("status") == "done":
            t["gen_result"] = st.get("result") or {}
            if not t["svc_swap"]:
                try:
                    final = await _ace_finalize_direct(tid, t, t["gen_result"])
                    return {"task_id": tid, "status": "done", "progress": 100,
                            "detail": "", "stage": "gen", **final}
                except Exception as e:
                    _logger.exception(f"[Song/create] 收尾失败 tid={tid}")
                    raise HTTPException(500, f"成品处理失败：{e}")
            # svc_swap: gen 结果先落库再交接换声（重启后不用重新生成）
            _task_persist("create", tid, t)
            if not t.get("cover_tid"):
                try:
                    await _ace_start_swap(tid, t)
                except Exception as e:
                    _logger.exception(f"[Song/create] 换声提交失败 tid={tid}")
                    return {"task_id": tid, "status": "error", "progress": 50,
                            "detail": str(e), "stage": "swap"}
            return {"task_id": tid, "status": "converting", "progress": 52,
                    "detail": "整曲已生成，正在用角色声音重唱", "stage": "swap"}
        # 生成中：换声任务把 gen 映射到 0~50%，纯生成 0~100%
        prog = int(st.get("progress", 0))
        out_prog = prog // 2 if t["svc_swap"] else prog
        return {"task_id": tid, "status": st.get("status", "queued"),
                "progress": max(2, out_prog), "detail": st.get("detail", ""),
                "stage": "gen", "queue_ahead": st.get("queue_ahead")}

    # stage == "swap"：轮询翻唱引擎，完成走 _song_finalize（全套收尾复用）
    cover_tid = t.get("cover_tid", "")
    hub_t = _SONG_TASKS.get(cover_tid)
    try:
        r = await http_pool.get(f"{_song_base()}/v1/task/{cover_tid}")
    except Exception as e:
        raise HTTPException(503, f"翻唱引擎不可达：{e}")
    if r.status_code != 200:
        try:
            detail = r.json().get("detail", f"HTTP {r.status_code}")
        except Exception:
            detail = f"HTTP {r.status_code}"
        raise HTTPException(r.status_code, detail)
    st = r.json()
    if st.get("status") == "error":
        _metrics["song_create_failed"] = _metrics.get("song_create_failed", 0) + 1
        return {"task_id": tid, "status": "error", "progress": 50,
                "detail": f"换声失败：{st.get('detail', '')}", "stage": "swap"}
    if st.get("status") == "cancelled":
        return {"task_id": tid, "status": "cancelled", "progress": 50,
                "detail": "已取消", "stage": "swap"}
    if st.get("status") == "done" and hub_t is not None:
        try:
            final = await _song_finalize(cover_tid, hub_t, st)
        except Exception as e:
            _logger.exception(f"[Song/create] 换声收尾失败 tid={tid}")
            raise HTTPException(500, f"成品处理失败：{e}")
        final = dict(final)
        final["gen_timings"] = (t.get("gen_result") or {}).get("timings", {})
        final["seed"] = (t.get("gen_result") or {}).get("seed")
        t["final"] = final
        _task_persist("create", tid, t)                  # P5: 终态落库
        _metrics["song_create_done"] = _metrics.get("song_create_done", 0) + 1
        return {"task_id": tid, "status": "done", "progress": 100,
                "detail": "", "stage": "swap", **final}
    prog = 52 + int(st.get("progress", 0)) * 48 // 100
    return {"task_id": tid, "status": "converting", "progress": min(99, prog),
            "detail": st.get("detail", "") or "正在用角色声音重唱", "stage": "swap"}


@app.post("/api/song/create/{tid}/cancel")
async def song_create_cancel(tid: str):
    """取消原创歌任务（gen 阶段取消生成；swap 阶段取消换声）。"""
    t = _ACE_TASKS.get(tid)
    if t is None:
        raise HTTPException(404, "任务不存在或已过期")
    try:
        if t["stage"] == "gen":
            r = await http_pool.post(f"{_ace_base()}/v1/task/{tid}/cancel")
        else:
            r = await http_pool.post(
                f"{_song_base()}/v1/task/{t.get('cover_tid', '')}/cancel")
        return r.json() if r.status_code == 200 else {"ok": False}
    except Exception as e:
        raise HTTPException(503, f"引擎不可达：{e}")


class LyricsAssistBody(BaseModel):
    topic: str                              # 主题/心情/关键词
    style: str = ""                         # 风格标签（帮 LLM 对齐节奏感）
    duration_s: float = 60.0


@app.post("/api/song/lyrics_assist")
async def song_lyrics_assist(req: LyricsAssistBody):
    """LLM 辅写歌词：主题 → [verse]/[chorus] 结构化歌词（ACE-Step 直接可用）。
    没配 LLM 就 503 人话提示（前端可手写歌词，功能不硬依赖）。"""
    topic = (req.topic or "").strip()
    if not topic:
        raise HTTPException(400, "先说说想唱什么主题（如：写给加班后的自己）")
    if _conv is None or _conv.registry.default_llm is None:
        raise HTTPException(503, "还没配置对话大模型，无法帮写歌词——请手写歌词，或先在对话页配置 LLM")
    llm = _conv.registry.get_llm(_conv.registry.default_llm)
    if llm is None:
        raise HTTPException(503, "对话大模型不可用，请手写歌词")
    dur = max(10.0, min(240.0, req.duration_s))
    n_sections = "一段主歌+一段副歌" if dur <= 75 else "两段主歌+两段副歌（副歌重复）"
    sys_prompt = (
        "你是中文流行歌词作者。按用户主题写一首可唱的歌词，要求：\n"
        f"1. 结构：{n_sections}，段前分别标 [verse] 和 [chorus]（英文方括号标记独占一行）；\n"
        "2. 每段 4 行左右，每行 6~12 字，口语化、有画面感，避免生僻字与陈词滥调；\n"
        "3. 副歌要朗朗上口、情绪浓；\n"
        "4. 只输出歌词本体（含结构标记），不要标题、注释或任何多余文字。")
    user_msg = f"主题：{topic}" + (f"\n风格参考：{req.style}" if req.style else "")
    parts: list = []
    try:
        async for tok in llm.stream(
                [{"role": "system", "content": sys_prompt},
                 {"role": "user", "content": user_msg}],
                max_tokens=500, temperature=0.85):
            parts.append(tok)
    except Exception as e:
        raise HTTPException(503, f"歌词生成失败：{e}")
    lyrics = "".join(parts).strip()
    if len(lyrics) < 20 or "[" not in lyrics:
        raise HTTPException(502, "大模型这次没写好（输出不含结构标记），请再试一次或手写")
    _logger.info(f"[Song/lyrics] 辅写完成 主题={topic!r} {len(lyrics)}字")
    return {"ok": True, "lyrics": lyrics}


# ══════════════════════════════════════════════════════════════════
#  Song-P2/F1: 直播间点歌台
#  观众（弹幕/公屏）或运营者点歌 → 队列 → 自动备歌（翻唱管线）→ 一键上麦。
#  - 曲库 = songs/ 目录（运营者放歌）；弹幕点歌按文件名模糊匹配，不匹配不入队（防滥点）
#  - 备歌 Hub 侧串行（GPU 串行由 song_studio 保证；一次备一首，队头不误判阻塞）
#  - 成品与手动翻唱同权：水印 + 历史入库 + 贴合度（复用 _song_finalize），重启后靠 hist_id 仍可播
#  - 上麦 = vcam /play_audio（待机脸不变，OBS 桌面声 + WebRTC 音轨），/stop_audio 切歌
# ══════════════════════════════════════════════════════════════════

SONGS_DIR = Path(rf"{_BASE}\songs")
SONGS_DIR.mkdir(exist_ok=True)
_STATION_STATE_FILE = SONGS_DIR / "station_state.json"
_STATION_AUDIO_EXTS = (".wav", ".mp3", ".flac", ".m4a", ".ogg", ".aac")
_STATION_MAX_Q = int(os.environ.get("SONG_STATION_MAX_Q", "30"))
_STATION_CHAT_COOLDOWN_S = float(os.environ.get("SONG_STATION_CHAT_COOLDOWN_S", "120"))

_station = {
    "enabled": False,          # 点歌台总开关
    "chat_enabled": True,      # 弹幕/公屏点歌入口
    "auto_prepare": True,      # 队列自动备歌
    "auto_play": False,        # 一首播完自动接播下一首就绪曲目
    "announce": False,         # P3: 上麦前角色开口播报「感谢 xx 点的歌」（现成 TTS+口型链）
    "quality": "standard",     # 备歌质量档
    "playing_id": None,        # 正在上麦的点歌 id
    "gift_min_value": 0.0,     # P5: 礼物插队价值门槛（0=不设门槛；低于门槛只谢不插队）
}
_station_reqs: dict = {}       # rid(int) → 点歌请求（dict 保序即队列顺序）
_station_seq = 0
_station_worker_task = None
_station_chat_last: dict = {}  # 点歌人 → 上次成功点歌时刻（防刷屏）


def _station_next_id() -> int:
    global _station_seq
    _station_seq += 1
    return _station_seq


def _station_save():
    """轻量快照：设置 + 队列（progress 等瞬态不存；preparing 重启后回 queued 重备）。"""
    try:
        reqs = []
        for r in _station_reqs.values():
            c = {k: r.get(k) for k in ("id", "song_name", "file", "requester", "source",
                                       "status", "hist_id", "audio_url", "pitch",
                                       "profile", "created", "duration_s", "error",
                                       "gift_value")}
            if c["status"] in ("preparing", "playing"):
                c["status"] = "queued" if c["status"] == "preparing" else "ready"
            reqs.append(c)
        cfg = {k: _station[k] for k in ("enabled", "chat_enabled", "auto_prepare",
                                        "auto_play", "announce", "quality",
                                        "gift_min_value")}
        _STATION_STATE_FILE.write_text(
            json.dumps({"station": cfg, "requests": reqs, "seq": _station_seq},
                       ensure_ascii=False), encoding="utf-8")
    except Exception as _e:
        _logger.debug(f"[Station] 快照落盘跳过: {_e}")


def _station_load():
    global _station_seq
    try:
        if not _STATION_STATE_FILE.exists():
            return
        d = json.loads(_STATION_STATE_FILE.read_text(encoding="utf-8"))
        _station.update({k: v for k, v in (d.get("station") or {}).items()
                         if k in _station})
        _station["playing_id"] = None          # 播放态不跨重启
        _station_seq = int(d.get("seq", 0))
        for r in d.get("requests", []):
            if r.get("id"):
                r.setdefault("progress", 0)
                r.setdefault("detail", "")
                r.setdefault("task_id", "")
                r.setdefault("similarity", None)
                _station_reqs[int(r["id"])] = r
    except Exception as _e:
        print(f"[Hub] 点歌台状态恢复跳过: {_e}")


_station_load()


def _station_lib() -> list:
    """曲库清单（songs/ 下的音频文件）。"""
    out = []
    try:
        for f in sorted(SONGS_DIR.iterdir()):
            if f.is_file() and f.suffix.lower() in _STATION_AUDIO_EXTS:
                out.append({"file": f.name, "name": f.stem,
                            "size_mb": round(f.stat().st_size / 1024 / 1024, 1)})
    except Exception:
        pass
    return out


def _station_norm(s: str) -> str:
    return re.sub(r"[\s\W_]+", "", (s or "").lower())


def _station_match_song(query: str) -> Optional[dict]:
    """弹幕点歌 → 曲库模糊匹配：子串优先，其次 difflib 近似（cutoff 0.6）。"""
    q = _station_norm(query)
    if not q:
        return None
    lib = _station_lib()
    subs = [it for it in lib
            if q in _station_norm(it["name"]) or _station_norm(it["name"]) in q]
    if subs:
        return min(subs, key=lambda it: abs(len(_station_norm(it["name"])) - len(q)))
    import difflib
    names = {_station_norm(it["name"]): it for it in lib}
    hit = difflib.get_close_matches(q, list(names.keys()), n=1, cutoff=0.6)
    return names[hit[0]] if hit else None


_STATION_CHAT_RE = re.compile(r"^\s*(?:点歌|點歌|唱首|来一首|來一首|唱一首|point\s*song)[\s:：,，]*(.+)$",
                              re.IGNORECASE)


def _station_parse_chat(text: str) -> Optional[str]:
    m = _STATION_CHAT_RE.match(text or "")
    return m.group(1).strip() if m else None


def _station_broadcast(event: str = "song_station", **extra):
    try:
        _t = asyncio.create_task(broadcast({"event": event, **extra}))
        _t.add_done_callback(lambda t: t.exception() if not t.cancelled() else None)
    except Exception:
        pass


def _station_enqueue(item: dict, requester: str, source: str,
                     pitch: str = "auto") -> dict:
    """入队公共路径（运营者/弹幕共用）。返回 {ok, id?, reason?}。"""
    pending = [r for r in _station_reqs.values()
               if r["status"] in ("queued", "preparing", "ready", "playing")]
    if len(pending) >= _STATION_MAX_Q:
        return {"ok": False, "reason": f"点歌队列已满（{_STATION_MAX_Q} 首）"}
    dup = next((r for r in pending if r.get("file") == item["file"]), None)
    if dup is not None:
        return {"ok": False, "reason": f"《{item['name']}》已在队列（#{dup['id']}），别重复点啦",
                "dup_id": dup["id"]}
    rid = _station_next_id()
    _station_reqs[rid] = {
        "id": rid, "song_name": item["name"], "file": item["file"],
        "requester": requester or "现场观众", "source": source,
        "status": "queued", "progress": 0, "detail": "排队等备歌",
        "task_id": "", "hist_id": None, "audio_url": "", "similarity": None,
        "pitch": pitch, "profile": _active_profile, "error": "",
        "created": time.time(), "duration_s": None,
    }
    _station_save()
    _station_kick()
    _station_broadcast(action="enqueued", id=rid)
    _logger.info(f"[Station] 点歌入队 #{rid}《{item['name']}》by {requester or '匿名'}({source})")
    return {"ok": True, "id": rid, "song_name": item["name"],
            "position": sum(1 for r in _station_reqs.values()
                            if r["status"] in ("queued", "preparing"))}


async def _station_prepare(req: dict):
    """备歌一首：曲库文件 → 翻唱引擎 → 完成收尾（水印+历史+贴合度，复用 _song_finalize）。"""
    rid = req["id"]
    fpath = SONGS_DIR / (req.get("file") or "")
    if not fpath.exists():
        req.update(status="failed", error="曲库文件不见了（可能被移走）", detail="")
        _station_save()
        _station_broadcast(action="failed", id=rid)
        return
    profile_name = req.get("profile") or _active_profile
    async with _PROFILES_LOCK:
        ref_b64 = dict(_profiles.get(profile_name, {})).get("voice_b64", "")
    if not ref_b64:
        req.update(status="failed", detail="",
                   error=f"角色「{profile_name}」没有克隆音，先去克隆页录一段")
        _station_save()
        _station_broadcast(action="failed", id=rid)
        return

    try:
        pitch_shift = (None if str(req.get("pitch", "auto")).strip() in ("", "auto")
                       else max(-12, min(12, int(req["pitch"]))))
    except ValueError:
        pitch_shift = None
    quality = _station.get("quality", "standard")
    payload = {
        "song_b64": base64.b64encode(fpath.read_bytes()).decode(),
        "reference_b64": ref_b64,
        "song_name": req["song_name"],
        "pitch_shift": pitch_shift,
        "diffusion_steps": 50 if quality == "fine" else 30,
        "skip_separation": False,
        "sep_overlap": 4 if quality == "fine" else 0,
    }
    req.update(status="preparing", progress=2, detail="提交翻唱引擎…")
    _station_broadcast(action="preparing", id=rid)
    try:
        async with _aclient(timeout=httpx.Timeout(connect=5.0, read=120.0,
                                                  write=120.0, pool=5.0)) as c:
            r = await c.post(f"{_song_base()}/v1/cover", json=payload)
        if r.status_code != 200:
            raise RuntimeError(r.json().get("detail", f"HTTP {r.status_code}"))
        tid = r.json().get("task_id", "")
    except Exception as e:
        req.update(status="failed", error=f"提交失败：{e}", detail="")
        _station_save()
        _station_broadcast(action="failed", id=rid)
        return
    req["task_id"] = tid
    _SONG_TASKS[tid] = {                     # 挂进翻唱登记表 → 收尾链路完全复用
        "profile": profile_name, "song_name": req["song_name"],
        "ref_b64": ref_b64, "ref_label": profile_name, "t0": time.time(),
        "processed": False, "final": None,
    }
    _task_persist("cover", tid, _SONG_TASKS[tid])
    _metrics["song_station_prepared"] = _metrics.get("song_station_prepared", 0) + 1

    fails = 0
    while True:
        await asyncio.sleep(2.5)
        if req.get("status") == "cancelled":         # 运营者取消：同步撤引擎任务
            try:
                await http_pool.post(f"{_song_base()}/v1/task/{tid}/cancel")
            except Exception:
                pass
            return
        try:
            r = await http_pool.get(f"{_song_base()}/v1/task/{tid}")
            if r.status_code == 404:
                raise RuntimeError("任务过期")
            st = r.json()
            fails = 0
        except Exception as e:
            fails += 1
            if fails >= 12:                          # 30s 连续失联才判失败
                req.update(status="failed", error=f"引擎失联：{e}", detail="")
                _station_save()
                _station_broadcast(action="failed", id=rid)
                return
            continue
        s = st.get("status", "")
        req["progress"] = st.get("progress", req["progress"])
        req["detail"] = st.get("detail", "")
        if s == "done":
            try:
                final = await _song_finalize(tid, _SONG_TASKS[tid], st)
            except Exception as e:
                req.update(status="failed", error=f"成品处理失败：{e}", detail="")
                _station_save()
                _station_broadcast(action="failed", id=rid)
                return
            req.update(status="ready", progress=100, detail="",
                       hist_id=final.get("history_id"),
                       audio_url=final.get("audio_url", ""),
                       similarity=final.get("similarity"),
                       duration_s=final.get("duration_s"))
            _station_save()
            _station_broadcast(action="ready", id=rid)
            _logger.info(f"[Station] 备歌完成 #{rid}《{req['song_name']}》hist={req['hist_id']}")
            # P6 全自动闭环：开了自动连播且此刻没歌在播 → 就绪即自动上麦
            # （原 auto_play 只在「播完接下一首」时触发，冷启动第一首仍要人点——补上这块，
            #   点歌→备歌→上麦→连播全程无人值守）。失败不砸备歌结果，人工仍可点播。
            if _station.get("auto_play") and _station["enabled"] and not _station.get("playing_id"):
                try:
                    await _station_do_play(req)
                    _logger.info(f"[Station] 自动上麦(就绪即播) #{rid}《{req['song_name']}》")
                except Exception as _ape:
                    _logger.warning(f"[Station] 就绪自动上麦失败(可人工点播): {_ape}")
            return
        if s in ("error", "cancelled"):
            req.update(status="failed", error=st.get("detail") or "引擎处理失败", detail="")
            _station_save()
            _station_broadcast(action="failed", id=rid)
            return
        if s == "queued":
            req["detail"] = st.get("detail") or "翻唱引擎排队中"


async def _station_worker():
    """备歌 worker：串行消化 queued 队列；空队/关台即退。"""
    global _station_worker_task
    try:
        while _station["enabled"] and _station["auto_prepare"]:
            nxt = next((r for r in _station_reqs.values() if r["status"] == "queued"), None)
            if nxt is None:
                return
            await _station_prepare(nxt)
    finally:
        _station_worker_task = None
        # 收尾竞态兜底：退出瞬间又有新 queued 且开关仍开 → 重新拉起
        if (_station["enabled"] and _station["auto_prepare"]
                and any(r["status"] == "queued" for r in _station_reqs.values())):
            _station_kick()


def _station_kick():
    global _station_worker_task
    if not (_station["enabled"] and _station["auto_prepare"]):
        return
    if _station_worker_task is None or _station_worker_task.done():
        try:
            _station_worker_task = asyncio.create_task(_station_worker())
        except RuntimeError:
            pass                                     # 无事件循环（导入期），启动后首次操作再拉


_station_autoplay_busy = False   # 防抖：并发快照拉取只允许一个兜底上麦在途


def _station_autoplay_kick():
    """P6: auto_play 兜底扫描（_station_kick 同构的自愈模式）。
    主路径是备歌完成瞬间直接上麦（_station_prepare done 分支）；这里补两个
    事件驱动盲区：①Hub 重启恢复出 ready 条目（没有新 done 事件）；
    ②歌先备好、auto_play 后打开。台开+连播开+没在播+有 ready → 上麦最早一首。"""
    global _station_autoplay_busy
    if not (_station["enabled"] and _station.get("auto_play")):
        return
    if _station.get("playing_id") or _station_autoplay_busy:
        return
    nxt = next((r for r in _station_reqs.values() if r["status"] == "ready"), None)
    if nxt is None:
        return

    async def _go():
        global _station_autoplay_busy
        try:
            if _station.get("playing_id") or nxt["status"] != "ready":
                return                               # 竞态再查：已被人工点播/播上了
            await _station_do_play(nxt)
            _logger.info(f"[Station] 自动上麦(兜底扫描) #{nxt['id']}《{nxt['song_name']}》")
        except Exception as e:
            _logger.warning(f"[Station] 兜底自动上麦失败(可人工点播): {e}")
        finally:
            _station_autoplay_busy = False

    try:
        _station_autoplay_busy = True
        _t = asyncio.create_task(_go())
        _t.add_done_callback(lambda t: t.exception() if not t.cancelled() else None)
    except RuntimeError:
        _station_autoplay_busy = False               # 无事件循环（导入期）


def _station_snapshot() -> dict:
    return {
        **{k: _station[k] for k in ("enabled", "chat_enabled", "auto_prepare",
                                    "auto_play", "announce", "quality", "playing_id")},
        "queue": list(_station_reqs.values()),
        "library": _station_lib(),
        "yield": _song_yield_state(),   # P3/O6: 直播让路状态（前端提示为什么备歌暂停）
        "chat_hint": "弹幕发「点歌 歌名」即可（也支持 POST /api/song/station/chat 接外部弹幕桥）",
    }


@app.get("/api/song/station")
async def api_station_state():
    """点歌台全量快照：设置 + 队列 + 曲库。
    顺手自愈：重启恢复出的 queued 条目没有事件驱动 → 首次快照拉取即拉起备歌 worker；
    ready 条目同理 → auto_play 兜底扫描补上麦（P6）。
    必须 async def：同步 def 进 FastAPI 线程池，asyncio.create_task 无 loop
    直接 RuntimeError 被吞——两个 kick 都会变静默 no-op（P6 真跑抓到的坑）。"""
    _station_kick()
    _station_autoplay_kick()
    return _station_snapshot()


@app.post("/api/song/station/config")
async def api_station_config(body: dict = Body(...)):
    """更新点歌台开关/质量档。开启+有队列即自动开备。"""
    for k in ("enabled", "chat_enabled", "auto_prepare", "auto_play", "announce"):
        if k in body:
            _station[k] = bool(body[k])
    if body.get("quality") in ("standard", "fine"):
        _station["quality"] = body["quality"]
    if "gift_min_value" in body:               # P5: 礼物插队门槛
        try:
            _station["gift_min_value"] = max(0.0, float(body["gift_min_value"]))
        except (TypeError, ValueError):
            pass
    _station_save()
    _station_kick()
    _station_autoplay_kick()      # P6: 刚打开 auto_play 且已有 ready → 立即补上麦
    _station_broadcast(action="config")
    return {"ok": True, **{k: _station[k] for k in
                           ("enabled", "chat_enabled", "auto_prepare", "auto_play",
                            "announce", "quality", "gift_min_value")}}


@app.get("/api/song/library")
def api_song_library():
    """曲库清单（songs/ 目录）。运营者往里放歌文件即可被点。"""
    return {"songs_dir": str(SONGS_DIR), "items": _station_lib()}


class StationRequestBody(BaseModel):
    file: str                       # 曲库文件名
    requester: str = ""
    pitch: str = "auto"


@app.post("/api/song/station/request")
async def api_station_request(req: StationRequestBody):
    """运营者从曲库点歌入队。"""
    if not _station["enabled"]:
        raise HTTPException(400, "点歌台未开启，先在唱歌页打开开关")
    fname = os.path.basename(req.file or "")
    fpath = SONGS_DIR / fname
    if not fname or not fpath.exists():
        raise HTTPException(404, "曲库里没有这首歌")
    r = _station_enqueue({"file": fname, "name": fpath.stem},
                         req.requester or "主播", "op", pitch=req.pitch)
    if not r.get("ok"):
        raise HTTPException(409, r.get("reason", "入队失败"))
    return r


class StationChatBody(BaseModel):
    text: str
    name: str = ""


@app.post("/api/song/station/chat")
async def api_station_chat(req: StationChatBody):
    """弹幕点歌入口（外部弹幕桥 POST 到这里）。识别「点歌 歌名」→ 曲库匹配 → 入队。
    非点歌弹幕返回 matched=false（不报错，方便桥端全量转发）。"""
    if not (_station["enabled"] and _station["chat_enabled"]):
        return {"ok": False, "matched": False, "reason": "点歌台未开启"}
    q = _station_parse_chat(req.text)
    if not q:
        return {"ok": False, "matched": False}
    who = (req.name or "").strip() or "现场观众"
    now = time.time()
    if now - _station_chat_last.get(who, 0) < _STATION_CHAT_COOLDOWN_S:
        return {"ok": False, "matched": True,
                "reason": f"{who} 点太快啦，{int(_STATION_CHAT_COOLDOWN_S)}s 内只能点一首"}
    item = _station_match_song(q)
    if item is None:
        return {"ok": False, "matched": True, "reason": f"曲库里没找到《{q}》"}
    r = _station_enqueue(item, who, "chat")
    if r.get("ok"):
        _station_chat_last[who] = now
        _metrics["song_station_chat_hits"] = _metrics.get("song_station_chat_hits", 0) + 1
    return {"matched": True, **r}


@app.post("/api/song/station/{rid}/cancel")
async def api_station_cancel(rid: int):
    r = _station_reqs.get(rid)
    if r is None:
        raise HTTPException(404, "点歌不存在")
    if r["status"] in ("done", "cancelled"):
        return {"ok": True, "status": r["status"]}
    was = r["status"]
    r.update(status="cancelled", detail="")
    if was == "playing":
        await _station_stop_playback()
    _station_save()
    _station_broadcast(action="cancelled", id=rid)
    return {"ok": True}


def _station_top_queued(rid: int) -> bool:
    """把排队中的点歌移到所有排队曲目最前。非 queued 返回 False。"""
    r = _station_reqs.get(rid)
    if r is None or r["status"] != "queued":
        return False
    items = list(_station_reqs.items())
    items.remove((rid, r))
    pos = next((i for i, (_, x) in enumerate(items) if x["status"] == "queued"), len(items))
    items.insert(pos, (rid, r))
    _station_reqs.clear()
    _station_reqs.update(items)
    return True


@app.post("/api/song/station/{rid}/top")
async def api_station_top(rid: int):
    """插队置顶（移到所有排队曲目最前）。"""
    if _station_reqs.get(rid) is None:
        raise HTTPException(404, "点歌不存在")
    if not _station_top_queued(rid):
        raise HTTPException(400, "只有排队中的点歌可以置顶")
    _station_save()
    _station_broadcast(action="reordered", id=rid)
    return {"ok": True}


class StationGiftBody(BaseModel):
    name: str                       # 送礼人（弹幕昵称）
    gift: str = ""                  # 礼物名（播报/留痕用）
    value: float = 0.0              # 礼物价值（桥端换算后的数字，仅记录）
    song: str = ""                  # 可选：礼物直接点歌（歌名，曲库匹配）


@app.post("/api/song/station/gift")
async def api_station_gift(req: StationGiftBody):
    """P3: 礼物插队入口（外部弹幕桥 POST 礼物事件）。规则：
    ①带 song → 曲库匹配入队（免弹幕冷却，礼物即诚意）+ 直接插队到队首；
    ②不带 song → 把送礼人已排队的点歌插到队首。
    返回人话 message 供桥端/前端播报。"""
    if not _station["enabled"]:
        return {"ok": False, "reason": "点歌台未开启"}
    who = (req.name or "").strip() or "现场观众"
    gift_tag = f"{req.gift}×1" if req.gift else "礼物"
    # P5: 价值门槛——低于门槛只谢不插队（带歌名仍免冷却入队，礼物即诚意）
    _minv = float(_station.get("gift_min_value") or 0)
    can_top = _minv <= 0 or float(req.value or 0) >= _minv
    if req.song:
        item = _station_match_song(req.song)
        if item is None:
            return {"ok": False, "reason": f"曲库里没找到《{req.song}》"}
        r = _station_enqueue(item, who, "gift")
        if not r.get("ok"):
            rid = r.get("dup_id")          # 同曲已在队 → 视为为它插队
            if not rid:
                return r
        else:
            rid = r["id"]
    else:
        mine = next((x for x in _station_reqs.values()
                     if x["status"] == "queued" and x.get("requester") == who), None)
        if mine is None:
            return {"ok": False, "reason": f"{who} 没有排队中的点歌，送礼时带上歌名可直接点歌插队"}
        rid = mine["id"]
    topped = _station_top_queued(rid) if can_top else False
    _station_reqs[rid]["gift_value"] = round(
        float(_station_reqs[rid].get("gift_value") or 0) + float(req.value or 0), 2)
    _station_save()
    _station_kick()
    _metrics["song_station_gift"] = _metrics.get("song_station_gift", 0) + 1
    msg = (f"感谢 {who} 送出{gift_tag}，点播的《{_station_reqs[rid]['song_name']}》"
           + ("已插队到最前" if topped
              else "已在备歌/就绪，马上安排" if can_top
              else f"已入队（插队需礼物价值满 {_minv:g}）"))
    _station_broadcast(action="gift", id=rid, message=msg)
    _logger.info(f"[Station] 礼物 #{rid} by {who} ({gift_tag} value={req.value} "
                 f"top={topped} 门槛={_minv:g})")
    return {"ok": True, "id": rid, "topped": topped, "message": msg}


@app.get("/api/song/station/leaderboard")
def api_station_leaderboard(days: int = 1, top: int = 10):
    """P5: 点歌榜——近 N 天点歌人排行（点歌数+礼物价值）。主播口播/贴片用。
    数据源=站台登记表（含持久化回载），轻聚合无库表。"""
    since = time.time() - max(1, min(30, days)) * 86400
    agg: dict = {}
    for r in _station_reqs.values():
        if (r.get("created") or 0) < since or r.get("status") == "cancelled":
            continue
        who = (r.get("requester") or "").strip() or "匿名"
        a = agg.setdefault(who, {"name": who, "count": 0, "gift_value": 0.0, "songs": []})
        a["count"] += 1
        a["gift_value"] = round(a["gift_value"] + float(r.get("gift_value") or 0), 2)
        if len(a["songs"]) < 3:
            a["songs"].append(r.get("song_name", ""))
    board = sorted(agg.values(), key=lambda x: (-x["count"], -x["gift_value"]))
    return {"days": max(1, min(30, days)), "board": board[:max(1, min(50, top))]}


@app.post("/api/song/station/{rid}/retry")
async def api_station_retry(rid: int):
    r = _station_reqs.get(rid)
    if r is None:
        raise HTTPException(404, "点歌不存在")
    if r["status"] not in ("failed", "cancelled"):
        raise HTTPException(400, "只有失败/取消的点歌可以重试")
    r.update(status="queued", progress=0, detail="排队等备歌", error="",
             task_id="", profile=_active_profile)
    _station_save()
    _station_kick()
    _station_broadcast(action="enqueued", id=rid)
    return {"ok": True}


@app.delete("/api/song/station/{rid}")
async def api_station_delete(rid: int):
    r = _station_reqs.get(rid)
    if r is None:
        raise HTTPException(404, "点歌不存在")
    if r["status"] in ("preparing", "playing"):
        raise HTTPException(400, "备歌/播放中不能直接删除，先取消/停止")
    _station_reqs.pop(rid, None)
    _station_save()
    _station_broadcast(action="deleted", id=rid)
    return {"ok": True}


async def _station_subtitle(l1: str, l2: str = "", ttl: float = 0.0):
    """P3: 演唱字幕（vcam 直播画面叠加；失败静默——字幕是锦上添花不挡播歌）。"""
    try:
        async with _aclient(timeout=5.0) as c:
            await c.post(f"{_VCAM_URL}/subtitle",
                         json={"line1": l1, "line2": l2, "ttl": ttl})
    except Exception:
        pass


async def _station_announce(r: dict) -> float:
    """P3: 点歌播报——上麦前角色开口谢点歌人（复用 /avatar/speak 全链：TTS+口型+水印）。
    口型视频优先（观众看到角色真开口），口型不可用退化纯音频。返回播报占用秒数（失败 0）。"""
    who = (r.get("requester") or "").strip()
    name = r.get("song_name") or "这首歌"
    text = (f"感谢{who}点的《{name}》，马上为你唱。" if who and who != "现场观众"
            else f"接下来给大家带来《{name}》。")
    try:
        headers = {"X-AH-Token": _API_TOKEN} if _API_TOKEN else {}
        async with _aclient(timeout=httpx.Timeout(connect=5.0, read=120.0,
                                                  write=30.0, pool=5.0)) as c:
            resp = await c.post(f"http://127.0.0.1:{PORT}/avatar/speak",
                                json={"text": text, "profile": r.get("profile") or "",
                                      "generate_lipsync": True, "incognito": True},
                                headers=headers)
        if resp.status_code != 200:
            raise RuntimeError(f"speak HTTP {resp.status_code}")
        j = resp.json()
        audio_b64 = j.get("audio_base64", "")
        if not audio_b64:
            return 0.0
        audio = base64.b64decode(audio_b64)
        dur = _wav_duration_ms(audio) / 1000.0
        video_b64 = j.get("lipsync_video_b64", "")
        if video_b64:
            await _vcam_push(base64.b64decode(video_b64), audio)
        else:
            async with _aclient(timeout=15.0) as c:
                await c.post(f"{_VCAM_URL}/play_audio",
                             files={"audio": ("announce.wav", audio, "audio/wav")})
        _logger.info(f"[Station] 播报 #{r['id']} {text!r} ({dur:.1f}s, "
                     f"{'口型' if video_b64 else '纯音频'})")
        return max(0.0, dur)
    except Exception as e:
        _logger.warning(f"[Station] 点歌播报跳过（不挡播歌）: {e}")
        return 0.0


async def _station_stop_playback():
    try:
        async with _aclient(timeout=5.0) as c:
            await c.post(f"{_VCAM_URL}/stop_audio")
    except Exception:
        pass
    _station["playing_id"] = None
    await _station_subtitle("", "", 0.0)     # P3: 停歌即清演唱字幕


async def _station_play_watch(rid: int, dur_s: float):
    """播完守望：时长到点仍是这首在播 → 标记完成；开了自动连播就接下一首就绪曲。"""
    await asyncio.sleep(max(3.0, dur_s + 1.5))
    if _station.get("playing_id") != rid:
        return
    _station["playing_id"] = None
    r = _station_reqs.get(rid)
    if r is not None and r["status"] == "playing":
        r.update(status="done", detail="")
        _station_save()
        _station_broadcast(action="done", id=rid)
    if _station.get("auto_play") and _station["enabled"]:
        nxt = next((x for x in _station_reqs.values() if x["status"] == "ready"), None)
        if nxt is not None:
            try:
                await _station_do_play(nxt)
            except Exception as _e:
                _logger.warning(f"[Station] 自动连播失败: {_e}")


async def _station_do_play(r: dict):
    """就绪曲目 → vcam 纯音频上麦（待机脸不动、桌面声+WebRTC 双出）。"""
    if not r.get("hist_id"):
        raise HTTPException(400, "成品缺失，请重试备歌")
    row = None
    try:
        with _db_conn() as conn:
            row = conn.execute("SELECT audio_file FROM speak_history WHERE id=?",
                               (r["hist_id"],)).fetchone()
    except Exception:
        pass
    fpath = (HISTORY_AUDIO / row["audio_file"]) if row and row["audio_file"] else None
    if fpath is None or not fpath.exists():
        raise HTTPException(404, "成品音频已被清理，请重试备歌")
    if _station.get("playing_id"):
        await _station_stop_playback()
        prev = _station_reqs.get(_station.get("playing_id") or -1)
        if prev is not None and prev["status"] == "playing":
            prev["status"] = "ready"
    audio_bytes = fpath.read_bytes()
    # P3: 点歌播报——角色先开口谢点歌人，报完再起歌（不叠声）。播报失败不挡播歌。
    if _station.get("announce"):
        _ann_s = await _station_announce(r)
        if _ann_s > 0:
            await asyncio.sleep(_ann_s + 0.5)
    try:
        async with _aclient(timeout=30.0) as c:
            resp = await c.post(f"{_VCAM_URL}/play_audio",
                                files={"audio": ("song.wav", audio_bytes, "audio/wav")})
        if resp.status_code != 200:
            raise RuntimeError(f"vcam HTTP {resp.status_code}")
        dur = float(resp.json().get("duration_s") or 0)
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(503, f"广播中枢(vcam)不可达，无法上麦：{e}")
    if dur <= 0:
        dur = float(r.get("duration_s") or _wav_duration_ms(audio_bytes) / 1000.0 or 180.0)
    # P3: 演唱字幕——歌名+点歌人挂满整曲（ttl 到点自动消，切歌另有显式清除）
    _who = (r.get("requester") or "").strip()
    _t = asyncio.create_task(_station_subtitle(
        f"♪ {r.get('song_name', '')}", f"@{_who} 点播" if _who else "", ttl=dur + 3.0))
    _t.add_done_callback(lambda t: t.exception() if not t.cancelled() else None)
    r.update(status="playing", detail="")
    _station["playing_id"] = r["id"]
    _metrics["song_station_played"] = _metrics.get("song_station_played", 0) + 1
    _w = asyncio.create_task(_station_play_watch(r["id"], dur))
    _w.add_done_callback(lambda t: t.exception() if not t.cancelled() else None)
    _station_save()
    _station_broadcast(action="playing", id=r["id"])
    _logger.info(f"[Station] 上麦 #{r['id']}《{r['song_name']}》{dur:.0f}s")
    return {"ok": True, "id": r["id"], "duration_s": round(dur, 1)}


@app.post("/api/song/station/{rid}/play")
async def api_station_play(rid: int):
    """就绪曲目一键上麦。正在播的会被切掉（回到 ready 可重播）。"""
    r = _station_reqs.get(rid)
    if r is None:
        raise HTTPException(404, "点歌不存在")
    if r["status"] not in ("ready", "playing", "done"):
        raise HTTPException(400, f"这首还没备好（当前状态: {r['status']}）")
    return await _station_do_play(r)


@app.post("/api/song/station/stop")
async def api_station_stop():
    """停止上麦（切歌）。曲目回到就绪态，可重播。"""
    rid = _station.get("playing_id")
    await _station_stop_playback()
    if rid:
        r = _station_reqs.get(rid)
        if r is not None and r["status"] == "playing":
            r.update(status="ready", detail="")
        _station_save()
        _station_broadcast(action="stopped", id=rid)
    return {"ok": True}


# ══════════════════════════════════════════════════════════════════
#  Song-P2: 15 秒高光 MV —— 副歌自动选段 + 现有口型管线（MuseTalk）出演唱视频。
#  翻唱成品(历史音频) → 能量峰值定位副歌 15s → 角色脸口型演唱 → MP4（含音轨）。
#  短视频分发素材一键出：黄金 15 秒挂钩，不用用户自己剪。
# ══════════════════════════════════════════════════════════════════

MV_DIR = Path(rf"{_BASE}\temp\song_mv")
MV_DIR.mkdir(parents=True, exist_ok=True)


def _pick_chorus_start(wav_bytes: bytes, want_s: float) -> float:
    """副歌探测：0.5s 帧 RMS → 滑窗能量和最大的 want_s 窗口起点。
    歌曲 25%~85% 区段加权 1.15（副歌大概率区，避开前奏/尾奏）。失败返回 0（从头截）。"""
    try:
        import io as _io
        import wave as _wave
        import numpy as _np
        with _wave.open(_io.BytesIO(wav_bytes), "rb") as w:
            sr, nch, width = w.getframerate(), w.getnchannels(), w.getsampwidth()
            raw = w.readframes(w.getnframes())
        if width != 2 or sr <= 0:
            return 0.0
        x = _np.frombuffer(raw, _np.int16).astype(_np.float32) / 32768.0
        if nch > 1:
            x = x.reshape(-1, nch).mean(axis=1)
        total_s = len(x) / sr
        if total_s <= want_s + 1.0:
            return 0.0
        hop = int(sr * 0.5)
        nfr = len(x) // hop
        rms = _np.sqrt(_np.maximum(1e-12, (x[: nfr * hop].reshape(nfr, hop) ** 2).mean(axis=1)))
        win = max(1, int(want_s / 0.5))
        if len(rms) <= win:
            return 0.0
        sums = _np.convolve(rms, _np.ones(win, _np.float32), "valid")
        pos = _np.arange(len(sums)) * 0.5 / total_s
        weight = _np.where((pos > 0.25) & (pos < 0.85), 1.15, 1.0).astype(_np.float32)
        return round(int((sums * weight).argmax()) * 0.5, 1)
    except Exception as _e:
        _logger.warning(f"[MV] 副歌探测失败(从头截): {_e}")
        return 0.0


def _cut_wav_segment(wav_bytes: bytes, start_s: float, dur_s: float) -> bytes:
    """PCM WAV 截段（标准库 wave，帧级切）。"""
    import io as _io
    import wave as _wave
    with _wave.open(_io.BytesIO(wav_bytes), "rb") as w:
        sr = w.getframerate()
        params = w.getparams()
        w.setpos(min(int(start_s * sr), w.getnframes()))
        frames = w.readframes(int(dur_s * sr))
    buf = _io.BytesIO()
    with _wave.open(buf, "wb") as out:
        out.setparams(params)
        out.writeframes(frames)
    return buf.getvalue()


class SongMvBody(BaseModel):
    history_id: int
    seconds: float = 15.0          # P4: 8~60s（副歌加长版；整曲 MV 待 P5 异步化）
    hd: bool = False               # gfpgan 增强（更清晰，约 +30ms/帧）
    profile: str = ""              # 默认当前激活角色的脸
    force: bool = False            # P3/O6: 直播中强制出片（前端确认后重发）


async def _mv_render(history_id: int, want_s: float, hd: bool, profile_name: str) -> dict:
    """MV 渲染核（同步端点与 P5 异步任务共用）：历史音频 → 选段（want_s<=0 = 整曲）
    → 口型演唱 → mp4 落盘。异常统一抛 HTTPException（worker 侧转人话 error）。"""
    with _db_conn() as conn:
        row = conn.execute("SELECT audio_file, text FROM speak_history WHERE id=?",
                           (history_id,)).fetchone()
    if not row:
        raise HTTPException(404, "历史记录不存在")
    fpath = HISTORY_AUDIO / (row["audio_file"] or "")
    if not row["audio_file"] or not fpath.exists():
        raise HTTPException(404, "音频文件已清理，没法做 MV 了")
    wav_bytes = fpath.read_bytes()
    total_s = _wav_duration_ms(wav_bytes) / 1000.0
    if want_s <= 0 or (total_s and want_s >= total_s - 1.0):
        # P5: 整曲——不选段不截段
        start_s, seg, want_s = 0.0, wav_bytes, round(total_s or 0.0, 1)
    else:
        start_s = _pick_chorus_start(wav_bytes, want_s)
        try:
            seg = _cut_wav_segment(wav_bytes, start_s, want_s)
        except Exception as e:
            raise HTTPException(400, f"音频截段失败（格式异常）：{e}")
    async with _PROFILES_LOCK:
        face_b64 = dict(_profiles.get(profile_name, {})).get("face_b64", "")
    if not face_b64:
        raise HTTPException(400, f"角色「{profile_name}」没绑人脸图，MV 需要一张脸")
    face_bytes = base64.b64decode(face_b64.split(",", 1)[-1] if "," in face_b64 else face_b64)
    t0 = time.time()
    # 口型调用统一走中央 helper（phase8 T36 守卫：禁止散落裸 POST /lipsync/generate）。
    # 读超时按曲长伸缩：45s 高光实测 ~40s 渲染（约 0.9x 实时），整曲 4 分钟 ≈ 4 分钟渲染
    _timeout = max(600.0, want_s * 12.0)
    try:
        resp = await _lipsync_call_service(seg, face_bytes, fps=25,
                                           enhance=("gfpgan" if hd else ""),
                                           timeout=_timeout)
    except Exception as e:
        raise HTTPException(503, f"口型服务不可达：{e}")
    # _lipsync_call_service 返回 _LSResp（.video_bytes，不是 httpx 的 .content）
    if resp.status_code != 200 or not resp.video_bytes:
        raise HTTPException(502, f"口型生成失败：HTTP {resp.status_code}")
    fname = f"mv_{history_id}_{uuid.uuid4().hex[:8]}.mp4"
    (MV_DIR / fname).write_bytes(resp.video_bytes)
    try:
        now = time.time()
        for old in MV_DIR.glob("mv_*.mp4"):
            if now - old.stat().st_mtime > 48 * 3600:
                old.unlink(missing_ok=True)
    except Exception:
        pass
    _metrics["song_mv_total"] = _metrics.get("song_mv_total", 0) + 1
    elapsed = int((time.time() - t0) * 1000)
    _logger.info(f"[MV] hist={history_id} 选段 {start_s:.1f}s+{want_s:.0f}s "
                 f"用时 {elapsed/1000:.0f}s → {fname}")
    return {"ok": True, "url": f"/api/song/mv/{fname}", "start_s": start_s,
            "seconds": want_s, "elapsed_ms": elapsed,
            "song": re.sub(r"^\[(翻唱|原创|魔改)\] ", "", row["text"] or "")}


@app.post("/api/song/mv")
async def api_song_mv(req: SongMvBody):
    """翻唱成品 → 高光口型 MV（8~60s）。同步返回（约 20~60s，前端有等待态）。
    整曲出片请走 /api/song/mv_task（P5 异步任务：排队+让路+可取消）。"""
    # P3/O6: MV 口型与直播口型同卡——直播/对话中默认拒（人话+可强制），别把直播卡成 PPT
    ys = _song_yield_state()
    if ys.get("yield") and not req.force:
        raise HTTPException(409, f"直播让路中（{ys.get('reason', '直播进行中')}）：出片会抢直播算力，"
                                 f"建议下播后再出；确要现在出请点「强制出片」")
    want_s = max(8.0, min(60.0, req.seconds))
    profile_name = req.profile or _active_profile
    if req.profile:
        _check_profile_name(req.profile)
    return await _mv_render(req.history_id, want_s, req.hd, profile_name)


@app.get("/api/song/mv/{fname}")
def api_song_mv_file(fname: str):
    """MV 成片（video/mp4，可 <video> 直播/下载）。"""
    if not re.fullmatch(r"mv_\d+_[0-9a-f]{8}\.mp4", fname):
        raise HTTPException(400, "非法文件名")
    p = MV_DIR / fname
    if not p.exists():
        raise HTTPException(404, "MV 已过期清理，请重新生成")
    return FileResponse(str(p), media_type="video/mp4", filename=fname)


# ══════════════════════════════════════════════════════════════════
#  Song-P5: 整曲 MV 异步任务——分钟级渲染不再占着 HTTP 连接干等。
#  队列语义与原创歌一致：排队 → 让路等待（live/converse/hold 无限等、
#  vram 源 30s 宽限放行——口型引擎本就常驻，MV 不新增大块显存）→ 渲染 →
#  产物 48h。任务写穿 song_tasks.db：Hub 重启回载重排（渲染不可断点，重头排队，如实告知）。
# ══════════════════════════════════════════════════════════════════
_MV_TASKS: dict = {}
_MV_QUEUE: "asyncio.Queue[str]" = asyncio.Queue()
_MV_VRAM_GRACE_S = 30.0


class SongMvTaskBody(BaseModel):
    history_id: int
    seconds: float = 0.0           # 0 = 整曲；>0 = 高光窗（8~240s）
    hd: bool = False
    profile: str = ""


@app.post("/api/song/mv_task")
async def api_song_mv_task_submit(req: SongMvTaskBody):
    """P5: 整曲/长窗 MV 异步出片。返回 task_id，经 /api/song/mv_task/{tid} 轮询。
    与同步 /api/song/mv 的区别：不占连接、直播中自动排队等档期（不 409）、可取消。"""
    profile_name = req.profile or _active_profile
    if req.profile:
        _check_profile_name(req.profile)
    # 提交时校验历史存在（别让用户等到队首才发现 404）
    with _db_conn() as conn:
        row = conn.execute("SELECT audio_file, text FROM speak_history WHERE id=?",
                           (req.history_id,)).fetchone()
    if not row or not row["audio_file"] or not (HISTORY_AUDIO / row["audio_file"]).exists():
        raise HTTPException(404, "历史记录不存在或音频已清理")
    want_s = 0.0 if req.seconds <= 0 else max(8.0, min(240.0, req.seconds))
    tid = uuid.uuid4().hex[:12]
    _MV_TASKS[tid] = {
        "history_id": req.history_id, "seconds": want_s, "hd": bool(req.hd),
        "profile": profile_name,
        "song_name": re.sub(r"^\[(翻唱|原创|魔改)\] ", "", row["text"] or "")[:40],
        "status": "queued", "progress": 0, "detail": "排队等出片档期",
        "cancel": False, "t0": time.time(), "final": None,
    }
    _task_persist("mv", tid, _MV_TASKS[tid])
    await _MV_QUEUE.put(tid)
    _metrics["song_mv_task_total"] = _metrics.get("song_mv_task_total", 0) + 1
    _logger.info(f"[MV/task] 提交 tid={tid} hist={req.history_id} "
                 f"{'整曲' if want_s <= 0 else f'{want_s:.0f}s'} hd={req.hd}")
    return {"ok": True, "task_id": tid}


@app.get("/api/song/mv_task/{tid}")
def api_song_mv_task_status(tid: str):
    t = _MV_TASKS.get(tid)
    if t is None:
        raise HTTPException(404, "任务不存在或已过期")
    out = {"task_id": tid, "status": t["status"], "progress": t.get("progress", 0),
           "detail": t.get("detail", ""), "song_name": t.get("song_name", ""),
           "seconds": t.get("seconds", 0)}
    if t.get("final"):
        out.update(t["final"])
    if t["status"] == "queued":
        ahead = sum(1 for x in _MV_TASKS.values()
                    if x.get("status") == "queued" and x.get("t0", 0) < t.get("t0", 0))
        busy = any(x.get("status") in ("waiting", "rendering") for x in _MV_TASKS.values())
        out["queue_ahead"] = ahead + (1 if busy else 0)
    return out


@app.post("/api/song/mv_task/{tid}/cancel")
def api_song_mv_task_cancel(tid: str):
    t = _MV_TASKS.get(tid)
    if t is None:
        raise HTTPException(404, "任务不存在或已过期")
    t["cancel"] = True
    if t["status"] in ("queued", "waiting"):
        t.update(status="cancelled", detail="已取消")
        _task_persist("mv", tid, t)
    return {"ok": True, "task_id": tid}          # rendering 中：口型调用不可中断，收尾时丢弃


async def _mv_task_run(tid: str, t: dict):
    """单个 MV 任务：让路等待（可取消）→ 渲染 → 终态落库。"""
    waited0 = time.time()
    while True:
        if t.get("cancel"):
            t.update(status="cancelled", detail="已取消")
            _task_persist("mv", tid, t)
            return
        ys = _song_yield_state()
        if not ys.get("yield"):
            break
        if ys.get("source") == "vram" and time.time() - waited0 > _MV_VRAM_GRACE_S:
            break                    # 口型引擎常驻，MV 不新增大块显存——vram 源宽限后放行
        t.update(status="waiting", progress=2,
                 detail=f"直播让路中（{ys.get('reason', '直播进行中')}）——出片不抢直播算力，结束后自动开始")
        await asyncio.sleep(5.0)
    t.update(status="rendering", progress=10,
             detail="正在渲染口型演唱视频" + ("（整曲，需几分钟）" if t["seconds"] <= 0 else ""))
    _task_persist("mv", tid, t)
    try:
        r = await _mv_render(t["history_id"], t["seconds"], t["hd"], t["profile"])
    except HTTPException as e:
        t.update(status="error", detail=str(e.detail), progress=0)
        _task_persist("mv", tid, t)
        return
    except Exception as e:
        t.update(status="error", detail=f"{type(e).__name__}: {e}", progress=0)
        _task_persist("mv", tid, t)
        return
    if t.get("cancel"):
        t.update(status="cancelled", detail="已取消（成片已丢弃）")
        _task_persist("mv", tid, t)
        return
    t.update(status="done", progress=100, detail="",
             final={"url": r["url"], "start_s": r["start_s"], "seconds": r["seconds"],
                    "elapsed_ms": r["elapsed_ms"], "song": r["song"]})
    _task_persist("mv", tid, t)
    _metrics["song_mv_task_done"] = _metrics.get("song_mv_task_done", 0) + 1


async def _bg_mv_worker():
    """MV 出片 worker：串行消化（口型渲染独占卡，别并行打架）。"""
    while True:
        tid = await _MV_QUEUE.get()
        t = _MV_TASKS.get(tid)
        if t is None or t.get("cancel") or t.get("status") in ("cancelled", "done"):
            continue
        try:
            await _mv_task_run(tid, t)
        except Exception as e:
            _logger.exception(f"[MV/task] {tid} 异常")
            t.update(status="error", detail=f"{type(e).__name__}: {e}")
            _task_persist("mv", tid, t)


@app.post("/avatar/speak/batch")
async def avatar_speak_batch(items: List[BatchSpeakItem]):
    if not items:
        return {"results": [], "count": 0, "total_ms": 0}
    # P11-A1: 上限50条，防止asyncio.gather创建海量Task+_SPEAK_SEM积压
    if len(items) > _BATCH_ITEM_LIMIT:
        raise HTTPException(400, f"单批最多 {_BATCH_ITEM_LIMIT} 条，当前请求 {len(items)} 条")
    # P13-A1: 入口级预校验全部 item.profile，一个非法名就 400（不占 _SPEAK_SEM 空间）
    for _it in items:
        if _it.profile:
            _check_profile_name(_it.profile)
    t0 = time.time()

    async def _one(item: BatchSpeakItem) -> dict:
        # P8-2: 批量接口也过_SPEAK_SEM，防止绕过P7-3并发上限
        try:
            await asyncio.wait_for(_SPEAK_SEM.acquire(), timeout=30.0)
        except asyncio.TimeoutError:
            return {"ok": False, "detail": "服务繁忙（并发超限）", "elapsed_ms": 0}
        t_i = time.time()
        async with _PROFILES_LOCK:                    # P12-B1: snapshot，防import_profiles批量替换竞态
            pname = item.profile or _active_profile
            p = dict(_profiles.get(pname, {}))
        voice_b64 = p.get("voice_b64", "")
        vname = p.get("voice_name") or "female_01.wav"
        try:
            # P11-B1: 经 _call_tts()享按1次连接级重试
            r = await _call_tts(voice_b64, vname, item.text, item.language)
            if r.status_code == 200:
                audio = (r.json().get("audio_base64", "")
                         if voice_b64 else base64.b64encode(r.content).decode())
            else:
                _metrics["batch_item_failed"] += 1  # P11-C2
                return {"ok": False, "detail": f"TTS HTTP {r.status_code}"}
            # RVC 音色转换（Phase6-6: 经适配器分发，引擎取角色配置/默认）
            rvc_model    = p.get("rvc_model", "")
            rvc_settings = p.get("rvc_settings", {})
            if rvc_model and audio:
                try:
                    _vce = p.get("vc_engine", "") or _default_engine("vc")
                    rvc_r = await _vc_dispatch(_vce, audio, rvc_model, rvc_settings)
                    if rvc_r.status_code == 200:
                        audio = rvc_r.audio_b64 or audio
                except Exception:
                    pass
            return {"ok": True, "audio_base64": audio,
                    "elapsed_ms": int((time.time() - t_i) * 1000)}
        except Exception as e:
            _metrics["batch_item_failed"] += 1  # P11-C2
            return {"ok": False, "detail": str(e)}
        finally:
            _SPEAK_SEM.release()  # P8-2: 无论成功失败都释放

    async with _BATCH_SEMAPHORE:          # P9-3: 限制并发批量数（复用batch_dub同一限制）
        results = await asyncio.gather(*[_one(item) for item in items])
    return {"results": list(results), "count": len(results),
            "total_ms": int((time.time() - t0) * 1000)}


# P22-1: 批量流式TTS并发控制（并行3句，平衡延迟与吞吐）
_BATCH_STREAM_CONCURRENCY = 3

@app.post("/avatar/speak/batch/stream")
async def avatar_speak_batch_stream(items: List[BatchSpeakItem],
                                    save_history: bool = False,
                                    task_id: str = ""):
    """SSE 流式批量 TTS：并发处理（默认3句并行），保持输出顺序，首句延迟~3s。
    格式: data: {"index":0, "ok":true, "audio_base64":"...", "elapsed_ms":123}\\n\\n
    P22-1优化: 从顺序改为并发(_BATCH_STREAM_CONCURRENCY=3)，吞吐提升3倍
    P22-2优化: 可选task_id参数，通过WebSocket推送实时进度（前端不依赖SSE也能获进度）
    """
    if len(items) > _BATCH_ITEM_LIMIT:
        raise HTTPException(400, f"单批最多 {_BATCH_ITEM_LIMIT} 条，当前请求 {len(items)} 条")
    for _it in items:
        if _it.profile:
            _check_profile_name(_it.profile)
    from fastapi.responses import StreamingResponse
    # P22-2: 生成或复用task_id
    if not task_id:
        task_id = f"batch_{time.time():.0f}_{random.randint(1000,9999)}"

    async def _stream():
        await _BATCH_SEMAPHORE.acquire()
        total = len(items)
        done_count = 0
        # P22-2: 发送初始进度
        await broadcast_task_progress(task_id, {"type": "batch", "total": total, "done": 0, "pct": 0})
        # P22-1: 并发信号量 + 结果队列保持顺序
        sem = asyncio.Semaphore(_BATCH_STREAM_CONCURRENCY)
        result_queue = asyncio.Queue()
        completed = [False] * total
        results = [None] * total
        next_to_yield = 0

        async def _do_one(idx, item):
            async with sem:
                t_i = time.time()
                async with _PROFILES_LOCK:
                    pname = item.profile or _active_profile
                    p = dict(_profiles.get(pname, {}))
                voice_b64 = p.get("voice_b64", "")
                vname = p.get("voice_name") or "female_01.wav"
                try:
                    emo = item.emotion or "neutral"
                    if emo == "auto":
                        try:
                            from emotion_detector import detect_emotion as _det
                            emo = _det(item.text)
                        except Exception:
                            emo = "neutral"
                    use_emotion_tts = emo not in ("", "neutral")
                    if use_emotion_tts:
                        epay = {"text": item.text, "emotion": emo, "speed": 1.0, "return_base64": True}
                        if voice_b64:
                            epay["reference_audio_b64"] = voice_b64
                            ep = f"{SERVICES['emotion_tts']}/v1/tts/clone"
                        else:
                            ep = f"{SERVICES['emotion_tts']}/v1/tts"
                        r = await http_pool.post(ep, json=epay, timeout=60)
                        audio = r.json().get("audio_base64", "") if r.status_code == 200 else ""
                    else:
                        r = await _call_tts(voice_b64, vname, item.text, item.language)
                        audio = (r.json().get("audio_base64", "")
                                 if voice_b64 else base64.b64encode(r.content).decode()) \
                               if r.status_code == 200 else ""
                    if audio:
                        rvc_model = p.get("rvc_model", "")
                        rvc_settings = p.get("rvc_settings", {})
                        if rvc_model:
                            try:
                                _vce = p.get("vc_engine", "") or _default_engine("vc")
                                rvc_r = await _vc_dispatch(_vce, audio, rvc_model, rvc_settings)
                                if rvc_r.status_code == 200:
                                    audio = rvc_r.audio_b64 or audio
                            except Exception:
                                pass
                        elapsed_i = int((time.time()-t_i)*1000)
                        chunk = {"index": idx, "ok": True, "audio_base64": audio,
                                 "emotion": emo, "elapsed_ms": elapsed_i}
                        if save_history and len(items) <= 20:
                            asyncio.get_running_loop().run_in_executor(
                                _history_executor, _write_history,
                                pname, item.text, item.language,
                                audio, elapsed_i, False, False, emo
                            )
                    else:
                        _metrics["batch_item_failed"] += 1
                        chunk = {"index": idx, "ok": False,
                                 "detail": f"TTS HTTP {r.status_code}",
                                 "elapsed_ms": int((time.time()-t_i)*1000)}
                    await result_queue.put((idx, chunk))
                except Exception as e:
                    _metrics["batch_item_failed"] += 1
                    chunk = {"index": idx, "ok": False, "detail": str(e),
                             "elapsed_ms": int((time.time()-t_i)*1000)}
                    await result_queue.put((idx, chunk))

        # 启动所有任务
        tasks = [asyncio.create_task(_do_one(i, item)) for i, item in enumerate(items)]

        # 消费结果，保持顺序产出
        try:
            while next_to_yield < total:
                idx, chunk = await result_queue.get()
                results[idx] = chunk
                completed[idx] = True
                done_count += 1
                # P22-2: WebSocket推送进度（每5句或最后一句）
                if done_count % 5 == 0 or done_count == total:
                    await broadcast_task_progress(task_id, {
                        "type": "batch", "total": total, "done": done_count,
                        "pct": int(done_count/total*100), "current_idx": idx
                    })
                # P22-1: 顺序产出（按index顺序yield，不等待全部完成）
                while next_to_yield < total and completed[next_to_yield]:
                    yield f"data: {json.dumps(results[next_to_yield])}\n\n"
                    next_to_yield += 1
            # 结束标记
            yield f"data: {json.dumps({'index': -1, 'done': True, 'total': total})}\n\n"
            # P22-2: 完成进度
            await broadcast_task_progress(task_id, {"type": "batch", "total": total, "done": total, "pct": 100, "status": "completed"})
        finally:
            # 清理未完成任务
            for t in tasks:
                if not t.done():
                    t.cancel()
            _BATCH_SEMAPHORE.release()

    return StreamingResponse(_stream(), media_type="text/event-stream")


# P22-4: 角色音色A/B对比端点（同文本多角色并行合成）
class ABCompareItem(BaseModel):
    text: str
    profile: str = ""  # 空则使用当前激活角色
    emotion: str = "neutral"
    language: str = "zh-cn"

@app.post("/api/ab_compare")
async def api_ab_compare(items: List[ABCompareItem]):
    """A/B对比：同文本不同角色音色并行合成，返回各角色音频用于对比播放
    限制：最多5个角色同时对比，避免资源占用过多"""
    if len(items) > 5:
        raise HTTPException(400, "A/B对比最多5个角色同时对比")
    if not items:
        return {"ok": True, "results": []}
    t0 = time.time()
    results = []
    sem = asyncio.Semaphore(3)  # 并发控制3个角色同时合成

    async def _synthesize_one(item: ABCompareItem, idx: int):
        async with sem:
            async with _PROFILES_LOCK:
                pname = item.profile or _active_profile
                p = dict(_profiles.get(pname, {}))
            if not p:
                return {"index": idx, "profile": pname, "ok": False, "detail": "角色不存在"}
            voice_b64 = p.get("voice_b64", "")
            vname = p.get("voice_name") or "female_01.wav"
            try:
                emo = item.emotion or "neutral"
                use_emotion_tts = emo not in ("", "neutral")
                if use_emotion_tts:
                    epay = {"text": item.text, "emotion": emo, "speed": 1.0, "return_base64": True}
                    if voice_b64:
                        epay["reference_audio_b64"] = voice_b64
                        ep = f"{SERVICES['emotion_tts']}/v1/tts/clone"
                    else:
                        ep = f"{SERVICES['emotion_tts']}/v1/tts"
                    r = await http_pool.post(ep, json=epay, timeout=60)
                    audio = r.json().get("audio_base64", "") if r.status_code == 200 else ""
                else:
                    r = await _call_tts(voice_b64, vname, item.text, item.language)
                    audio = (r.json().get("audio_base64", "")
                             if voice_b64 else base64.b64encode(r.content).decode()) \
                           if r.status_code == 200 else ""
                # RVC处理（Phase6-6: 经适配器分发，引擎取角色配置/默认）
                rvc_model = p.get("rvc_model", "")
                if audio and rvc_model:
                    try:
                        _vce = p.get("vc_engine", "") or _default_engine("vc")
                        rvc_r = await _vc_dispatch(_vce, audio, rvc_model, p.get("rvc_settings", {}))
                        if rvc_r.status_code == 200:
                            audio = rvc_r.audio_b64 or audio
                    except Exception:
                        pass
                return {"index": idx, "profile": pname, "ok": bool(audio), "audio_base64": audio,
                        "emotion": emo, "elapsed_ms": int((time.time()-t0)*1000)}
            except Exception as e:
                return {"index": idx, "profile": pname, "ok": False, "detail": str(e)}

    tasks = [_synthesize_one(item, i) for i, item in enumerate(items)]
    results = await asyncio.gather(*tasks)
    return {"ok": True, "results": results, "total_ms": int((time.time()-t0)*1000)}


class EngineABRequest(BaseModel):
    profile:  str
    text:     str
    language: str = "zh-cn"
    emotion:  str = "neutral"


@app.post("/api/engine_ab_compare")
async def api_engine_ab_compare(req: EngineABRequest):
    """同角色、同文本：Fish-Speech vs CosyVoice 并行合成 + 音色/自然度打分。"""
    if req.profile not in _profiles:
        raise HTTPException(404, "角色不存在")
    ref_b64 = _profiles[req.profile].get("voice_b64", "")
    if not ref_b64:
        return {"ok": False, "detail": "该角色无参考音频"}
    try:
        import clone_scorer
        import prosody_scorer as _ps
    except Exception as e:
        return {"ok": False, "detail": f"评分模块加载失败: {e}"}
    base = dict(_profiles[req.profile])
    t0 = time.time()

    async def _one(engine: str) -> dict:
        prof = dict(base)
        prof["tts_engine"] = engine
        t1 = time.time()
        a = await _conv_synthesize(req.text, prof, language=req.language, emotion=req.emotion,
                                   vc_engine="", watermark=None, _use_opener_cache=False)
        elapsed = int((time.time() - t1) * 1000)
        if not a:
            return {"engine": engine, "ok": False, "detail": "合成失败", "elapsed_ms": elapsed}
        sc = await asyncio.to_thread(clone_scorer.score_similarity, ref_b64, a)
        nt = await asyncio.to_thread(_ps.naturalness_score, a, ref_b64)
        return {
            "engine": engine, "ok": True, "audio_base64": a,
            "cosine": round(sc.get("cosine", 0.0), 4) if sc.get("ok") else None,
            "naturalness": round(nt.get("naturalness", 0.0), 4) if nt.get("ok") else None,
            "elapsed_ms": elapsed,
        }

    fish_r, cosy_r = await asyncio.gather(_one("fish_speech"), _one("cosyvoice"))
    winner = ""
    if fish_r.get("ok") and cosy_r.get("ok"):
        fc, cc = fish_r.get("cosine") or 0, cosy_r.get("cosine") or 0
        winner = "fish_speech" if fc >= cc else "cosyvoice"
    return {"ok": True, "profile": req.profile, "text": req.text,
            "results": [fish_r, cosy_r], "winner_cosine": winner,
            "total_ms": int((time.time() - t0) * 1000)}


class ListeningAbRequest(BaseModel):
    profile:  str
    text:     str = ""
    alt_ref:  str = ""              # 预切参考文件名，如 xi_ref_37_47s.wav
    language: str = "zh-cn"
    emotion:  str = "neutral"


@app.get("/api/voice_pack/segments/{name}")
def api_voice_pack_segments(name: str):
    """列出角色声音包预切参考段（供听感 A/B 盲听对比）。"""
    import glob
    _check_profile_name(name)
    pattern = _PROFILE_SEGMENT_GLOBS.get(name, "")
    if not pattern:
        return {"ok": True, "segments": []}
    cur_b64 = (_profiles.get(name) or {}).get("voice_b64", "")
    segs = []
    for fp in sorted(glob.glob(pattern)):
        b64 = base64.b64encode(Path(fp).read_bytes()).decode()
        segs.append({
            "name": Path(fp).name,
            "active": b64 == cur_b64,
        })
    return {"ok": True, "profile": name, "segments": segs}


@app.post("/api/listening_ab")
async def api_listening_ab(req: ListeningAbRequest):
    """听感 A/B：当前参考 vs 候选预切段，同文本盲听对比（比 cosine 更贴近主观听感）。"""
    if req.profile not in _profiles:
        raise HTTPException(404, "角色不存在")
    base = dict(_profiles[req.profile])
    ref_b64 = base.get("voice_b64", "")
    if not ref_b64:
        return {"ok": False, "detail": "该角色无参考音频"}
    text = (req.text or "").strip()
    if not text:
        ps = [s for s in (base.get("probe_sentences") or []) if isinstance(s, str) and s.strip()]
        text = ps[0] if ps else "各位同志，深圳是一座充满活力的现代化城市。"
    alt_name = (req.alt_ref or "").strip()
    if not alt_name:
        raise HTTPException(400, "请指定 alt_ref 预切参考文件名")
    import glob
    pattern = _PROFILE_SEGMENT_GLOBS.get(req.profile, "")
    alt_path = None
    for fp in glob.glob(pattern or ""):
        if Path(fp).name == alt_name:
            alt_path = Path(fp)
            break
    if not alt_path or not alt_path.exists():
        raise HTTPException(404, f"找不到预切参考 {alt_name}")
    alt_b64 = base64.b64encode(alt_path.read_bytes()).decode()
    alt_text = ""
    for r in (base.get("fish_refs") or []):
        if r.get("voice_b64") == alt_b64:
            alt_text = r.get("text") or ""
            break
    if not alt_text:
        ftp = dict(base.get("fish_tts_params") or {})
        alt_text = ftp.get("reference_text") or ""
    try:
        import clone_scorer
        import prosody_scorer as _ps
    except Exception as e:
        return {"ok": False, "detail": f"评分模块加载失败: {e}"}
    t0 = time.time()

    cur_seg = _active_segment_name(req.profile)

    async def _synth(label: str, prof: dict, *, segment: str = "", is_current: bool = False) -> dict:
        t1 = time.time()
        a = await _conv_synthesize(text, prof, language=req.language, emotion=req.emotion,
                                   vc_engine="", watermark=None, _use_opener_cache=False)
        elapsed = int((time.time() - t1) * 1000)
        if not a:
            return {"label": label, "ok": False, "detail": "合成失败", "elapsed_ms": elapsed,
                    "segment": segment, "is_current": is_current}
        sc = await asyncio.to_thread(clone_scorer.score_similarity, ref_b64, a)
        nt = await asyncio.to_thread(_ps.naturalness_score, a, ref_b64)
        return {
            "label": label, "ok": True, "audio_base64": a,
            "cosine": round(sc.get("cosine", 0.0), 4) if sc.get("ok") else None,
            "naturalness": round(nt.get("naturalness", 0.0), 4) if nt.get("ok") else None,
            "elapsed_ms": elapsed,
            "segment": segment, "is_current": is_current,
        }

    prof_a = dict(base)
    prof_b = dict(base)
    prof_b["voice_b64"] = alt_b64
    ftp_b = dict(prof_b.get("fish_tts_params") or {})
    if alt_text:
        ftp_b["reference_text"] = alt_text
    prof_b["fish_tts_params"] = ftp_b
    a_r, b_r = await asyncio.gather(
        _synth("当前参考", prof_a, segment=cur_seg or "", is_current=True),
        _synth(alt_name, prof_b, segment=alt_name, is_current=False),
    )
    if _convmetrics is not None:
        for r in (a_r, b_r):
            if r.get("ok") and r.get("cosine") is not None:
                _convmetrics.record_clone_score(
                    profile=req.profile, cosine=r["cosine"],
                    label=f"听感AB·{r.get('label','')}")
    return {
        "ok": True, "profile": req.profile, "text": text,
        "alt_ref": alt_name, "results": [a_r, b_r],
        "total_ms": int((time.time() - t0) * 1000),
    }


# ── 路由：实时变声翻译 ────────────────────────────────────────────────
# 支持语言映射（Google 翻译语言代码 → TTS 语言代码）
_LANG_MAP_TTS = {
    "ja": "ja",    "zh-CN": "zh-cn", "zh-TW": "zh-cn",
    "en": "en",    "ko": "ko",       "fr": "fr",
    "de": "de",    "es": "es",       "it": "it",
    "pt": "pt",    "ru": "ru",       "ar": "ar",
    "hi": "hi",    "vi": "vi",       "th": "th",
    "id": "id",    "tr": "tr",       "nl": "nl",
    "pl": "pl",    "uk": "uk",
}

_GOOGLE_LANG_NORM = {
    "zh-cn": "zh-CN", "zh": "zh-CN", "zh-CN": "zh-CN", "zh-TW": "zh-TW",
    "en": "en", "en-us": "en", "ja": "ja", "ko": "ko", "fr": "fr", "de": "de",
    "es": "es", "it": "it", "pt": "pt", "ru": "ru", "ar": "ar", "hi": "hi",
    "vi": "vi", "th": "th", "id": "id", "tr": "tr", "nl": "nl", "pl": "pl",
}

_WHISPER_LANG = {
    "zh-CN": "zh", "zh-TW": "zh", "en": "en", "ja": "ja", "ko": "ko",
    "fr": "fr", "de": "de", "es": "es", "it": "it", "pt": "pt", "ru": "ru",
    "ar": "ar", "hi": "hi", "vi": "vi", "th": "th", "id": "id", "tr": "tr",
    "nl": "nl", "pl": "pl",
}


def _google_lang(code: str) -> str:
    if not code:
        return "zh-CN"
    c = code.strip()
    return _GOOGLE_LANG_NORM.get(c.lower(), c)


def _whisper_lang(code: str) -> str:
    g = _google_lang(code)
    return _WHISPER_LANG.get(g, g[:2].lower() if len(g) >= 2 else "zh")


def _google_to_tts_lang(gl: str, fallback: str = "zh-cn") -> str:
    """Google 语种代码 → TTS 朗读语种代码。中文/未知回退到 fallback(默认 zh-cn)。"""
    if not gl or gl in ("zh-CN", "zh-TW", "auto"):
        return fallback or "zh-cn"
    return _LANG_MAP_TTS.get(gl, gl.lower().replace("-", "_")[:5])


try:
    from zhconv import convert as _zhconv_convert
except Exception:
    _zhconv_convert = None

def _to_simplified(text: str) -> str:
    """繁体中文 → 简体：云端 LLM(DeepSeek)偶发返回繁体，面向大陆用户/字幕统一简体
    （Mandarin 发音不变，仅字形统一）。仅在文本判定为中文时调用。zhconv 缺失则原样返回。"""
    if not text or _zhconv_convert is None:
        return text
    try:
        return _zhconv_convert(text, "zh-cn")
    except Exception:
        return text


def _conv_reply_tts_lang(req: "ConverseRequest") -> str:
    # 实际朗读语种：翻译模式=目标语；否则=输入语(auto 时按用户文本检测)
    rl = _google_lang(req.reply_lang) if (req.reply_lang and req.reply_lang.strip().lower() != "auto") else ""
    if _conv_need_translate(req):
        rl = _google_lang(req.reply_lang)
    elif not rl:
        rl = _conv_src_lang(req)
    if not rl or rl in ("zh-CN", "zh-TW", "auto"):
        lang = req.language or "zh-cn"
        return "zh-cn" if (not lang or lang.lower() == "auto") else lang
    return _LANG_MAP_TTS.get(rl, rl.lower().replace("-", "_")[:5])


def _conv_src_lang(req: "ConverseRequest") -> str:
    """解析「来源语种」：input_lang=auto 时按用户文本检测，否则用显式设置。"""
    il = (req.input_lang or "").strip().lower()
    if not il or il == "auto":
        return _detect_text_lang(req.text) or _google_lang(req.language or "zh-CN")
    return _google_lang(req.input_lang or req.language or "zh-CN")


def _conv_need_translate(req: "ConverseRequest") -> bool:
    # reply_lang 空或 auto(跟随输入) → 不翻译，直接用输入语种回复
    if not req.reply_lang or req.reply_lang.strip().lower() == "auto":
        return False
    il = (req.input_lang or "").strip().lower()
    if not il or il == "auto":
        # 输入自动：按用户文本判定来源语种（语音输入无文本时退回中文）
        src = _detect_text_lang(req.text) or "zh-CN"
    else:
        src = _google_lang(req.input_lang or req.language or "zh-CN")
    dest = _google_lang(req.reply_lang)
    return src != dest


_LANG_DISPLAY = {
    "ja": "日语", "en": "英语", "ko": "韩语", "zh-CN": "中文(简体)", "zh-TW": "中文(繁体)",
    "fr": "法语", "de": "德语", "es": "西班牙语", "it": "意大利语", "pt": "葡萄牙语",
    "ru": "俄语", "ar": "阿拉伯语", "hi": "印地语", "vi": "越南语", "th": "泰语",
    "id": "印尼语", "tr": "土耳其语", "nl": "荷兰语", "pl": "波兰语",
}

_LANG_PROMPT_TAG = "[REPLY_LANG]"

# 轻量语种检测（免依赖）：LLM 已用目标语回复则跳过 Google 翻译
_RE_JA_KANA = __import__("re").compile(r"[\u3040-\u30ff\u31f0-\u31ff]")
_RE_KO = __import__("re").compile(r"[\uac00-\ud7af]")
_RE_CJK = __import__("re").compile(r"[\u4e00-\u9fff]")
_RE_LATIN = __import__("re").compile(r"[A-Za-z]")


def _text_likely_lang(text: str, google_code: str) -> bool:
    """启发式判断文本是否已是目标语种（用于跳过冗余机器翻译）。"""
    if not text or not text.strip():
        return True
    g = _google_lang(google_code)
    t = text.strip()
    n = max(1, len(t))
    if g in ("zh-CN", "zh-TW"):
        cjk = len(_RE_CJK.findall(t))
        return cjk >= n * 0.35 and not _RE_JA_KANA.search(t) and not _RE_KO.search(t)
    if g == "ja":
        kana = len(_RE_JA_KANA.findall(t))
        cjk = len(_RE_CJK.findall(t))
        return kana >= max(2, n * 0.08) or (cjk >= 2 and kana >= 1)
    if g == "ko":
        return len(_RE_KO.findall(t)) >= max(2, n * 0.25)
    if g == "en":
        latin = len(_RE_LATIN.findall(t))
        return latin >= n * 0.45 and len(_RE_CJK.findall(t)) < n * 0.15
    return False


def _detect_text_lang(text: str) -> str:
    """从用户文本启发式检测语种(Google 代码)，供「自动跟随」模式。
    优先级：韩文 > 日文假名 > 西里尔 > 中文汉字 > 拉丁字母。空/无法判定返回 ""。"""
    if not text or not text.strip():
        return ""
    t = text.strip()
    if _RE_KO.search(t):
        return "ko"
    if _RE_JA_KANA.search(t):
        return "ja"
    if __import__("re").search(r"[\u0400-\u04ff]", t):
        return "ru"
    if _RE_CJK.search(t):
        return "zh-CN"
    if _RE_LATIN.search(t):
        return "en"
    return ""


def _translate_for_speech(text: str, src: str, dest: str) -> tuple:
    """智能翻译：已是目标语则直读。返回 (朗读文本, 是否机器翻译)。"""
    if not text or not text.strip():
        return text, False
    s, d = _google_lang(src), _google_lang(dest)
    if s == d or _text_likely_lang(text, d):
        return text, False
    return _translate(text, s, d), True


def _strip_lang_prompt(prompt: str) -> str:
    idx = prompt.find(_LANG_PROMPT_TAG)
    return prompt[:idx].rstrip() if idx >= 0 else prompt


def _reply_lang_system_hint(dest: str) -> str:
    name = _LANG_DISPLAY.get(dest, dest)
    return (f"{_LANG_PROMPT_TAG} 你必须全程用{name}回答，不要使用中文或其他语言。"
            f"不要用「嗯」「好的」等中文口头语开场。"
            f"回答简短自然、口语化，适合语音朗读（每次 1~3 句）。")


def _apply_reply_lang_prompt(base: str, dest: str) -> str:
    base = _strip_lang_prompt(base or "")
    if not dest or dest in ("zh-CN", "zh-TW"):
        return base or "你是一个友好的虚拟主播，用简短自然的中文回答。"
    hint = _reply_lang_system_hint(dest)
    if not base:
        base = "你是一个友好的虚拟主播。"
    return base + "\n\n" + hint


def _translate(text: str, src: str, dest: str) -> str:
    """使用 deep-translator (Google) 翻译文字"""
    try:
        from deep_translator import GoogleTranslator
        translated = GoogleTranslator(source=src, target=dest).translate(text)
        return translated or text
    except Exception as e:
        _logger.warning(f"[翻译] 失败，返回原文: {e}")
        return text


class TranslateSpeakRequest(BaseModel):
    text:        str
    src_lang:    str = "zh-CN"   # 输入语言 (Google 代码)
    dest_lang:   str = "ja"      # 目标语言 (Google 代码)
    profile:     str = ""        # 角色名（为空用激活角色）
    engine:      str = ""        # 强制 TTS 引擎(如 "fish_speech")；空=用角色配置


class AsrTranslateRequest(BaseModel):
    audio_base64: str             # WAV base64（麦克风录音）
    src_lang:     str = "zh"      # Whisper 识别语言
    dest_lang:    str = "ja"      # 翻译目标语言
    profile:      str = ""


@app.post("/avatar/translate_speak")
async def avatar_translate_speak(req: TranslateSpeakRequest):
    """
    文字翻译变声联动：
      输入文字 → Google翻译 → TTS(目标语言) → RVC(角色音色) → 返回音频
    """
    t0 = time.time()
    profile_name = req.profile or _active_profile
    profile      = dict(_profiles.get(profile_name, {}))
    profile.setdefault("name", profile_name)

    src = _google_lang(req.src_lang)
    dest = _google_lang(req.dest_lang)
    translated = await asyncio.get_running_loop().run_in_executor(
        None, _translate, req.text, src, dest
    )
    tts_lang = _LANG_MAP_TTS.get(dest, dest.lower().replace("-", "_")[:5])

    audio_b64 = await _conv_synthesize(
        translated, profile, language=tts_lang, emotion="neutral",
        vc_engine="", watermark=None, _use_opener_cache=False,
        prefer_engine=req.engine or "")
    if not audio_b64:
        raise HTTPException(500, "TTS 合成失败（请确认 Fish-TTS 已启动且角色已绑定音色）")

    return {
        "ok":           True,
        "original":     req.text,
        "translated":   translated,
        "dest_lang":    req.dest_lang,
        "tts_lang":     tts_lang,
        "audio_base64": audio_b64,
        "elapsed_ms":   int((time.time() - t0) * 1000),
    }


@app.post("/avatar/asr_translate_speak")
async def avatar_asr_translate_speak(req: AsrTranslateRequest):
    """
    录音→ASR识别→翻译→TTS→RVC 全链路：
      WAV base64 → Whisper识别文字 → 翻译 → TTS(目标语言) → RVC → 返回音频+字幕
    需要安装: pip install faster-whisper
    """
    import tempfile, os as _os
    t0 = time.time()

    # 解码音频
    try:
        raw = base64.b64decode(req.audio_base64)
    except Exception as e:
        raise HTTPException(400, f"音频解码失败: {e}")

    # 写临时文件
    with tempfile.NamedTemporaryFile(suffix=".wav", delete=False) as tmp:
        tmp.write(raw)
        tmp_path = tmp.name

    try:
        # ASR 识别
        try:
            from faster_whisper import WhisperModel
            if not hasattr(avatar_asr_translate_speak, "_whisper"):
                avatar_asr_translate_speak._whisper = WhisperModel(
                    "small", device="cuda", compute_type="float16"
                )
            model = avatar_asr_translate_speak._whisper
            segs, _ = model.transcribe(tmp_path, language=req.src_lang or None)
            recognized = " ".join(s.text for s in segs).strip()
        except Exception as e:
            raise HTTPException(500, f"ASR 识别失败（请确认 faster-whisper 已安装）: {e}")
    finally:
        _os.unlink(tmp_path)

    if not recognized:
        raise HTTPException(400, "未识别到语音内容")

    # 翻译 + TTS + RVC（复用 translate_speak 逻辑）
    sub_req = TranslateSpeakRequest(
        text=recognized, src_lang=req.src_lang or "zh-CN",
        dest_lang=req.dest_lang, profile=req.profile
    )
    result = await avatar_translate_speak(sub_req)
    result["recognized"] = recognized
    result["asr_elapsed_ms"] = int((time.time() - t0) * 1000)
    return result


