# ── 路由：Phase9 对话式数字人（STT→LLM→TTS 流式编排）──────────────────
class ConverseRequest(BaseModel):
    text:          str = ""                # 文本输入（与 audio_base64 二选一）
    audio_base64:  str = ""                # 语音输入（WAV base64，走 STT）
    session_id:    str = "default"         # 会话标识（维持多轮上下文）
    profile:       str = ""                # 角色（决定音色/RVC）
    system_prompt: str = ""                # 覆盖系统提示
    stt_engine:    str = ""                # 空=默认(mock_stt)
    llm_engine:    str = ""                # 空=默认(mock_llm)
    language:      str = "zh-cn"           # STT 语言（Whisper 代码，可由 input_lang 推导）
    input_lang:    str = ""                # 输入语种 Google 代码（zh-CN / en / ja …）
    reply_lang:    str = ""                # 回复朗读语种 Google 代码；与 input 不同则逐句翻译后 TTS
    emotion:       str = "neutral"
    auto_emotion:  Optional[bool] = None   # 情感自适应开关：None=全局默认/True=强制开/False=强制中性
    after_barge_in: bool = False           # 本轮紧接打断之后：开口先来句应答词("嗯，您说")更像真人
    speak:         bool = True             # 是否对回复逐句 TTS
    generate_lipsync: bool = False         # Phase9-3: 逐句口型双流（需角色有人脸+lipsync服务）
    lipsync_engine: str = ""               # 空=默认(musetalk)
    lipsync_enhance: bool = False          # 实时 256(musetalk) 过 GFPGAN 人脸增强（更清晰，约+30ms/帧）
    superres:       bool = False           # Phase8-4: 离线 HD 整帧超分(Real-ESRGAN)，升整帧分辨率(背景/身体)；非实时
    superres_scale: float = 2.0            # 超分倍率（默认 2x；模型原生 x4，按需缩放）
    use_rag:       bool = True             # Phase9-4: 启用知识库检索（库空则自动跳过）
    rag_top_k:     int  = 3
    temperature:   Optional[float] = None  # Phase9-2b: 采样温度（空=后端默认 0.7）
    max_tokens:    Optional[int]   = None  # 回复最大 token（空=后端默认）
    top_p:         Optional[float] = None  # 核采样（空=后端默认）
    vc_engine:     str = ""
    tts_engine:    str = ""                 # 覆盖对话逐句 TTS 引擎(空=用 CONV_TTS_ENGINE/角色)
    watermark:     Optional[bool] = None
    priority:      int = 0                  # P-Conc2: 准入优先级(越大越先服务)；主播控场指令>观众弹幕
    brevity_hint:  str = ""                 # P-Conc14: 追加(非替换)的简短作答指令；保留人设，仅约束篇幅
                                            #   (观众自动应答用→更短更快，单数字人串行下直接抬吞吐)
    lipsync_serialize: Optional[bool] = None  # 句间口型串行化覆盖：None=按引擎策略(_lipsync_serialize_for)；
                                            #   True=本句口型渲染完才产下句TTS(逐句满速、句间ditto空转)；
                                            #   False=口型后台跑、与下句TTS重叠(句间背靠背)。供整机 A/B 验收/运维现场调参

def _conv_llm_opts(req: "ConverseRequest") -> dict:
    """仅收集显式给出的采样参数，透传给 LLM.stream（空值不传，保留后端默认）。"""
    o = {}
    if req.temperature is not None: o["temperature"] = req.temperature
    if req.max_tokens  is not None: o["max_tokens"]  = req.max_tokens
    if req.top_p       is not None: o["top_p"]       = req.top_p
    return o

# 两段式首音优化：首块合成期间暂停本地 LLM 生成，消除 GPU 争用（实测首块 5s→~2s）。
# 仅对「本地 GPU 对话模型 + 需要 TTS」启用；云端无本地争用、mock 会重复生成，均跳过。
_TTFA_TWO_PHASE = os.environ.get("CONV_TTFA_TWO_PHASE", "1") == "1"
_TTFA_PHASE1_CHARS = int(os.environ.get("CONV_TTFA_PHASE1_CHARS", "12"))

# 口型与下一句 TTS 是否串行化（单卡防同卡争用；多卡可关→跨卡流水化，单答案内提速）。
# auto(默认)：口型为多卡池(size>1)时关串行→本句口型与下句 TTS 落不同卡并发；否则串行
# (= 改造前行为，单卡零回归)。1/on=强制串行；0/off=强制并发(operator 自知拓扑时用)。
_CONV_LIPSYNC_SERIALIZE = os.environ.get("CONV_LIPSYNC_SERIALIZE", "auto").strip().lower()
# ditto 专用串行化策略（独立于上方全局口型策略）。auto(默认)对 ditto 放开重叠：
#   依据——ditto 在独立进程(无 MuseTalk 那种同进程/同 CUDA 上下文的 25× 争用)、自带 GPU 锁(句间天然
#   FIFO 串行、不乱序)、快于实时(即便与 TTS 共卡时分片降速仍能跟上播放)、且流式推到带缓冲的 vcam
#   (尾部渲染降速被缓冲+STREAM_GRACE 吸收)。故句 N 渲染与句 N+1 的 TTS 重叠 → 句间空隙被隐藏。
#   单卡整机实测若发现 ditto×TTS 共卡争用得不偿失，置 1/on 即恢复严格串行(逐句满速、句间串行)。
_CONV_LIPSYNC_SERIALIZE_DITTO = os.environ.get("CONV_LIPSYNC_SERIALIZE_DITTO", "auto").strip().lower()


def _lipsync_serialize_for(engine: str = "") -> bool:
    # 全局强制开关优先于一切（operator 显式指定时全引擎生效）
    if _CONV_LIPSYNC_SERIALIZE in ("0", "false", "no", "off"):
        return False
    if _CONV_LIPSYNC_SERIALIZE in ("1", "true", "yes", "on"):
        return True
    # ditto：独立进程+自带 GPU 锁+快于实时+流式缓冲 → 默认放开句间重叠（见上方注释）。
    # MuseTalk 等同进程口型不走此分支，行为与改造前完全一致（零回归）。
    if engine == "ditto":
        if _CONV_LIPSYNC_SERIALIZE_DITTO in ("1", "true", "yes", "on"):
            return True
        if _CONV_LIPSYNC_SERIALIZE_DITTO in ("0", "false", "no", "off"):
            return False
        return False           # auto：默认放开重叠
    try:                       # auto：仅当口型确为多卡池才放开并发，单卡严格保持串行
        return not (_svc_pool("lipsync").size > 1)
    except Exception:
        return True

# 单句内流式 TTS：边合成边吐音频块、逐块即喂口型，破“整句合成完才起播”的固定延迟(降 TTFA、
# 单句内 TTS/口型/播放重叠)。默认关(0)→走原整句路径，零回归。需 fish_speech_server 暴露
# /v1/tts/clone/stream（已附加，幂等且不影响原 /v1/tts/clone）。开启前请在 GPU 机实测验收。
_CONV_TTS_STREAMING = os.environ.get("CONV_TTS_STREAMING", "0") == "1"


def _pcm16_to_wav_b64(pcm: bytes, sr: int) -> str:
    import io as _io, wave as _wave
    buf = _io.BytesIO()
    with _wave.open(buf, "wb") as w:
        w.setnchannels(1)
        w.setsampwidth(2)
        w.setframerate(sr)
        w.writeframes(pcm)
    return base64.b64encode(buf.getvalue()).decode()


def _concat_wav_b64(chunks: list) -> str:
    """UI-P1: 按序拼接多段 wav(base64) 为整段 wav(base64)，供流式多句落历史。
    以首段参数为基准；混流护栏——开场白缓存/RVC 输出与 fish 子块采样率可能不同，
    不一致的段用 audioop 就地转换（位宽 lin2lin / 声道 tomono/tostereo / 采样率 ratecv）。"""
    import io as _io, wave as _wave, audioop as _audioop
    target = None                      # (nchannels, sampwidth, framerate)
    pcm_all = bytearray()
    for b64 in chunks:
        try:
            with _wave.open(_io.BytesIO(base64.b64decode(b64)), "rb") as w:
                params = (w.getnchannels(), w.getsampwidth(), w.getframerate())
                pcm = w.readframes(w.getnframes())
        except Exception:
            continue                   # 坏段跳过，不因单段解析失败丢整场
        if not pcm:
            continue
        if target is None:
            target = params
        nch, sw, sr = params
        if sw != target[1]:
            pcm = _audioop.lin2lin(pcm, sw, target[1]); sw = target[1]
        if nch != target[0]:
            pcm = (_audioop.tomono(pcm, sw, 0.5, 0.5) if target[0] == 1
                   else _audioop.tostereo(pcm, sw, 1, 1)); nch = target[0]
        if sr != target[2]:
            pcm, _st = _audioop.ratecv(pcm, sw, nch, sr, target[2], None)
        pcm_all += pcm
    if target is None or not pcm_all:
        return ""
    buf = _io.BytesIO()
    with _wave.open(buf, "wb") as w:
        w.setnchannels(target[0]); w.setsampwidth(target[1]); w.setframerate(target[2])
        w.writeframes(bytes(pcm_all))
    return base64.b64encode(buf.getvalue()).decode()


# 流式块自适应合并：fish 逐段(按 token chunk_length)吐 PCM，单段常偏小→直喂口型碎、每块有
# 固定开销。聚到「首块 ~300ms / 后续 ~550ms」再喂：首块小→保 TTFA 低，后续大→口型连贯；
# 单块上限 max_ms 防个别大段拖慢起播。0=该档不合并(逐段吐)。
_CONV_TTS_STREAM_FIRST_MS = int(os.environ.get("CONV_TTS_STREAM_FIRST_MS", "300"))
_CONV_TTS_STREAM_CHUNK_MS = int(os.environ.get("CONV_TTS_STREAM_CHUNK_MS", "550"))
_CONV_TTS_STREAM_MAX_MS   = int(os.environ.get("CONV_TTS_STREAM_MAX_MS", "1500"))

# 口型(视频)模式专用合并档：每个音频块=一次 MuseTalk 调用，单卡实测「固定开销≈256ms +
# 19.7ms/帧」。块太小→固定开销占比高→单卡渲染倍率掉到 <1×(0.3s块=0.78×,跟不上实时,
# 直播累积卡顿)。块≥1s音频→倍率≥1.33×,4s句切~4块总渲染≈3.0s(1.34×)稳达实时。故口型模式
# 用更大的块：首块 600ms(开场词走缓存,首帧延迟由缓存兜,这里只为内容句留余量) / 后续 1000ms。
# 纯音频模式不变(小块=低 TTFA)。可分别 env 覆盖。
_CONV_TTS_STREAM_LIP_FIRST_MS = int(os.environ.get("CONV_TTS_STREAM_LIP_FIRST_MS", "600"))
_CONV_TTS_STREAM_LIP_CHUNK_MS = int(os.environ.get("CONV_TTS_STREAM_LIP_CHUNK_MS", "1000"))
_CONV_TTS_STREAM_LIP_MAX_MS   = int(os.environ.get("CONV_TTS_STREAM_LIP_MAX_MS", "1800"))
# 高清(GFPGAN 增强)口型更重：单卡实测 28.5ms/帧(35fps上限,标准是 19.7ms/50fps)，每帧成本
# 高→渲染余量薄(整句仅 1.27×,2s块 1.16×,4块/4s句已 0.99× 跟不上)。实测整轮 RTF 在 0.75~1.12×
# 间抖动→流式的「多调用」HD 担不起。故 HD 用「逼近整句」的大块(典型句<5s→每句~1次调用→
# 吃满 1.27× 单卡上限)：开场词仍走缓存兜首帧延迟，内容句牺牲块内流式换取实时余量。
# 单卡 HD 直播余量本就薄，若仍卡顿请：①改用标准(不增强) ②加第二张 lipsync 卡(多副本并行)。
_CONV_TTS_STREAM_HD_FIRST_MS = int(os.environ.get("CONV_TTS_STREAM_HD_FIRST_MS", "1500"))
_CONV_TTS_STREAM_HD_CHUNK_MS = int(os.environ.get("CONV_TTS_STREAM_HD_CHUNK_MS", "4000"))
_CONV_TTS_STREAM_HD_MAX_MS   = int(os.environ.get("CONV_TTS_STREAM_HD_MAX_MS", "5000"))
# ditto 专用「首块」档：仅缩小首块以压首帧(首句首块越小→ditto 越早拿到音频→越早出第一帧)，中段/上限
# 仍沿用 LIP 档(实测 ditto 越小的块喂 vcam 越稳，故不动中段)。依据——600ms LIP 首块是为 MuseTalk
# 渲染余量定的，对「独立进程、首段仅 6 帧(240ms)」的 ditto 是纯首帧负担;纯 TTS 路径(stream_sse)用
# 180ms 首块实测 TTFA 中位 1178ms vs converse 600ms 首块 ~1.9s。300ms≈ditto 首段(6帧/240ms)对齐
# +少量余量。MuseTalk/HD 不走此分支(零回归)。
_CONV_TTS_STREAM_DITTO_FIRST_MS = int(os.environ.get("CONV_TTS_STREAM_DITTO_FIRST_MS", "300"))


def _pick_coalesce_params(lip_active: bool, lip_hd: bool, lip_eng: str = ""):
    """选本轮流式 PCM 合并档(first/chunk/max ms)。纯函数便于单测：
    纯音频→小块(低 TTFA)；口型(标准)→中块(每块≥1s,单卡 MuseTalk 渲染≥1.5×实时)；
    口型(HD/GFPGAN)→大块逼近整句(单卡 HD 渲染仅 ~1.27× 余量,经不起多调用)。
    注：ditto(流式推 vcam)实测「加大中段块」并不减少视频膨胀、反而段交付更爆发→vcam 队列瞬时
    见底→微卡顿增多(4→8),故 ditto 中段/上限沿用标准 LIP 档(更小块=更稳地喂 vcam);仅「首块」
    缩小(DITTO_FIRST,默认 300ms)以压首帧——首块越小 ditto 越早拿到首句音频→越早出第一帧。
    MuseTalk/HD 不走 ditto 分支(零回归)。"""
    if lip_hd:
        return (_CONV_TTS_STREAM_HD_FIRST_MS, _CONV_TTS_STREAM_HD_CHUNK_MS, _CONV_TTS_STREAM_HD_MAX_MS)
    if lip_active and lip_eng == "ditto":
        return (_CONV_TTS_STREAM_DITTO_FIRST_MS, _CONV_TTS_STREAM_LIP_CHUNK_MS, _CONV_TTS_STREAM_LIP_MAX_MS)
    if lip_active:
        return (_CONV_TTS_STREAM_LIP_FIRST_MS, _CONV_TTS_STREAM_LIP_CHUNK_MS, _CONV_TTS_STREAM_LIP_MAX_MS)
    return (_CONV_TTS_STREAM_FIRST_MS, _CONV_TTS_STREAM_CHUNK_MS, _CONV_TTS_STREAM_MAX_MS)


def _resolve_tts_engine(profile: dict, override: str = "") -> str:
    """与 _conv_build_tts_stream_fn 一致的引擎解析(用于就绪判定)。"""
    return (override or profile.get("tts_engine", "") or _CONV_TTS_ENGINE
            or _default_engine("tts") or "")


def _streaming_tts_ready(profile: dict | None = None) -> dict:
    """流式 TTS 开关 + 当前角色是否满足 fish 克隆音前置条件。"""
    p = profile or _profiles.get(_active_profile or "", {})
    eng = _resolve_tts_engine(p)
    has_voice = bool(p.get("voice_b64"))
    enabled = _CONV_TTS_STREAMING
    return {"enabled": enabled,
            "eligible": enabled and has_voice and bool(_fish_compat_svc(eng)),
            "engine": eng,
            "has_clone_voice": has_voice,
            "profile": p.get("name") or _active_profile or "",
            "slo_ttfa_p95_ms": SLO_TARGETS.get("stream_ttfa_p95_ms", 0),
            "low_latency_default": _STREAM_SSE_LOW_LATENCY_DEFAULT,   # Phase7: 流式首块加速灰度默认态(可观测)
            "coalesce": {"first_ms": _CONV_TTS_STREAM_FIRST_MS,
                         "chunk_ms": _CONV_TTS_STREAM_CHUNK_MS,
                         "max_ms": _CONV_TTS_STREAM_MAX_MS}}


def _streaming_tts_metrics() -> dict:
    """对话/观众两路首音延迟滚动分位(流式 vs 整句对照)。"""
    stream = sorted(_metrics["conv_stream_first_ms"])
    whole = sorted(_metrics["conv_whole_first_ms"])
    aud = sorted(_metrics["audience_first_ms"])
    aud_s = sorted(_metrics["audience_stream_first_ms"])
    def _win(xs):
        return {"samples": len(xs), "p50_ms": _pct(xs, 0.50), "p95_ms": _pct(xs, 0.95)}
    return {"conv_stream": _win(stream), "conv_whole": _win(whole),
            "audience": _win(aud), "audience_stream": _win(aud_s)}


def _streaming_tts_snapshot(profile: dict | None = None) -> dict:
    snap = _streaming_tts_ready(profile)
    snap["metrics"] = _streaming_tts_metrics()
    return snap


async def _coalesce_pcm_stream(pcm_aiter, *, sr: int, first_ms: int,
                               chunk_ms: int, max_ms: int):
    """把上游 PCM16(mono) 段流聚合成 ~首块 first_ms / 后续 chunk_ms 的块(上限 max_ms)。
    纯逻辑、与 HTTP/GPU 解耦，便于单测。first_ms<=0 时首块亦逐段吐；chunk_ms<=0 时后续逐段吐。"""
    bps = max(1, int(sr) * 2)                 # bytes/sec：mono int16
    buf = bytearray()
    first_done = False
    async for pcm in pcm_aiter:
        if not pcm:
            continue
        buf += pcm
        while True:
            thr_ms = chunk_ms if first_done else first_ms
            if thr_ms <= 0:                   # 该档不合并：整 buf 吐出
                if not buf:
                    break
                yield bytes(buf); buf.clear(); first_done = True; break
            thr_bytes = thr_ms * bps // 1000
            if len(buf) < thr_bytes:
                break
            max_bytes = (max_ms * bps // 1000) if max_ms > 0 else 0
            take = len(buf) if (max_bytes <= 0 or len(buf) <= max_bytes) else max_bytes
            yield bytes(buf[:take]); del buf[:take]; first_done = True
    if buf:
        yield bytes(buf)                      # 收尾：余量整块吐出

# 对话主链路 TTS 引擎覆盖：fish 单句 6-9s 太慢，CosyVoice(184) ~1.6s。设 "cosyvoice"
# 把对话逐句合成强制走 CosyVoice 克隆（仍按句带情感），fish 留给离线/高质量克隆。
# 空=尊重角色 tts_engine（不改变其它合成入口）。请求级 req.tts_engine 优先级更高。
_CONV_TTS_ENGINE = os.environ.get("CONV_TTS_ENGINE", "")

def _two_phase_enabled(req: "ConverseRequest") -> bool:
    if not (_TTFA_TWO_PHASE and req.speak and _conv is not None):
        return False
    be = _conv.registry.get_llm(req.llm_engine)
    if be is None or be.name.startswith("mock"):
        return False
    # 仅本地后端有与本地 TTS 的显存/算力争用；云端续写还会多一次远程往返
    return getattr(be, "kind", "local") == "local"

# 每会话的 barge-in 取消令牌：每一轮发言持有「自己的」Event(per-turn token)，而非
# 全会话共享。这样「直接发新一轮」即可可靠打断上一轮——开新轮时 set 掉旧令牌(旧轮在
# 检查点停止)、给新轮装一个全新令牌；不再有「fresh 清零反而把旧轮取消标志抹掉」的竞态，
# 也杜绝同一会话两轮并发(旧音/旧口型与新轮叠播)。
_conv_cancel: dict = {}

def _conv_get_cancel(sid: str):
    """取会话「当前活动轮」的取消令牌；interrupt 用其 .set() 打断当前轮。"""
    ev = _conv_cancel.get(sid)
    if ev is None:
        ev = asyncio.Event(); _conv_cancel[sid] = ev
    return ev

def _conv_new_turn_cancel(sid: str):
    """开启新一轮：set 掉旧令牌(打断上一轮，旧轮持引用→检查点处停)，装一个全新令牌给新轮。
    返回 (new_event, had_prev)；had_prev 表示此会话此前已有轮(用于决定是否清 vcam 队列)。"""
    old = _conv_cancel.get(sid)
    had_prev = old is not None
    if old is not None:
        old.set()
    ev = asyncio.Event()
    _conv_cancel[sid] = ev
    return ev, had_prev

async def _vcam_clear_async():
    """清空 vcam 播放队列(打断时让画面即时停说)。空闲时为无副作用 no-op。"""
    if not _vcam_enabled:
        return
    try:
        async with _aclient(timeout=2.0) as _cli:
            await _cli.post(f"{_VCAM_URL}/clear")
    except Exception:
        pass

async def _ditto_cancel_async():
    """打断时中止 ditto 在推的流式句(否则其上传线程会在 vcam 清空后继续回填画面)。
    fire-and-forget,无在推任务时为 no-op。"""
    base = SERVICES.get("ditto", "")
    if not base:
        return
    try:
        async with _aclient(timeout=2.0) as _cli:
            await _cli.post(f"{base.rstrip('/')}/ditto/cancel")
    except Exception:
        pass

# ── Phase 9-10：开场白缓存 ───────────────────────────────────────
# vllm 本机不可行(Win+sm_120)，AR 语音 token 生成 ~1s 是硬下限。改用「常见开场白
# 预合成缓存」：角色激活时用其音色后台预合成一组高频开场词，对话首句精确命中即 0ms
# 返回，感知 TTFA→~0。与 9-8 短开场互补(短开场让 LLM 多以这些词起头，提高命中率)。
_OPENER_PHRASES = [s for s in os.environ.get(
    "CONV_OPENER_PHRASES",
    "你好，|你好！|好的，|好的。|嗯，|嗯。|是的，|对，|当然，|当然可以，|没问题，|"
    "哈哈，|这个嘛，|让我想想，|我觉得，|其实，|确实，|不用谢，|不客气，|谢谢，|"
    "大家好，|我来说说，|这样啊，|原来如此，|没错，|可以的，|当然了，|嗯嗯，|"
    # 与 _SHORT_OPENER_HINT 引导词对齐的高频起手语（确保 LLM 起头即 0ms 命中）
    "说起来，|怎么说呢，|老实说，|要我说，|这样，|嗯…|我想想，|是这样，|"
    "其实吧，|说真的，|这么说吧，").split("|") if s.strip()]
# 开场词词干（去尾标点、≥2字、按长度降序）：用于首块"有词无逗号"也能切出并命中缓存。
_OPENER_STEMS = sorted(
    {p.rstrip("，,。.！!？?…、 ") for p in _OPENER_PHRASES
     if len(p.rstrip("，,。.！!？?…、 ")) >= 2},
    key=len, reverse=True)

# {profile_name: {text: audio_b64}}（音色随角色，故按角色名分桶）
_opener_cache: dict = {}
_opener_cache_lock = threading.Lock()

# ── 开场白缓存持久化（落盘 → 重启暖启，把"重启后首音又变慢"的退化堵死）──
# 缓存音频由角色音色/引擎决定，故用指纹做失效判定：音色/引擎/短语集任一变化即弃用旧盘缓存。
_OPENER_CACHE_DIR = Path(rf"{_BASE}\opener_cache")
_OPENER_CACHE_VERSION = "1"


def _opener_cache_fp(profile: dict) -> str:
    """对"影响中性合成音"的字段取指纹：变了就让盘上旧缓存失效，避免暖启出错音色。"""
    import hashlib
    keys = ["tts_engine", "vc_engine", "voice_b64", "active_ref", "references",
            "rvc_model", "rvc_settings", "seed", "opener_phrases", "emotion_refs"]
    snap = {k: profile.get(k) for k in keys
            if profile.get(k) not in (None, "", [], {})}
    eng = (profile.get("tts_engine") or os.environ.get("CONV_TTS_ENGINE", "")
           or _default_engine("tts"))
    blob = json.dumps(snap, sort_keys=True, ensure_ascii=False, default=str)
    h = hashlib.sha1()
    h.update((_OPENER_CACHE_VERSION + "|" + eng).encode("utf-8"))
    h.update(blob.encode("utf-8"))
    h.update(("|".join(_OPENER_PHRASES)).encode("utf-8"))
    return h.hexdigest()[:16]


def _opener_cache_path(name: str) -> Path:
    import hashlib
    # 用名字哈希做文件名，规避中文/非法字符与跨平台路径问题
    safe = hashlib.sha1(name.encode("utf-8")).hexdigest()[:16]
    return _OPENER_CACHE_DIR / f"{safe}.json"


def _opener_cache_save(name: str, profile: dict) -> None:
    """把某角色的开场白缓存原子落盘（含指纹）。"""
    try:
        with _opener_cache_lock:
            items = dict(_opener_cache.get(name, {}))
        if not items:
            return
        _OPENER_CACHE_DIR.mkdir(parents=True, exist_ok=True)
        payload = {"name": name, "fp": _opener_cache_fp(profile),
                   "version": _OPENER_CACHE_VERSION, "saved_at": time.time(),
                   "items": items}
        dst = _opener_cache_path(name)
        tmp = dst.with_suffix(".tmp")
        tmp.write_text(json.dumps(payload, ensure_ascii=False), encoding="utf-8")
        tmp.replace(dst)
        _logger.info(f"[OpenerCache] {name} 落盘 {len(items)} 条")
    except Exception as e:
        _logger.warning(f"[OpenerCache] 落盘失败 {name}: {e}")


def _opener_cache_load_all() -> None:
    """启动时载入盘上缓存：指纹匹配当前角色才用（音色变了则弃用，待激活重算）。"""
    try:
        if not _OPENER_CACHE_DIR.exists():
            return
        loaded = 0
        for name, p in list(_profiles.items()):
            try:
                fpth = _opener_cache_path(name)
                if not fpth.exists():
                    continue
                data = json.loads(fpth.read_text(encoding="utf-8"))
                if data.get("fp") != _opener_cache_fp(p):
                    continue   # 音色/引擎/短语集已变 → 弃用旧缓存
                items = data.get("items") or {}
                if items:
                    with _opener_cache_lock:
                        _opener_cache[name] = dict(items)
                    loaded += 1
            except Exception:
                continue
        if loaded:
            _logger.info(f"[OpenerCache] 启动暖启：载入 {loaded} 个角色的开场白缓存")
    except Exception as e:
        _logger.warning(f"[OpenerCache] 启动载入失败: {e}")


def _opener_cache_get(profile_name: str, text: str, emotion: str) -> str:
    if emotion and emotion not in ("neutral", "auto"):
        return ""   # 情感句音色不同，不命中中性缓存
    with _opener_cache_lock:
        return _opener_cache.get(profile_name, {}).get(text.strip(), "")


# ── Phase 9-11：思考音占位(填充音) ───────────────────────────────
# 未命中开场白缓存时,真实首句要 ~1s 合成。延迟触发:首句出现后若 _FILLER_DELAY 内
# 真实音频仍未到(=未命中),先吐一段预合成的极短填充音(复用开场白缓存),把未命中
# 场景的感知 TTFA 也压到 ~150ms;命中时(~150ms 到达)不触发,天然不双重说话。
_FILLER_ON = os.environ.get("CONV_FILLER", "1") == "1"
_FILLER_DELAY = float(os.environ.get("CONV_FILLER_DELAY_MS", "400")) / 1000.0
# 扩充自然语气词库：均为通用「思考垫词」，结尾「，」可顺接真实首句，不破坏语义
_FILLER_PHRASES = [s for s in os.environ.get(
    "CONV_FILLER_PHRASES",
    "嗯，|嗯…|这个嘛，|让我想想，|唔，|那个，|怎么说呢，|我想想哦，|嗯，这样的，"
).split("|") if s.strip()]
# 多语种思考垫词：与中文同理(极短、中性、可顺接真实首句)，让非中文回复的感知 TTFA
# 也从 ~3s 压到 ~1s。按朗读语种取用，语种作用域缓存键(见 _filler_cache_key)。
_FILLER_PHRASES_BY_LANG: dict[str, list] = {
    "zh-CN": _FILLER_PHRASES,
    "en":    ["Hmm,", "Well,", "Let me think,", "So,", "You know,"],
    "ja":    ["えーと、", "そうですね、", "うーん、", "ええと、"],
    "ko":    ["음,", "글쎄요,", "그러니까,", "어,"],
}

# 记录每个角色上一次用过的填充音内容键，避免连续重复（更自然）
_last_filler: dict = {}

# 打断应答词：被打断后开口先说一句，像真人被打断时的"嗯？您说"
_ACK_PHRASES = [s for s in os.environ.get(
    "CONV_ACK_PHRASES", "嗯，您说。|好的，您说。|我在听。|您讲。|嗯，我在。"
).split("|") if s.strip()]
_ACK_PHRASES_BY_LANG: dict[str, list] = {
    "zh-CN": _ACK_PHRASES,
    "zh-TW": ["嗯，您說。", "好的，您說。", "我在聽。", "您講。"],
    "en":    ["Yes, go ahead.", "I'm listening.", "Please continue.", "Go on."],
    "ja":    ["はい、どうぞ。", "聞いています。", "どうぞ続けて。", "はい。"],
    "ko":    ["네, 말씀하세요.", "듣고 있어요.", "계속 말씀해 주세요."],
}
_last_ack: dict = {}


def _ack_phrases_for(reply_lang: str) -> list:
    gl = _google_lang(reply_lang or "zh-CN")
    return _ACK_PHRASES_BY_LANG.get(gl) or _ACK_PHRASES


def _ack_cache_key(reply_lang: str, phrase: str) -> str:
    gl = _google_lang(reply_lang or "zh-CN")
    return f"ack|{gl}|{phrase}"


def _filler_phrases_for(profile: dict) -> list:
    """角色专属垫话优先（profile.filler_phrases），否则用全局默认库。"""
    fp = profile.get("filler_phrases") if isinstance(profile, dict) else None
    if fp and isinstance(fp, list):
        cleaned = [s for s in fp if isinstance(s, str) and s.strip()]
        if cleaned:
            return cleaned
    return _FILLER_PHRASES


def _filler_cache_key(glang: str, phrase: str) -> str:
    """填充音缓存键：中文沿用原始 phrase 键(兼容已有缓存)，其它语种按语种作用域。"""
    gl = _google_lang(glang or "zh-CN")
    return phrase if gl in ("zh-CN", "zh-TW") else f"filler|{gl}|{phrase}"


def _filler_phrases_for_lang(profile: dict, glang: str) -> list:
    """按朗读语种取填充音短语：中文用角色专属/默认库，其它语种用多语种库。"""
    gl = _google_lang(glang or "zh-CN")
    if gl in ("zh-CN", "zh-TW"):
        return _filler_phrases_for(profile)
    return _FILLER_PHRASES_BY_LANG.get(gl, [])


def _opener_phrases_for(profile: dict) -> list:
    """角色专属开场白优先合并进预合成列表（LLM 常以这些词起头 → 0ms 命中）。"""
    base = list(_OPENER_PHRASES)
    op = profile.get("opener_phrases") if isinstance(profile, dict) else None
    if op and isinstance(op, list):
        extra = [s for s in op if isinstance(s, str) and s.strip()]
        if extra:
            return list(dict.fromkeys(extra + base))
    return base


def _opener_prefix_hit(profile_name: str, profile: dict, head: str):
    """首块以某条已缓存开场白(中性)开头时，返回 (该开场白音频b64, 去掉前缀后的剩余文本)。
    取最长匹配前缀，确保剩余非空；无匹配返回 (None, head)。用于把「你好，今天…」拆成
    「你好，」(缓存秒回) + 「今天…」(现合成)，让感知 TTFA≈0 覆盖开场白起头的任意首句。"""
    h = (head or "").strip()
    if not h:
        return None, head
    with _opener_cache_lock:
        bucket = dict(_opener_cache.get(profile_name, {}))
    if not bucket:
        return None, head
    cands = sorted((p.strip() for p in _opener_phrases_for(profile)),
                   key=len, reverse=True)
    for ps in cands:
        if ps and bucket.get(ps) and h.startswith(ps) and len(h) > len(ps):
            return bucket[ps], h[len(ps):].lstrip()
    return None, head


def _pick_filler(profile_name: str, phrases: list | None = None,
                 reply_lang: str = "zh-CN") -> str:
    """从缓存取一条已预合成的填充音(按朗读语种)：随机 + 不与上一次相同，更自然。
    中文用原始 phrase 键(兼容)，其它语种用语种作用域键。未就绪返回 ''。"""
    import random
    gl = _google_lang(reply_lang or "zh-CN")
    plist = phrases or _FILLER_PHRASES
    with _opener_cache_lock:
        bucket = _opener_cache.get(profile_name, {})
        avail = [(p, bucket[_filler_cache_key(gl, p)]) for p in plist
                 if bucket.get(_filler_cache_key(gl, p))]
    if not avail:
        return ""
    _lk = f"{profile_name}|{gl}"
    last = _last_filler.get(_lk)
    pool = [x for x in avail if x[0] != last] or avail   # 全被排除则回退全集
    phrase, audio = random.choice(pool)
    _last_filler[_lk] = phrase
    return audio


def _pick_ack(profile_name: str, reply_lang: str = "zh-CN") -> str:
    """取一条已预合成的打断应答词（按朗读语种）：随机+不连续重复。未就绪返回 ''。"""
    import random
    gl = _google_lang(reply_lang or "zh-CN")
    phrases = _ack_phrases_for(gl)
    with _opener_cache_lock:
        bucket = _opener_cache.get(profile_name, {})
        avail = []
        for p in phrases:
            audio = bucket.get(_ack_cache_key(gl, p)) or (
                bucket.get(p) if gl in ("zh-CN", "zh-TW") else "")
            if audio:
                avail.append((p, audio))
    if not avail:
        return ""
    last_key = f"{profile_name}|{gl}"
    last = _last_ack.get(last_key)
    pool = [x for x in avail if x[0] != last] or avail
    phrase, audio = random.choice(pool)
    _last_ack[last_key] = phrase
    return audio


async def _precompute_openers(profile: dict):
    """角色激活后台预合成开场白+垫话(顺序、低优先，避免与人脸预计算抢 GPU)。"""
    name = profile.get("name", "")
    if not name:
        return
    # 垫话 + 打断应答词 + 开场白 + 开场词词干(无逗号形式，供"有词无逗号"命中)（去重保序）
    _fillers = _filler_phrases_for(profile)
    _openers = _opener_phrases_for(profile)
    _stems = sorted(
        {p.rstrip("，,。.！!？?…、 ") for p in _openers
         if len(p.rstrip("，,。.！!？?…、 ")) >= 2},
        key=len, reverse=True)
    _phrases = list(dict.fromkeys(_fillers + _ACK_PHRASES + _openers + _stems))
    _synth_n = 0          # 本轮真正新合成的条数（>0 才落盘，避免暖启时重写大文件）
    _ack_jobs: list[tuple[str, str, str]] = []   # (cache_key, phrase, tts_lang)
    for glang, acks in _ACK_PHRASES_BY_LANG.items():
        tts_l = (_LANG_MAP_TTS.get(glang, glang.lower().replace("-", "_")[:5])
                 if glang not in ("zh-CN", "zh-TW") else "zh-cn")
        for ph in acks:
            _ack_jobs.append((_ack_cache_key(glang, ph), ph, tts_l))
    # 非中文思考垫词(en/ja/ko…)：语种作用域键，与 ack 同批合成(中文垫词已在 _phrases 里)
    for glang, fills in _FILLER_PHRASES_BY_LANG.items():
        if glang in ("zh-CN", "zh-TW"):
            continue
        tts_l = _LANG_MAP_TTS.get(glang, glang.lower().replace("-", "_")[:5])
        for ph in fills:
            _ack_jobs.append((_filler_cache_key(glang, ph), ph, tts_l))
    # 连败即撤：TTS 引擎不在（Lite 档未装/服务未启动）时，逐条硬试 ~50 短语会拖 8 分钟、
    # 每条产出 3 行连接失败 WARNING 刷屏（2026-07-12 在 198 激活角色后实锤）。
    # 连续 3 条全链路合成失败 → 判定引擎不可用，本轮预热整体放弃（下次激活再试）。
    _fail_streak = 0
    for ph in _phrases:
        # 已缓存则跳过；其余逐条合成(中性)，存入缓存
        with _opener_cache_lock:
            if _opener_cache.get(name, {}).get(ph):
                continue
        try:
            b64 = await _conv_synthesize(ph, profile, language="zh-cn",
                                         emotion="neutral", vc_engine="",
                                         watermark=None, _use_opener_cache=False)
        except Exception:
            b64 = ""
        if b64:
            with _opener_cache_lock:
                _opener_cache.setdefault(name, {})[ph] = b64
            _synth_n += 1
            _fail_streak = 0
        else:
            _fail_streak += 1
            if _fail_streak >= 3:
                _logger.warning(f"[OpenerCache] {name} 预合成连续失败 {_fail_streak} 次，"
                                "判定 TTS 引擎不可用（未安装或未启动），本轮预热放弃")
                return
        await asyncio.sleep(0.05)   # 让出事件循环
    for key, ph, tts_l in _ack_jobs:
        with _opener_cache_lock:
            if _opener_cache.get(name, {}).get(key):
                continue
        try:
            b64 = await _conv_synthesize(ph, profile, language=tts_l,
                                         emotion="neutral", vc_engine="",
                                         watermark=None, _use_opener_cache=False)
        except Exception:
            b64 = ""
        if b64:
            with _opener_cache_lock:
                _opener_cache.setdefault(name, {})[key] = b64
            _synth_n += 1
            _fail_streak = 0
        else:
            _fail_streak += 1
            if _fail_streak >= 3:
                _logger.warning(f"[OpenerCache] {name} 垫话预合成连续失败 {_fail_streak} 次，"
                                "判定 TTS 引擎不可用，本轮预热放弃")
                return
        await asyncio.sleep(0.05)
    _logger.info(f"[OpenerCache] {name} 预合成完成: "
                 f"{len(_opener_cache.get(name, {}))}/{len(_OPENER_PHRASES)} 条")
    # 落盘暖启：仅当本轮有新合成才写（暖启全命中时不重复写大文件）
    if _synth_n > 0:
        _opener_cache_save(name, profile)


# ── 情感自适应 TTS：逐句从文本启发式推断情绪，按句动态发声 ──────────────
# 与 LLM 无关、零提示词污染、对任意角色即时生效。CosyVoice 直接支持 11 类情感；
# Fish-Speech 克隆路径无情感字段，故映射为 temperature/rep 微调以产生表现力差异。
_AUTO_EMOTION = os.environ.get("CONV_AUTO_EMOTION", "1") == "1"

# 情绪关键词（中文为主），优先级从上到下：安慰>开心>悲伤>惊讶>认真>中性
_EMOTION_CUES = [
    ("gentle",   ["别担心", "没关系", "别怕", "不用怕", "放心", "慢慢来", "会好的",
                   "别着急", "辛苦了", "抱抱", "陪着你", "我懂", "理解你", "加油",
                   "不要难过", "一切都会"]),
    ("happy",    ["哈哈", "太好了", "真棒", "太棒", "好开心", "高兴", "恭喜", "棒极了",
                   "真不错", "太赞", "好厉害", "耶", "嘻嘻", "开心", "好呀", "好耶"]),
    ("sad",      ["抱歉", "对不起", "很遗憾", "可惜", "难过", "伤心", "唉", "遗憾",
                   "失望", "心疼", "不好意思"]),
    ("surprised",["真的吗", "居然", "竟然", "哇", "没想到", "天哪", "不会吧", "惊讶",
                   "难以置信", "我的天"]),
    ("serious",  ["请注意", "务必", "必须", "重要的是", "切记", "请记住", "需要注意",
                   "特别提醒", "千万", "重点", "关键在于", "严格"]),
]
# Fish-Speech 克隆路径的情绪→采样参数微调（基于基线增量；温和以保音质）
_EMOTION_FISH_DELTA = {
    "happy":     {"temperature": +0.10, "repetition_penalty": -0.05},
    "excited":   {"temperature": +0.15, "repetition_penalty": -0.05},
    "surprised": {"temperature": +0.15},
    "sad":       {"temperature": -0.05},
    "gentle":    {"temperature": -0.05},
    "serious":   {"temperature": -0.10},
    "calm":      {"temperature": -0.05},
}


def _infer_emotion(text: str) -> str:
    """从单句文本启发式推断情绪标签。命中关键词即返回，默认 neutral。"""
    if not text:
        return "neutral"
    t = text.strip()
    for emo, cues in _EMOTION_CUES:
        if any(c in t for c in cues):
            return emo
    # 标点兜底：感叹号→更有活力(开心)，问号+短句→中性，省略号→平静
    excl = t.count("！") + t.count("!")
    if excl >= 1 and ("？" not in t and "?" not in t):
        return "happy"
    return "neutral"


# ── Phase9-9 共情：据【用户】情绪自适应回应口吻 + 语音情感 ───────────────────
# 既有 _infer_emotion 只看「助手回复文本」的措辞；本段补「读懂用户情绪 → 共情」这一真人化拼图：
#   ① 给 LLM 注入本轮语气引导（让回答措辞带共情）→ 自然流入既有逐句情感检测；
#   ② 用户明显苦恼(sad/angry)时，给中性措辞的句子兜一个温柔语音 bias，使「声音」也共情。
_AUTO_EMPATHY = os.environ.get("CONV_EMPATHY", "1") == "1"
# 用户情绪 → (回应语气引导, 语音情感 bias)。bias 仅在助手该句被判中性时兜底生效。
_EMPATHY_TONE = {
    "sad":       ("用户此刻情绪低落/难过。请先简短共情接纳其感受，语气温柔放缓、给予安慰与支持，"
                  "不要急于讲道理或转移话题。", "gentle"),
    "angry":     ("用户此刻有些生气/不满。请先平和地接纳其情绪、必要时致歉，语气稳重不对抗，"
                  "再务实地帮助解决问题。", "gentle"),
    "fearful":   ("用户此刻紧张/担心/不安。请先安抚情绪、给予确定感与支持，语气温柔笃定，"
                  "再一步步说明怎么办。", "gentle"),
    "happy":     ("用户此刻心情愉快。请用热情、有活力的语气回应，与对方分享这份好心情。", "happy"),
    "excited":   ("用户此刻很兴奋/激动。请用同样热情高涨的语气回应，呼应并放大这份喜悦。", "happy"),
    "surprised": ("用户感到惊讶/好奇。请用同样好奇、有兴致的语气回应，顺着这份新鲜感展开。", "happy"),
    "disgusted": ("用户表达了反感/不适。请认真接纳其感受、不评判，语气理解而稳重。", "gentle"),
    "neutral":   ("", ""),
}
# 每会话「本轮共情结果」：empathy_fn 写、_emotion_for 读（按 session_id 隔离，避免穿插）。
_turn_empathy: dict = {}
# 9-10 多轮情绪轨迹：按 session_id 记最近用户情绪，连续负面 ≥ 阈值 → 升级共情（更主动关怀）。
_EMO_NEGATIVE = {"sad", "angry", "fearful", "disgusted"}
_EMO_POSITIVE = {"happy", "excited"}                         # 9-11 由负转正识别用
_emotion_history: dict = {}                                  # session_id -> [最近情绪标签]
_EMO_TRAJ_N = int(os.environ.get("CONV_EMO_TRAJ_N", "2"))    # 连续负面轮阈值（达到则升级）
_EMO_TRAJ_KEEP = 8                                           # 每会话保留的情绪轨迹长度


def _empathy_for_user_emotion(user_emotion: str) -> tuple:
    return _EMPATHY_TONE.get(user_emotion or "neutral", ("", ""))


def _build_empathy_fn(session_id: str, enabled: bool):
    """构造传给编排器的共情回调：输入=用户文本(STT后)，输出={user_emotion, tone_hint, ...}。
    同时把语音 bias 落 _turn_empathy[session_id] 供 _emotion_for 读取。失败静默降级。"""
    if not enabled:
        _turn_empathy.pop(session_id, None)
        return None

    def _fn(user_text: str) -> dict:
        ue, conf = "neutral", 0.0
        try:
            from emotion_detector import detect_emotion_detail as _detd
            d = _detd(user_text) or {}
            ue = d.get("emotion", "neutral") or "neutral"
            conf = float(d.get("confidence", 0.0) or 0.0)
        except Exception:
            try:
                from emotion_detector import detect_emotion as _det
                ue = _det(user_text) or "neutral"
            except Exception:
                ue = "neutral"
        tone_hint, bias = _empathy_for_user_emotion(ue)
        # 9-10 多轮情绪轨迹：累计本会话情绪，统计「当前连续负面轮数」
        hist = _emotion_history.setdefault(session_id, [])
        hist.append(ue)
        if len(hist) > _EMO_TRAJ_KEEP:
            del hist[:-_EMO_TRAJ_KEEP]
        neg_streak = 0
        for e in reversed(hist):
            if e in _EMO_NEGATIVE:
                neg_streak += 1
            else:
                break
        escalated = False
        if ue in _EMO_NEGATIVE and neg_streak >= _EMO_TRAJ_N:
            tone_hint = (tone_hint + " 该用户已连续多轮情绪不佳，请更主动地表达关心、"
                         "轻声询问发生了什么或是否需要帮助，避免敷衍或急于结束话题。").strip()
            bias = bias or "gentle"
            escalated = True
        # 9-11 由负转正：之前两轮内出现过负面、本轮转积极、且上一轮不是积极（只在转折点触发一次，
        # 避免连续积极时反复鼓励）→ 真诚肯定+鼓励，强化向好势头
        encourage = False
        _prev = hist[-2] if len(hist) >= 2 else ""
        if (ue in _EMO_POSITIVE and _prev not in _EMO_POSITIVE
                and any(e in _EMO_NEGATIVE for e in hist[-3:-1])):
            tone_hint = (tone_hint + " 用户情绪由低落明显转好，请真诚地肯定这份积极、"
                         "给予温暖鼓励，强化这份向上的势头。").strip()
            encourage = True
        _turn_empathy[session_id] = {"user_emotion": ue, "bias": bias}
        return {"user_emotion": ue, "confidence": round(conf, 3),
                "tone": ("comfort" if bias == "gentle" else
                         ("upbeat" if bias == "happy" else "")),
                "neg_streak": neg_streak, "escalated": escalated,
                "encourage": encourage, "tone_hint": tone_hint}
    return _fn


def _reset_empathy_state(session_id: str):
    """会话重置时清理共情/情绪轨迹状态（避免跨会话串味）。"""
    _turn_empathy.pop(session_id, None)
    _emotion_history.pop(session_id, None)


# Fish-Speech 默认 seed：固定采样路径以消除合成延迟抖动（见 _conv_synthesize 注释）。
# 置 -1（或环境变量 CONV_FISH_SEED=-1）恢复随机 seed（每次音色微变、延迟忽高忽低）。
_FISH_DEFAULT_SEED = int(os.environ.get("CONV_FISH_SEED", "42"))

def _fish_seed_for(ftp: dict):
    """优先用 profile 显式 seed；未设(None)则回退全局默认；默认<0 表示随机。"""
    s = ftp.get("seed") if isinstance(ftp, dict) else None
    if s is not None:
        return s
    return _FISH_DEFAULT_SEED if _FISH_DEFAULT_SEED >= 0 else None


_JP_CHARS = set("あいうえおかきくけこさしすせそたちつてとなにぬねのはひふへほまみむめもやゆよらりるれろわをんアイウエオカキクケコサシスセソタチツテトナニヌネノハヒフヘホマミムメモヤユヨラリルレロワヲン")

def _has_japanese(text: str) -> bool:
    return any(c in _JP_CHARS for c in text)


# CosyVoice 参考音频时长上限：克隆只需 ~5-10s，过长(如 20s)会让每句都付昂贵的说话人
# 特征抽取(onnx campplus+tokenizer)。裁到固定时长既降抽取耗时，又让字节稳定→中性句命中
# emotion 服务的 ref-spk 缓存(只首句抽取)。fish 不裁(长参考有助其零样本音质)。
_COSY_REF_SEC = float(os.environ.get("COSY_REF_SEC", "10"))

def _trim_wav_b64(b64: str, max_sec: float) -> str:
    try:
        import wave, io as _io
        raw = base64.b64decode(b64)
        w = wave.open(_io.BytesIO(raw))
        fr = w.getframerate()
        want = int(fr * max_sec)
        if w.getnframes() <= want:
            return b64
        frames = w.readframes(want)
        out = _io.BytesIO()
        ww = wave.open(out, "wb")
        ww.setnchannels(w.getnchannels()); ww.setsampwidth(w.getsampwidth()); ww.setframerate(fr)
        ww.writeframes(frames); ww.close()
        return base64.b64encode(out.getvalue()).decode()
    except Exception:
        return b64

# fish 就绪门控：fish 重启/编译(~3min)期间 model_loaded=False，此时对话本句临时走
# CosyVoice 兜底，编译好自动切回 fish——消除重启窗口的"对话断声"。带 TTL 缓存：就绪时
# 15s 探一次(几乎零开销)，未就绪时 3s 探一次(尽快发现恢复)。fish /health 返回 model_loaded。
_FISH_READY = {"ready": False, "ts": 0.0}
_FISH_READY_TTL_OK = 15.0
_FISH_READY_TTL_BAD = 3.0
# fish-兼容引擎各自的就绪缓存（fish_tts 仍用 _FISH_READY 以零回归；qwen3_tts 等用本表）。
_TTS_READY_CACHE: dict = {}

async def _fish_ready(svc_key: str = "fish_tts") -> bool:
    """fish-兼容 TTS 模型是否已加载完成(非编译/重启中)。低开销带 TTL 缓存。
    默认探 fish_tts（与改造前完全一致）；传 qwen3_tts 等可探对应服务（各自独立缓存）。"""
    st = _FISH_READY if svc_key == "fish_tts" else _TTS_READY_CACHE.setdefault(
        svc_key, {"ready": False, "ts": 0.0})
    now = time.time()
    ttl = _FISH_READY_TTL_OK if st["ready"] else _FISH_READY_TTL_BAD
    if now - st["ts"] < ttl:
        return st["ready"]
    ready = False
    try:
        _hp = health_pool or http_pool
        r = await _hp.get(f"{SERVICES[svc_key]}/health", timeout=1.5)
        if r.status_code == 200:
            ready = bool(r.json().get("model_loaded", False))
    except Exception:
        ready = False
    if ready != st["ready"]:
        _logger.info(f"[TTS] {svc_key} 就绪状态变化 → {'就绪' if ready else '未就绪(临时走兜底TTS)'}")
    st["ready"] = ready
    st["ts"] = now
    return ready


# ── TTS 双通道并发分流（Phase#2）──────────────────────────────────────────────
# 设计初衷：单卡 fish 串行是多用户并发的瓶颈，想把溢出轮分流到 CosyVoice(184) 与 fish 并行。
# 实测结论(2026-06)：本机硬件**不对称**——fish(5090)≈6s/轮，cosy(4070@184)≈9-11s/轮且更慢。
# FISH_MAX_TURNS=1 时 10 路并发把 9 轮全压到「更慢的」单实例 cosy 串行→总时长 39s 劣化到 108s；
# 即便理论最优分流(6 fish/4 cosy)也仅 ~36s vs 39s，收益微薄却牺牲音质，而本产品是「单路直播」
# (并发恒为1→永远走 fish 最优)。故**忙时溢出默认关闭**(CONV_DUAL_TTS=0)，保留高质量单路 fish；
# 仅保留「fish 未就绪(编译/重启)→整轮固定 cosy」这一**正确性兜底**(与 _DUAL_TTS_ON 解耦)。
# 对称多卡或多主播场景可置 CONV_DUAL_TTS=1 + 调 FISH_MAX_TURNS 重新启用。
_DUAL_TTS_ON = os.environ.get("CONV_DUAL_TTS", "0") != "0"      # 忙时溢出分流，默认关
_FISH_MAX_TURNS = int(os.environ.get("FISH_MAX_TURNS", "1"))   # 同时占用 fish 的进行中轮次上限
_fish_turns = 0                                               # 当前占用 fish 通道的轮次计数
_TTS_CHAN_STATS = {"fish": 0, "cosy_overflow": 0, "cosy_notready": 0,
                   "fish_queue": 0, "passthrough": 0, "peak_fish_turns": 0}
_cosy_ok = {"ok": True, "ts": 0.0}                           # CosyVoice 可达性缓存(溢出前确认)


async def _cosy_reachable() -> bool:
    """CosyVoice(emotion_tts 184) 是否可达。10s 缓存，溢出决策用。"""
    now = time.time()
    if now - _cosy_ok["ts"] < 10.0:
        return _cosy_ok["ok"]
    ok = False
    try:
        _hp = health_pool or http_pool
        r = await _hp.get(f"{SERVICES['emotion_tts']}/health", timeout=1.2)
        ok = (r.status_code == 200)
    except Exception:
        ok = False
    _cosy_ok["ok"] = ok
    _cosy_ok["ts"] = now
    return ok


def _profile_wants_fish(req: "ConverseRequest", profile: dict) -> bool:
    eng = (req.tts_engine or _CONV_TTS_ENGINE or profile.get("tts_engine", "")).strip()
    if not _fish_compat_svc(eng):        # fish_speech / qwen3_tts… 共用重型 TTS 并发通道
        return False
    return bool(profile.get("voice_b64") or profile.get("fish_refs")
                or profile.get("emotion_refs"))


async def _acquire_tts_channel(req: "ConverseRequest", profile: dict):
    """轮首决策本轮 TTS 通道，返回 (engine_override, claimed_fish, info)。
    engine_override 为 "" 时维持原有逐句路由(角色非 fish 时)；为 "fish_speech"/"cosyvoice" 时
    全轮锁定该引擎。claimed_fish=True 表示占了一个 fish 并发槽，轮尾须 release。"""
    global _fish_turns
    if not req.speak or not _profile_wants_fish(req, profile):
        _TTS_CHAN_STATS["passthrough"] += 1
        return "", False, "passthrough"
    # 本轮解析到的 fish-兼容引擎（fish_speech / qwen3_tts…），全轮锁定该引擎而非写死 fish。
    _eng = (req.tts_engine or _CONV_TTS_ENGINE or profile.get("tts_engine", "")).strip()
    _svc = _fish_compat_svc(_eng) or "fish_tts"
    if not await _fish_ready(_svc):
        # 重型 TTS 编译/重启中：整轮固定 cosy(若可达)，避免编译完成时中途切换音色。
        # 这是正确性兜底(消除重启窗口断声)，与忙时溢出无关，故不受 _DUAL_TTS_ON 开关影响。
        if await _cosy_reachable():
            _TTS_CHAN_STATS["cosy_notready"] += 1
            return "cosyvoice", False, f"{_eng}_not_ready→cosy"
        return _eng, False, f"{_eng}_not_ready_no_cosy"
    if _fish_turns < _FISH_MAX_TURNS:
        _fish_turns += 1
        _TTS_CHAN_STATS["fish"] += 1
        _TTS_CHAN_STATS["peak_fish_turns"] = max(_TTS_CHAN_STATS["peak_fish_turns"], _fish_turns)
        return _eng, True, f"{_eng}(slot {_fish_turns}/{_FISH_MAX_TURNS})"
    # 满载 → 溢出到 cosy 与之并行（cosy 不可达则仍排队，保证不丢句）
    if _DUAL_TTS_ON and await _cosy_reachable():
        _TTS_CHAN_STATS["cosy_overflow"] += 1
        return "cosyvoice", False, "overflow→cosy"
    _TTS_CHAN_STATS["fish_queue"] += 1
    return _eng, False, "overflow_no_cosy(queue_fish)"


def _release_tts_channel(claimed: bool):
    global _fish_turns
    if claimed:
        _fish_turns = max(0, _fish_turns - 1)


# ── 运维指标落盘（Phase#3）──────────────────────────────────────────────────
# /ops 看板原为内存态，重启清零。落盘到 JSONL 做趋势/留痕，带行数上限滚动裁剪。
_OPS_PERSIST_ON = os.environ.get("OPS_PERSIST", "1") != "0"
_OPS_PERSIST_SEC = int(os.environ.get("OPS_PERSIST_SEC", "60"))
_OPS_LOG_MAX_LINES = int(os.environ.get("OPS_LOG_MAX_LINES", "20000"))   # ~13.8天@60s
_OPS_LOG_PATH = Path(rf"{_BASE}\logs\ops_metrics.jsonl")
_ops_persist_n = {"writes": 0}


def _ops_persist_append(rec: dict):
    try:
        _OPS_LOG_PATH.parent.mkdir(parents=True, exist_ok=True)
        with open(_OPS_LOG_PATH, "a", encoding="utf-8") as f:
            f.write(json.dumps(rec, ensure_ascii=False) + "\n")
        _ops_persist_n["writes"] += 1
        # 周期裁剪：每 200 次写检查一次行数，超限保留后半段
        if _ops_persist_n["writes"] % 200 == 0:
            try:
                lines = _OPS_LOG_PATH.read_text(encoding="utf-8").splitlines()
                if len(lines) > _OPS_LOG_MAX_LINES:
                    keep = lines[-(_OPS_LOG_MAX_LINES // 2):]
                    _OPS_LOG_PATH.write_text("\n".join(keep) + "\n", encoding="utf-8")
            except Exception:
                pass
    except Exception:
        pass


# ── 前端客户端日志上报（pageerror / unhandledrejection / 自定义）─────────────
_CLIENTLOG_PATH = Path(rf"{_BASE}\logs\client_errors.jsonl")
_CLIENTLOG_MAX_LINES = 2000
_clientlog_n = {"writes": 0}
_clientlog_lock = threading.Lock()


def _clientlog_append(rec: dict):
    try:
        _CLIENTLOG_PATH.parent.mkdir(parents=True, exist_ok=True)
        with _clientlog_lock:
            with open(_CLIENTLOG_PATH, "a", encoding="utf-8") as f:
                f.write(json.dumps(rec, ensure_ascii=False) + "\n")
            _clientlog_n["writes"] += 1
            if _clientlog_n["writes"] % 100 == 0:
                try:
                    lines = _CLIENTLOG_PATH.read_text(encoding="utf-8").splitlines()
                    if len(lines) > _CLIENTLOG_MAX_LINES:
                        keep = lines[-(_CLIENTLOG_MAX_LINES // 2):]
                        _CLIENTLOG_PATH.write_text("\n".join(keep) + "\n", encoding="utf-8")
                except Exception:
                    pass
    except Exception:
        pass


def _clip(v, n: int) -> str:
    s = "" if v is None else str(v)
    return s[:n]


@app.post("/api/clientlog")
async def api_clientlog(request: Request):
    """接收前端运行时错误/告警，落盘到 logs\\client_errors.jsonl（写多读少，防滥用截断）。"""
    try:
        raw = await request.body()
        if len(raw) > 16384:          # 单包上限 16KB，防滥用
            raw = raw[:16384]
        try:
            body = json.loads(raw.decode("utf-8", "ignore") or "{}")
        except Exception:
            body = {}
        if not isinstance(body, dict):
            body = {}
        rec = {
            "ts":     time.time(),
            "level":  _clip(body.get("level") or "error", 16),
            "kind":   _clip(body.get("kind") or "pageerror", 32),
            "msg":    _clip(body.get("msg"), 1000),
            "stack":  _clip(body.get("stack"), 2000),
            "page":   _clip(body.get("page"), 200),
            "src":    _clip(body.get("src"), 300),
            "line":   _clip(body.get("line"), 12),
            "col":    _clip(body.get("col"), 12),
            "ua":     _clip(request.headers.get("user-agent"), 300),
            "client": (request.client.host if request.client else "") or "",
        }
        _clientlog_append(rec)
        try:
            _logger.warning(f"[ClientLog] {rec['kind']} @{rec['page']}: {rec['msg'][:160]}")
        except Exception:
            pass
        return {"ok": True}
    except Exception as e:
        return JSONResponse({"ok": False, "detail": str(e)[:200]}, status_code=200)


# ── 入口埋点（UI 事件漏斗）：与错误日志分离的独立"只写"通道 ─────────────────
#   为何不复用 /api/clientlog：那是"错误"语义(落 client_errors.jsonl，/ops 当错误面板展示)，且前端
#   _clientlog 有"去重 + 40/会话上限"——点击会被去重丢弃并污染错误面板。故独立成 ui_events.jsonl。
_UIEVENT_PATH = Path(rf"{_BASE}\logs\ui_events.jsonl")
_UIEVENT_MAX_LINES = 5000
_uievent_n = {"writes": 0}
_uievent_lock = threading.Lock()


def _uievent_append(rec: dict):
    try:
        _UIEVENT_PATH.parent.mkdir(parents=True, exist_ok=True)
        with _uievent_lock:
            with open(_UIEVENT_PATH, "a", encoding="utf-8") as f:
                f.write(json.dumps(rec, ensure_ascii=False) + "\n")
            _uievent_n["writes"] += 1
            if _uievent_n["writes"] % 200 == 0:      # 写多读少：周期截断，防无限增长
                try:
                    lines = _UIEVENT_PATH.read_text(encoding="utf-8").splitlines()
                    if len(lines) > _UIEVENT_MAX_LINES:
                        keep = lines[-(_UIEVENT_MAX_LINES // 2):]
                        _UIEVENT_PATH.write_text("\n".join(keep) + "\n", encoding="utf-8")
                except Exception:
                    pass
    except Exception:
        pass


@app.post("/api/ui/event")
async def api_ui_event(request: Request):
    """接收前端入口埋点（点击/导航漏斗），落盘 logs\\ui_events.jsonl（只写不可读、防滥用截断）。
    非敏感、免鉴权（与 /api/clientlog 同级）：仅记录页内入口 id，不含 PII。"""
    try:
        raw = await request.body()
        if len(raw) > 4096:               # 单包上限 4KB，防滥用
            raw = raw[:4096]
        try:
            body = json.loads(raw.decode("utf-8", "ignore") or "{}")
        except Exception:
            body = {}
        if not isinstance(body, dict):
            body = {}
        rec = {
            "ts":      round(time.time(), 2),
            "ev":      _clip(body.get("ev") or "click", 24),
            "id":      _clip(body.get("id"), 48),
            "line":    _clip(body.get("line"), 32),
            "edition": _clip(body.get("edition"), 12),
            "href":    _clip(body.get("href"), 200),
            "page":    _clip(body.get("page"), 120),
            "sid":     _clip(body.get("sid"), 24),
        }
        _uievent_append(rec)
        return {"ok": True}
    except Exception as e:
        return JSONResponse({"ok": False, "detail": str(e)[:200]}, status_code=200)


@app.get("/api/ui/events/summary")
def api_ui_events_summary(days: float = 0.0, limit: int = 8):
    """入口埋点聚合（只读、非敏感；GET 默认放行）：供 /ops「入口热度」把首页点击漏斗可视化。
    days>0 仅统计近 N 天；limit 控制各 Top 列表长度。文件缺失/空 → available=False 优雅降级。
    功能名/产品线联 FEATURE_REGISTRY 现取（单一真相，避免前端另存清单漂移）。"""
    try:
        if not _UIEVENT_PATH.exists():
            return {"ok": True, "available": False, "total": 0, "sessions": 0}
        cutoff = (time.time() - days * 86400.0) if (days and days > 0) else 0.0
        by_ev: dict = {}
        feat: dict = {}
        role: dict = {}
        line: dict = {}
        sids = set()
        total = 0
        since = None
        until = None
        try:
            raw_lines = _UIEVENT_PATH.read_text(encoding="utf-8").splitlines()
        except Exception:
            raw_lines = []
        for ln in raw_lines[-_UIEVENT_MAX_LINES:]:
            ln = ln.strip()
            if not ln:
                continue
            try:
                r = json.loads(ln)
            except Exception:
                continue
            if not isinstance(r, dict):
                continue
            ts = r.get("ts") or 0
            if cutoff and ts and ts < cutoff:
                continue
            total += 1
            ev = r.get("ev") or "click"
            by_ev[ev] = by_ev.get(ev, 0) + 1
            rid = r.get("id") or ""
            if ev == "feature" and rid:
                feat[rid] = feat.get(rid, 0) + 1
            elif ev == "role" and rid:
                role[rid] = role.get(rid, 0) + 1
            rln = r.get("line") or ""
            if rln:
                line[rln] = line.get(rln, 0) + 1
            sid = r.get("sid") or ""
            if sid:
                sids.add(sid)
            if ts:
                since = ts if since is None else min(since, ts)
                until = ts if until is None else max(until, ts)
        reg_by_id = {f.get("id"): f for f in FEATURE_REGISTRY}

        def _top(d, n):
            return [{"k": k, "n": v} for k, v in sorted(d.items(), key=lambda kv: kv[1], reverse=True)[:max(1, n)]]

        def _top_feat(d, n):
            out = []
            for k, v in sorted(d.items(), key=lambda kv: kv[1], reverse=True)[:max(1, n)]:
                f = reg_by_id.get(k) or {}
                out.append({"id": k, "n": v, "name": f.get("name") or k, "line": f.get("line") or ""})
            return out

        return {
            "ok": True,
            "available": total > 0,
            "total": total,
            "sessions": len(sids),
            "since": since,
            "until": until,
            "by_ev": by_ev,
            "top_features": _top_feat(feat, limit),
            "top_roles": _top(role, limit),
            "top_lines": _top(line, limit),
        }
    except Exception as e:
        return JSONResponse({"ok": False, "detail": str(e)[:200]}, status_code=200)


@app.get("/api/clientlog/recent")
async def api_clientlog_recent(limit: int = 50):
    """运维查看最近的前端错误（敏感读，需令牌）。"""
    try:
        if not _CLIENTLOG_PATH.exists():
            return {"ok": True, "items": [], "total": 0}
        lines = _CLIENTLOG_PATH.read_text(encoding="utf-8").splitlines()
        limit = max(1, min(int(limit or 50), 500))
        items = []
        for ln in lines[-limit:]:
            try:
                items.append(json.loads(ln))
            except Exception:
                pass
        return {"ok": True, "items": list(reversed(items)), "total": len(lines)}
    except Exception as e:
        return JSONResponse({"ok": False, "detail": str(e)[:200]}, status_code=200)


async def _conv_synthesize(text: str, profile: dict, *, language: str,
                           emotion: str, vc_engine: str,
                           watermark, _use_opener_cache: bool = True,
                           prefer_engine: str = "") -> str:
    """对话内逐句 TTS：Fish-Speech(优先) / CosyVoice / XTTS，可选 RVC + 水印，返回 audio base64。
    prefer_engine: 覆盖角色的 tts_engine（对话主链路用它强制走 CosyVoice 以压低实时延迟，
    fish 仍保留给离线/高质量克隆）。空=用角色配置（保持其它调用方不变）。"""
    # 语言兜底：中文对话里混入日文假名 → 去掉假名朗读其余中文；几乎整句日文才跳过
    if language and language.lower().startswith("zh") and _has_japanese(text):
        cleaned = "".join(c for c in text if c not in _JP_CHARS)
        if len(cleaned.strip()) >= max(2, len(text) // 2):
            _logger.warning(f"[TTS] 中文回复混入日文假名，已剔除: {text[:40]!r}")
            text = cleaned
        else:
            _logger.warning(f"[TTS] 整句疑似日文，跳过合成: {text[:40]!r}")
            return ""
    # 开场白缓存命中 → 0ms 返回（仅中性句）
    if _use_opener_cache:
        _hit = _opener_cache_get(profile.get("name", ""), text, emotion)
        if _hit:
            return _hit
    voice_b64  = profile.get("voice_b64", "")
    voice_name = profile.get("voice_name", "") or "female_01.wav"
    audio_b64 = ""
    _src = "cosyvoice"

    # Fish-Speech 路由：profile.tts_engine == "fish_speech" 时优先使用
    # prefer_engine 覆盖角色配置（对话链路传 "cosyvoice" 强制快路径；"fish_speech" 强制 fish）
    _tts_eng = prefer_engine or profile.get("tts_engine", "")
    # 多段参考：profile.fish_refs = [{voice_b64, text}, ...]，优先于单段
    _fish_refs = profile.get("fish_refs") or []
    # 情绪参考音：profile.emotion_refs = {emotion: [{voice_b64, text}, ...]}
    #   零样本克隆的情绪源自参考音频。命中推断情绪→改用该情绪的参考录音，
    #   Fish 克隆其语气=强情感；未命中→回退默认参考 + 采样参数微调(弱情感)。
    _emo_refs_map = profile.get("emotion_refs") or {}
    _emo_segs = (_emo_refs_map.get(emotion) or []) if emotion and emotion != "neutral" else []
    # fish 就绪门控：选 fish 但其正在编译/重启(model_loaded=False)时，跳过 fish 直接走下方
    # CosyVoice 兜底；编译好后 _fish_ready() 自动转 True，本句起又回到 fish。
    _fish_svc = _fish_compat_svc(_tts_eng)     # fish_speech / qwen3_tts… → 服务键
    _want_fish = bool(_fish_svc) and (voice_b64 or _fish_refs or _emo_segs)
    if _want_fish and not await _fish_ready(_fish_svc):
        _want_fish = False
    if _want_fish:
        _src = _tts_eng
        _ftp = profile.get("fish_tts_params") or {}
        _base_temp = _ftp.get("temperature", 0.7)
        _base_rep  = _ftp.get("repetition_penalty", 1.2)
        if _emo_segs:
            # 情绪参考命中：用情绪录音作参考，韵律由参考承载，参数保持基线
            _emo_temp, _emo_rep = _base_temp, _base_rep
            _use_refs = [{"audio_b64": s.get("voice_b64", ""), "text": s.get("text", "")}
                         for s in _emo_segs if s.get("voice_b64")]
        else:
            # 无情绪参考：采样参数微调产生表现力差异(弱情感兜底)
            _delta = _EMOTION_FISH_DELTA.get(emotion, {}) if emotion else {}
            _emo_temp = round(min(1.0, max(0.4, _base_temp + _delta.get("temperature", 0.0))), 3)
            _emo_rep  = round(min(1.5, max(1.0, _base_rep + _delta.get("repetition_penalty", 0.0))), 3)
            _use_refs = [{"audio_b64": s.get("voice_b64", ""), "text": s.get("text", "")}
                         for s in _fish_refs if s.get("voice_b64")]
        try:
            epay = {
                "text":                text,
                "reference_audio_b64": ("" if _emo_segs else voice_b64),
                "reference_text":      _ftp.get("reference_text", ""),
                "language":            language or "zh",
                "temperature":         _emo_temp,
                "top_p":               _ftp.get("top_p", 0.7),
                "repetition_penalty":  _emo_rep,
                "chunk_length":        _ftp.get("chunk_length", 200),
                # 固定 seed 大幅降低 AR 采样抖动：实测延迟 CV 38%→8%、尾延迟 -48%、中位 -20%
                # （音色仍由参考音决定，seed 仅固定采样路径→同文本可复现、不再忽快忽慢）。
                # profile 显式设了 seed 则尊重其值；未设则用全局默认；置 -1 可恢复随机。
                "seed":                _fish_seed_for(_ftp),
            }
            if _use_refs:
                epay["references"] = _use_refs
            async with _svc_lease(_fish_svc) as _fbase:   # P-Conc5: 多卡时散到不同 GPU 副本
                r = await http_pool.post(f"{_fbase}/v1/tts/clone", json=epay, timeout=120)
            if r.status_code == 200:
                audio_b64 = r.json().get("audio_base64", "")
        except Exception:
            audio_b64 = ""

    # 回退 / 非 fish-兼容引擎：CosyVoice(emotion_tts 7852)
    if not audio_b64:
        _src = "cosyvoice"
        try:
            epay = {"text": text, "emotion": (emotion or "neutral"), "speed": 1.0, "return_base64": True}
            async with _svc_lease("emotion_tts") as _cbase:   # P-Conc5: 多卡时散到不同 GPU 副本
                if voice_b64:
                    epay["reference_audio_b64"] = _trim_wav_b64(voice_b64, _COSY_REF_SEC)
                    ep = f"{_cbase}/v1/tts/clone"
                else:
                    ep = f"{_cbase}/v1/tts"
                r = await http_pool.post(ep, json=epay, timeout=120)
            if r.status_code == 200:
                audio_b64 = r.json().get("audio_base64", "")
            else:
                _logger.warning(f"[TTS/cosy] HTTP {r.status_code}: {r.text[:160]}")
        except Exception as _e:
            _logger.warning(f"[TTS/cosy] EXC {type(_e).__name__}: {_e}")
            audio_b64 = ""
    if not audio_b64:
        # 回退：7851（XTTS / 临时 SAPI）
        _src = "xtts"
        try:
            r = await _call_tts(voice_b64, voice_name, text, language)
            if r.status_code == 200:
                audio_b64 = (r.json().get("audio_base64", "") if voice_b64
                             else base64.b64encode(r.content).decode())
        except Exception:
            audio_b64 = ""
    if not audio_b64:
        return ""
    # 可选 RVC（经 Phase6 分发）
    rvc_model = profile.get("rvc_model", "")
    if rvc_model:
        try:
            _vce = vc_engine or profile.get("vc_engine", "") or _default_engine("vc")
            rvc_r = await _vc_dispatch(_vce, audio_b64, rvc_model, profile.get("rvc_settings", {}))
            if rvc_r.status_code == 200:
                audio_b64 = rvc_r.audio_b64 or audio_b64
        except Exception:
            pass
    # 可选水印（Phase11，合规默认开）
    _wm = PROVENANCE_ENABLED if watermark is None else watermark
    if _wm and _provenance is not None and audio_b64:
        try:
            _res = _provenance.attach_credentials(
                base64.b64decode(audio_b64),
                model=_src,
                profile=profile.get("name", ""), ai_generated=True,
                extra={"source": "converse"})
            if _res.get("ok"):
                audio_b64 = base64.b64encode(_res["audio_bytes"]).decode()
        except Exception:
            pass
    return audio_b64

def _emotion_for(req: ConverseRequest, text: str, index: int) -> str:
    """统一的逐句情绪决策（tts_fn 与 SSE 事件共用，确保一致）。
    auto_emotion: None=全局默认 / True=强制开 / False=强制中性。
    仅在未显式指定具体情感(neutral/auto/空)时才自适应；首句保持中性以保 TTFA。"""
    if req.auto_emotion is False:
        return req.emotion or "neutral"
    _enabled = req.auto_emotion if req.auto_emotion is not None else _AUTO_EMOTION
    _auto = _enabled and (req.emotion in ("", "neutral", "auto"))
    if _auto and index >= 2:
        emo = _infer_emotion(text)
        # 9-9 共情兜底：助手该句措辞中性，但用户此刻苦恼/愉快 → 让「声音」也共情(温柔/有活力)。
        if emo == "neutral":
            _te = _turn_empathy.get(getattr(req, "session_id", "") or "")
            if _te and _te.get("bias"):
                return _te["bias"]
        return emo
    return req.emotion or "neutral"


# 对话级自然度抽检：异步 fire-and-forget，绝不阻塞音频热路径(不影响 TTFA)。
_NAT_SAMPLE_RATE = float(os.environ.get("CONV_NAT_SAMPLE_RATE", "0.25"))  # 抽检比例
_NAT_SAMPLE_MINLEN = int(os.environ.get("CONV_NAT_SAMPLE_MINLEN", "8"))   # 句子最短字数

async def _sample_naturalness_bg(audio_b64: str, ref_b64: str, profile_name: str):
    """后台抽检一句的自然度并记入指标。任何异常都吞掉，保证不影响对话。"""
    try:
        if not audio_b64 or not ref_b64 or _convmetrics is None:
            return
        import prosody_scorer as _ps
        nat = await asyncio.to_thread(_ps.naturalness_score, audio_b64, ref_b64)
        if nat.get("ok"):
            _convmetrics.record_naturalness(profile=profile_name,
                                            naturalness=nat["naturalness"],
                                            label=nat["label"])
    except Exception:
        pass

def _conv_build_tts_fn(req: ConverseRequest, profile: dict, engine_override: str = ""):
    if not req.speak:
        return None
    _ref_b64 = profile.get("voice_b64", "")
    _pname = req.profile or _active_profile or ""
    _tts_lang = _conv_reply_tts_lang(req)
    _do_tr = _conv_need_translate(req)
    _tr_src = _conv_src_lang(req)
    _tr_dest = _google_lang(req.reply_lang) if (req.reply_lang and req.reply_lang.strip().lower() != "auto") else _tr_src
    _bridge_used = {"v": False}     # 本轮是否已用缓存垫话兜底过（每轮至多一次，避免一连串无关垫词）
    async def _fn(text: str, *, index: int = 0) -> str:
        speak_text, _mt = text, False
        if _do_tr and speak_text.strip():
            speak_text, _mt = await asyncio.get_running_loop().run_in_executor(
                None, _translate_for_speech, speak_text, _tr_src, _tr_dest)
        emo = _emotion_for(req, text, index)
        # 朗读语种按「实际要念的文本」判定：修复语音输入(req.text 空→_tts_lang 锁死中文)，
        # 也兜底 LLM 偶发语种偏移。翻译模式 speak_text 已是目标语，检测亦得目标语，一致。
        _g = _detect_text_lang(speak_text)
        if _g == "zh-CN":                      # 繁体→简体，统一发音文本(面向大陆用户)
            speak_text = _to_simplified(speak_text)
        _eff_lang = _google_to_tts_lang(_g, _tts_lang) if _g else _tts_lang
        b64 = await _conv_synthesize(speak_text, profile, language=_eff_lang,
                                     emotion=emo, vc_engine=req.vc_engine,
                                     watermark=req.watermark,
                                     _use_opener_cache=not _do_tr,
                                     prefer_engine=(engine_override or req.tts_engine or _CONV_TTS_ENGINE))
        # 断声兜底：全部 TTS 引擎都不可用时(如 fish 编译/重启中 + cosy/xtts 离线/未部署)，
        # 用缓存的"克隆音垫话"顶上——保住角色本音、绝不让用户听到死寂；文本仍照常流式呈现。
        # 每轮至多兜一次(其余句靠文本)，避免一连串无关垫词；零额外服务/显存，与部署形态无关。
        if (not b64) and req.speak and (not _bridge_used["v"]):
            _glang = _g or "zh-CN"
            fb = _pick_filler(_pname, _filler_phrases_for_lang(profile, _glang),
                              reply_lang=_glang)
            if fb:
                _bridge_used["v"] = True
                _logger.warning(f"[TTS] 全引擎不可用 → 缓存垫话兜底(避免断声) idx={index} lang={_glang}")
                return fb
        # 跳过 index 0(开场/垫话，多为缓存命中) + 短句；按比例抽检，后台异步评分
        if (b64 and _ref_b64 and index >= 1 and len(text) >= _NAT_SAMPLE_MINLEN
                and _NAT_SAMPLE_RATE > 0 and random.random() < _NAT_SAMPLE_RATE):
            asyncio.create_task(_sample_naturalness_bg(b64, _ref_b64, _pname))
        return b64
    return _fn


def _conv_build_tts_stream_fn(req: ConverseRequest, profile: dict, engine_override: str = ""):
    """单句内流式克隆 TTS（async gen，逐块产 WAV b64）。仅在 CONV_TTS_STREAMING=1 且
    选定引擎为 fish_speech 且角色有参考音色时启用；否则返回 None → 编排器走原整句路径。
    fish 流式仅做克隆音色，不带情感预设(与现 fish 路径一致)；翻译模式整句先译再流式合成。"""
    if not (_CONV_TTS_STREAMING and req.speak):
        return None
    eng = (engine_override or req.tts_engine or _CONV_TTS_ENGINE or profile.get("tts_engine", ""))
    _stream_svc = _fish_compat_svc(eng)        # fish_speech / qwen3_tts… → 服务键
    if not _stream_svc:
        return None
    voice_b64 = profile.get("voice_b64", "")
    if not voice_b64:
        return None
    _ftp = profile.get("fish_tts_params") or {}
    _do_tr = _conv_need_translate(req)
    _tr_src = _conv_src_lang(req)
    _tr_dest = _google_lang(req.reply_lang) if (req.reply_lang and req.reply_lang.strip().lower() != "auto") else _tr_src
    # 优雅降级：流式端点 404(旧 fish)/连接异常/空产出 → 回退整句合成，绝不让本句静音。
    # 整句路径走原始 /v1/tts/clone(旧 fish 亦有)且自带克隆音垫话兜底；传原始 text(其内部自做翻译/简繁)。
    _whole_fn = _conv_build_tts_fn(req, profile, engine_override=engine_override)
    # 口型自适应合并：本轮开口型且角色有脸 → 用更大的块档(每块足够大→单卡 MuseTalk 渲染稳达
    # 实时)；否则纯音频档(小块低 TTFA)。HD(增强)更重→更大块。见 _CONV_TTS_STREAM_LIP/HD_* 实测。
    _lip_active = bool(req.generate_lipsync and req.speak and profile.get("face_b64", ""))
    _lip_eng = _lipsync_resolve_rt(req.lipsync_engine, profile)  # 实时高清默认档(ditto·在线才用)，否则 musetalk
    _lip_hd = bool(_lip_active and req.lipsync_enhance and _lip_eng in ("musetalk", "")
                   and not _rt_overloaded())   # 满载门控下连 GFPGAN 也省掉(回落 musetalk raw≈0.52 RTF, 真正留余量)
    _co_first, _co_chunk, _co_max = _pick_coalesce_params(_lip_active, _lip_hd, _lip_eng)
    if _lip_active:     # 口型轮才记一行(低频)：交付排障时可核对实际生效的合并档与 HD 判定
        _logger.info(f"[TTS/stream] 口型自适应合并 eng={_lip_eng} hd={_lip_hd} "
                     f"first={_co_first} chunk={_co_chunk} max={_co_max}ms")

    async def _gen(text: str, *, index: int = 0):
        import struct as _struct
        speak_text = text
        if _do_tr and speak_text.strip():
            speak_text, _ = await asyncio.get_running_loop().run_in_executor(
                None, _translate_for_speech, speak_text, _tr_src, _tr_dest)
        if _detect_text_lang(speak_text) == "zh-CN":
            speak_text = _to_simplified(speak_text)
        payload = {"reference_audio_b64": voice_b64,
                   "reference_text": _ftp.get("reference_text", "") if _ftp else "",
                   "text": speak_text, "language": req.language or "zh"}
        for k in ("temperature", "top_p", "repetition_penalty", "chunk_length", "seed"):
            if k in _ftp:
                payload[k] = _ftp[k]
        _emitted = False
        try:
            async with _svc_lease(_stream_svc) as base:   # 多卡时落到某张空闲副本
                async with http_pool.stream("POST", f"{base}/v1/tts/clone/stream",
                                            json=payload, timeout=90) as resp:
                    if resp.status_code == 200:
                        try:
                            sr = int(resp.headers.get("X-Sample-Rate", "44100"))
                        except Exception:
                            sr = 44100

                        async def _frames():   # 解长度前缀帧 → 逐段 PCM；0 帧=结束
                            buf = b""
                            async for data in resp.aiter_bytes():
                                buf += data
                                while len(buf) >= 4:
                                    n = _struct.unpack("<I", buf[:4])[0]
                                    if n == 0:
                                        return
                                    if len(buf) < 4 + n:
                                        break
                                    pcm, buf = buf[4:4 + n], buf[4 + n:]
                                    if pcm:
                                        yield pcm

                        async for blk in _coalesce_pcm_stream(
                                _frames(), sr=sr, first_ms=_co_first,
                                chunk_ms=_co_chunk, max_ms=_co_max):
                            _emitted = True
                            yield _pcm16_to_wav_b64(blk, sr)
                    else:
                        _logger.warning(f"[TTS/stream] fish 流式 HTTP {resp.status_code} → 回退整句 idx={index}")
        except Exception as e:
            _logger.warning(f"[TTS/stream] 流式合成失败 idx={index}: {e} → 回退整句")
        # 兜底：流式一块都没吐(404/异常/空)→整句合成顶上；半路才失败则不回退(避免重复整句音)。
        if not _emitted:
            try:
                b64 = await _whole_fn(text, index=index)
                if b64:
                    yield b64
            except Exception as e2:
                _logger.warning(f"[TTS/stream] 整句兜底失败 idx={index}: {e2}")
    return _gen


def _conv_build_lipsync_fn(req: ConverseRequest, profile: dict):
    """Phase9-3: 逐句口型回调（音频→口型视频块）。需角色有人脸；经 Phase8 分发。"""
    if not (req.generate_lipsync and req.speak):
        return None
    face_b64 = profile.get("face_b64", "")
    if not face_b64:
        return None
    sel_ls = _lipsync_resolve_rt(req.lipsync_engine, profile)  # 实时高清默认档(ditto·在线才用)，否则 musetalk
    # 仅实时 256(musetalk) 需要 GFPGAN 增强；latentsync 已是 512
    enh = "gfpgan" if (req.lipsync_enhance and sel_ls in ("musetalk", "")
                       and not _rt_overloaded()) else ""   # 满载门控下省 GFPGAN, 保 musetalk raw 实时余量
    profile_name = req.profile or _active_profile   # C2PA 嵌入标签（曾漏定义→browser 口型全废）
    # ditto: 开口前预注册头像(与 STT/LLM 首 token 重叠),让首句也跳过人脸注册开销
    if sel_ls == "ditto":
        try:
            asyncio.get_running_loop().create_task(
                _ditto_register_async(base64.b64decode(face_b64)))
        except Exception:
            pass
    async def _fn(audio_b64: str, *, index: int = 0) -> str:
        try:
            _aud = base64.b64decode(audio_b64)
            _face = base64.b64decode(face_b64)
            # 直播(vcam开) + 实时 256(musetalk) → 流式直推中枢：首帧≈首段(~1s)。
            #   STD: 25fps 平滑; HD(enh): 同进程 GFPGAN(bf16+GPU warp,免mp4/跨进程)以 fps=20 推流。
            #   手机/浏览器经 WebRTC 看连续流，故不回 base64。
            if _vcam_enabled and sel_ls in ("musetalk", ""):
                if await _lipsync_stream_to_vcam(_aud, _face, enhance=enh):
                    return ""
                # 流式失败 → 回退整段
            elif _vcam_enabled and sel_ls == "ditto":
                # Ditto 实时全脸：online 流式直推 vcam,句内首帧≈0.6s
                if await _ditto_stream_to_vcam(_aud, _face):
                    return ""
                # 流式失败 → 回退整段(下方整段 dispatch)
            ls_r = await _lipsync_dispatch(sel_ls, _aud, _face, enhance=enh)
            if ls_r.status_code == 200 and ls_r.video_bytes:
                _vcam_vb = _maybe_embed_video_c2pa(ls_r.video_bytes,
                                                   model=sel_ls, profile=profile_name)
                if _vcam_enabled:           # 同步推到虚拟摄像头(不阻塞流式)，带音频→OBS可同步发声
                    asyncio.create_task(_vcam_push(_vcam_vb, _aud))
                return base64.b64encode(_vcam_vb).decode()
        except Exception as _e:
            _logger.warning(f"[Converse/lipsync] 跳过句{index}: {_e}")
        return ""
    return _fn

# 最近一次对话活动时间戳：供 LLM 保活心跳判断是否仍需常驻显存。
_conv_last_active = 0.0

async def _conv_prepare(req: ConverseRequest):
    """公共前置：校验 + 取角色快照 + 建会话 + 取消事件 + TTS 回调。"""
    if _conv is None:
        raise HTTPException(503, "conversation 模块未加载")
    global _conv_last_active
    _conv_last_active = time.time()
    if not req.text and not req.audio_base64:
        raise HTTPException(400, "text 与 audio_base64 至少提供一个")
    if req.stt_engine and _conv.registry.get_stt(req.stt_engine) is None:
        raise HTTPException(400, f"未知 STT 引擎: {req.stt_engine}")
    # P2: 健康门控——选了 Nemotron 但其服务当前不在线时，回退默认 Whisper，
    #     不让「可选流式引擎临时掉线」拖垮整轮对话（与 listen 桥接的能量回退同一优雅降级原则）。
    if req.stt_engine == "nemotron_stt":
        try:
            _hsvc = (await health()).get("services") or {}
            if not _hsvc.get("nemo_stt"):
                req.stt_engine = "whisper_stt"
        except Exception:
            req.stt_engine = "whisper_stt"
    if req.llm_engine and _conv.registry.get_llm(req.llm_engine) is None:
        raise HTTPException(400, f"未知 LLM 引擎: {req.llm_engine}")
    profile_name = req.profile or _active_profile
    async with _PROFILES_LOCK:
        profile = dict(_profiles.get(profile_name, {}))
    profile.setdefault("name", profile_name)
    # 「自动跟随」语种：input_lang=auto/空 → 按用户实际输入文字判定；语音输入交给 STT 自动识别
    _auto_lang = (not req.input_lang) or req.input_lang.strip().lower() in ("auto", "")
    _detected = _detect_text_lang(req.text) if (_auto_lang and req.text) else ""
    if _auto_lang and req.text:
        stt_language = _whisper_lang(_detected or "zh-CN")
    elif _auto_lang:
        stt_language = ""   # 语音 + 自动：让 Whisper 自行识别语种
    else:
        stt_language = _whisper_lang(req.input_lang or req.language or "zh-CN")
    _dest = _google_lang(req.reply_lang) if req.reply_lang else ""
    _base_prompt = req.system_prompt or profile.get("system_prompt", "")
    if _conv_need_translate(req):
        session_prompt = _apply_reply_lang_prompt(_base_prompt, _dest)
    else:
        # 非翻译模式：用「输入/选定语种」回复（你说什么语言它用什么语言答，不锁死中文）
        session_prompt = _strip_lang_prompt(_base_prompt) if _base_prompt else ""
        if _auto_lang and not _detected:
            # 自动模式且无法预判（多为语音输入）：让 LLM 跟随用户输入语种。语种指令置于
            # 最高优先级且压过人设——否则强中文人设(阿习)会把英文输入也答成中文(实测 EN 偶发)。
            if not session_prompt:
                session_prompt = "你是一个友好的虚拟主播，用简短自然的口吻回答。"
            _lang_hint = ("【语种·最高优先级，优先于人设】必须使用与用户本轮输入完全相同的语言回复："
                          "用户说英文就全程英文，说日文就全程日文，说韩文就全程韩文，说中文就全程中文"
                          "（中文一律用简体中文，不要用繁体）。"
                          "即使人设是中文主播，本轮也绝不擅自改用中文，不要混入任何其它语言。")
        else:
            _conv_lang = _detected or _google_lang(req.input_lang or req.language or "zh-CN")
            _lang_name = _LANG_DISPLAY.get(_conv_lang, _conv_lang)
            if not session_prompt:
                session_prompt = f"你是一个友好的虚拟主播，用简短自然的{_lang_name}回答。"
            # 语种一致约束：防止多语言 LLM 中途混出其它语言（按对话语种动态生成）
            _lang_hint = f"【语种】请全程使用{_lang_name}回复，与用户输入语言保持一致，不要混入其它语言。"
        if "【语种】" not in session_prompt:
            session_prompt = session_prompt + "\n" + _lang_hint
    if req.brevity_hint:        # 追加篇幅约束（保留人设/语种指令，仅让本轮更简短）
        session_prompt = (session_prompt + "\n" + req.brevity_hint).strip()
    session = await _conv.sessions.get_or_create(req.session_id)
    session.system_prompt = session_prompt
    # Phase9-8: 跨会话长期记忆召回注入（query=本轮文本；语音输入文本未知→按最近召回）。
    # 失败/未启用绝不影响对话（优雅降级）。user_key 用 session_id（稳定客户端/设备标识）。
    if os.environ.get("CONV_LTM", "1") != "0":
        try:
            _mem_hits = _conv.long_term.recall(
                req.session_id, query=(req.text or "").strip(),
                top_k=int(os.environ.get("CONV_LTM_TOPK", "4")),
                retriever=_conv.registry.retriever)
            session.long_term_memory = "\n".join(
                f"- {d.text}" for d, _ in _mem_hits) if _mem_hits else ""
        except Exception:
            session.long_term_memory = ""
    # 中文起手语引导(让 LLM 以"这个嘛/其实…"起头命中 0ms 缓存)仅在「确定回复中文」时开。
    # 语音输入/自动语种在 STT 前语种未知(_auto_lang and not _detected)：绝不强制中文起手，
    # 否则英/日/韩回复会被迫以中文词起头(实测"这个嘛，오늘…"中韩混读)。垫词改由触发时按
    # 首句实际语种选取(见 stream 的 timeout 分支)，故此处关掉不影响非中文的感知 TTFA。
    _reply_lang_eff = _google_lang(req.reply_lang) if _conv_need_translate(req) else (_detected or _conv_src_lang(req))
    _lang_unknown = _auto_lang and not _detected
    session.short_opener = (not _conv_need_translate(req) and not _lang_unknown
                            and _reply_lang_eff in ("zh-CN", "zh-TW"))
    audio_bytes = base64.b64decode(req.audio_base64) if req.audio_base64 else None
    return profile, session, audio_bytes, stt_language


@app.post("/api/converse")
async def api_converse(req: ConverseRequest):
    """非流式对话：STT→LLM→(逐句TTS)，返回识别文本、回复、各句音频与延迟预算。"""
    _mark_activity()                       # L5-2: 刷新活动计时（LLM 退出让渡态）
    profile, session, audio_bytes, stt_language = await _conv_prepare(req)
    # P-Conc: 非流式准入(启用时)——有界等待槽位；队列满/超时则 429。先于 TTS 通道占用，拒绝时无残留。
    if not await _conv_admit_wait(int(getattr(req, "priority", 0) or 0)):
        raise HTTPException(429, "数字人正忙，请稍后再试",
                            headers={"Retry-After": str(max(1, _conv_eta_ms(1) // 1000))})
    _adm_held = (_conv_admission is not None)
    _adm_t0 = time.time()
    _rag_profile = profile.get("name", "") or req.profile or _active_profile or ""
    _chan_engine, _fish_claimed, _chan_info = await _acquire_tts_channel(req, profile)
    tts_fn = _conv_build_tts_fn(req, profile, engine_override=_chan_engine)
    lipsync_fn = _conv_build_lipsync_fn(req, profile)
    cancel_ev, _had_prev = _conv_new_turn_cancel(req.session_id)
    if _had_prev:
        asyncio.create_task(_vcam_clear_async())   # 打断上一轮：画面/声音即时停说
        asyncio.create_task(_ditto_cancel_async())  # 同时中止 ditto 在推的流式句,防其回填画面
    orch = _conv.ConversationOrchestrator()
    _llm_opts = _conv_llm_opts(req)
    chunks, video_chunks, sentences, final, blocked, rag_hits = [], [], [], {}, None, []
    _t0 = time.time()
    _perceived = None
    try:
        async for ev in orch.run_turn(session, audio_bytes=audio_bytes, text=req.text,
                                      stt_engine=req.stt_engine, llm_engine=req.llm_engine,
                                      tts_fn=tts_fn, lipsync_fn=lipsync_fn,
                                      cancel_event=cancel_ev, language=stt_language,
                                      use_rag=req.use_rag, rag_top_k=req.rag_top_k,
                                      rag_profile=_rag_profile,
                                      empathy_fn=_build_empathy_fn(req.session_id, _AUTO_EMPATHY and req.auto_emotion is not False),
                                      **_llm_opts):
            ph = ev.get("phase")
            if ph == "sentence":
                sentences.append(ev["text"])
            elif ph == "tts_chunk":
                if _perceived is None:
                    _perceived = int((time.time() - _t0) * 1000)
                chunks.append({"index": ev["index"], "audio_base64": ev["audio_base64"]})
            elif ph == "lipsync_chunk":
                video_chunks.append({"index": ev["index"], "video_base64": ev["video_base64"]})
            elif ph == "rag":
                rag_hits = ev.get("hits", [])
            elif ph == "guard_block" and ev.get("stage") == "input":
                blocked = ev.get("reason", "输入被安全闸门拦截")
            elif ph == "error":
                raise HTTPException(500, ev.get("message", "对话失败"))
            elif ph in ("done", "cancelled"):
                final = ev
    finally:
        _release_tts_channel(_fish_claimed)
        if _adm_held and _conv_admission is not None:    # P-Conc: 归还槽位 + 记录整轮耗时(供 ETA)
            _conv_admission.release()
            _conv_recent_turn_ms.append((time.time() - _adm_t0) * 1000.0)
    # L3-2: 非流式路径也埋点，使压测/看板可见 TTFA
    if _convmetrics is not None and blocked is None:
        try:
            tm = final.get("timings") or {}
            _convmetrics.record_turn(
                profile=_rag_profile,
                ttfa_ms=tm.get("first_audio_ms", 0),
                perceived_ttfa_ms=_perceived or 0,
                stt_ms=tm.get("stt_ms", 0),
                first_sentence_ms=tm.get("first_sentence_ms", 0),
                llm_first_token_ms=tm.get("llm_first_token_ms", 0),
                total_ms=tm.get("total_ms", 0) or int((time.time() - _t0) * 1000),
                n_sentences=len(sentences),
                cancelled=(final.get("phase") == "cancelled"))
        except Exception:
            pass
    return {
        "ok": blocked is None and final.get("phase", "done") != "cancelled",
        "blocked": blocked is not None,
        "block_reason": blocked,
        "recognized": final.get("recognized", req.text),
        "reply": final.get("reply", ""),
        "sentences": sentences,
        "audio_chunks": chunks,
        "lipsync_chunks": video_chunks,
        "rag_hits": rag_hits,
        "timings": final.get("timings", {}),
        "session_id": req.session_id,
        "cancelled": final.get("phase") == "cancelled",
    }


# ── 离线高清(LatentSync 512)显存让渡 ─────────────────────────────
# 单卡 32G：LLM(~17.8G)+MuseTalk+TTS 已近满，LatentSync(~6G)无法同驻。HD 为离线档，
# 故先跑完 LLM+TTS(音频先给用户)→卸载 LLM 让出显存→逐句扩散渲染→卸载 latentsync→回暖 LLM。
def _default_llm_backend():
    try:
        name = _conv.registry.default_llm if _conv else ""
        return _conv.registry.get_llm(name) if name else None
    except Exception:
        return None


async def _llm_yield_vram() -> bool:
    """卸载默认本地 LLM 释放显存(ollama keep_alive=0)。云端后端无需让渡，返回 False。"""
    be = _default_llm_backend()
    if be is None or getattr(be, "kind", "local") != "local":
        return False
    base = getattr(be, "base_url", "").rstrip("/")
    model = getattr(be, "model", "")
    if not base or not model:
        return False
    try:
        async with _aclient(timeout=30.0) as c:
            await c.post(f"{base}/api/generate", json={"model": model, "keep_alive": 0})
        _logger.info(f"[HD] 已卸载 LLM 让出显存: {model}")
        return True
    except Exception as e:
        _logger.warning(f"[HD] LLM 卸载失败: {e}")
        return False


async def _llm_rewarm():
    """重新载入默认本地 LLM 常驻(HD 渲染结束后)。"""
    be = _default_llm_backend()
    if be is None or getattr(be, "kind", "local") != "local":
        return
    base = getattr(be, "base_url", "").rstrip("/")
    model = getattr(be, "model", "")
    ka = getattr(be, "keep_alive", "30m") or "30m"
    if not base or not model:
        return
    try:
        async with _aclient(timeout=120.0) as c:
            await c.post(f"{base}/api/generate", json={"model": model, "keep_alive": ka})
        _logger.info(f"[HD] LLM 已回暖: {model}")
    except Exception as e:
        _logger.warning(f"[HD] LLM 回暖失败: {e}")


async def _latentsync_unload():
    url = SERVICES.get("latentsync", "http://127.0.0.1:8091").rstrip("/")
    try:
        async with _aclient(timeout=30.0) as c:
            await c.post(f"{url}/unload")
    except Exception:
        pass


# ── 整帧超分（Phase 8-4：Real-ESRGAN，离线 HD 后处理）────────────────────
#   GFPGAN(enhance) 只复原人脸；超分升整帧分辨率(背景/身体/服装)。非实时，仅离线 HD 通道用。
#   enhance 服务离线/缺权重 → 优雅返回原视频字节（绝不阻断 HD 出片）。
async def _superres_video_bytes(video_bytes: bytes, scale: float = 2.0,
                                denoise: float = 0.0) -> bytes:
    base = SERVICES.get("enhance", "http://127.0.0.1:8092").rstrip("/")
    try:
        async with _aclient(timeout=300.0) as c:
            r = await c.post(f"{base}/superres_video",
                             files={"video": ("hd.mp4", video_bytes, "video/mp4")},
                             data={"scale": str(scale), "denoise": str(denoise)},
                             headers=_svc_req_headers())
        if r.status_code == 200 and r.content:
            return r.content
        _logger.warning(f"[SuperRes] 服务 HTTP {r.status_code}，回退原视频")
    except Exception as e:
        _logger.warning(f"[SuperRes] 不可达，回退原视频: {e}")
    return video_bytes


@app.post("/api/superres/video")
async def proxy_superres_video(video: UploadFile = File(...),
                               scale: float = Form(2.0),
                               denoise: float = Form(0.0)):
    """整帧超分视频（转发 enhance 服务的 Real-ESRGAN）。离线 HD 后处理。"""
    base = SERVICES.get("enhance", "http://127.0.0.1:8092").rstrip("/")
    raw = await video.read()
    try:
        async with _aclient(timeout=600.0) as c:
            r = await c.post(f"{base}/superres_video",
                             files={"video": ("in.mp4", raw, "video/mp4")},
                             data={"scale": str(scale), "denoise": str(denoise)},
                             headers=_svc_req_headers())
    except Exception as e:
        raise HTTPException(502, f"超分服务不可达: {e}")
    if r.status_code != 200:
        raise HTTPException(r.status_code, f"超分失败: {r.text[:200]}")
    from fastapi.responses import Response as _Resp
    return _Resp(content=r.content, media_type="video/mp4",
                 headers={"X-Output-Size": r.headers.get("X-Output-Size", "")})


@app.post("/api/superres/image")
async def proxy_superres_image(image: UploadFile = File(...),
                               scale: float = Form(2.0),
                               denoise: float = Form(0.0)):
    """整帧超分单图（转发 enhance 服务的 Real-ESRGAN）。"""
    base = SERVICES.get("enhance", "http://127.0.0.1:8092").rstrip("/")
    raw = await image.read()
    try:
        async with _aclient(timeout=120.0) as c:
            r = await c.post(f"{base}/superres_image",
                             files={"image": ("in.png", raw, "image/png")},
                             data={"scale": str(scale), "denoise": str(denoise)},
                             headers=_svc_req_headers())
    except Exception as e:
        raise HTTPException(502, f"超分服务不可达: {e}")
    if r.status_code != 200:
        raise HTTPException(r.status_code, f"超分失败: {r.text[:200]}")
    from fastapi.responses import Response as _Resp
    return _Resp(content=r.content, media_type="image/png",
                 headers={"X-Output-Size": r.headers.get("X-Output-Size", "")})


@app.post("/api/converse/stream")
async def api_converse_stream(req: ConverseRequest):
    """SSE 流式对话：实时推送 stt_done→sentence→tts_chunk→done，前端边收边播。
    HD(latentsync)走离线显存让渡流程：音频先到→卸载 LLM→逐句 512 渲染→回暖 LLM。"""
    from fastapi.responses import StreamingResponse
    _mark_activity()                       # L5-2: 刷新活动计时（LLM 退出让渡态）
    profile, session, audio_bytes, stt_language = await _conv_prepare(req)
    _chan_engine, _fish_claimed, _chan_info = await _acquire_tts_channel(req, profile)
    tts_fn = _conv_build_tts_fn(req, profile, engine_override=_chan_engine)
    tts_stream_fn = _conv_build_tts_stream_fn(req, profile, engine_override=_chan_engine)
    lipsync_fn = _conv_build_lipsync_fn(req, profile)
    cancel_ev, _had_prev = _conv_new_turn_cancel(req.session_id)
    if _had_prev:
        asyncio.create_task(_vcam_clear_async())   # 打断上一轮：画面/声音即时停说
        asyncio.create_task(_ditto_cancel_async())  # 同时中止 ditto 在推的流式句,防其回填画面
    orch = _conv.ConversationOrchestrator()
    _llm_opts = _conv_llm_opts(req)
    _tr_on = _conv_need_translate(req)
    _tr_src = _conv_src_lang(req)
    _tr_dest = _google_lang(req.reply_lang) if (req.reply_lang and req.reply_lang.strip().lower() != "auto") else _tr_src
    _rag_profile = profile.get("name", "") or req.profile or _active_profile or ""

    sel_ls = _lipsync_resolve_rt(req.lipsync_engine, profile)  # 实时高清默认档(ditto·在线才用)，否则 musetalk
    # 离线高清 HD 通道：latentsync(扩散口型) 与 echomimic(全脸数字人) 都属离线重型，
    # 走「先产音频→让出显存→逐句渲染→回暖 LLM」流程，避免与实时链路抢卡。
    #   ditto 虽是整脸单图引擎，但 warm 后快于实时且显存轻量 → 不走 HD，改走正常内联 lipsync_fn
    #   路径(逐句渲染与 LLM/TTS 重叠、LLM 常驻),交互延迟更低。
    hd_mode = (sel_ls in ("latentsync", "echomimic") and req.generate_lipsync and req.speak
               and bool(profile.get("face_b64")))
    # 两段式首音优化：HD(显存让渡)流程自有 LLM 卸载逻辑，不叠加
    _two_phase = _two_phase_enabled(req) and not hd_mode
    # 口型串行化决策：多卡口型池→关串行，本句口型与下句 TTS 跨卡并发(单答案内提速)
    #   每请求 lipsync_serialize 显式覆盖优先(整机 A/B/运维现场调参)；None=按引擎策略
    _ls_serialize = (req.lipsync_serialize if req.lipsync_serialize is not None
                     else _lipsync_serialize_for(sel_ls))

    def _sse(d: dict) -> str:
        return f"data: {json.dumps(d, ensure_ascii=False)}\n\n"

    # ── 可观测埋点：累计本轮指标，done/cancelled 时落库 ──
    _emo_refs_map = profile.get("emotion_refs") or {}
    _turn_obs = {"t0": time.time(), "profile": profile.get("name", ""),
                 "emotions": {}, "filler": False, "emoref_hits": 0,
                 "emo_sentences": 0, "n_sentences": 0, "done": False,
                 "perceived_ttfa": None, "first_audio_recorded": False}

    def _obs(ev: dict):
        ph = ev.get("phase")
        # 感知 TTFA：用户实际听到的第一段音频（含垫话/开场白），不同于真实首音
        if ph == "tts_chunk" and ev.get("audio_base64"):
            if _turn_obs["perceived_ttfa"] is None:
                _turn_obs["perceived_ttfa"] = int((time.time() - _turn_obs["t0"]) * 1000)
            # 流式 vs 整句首音分桶：chunk 字段存在=单句内流式首块；供 ops/容量对照量化 A 收益
            if not _turn_obs["first_audio_recorded"]:
                _turn_obs["first_audio_recorded"] = True
                _fa_ms = _turn_obs["perceived_ttfa"]
                _is_stream = ("chunk" in ev)
                if _is_stream:
                    _metrics["conv_stream_first_ms"].append(_fa_ms)
                else:
                    _metrics["conv_whole_first_ms"].append(_fa_ms)
                if req.session_id == _AUDIENCE_AUTO_SESSION:
                    _metrics["audience_first_ms"].append(_fa_ms)
                    if _is_stream:
                        _metrics["audience_stream_first_ms"].append(_fa_ms)
        if ph == "sentence":
            emo = ev.get("emotion", "neutral") or "neutral"
            _turn_obs["n_sentences"] += 1
            _turn_obs["emotions"][emo] = _turn_obs["emotions"].get(emo, 0) + 1
            if emo != "neutral":
                _turn_obs["emo_sentences"] += 1
                if _emo_refs_map.get(emo):
                    _turn_obs["emoref_hits"] += 1
        elif ph == "tts_chunk" and ev.get("filler"):
            _turn_obs["filler"] = True
        elif ph in ("done", "cancelled") and not _turn_obs["done"]:
            _turn_obs["done"] = True
            if ph == "done":
                try:
                    asyncio.create_task(
                        _consolidate_session_memory(session, req.session_id, req.llm_engine))
                except Exception:
                    pass
            if _convmetrics is not None:
                tm = ev.get("timings") or {}
                try:
                    _convmetrics.record_turn(
                        profile=_turn_obs["profile"],
                        ttfa_ms=tm.get("first_audio_ms", 0),
                        perceived_ttfa_ms=_turn_obs["perceived_ttfa"] or 0,
                        stt_ms=tm.get("stt_ms", 0),
                        first_sentence_ms=tm.get("first_sentence_ms", 0),
                        llm_first_token_ms=tm.get("llm_first_token_ms", 0),
                        total_ms=tm.get("total_ms", 0) or int((time.time() - _turn_obs["t0"]) * 1000),
                        n_sentences=_turn_obs["n_sentences"], filler=_turn_obs["filler"],
                        emotions=_turn_obs["emotions"], emoref_hits=_turn_obs["emoref_hits"],
                        emo_sentences=_turn_obs["emo_sentences"], cancelled=(ph == "cancelled"))
                except Exception:
                    pass

    async def _emit(ev: dict) -> str:
        # 在 sentence 事件上附加逐句情绪标签，供前端心情指示器展示
        if ev.get("phase") == "sentence":
            if _detect_text_lang(ev.get("text", "")) == "zh-CN":   # 字幕统一简体
                ev["text"] = _to_simplified(ev["text"])
            ev["emotion"] = _emotion_for(req, ev.get("text", ""), ev.get("index", 0))
            if _tr_on and ev.get("text"):
                tts_t, mt = await asyncio.get_running_loop().run_in_executor(
                    None, _translate_for_speech, ev["text"], _tr_src, _tr_dest)
                ev["tts_text"] = tts_t
                ev["tts_translated"] = mt
        _obs(ev)
        return _sse(ev)

    async def _gen_hd():
        """离线 HD：先流式产音频(口型关)，LLM 完成后让出显存逐句扩散渲染。"""
        pending, done_ev = [], None
        face = base64.b64decode(profile.get("face_b64", ""))
        async for ev in orch.run_turn(session, audio_bytes=audio_bytes, text=req.text,
                                      stt_engine=req.stt_engine, llm_engine=req.llm_engine,
                                      tts_fn=tts_fn, lipsync_fn=None,
                                      cancel_event=cancel_ev, language=stt_language,
                                      use_rag=req.use_rag, rag_top_k=req.rag_top_k,
                                      rag_profile=_rag_profile,
                                      empathy_fn=_build_empathy_fn(req.session_id, _AUTO_EMPATHY and req.auto_emotion is not False),
                                      **_llm_opts):
            ph = ev.get("phase")
            if ph == "done":
                done_ev = ev      # 渲染完再发 done
                continue
            if ph == "tts_chunk" and ev.get("audio_base64"):
                pending.append((ev.get("index", 0), ev["audio_base64"]))
            yield await _emit(ev)
        # LLM 已产完全部句子 → 卸载让出显存给扩散模型
        yielded = await _llm_yield_vram()
        for idx, ab in pending:
            yield _sse({"phase": "lipsync_start", "index": idx})
            try:
                r = await _lipsync_dispatch(sel_ls, base64.b64decode(ab), face)
                if getattr(r, "status_code", 0) == 200 and getattr(r, "video_bytes", b""):
                    _hd_vb = r.video_bytes
                    # Phase8-4: 离线 HD 整帧超分（Real-ESRGAN）—— 仅 HD 通道、显式开启时；失败回退原片
                    if req.superres:
                        _hd_vb = await _superres_video_bytes(_hd_vb, scale=req.superres_scale)
                    _ls_vb = _maybe_embed_video_c2pa(_hd_vb,
                                                     model=sel_ls, profile="converse")
                    if _vcam_enabled:
                        asyncio.create_task(_vcam_push(_ls_vb, base64.b64decode(ab)))
                    yield _sse({"phase": "lipsync_chunk", "index": idx,
                                "video_base64": base64.b64encode(_ls_vb).decode()})
                else:
                    yield _sse({"phase": "lipsync_error", "index": idx,
                                "message": f"{sel_ls} status {getattr(r, 'status_code', '?')}"})
            except Exception as e:
                yield _sse({"phase": "lipsync_error", "index": idx, "message": str(e)})
        if sel_ls == "latentsync":
            await _latentsync_unload()   # 释放 ~6G，腾给 LLM 回暖（echomimic 为常驻服务，免卸载）
        if yielded:
            asyncio.create_task(_llm_rewarm())
        if done_ev is not None:
            yield await _emit(done_ev)

    # Phase 9-11: 仅音频模式(关口型)启用填充音；开口型时填充音无配套视频会破坏
    #   首句音视频配对，故不注入(命中缓存的快路径仍生效)。
    # 垫词语种在「填充音真正触发」时按首句实际文本判定(见下方 timeout 分支)，因此语音输入
    # (STT 后才知语种)也能用对应语种垫词，非中文不再误播中文"嗯，"；翻译模式直接用目标语。
    # 若该语种无预合成垫词则 _pick_filler 返回 ''（优雅退化为不垫词）。
    _reply_gl = (_tr_dest if _tr_on else _conv_src_lang(req)) or "zh-CN"
    _filler_enabled = (_FILLER_ON and req.speak and not req.generate_lipsync
                       and not hd_mode)

    async def _gen():
        _slot_held = False
        _gen_t0 = time.time()
        _adm = _conv_admission
        try:
            # P-Conc1/2: 优先级会话准入（CONV_MAX_CONCURRENT=N>0 或 auto 时启用）。
            # 立刻有空位→秒进(行为同改造前)；满载→按(优先级高→先到)排队，期间推 queue 事件
            # (位次 + ETA 倒计时)；排队数超 CONV_MAX_QUEUE→优雅拒绝(busy)。主播 priority 高者插队。
            if _adm is not None:
                if not _adm.try_acquire():
                    if CONV_MAX_QUEUE > 0 and _adm.waiting >= CONV_MAX_QUEUE:
                        yield _sse({"phase": "busy", "waiting": _adm.waiting,
                                    "max": _adm.capacity, "max_queue": CONV_MAX_QUEUE,
                                    "message": "数字人正忙，请稍后再试"})
                        return
                    _prio = int(getattr(req, "priority", 0) or 0)
                    _item = _adm.enqueue(_prio)
                    _fut = _item[2]
                    _q_t0 = time.time()
                    _acquired = False
                    try:
                        while not _fut.done():
                            _pos = _adm.position(_item)
                            # ETA 倒计时：随等待递减，避免"预计 8s"恒定不动的死板观感
                            _eta = max(0, int(_conv_eta_ms(_pos) - (time.time() - _q_t0) * 1000))
                            yield _sse({"phase": "queue", "position": _pos,
                                        "active": _adm.active, "max": _adm.capacity,
                                        "waiting": _adm.waiting, "eta_ms": _eta,
                                        "priority": _prio})
                            try:
                                await asyncio.wait_for(asyncio.shield(_fut),
                                                       timeout=_QUEUE_PING_SEC)
                            except asyncio.TimeoutError:
                                pass
                        _acquired = not _fut.cancelled()
                    finally:
                        if _acquired:
                            _slot_held = True        # 槽位已交接给本会话，轮尾负责 release
                        else:
                            _adm.abandon(_item)      # 排队中断开/出错：退出队列，不泄漏槽位
                else:
                    _slot_held = True
            if hd_mode:
                async for x in _gen_hd():
                    yield x
                return
            if not _filler_enabled:
                async for ev in orch.run_turn(session, audio_bytes=audio_bytes, text=req.text,
                                              stt_engine=req.stt_engine, llm_engine=req.llm_engine,
                                              tts_fn=tts_fn, tts_stream_fn=tts_stream_fn,
                                              lipsync_fn=lipsync_fn,
                                              cancel_event=cancel_ev, language=stt_language,
                                              use_rag=req.use_rag, rag_top_k=req.rag_top_k,
                                              rag_profile=_rag_profile, lipsync_serialize=_ls_serialize,
                                              llm_two_phase=_two_phase, phase1_chars=_TTFA_PHASE1_CHARS,
                                              first_chunk_stems=([] if _tr_on else _OPENER_STEMS),
                                              empathy_fn=_build_empathy_fn(req.session_id, _AUTO_EMPATHY and req.auto_emotion is not False),
                                              **_llm_opts):
                    yield await _emit(ev)
                return
            # 填充音路径：producer→queue，consumer 带超时读取以便延迟触发填充音
            loop = asyncio.get_event_loop()
            q: asyncio.Queue = asyncio.Queue()

            async def _produce():
                try:
                    async for ev in orch.run_turn(session, audio_bytes=audio_bytes, text=req.text,
                                                  stt_engine=req.stt_engine, llm_engine=req.llm_engine,
                                                  tts_fn=tts_fn, tts_stream_fn=tts_stream_fn,
                                                  lipsync_fn=lipsync_fn,
                                                  cancel_event=cancel_ev, language=stt_language,
                                                  use_rag=req.use_rag, rag_top_k=req.rag_top_k,
                                                  rag_profile=_rag_profile, lipsync_serialize=_ls_serialize,
                                                  llm_two_phase=_two_phase, phase1_chars=_TTFA_PHASE1_CHARS,
                                                  first_chunk_stems=([] if _tr_on else _OPENER_STEMS),
                                                  empathy_fn=_build_empathy_fn(req.session_id, _AUTO_EMPATHY and req.auto_emotion is not False),
                                                  **_llm_opts):
                        await q.put(ev)
                except Exception as e:
                    await q.put({"phase": "error", "message": str(e)})
                finally:
                    await q.put(None)

            prod = asyncio.create_task(_produce())
            first_audio_seen = False
            filler_emitted = False
            deadline = None      # 首句出现后设定；到点未见真实音频则吐填充音
            _first_sent_text = ""  # 首句文本：触发垫词时据此判定语种(语音输入 STT 后才知)
            # 打断后续接：本轮紧接打断，开口先吐一句应答词（像真人被打断后"嗯，您说"）
            if req.after_barge_in and not _tr_on:
                _ack = _pick_ack(profile.get("name", ""), reply_lang=_reply_gl)
                if _ack:
                    yield await _emit({"phase": "tts_chunk", "index": 0,
                                       "audio_base64": _ack, "filler": True})
                    filler_emitted = True   # 已应答，不再叠加"让我想想"类垫话
            try:
                while True:
                    timeout = None
                    if (deadline is not None and not first_audio_seen
                            and not filler_emitted):
                        timeout = max(0.0, deadline - loop.time())
                    try:
                        ev = (await asyncio.wait_for(q.get(), timeout=timeout)
                              if timeout is not None else await q.get())
                    except asyncio.TimeoutError:
                        # 垫词语种：翻译模式用目标语；否则按首句实际文本判定(覆盖语音输入)
                        _fl_gl = (_reply_gl if _tr_on
                                  else (_detect_text_lang(_first_sent_text) or _reply_gl))
                        _fl_plist = _filler_phrases_for_lang(profile, _fl_gl)
                        fb = _pick_filler(profile.get("name", ""),
                                          _fl_plist, reply_lang=_fl_gl)
                        if fb:
                            yield await _emit({"phase": "tts_chunk", "index": 0,
                                               "audio_base64": fb, "filler": True})
                        filler_emitted = True
                        continue
                    if ev is None:
                        break
                    ph = ev.get("phase")
                    if (ph == "sentence" and ev.get("index") == 1
                            and not first_audio_seen and not filler_emitted):
                        deadline = loop.time() + _FILLER_DELAY
                        _first_sent_text = ev.get("text", "")
                    elif ph == "tts_chunk":
                        first_audio_seen = True
                    yield await _emit(ev)
            finally:
                if not prod.done():
                    prod.cancel()
        except Exception as e:
            yield _sse({"phase": "error", "message": str(e)})
        finally:
            # 轮尾释放 fish 并发槽（正常结束 / 客户端断开 / 打断 → 生成器关闭均会触发）
            _release_tts_channel(_fish_claimed)
            # P-Conc1/2: 释放会话槽位并记录整轮耗时（喂排队 ETA 估计）
            if _slot_held and _adm is not None:
                _adm.release()
                _conv_recent_turn_ms.append((time.time() - _gen_t0) * 1000.0)

    return StreamingResponse(_gen(), media_type="text/event-stream",
                             headers={"Cache-Control": "no-cache",
                                      "X-Accel-Buffering": "no"})


