@app.post("/api/vcam/webrtc/offer")
async def api_vcam_webrtc_offer(request: Request):
    """把浏览器/手机的 WebRTC offer 转发给广播中枢(7870)拿 answer。
    经本(HTTPS)源代理，规避 HTTPS 页面直连 HTTP 中枢的混合内容限制；
    媒体(RTP/ICE)仍走对端↔中枢的 P2P(同局域网 host 候选)。
    顺手开启 vcam 推流，让直播流能看到对话口型。"""
    global _vcam_enabled
    if not _vcam_enabled:
        _vcam_enabled = True
        try:
            async with _PROFILES_LOCK:
                _fb = dict(_profiles.get(_active_profile, {})).get("face_b64", "")
            if _fb:
                await _vcam_set_idle(base64.b64decode(_fb))
        except Exception:
            pass
    body = await request.json()
    async with _aclient(timeout=20.0) as _cli:
        r = await _cli.post(f"{_VCAM_URL}/webrtc/offer", json=body)
    return JSONResponse(status_code=r.status_code, content=r.json())


@app.get("/api/vcam/preview.mjpeg")
async def api_vcam_preview_mjpeg(fps: float = 10.0):
    """D-2 手机预览 MJPEG 兜底：同源转发 vcam /preview.mjpeg(手机页不能直连 7870，
    HTTPS 页面直连 HTTP 也会被混合内容拦截)。WebRTC 失败时 phone.html 自动切到这里。"""
    fps = max(1.0, min(15.0, fps))

    async def relay():
        try:
            async with _aclient(timeout=None) as cli:
                async with cli.stream("GET", f"{_VCAM_URL}/preview.mjpeg",
                                      params={"fps": fps}) as r:
                    async for chunk in r.aiter_bytes():
                        yield chunk
        except Exception:
            return   # 客户端断开/上游停机：安静收尾

    return StreamingResponse(relay(),
                             media_type="multipart/x-mixed-replace; boundary=vcamframe",
                             headers={"Cache-Control": "no-store"})


