@app.post("/api/stream_out/start")
async def api_stream_out_start(req: StreamOutStartRequest):
    """启动 StreamOut 插件（vcam/webrtc 等）；自动开启 Hub vcam 推流并设置空闲脸。"""
    global _vcam_enabled
    if _stream_out is None:
        raise HTTPException(503, "stream_out 模块未加载")
    pname = req.profile or _active_profile
    face_b64 = ""
    if pname and pname in _profiles:
        face_b64 = _profiles[pname].get("face_b64", "")
    if face_b64:
        await _stream_out.set_idle_face(base64.b64decode(face_b64))
    if any(p in ("vcam", "webrtc") for p in req.plugins):
        _vcam_enabled = True
    plugins = list(req.plugins)
    if req.record and "recorder" not in plugins:
        plugins.append("recorder")
    ctx = {"profile": pname, "face_b64": face_b64, "rtmp_url": req.rtmp_url.strip()}
    result = await _stream_out.start_plugins(plugins, ctx)
    result["hub_vcam_enabled"] = _vcam_enabled
    return result


