def _parse_consolidation(text: str) -> tuple[str, list]:
    """解析后台整合输出：『摘要：…』+『记忆：- …』两段。返回 (summary, [facts])。
    鲁棒处理中英文冒号 / 缺段 / 列表符号；记忆为『无』视作空。"""
    summary = ""
    facts: list = []
    if not text:
        return summary, facts
    norm = text.replace("：", ":")
    # 以「记忆」为界切两段（任一段可缺失）
    mem_part = ""
    sum_part = norm
    for kw in ("记忆:", "记忆", "Memory:"):
        idx = norm.find(kw)
        if idx >= 0:
            sum_part = norm[:idx]
            mem_part = norm[idx + len(kw):]
            break
    for kw in ("摘要:", "摘要", "Summary:"):
        if kw in sum_part:
            sum_part = sum_part.split(kw, 1)[1]
            break
    summary = sum_part.strip().strip("-•· ").strip()
    for ln in mem_part.splitlines():
        s = ln.strip().lstrip("-•*·0123456789.、) ").strip()
        if not s or s in ("无", "None", "none", "（无）", "(无)"):
            continue
        if 2 <= len(s) <= 80:
            facts.append(s)
    return summary, facts[:6]


async def _consolidate_session_memory(session, user_key: str = "",
                                      llm_engine: str = "") -> None:
    """Phase9-8 后台记忆整合（轮次结束后异步、不阻塞 TTFA）：单次 LLM 调用同时产出
    ①滚动摘要(更新 session.summary) ②关于用户的持久事实(写入跨会话长期记忆)。
    合并为一次调用，省一半 LLM 开销/显存争用。任一环节失败都静默降级。"""
    if os.environ.get("CONV_LLM_SUMMARY", "1") != "1" or _conv is None or session is None:
        return
    if len(session.history) < 10 and len(session.summary or "") < 120:
        return
    llm = _conv.registry.get_llm(llm_engine or _conv.registry.default_llm)
    if llm is None:
        return
    recent = list(session.history)[-8:]
    chunk = "\n".join(
        f"{'用户' if m.get('role') == 'user' else '助手'}:{(m.get('content') or '')[:100]}"
        for m in recent)
    _ltm_on = os.environ.get("CONV_LTM", "1") != "0"
    sys_prompt = (
        "你在整理对话记忆。严格按以下两段输出，不要多余文字、不要编造：\n"
        "摘要：把对话压缩为不超过120字要点，保持人称与话题连贯。\n")
    if _ltm_on:
        sys_prompt += (
            "记忆：另起一段，逐行列出【用户明确表达过的、值得长期记住的事实】"
            "（如称呼/喜好/职业/所在地/重要约定）；每行一条、简洁；"
            "若本段无新事实，写「无」。不要把助手的话或临时话题当事实。")
    msgs = [
        {"role": "system", "content": sys_prompt},
        {"role": "user",
         "content": f"已有摘要：{(session.summary or '')[:320]}\n\n近期对话：\n{chunk}"},
    ]
    parts: list[str] = []
    try:
        async for tok in llm.stream(msgs, max_tokens=260, temperature=0.25):
            parts.append(tok)
    except Exception:
        return
    raw = "".join(parts).strip()
    if not raw:
        return
    new_sum, facts = _parse_consolidation(raw)
    if new_sum and len(new_sum) > 16:
        session.summary = new_sum[:720]
    if _ltm_on and facts and user_key:
        for f in facts:
            try:
                _conv.long_term.add(user_key, f, kind="fact")
            except Exception:
                pass


async def _llm_summarize_session(session, llm_engine: str = "") -> None:
    """兼容保留：委托到 9-8 合并整合（含摘要）。user_key 取 session_id。"""
    await _consolidate_session_memory(
        session, getattr(session, "session_id", "") or "", llm_engine)


