@app.post("/api/optimize_references/voice_pack/{name}")
async def api_optimize_voice_pack(name: str, max_refs: int = 1):
    """从声音包长录音切段优选（演讲域 holdout + 单参考推荐）。"""
    _check_profile_name(name)
    if name not in _profiles:
        raise HTTPException(404, "角色不存在")
    wf = _PROFILE_VOICE_FILES.get(name)
    if not wf or not wf.exists():
        raise HTTPException(404, f"未找到 {name} 的声音包 WAV")
    source_b64 = base64.b64encode(wf.read_bytes()).decode()
    req = OptimizeRefsRequest(
        profile=name, source_b64=source_b64,
        max_refs=max(1, min(max_refs, 2)),
        apply_if_better=True, use_speech_corpus=True,
    )
    job_id = uuid.uuid4().hex[:12]
    _optjobs[job_id] = {"status": "running", "progress": "声音包优化启动…", "result": None, "error": ""}
    asyncio.create_task(_run_optimize_job(job_id, req, run_probe=True))
    return {"ok": True, "job_id": job_id, "source": wf.name, "size_mb": round(wf.stat().st_size / 1e6, 2)}

