async def api_optimize_references_status(job_id: str):
    j = _optjobs.get(job_id)
    if not j:
        raise HTTPException(404, "任务不存在")
    return {"ok": True, **j}


class QualityProbeRequest(BaseModel):
    profile:   str
    sentences: list[str] | None = None   # 可选；未传则用 profile.probe_sentences 或默认句

_QUALITY_PROBE_SENTS = [
    "大家好，今天天气真不错，很高兴见到各位朋友。",
    "我最近在读一本很有意思的书，想和你分享一下。",
]

@app.post("/api/profile_quality_probe")
async def api_profile_quality_probe(req: QualityProbeRequest):
    """角色音质体检：合成标准句，评音色(cosine)+自然度，写入 profile.quality_axes 供徽章展示。"""
    if req.profile not in _profiles:
        raise HTTPException(404, "角色不存在")
    if not _profiles[req.profile].get("voice_b64", ""):
        return {"ok": False, "detail": "该角色无参考音频，无法体检"}
    res = await _measure_profile_quality(req.profile, req.sentences)
    if not res.get("ok"):
        return {"ok": False, "detail": res.get("detail", "体检失败")}
    axes, coss, nats = res["axes"], res["coss"], res["nats"]
    async with _PROFILES_LOCK:
        p = dict(_profiles[req.profile])
        p["quality_axes"] = axes
        _profiles[req.profile] = p
        _save_profile(req.profile)
    if _convmetrics is not None:
        try:
            if coss:
                _convmetrics.record_clone_score(profile=req.profile, cosine=axes["cosine"])
            if nats:
                _convmetrics.record_naturalness(profile=req.profile, naturalness=axes["naturalness"])
        except Exception:
            pass
    # 同步进声纹趋势看板：每次体检也作为一个基线样本点（badge 与 trend 同源）
    _vq_append(req.profile, axes["cosine"], axes["naturalness"], ok=True, source="probe")
    await broadcast({"event": "profile_updated", "name": req.profile})
    return {"ok": True, "profile": req.profile, "quality_axes": axes,
            "sentences_used": res["n"]}


class SetSeedRequest(BaseModel):
    profile: str
    seed:    int

@app.post("/api/set_profile_seed")
async def api_set_profile_seed(req: SetSeedRequest):
    """把指定 seed 固定到角色 fish_tts_params.seed（盲听挑中后一键固定，零延迟）。"""
    if req.profile not in _profiles:
        raise HTTPException(404, "角色不存在")
    async with _PROFILES_LOCK:
        p = dict(_profiles[req.profile])
        _ftp = dict(p.get("fish_tts_params") or {})
        _ftp["seed"] = int(req.seed)
        p["fish_tts_params"] = _ftp
        _profiles[req.profile] = p
        saved = _save_profile(req.profile)
    if not saved:
        raise HTTPException(500, "保存失败")
    await broadcast({"event": "profile_updated", "name": req.profile})
    return {"ok": True, "profile": req.profile, "seed": int(req.seed)}


class FuseSegment(BaseModel):
    voice_b64: str
    text: str = ""

class CloneFuseRequest(BaseModel):
    profile:  str
    text:     str = "大家好，今天天气真不错，很高兴见到你。"
    segments: list[FuseSegment]            # 多段参考
    save:     bool = False                 # 满意后写入 profile.fish_refs

async def _fish_clone_with_refs(profile: dict, text: str, refs: list[dict]) -> str:
    """用指定 references 列表调用 Fish-Speech 克隆，返回 audio b64。"""
    _ftp = profile.get("fish_tts_params") or {}
    epay = {
        "text": text, "language": "zh",
        "temperature":        _ftp.get("temperature", 0.7),
        "top_p":              _ftp.get("top_p", 0.7),
        "repetition_penalty": _ftp.get("repetition_penalty", 1.2),
        "chunk_length":       _ftp.get("chunk_length", 200),
        "seed":               _ftp.get("seed"),
        "references": [{"audio_b64": r["voice_b64"], "text": r.get("text", "")}
                       for r in refs if r.get("voice_b64")],
    }
    r = await http_pool.post(f"{SERVICES['fish_tts']}/v1/tts/clone", json=epay, timeout=180)
    if r.status_code == 200:
        return r.json().get("audio_base64", "")
    return ""

@app.post("/api/clone_fuse")
async def api_clone_fuse(req: CloneFuseRequest):
    """多段参考融合：同一文本分别用「单段(第一段)」与「多段全部」合成，
    各自与角色既有参考音做说话人相似度评分，量化融合带来的提升。save=true 时落库。"""
    if req.profile not in _profiles:
        raise HTTPException(404, "角色不存在")
    segs = [{"voice_b64": s.voice_b64, "text": s.text} for s in req.segments if s.voice_b64]
    if not segs:
        raise HTTPException(400, "至少需要一段参考音频")
    profile = dict(_profiles[req.profile])
    # 评分基准：优先用角色既有参考音；没有则用第一段
    gt_b64 = profile.get("voice_b64", "") or segs[0]["voice_b64"]

    try:
        import clone_scorer
    except Exception as e:
        return {"ok": False, "detail": f"评分模块加载失败: {e}"}

    # 单段基线 + 多段融合（并行合成）
    single_task = _fish_clone_with_refs(profile, req.text, segs[:1])
    multi_task  = _fish_clone_with_refs(profile, req.text, segs)
    single_b64, multi_b64 = await asyncio.gather(single_task, multi_task)

    async def _score(a):
        if not a:
            return {"ok": False, "detail": "合成失败"}
        return await asyncio.to_thread(clone_scorer.score_similarity, gt_b64, a)
    single_score, multi_score = await asyncio.gather(_score(single_b64), _score(multi_b64))

    improvement = None
    if single_score.get("ok") and multi_score.get("ok"):
        improvement = round(multi_score["cosine"] - single_score["cosine"], 4)

    saved = False
    if req.save:
        async with _PROFILES_LOCK:
            if req.profile in _profiles:
                p = dict(_profiles[req.profile])
                p["fish_refs"] = segs
                _profiles[req.profile] = p
                saved = _save_profile(req.profile)
        await broadcast({"event": "profile_updated", "name": req.profile})

    return {"ok": True, "profile": req.profile, "n_segments": len(segs),
            "single": {"score": single_score, "audio_base64": single_b64},
            "multi":  {"score": multi_score,  "audio_base64": multi_b64},
            "improvement_cosine": improvement, "saved": saved}


class AutoFuseRequest(BaseModel):
    profile:      str
    audio_base64: str                      # 单段长录音（WAV base64）
    text:         str = "大家好，今天天气真不错，很高兴见到你。"
    save:         bool = False

@app.post("/api/auto_fuse")
async def api_auto_fuse(req: AutoFuseRequest):
    """长录音一键融合：自动 VAD 分非重叠片段 → 单段 vs 多段评分对比 → 可保存。"""
    if req.profile not in _profiles:
        raise HTTPException(404, "角色不存在")
    if not req.audio_base64:
        raise HTTPException(400, "audio_base64 不能为空")
    try:
        import audio_segment, clone_scorer
    except Exception as e:
        return {"ok": False, "detail": f"模块加载失败: {e}"}

    # 1) 自动分段（CPU，放线程池）
    raw = base64.b64decode(req.audio_base64)
    seg_res = await asyncio.to_thread(audio_segment.auto_segment, raw)
    if not seg_res.get("ok"):
        return seg_res
    segs = [{"voice_b64": s["b64"], "text": ""} for s in seg_res["segments"]]
    durations = [s["dur"] for s in seg_res["segments"]]
    if len(segs) < 2:
        return {"ok": False, "detail": f"仅切出 {len(segs)} 段，无法融合（录音过短或静音过多）",
                "durations": durations}

    profile = dict(_profiles[req.profile])
    gt_b64 = profile.get("voice_b64", "") or segs[0]["voice_b64"]

    # 2) 单段 vs 多段并行合成
    single_b64, multi_b64 = await asyncio.gather(
        _fish_clone_with_refs(profile, req.text, segs[:1]),
        _fish_clone_with_refs(profile, req.text, segs))

    async def _score(a):
        if not a:
            return {"ok": False, "detail": "合成失败"}
        return await asyncio.to_thread(clone_scorer.score_similarity, gt_b64, a)
    single_score, multi_score = await asyncio.gather(_score(single_b64), _score(multi_b64))
    improvement = None
    if single_score.get("ok") and multi_score.get("ok"):
        improvement = round(multi_score["cosine"] - single_score["cosine"], 4)

    # 3) 可选落库
    saved = False
    if req.save:
        async with _PROFILES_LOCK:
            if req.profile in _profiles:
                p = dict(_profiles[req.profile])
                p["fish_refs"] = segs
                _profiles[req.profile] = p
                saved = _save_profile(req.profile)
        await broadcast({"event": "profile_updated", "name": req.profile})

    return {"ok": True, "profile": req.profile, "n_segments": len(segs),
            "durations": durations, "total_sec": seg_res.get("total_sec"),
            "single": {"score": single_score, "audio_base64": single_b64},
            "multi":  {"score": multi_score,  "audio_base64": multi_b64},
            "improvement_cosine": improvement, "saved": saved}


_EMOTION_REF_KEYS = {"happy", "sad", "angry", "surprised", "gentle",
                     "serious", "excited", "calm", "fearful"}


class EmotionRefRequest(BaseModel):
    profile:      str
    emotion:      str
    audio_base64: str = ""                 # 单段长录音（自动分段）；与 segments 二选一
    segments:     list[FuseSegment] | None = None  # 已切好的多段
    save:         bool = True              # 落库（False=仅预览）
    preview_text: str = "今天真的很感谢大家，希望我们一起越来越好。"


@app.post("/api/emotion_ref")
async def api_emotion_ref(req: EmotionRefRequest):
    """设置/清除某情绪的参考音并预览。emotion 留空音频=清除该情绪参考。"""
    if req.profile not in _profiles:
        raise HTTPException(404, "角色不存在")
    if req.emotion not in _EMOTION_REF_KEYS:
        raise HTTPException(400, f"不支持的情绪: {req.emotion}（可选: {sorted(_EMOTION_REF_KEYS)}）")

    # 组装片段：优先 segments，否则对长录音自动分段
    segs: list = []
    if req.segments:
        segs = [{"voice_b64": s.voice_b64, "text": s.text}
                for s in req.segments if s.voice_b64]
    elif req.audio_base64:
        try:
            import audio_segment
            raw = base64.b64decode(req.audio_base64)
            seg_res = await asyncio.to_thread(audio_segment.auto_segment, raw)
            if seg_res.get("ok"):
                segs = [{"voice_b64": s["b64"], "text": ""} for s in seg_res["segments"]]
            if not segs:   # 分段失败则整段作单参考
                segs = [{"voice_b64": req.audio_base64, "text": ""}]
        except Exception:
            segs = [{"voice_b64": req.audio_base64, "text": ""}]

    is_clear = (not segs)
    profile = dict(_profiles[req.profile])

    # 预览：用该情绪参考合成测试句
    preview_b64 = ""
    if segs and req.preview_text:
        preview_b64 = await _fish_clone_with_refs(profile, req.preview_text, segs)

    saved = False
    if req.save:
        async with _PROFILES_LOCK:
            if req.profile in _profiles:
                p = dict(_profiles[req.profile])
                _er = dict(p.get("emotion_refs") or {})
                if is_clear:
                    _er.pop(req.emotion, None)
                else:
                    _er[req.emotion] = segs
                p["emotion_refs"] = _er
                _profiles[req.profile] = p
                saved = _save_profile(req.profile)
        await broadcast({"event": "profile_updated", "name": req.profile})

    return {"ok": True, "profile": req.profile, "emotion": req.emotion,
            "n_segments": len(segs), "cleared": is_clear, "saved": saved,
            "preview_base64": preview_b64}


