@app.get("/api/ops/snapshot")
async def api_ops_snapshot():
    """上线运维总览（/ops 看板数据源）：健康/压力 + 守护自愈 + TTS 双通道 + 近窗 TTFA。
    一处看全：稳不稳(服务/重启/熔断)、卡不卡(压力/GPU/内存)、快不快(TTFA)、分流(fish/cosy)。"""
    h = _HEALTH_CACHE["data"] or await _health_fresh()
    sup = {}
    if _supervisor is not None:
        try:
            sup = await asyncio.to_thread(_supervisor.snapshot)
        except Exception as e:
            sup = {"ok": False, "detail": str(e)}
    chan = {
        "dual_tts_on": _DUAL_TTS_ON, "fish_max_turns": _FISH_MAX_TURNS,
        "fish_turns_now": _fish_turns, "stats": dict(_TTS_CHAN_STATS),
    }
    mx = {}
    if _convmetrics is not None:
        try:
            snap = _convmetrics.snapshot(recent=20)
            agg = snap.get("aggregate", snap) if isinstance(snap, dict) else {}

            def _stat(x, k="p50"):
                return x.get(k) if isinstance(x, dict) else x
            _pt = agg.get("perceived_ttfa_ms")
            mx = {
                "perceived_ttfa_ms": _stat(_pt),
                "ttfa_ms": _stat(agg.get("ttfa_ms")),
                "turns": _stat(_pt, "n"),
            }
        except Exception:
            mx = {}
    # 生效中的 UI 偏好 + 锁语种提醒（脏数据静默锁全局语种的可见性兜底）
    prefs = {}
    try:
        if _UIPREFS_FILE.exists():
            prefs = json.loads(_UIPREFS_FILE.read_text(encoding="utf-8"))
    except Exception:
        prefs = {}
    pref_warn = ""
    _rl = str(prefs.get("reply_lang", "auto") or "auto")
    if _rl.lower() != "auto":
        pref_warn = f"回复语种被固定为「{_rl}」(非自动)——如非预期，到对话页语种条一键恢复自动"
    return {
        "ok": True,
        "ts": time.time(),
        "pressure": h.get("pressure"), "gpu_util": h.get("gpu_util"),
        "ram_percent": h.get("ram_percent"),
        "services": h.get("services", {}), "services_busy": h.get("services_busy", []),
        "latency_ms": h.get("latency_ms", {}),
        "supervisor": sup.get("supervised", {}),
        "tts_channel": chan,
        "metrics": mx,
        "face_prep": _face_prep_metrics(),        # P5: 数字人人脸预计算就绪态(计数/耗时分位/归因/真实失败率)
        "capacity": _conv_capacity_snapshot(),   # P-Conc: 实时会话容量/排队(交付看"还能接几路")
        "audience": _audience_ops_snapshot(),     # P-Conc7/8/9: 观众队列+点赞+自动应答+公屏
        "prefs": prefs,
        "pref_warn": pref_warn,
        "security": _security_panorama(),
    }


# ── P11 稳定性账本(2026-07-06)：守护重启 × Windows 崩溃事件 × 启动溯源 三源关联 ──
# P10 的验收指标「Hub 非计划重启归零」散在三处日志里，人肉对账才拼得出真相
# (当天就发生过"18:15 谁重启了 hub"说不清的场面)。tools/stability_report.py 把账算好，
# 这里只做子进程调度(与 dev_probe 同一隔离模式：事件日志查询/大日志扫描都不进 Hub 进程)+缓存。
_STABILITY_CACHE: dict = {"ts": 0.0, "data": None}
_STABILITY_TTL = 300.0


def _stability_report_run(days: float) -> dict:
    """跑账本子进程,解析末行 JSON(哨兵与 /ops 端点共用)。"""
    p = _subprocess.run(
        [sys.executable, "-X", "utf8", str(Path(__file__).parent / "tools" / "stability_report.py"),
         "--days", str(max(0.25, min(30.0, days)))],
        capture_output=True, timeout=120,
        creationflags=getattr(_subprocess, "CREATE_NO_WINDOW", 0))
    raw = (p.stdout or b"").decode("utf-8", errors="replace").strip()
    for ln in reversed(raw.splitlines()):
        ln = ln.strip()
        if ln.startswith("{"):
            return json.loads(ln)
    return {"ok": False, "detail": f"报告进程无输出(rc={p.returncode})"}


def _stability_sentinel_eval(data: dict) -> str:
    """P12 哨兵裁决：账本发现 P10 后有「崩溃实锤归因」的守护拉活 → 触发告警(钉钉/toast,
    去抖由 alerts 层管)；恢复归零 → 自动解除。账本是拉式看板,没人开 /ops 就没人知道回归——
    哨兵把它变成推式。口径(2026-07-06 部署竞态实证后收窄)：只有崩溃击中 Hub 才算 P10 崩溃面
    回归；无实锤拉活(人工杀/部署竞态/静默死)进账本供人判读,不触发告警——否则每次部署杀进程
    被守护抢拉,哨兵要误报一整天(1 天统计窗)。返回动作字符串(测试/日志用)。"""
    if not data.get("ok"):
        return "skip(报告失败)"
    s = data.get("summary") or {}
    p10_ts = (data.get("baseline") or {}).get("p10_deploy_ts", 0)
    hits = [r for r in (data.get("watchdog_restarts") or [])
            if r.get("ts", 0) >= p10_ts and r.get("crash")]
    try:
        import alerts as _al
        if hits:
            mods = [((r.get("crash") or {}).get("module") or "?") for r in hits]
            _al.raise_alert("hub_stability_regression",
                            "Hub 稳定性回归：原生崩溃再次击中 Hub",
                            detail=f"P10 后 {len(hits)} 次崩溃实锤拉活；模块: {', '.join(mods[-5:])}"
                                   f"。{s.get('verdict','')}。到 /ops「Hub 稳定性账本」看逐条归因。",
                            level="error", source="stability_sentinel")
            return f"fire(n={len(hits)})"
        _al.clear_alert("hub_stability_regression", note=s.get("verdict", "崩溃面无回归"))
        return "clear"
    except Exception as e:
        return f"skip({e})"


async def _bg_stability_sentinel():
    """P12：稳定性哨兵后台环——启动 3min 后首查,之后每 30min(HUB_STAB_SENTINEL_SEC 可调)。
    结果回填 /ops 缓存(开页秒出)。子进程跑账本,事件日志查询不进 Hub 进程。"""
    try:
        interval = max(300, int(os.environ.get("HUB_STAB_SENTINEL_SEC", "1800")))
    except Exception:
        interval = 1800
    await asyncio.sleep(180.0)      # 避开启动拥塞;守护发现重启也要 ~20s+日志落盘
    while True:
        try:
            data = await asyncio.to_thread(_stability_report_run, 1.0)
            if data.get("ok"):
                _STABILITY_CACHE.update(ts=time.time(), data=data)
            act = _stability_sentinel_eval(data)
            if act.startswith("fire"):
                _logger.warning(f"[StabSentinel] {act}: {((data.get('summary') or {}).get('verdict'))}")
        except Exception as exc:
            _logger.warning(f"[StabSentinel] 异常: {exc}")
        await asyncio.sleep(interval)


@app.get("/api/ops/stability")
async def api_ops_stability(days: float = 3.0, refresh: int = 0):
    """Hub 稳定性账本：P10 部署前后重启频次对比 + 崩溃模块归因 + 启动溯源。/ops 看板用。
    refresh=1 现跑并顺带哨兵裁决(与后台哨兵同一路径,E2E 可即时验证)。"""
    now = time.time()
    if not refresh and _STABILITY_CACHE["data"] is not None \
            and now - _STABILITY_CACHE["ts"] < _STABILITY_TTL:
        return _STABILITY_CACHE["data"]
    try:
        data = await asyncio.to_thread(_stability_report_run, days)
    except Exception as e:
        return {"ok": False, "detail": f"{type(e).__name__}: {e}"[:200]}
    if data.get("ok"):
        _STABILITY_CACHE.update(ts=now, data=data)
        if refresh:
            data = dict(data)
            data["sentinel"] = await asyncio.to_thread(_stability_sentinel_eval, data)
    return data


# ── P14 换脸核发布哨兵：官方(inswapper-512-live Release)/社区(ReSwapper HF) 出新货→告警 ──
# 循证(2026-07-07)：官方明确不公开 256/512、512-live 仅授权分发；社区 512 在 To-Do。
# 「记得隔段时间去看看」必然忘——日查子进程化(出网请求不进 Hub 进程)，命中走 alerts 推送。
_SWAPCORE_CACHE: dict = {"ts": 0.0, "data": None}


def _swapcore_watch_run(alert: bool = True) -> dict:
    cmd = [sys.executable, "-X", "utf8",
           str(Path(__file__).parent / "tools" / "swapcore_watch.py")]
    if alert:
        cmd.append("--alert")
    p = _subprocess.run(cmd, capture_output=True, timeout=120,
                        creationflags=getattr(_subprocess, "CREATE_NO_WINDOW", 0))
    raw = (p.stdout or b"").decode("utf-8", errors="replace").strip()
    for ln in reversed(raw.splitlines()):
        ln = ln.strip()
        if ln.startswith("{"):
            data = json.loads(ln)
            _SWAPCORE_CACHE.update(ts=time.time(), data=data)
            return data
    return {"ok": False, "detail": f"哨兵进程无输出(rc={p.returncode})"}


