async def _bg_swapcore_watch():
    """P14 日查环：启动 10min 后首查(避开启动拥塞)，之后每 24h(HUB_SWAPCORE_WATCH_SEC 可调)。
    出网失败=SKIP 不告警（脚本内置 hf-mirror 兜底）；HUB_SWAPCORE_WATCH=0 关闭。"""
    if os.environ.get("HUB_SWAPCORE_WATCH", "1") != "1":
        return
    try:
        interval = max(3600, int(os.environ.get("HUB_SWAPCORE_WATCH_SEC", "86400")))
    except Exception:
        interval = 86400
    await asyncio.sleep(600.0)
    while True:
        try:
            data = await asyncio.to_thread(_swapcore_watch_run, True)
            if data.get("hits"):
                _logger.info(f"[SwapcoreWatch] 有新货: {data['hits']}")
        except Exception as exc:
            _logger.debug(f"[SwapcoreWatch] 巡查异常: {exc}")
        await asyncio.sleep(interval)


def _tail_text(path: Path, max_bytes: int = 65536) -> list:
    """安全读 utf-8 文件尾部(最多 max_bytes)→ 行列表；文件不存在/异常→[]。只 seek 尾段，避免整读超大日志。
    seek 后先 readline() 丢弃可能被截断的半行/半个多字节字符，从整行边界起再 decode，避免中文乱码。"""
    try:
        if not path.exists():
            return []
        size = path.stat().st_size
        with open(path, "rb") as f:
            if size > max_bytes:
                f.seek(-max_bytes, os.SEEK_END)
                f.readline()               # 对齐到下一整行(丢弃半行/半字符)
            data = f.read()
        return data.decode("utf-8", "replace").splitlines()
    except Exception:
        return []


@app.get("/realtime/selfcheck")
async def realtime_selfcheck(logs: int = 10):
    """开播故障自检包(服务端聚合)：把网页看不到的守护/自愈/日志/版本汇成一份诊断，供前端「自检报告」合并 或 curl 直取。
    只读、尽力而为：任一子项失败降级为占位/错误串，绝不 500(排障工具本身必须稳)。不触发任何主动探测(翻译/合成)。"""
    out = {"ok": True, "ts": int(time.time())}
    n = max(1, min(int(logs or 10), 30))
    # 运行时/版本：uptime + 主文件 mtime + python + git 短哈希(best-effort)
    try:
        import sys as _sys
        hub_py = Path(rf"{_BASE}\avatar_hub.py")
        out["build"] = {
            "uptime_s": round(time.time() - _metrics.get("uptime_start", time.time())),
            "hub_mtime": int(hub_py.stat().st_mtime) if hub_py.exists() else 0,
            "python": _sys.version.split()[0],
            "port": PORT,
        }
        try:
            g = _subprocess.run(["git", "rev-parse", "--short", "HEAD"], cwd=_BASE,
                                capture_output=True, text=True, timeout=3,
                                creationflags=getattr(_subprocess, "CREATE_NO_WINDOW", 0))
            if g.returncode == 0:
                out["build"]["git"] = g.stdout.strip()
        except Exception:
            pass
    except Exception as e:
        out["build"] = {"err": str(e)[:80]}
    # 复用 ops 快照：服务在线/延迟/压力/GPU/内存/supervisor(重启·熔断)
    try:
        snap = await api_ops_snapshot()
        out["services"] = snap.get("services")
        out["latency_ms"] = snap.get("latency_ms")
        out["pressure"] = snap.get("pressure")
        out["gpu_util"] = snap.get("gpu_util")
        out["ram_percent"] = snap.get("ram_percent")
        out["supervisor"] = snap.get("supervisor")     # {name:{restarts,tripped,...}} 前端只挑异常项展示
    except Exception as e:
        out["ops_err"] = str(e)[:120]
    # 自愈：配置 + 计数(视频换源/变声拉起) + 累计统计 + 近期事件(内存环)
    try:
        out["heal"] = {
            "autoheal": _AUTOHEAL_ON, "alerts": _SH_ALERTS_ON,
            "video_restart_count": _AH_RESTART_COUNT,
            "rvc_relaunch_count": _AH_RVC_COUNT, "rvc_seen_up": _AH_RVC_SEEN_UP,
            "stats": _sh_stats_snapshot(),
            "audio_guard": {"silence_warn_s": _CS_SILENT_SEC, "silence_crit_extra_s": _CS_CRIT_EXTRA,
                            "rvc_grace_s": _AH_RVC_GRACE, "rvc_max": _AH_RVC_MAX},   # 音频守护护栏(供报告显形)
        }
        out["timeline"] = list(_SH_TIMELINE)[-8:]
    except Exception as e:
        out["heal_err"] = str(e)[:120]
    # 当前正在告警的项(firing)：一眼看出「此刻有没有在报警」(含无人值守·直播静音)
    try:
        import alerts as _al
        out["alerts_active"] = [{"key": k, "title": v.get("title") or k, "level": v.get("level"),
                                 "since": v.get("since_str"), "count": v.get("count")}
                                for k, v in _al.active_alerts().items()]
    except Exception:
        out["alerts_active"] = []
    # 音频链路：推流态 + RVC api 进程存活 + 直播输出设备 token + 最近一次馈线探针缓存
    try:
        out["audio"] = {
            "streaming": bool(_realtime_proc and _realtime_proc.poll() is None),
            "rvc_api_alive": bool(_rvc_api_proc and _rvc_api_proc.poll() is None),
            "broadcast_dev": _broadcast_dev_token(),
            "cable": dict(_SIGNAL_CABLE_CACHE.get("data") or {}),
        }
    except Exception as e:
        out["audio_err"] = str(e)[:120]
    # 近期错误：前端上报(client_errors.jsonl 结构化) + hub 日志尾的 WARNING/ERROR(实际报错文案)
    try:
        out["client_errors"] = _tail_text(_CLIENTLOG_PATH, 32768)[-n:]
    except Exception:
        out["client_errors"] = []
    try:
        _hub_log = _LOG_DIR / "avatar_hub.log"     # 正牌日志(utf-8·当前进程在写)，非旧控制台重定向
        _lines = _tail_text(_hub_log, 131072)
        _warns = [ln for ln in _lines if ("[WARNING]" in ln or "[ERROR]" in ln or ln.startswith("ERROR:"))]
        out["recent_log"] = _warns[-n:]
    except Exception:
        out["recent_log"] = []
    return out


@app.get("/api/ops/history")
def api_ops_history(limit: int = 240):
    """运维指标历史（落盘 JSONL 的近 limit 条）：供 /ops 画趋势/留痕审计。"""
    if not _OPS_LOG_PATH.exists():
        return {"ok": True, "samples": [], "persist_on": _OPS_PERSIST_ON,
                "interval_sec": _OPS_PERSIST_SEC}
    try:
        lines = _OPS_LOG_PATH.read_text(encoding="utf-8").splitlines()
        tail = lines[-max(1, min(limit, 5000)):]
        samples = []
        for ln in tail:
            ln = ln.strip()
            if not ln:
                continue
            try:
                samples.append(json.loads(ln))
            except Exception:
                continue
        return {"ok": True, "samples": samples, "persist_on": _OPS_PERSIST_ON,
                "interval_sec": _OPS_PERSIST_SEC, "writes": _ops_persist_n["writes"]}
    except Exception as e:
        return {"ok": False, "detail": str(e)}


@app.get("/api/ops/selfcheck")
async def api_ops_selfcheck(run: int = 1, latency: int = 1, alert: int = 0, history: int = 40):
    """全链路自检（健康 + 关键阶段延迟 NMT/STT/TTS + 红旗）：供 /ops 看板一键触发。
    进程内复用 selfcheck_pipeline（只读探测，不改运行状态）；阻塞式 HTTP 探测放线程池，不卡事件循环。
      run=0    只回历史(不探测)，供页面加载显示趋势；
      run=1    现跑并落历史(logs/selfcheck_history.jsonl，与 CLI/计划任务共用同一份)；
      latency=0 只做健康扫描(更快)；
      alert=1  顺带把红旗同步到 alerts.py(去抖 raise/clear，含恢复)——等价于 CLI 的 --alert。
    因会触发真实探测(翻译/转写/TTS 合成)与告警，已按敏感 GET 鉴权(本机回环免令牌)。"""
    import selfcheck_pipeline as _sp
    if not run:
        hist = await asyncio.to_thread(_sp.read_history, history)
        return {"cached": True, "history": hist, "last": (hist[-1] if hist else None)}
    try:
        res = await asyncio.to_thread(_sp.run, bool(latency))
        res["up"] = sum(1 for r in res.get("health", []) if r.get("up"))
        res["total"] = len(res.get("health", []))
        res["ts"] = time.time()
        if alert:
            res["alert_sync"] = await asyncio.to_thread(_sp.sync_alerts, res)
        await asyncio.to_thread(_sp.append_history, res)
        res["history"] = await asyncio.to_thread(_sp.read_history, history)
        return res
    except Exception as e:
        hist = await asyncio.to_thread(_sp.read_history, history)
        return {"ok": False, "error": "自检执行失败：%s" % e, "health": [],
                "flags": [], "latency": {}, "up": 0, "total": 0, "history": hist}


_ACCEPT_REPORT = Path(rf"{_BASE}\logs\acceptance_report.json")
_ACCEPT_HISTORY = Path(rf"{_BASE}\logs\acceptance_history.jsonl")
_ACCEPT_STALE_SEC = float(os.environ.get("ACCEPT_STALE_SEC", str(36 * 3600)))  # 超 36h 视为陈旧


@app.get("/api/ops/acceptance")
def api_ops_acceptance(history: int = 30):
    """上线前一键体检结果：最近一次总表 + 历史趋势（供 /ops 看板 + 失败告警）。"""
    latest = None
    if _ACCEPT_REPORT.exists():
        try:
            latest = json.loads(_ACCEPT_REPORT.read_text(encoding="utf-8"))
        except Exception:
            latest = None
    hist = []
    if _ACCEPT_HISTORY.exists():
        try:
            lines = _ACCEPT_HISTORY.read_text(encoding="utf-8").splitlines()
            for ln in lines[-max(1, min(history, 300)):]:
                ln = ln.strip()
                if ln:
                    try:
                        hist.append(json.loads(ln))
                    except Exception:
                        pass
        except Exception:
            pass
    age = (time.time() - latest["ts"]) if (latest and latest.get("ts")) else None
    stale = (age is None) or (age > _ACCEPT_STALE_SEC)
    # 告警等级：从未跑/陈旧=warn；最近一次有失败=crit；否则=ok
    if latest is None:
        alert, msg = "warn", "尚未运行上线体检（acceptance.py）"
    elif not latest.get("overall"):
        fails = [r["title"] for r in latest.get("results", []) if not r.get("ok")]
        alert, msg = "crit", "上次体检存在失败项：" + "、".join(fails[:6])
    elif stale:
        hrs = int(age / 3600) if age else 0
        alert, msg = "warn", f"体检结果已陈旧（{hrs}h 前），建议重跑"
    else:
        alert, msg = "ok", "上次体检全部通过"
    return {"ok": True, "latest": latest, "history": hist,
            "age_sec": age, "stale": stale, "alert": alert, "alert_msg": msg}


