_VQ_LOG_PATH = Path(rf"{_BASE}\logs\voice_quality.jsonl")
_VQ_HARD_FLOOR = float(os.environ.get("VQ_HARD_FLOOR", "0.30"))   # 绝对兜底（疑似坏掉）
_VQ_CEIL_TARGET = float(os.environ.get("VQ_CEIL_TARGET", "0.55")) # 低于此且稳定=源录音到顶
_VQ_MIN_SAMPLES = 4                                               # 建基线所需最少样本


def _stdev(xs):
    if len(xs) < 2:
        return 0.0
    m = sum(xs) / len(xs)
    return (sum((x - m) ** 2 for x in xs) / (len(xs) - 1)) ** 0.5


def _vq_aggregate(history: int = 30) -> dict:
    """从 voice_quality.jsonl 聚合每角色：cosine 趋势 + 个体基线带 + 回归/到顶判定。
    回归告警以"较自身基线显著下降"为准（比固定下限更灵敏、对源录音受限角色更少误报），
    同时保留极低绝对兜底。"""
    runs = []
    if _VQ_LOG_PATH.exists():
        try:
            lines = _VQ_LOG_PATH.read_text(encoding="utf-8").splitlines()
            for ln in lines[-max(1, min(history, 400)):]:
                ln = ln.strip()
                if ln:
                    try:
                        runs.append(json.loads(ln))
                    except Exception:
                        pass
        except Exception:
            pass
    cos_min = 0.45
    by_profile: dict = {}
    for r in runs:
        cos_min = r.get("cos_min", cos_min)
        for p in r.get("profiles", []):
            nm = p.get("name")
            if not nm:
                continue
            d = by_profile.setdefault(nm, {"name": nm, "cos_series": [], "nat_series": [],
                                           "last": None, "ok": True})
            if p.get("cos") is not None:
                d["cos_series"].append(p.get("cos"))
            if p.get("nat") is not None:
                d["nat_series"].append(p.get("nat"))
            d["last"] = p
            d["ok"] = bool(p.get("ok"))
    regressed, weak = [], []
    for nm, d in by_profile.items():
        cs = d["cos_series"]
        last = d.get("last") or {}
        c = last.get("cos")
        d["baseline"] = d["band_low"] = d["std"] = None
        d["near_ceiling"] = False
        d["floor_eff"] = _VQ_HARD_FLOOR
        if c is None:
            continue
        if len(cs) >= _VQ_MIN_SAMPLES:
            hist = cs[:-1] if len(cs) > _VQ_MIN_SAMPLES else cs   # 用历史(不含本次)做基线
            base = sum(hist) / len(hist)
            sd = _stdev(hist)
            # 自适应个体地板：基线本就贴着绝对地板的「源录音受限」角色(如基线 0.306 vs 地板 0.30)，
            # 引擎重启带来的 0.01 级数值漂移就会击穿 max(地板, 带下沿) 的钳位 → 假"疑似坏掉"
            # (2026-07-06 刘德华实锤：0.31→0.293，nat/时长/能量全正常)。基线离地板不足 0.03 时，
            # 地板放宽到 (基线-0.06)，但绝不低于 地板-0.05——真坏(崩到 0.2x 以下)仍然拦得住。
            floor_eff = _VQ_HARD_FLOOR
            if base < _VQ_HARD_FLOOR + 0.03:
                floor_eff = max(_VQ_HARD_FLOOR - 0.05, base - max(2 * sd, 0.06))
            band_low = max(floor_eff, base - max(2 * sd, 0.06))
            d["baseline"] = round(base, 3); d["std"] = round(sd, 3)
            d["band_low"] = round(band_low, 3)
            d["floor_eff"] = round(floor_eff, 3)
            d["near_ceiling"] = (base < _VQ_CEIL_TARGET and sd < 0.05)
            if c < band_low:
                regressed.append({"name": nm, "cos": c, "baseline": round(base, 3),
                                  "band_low": round(band_low, 3)})
        else:
            # 样本不足以建基线：退回极低绝对兜底，避免对源录音受限角色误报
            if c < _VQ_HARD_FLOOR:
                weak.append({"name": nm, "cos": c})
    alerts = regressed + weak
    alert = "warn" if alerts else "ok"
    msg = ""
    if regressed:
        msg = "声纹较基线回归：" + "、".join(
            "%s %.3f(基线%.3f)" % (a["name"], a["cos"], a["baseline"]) for a in regressed)
    elif weak:
        msg = "声纹异常低（<%.2f）：" % _VQ_HARD_FLOOR + "、".join(
            "%s %.3f" % (w["name"], w["cos"]) for w in weak)
    return {"ok": True, "cos_min": cos_min, "runs": len(runs),
            "ceil_target": _VQ_CEIL_TARGET, "hard_floor": _VQ_HARD_FLOOR,
            "profiles": list(by_profile.values()),
            "regressed": regressed, "weak": weak, "alert": alert, "alert_msg": msg}


@app.get("/api/ops/voice_quality")
def api_ops_voice_quality(history: int = 30):
    """真出声质量历史：每角色 cosine/naturalness 趋势 + 个体基线带 + 回归告警 + 到顶标记。"""
    return _vq_aggregate(history)


# ── 集群显存 · 预算 vs 实测（cluster_map.vram_budget 静态门禁的运行时可视）──────────
_VRAM_ACTUAL_CACHE: dict = {"ts": 0.0, "hosts": {}, "busy": False}
_VRAM_CACHE_TTL = float(os.environ.get("OPS_VRAM_TTL_SEC", "60"))


def _nvsmi_query(ip: str, local: bool) -> dict:
    """单机显存实测（本机直跑 nvidia-smi / 远程走 SSH），失败返回 {}（看板显示"—"）。"""
    q = ("nvidia-smi --query-gpu=memory.used,memory.total,utilization.gpu "
         "--format=csv,noheader,nounits")
    cmd = q.split() if local else ["ssh", "-o", "ConnectTimeout=6", "-o", "BatchMode=yes",
                                   f"Administrator@{ip}", q]
    try:
        r = _subprocess.run(cmd, capture_output=True, text=True, timeout=12)
        m = re.search(r"(\d+),\s*(\d+),\s*(\d+)", r.stdout or "")
        if m:
            return {"used_gb": round(int(m.group(1)) / 1024, 1),
                    "total_gb": round(int(m.group(2)) / 1024, 1),
                    "util": int(m.group(3))}
    except Exception:
        pass
    return {}


def _vram_actual_refresh(ips: list, hub_ip: str):
    """后台并行采集全机显存实测 → 进程内缓存（SSH 慢，绝不在请求线程里跑）。"""
    try:
        from concurrent.futures import ThreadPoolExecutor
        with ThreadPoolExecutor(max_workers=5) as ex:
            futs = {ip: ex.submit(_nvsmi_query, ip, ip == hub_ip) for ip in ips}
            _VRAM_ACTUAL_CACHE["hosts"] = {ip: f.result() for ip, f in futs.items()}
        _VRAM_ACTUAL_CACHE["ts"] = time.time()
    finally:
        _VRAM_ACTUAL_CACHE["busy"] = False


@app.get("/api/ops/vram_budget")
def api_ops_vram_budget(refresh: int = 0):
    """集群显存「预算(cluster_map.vram_budget) vs 实测(nvidia-smi)」对照。
    topology_lint 只在改配置时静态把关；这里把同一张预算表升级为运行时可视：
    实测 > 机器上限(物理×阈值) 即红——谁在真机上偷偷多吃显存一眼可见。"""
    try:
        cm = json.loads((Path(rf"{_BASE}") / "cluster_map.json").read_text(encoding="utf-8"))
    except Exception as e:
        return {"ok": False, "detail": f"cluster_map.json 读取失败: {e}"}
    vb = cm.get("vram_budget") or {}
    thr = float(vb.get("threshold") or 0.92)
    hub_ip = (cm.get("hub") or {}).get("ip", "")
    ips = [k for k in vb.keys() if k != "threshold"]
    stale = (time.time() - _VRAM_ACTUAL_CACHE["ts"]) > (0 if refresh else _VRAM_CACHE_TTL)
    if stale and not _VRAM_ACTUAL_CACHE["busy"]:
        _VRAM_ACTUAL_CACHE["busy"] = True
        threading.Thread(target=_vram_actual_refresh, args=(ips, hub_ip), daemon=True).start()
    hosts = []
    for ip in ips:
        ent = vb.get(ip) or {}
        svcs = ent.get("services") or {}
        budget = round(sum(float(v) for v in svcs.values()), 1)
        cap = round(float(ent.get("vram_gb") or 0) * thr, 1)
        act = (_VRAM_ACTUAL_CACHE["hosts"] or {}).get(ip) or {}
        used = act.get("used_gb")
        hosts.append({
            "ip": ip, "gpu": ent.get("gpu", ""), "vram_gb": ent.get("vram_gb"),
            "cap_gb": cap, "budget_gb": budget, "services": svcs,
            "actual_used_gb": used, "actual_total_gb": act.get("total_gb"),
            "gpu_util": act.get("util"),
            "budget_over": budget > cap,
            "actual_over": (used is not None and used > cap),
        })
    return {"ok": True, "ts": _VRAM_ACTUAL_CACHE["ts"], "threshold": thr,
            "collecting": _VRAM_ACTUAL_CACHE["busy"], "hosts": hosts}


_vq_write_lock = threading.Lock()


def _vq_append(name: str, cos, nat, *, dur=None, voiced=None, rms=None, cps=None,
               ok: bool = True, source: str = "probe") -> bool:
    """向 voice_quality.jsonl 追加一条单角色样本（schema 与 _voice_quality.py 一致）。
    用途：新克隆/体检过的角色立即出现在声纹趋势看板，并尽快累积出个体基线带。"""
    try:
        rec = {"ts": time.time(), "cos_min": 0.45, "pass": 1 if ok else 0, "total": 1,
               "source": source,
               "profiles": [{"name": name, "ok": bool(ok), "cos": cos, "nat": nat,
                             "dur": dur, "voiced": voiced, "rms": rms, "cps": cps}]}
        with _vq_write_lock:
            _VQ_LOG_PATH.parent.mkdir(parents=True, exist_ok=True)
            lines = _VQ_LOG_PATH.read_text(encoding="utf-8").splitlines() if _VQ_LOG_PATH.exists() else []
            lines.append(json.dumps(rec, ensure_ascii=False))
            _VQ_LOG_PATH.write_text("\n".join(lines[-400:]) + "\n", encoding="utf-8")
        return True
    except Exception as e:
        _logger.warning(f"[VQ] append 失败 {name}: {e}")
        return False


async def _measure_profile_quality(name: str, sentences=None) -> dict:
    """合成标准句并评 cosine/naturalness（体检端点与"入库自动建基线"共用，避免重复逻辑）。"""
    prof = _profiles.get(name)
    if not prof:
        return {"ok": False, "detail": "角色不存在"}
    ref_b64 = prof.get("voice_b64", "")
    if not ref_b64:
        return {"ok": False, "detail": "无参考音频"}
    try:
        import clone_scorer
        import prosody_scorer as _ps
    except Exception as e:
        return {"ok": False, "detail": f"评分模块加载失败: {e}"}
    profile = dict(prof); profile["name"] = name
    sents = sentences or profile.get("probe_sentences") or _QUALITY_PROBE_SENTS
    sents = [s for s in sents if isinstance(s, str) and s.strip()] or _QUALITY_PROBE_SENTS
    coss, nats = [], []
    for s in sents:
        a = await _conv_synthesize(s, profile, language="zh-cn", emotion="neutral",
                                   vc_engine="", watermark=None, _use_opener_cache=False)
        if not a:
            continue
        sc = await asyncio.to_thread(clone_scorer.score_similarity, ref_b64, a)
        if sc.get("ok"):
            coss.append(sc.get("cosine", 0.0))
        nt = await asyncio.to_thread(_ps.naturalness_score, a, ref_b64)
        if nt.get("ok"):
            nats.append(nt.get("naturalness", 0.0))
    if not coss and not nats:
        return {"ok": False, "detail": "合成失败"}
    axes = {"cosine": round(sum(coss) / len(coss), 4) if coss else 0.0,
            "naturalness": round(sum(nats) / len(nats), 4) if nats else 0.0,
            "ts": time.time()}
    return {"ok": True, "axes": axes, "coss": coss, "nats": nats, "n": len(sents)}


async def _async_seed_voice_quality(name: str):
    """新角色入库后台自动建声纹基线首点：合成→clone_score→写 quality_axes + vq 日志。
    让新克隆的角色第一天就出现在声纹趋势看板，而非"暂无样本"。"""
    await asyncio.sleep(2.5)   # 让试听预生成先跑，降低 TTS 争用
    prof = _profiles.get(name, {})
    if not prof or not prof.get("voice_b64"):
        return
    if prof.get("quality_axes"):   # 已有质量轴（如导入带过来的）则不重复刷
        return
    try:
        res = await _measure_profile_quality(name)
    except Exception as e:
        _logger.warning(f"[VQseed] {name} 失败: {e}")
        return
    if not res.get("ok"):
        _logger.info(f"[VQseed] {name} 跳过: {res.get('detail')}")
        return
    axes = res["axes"]
    async with _PROFILES_LOCK:
        if name in _profiles:
            p = dict(_profiles[name]); p["quality_axes"] = axes
            _profiles[name] = p; _save_profile(name)
    _vq_append(name, axes["cosine"], axes["naturalness"], ok=True, source="enroll")
    _logger.info(f"[VQseed] {name} 首点入库 cos={axes['cosine']} nat={axes['naturalness']}")
    try:
        await broadcast({"event": "profile_updated", "name": name})
    except Exception:
        pass


def _analyze_recording(b64: str) -> dict:
    """源录音质量自检：时长/采样率/电平(dBFS)/底噪/信噪比SNR/削幅/首尾静音。
    用于指导用户录出能把克隆 cosine 拉高的素材（干净、够长、不削幅、底噪低）。"""
    import wave as _wave
    import io as _io
    import numpy as _np
    raw = base64.b64decode(b64)
    try:
        wf = _wave.open(_io.BytesIO(raw), "rb")
    except Exception as e:
        return {"ok": False, "detail": "非 WAV 或解析失败：%s（建议导出 16k/16bit 单声道 WAV）" % e}
    ch, sw, fr, nf = wf.getnchannels(), wf.getsampwidth(), wf.getframerate(), wf.getnframes()
    pcm = wf.readframes(nf); wf.close()
    dur = nf / float(fr) if fr else 0.0
    if sw != 2:
        return {"ok": True, "duration_s": round(dur, 2), "sample_rate": fr, "channels": ch,
                "advice": ["位深非 16bit，建议导出 16bit PCM WAV 以便统一分析"], "grade": "未知"}
    a = _np.frombuffer(pcm, dtype=_np.int16).astype(_np.float32) / 32768.0
    if ch > 1:
        a = a.reshape(-1, ch).mean(axis=1)
    if a.size == 0:
        return {"ok": False, "detail": "空音频"}
    peak = float(_np.abs(a).max())
    win = max(1, int(fr * 0.03))
    n = a.size // win
    frames = a[:n * win].reshape(n, win) if n > 0 else a.reshape(1, -1)
    rms = _np.sqrt((frames ** 2).mean(axis=1) + 1e-12)
    # 底噪/语音只在"有效帧"里取：排除数字静音帧(<≈-80dBFS，录制软件补零/剪辑留白)，
    # 否则纯零段会把 SNR 虚高到 100dB+；全静音时退回全部帧。
    # 底噪取低 2% 分位：连续说话、几乎无停顿的素材，低 10% 帧可能仍是人声、会高估底噪
    rms_sorted = _np.sort(rms)
    active = rms_sorted[rms_sorted > 1e-4]
    if active.size == 0:
        active = rms_sorted
    noise = float(active[:max(1, int(active.size * 0.02))].mean())   # 低 2% 有效帧≈底噪
    speech = float(active[int(active.size * 0.60):].mean())          # 高 40% 有效帧≈语音
    snr = 20.0 * _np.log10((speech + 1e-9) / (noise + 1e-9))
    thr = max(0.01, float(rms.max()) * 0.10)
    voiced_ratio = float((rms > thr).mean())
    clip = float((_np.abs(a) > 0.99).mean())
    # 首尾静音
    voiced_idx = _np.where(rms > thr)[0]
    lead = float(voiced_idx[0] * win / fr) if voiced_idx.size else dur
    trail = float((len(rms) - 1 - voiced_idx[-1]) * win / fr) if voiced_idx.size else dur
    peak_db = 20.0 * _np.log10(peak + 1e-9)

    advice = []
    if dur < 8:
        advice.append("时长仅 %.1fs，建议 ≥15s 连续清晰语音（素材越足，克隆越稳）" % dur)
    if fr < 16000:
        advice.append("采样率 %dHz 偏低，建议 ≥16kHz 录制" % fr)
    if snr < 18:
        advice.append("信噪比 %.1fdB 偏低（环境噪声大），建议安静环境/近麦录制（目标 ≥25dB）" % snr)
    if clip > 0.001:
        advice.append("检测到削幅(%.2f%% 采样点接近满幅)，请降低输入增益重录" % (clip * 100))
    if peak_db < -18:
        advice.append("整体电平偏小(峰值 %.1fdBFS)，建议靠近麦克风或适当提高增益（目标峰值 -6~-3dBFS）" % peak_db)
    if max(lead, trail) > 1.5:
        advice.append("首/尾静音较长(前%.1fs 后%.1fs)，建议裁掉纯静音段" % (lead, trail))
    if voiced_ratio < 0.5:
        advice.append("有话比 %.0f%% 偏低（停顿/静音多），建议选连续说话片段" % (voiced_ratio * 100))
    # 评级
    score = 0
    score += 1 if dur >= 8 else 0
    score += 1 if snr >= 25 else (0 if snr < 18 else 0.5)
    score += 1 if clip <= 0.001 else 0
    score += 1 if -18 <= peak_db <= -1 else 0.5
    score += 1 if voiced_ratio >= 0.5 else 0
    grade = "优" if score >= 4.5 else ("良" if score >= 3.5 else ("一般" if score >= 2.5 else "建议重录"))
    if not advice:
        advice.append("录音质量良好，可直接用于克隆/参考音")
    return {"ok": True, "duration_s": round(dur, 2), "sample_rate": fr, "channels": ch,
            "peak_dbfs": round(peak_db, 1), "snr_db": round(float(snr), 1),
            "noise_floor": round(noise, 4), "voiced_ratio": round(voiced_ratio, 2),
            "clipping_pct": round(clip * 100, 3), "lead_silence_s": round(lead, 2),
            "trail_silence_s": round(trail, 2), "grade": grade, "advice": advice}


import hmac as _hmac

def _ops_share_token() -> str:
    """只读看板分享 token：优先环境变量 OPS_SHARE_TOKEN；否则生成并持久化到 logs。"""
    t = os.environ.get("OPS_SHARE_TOKEN", "").strip()
    if t:
        return t
    fp = Path(rf"{_BASE}\secrets\ops_share_token.txt")       # 受限目录，勿随日志/仓库外泄
    legacy = Path(rf"{_BASE}\logs\ops_share_token.txt")      # 旧位置：迁移并保留同值
    try:
        if fp.exists():
            return fp.read_text(encoding="utf-8").strip()
        fp.parent.mkdir(parents=True, exist_ok=True)
        if legacy.exists():                                   # 迁移：保留原 token 值，旧链接不失效
            t = legacy.read_text(encoding="utf-8").strip()
            if t:
                fp.write_text(t, encoding="utf-8")
                try:
                    legacy.unlink()
                except Exception:
                    pass
                _logger.info("[OpsShare] 已将分享 token 迁移至 secrets/ 目录")
                return t
        t = uuid.uuid4().hex
        fp.write_text(t, encoding="utf-8")
        _logger.info("[OpsShare] 生成只读看板分享 token（也可用 OPS_SHARE_TOKEN 覆盖）")
        return t
    except Exception:
        return ""


def _ops_sign_link(ttl_sec: int = 86400) -> dict:
    """生成带过期时间的签名 token：v1.<exp>.<sig>，sig=HMAC(master_token, exp)。
    对外临时分享用，到期自动失效，且不泄漏长期 master token。"""
    import hashlib
    exp = int(time.time()) + max(60, int(ttl_sec))
    key = _ops_share_token().encode("utf-8")
    sig = _hmac.new(key, str(exp).encode("utf-8"), hashlib.sha256).hexdigest()[:32]
    tok = "v1.%d.%s" % (exp, sig)
    return {"token": tok, "exp": exp, "ttl_sec": int(ttl_sec),
            "path": "/share/ops?token=" + tok}


def _ops_signed_ok(token: str) -> bool:
    """校验签名 token（格式 v1.<exp>.<sig>）：未过期且签名正确。"""
    import hashlib
    try:
        ver, exp_s, sig = token.split(".", 2)
        if ver != "v1":
            return False
        exp = int(exp_s)
        if exp < time.time():
            return False
        key = _ops_share_token().encode("utf-8")
        good = _hmac.new(key, str(exp).encode("utf-8"), hashlib.sha256).hexdigest()[:32]
        return _hmac.compare_digest(sig, good)
    except Exception:
        return False


def _ops_share_ok(token: str) -> bool:
    if not token:
        return False
    real = _ops_share_token()
    # 1) 兼容旧的长期 master token（本机/内网长期看板）
    if real and _hmac.compare_digest(str(token), real):
        return True
    # 2) 签名时效 token（对外临时分享，到期失效）
    if token.startswith("v1."):
        return _ops_signed_ok(token)
    return False


@app.get("/api/share/ops")
async def api_share_ops(token: str = ""):
    """只读看板数据（token 鉴权）：稳健性总览 + 上线体检 + 真出声质量，一份给手机看。"""
    if not _ops_share_ok(token):
        raise HTTPException(403, "token 无效")
    snap = await api_ops_snapshot()
    acc = api_ops_acceptance(history=20)
    vq = _vq_aggregate(history=30)
    # 精简：只挑手机端要看的关键字段
    return {
        "ok": True, "ts": time.time(),
        "pressure": snap.get("pressure"), "gpu_util": snap.get("gpu_util"),
        "ram_percent": snap.get("ram_percent"),
        "services": snap.get("services", {}), "services_busy": snap.get("services_busy", []),
        "pref_warn": snap.get("pref_warn"),
        "acceptance": {"alert": acc.get("alert"), "alert_msg": acc.get("alert_msg"),
                       "age_sec": acc.get("age_sec"), "stale": acc.get("stale"),
                       "latest": acc.get("latest")},
        "voice_quality": {"alert": vq.get("alert"), "alert_msg": vq.get("alert_msg"),
                          "profiles": [{"name": p["name"],
                                        "last_cos": (p.get("last") or {}).get("cos"),
                                        "baseline": p.get("baseline"), "band_low": p.get("band_low"),
                                        "near_ceiling": p.get("near_ceiling", False),
                                        "cos_series": p.get("cos_series", [])}
                                       for p in vq.get("profiles", [])]},
    }


@app.get("/share/ops")
def ops_share_page(token: str = ""):
    """只读移动端看板页（token 鉴权）：体检/质量趋势随时手机查看，配合告警形成闭环。"""
    if not _ops_share_ok(token):
        return Response(content="<h3 style='font-family:sans-serif'>403 · token 无效或缺失</h3>",
                        status_code=403, media_type="text/html")
    _f = Path(rf"{_BASE}\static\ops_share.html")
    if _f.exists():
        return Response(content=_f.read_text(encoding="utf-8"), media_type="text/html")
    return Response(content="ops_share.html not found", status_code=404)


