@app.get("/api/auth/status")
def api_auth_status(request: Request):
    """前端探测管理面是否启用令牌、本次请求是否已授权（公开只读）。"""
    enabled = bool(_API_TOKEN)
    authed = True
    if enabled:
        import hmac as _h
        tok = (request.headers.get("X-AH-Token")
               or request.cookies.get("ah_token")
               or request.query_params.get("ah_token") or "")
        client_host = (request.client.host if request.client else "") or ""
        loopback_ok = (_AUTH_TRUST_LOOPBACK and client_host in _LOOPBACK_HOSTS)
        authed = loopback_ok or bool(tok and _h.compare_digest(str(tok), _API_TOKEN))
    return {"ok": True, "auth_enabled": enabled, "authed": authed,
            "trust_loopback": _AUTH_TRUST_LOOPBACK}


@app.get("/api/security/posture")
def api_security_posture(request: Request):
    """只读安全体检：把「对外暴露面」摊开给运维自查——绑定地址 / 管理令牌 / 子服务令牌 / IP 白名单 /
    CORS / 授权强制，并给风险等级 + 可执行建议。设管理令牌后本端点转为敏感读（远端需令牌，
    避免把安全配置泄给攻击者）；未设令牌时公开可读（门本就敞着，正好提醒运维「你在裸奔」）。"""
    client_host = (request.client.host if request.client else "") or ""
    remote = client_host not in _LOOPBACK_HOSTS
    exposed = _BIND_HOST not in ("127.0.0.1", "::1", "localhost")
    api_tok = bool(_API_TOKEN)
    svc_tok = svc_ips = False
    try:
        import app_config as _ac
        svc_tok = bool(_ac.service_token())
        svc_ips = bool(_ac.service_allow_ips())
    except Exception:
        pass
    cors_wild = any(o == "*" for o in _CORS_ORIGINS)
    enforcing = False
    try:
        enforcing = bool(_license and _license.enforcing())
    except Exception:
        pass

    findings = []

    def add(level, msg, fix=""):
        findings.append({"level": level, "msg": msg, "fix": fix})

    if not exposed:
        add("ok", "管理面仅绑定本机(127.0.0.1)，对外零暴露（最强隔离）。")
    elif api_tok:
        add("ok", "管理面对外可达但已启用令牌：非回环的写操作/敏感读均需令牌。")
    else:
        add("high", "管理面绑定 0.0.0.0 且未设管理令牌——同网任意机器可改配置 / 增删角色 / 克隆声音 / 操纵服务。",
            "设 AVATARHUB_API_TOKEN（或运行 harden.bat），或 AVATARHUB_BIND=127.0.0.1 只留本机、对外走反代。")
    if cors_wild:
        add("medium", "CORS 允许任意来源(*)——恶意网页可借用户浏览器跨站调用管理面。",
            "把 AVATARHUB_CORS_ORIGINS 收敛到确切来源（默认已仅本机）。")
    if not svc_tok and not svc_ips:
        add("medium", "子服务面(TTS/STT/口型/换脸等)未设共享令牌或 IP 白名单——多机部署时其它机器可直连算力面。",
            "运行 harden.bat 生成并下发 AVATARHUB_SERVICE_TOKEN，或设 AVATARHUB_SERVICE_ALLOW_IPS。")

    risk = ("high" if any(f["level"] == "high" for f in findings)
            else "medium" if any(f["level"] == "medium" for f in findings) else "low")
    return {"ok": True, "risk": risk, "bind_host": _BIND_HOST, "exposed_bind": exposed,
            "remote_request": remote, "api_token_set": api_tok,
            "trust_loopback": _AUTH_TRUST_LOOPBACK, "service_token_set": svc_tok,
            "service_allow_ips_set": svc_ips, "cors_wildcard": cors_wild,
            "license_enforcing": enforcing, "findings": findings}


# ── 一键令牌轮换（/ops 安全卡 → harden_remote.ps1 -Mode rotate）──────────────
_ROTATE_STATE = {"running": False, "started_at": 0.0, "result": "", "detail": "", "ended_at": 0.0}
_ROTATE_MUTEX = threading.Lock()


def _live_session_busy():
    """直播/同传是否进行中——与 harden_remote drill 守卫同判据：
    本机换脸直播(realtime_stream 子进程存活) + live_interpreter 会话 running。"""
    if _realtime_proc is not None and _realtime_proc.poll() is None:
        return True, "换脸直播进行中(realtime_stream)"
    try:
        j = requests.get(_INTERP_BASE + "/health", timeout=2).json()
        if j.get("running"):
            return True, "同传会话进行中(live_interpreter)"
    except Exception:
        pass
    return False, ""


def _rotate_worker():
    """后台执行轮换：写 drill 标记(看门狗巡检让路,TTL 自动失效)→ ps1 rotate(下发+重启+复验)
    → 记结果+事件通知（操作者可能已关页面，webhook 留痕保证结果必达）。"""
    base = Path(__file__).resolve().parent
    flag = base / "logs" / "drill_active.flag"
    logf = base / "logs" / "token_rotate_ui.log"
    result, detail = "FAIL", ""
    try:
        try:
            flag.write_text("rotate " + time.strftime("%Y-%m-%d %H:%M:%S"), encoding="utf-8")
        except Exception:
            pass
        r = _subprocess.run(
            ["powershell", "-NoProfile", "-ExecutionPolicy", "Bypass",
             "-File", str(base / "harden_remote.ps1"), "-Mode", "rotate"],
            cwd=str(base), capture_output=True, text=True,
            encoding="utf-8", errors="replace", timeout=600,
            creationflags=getattr(_subprocess, "CREATE_NO_WINDOW", 0))
        ok = (r.returncode == 0)
        result = "PASS" if ok else "FAIL"
        tail = [ln for ln in (r.stdout or "").splitlines() if ln.strip()][-30:]
        detail = ("退出码=%d" % r.returncode) if not ok else "新令牌已生效，旧令牌已失效"
        try:
            with open(logf, "a", encoding="utf-8") as f:
                f.write("\n[%s] rotate(ui) exit=%d\n%s\n" % (
                    time.strftime("%Y-%m-%d %H:%M:%S"), r.returncode, "\n".join(tail)))
        except Exception:
            pass
    except Exception as e:
        detail = "执行异常: %s" % e
    finally:
        try:
            flag.unlink(missing_ok=True)
        except Exception:
            pass
        _ROTATE_STATE.update(running=False, result=result, detail=detail, ended_at=time.time())
        try:
            import alerts
            alerts.notify_event(
                "令牌轮换%s（/ops 一键触发）" % ("完成" if result == "PASS" else "失败"),
                detail=detail + ("" if result == "PASS" else " | 详情见 logs/token_rotate_ui.log，可重试或手动 -Mode rotate"),
                level=("info" if result == "PASS" else "error"),
                source="avatar_hub/一键轮换")
        except Exception:
            pass


@app.post("/api/security/rotate_token")
def api_security_rotate_token(force: int = 0):
    """一键轮换服务令牌（写操作：启用管理令牌后需授权）：生成新令牌→三机下发→重启子服务→复验旧令牌失效。
    直播/同传进行中默认拒绝（轮换要重启 GPU 服务,会掐断在线会话；force=1 明确强制才放行）。
    并发防抖：同一时刻只允许一场轮换。进度由 /api/ops/snapshot security.rotate 观测。"""
    if not force:
        busy, why = _live_session_busy()
        if busy:
            return {"ok": False, "busy": True,
                    "detail": why + "——轮换会重启子服务掐断会话；直播结束后再试，或明确 force=1 强制"}
    with _ROTATE_MUTEX:
        if _ROTATE_STATE["running"]:
            return {"ok": False, "detail": "轮换已在进行中（约 1-2 分钟），请稍候观察安全卡状态"}
        if not (Path(__file__).resolve().parent / "harden_remote.ps1").exists():
            return {"ok": False, "detail": "缺 harden_remote.ps1，无法轮换"}
        _ROTATE_STATE.update(running=True, started_at=time.time(),
                             result="", detail="", ended_at=0.0)
    threading.Thread(target=_rotate_worker, daemon=True, name="token-rotate").start()
    return {"ok": True, "started": True,
            "detail": "轮换已启动：新令牌下发→服务重启→复验（约 1-2 分钟，安全卡实时可见）"}


@app.get("/api/license/status")
def api_license_status():
    """授权状态（公开只读）：档位/有效期/能力/机器指纹/是否强制。看板与运维据此提示续费。"""
    if _license is None:
        return {"ok": True, "available": False,
                "state": {"status": "no_module", "status_label": "未授权",
                          "edition": "trial", "edition_label": "试用版",
                          "days_left": -1, "expiring_soon": False, "enforcing": False,
                          "message": "license 模块未加载（按未授权/试用处理）。"}}
    try:
        # P11 试用到期软着陆：徽章每 60s 轮询到这——试签到期即自动还原备份的正式授权，
        # 客户最多晚 1 分钟看到「已还原」而不是「已过期」死局。幂等（还原后不再是试签→纯读）。
        try:
            _msg = _license.trial_autorestore_if_due()
            if _msg:
                _lic_audit("自动还原", True, _msg)
        except Exception:
            pass
        # 失效即时补救（旁路热点、绝不阻塞本响应）：已开强制且当前无效(过期/被挡)且到刷新节流窗口→
        # 起后台线程按指纹拉一次。管理后台刚续的费，客户 ≤1 次状态轮询(~60s)即恢复，不必干等 1h 周期。
        try:
            _st_now = _license.load_state()
            if _license.enforcing() and not _st_now.valid and _license.refresh_due():
                threading.Thread(target=_license.maybe_refresh, kwargs={"force": False},
                                 daemon=True, name="lic-jit-refresh").start()
        except Exception:
            pass
        out = {"ok": True, "available": True, "state": _license.summary()}
        try:
            out["matrix"] = _license.editions_matrix()   # P5 档位对比表（EDITION_FEATURES 单源）
        except Exception:
            pass
        return out
    except Exception as e:
        return {"ok": False, "detail": "读取授权状态失败：%s" % e}


@app.post("/api/license/crl/refresh")
async def api_license_crl_refresh():
    """手动在线拉取吊销名单（写操作：启用管理令牌后需令牌）。运维吊销后想「分钟级即时生效」而不
    必等周期轮询时用。未配置在线源→返回提示；拉取失败/更旧→软处理，绝不影响现有授权状态。"""
