class MetricsFeedbackRequest(BaseModel):
    profile:      str = ""
    rating:       int = 0          # 1=👍  -1=👎
    source:       str = "phone"
    text_preview: str = ""
    reply_lang:   str = ""
    msg_id:       int = 0


def _tune_hint_for_profile(profile: str) -> dict:
    """差评运维闭环：推荐候选参考段 + 工作室/对话深链。"""
    import glob
    import urllib.parse
    name = (profile or "").strip()
    if not name:
        return {}
    enc = urllib.parse.quote(name, safe="")
    alt = ""
    pattern = _PROFILE_SEGMENT_GLOBS.get(name, "")
    if pattern:
        cur_b64 = (_profiles.get(name) or {}).get("voice_b64", "")
        for fp in sorted(glob.glob(pattern)):
            b64 = base64.b64encode(Path(fp).read_bytes()).decode()
            if b64 != cur_b64:
                alt = Path(fp).name
                break
    return {
        "studio_url": f"/ui?profile={enc}&open=tune",
        "phone_url": f"/phone?profile={enc}",
        "suggested_segment": alt,
        "actions": ["listening_ab", "apply_segment_ref", "optimize_segments"],
    }


@app.get("/api/metrics/tune_hint")
def api_metrics_tune_hint(profile: str = ""):
    """听感差评调音建议（候选参考段 + 跳转链接）。"""
    if not profile:
        raise HTTPException(400, "profile 不能为空")
    hint = _tune_hint_for_profile(profile)
    streak = 0
    if _convmetrics is not None:
        streak = _convmetrics.feedback_streak(profile, -1)
    return {"ok": True, "profile": profile, "down_streak": streak,
            "suggest_tune": streak >= 2, **hint}


@app.post("/api/metrics/feedback")
async def api_metrics_feedback(req: MetricsFeedbackRequest):
    """用户听感评分闭环：对话页/工作室提交 👍👎，dashboard 聚合好评率。"""
    if _convmetrics is None:
        return {"ok": False, "detail": "metrics 模块未加载"}
    if req.rating not in (1, -1):
        raise HTTPException(400, "rating 须为 1 或 -1")
    _convmetrics.record_feedback(
        profile=req.profile, rating=req.rating, source=req.source,
        text_preview=req.text_preview, reply_lang=req.reply_lang, msg_id=req.msg_id)
    # 单快照复用(v5)：带 baselines 取一次，回包与告警裁决共用，省掉此前的第二次全量快照
    baselines = ({n: p.get("quality_axes", {}) for n, p in _profiles.items()}
                 if _DASH_QUALITY_ALERTS_ON else None)
    snap = await asyncio.to_thread(_convmetrics.snapshot, 5, baselines)
    fb = snap.get("feedback") or {}
    out = {"ok": True, "rating": req.rating,
           "feedback_rate": fb.get("rate", 0.0), "feedback_n": fb.get("n", 0),
           "feedback_db_count": snap.get("feedback_db_count", 0)}
    if req.rating < 0 and req.profile:
        streak = _convmetrics.feedback_streak(req.profile, -1)
        hint = _tune_hint_for_profile(req.profile)
        out["down_streak"] = streak
        out["suggest_tune"] = streak >= 2
        out["tune_hint"] = hint
        if _should_trigger_auto_tune(req.profile, streak):
            prefer = hint.get("suggested_segment") or ""
            job_id = _start_auto_tune_job(req.profile, trigger="feedback_streak",
                                          prefer=prefer)
            if job_id:
                _autotune_jobs[job_id]["feedback_trigger"] = True
                out["auto_tune_triggered"] = True
                out["auto_tune_job_id"] = job_id
    if _DASH_QUALITY_ALERTS_ON:
        # 告警键(feedback_alerts/quality_alerts)不依赖 recent 长度，直接复用上面的快照
        await asyncio.to_thread(_dashboard_quality_sentinel_eval, snap)
    return out


_UIPREFS_FILE = Path(rf"{_BASE}\data\ui_prefs.json")


@app.get("/api/ui_prefs")
def api_ui_prefs_get():
    """跨端 UI 偏好（VAD/口型/语种），供手机遥控与对话页同步。
    附带链路支持的语种集合，供前端下拉收敛 + 不支持语种降级提示。"""
    prefs = {}
    try:
        if _UIPREFS_FILE.exists():
            prefs = json.loads(_UIPREFS_FILE.read_text(encoding="utf-8"))
    except Exception:
        prefs = {}
    return {"ok": True, "prefs": prefs,
            "supported_reply_langs": _supported_langs("reply"),
            "supported_input_langs": _supported_langs("input")}


class UiPrefsRequest(BaseModel):
    prefs: dict = {}


import re as _re_prefs
_LANG_CODE_RE = _re_prefs.compile(r"^[a-z]{2}(-[A-Za-z]{2})?$")
_LIP_MODES = {"off", "rt", "rt_enh", "hd"}
# 全链路真正支持的语种集合（Google 代码形式）：回复朗读以 TTS 映射为准，输入听写以 Whisper 为准。
_SUPPORTED_REPLY_LANGS = set(_LANG_MAP_TTS.keys())     # ja/zh-CN/en/ko/fr/... 见 _LANG_MAP_TTS
_SUPPORTED_INPUT_LANGS = set(_WHISPER_LANG.keys())


def _supported_langs(kind: str) -> list:
    """供前端下拉/降级提示用的有序支持语种列表。"""
    s = _SUPPORTED_REPLY_LANGS if kind == "reply" else _SUPPORTED_INPUT_LANGS
    return ["auto"] + sorted(s)


def _sanitize_ui_prefs(prefs: dict) -> tuple[dict, list]:
    """偏好落库前校验/归一，防脏数据静默锁死体验（如曾出现的 reply_lang='ja' 锁全局日语）。
    语种：'auto' 或链路支持的语言码→规整为规范码；非法码或链路不支持的有效码→归 auto 并提示降级。
    返回 (清洗后 prefs, 被改动项说明)。"""
    out = dict(prefs)
    notes = []
    for k in ("reply_lang", "input_lang"):
        if k in out:
            v = str(out[k] or "").strip()
            sup = _SUPPORTED_REPLY_LANGS if k == "reply_lang" else _SUPPORTED_INPUT_LANGS
            if v.lower() == "auto" or v == "":
                out[k] = "auto"
            elif not _LANG_CODE_RE.match(v):
                notes.append(f"{k}={v!r}→auto(非法语言码)")
                out[k] = "auto"
            else:
                canon = _google_lang(v)   # 'zh-cn'→'zh-CN','en-us'→'en'
                if canon in sup:
                    out[k] = canon
                else:
                    disp = _LANG_DISPLAY.get(canon, v)
                    notes.append(f"{k}={v!r}→auto(暂不支持{disp}朗读/听写)")
                    out[k] = "auto"
    if "lip_mode" in out and str(out["lip_mode"]) not in _LIP_MODES:
        notes.append(f"lip_mode={out['lip_mode']!r}→rt")
        out["lip_mode"] = "rt"
    if "vad_sense" in out:
        try:
            out["vad_sense"] = str(max(0, min(100, int(float(out["vad_sense"])))))
        except Exception:
            notes.append(f"vad_sense={out.get('vad_sense')!r}→55")
            out["vad_sense"] = "55"
    return out, notes


# ── P9 效果配置服务端持久化（2026-07-05 方案 P1 收口）─────────────────────────
#   开播页 12 项效果配置原先只存浏览器 localStorage：换电脑/手机遥控各存一份，互相看不见。
#   落 data/effect_cfg.json 成单一真相(前端启动先读服务端，localStorage 降级为离线缓存)。
#   刻意「跟机器走」而非方案原文的「跟角色走」：分辨率/帧率/画质档描述的是这台机器与场景的
#   能力上限，按角色切分只会让同一台机器的配置碎片化互相打架；角色差异已由 face_map/定妆承载。
_EFFECT_CFG_FILE = Path(rf"{_BASE}\data\effect_cfg.json")
_EFFECT_CFG_LOCK = threading.Lock()
# 字段白名单 + 范围（键名与前端 hub.js effect cfg v3 一致；越界值拒绝整单，不部分落库）
_EFFECT_CFG_NUM = {   # key: (min, max)
    "videoWidth": (320, 3840), "videoHeight": (240, 2160), "videoFps": (5, 60),
    "swapFps": (1, 30), "mjpegFps": (1, 30), "jpegQuality": (5, 100),
    "crossfade": (0.0, 1.5), "faceBlend": (0.0, 1.0), "faceThreshold": (0.0, 0.95),
    "faceSmooth": (0.0, 0.95),
}
_EFFECT_CFG_ENUM = {
    "faceEnhance": {"", "none", "gfpgan", "codeformer", "gpen"},
    "enginePreset": {"eco", "natural", "beauty", "hd"},
    # 输出画面比例(单一真相,跨端/重启/自愈都读它)：手机竖屏/横屏/方形。auto=不强制(沿用横屏默认)。
    "outputAspect": {"", "auto", "portrait916", "portrait34", "landscape169", "landscape169hd", "square11"},
    "awayStyle": {"blur", "image", "off"},   # 06v 离席画面
}
# 自由文本字段: key -> 最大长度。awayText 空串=撤角标(显式语义,与"没存过"不同)；
# awayImage 只收 bg_images 目录内的文件名(拒路径分隔符/..，防目录穿越)，空=不用图。
_EFFECT_CFG_STR = {"awayText": 40, "awayImage": 120}


def _effect_cfg_str_clean(k: str, v) -> "str|None":
    """字符串字段校验：超长/含控制符/awayImage 带路径成分 → None(整单拒绝)。"""
    s = str(v).strip()
    if len(s) > _EFFECT_CFG_STR[k] or any(ord(c) < 32 for c in s):
        return None
    if k == "awayImage" and s and (("/" in s) or ("\\" in s) or (".." in s) or (":" in s)):
        return None
    return s


def _effect_cfg_load() -> dict:
    try:
        d = json.loads(_EFFECT_CFG_FILE.read_text(encoding="utf-8"))
        return d if isinstance(d, dict) else {}
    except Exception:
        return {}


@app.get("/api/effect_cfg")
def api_effect_cfg_get():
    """读服务端效果配置（空 dict = 从未保存过，前端回退本地缓存/默认档）。"""
    return {"ok": True, "cfg": _effect_cfg_load()}


@app.post("/api/effect_cfg")
def api_effect_cfg_set(body: dict = Body(default={})):
    """保存效果配置（整单校验：未知键丢弃、越界值拒绝）。body={"reset":true} = 删除恢复默认。"""
    if body.get("reset"):
        with _EFFECT_CFG_LOCK:
            try:
                _EFFECT_CFG_FILE.unlink(missing_ok=True)
            except Exception as e:
                return {"ok": False, "detail": str(e)}
        return {"ok": True, "cfg": {}}
    clean = {}
    for k, (lo, hi) in _EFFECT_CFG_NUM.items():
        if k in body:
            try:
                v = float(body[k])
            except Exception:
                return {"ok": False, "detail": f"{k} 不是数字"}
            if not lo <= v <= hi:
                return {"ok": False, "detail": f"{k}={body[k]} 超出 {lo}~{hi}"}
            clean[k] = int(v) if float(v).is_integer() and k != "crossfade" else round(v, 3)
    for k, allowed in _EFFECT_CFG_ENUM.items():
        if k in body:
            v = str(body[k]).strip().lower()
            if v not in allowed:
                return {"ok": False, "detail": f"{k}={body[k]} 非法"}
            clean[k] = v
    for k in _EFFECT_CFG_STR:
        if k in body:
            v = _effect_cfg_str_clean(k, body[k])
            if v is None:
                return {"ok": False, "detail": f"{k} 非法(超长/控制符/路径成分)"}
            clean[k] = v
    if not clean:
        return {"ok": False, "detail": "没有可保存的字段"}
    with _EFFECT_CFG_LOCK:
        cur = _effect_cfg_load()
        cur.update(clean)
        cur["_ts"] = int(time.time())
        try:
            _EFFECT_CFG_FILE.parent.mkdir(parents=True, exist_ok=True)
            _EFFECT_CFG_FILE.write_text(json.dumps(cur, ensure_ascii=False, indent=2), encoding="utf-8")
        except Exception as e:
            return {"ok": False, "detail": str(e)}
    return {"ok": True, "cfg": cur}


@app.post("/api/ui_prefs")
def api_ui_prefs_set(req: UiPrefsRequest):
    """保存 UI 偏好（合并更新，落库前做健壮性校验）。"""
    cur = {}
    try:
        if _UIPREFS_FILE.exists():
            cur = json.loads(_UIPREFS_FILE.read_text(encoding="utf-8"))
    except Exception:
        pass
    notes = []
    if isinstance(req.prefs, dict):
        clean, notes = _sanitize_ui_prefs(req.prefs)
        if notes:
            _logger.warning(f"[UiPrefs] 偏好校验归一: {', '.join(notes)}")
        cur.update(clean)
    try:
        _UIPREFS_FILE.parent.mkdir(parents=True, exist_ok=True)
        _UIPREFS_FILE.write_text(json.dumps(cur, ensure_ascii=False, indent=2), encoding="utf-8")
    except Exception as e:
        return {"ok": False, "detail": str(e)}
    # adjusted：前端据此弹"已降级为自动"提示，避免脏/不支持语种静默锁体验
    return {"ok": True, "prefs": cur, "adjusted": notes}


@app.get("/api/metrics/weekly_report")
def api_metrics_weekly_report(download: int = 0):
    """听感运维周报：好评率、差评聚类、cosine、角色基线（?download=1 触发下载头）。⑭：并入分享漏斗 + 近7天趋势。"""
    if _convmetrics is None:
        return {"ok": False, "detail": "metrics 模块未加载"}
    baselines = {n: p.get("quality_axes", {}) for n, p in _profiles.items()}
    report = _convmetrics.weekly_report(profile_baselines=baselines)
    # ⑭：注入分享漏斗摘要
    with _share_lock:
        _st = {k: _share_stats.get(k, 0) for k in _SHARE_ACTIONS}
        _st["by_profile"] = {k: dict(v) for k, v in _share_stats.get("by_profile", {}).items()}
        daily_snap = dict(_share_stats.get("daily", {}))
    import datetime as _dtt
    today = _dtt.date.today()
    week7 = [((today - _dtt.timedelta(days=i)).strftime("%Y-%m-%d")) for i in range(6, -1, -1)]
    trend7 = [{"date": d, **{k: daily_snap.get(d, {}).get(k, 0) for k in ("open", "land", "cta")}}
              for d in week7]
    land = _st.get("land") or 1
    cta = _st.get("cta", 0)
    report["share_funnel"] = {
        "open":       _st.get("open", 0),
        "land":       _st.get("land", 0),
        "ab_played":  (_st.get("ab_ref", 0) + _st.get("ab_clone", 0)),
        "cta":        cta,
        "cta_from_ab": _st.get("cta_from_ab", 0),
        "landing_conv": round(cta / land, 3),
        "guess_right": _st.get("ab_guess_right", 0),
        "guess_wrong": _st.get("ab_guess_wrong", 0),
        "gallery_play": _st.get("gallery_play", 0),
    }
    report["share_trend_7d"] = trend7
    # 真出声质量并入周报：每角色基线/趋势/回归/到顶，形成"声纹回归"留痕
    try:
        vq = _vq_aggregate(history=60)
        report["voice_quality"] = {
            "runs": vq["runs"], "ceil_target": vq["ceil_target"],
            "regressed": vq["regressed"], "weak": vq["weak"],
            "profiles": [{"name": p["name"], "last_cos": (p.get("last") or {}).get("cos"),
                          "baseline": p.get("baseline"), "std": p.get("std"),
                          "near_ceiling": p.get("near_ceiling", False),
                          "samples": len(p.get("cos_series", []))}
                         for p in vq["profiles"]],
        }
    except Exception as e:
        report["voice_quality"] = {"ok": False, "detail": str(e)}
    if download:
        body = json.dumps(report, ensure_ascii=False, indent=2)
        fname = f"weekly_report_{_dt.datetime.now().strftime('%Y%m%d_%H%M')}.json"
        return Response(
            content=body,
            media_type="application/json",
            headers={"Content-Disposition": f'attachment; filename="{fname}"'},
        )
    return report


@app.get("/api/share/export")
def api_share_export(fmt: str = "csv", days: int = 90):
    """⑭：分享漏斗全量导出（?fmt=csv 或 json）。
    P15-3 追加 ?fmt=long：长表 date,profile,action,count（profile 空=全站合计），
    近 N 天日桶 + 日×角色扫码归因平铺 + 出窗月桶（date=YYYY-MM）附表尾——
    Excel 透视即得任意切面，运营对账/汇报的机器可读出口。零值行不导出。"""
    with _share_lock:
        totals = {k: _share_stats.get(k, 0) for k in _SHARE_ACTIONS}
        by_profile = {k: dict(v) for k, v in _share_stats.get("by_profile", {}).items()}
        daily = json.loads(json.dumps(_share_stats.get("daily", {})))
        monthly = dict(_share_stats.get("monthly", {}))
    if fmt == "long":
        days = max(1, min(int(days or 90), 90))
        _q = lambda s: ('"%s"' % str(s).replace('"', '""')
                        if any(c in str(s) for c in ',"\n') else str(s))
        today = _dt.date.today()
        lines = ["date,profile,action,count"]
        for i in range(days - 1, -1, -1):
            d = (today - _dt.timedelta(days=i)).strftime("%Y-%m-%d")
            rec = daily.get(d) or {}
            for a, v in rec.items():
                if a != "by_profile" and isinstance(v, int) and v:
                    lines.append(f"{d},,{a},{v}")
            for nm, acts in (rec.get("by_profile") or {}).items():
                for a, v in (acts or {}).items():
                    if v:
                        lines.append(f"{d},{_q(nm)},{a},{v}")
        for mo in sorted(monthly):
            for a, v in (monthly[mo] or {}).items():
                if v:
                    lines.append(f"{mo},,{a},{v}")
        body = "\n".join(lines) + "\n"
        return Response(content=body.encode("utf-8-sig"), media_type="text/csv",
                        headers={"Content-Disposition": 'attachment; filename="share_trend_long.csv"'})
    if fmt == "json":
        body = json.dumps({"totals": totals, "by_profile": by_profile, "daily": daily},
                          ensure_ascii=False, indent=2)
        fname = f"share_stats_{_dt.datetime.now().strftime('%Y%m%d_%H%M')}.json"
        return Response(content=body, media_type="application/json",
                        headers={"Content-Disposition": f'attachment; filename="{fname}"'})
    # CSV：汇总行 + 按角色行 + 按日行
    import io as _io
    buf = _io.StringIO()
    buf.write("# 汇总\n")
    buf.write(",".join(["指标"] + list(_SHARE_ACTIONS)) + "\n")
    buf.write(",".join(["总计"] + [str(totals.get(k, 0)) for k in _SHARE_ACTIONS]) + "\n\n")
    buf.write("# 按角色\n")
    buf.write(",".join(["角色"] + list(_SHARE_ACTIONS)) + "\n")
    for nm, s in sorted(by_profile.items()):
        buf.write(",".join([nm] + [str(s.get(k, 0)) for k in _SHARE_ACTIONS]) + "\n")
    buf.write("\n# 按日\n")
    buf.write(",".join(["日期"] + ["open", "land", "cta", "scan"]) + "\n")   # scan 与趋势图同口径（P12）
    for d in sorted(daily):
        r = daily[d]
        buf.write(",".join([d, str(r.get("open", 0)), str(r.get("land", 0)), str(r.get("cta", 0)),
                            str(r.get("land_recap", 0) + r.get("land_poster", 0))]) + "\n")
    fname = f"share_stats_{_dt.datetime.now().strftime('%Y%m%d_%H%M')}.csv"
    return Response(content=buf.getvalue().encode("utf-8-sig"), media_type="text/csv",
                    headers={"Content-Disposition": f'attachment; filename="{fname}"'})


@app.post("/api/metrics/reset")
def api_metrics_reset(scope: str = "window"):
    """清空统计（看板 v2 拆语义）：scope=window 软清视图（默认，账本无损）/
    all 硬清指标（好评账本保留）/ all_with_feedback 连听感评分一起删。
    旧调用不带参 → 落到最安全的 window，杜绝「清个页面把 60 条好评删了」的历史行为。"""
    if _convmetrics is None:
        return {"ok": False, "detail": "metrics 模块未加载"}
    return _convmetrics.reset(scope=scope)


