@app.get("/api/dashboard/compare")
async def api_dashboard_compare(a: str, b: str, days: int = 14):
    """角色 A/B 对比（看板 v4）：两角色并排展示好评率/相似度/自然度/漏斗/日趋势。
    选角色上直播时用数据说话，不用凭感觉。"""
    for nm in (a.strip(), b.strip()):
        _check_profile_name(nm)
        if nm not in _profiles:
            raise HTTPException(404, f"角色不存在: {nm}")
    if a.strip() == b.strip():
        raise HTTPException(400, "请选择两个不同角色")
    if _convmetrics is None:
        return {"ok": False, "detail": "metrics 模块未加载"}

    async def _pack(name: str) -> dict:
        p = _profiles[name]
        series = await asyncio.to_thread(_convmetrics.profile_series, name, days)
        with _share_lock:
            share = dict((_share_stats.get("by_profile", {}) or {}).get(name, {}) or {})
        return {
            "profile": name,
            "active": name == _active_profile,
            "quality_axes": p.get("quality_axes") or {},
            "series": series,
            "share": share,
            "golden": {"exists": _golden_path(name).exists(), **_golden_meta(name)},
        }

    pa, pb = await asyncio.gather(_pack(a.strip()), _pack(b.strip()))
    return {"ok": True, "a": pa, "b": pb, "days": days}


@app.get("/api/dashboard/reports")
def api_dashboard_reports_list():
    """历史战报列表（logs/reports/report_YYYYMMDD.html），按日期倒序。"""
    _REPORT_ARCHIVE_DIR.mkdir(parents=True, exist_ok=True)
    items = []
    for f in sorted(_REPORT_ARCHIVE_DIR.glob("report_*.html"), reverse=True):
        m = re.fullmatch(r"report_(\d{8})\.html", f.name)
        if not m:
            continue
        d = m.group(1)
        try:
            st = f.stat()
            items.append({
                "date": f"{d[:4]}-{d[4:6]}-{d[6:8]}",
                "day_key": d,
                "size_kb": st.st_size // 1024,
                "mtime": st.st_mtime,
                "url": f"/api/dashboard/reports/{d}",
            })
        except Exception:
            pass
    return {"ok": True, "reports": items, "count": len(items)}


@app.get("/api/dashboard/reports/{day_key}")
def api_dashboard_reports_get(day_key: str):
    """读取已归档战报 HTML（day_key=YYYYMMDD）。"""
    if not re.fullmatch(r"\d{8}", day_key):
        raise HTTPException(400, "day_key 须为 YYYYMMDD")
    path = _REPORT_ARCHIVE_DIR / f"report_{day_key}.html"
    if not path.is_file():
        raise HTTPException(404, "该日战报尚未归档")
    return Response(content=path.read_bytes(), media_type="text/html")


@app.get("/api/dashboard/stream")
async def api_dashboard_stream(recent: int = 30, trend_days: int = 14):
    """看板推流（SSE）：连接即推全量快照，之后仅在数据实际变化时再推（心跳保活）。
    与 /api/dashboard/snapshot 共享 TTL 缓存与并发聚合，前端断流自动回退轮询。"""
    import hashlib as _hl

    async def _gen():
        last_sig = ""
        while True:
            try:
                snap = await api_dashboard_snapshot(recent=recent, trend_days=trend_days)
                body = dict(snap)
                body.pop("ts", None)
                sig = _hl.md5(json.dumps(body, sort_keys=True, default=str)
                              .encode("utf-8", "replace")).hexdigest()
                if sig != last_sig:
                    last_sig = sig
                    yield f"data: {json.dumps(snap, ensure_ascii=False, default=str)}\n\n"
                else:
                    yield ": hb\n\n"      # SSE 注释帧：保活但不触发前端渲染
            except asyncio.CancelledError:
                raise
            except Exception as e:
                yield f"event: err\ndata: {str(e)[:100]}\n\n"
            await asyncio.sleep(_DASH_SNAP_TTL + 0.5)
    return StreamingResponse(_gen(), media_type="text/event-stream",
                             headers={"Cache-Control": "no-cache",
                                      "X-Accel-Buffering": "no"})


@app.get("/api/dashboard/report")
def api_dashboard_report(fmt: str = "html"):
    """客户版战报（一页 HTML，数据服务端内嵌）：Ctrl+S/打印即成品，离线可看。
    与 JSON 周报互补——这页是给客户/老板的人话版，黑话只留在悬停提示。
    ?fmt=png：无头浏览器整页长图（微信直发，不用教客户 Ctrl+S），子进程渲染不进 Hub 事件环。"""
    if fmt == "png":
        shot = Path(rf"{_BASE}\tools\report_shot.py")
        if not shot.is_file():
            return JSONResponse({"ok": False, "detail": "tools/report_shot.py 缺失"},
                                status_code=503)
        out = Path(rf"{_BASE}\logs\report_shot.png")
        try:
            r = _subprocess.run(
                [sys.executable, "-X", "utf8", str(shot), "--out", str(out)],
                capture_output=True, text=True, encoding="utf-8", errors="replace",
                timeout=90, cwd=str(_BASE),
                creationflags=getattr(_subprocess, "CREATE_NO_WINDOW", 0))
            if r.returncode != 0 or not out.is_file():
                tail = (r.stdout or r.stderr or "").strip().splitlines()
                return JSONResponse({"ok": False,
                                     "detail": (tail[-1] if tail else "截图子进程失败")[:200]},
                                    status_code=502)
            fname = f"report_{_dt.datetime.now().strftime('%Y%m%d_%H%M')}.png"
            return Response(content=out.read_bytes(), media_type="image/png",
                            headers={"Content-Disposition": f'attachment; filename="{fname}"'})
        except Exception as e:
            return JSONResponse({"ok": False, "detail": str(e)[:200]}, status_code=502)
    if _convmetrics is None:
        return Response(content="metrics 模块未加载", status_code=503)
    baselines = {n: p.get("quality_axes", {}) for n, p in _profiles.items()}
    snap = _convmetrics.snapshot(recent=100, profile_baselines=baselines)
    daily = _convmetrics.daily_trend(days=14)
    with _share_lock:
        share = {k: _share_stats.get(k, 0) for k in _SHARE_ACTIONS}
    payload = {
        "generated_at": _dt.datetime.now().strftime("%Y-%m-%d %H:%M"),
        "active_profile": _active_profile or "",
        "profiles": {n: (p.get("quality_axes") or {}) for n, p in _profiles.items()},
        "metrics": {
            "total_turns_alltime": snap.get("total_turns_alltime", 0),
            "perceived_ttfa_ms": snap.get("perceived_ttfa_ms") or {},
            "ttfa_ms": snap.get("ttfa_ms") or {},
            "feedback": snap.get("feedback") or {},
            "clone_scores": snap.get("clone_scores") or {},
        },
        "share": share,
        "daily": daily.get("trend") or [],
    }
    tpl_path = Path(rf"{_BASE}\static\report.html")
    if not tpl_path.exists():
        return Response(content="report.html not found", status_code=404)
    # "<"→\u003c：数据含用户文本（评价预览），防 </script> 提前闭合注入
    data_js = json.dumps(payload, ensure_ascii=False).replace("<", "\\u003c")
    html = tpl_path.read_text(encoding="utf-8").replace(
        "/*__REPORT_DATA__*/null", data_js)
    return Response(content=html, media_type="text/html")


# ── 看板 v3：战报自动归档（可回溯的运营周志） ──────────────────────
_REPORT_ARCHIVE_DIR = Path(rf"{_BASE}\logs\reports")
_REPORT_ARCHIVE_HOUR = int(os.environ.get("HUB_REPORT_ARCHIVE_HOUR", "5"))
_REPORT_ARCHIVE_KEEP = int(os.environ.get("HUB_REPORT_ARCHIVE_KEEP", "60"))


def _report_archive_run() -> dict:
    """把当日战报 HTML 落到 logs/reports/report_YYYYMMDD.html。
    幂等（当日文件已存在即跳过，跨重启天然去重）+ 按保留数清老档（默认 60 天）。"""
    _REPORT_ARCHIVE_DIR.mkdir(parents=True, exist_ok=True)
    day = _dt.datetime.now().strftime("%Y%m%d")
    path = _REPORT_ARCHIVE_DIR / f"report_{day}.html"
    if path.exists():
        return {"ok": True, "skipped": "already_archived", "path": str(path)}
    resp = api_dashboard_report()
    body = getattr(resp, "body", b"") or b""
    if len(body) < 1000:                  # 渲染异常（模板缺失/metrics 未载）不落残档
        return {"ok": False, "detail": "战报渲染异常，未归档"}
    path.write_bytes(body)
    olds = sorted(_REPORT_ARCHIVE_DIR.glob("report_*.html"))
    for f in (olds[:-_REPORT_ARCHIVE_KEEP] if len(olds) > _REPORT_ARCHIVE_KEEP else []):
        f.unlink(missing_ok=True)
    return {"ok": True, "path": str(path), "archived": True}


@app.post("/api/dashboard/report/archive")
def api_dashboard_report_archive():
    """手动触发战报归档（与夜间环同一路径，幂等，供即时留档/E2E 验证）。"""
    return _report_archive_run()


async def _bg_report_archive():
    """看板 v3：夜间战报归档环——每日 HUB_REPORT_ARCHIVE_HOUR(默认5)点后补发式触发。
    Hub 当天任意时刻在线都会补齐当日档（文件存在即幂等跳过），HUB_REPORT_ARCHIVE=0 停用。"""
    if os.environ.get("HUB_REPORT_ARCHIVE", "1") != "1":
        return
    await asyncio.sleep(120.0)            # 避开启动拥塞
    while True:
        try:
            if time.localtime().tm_hour >= _REPORT_ARCHIVE_HOUR:
                r = await asyncio.to_thread(_report_archive_run)
                if r.get("archived"):
                    _logger.info(f"[ReportArchive] 战报已归档 {r.get('path')}")
        except Exception as exc:
            _logger.warning(f"[ReportArchive] 异常: {exc}")
        await asyncio.sleep(1800)


# ── 看板 v6：战报日报推送（webhook 卡片 + 企微长图）────────────────────
_REPORT_PUSH_HOUR = int(os.environ.get("HUB_REPORT_PUSH_HOUR", "9"))
_REPORT_PUSH_STATE = Path(rf"{_BASE}\logs\report_push_state.json")


def _report_push_digest() -> tuple[str, str, list]:
    """昨日运营摘要：老板要的是方向感（昨天多少轮、比前天如何、好评率），不是全量报表。
    返回 (标题, markdown 正文, 直达链接)。"""
    trend = (_convmetrics.daily_trend(days=3) or {}).get("trend") or []
    y = trend[-2] if len(trend) >= 2 else {}
    p = trend[-3] if len(trend) >= 3 else {}
    snap = _convmetrics.snapshot(recent=5)
    base = _dash_public_base()
    lines = [f"### 📊 数字人日报 · {y.get('date', '')}"]
    dt_txt = ""
    if p.get("turns") is not None and (y.get("turns", 0) + p.get("turns", 0)) > 0:
        d = (y.get("turns", 0)) - (p.get("turns", 0))
        dt_txt = f"（较前日 {'+' if d >= 0 else ''}{d}）"
    lines.append(f"- **对话**: {y.get('turns', 0)} 轮{dt_txt}")
    n_fb = (y.get("fb_up", 0) or 0) + (y.get("fb_down", 0) or 0)
    if n_fb:
        lines.append(f"- **听感**: 👍{y.get('fb_up', 0)} 👎{y.get('fb_down', 0)}"
                     f"（好评率 {(y.get('fb_rate') or 0) * 100:.0f}%）")
    if y.get("perceived_avg"):
        lines.append(f"- **开口速度**: 均值 {y['perceived_avg'] / 1000:.2f}s")
    lines.append(f"- **累计对话**: {snap.get('total_turns_alltime', 0)} 轮")
    try:            # P13: 昨日音色动静（全零不占版面）
        vd = (_vp_stats().get("days") or {}).get(
            time.strftime("%Y%m%d", time.localtime(time.time() - 86400))) or {}
        vs = {k: sum(int(c.get(k, 0)) for c in vd.values())
              for k in ("pv", "au", "imp", "use")}
        if vs["pv"] + vs["au"] + vs["imp"] + vs["use"]:
            lines.append(f"- **音色**: 试听 {vs['pv'] + vs['au']} 次 · "
                         f"导入 {vs['imp']} · 开播使用 {vs['use']}")
    except Exception:
        pass
    links = [("打开看板", f"{base}/dashboard"),
             ("完整战报", f"{base}/api/dashboard/report")]
    return f"数字人日报 · {y.get('date', '')}", "\n".join(lines), links


def _report_push_png_wecom() -> int:
    """尽力而为：战报长图直发企微群（webhook image 消息，≤2MB）。
    钉钉自定义机器人不支持直传图片——钉钉群只有摘要卡片+链接。失败/超限静默跳过不影响日报。"""
    import alerts as _al
    wecom = [u for u in _al._webhooks()
             if "weixin" in u.lower() or "qyapi" in u.lower()]
    if not wecom or os.environ.get("HUB_REPORT_PUSH_PNG", "1") != "1":
        return 0
    shot = Path(rf"{_BASE}\tools\report_shot.py")
    out = Path(rf"{_BASE}\logs\report_push.png")
    try:
        r = _subprocess.run(
            [sys.executable, "-X", "utf8", str(shot), "--out", str(out)],
            capture_output=True, text=True, encoding="utf-8", errors="replace",
            timeout=90, cwd=str(_BASE),
            creationflags=getattr(_subprocess, "CREATE_NO_WINDOW", 0))
        if r.returncode != 0 or not out.is_file():
            return 0
        raw = out.read_bytes()
        if len(raw) > 1_400_000:          # base64 膨胀 4/3，留足余量贴 2MB 上限
            return 0
        import base64
        import hashlib
        payload = {"msgtype": "image",
                   "image": {"base64": base64.b64encode(raw).decode(),
                             "md5": hashlib.md5(raw).hexdigest()}}
        return sum(1 for u in wecom if _al._post_payload(u, payload))
    except Exception:
        return 0


def _report_push_run(force: bool = False) -> dict:
    """日报推送执行器。自动路径三道闸：今天已发过(跨重启去重)/无 webhook/昨日零数据。
    force=True（手动按钮）：跳过三道闸真发一次，且不占当日自动额度。"""
    try:
        import alerts as _al
    except Exception as e:
        return {"ok": False, "detail": f"alerts 不可用: {e}"}
    if _convmetrics is None:
        return {"ok": False, "detail": "metrics 模块未加载"}
    day = time.strftime("%Y%m%d")
    try:
        state = json.loads(_REPORT_PUSH_STATE.read_text(encoding="utf-8"))
    except Exception:
        state = {}
    title, md, links = _report_push_digest()
    if not force:
        if state.get("sent_day") == day:
            return {"ok": True, "sent": 0, "skipped": "already_sent"}
        if _al.channels().get("webhook_count", 0) <= 0:
            return {"ok": True, "sent": 0, "skipped": "no_webhook"}
        trend = (_convmetrics.daily_trend(days=2) or {}).get("trend") or []
        yd = trend[-2] if len(trend) >= 2 else {}
        if not (yd.get("turns") or yd.get("fb_up") or yd.get("fb_down")):
            return {"ok": True, "sent": 0, "skipped": "empty_yesterday"}
    sent = _al.notify_event(title, md_body=md, links=links,
                            level="info", source="看板日报")
    png_sent = _report_push_png_wecom() if sent else 0
    if not force:
        try:
            _REPORT_PUSH_STATE.parent.mkdir(parents=True, exist_ok=True)
            _REPORT_PUSH_STATE.write_text(
                json.dumps({"sent_day": day, "ts": time.time()}), encoding="utf-8")
        except Exception:
            pass
    return {"ok": True, "sent": sent, "png_sent": png_sent, "preview": md}


@app.post("/api/dashboard/report/push")
async def api_dashboard_report_push(force: int = 1):
    """手动推送日报到群（默认 force=1 真发一次不占自动额度；无 webhook 时返回预览便于自查）。"""
    r = await asyncio.to_thread(_report_push_run, bool(force))
    try:
        import alerts as _al
        r["channels"] = _al.channels()
    except Exception:
        pass
    return r


async def _bg_report_push():
    """看板 v6：日报推送环——每日 HUB_REPORT_PUSH_HOUR(默认9)点后补发式触发；
    HUB_REPORT_PUSH=0 或小时设为负数停用。无 webhook/昨日零数据自动跳过，不空喊。"""
    if os.environ.get("HUB_REPORT_PUSH", "1") != "1" or _REPORT_PUSH_HOUR < 0:
        return
    await asyncio.sleep(150.0)
    while True:
        try:
            if time.localtime().tm_hour >= _REPORT_PUSH_HOUR:
                r = await asyncio.to_thread(_report_push_run)
                if r.get("sent"):
                    _logger.info(f"[ReportPush] 日报已推送 {r['sent']} 通道"
                                 f"(长图 {r.get('png_sent', 0)})")
        except Exception as exc:
            _logger.warning(f"[ReportPush] 异常: {exc}")
        await asyncio.sleep(1800)


