class LLMConnectRequest(BaseModel):
    base_url:    str                  # 如 http://127.0.0.1:11434 (Ollama) / :1234 (LM Studio) / https://api.deepseek.com
    model:       str
    api_key:     str  = ""
    name:        str  = ""            # 注册名（空=用 model 名）
    kind:        str  = "local"       # local(本机) / lan(局域网) / cloud(云端)
    label:       str  = ""            # UI 友好显示名（空=model）
    keep_alive:  str  = ""            # Ollama 常驻时长（如 "30m"/-1）；云端忽略
    set_default: bool = True
    persist:     bool = True          # 是否写入 llm_backends.json（重启自动恢复）

def _conv_persist_backend(req: "LLMConnectRequest"):
    """把一个后端写入/更新到 llm_backends.json（按 name 去重）。"""
    cfg = _conv_read_llm_backends()
    name = req.name or req.model
    entry = {"name": name, "kind": req.kind, "label": req.label or req.model,
             "base_url": req.base_url, "model": req.model,
             "api_key": req.api_key, "keep_alive": req.keep_alive}
    cfg["backends"] = [e for e in cfg.get("backends", []) if e.get("name") != name]
    cfg["backends"].append(entry)
    if req.set_default:
        cfg["default"] = name
    _conv_write_llm_backends(cfg)

@app.post("/api/converse/llm/connect")
def api_converse_llm_connect(req: LLMConnectRequest):
    """接入/更新一个 OpenAI 兼容 LLM 后端（本地 Ollama/vLLM、局域网、云端 DeepSeek 等）。
    会探测可达性但不强制——不可达也会注册（便于先配置后启动/先填密钥）。persist=True 则落盘。"""
    if _conv is None:
        raise HTTPException(503, "conversation 模块未加载")
    backend = _conv.OpenAICompatLLM(
        req.base_url, req.model, req.api_key,
        keep_alive=req.keep_alive, kind=req.kind, label=req.label)
    backend.name = req.name or req.model
    reachable = False
    try:
        h = {"Authorization": f"Bearer {req.api_key}"} if req.api_key else {}
        rr = requests.get(f"{req.base_url.rstrip('/')}/v1/models", headers=h, timeout=5)
        reachable = rr.status_code == 200
    except Exception:
        reachable = False
    _conv.registry.register_llm(backend, default=req.set_default)
    if req.persist:
        _conv_persist_backend(req)
    return {"ok": True, "name": backend.name, "kind": req.kind, "reachable": reachable,
            "default_llm": _conv.registry.default_llm, "model": req.model}


class LLMSelectRequest(BaseModel):
    name: str

@app.post("/api/converse/llm/default")
def api_converse_llm_default(req: LLMSelectRequest):
    """切换当前活跃（默认）对话引擎；name 必须已注册。落盘默认值，重启保持。"""
    if _conv is None:
        raise HTTPException(503, "conversation 模块未加载")
    if not _conv.registry.set_default_llm(req.name):
        raise HTTPException(404, f"未注册的 LLM: {req.name}")
    cfg = _conv_read_llm_backends(); cfg["default"] = req.name; _conv_write_llm_backends(cfg)
    # 切到本地后端时顺手预热（云端无需）
    be = _conv.registry.get_llm(req.name)
    if be is not None and getattr(be, "kind", "local") == "local" and getattr(be, "base_url", ""):
        try:
            if requests.get(f"{be.base_url}/v1/models", timeout=3).status_code == 200:
                _conv_warmup_llm(be.base_url, be.model, getattr(be, "api_key", ""),
                                 getattr(be, "keep_alive", "30m") or "30m")
        except Exception:
            pass
    return {"ok": True, "default_llm": _conv.registry.default_llm}

class EmbedderRequest(BaseModel):
    model: str = ""                                  # 嵌入模型（如 bge-m3）；空=撤回，退回纯 BM25
    base_url: str = "http://127.0.0.1:11434"
    api_key: str = ""

@app.post("/api/converse/embedder")
def api_converse_embedder(req: EmbedderRequest):
    """Phase9-5: 运行时启用/切换/撤回语义嵌入后端（无需重启）。
    启用即切 BM25+语义 混合检索并回填存量知识库；探测不可达则报错且保持原状（不破坏 BM25）。"""
    if _conv is None:
        raise HTTPException(503, "conversation 模块未加载")
    if not req.model.strip():                        # 撤回 → 退回 BM25
        _conv.registry.set_embedder(None)
        return {"ok": True, "enabled": False, "kb": _conv.registry.list().get("kb", {})}
    try:
        emb = _conv.OpenAICompatEmbedding(req.base_url, req.model.strip(), req.api_key)
        probe = emb.embed(["语义检索连通性探针"])
        if not probe or not probe[0]:
            raise RuntimeError("空向量返回")
    except Exception as e:
        raise HTTPException(502, f"嵌入后端不可用(保持 BM25): {e}")
    _conv.registry.set_embedder(emb)                 # 含存量回填
    try:
        _conv.long_term.set_embedder(emb)            # 与启动时一致：长期记忆同享语义召回/去重/冲突消解
    except Exception:
        pass
    kb = _conv.registry.list().get("kb", {})
    return {"ok": True, "enabled": True, "dim": len(probe[0]),
            "model": req.model.strip(), "base_url": req.base_url, "kb": kb}

@app.post("/api/converse/llm/remove")
def api_converse_llm_remove(req: LLMSelectRequest):
    """移除一个对话后端（同步从 llm_backends.json 删除；不能删 mock_llm）。"""
    if _conv is None:
        raise HTTPException(503, "conversation 模块未加载")
    if not _conv.registry.remove_llm(req.name):
        raise HTTPException(400, f"无法移除: {req.name}")
    cfg = _conv_read_llm_backends()
    cfg["backends"] = [e for e in cfg.get("backends", []) if e.get("name") != req.name]
    if cfg.get("default") == req.name:
        cfg["default"] = _conv.registry.default_llm
    _conv_write_llm_backends(cfg)
    return {"ok": True, "default_llm": _conv.registry.default_llm}

@app.get("/api/converse/llm/probe")
def api_converse_llm_probe():
    """探测本机常见 OpenAI 兼容 LLM 服务，便于一键发现可接入端点。"""
    candidates = [
        ("ollama",          "http://127.0.0.1:11434"),
        ("vllm",            "http://127.0.0.1:8000"),
        ("lmstudio",        "http://127.0.0.1:1234"),
        ("llamacpp",        "http://127.0.0.1:8080"),
        ("localai",         "http://127.0.0.1:8085"),
    ]
    out = []
    for name, url in candidates:
        reachable = False
        try:
            reachable = requests.get(f"{url}/v1/models", timeout=2).status_code == 200
        except Exception:
            reachable = False
        out.append({"name": name, "base_url": url, "reachable": reachable})
    return {"candidates": out,
            "hint": "POST /api/converse/llm/connect {base_url, model} 即可接入"}


