class KBAddRequest(BaseModel):
    docs:    List[str] = []           # 知识文档（每条一段文本）
    replace: bool      = False        # True=先清空再添加
    profile: str      = ""          # 可选：写入 meta.profile 供按角色过滤


class KBImportTextRequest(BaseModel):
    text:            str
    profile:         str = ""
    replace_profile: bool = True      # True=仅替换该 profile 的文档

_PROFILE_KB_FILES = {
    "阿习讲话": Path(rf"{_BASE}\声音包\阿习讲话.txt"),
}


def _chunk_kb_text(text: str, min_len: int = 12, target: int = 72) -> list:
    """切块：优先句读符；无标点则按空格聚合为短段（适配 STT 演讲稿）。"""
    import re
    t = re.sub(r"\s+", " ", text.strip())
    if not t:
        return []
    parts = re.split(r"[。！？；\n]+", t)
    chunks = [p.strip() for p in parts if len(p.strip()) >= min_len]
    if len(chunks) > 1:
        return chunks
    words = t.split(" ")
    buf, out = "", []
    for w in words:
        buf = f"{buf} {w}".strip() if buf else w
        if len(buf) >= target:
            out.append(buf)
            buf = ""
    if len(buf) >= min_len:
        out.append(buf)
    if not out and len(t) >= min_len:
        out = [t]
    return out


@app.post("/api/converse/kb")
def api_converse_kb_add(req: KBAddRequest):
    """向对话知识库添加文档（9-4 RAG，词法 BM25 检索，零下载）。"""
    if _conv is None:
        raise HTTPException(503, "conversation 模块未加载")
    if req.replace:
        _conv.registry.kb.clear()
    ids = []
    meta = {"profile": req.profile} if req.profile else {}
    for doc in req.docs:
        if doc and doc.strip():
            ids.append(_conv.registry.kb.add(doc.strip(), meta=meta or None))
    return {"ok": True, "added": len(ids), "ids": ids,
            "total": _conv.registry.kb.count()}


@app.post("/api/converse/kb/import_text")
def api_converse_kb_import_text(req: KBImportTextRequest):
    """上传 .txt 全文：智能切块后按角色导入知识库。"""
    if _conv is None:
        raise HTTPException(503, "conversation 模块未加载")
    text = (req.text or "").strip()
    if not text:
        raise HTTPException(400, "文本为空")
    chunks = _chunk_kb_text(text)
    if not chunks:
        raise HTTPException(400, "无有效文本块")
    prof = (req.profile or "").strip()
    if req.replace_profile and prof:
        with _conv.registry.kb._lock:
            rm_ids = [d.id for d in _conv.registry.kb.docs if d.meta.get("profile") == prof]
            _conv.registry.kb.docs = [d for d in _conv.registry.kb.docs
                                        if d.meta.get("profile") != prof]
            if _conv.registry.kb._conn is not None:
                for did in rm_ids:
                    _conv.registry.kb._conn.execute("DELETE FROM kb_docs WHERE id=?", (did,))
                _conv.registry.kb._conn.commit()
    meta = {"profile": prof, "source": "upload"} if prof else {"source": "upload"}
    ids = []
    for ch in chunks:
        ids.append(_conv.registry.kb.add(ch, meta=meta))
    return {"ok": True, "added": len(ids), "chunks": len(chunks),
            "total": _conv.registry.kb.count(),
            "sample": chunks[0][:80] if chunks else ""}


@app.post("/api/converse/kb/import_profile/{name}")
def api_converse_kb_import_profile(name: str, replace: bool = True):
    """从角色关联文本文件切块导入知识库（如 声音包/阿习讲话.txt）。"""
    if _conv is None:
        raise HTTPException(503, "conversation 模块未加载")
    _check_profile_name(name)
    src = _PROFILE_KB_FILES.get(name)
    if not src or not src.exists():
        raise HTTPException(404, f"未配置或找不到 {name} 的知识库源文件")
    text = src.read_text(encoding="utf-8", errors="ignore")
    chunks = _chunk_kb_text(text)
    if not chunks:
        raise HTTPException(400, "源文件无有效文本块")
    if replace:
        with _conv.registry.kb._lock:
            rm_ids = [d.id for d in _conv.registry.kb.docs if d.meta.get("profile") == name]
            _conv.registry.kb.docs = [d for d in _conv.registry.kb.docs
                                        if d.meta.get("profile") != name]
            if _conv.registry.kb._conn is not None:
                for did in rm_ids:
                    _conv.registry.kb._conn.execute("DELETE FROM kb_docs WHERE id=?", (did,))
                _conv.registry.kb._conn.commit()
    ids = []
    prof = _profiles.get(name, {})
    for ps in (prof.get("probe_sentences") or []):
        if isinstance(ps, str) and ps.strip() and ps.strip() not in chunks:
            chunks.append(ps.strip())
    for ch in chunks:
        ids.append(_conv.registry.kb.add(ch, meta={"profile": name, "source": src.name}))
    return {"ok": True, "profile": name, "added": len(ids), "chunks": len(chunks),
            "total": _conv.registry.kb.count(),
            "sample": chunks[0][:80] if chunks else ""}

