# ── 路由：实时直播启停 ────────────────────────────────────────────────
_realtime_proc = None
_rvc_proc      = None
_scrcpy_proc   = None
_scrcpy_watchdog_started = False
_scrcpy_cmd = None
_scrcpy_fail_count = 0
_scrcpy_next_retry_ts = 0.0
_scrcpy_last_start_ts = 0.0
_LAST_VIDEO_START_TS = 0.0   # 视频管线最近一次(重)启动时刻——浏览器/守护共用，作跨端去重信号
_LAST_VIDEO_BODY     = {}    # 最近一次视频启动的有效参数(源/画质/换脸参数)——守护按原配置重启

def _start_scrcpy_proc():
    global _scrcpy_proc, _scrcpy_last_start_ts
    if not _scrcpy_cmd:
        return None
    now = time.time()
    if now - _scrcpy_last_start_ts < 8:
        return _scrcpy_proc
    _scrcpy_last_start_ts = now
    try:
        _subprocess.run(
            ["powershell", "-NoProfile", "-Command",
             "Get-CimInstance Win32_Process | Where-Object { $_.CommandLine -like '*scrcpy.exe*' } | ForEach-Object { Stop-Process -Id $_.ProcessId -Force }"],
            capture_output=True, text=True, timeout=5,
            creationflags=getattr(_subprocess, "CREATE_NO_WINDOW", 0))
    except Exception:
        pass
    _scrcpy_proc = _subprocess.Popen(_scrcpy_cmd, creationflags=_subprocess.CREATE_NEW_CONSOLE)
    return _scrcpy_proc

def _scrcpy_watchdog():
    global _scrcpy_proc, _scrcpy_fail_count, _scrcpy_next_retry_ts
    adb_path = rf"{_BASE}\scrcpy\scrcpy-win64-v3.1\adb.exe"
    while True:
        time.sleep(3)
        try:
            if not (_realtime_proc and _realtime_proc.poll() is None):
                _scrcpy_fail_count = 0
                continue
            if time.time() < _scrcpy_next_retry_ts:
                continue
            adb_r = _subprocess.run([adb_path, "devices"], capture_output=True, text=True, timeout=5, creationflags=getattr(_subprocess, "CREATE_NO_WINDOW", 0))
            if adb_r.returncode != 0 or "\tdevice" not in adb_r.stdout:
                _scrcpy_fail_count = min(_scrcpy_fail_count + 1, 6)
                _scrcpy_next_retry_ts = time.time() + min(60, 5 * (2 ** (_scrcpy_fail_count - 1)))
                continue
            if (not _scrcpy_proc) or (_scrcpy_proc.poll() is not None):
                _start_scrcpy_proc()
                time.sleep(4)
                if _scrcpy_proc and _scrcpy_proc.poll() is None:
                    _scrcpy_fail_count = 0
                    _scrcpy_next_retry_ts = 0
                else:
                    _scrcpy_fail_count = min(_scrcpy_fail_count + 1, 6)
                    _scrcpy_next_retry_ts = time.time() + min(60, 5 * (2 ** (_scrcpy_fail_count - 1)))
        except Exception as e:
            _scrcpy_fail_count = min(_scrcpy_fail_count + 1, 6)
            _scrcpy_next_retry_ts = time.time() + min(60, 5 * (2 ** (_scrcpy_fail_count - 1)))

@app.get("/realtime/scrcpy_status")
def realtime_scrcpy_status():
    return {
        "running": bool(_scrcpy_proc and _scrcpy_proc.poll() is None),
        "pid": _scrcpy_proc.pid if _scrcpy_proc else None,
        "fail_count": _scrcpy_fail_count,
        "retry_in_sec": max(0, int(_scrcpy_next_retry_ts - time.time())),
        "watchdog_started": _scrcpy_watchdog_started,
    }

@app.post("/realtime/start")
def realtime_start(body: dict = {}):
    global _realtime_proc, _scrcpy_proc, _scrcpy_watchdog_started, _scrcpy_cmd, _scrcpy_fail_count, _scrcpy_next_retry_ts, _scrcpy_last_start_ts
    global _LAST_VIDEO_START_TS, _LAST_VIDEO_BODY
    _LAST_VIDEO_BODY = dict(body or {})    # 记下本次源/参数，供服务端自愈按「原配置」重启（单一启动口径）
    # S4: 开播即预热本场热角色 DFM（活动角色+最常用，引擎 LRU 预算内；后台跑，不阻塞开播）。
    #     开播前预热完 → 场内切角色 ~20ms 零冻结（冷加载对照：阻塞 4.5s、卡帧 2.8s）。
    _prewarm_hot_dfms_async(reason="一键开播")
    try:
        _subprocess.run(
            ["powershell", "-NoProfile", "-Command",
             "Get-CimInstance Win32_Process | Where-Object { $_.CommandLine -like '*realtime_stream.py*' -or $_.CommandLine -like '*scrcpy.exe*' } | ForEach-Object { Stop-Process -Id $_.ProcessId -Force }"],
            capture_output=True, text=True, timeout=10,
            creationflags=getattr(_subprocess, "CREATE_NO_WINDOW", 0))
        _realtime_proc = None
        _scrcpy_proc = None
        _scrcpy_fail_count = 0
        _scrcpy_next_retry_ts = 0.0
        _scrcpy_last_start_ts = 0.0
        if _realtime_proc and _realtime_proc.poll() is None:
            return {"ok": True, "detail": "already running"}
        source = str(body.get("source", "")).strip()
        width  = int(body.get("width", 0) or 0)
        height = int(body.get("height", 0) or 0)
        # 输出比例(effect_cfg 单一真相)：设了就以它为准 → 覆盖 w/h 并透传 --aspect。
        # 这样一键开播/画质预设/自愈重启任何路径都不会把竖屏翻回横屏(用户投诉根因)。
        _out_aspect = str(body.get("aspect", "") or "").strip().lower()
        if _out_aspect not in _ASPECT_WH:
            _out_aspect = _resolved_output_aspect()
        if _out_aspect:
            width, height = _ASPECT_WH[_out_aspect]
        fps    = int(body.get("fps", 0) or 0)
        swap_fps = int(body.get("swap_fps", 0) or 0)
        mjpeg_fps = int(body.get("mjpeg_fps", 0) or 0)
        jpeg_quality = int(body.get("jpeg_quality", 0) or 0)
        crossfade = float(body.get("crossfade", 0) or 0)
        # 换脸效果参数（0/空 = 沿用引擎默认，不改变既有观感）
        face_blend     = float(body.get("face_blend", 0) or 0)
        face_threshold = float(body.get("face_threshold", 0) or 0)
        face_smooth    = float(body.get("face_smooth", 0) or 0)
        face_enhance   = str(body.get("face_enhance", "")).strip()
        # 画质目标档(eco/natural/beauty/hd)：UI 预设按钮的引擎侧联动(2026-07-05 P0)。空=沿用 SWAP_PRESET 环境变量
        swap_preset    = str(body.get("swap_preset", "")).strip().lower()
        if swap_preset not in ("", "eco", "natural", "beauty", "hd"):
            swap_preset = ""
        # P5 授权预设分层闸门：一处设闸覆盖两条开播路径(/realtime/start 直呼 + one_click_start 函数调用)
        width, height, face_enhance, _lic_note = _license_preset_gate(width, height, face_enhance)
        # 自动选源：安卓(ADB已授权)→scrcpy；否则按名识别手机虚拟摄像头(iPhone 等)并活帧探测→索引；兜底 scrcpy
        auto_reason = ""
        if source in ("", "auto"):
            try:
                _adb_path = rf"{_BASE}\scrcpy\scrcpy-win64-v3.1\adb.exe"
                try:
                    _adb_r = _subprocess.run([_adb_path, "devices"], capture_output=True, text=True, timeout=5, creationflags=getattr(_subprocess, "CREATE_NO_WINDOW", 0))
                    _adb_ok = "\tdevice" in _adb_r.stdout
                except Exception:
                    _adb_ok = False
                _pick = _pick_camera_source_safe(_adb_ok, probe=True)   # P10: 子进程隔离
                source = _pick["source"]
                auto_reason = _pick["reason"]
            except Exception as _e:
                source = "scrcpy"
                auto_reason = f"auto-failed:{_e}"
        if source == "scrcpy":
            scrcpy_path = rf"{_BASE}\scrcpy\scrcpy-win64-v3.1\scrcpy.exe"
            adb_path = rf"{_BASE}\scrcpy\scrcpy-win64-v3.1\adb.exe"
            adb_r = _subprocess.run([adb_path, "devices"], capture_output=True, text=True, timeout=5, creationflags=getattr(_subprocess, "CREATE_NO_WINDOW", 0))
            if "\tdevice" not in adb_r.stdout:
                return {"ok": False, "detail": "手机未授权ADB，请解锁手机并允许USB调试"}
            # 窗口放到主屏左上角（50,50）而非两屏交界(1500,0)；保留 --always-on-top 以便
            # BitBlt 截图始终能截到（窗口不被遮挡）。用户可自由拖动到任意位置，截图按实时坐标跟随。
            # --audio-source=mic：把手机麦转发到 Windows 默认播放设备(应为 Voicemeeter Input)，
            # 经 VoiceMeeter VAIO->B1 路由后由 live_interpreter 从 "Voicemeeter Out B1" 采集。
            # --audio-buffer 压低延迟；camera 视频源需显式指定音频源。
            _scrcpy_cmd = [scrcpy_path, "--window-title", "PhoneCam", "--always-on-top",
                           "--window-x", "50", "--window-y", "50",
                           "--max-fps", "20", "--video-source=camera",
                           "--audio-source=mic", "--audio-buffer=50",
                           "--camera-id=1",
                           "--capture-orientation=270", "--render-driver", "software"]
            if not (_scrcpy_proc and _scrcpy_proc.poll() is None):
                _start_scrcpy_proc()
                time.sleep(3)
            if not _scrcpy_watchdog_started:
                threading.Thread(target=_scrcpy_watchdog, daemon=True).start()
                _scrcpy_watchdog_started = True
            # 竖屏默认 720x960：匹配手机相机 3:4 竖屏内容，避免横屏 cover 裁掉上下/比例对不上。
            # 经验更正：Telegram 能否看到 OBS 取决于"重启 Telegram 刷新设备列表"，与横竖屏无关；
            # 竖屏更贴合手机视频通话观感。可被前端 width/height 覆盖。
            w = width if width > 0 else 720
            h = height if height > 0 else 960
            cmd = [app_config.conda_python("facefusion"),
                   rf"{_BASE}\realtime_stream.py",
                   "--source", "scrcpy", "--width", str(w), "--height", str(h)]
            if fps > 0:          cmd += ["--fps", str(fps)]
            if swap_fps > 0:     cmd += ["--swap-fps", str(swap_fps)]
            if mjpeg_fps > 0:    cmd += ["--mjpeg-fps", str(mjpeg_fps)]
            if jpeg_quality > 0: cmd += ["--jpeg-quality", str(jpeg_quality)]
            if crossfade > 0:    cmd += ["--crossfade", str(crossfade)]
            if face_blend > 0:       cmd += ["--face-blend", str(face_blend)]
            if face_threshold > 0:   cmd += ["--face-threshold", str(face_threshold)]
            if face_smooth > 0:      cmd += ["--face-smooth", str(face_smooth)]
            if face_enhance:         cmd += ["--face-enhance", face_enhance]
            if swap_preset:          cmd += ["--swap-preset", swap_preset]
            if _out_aspect:          cmd += ["--aspect", _out_aspect]
            # P9：一键标定的自适应阈值(如有)随环境注入——每台机器用自己实测的降/升档线
            _realtime_proc = _subprocess.Popen(cmd, creationflags=_subprocess.CREATE_NEW_CONSOLE, env=_video_env())
            _LAST_VIDEO_START_TS = time.time()
            out = {"ok": True, "detail": f"pid={_realtime_proc.pid}", "camera": "scrcpy", "scrcpy_pid": _scrcpy_proc.pid, "auto_reason": auto_reason}
            if _lic_note: out["lic_note"] = _lic_note
            return out
        # 读取持久化摄像头索引
        cam_idx = source if source else "0"
        if (not cam_idx) or (cam_idx == "camera"):
            cam_idx = "0"
        if _CAMERA_IDX_FILE.exists():
            try:
                saved = _CAMERA_IDX_FILE.read_text().strip()
                if saved.isdigit() and not cam_idx:
                    cam_idx = saved
            except Exception:
                pass
        # 根因修复：DirectShow 索引不稳定——手机虚拟摄像头(DroidCam/iVCam)会注册"未推流"的占位设备，
        # 一旦钉死的索引对应到没在推流的设备，realtime_stream 会每 3s 死循环打不开并刷满 DSHOW 报错。
        # 启动前先活帧探测该索引；打不开就自动改用"能出活帧"的源，而不是发起一个注定失败的采集进程。
        if cam_idx.isdigit():
            try:
                if not _probe_live_safe(int(cam_idx)):   # P10: 子进程隔离
                    _pick = _pick_camera_source_safe(False, probe=True)
                    _alt = str(_pick.get("source") or "")
                    if _alt and _alt not in ("scrcpy", cam_idx):
                        auto_reason = f"索引{cam_idx}无活帧→改用 {_alt}({_pick.get('reason')})"
                        cam_idx = _alt
                    else:
                        auto_reason = auto_reason or f"索引{cam_idx}无活帧(暂无其它活源,交由运行时自愈)"
            except Exception as _e:
                auto_reason = auto_reason or f"活帧校验跳过:{_e}"
        # 手机 monitor_relay 源(cam.mjpeg)恒为竖屏 720x1280。one_click_start/画质预设/自愈重启
        # (_restart_video_pipeline_core 回放 _LAST_VIDEO_BODY) 都会带横屏默认(1280x720)，若照单
        # 输出会把竖屏硬拉成横屏"压扁"，且中途切分辨率会让下游(SplitCam)按旧 stride 读出"花屏"。
        # 故对手机源强制竖屏：仅当调用方显式给出竖屏尺寸(h>w)才尊重，否则一律 720x1280，
        # 从根上杜绝"点一键开播/自愈又翻回横屏"。普通 USB 摄像头(非 cam.mjpeg)仍默认横屏。
        _phone_portrait = isinstance(cam_idx, str) and "cam.mjpeg" in cam_idx
        if _phone_portrait:
            if width > 0 and height > 0 and height > width:
                w, h = width, height
            else:
                w, h = 720, 1280
        else:
            w = width if width > 0 else 1280
            h = height if height > 0 else 720
        cmd = [app_config.conda_python("facefusion"),
               rf"{_BASE}\realtime_stream.py",
               "--source", cam_idx, "--width", str(w), "--height", str(h)]
        if fps > 0:          cmd += ["--fps", str(fps)]
        if swap_fps > 0:     cmd += ["--swap-fps", str(swap_fps)]
        if mjpeg_fps > 0:    cmd += ["--mjpeg-fps", str(mjpeg_fps)]
        if jpeg_quality > 0: cmd += ["--jpeg-quality", str(jpeg_quality)]
        if crossfade > 0:    cmd += ["--crossfade", str(crossfade)]
        if face_blend > 0:       cmd += ["--face-blend", str(face_blend)]
        if face_threshold > 0:   cmd += ["--face-threshold", str(face_threshold)]
        if face_smooth > 0:      cmd += ["--face-smooth", str(face_smooth)]
        if face_enhance:         cmd += ["--face-enhance", face_enhance]
        if swap_preset:          cmd += ["--swap-preset", swap_preset]
        if _out_aspect:          cmd += ["--aspect", _out_aspect]
        # P9：一键标定的自适应阈值(如有)随环境注入——每台机器用自己实测的降/升档线
        _realtime_proc = _subprocess.Popen(cmd, creationflags=_subprocess.CREATE_NEW_CONSOLE, env=_video_env())
        _LAST_VIDEO_START_TS = time.time()
        out = {"ok": True, "detail": f"pid={_realtime_proc.pid}", "camera": cam_idx, "auto_reason": auto_reason}
        if _lic_note: out["lic_note"] = _lic_note
        return out
    except Exception as e:
        return {"ok": False, "detail": str(e)}

@app.post("/realtime/stop")
def realtime_stop():
    global _realtime_proc
    if _realtime_proc and _realtime_proc.poll() is None:
        _realtime_proc.terminate()
        threading.Thread(target=_matting_try_drain, daemon=True, name="matting-drain-stop").start()
        return {"ok": True}
    return {"ok": False, "detail": "not running"}

@app.get("/realtime/status")
def realtime_status():
    video_ok = _realtime_proc is not None and _realtime_proc.poll() is None
    rvc_ok   = _rvc_proc is not None and _rvc_proc.poll() is None
    # 读取实时状态文件（由 realtime_stream 写入）
    metrics = {}
    try:
        status_path = Path(rf"{_BASE}\realtime_status.json")
        if status_path.exists():
            import json as _json
            metrics = _json.loads(status_path.read_text(encoding='utf-8'))
    except Exception:
        metrics = {}
    _fs_up = ((_HEALTH_CACHE.get("data") or {}).get("services") or {}).get("faceswap")
    # 06t: 当前受管进程若是收养来的(hub 重启丢句柄后按 PID 认领)，如实展示——前端出「已接管」提示
    _adopted = (_ORPHAN_STREAM.get("adopted")
                if (video_ok and isinstance(_realtime_proc, _AdoptedProc)) else None)
    return {"video_running": video_ok, "rvc_running": rvc_ok, "metrics": metrics,
            "orphan": _ORPHAN_STREAM["info"],   # 未收养孤儿摘要(None=无)：收养失败才出横幅
            "orphan_adopted": _adopted,          # 无闪断收养记录(pid/ts)：在管且为收养句柄时非空
            # P7-1 顺风车：最近一次服务端自动热切(10min 内)——前端 4s 轮询到即弹 toast+刷设备条
            "dev_autoswitch_last": (dict(_DEV_AUTOSW_LAST)
                                    if _DEV_AUTOSW_LAST["ts"] and time.time() - _DEV_AUTOSW_LAST["ts"] < 600
                                    else None),
            # P8-1 变声转换是否在跑（hub 代理起停时打的旗标）：自救卡看到它恢复 True 即自动退场
            "rvc_conv": bool(_RVC_CONV.get("active")),
            "health": _compute_stream_health(metrics, _fs_up, video_ok)}   # 开播健康单一真相（下沉后端，多端共享）

@app.get("/realtime/health_timeline")
def realtime_health_timeline(limit: int = 50):
    """开播健康时间线（P3-C③）：服务端守护记录的近期「状态跳迁 + 自愈动作」事件 + 累计统计，供复盘。
    无浏览器在场也照常累计（守护后台运行）；autoheal_on 标示服务端非破坏自愈是否已开启。"""
    n = max(1, min(int(limit or 50), 80))
    return {"ok": True, "timeline": list(_SH_TIMELINE)[-n:], "stats": _sh_stats_snapshot(),
            "autoheal_on": _AUTOHEAL_ON, "watch_sec": _SH_WATCH_SEC}


def _heal_config_snapshot() -> dict:
    """服务端自愈/告警的运行时配置快照（含护栏参数 + 告警通道概况，供前端展示与确认）。"""
    try:
        import alerts as _al
        ch = _al.channels()
    except Exception:
        ch = {}
    return {"ok": True, "autoheal": _AUTOHEAL_ON, "alerts": _SH_ALERTS_ON,
            "dev_autoswitch": _DEV_AUTOSW_ON,
            "dev_autoswitch_guard": {"confirm": _DEV_AUTOSW_CONFIRM,
                                     "cooldown": _DEV_AUTOSW_COOLDOWN, "max": _DEV_AUTOSW_MAX},
            "idle_live_govern": _IDLE_LIVE_GOVERN,   # Song-P6 空转直播治理
            "idle_live_guard": {"noface_min": _IDLE_LIVE_NOFACE_MIN,
                                "stalled_min": _IDLE_LIVE_STALLED_MIN},
            "watch_sec": _SH_WATCH_SEC, "restart_count": _AH_RESTART_COUNT,
            "restart": {"dwell": _AH_RESTART_DWELL, "cooldown": _AH_RESTART_COOLDOWN,
                        "max": _AH_RESTART_MAX, "dedup": _AH_RESTART_DEDUP},
            "vram": {"dwell": _AH_VRAM_DWELL, "cooldown": _AH_VRAM_COOLDOWN},
            "alert_dwell": {"svc_down": _AH_ALERT_SVC, "noface": _AH_ALERT_NOFACE},
            "audio": {   # 音频链路守护(与前端 soundDiag 互补)：P4 变声掉线自动拉起 + P-Silence 无人值守静音告警
                "rvc_heal": {"grace": _AH_RVC_GRACE, "cooldown": _AH_RVC_COOLDOWN,
                             "max": _AH_RVC_MAX, "count": _AH_RVC_COUNT},         # 受 autoheal 控
                "silence": {"warn_sec": _CS_SILENT_SEC, "never_grace": _CS_GRACE_SEC,
                            "crit_extra": _CS_CRIT_EXTRA, "rms_on": _CS_RMS_ON,
                            # P-Bed 哑播保险(垫播兜底)状态
                            "bed_on": _CS_BED_ON, "bed_active": _CS_BED["active"],
                            "bed_max_min": _CS_BED_MAX_MIN}},  # 受 alerts 控
            "channels": ch}

@app.get("/api/heal/config")
def api_heal_config_get():
    """读取服务端自愈/告警的运行时开关与护栏参数（前端开播页据此渲染开关状态）。"""
    return _heal_config_snapshot()

@app.post("/api/heal/config")
def api_heal_config_set(body: dict = {}):
    """运行时切换服务端自愈/告警（免改环境变量、免重启，便于灰度）。
    body: {autoheal?:bool, alerts?:bool, dev_autoswitch?:bool, dry_run?:bool}。仅切布尔总开关；护栏阈值仍由环境变量定，避免误调失稳。
    dry_run=true：只回显「将变更什么」(changed)，不改运行时/不落盘——供前端提交前校验、自检回归安全反复跑。"""
    global _AUTOHEAL_ON, _SH_ALERTS_ON, _DEV_AUTOSW_ON, _IDLE_LIVE_GOVERN
    dry = bool(isinstance(body, dict) and body.get("dry_run"))
    changed = {}
    if isinstance(body, dict):
        if "autoheal" in body:
            nv = bool(body["autoheal"])
            if not dry:
                _AUTOHEAL_ON = nv
            changed["autoheal"] = nv
        if "alerts" in body:
            nv = bool(body["alerts"])
            if not dry:
                _SH_ALERTS_ON = nv
            changed["alerts"] = nv
        if "dev_autoswitch" in body:
            nv = bool(body["dev_autoswitch"])
            if not dry:
                _DEV_AUTOSW_ON = nv
            changed["dev_autoswitch"] = nv
        if "idle_live_govern" in body:           # Song-P6 空转直播治理
            nv = bool(body["idle_live_govern"])
            if not dry:
                _IDLE_LIVE_GOVERN = nv
            changed["idle_live_govern"] = nv
    if changed and not dry:
        _save_heal_cfg()                     # 持久化，跨重启保留灰度选择
        _logger.info(f"[StreamHeal] 运行时配置变更 {changed}（autoheal={_AUTOHEAL_ON} alerts={_SH_ALERTS_ON}）")
    snap = _heal_config_snapshot(); snap["changed"] = changed
    snap["dry_run"] = dry
    snap["persisted"] = ("" if dry else str(_HEAL_CFG_FILE))
    return snap


def _health_sessions(max_sessions: int = 12, tail_lines: int = 2000, path=None) -> list:
    """从时间线 jsonl 派生「按场次(开播→停播)聚合」的复盘摘要（单一来源=timeline，跨重启可读）。
    以 idle 为场次边界：进入非 idle 开场、回到 idle 收场；场内累计丢脸/卡顿/掉线/自动重启/腾显存/告警/恢复。
    path 可注入(默认生产时间线)，供 selftest 演练读合成临时文件、不碰生产数据。"""
    p = path or _SH_TIMELINE_PATH
    lines = []
    try:
        if p.exists():
            lines = p.read_text(encoding="utf-8").splitlines()[-max(50, tail_lines):]
    except Exception:
        lines = []
    sessions, cur = [], None
    def _new(ts):
        return {"start": ts, "end": None, "open": True, "events": 0,
                "noface": 0, "svc_down": 0, "lag": 0, "recovered": 0,
                "restart": 0, "free_vram": 0, "alert": 0, "hot_switch": 0,
                "dfm_switch": 0}   # S5 场内换脸角色热切次数
    for ln in lines:
        ln = ln.strip()
        if not ln:
            continue
        try:
            e = json.loads(ln)
        except Exception:
            continue
        ev, frm, to, ts = e.get("event"), e.get("from"), e.get("to"), e.get("ts")
        if ev == "transition":
            if to and to != "idle":
                if cur is None:
                    cur = _new(ts)
                cur["events"] += 1
                if to in ("noface", "svc_down", "lag"):
                    cur[to] += 1
                if to == "ok" and frm in ("noface", "svc_down", "lag"):
                    cur["recovered"] += 1
            elif to == "idle" and cur is not None:
                cur["end"] = ts; cur["open"] = False
                sessions.append(cur); cur = None
        elif cur is not None and ev == "auto_heal":
            cur["events"] += 1
            lab = e.get("label", "")
            if "free_vram" in lab: cur["free_vram"] += 1
            elif "restart" in lab: cur["restart"] += 1
        elif cur is not None and ev == "alert":
            cur["events"] += 1; cur["alert"] += 1
        elif cur is not None and ev == "device":     # P4-1 场内设备热切（拔插一键恢复）计入本场
            cur["events"] += 1; cur["hot_switch"] += 1
        elif cur is not None and ev == "dfm":        # S5 场内换脸角色热切计入本场
            cur["events"] += 1; cur["dfm_switch"] += 1
    if cur is not None:
        sessions.append(cur)                 # 仍在进行中的当前场
    now = time.time()
    for s in sessions:
        s["dur_s"] = max(0, int((s["end"] if s["end"] else now) - s["start"]))
    return sessions[-max_sessions:][::-1]     # 最近 N 场，倒序(新在前)

@app.get("/realtime/health_sessions")
def realtime_health_sessions(limit: int = 12):
    """开播健康·场次复盘（P3-D）：把时间线按「开播→停播」聚合成每场摘要，供收播后一眼回看本场稳定度。"""
    return {"ok": True, "sessions": _health_sessions(max_sessions=max(1, min(int(limit or 12), 50)))}


@app.get("/realtime/swap/sessions")
def realtime_swap_sessions(limit: int = 5):
    """场次换脸质量报告（观察自动化）：停播自动聚合的裁剪命中/自动降档/时延/增强场次账本，最新在前。
    在播时附 current（进行中的未收场聚合），供「本场目前」预览。前端停播成绩单据此补量化四格。"""
    out = []
    try:
        if _SWAP_SESS_PATH.exists():
            lines = _SWAP_SESS_PATH.read_text(encoding="utf-8").splitlines()
            for ln in lines[-max(1, min(int(limit or 5), 50)):]:
                try:
                    out.append(json.loads(ln))
                except Exception:
                    pass
    except Exception as e:
        _logger.warning(f"[SwapSess] 读场次账本失败: {e}")
    cur = None
    if _swap_sess.get("active") and _swap_sess.get("samples", 0) >= 1:
        cur = _swap_sess_report(_swap_sess, time.time())
    return {"ok": True, "sessions": out[::-1], "current": cur}


@app.post("/realtime/swap/sessions/rate")
async def realtime_swap_sessions_rate(request: Request):
    """P7 五期·主观两问速记：把真人观察仅剩的两件主观项（贴缝观感/精修观感）从「记脑子里」
    改成停播成绩单上两次点选即入账——量化与主观落同一本场次账本，复盘/趋势一处看全。
    body: {start: 场次键(报告 start 秒), seam|enhance: good|ok|bad|""(撤销), note: ≤120字}"""
    try:
        body = await request.json()
    except Exception:
        body = {}
    if not isinstance(body, dict):
        raise HTTPException(400, "需要 JSON body")
    try:
        start = float(body.get("start"))
    except Exception:
        raise HTTPException(400, "缺 start(场次键)")
    human = {}
    for k in ("seam", "enhance"):
        if k in body:
            v = str(body.get(k) or "").strip()
            if v not in ("", "good", "ok", "bad"):
                raise HTTPException(400, f"{k} 只接受 good/ok/bad/空")
            human[k] = v
    if "note" in body:
        human["note"] = _clip(str(body.get("note") or ""), 120)
    if not human:
        raise HTTPException(400, "至少带一项 seam/enhance/note")
    human["ts"] = round(time.time(), 1)
    with _SWAP_SESS_FILE_LOCK:
        lines = []
        if _SWAP_SESS_PATH.exists():
            lines = _SWAP_SESS_PATH.read_text(encoding="utf-8").splitlines()
        new_lines, row = _swap_sess_rate_apply(lines, start, human)
        if row is None:
            raise HTTPException(404, "未找到该场次（start 不匹配）")
        _SWAP_SESS_PATH.write_text("\n".join(new_lines) + "\n", encoding="utf-8")
    return {"ok": True, "session": row}


@app.get("/api/swap_sess/selftest")
def swap_sess_selftest():
    """场次报告聚合演练（同 heal/selftest 思路：真函数+合成输入，无需真开播）：
    喂两份合成 /swap/status 快照（第二份模拟进程重启计数器归零），断言进位/命中率/降档/引擎统计。"""
    agg = _swap_sess_begin(1000.0)
    _swap_sess_sample(agg, {
        "stats": {"ok": 100, "fail": 0, "fps": 8.0, "latency_ms": 120.0},
        "crop": {"hits": 90, "miss": 10},
        "auto": {"effective": "hd", "target": "hd"}, "preset": "hd",
        "params": {"enhance": "gfpgan"}, "bg": {"enabled": False}}, "ok")
    _swap_sess_sample(agg, {
        "stats": {"ok": 20, "fail": 5, "fps": 6.0, "latency_ms": 200.0},   # 计数器已重置(自愈重启)
        "crop": {"hits": 10, "miss": 0},
        "auto": {"effective": "natural", "target": "hd", "reason": "load"}, "preset": "natural",
        "params": {"enhance": "codeformer"}, "bg": {"enabled": True, "mode": "blur"}}, "lag")
    # 第三份快照：离席(noface)期 fail +20——断言在席/离席拆账(2026-07-06p 二期)
    _swap_sess_sample(agg, {
        "stats": {"ok": 20, "fail": 25, "fps": 6.0, "latency_ms": 0},
        "crop": {"hits": 10, "miss": 0},
        "auto": {"effective": "natural", "target": "hd", "reason": "load"}, "preset": "natural",
        "params": {"enhance": "codeformer"}, "bg": {"enabled": True, "mode": "blur"}}, "noface")
    rep = _swap_sess_report(agg, 1060.0)
    checks = {
        "重置进位·换脸成功=120": rep["swap"]["ok"] == 120,
        "重置进位·裁剪命中率=91%": rep["crop"]["hit_pct"] == 91,     # (90+10)/(100+10)
        "降档tick·占比": rep["degraded_ticks"] == 2 and rep["degraded_pct"] == 67,
        "降档原因捕获": rep["degrade_reasons"].get("load") == 2,
        "增强引擎双计数": rep["enhance"] == {"gfpgan": 1, "codeformer": 2},
        "虚拟背景计数": rep["bg"] == {"none": 1, "blur": 2},
        "时延中位/峰值": rep["latency_ms"]["med"] == 200.0 and rep["latency_ms"]["max"] == 200.0,
        "时长=60s": rep["dur_s"] == 60,
        # 离席拆账：总失败率 17%(25/145)，剔除离席后有效失败率 4%(5/125)，离席时长=1 tick
        "离席拆账·原始失败率17%": rep["swap"]["fail_pct"] == 17,
        "离席拆账·有效失败率4%": rep["swap"]["fail_pct_active"] == 4,
        "离席拆账·离席时长>0": rep["away_s"] == int(max(1.0, _SH_WATCH_SEC)),
    }
    # P7 五期·主观评注合并（纯函数、合成行,不碰生产账本）：定位/覆盖/未命中三态
    _l0 = [json.dumps({"start": 1000.0, "dur_s": 60}, ensure_ascii=False),
           json.dumps({"start": 2000.0, "dur_s": 90}, ensure_ascii=False)]
    _l1, _r1 = _swap_sess_rate_apply(_l0, 2000.4, {"seam": "good"})           # ±2s 容差定位
    _l2, _r2 = _swap_sess_rate_apply(_l1, 2000.0, {"seam": "bad", "note": "边缘闪"})   # 改选覆盖
    _, _r3 = _swap_sess_rate_apply(_l2, 5000.0, {"seam": "good"})             # 未命中
    checks.update({
        "评注·容差定位": bool(_r1) and _r1.get("human", {}).get("seam") == "good",
        "评注·改选覆盖+备注保留": bool(_r2) and _r2["human"]["seam"] == "bad" and _r2["human"]["note"] == "边缘闪",
        "评注·其余行不动": bool(_l1) and json.loads(_l1[0]).get("human") is None,
        "评注·未命中回 None": _r3 is None,
    })
    return {"ok": all(checks.values()), "checks": checks, "report": rep}


def _health_gantt(max_sessions: int = 12, tail_lines: int = 4000, path=None) -> list:
    """从时间线 jsonl 派生「按场次」的甘特数据：每场 = 按状态着色的时间段 segments + 自愈/告警 markers + 计数。
    单一来源=timeline（读全量文件，不受内存环 80 条上限），跨重启可读；供 /ops 看板画时间甘特。
    相邻跳迁构造区间 [t0,t1) 状态=前一跳迁的 to；idle 为场次边界；标记按时间戳归属到所在场。
    path 可注入(默认生产时间线)，供 selftest 演练读合成临时文件、不碰生产数据。"""
    p = path or _SH_TIMELINE_PATH
    lines = []
    try:
        if p.exists():
            lines = p.read_text(encoding="utf-8").splitlines()[-max(100, tail_lines):]
    except Exception:
        lines = []
    evs = []
    for ln in lines:
        ln = ln.strip()
        if not ln:
            continue
        try:
            evs.append(json.loads(ln))
        except Exception:
            continue
    now = int(time.time())
    trans = [(int(e.get("ts") or 0), e.get("to")) for e in evs
             if e.get("event") == "transition" and e.get("to")]
    marks = [(int(e.get("ts") or 0), e.get("event"), e.get("label", "")) for e in evs
             if e.get("event") in ("auto_heal", "alert", "device", "dfm")]   # device=P4-1 热切(🎚)；dfm=S5 换脸角色热切(🎭)
    intervals = []                                    # (t0, t1, state)
    for i, (ts, st) in enumerate(trans):
        t1 = trans[i + 1][0] if i + 1 < len(trans) else now
        intervals.append((ts, max(ts, t1), st))
    sessions, cur, prev_state = [], None, None

    def _new(ts):
        return {"start": ts, "end": None, "open": True, "segments": [], "markers": [],
                "noface": 0, "svc_down": 0, "lag": 0, "recovered": 0,
                "restart": 0, "free_vram": 0, "alert": 0, "hot_switch": 0,
                "dfm_switch": 0}   # S5 场内换脸角色热切次数(🎭 标记)

    for (t0, t1, st) in intervals:
        if st == "idle":
            if cur is not None:
                cur["end"] = t0; cur["open"] = False
                sessions.append(cur); cur = None
            prev_state = st
            continue
        if cur is None:
            cur = _new(t0)
        cur["segments"].append({"state": st, "t0": t0, "t1": t1, "dur": max(0, t1 - t0)})
        if st in ("noface", "svc_down", "lag"):
            cur[st] += 1
        if st == "ok" and prev_state in ("noface", "svc_down", "lag"):
            cur["recovered"] += 1
        prev_state = st
    if cur is not None:
        sessions.append(cur)                          # 仍在进行中的当前场(open=True,end=None)
    for (ts, ev, lab) in marks:                       # 标记归属到所在场次
        for s in sessions:
            end = s["end"] if s["end"] else now
            if s["start"] <= ts <= end:
                s["markers"].append({"ts": ts, "kind": ev, "label": lab})
                if ev == "alert":
                    s["alert"] += 1
                elif ev == "device":                  # P4-1 场内设备热切
                    s["hot_switch"] += 1
                elif ev == "dfm":                     # S5 场内换脸角色热切
                    s["dfm_switch"] += 1
                elif "free_vram" in (lab or ""):
                    s["free_vram"] += 1
                elif "restart" in (lab or ""):
                    s["restart"] += 1
                break
    for s in sessions:
        s["dur_s"] = max(0, int((s["end"] if s["end"] else now) - s["start"]))
    return sessions[-max_sessions:][::-1]             # 最近 N 场，倒序(新在前)

@app.get("/realtime/health_gantt")
def realtime_health_gantt(limit: int = 12):
    """开播健康·甘特复盘：每场按状态着色的时间段 + 自愈/告警标记，供 /ops 运维看板可视化回看。"""
    return {"ok": True, "now": int(time.time()),
            "sessions": _health_gantt(max_sessions=max(1, min(int(limit or 12), 40)))}

@app.post("/api/heal/test_alert")
async def api_heal_test_alert():
    """告警通路自检：发一条测试告警(逐 webhook 投递 + 本地弹窗)，返回每通道结果。
    纯通路验证，不写 state/历史、不影响 active_alerts；用于开播前确认「真出问题时报得出去」。"""
    try:
        import alerts as _al
        return await asyncio.to_thread(_al.send_test)
    except Exception as e:
        return {"ok": False, "detail": str(e)}

@app.get("/api/heal/selftest")
def api_heal_selftest():
    """开播健康·自愈演练自诊断：不碰真硬件/不发真告警/不动真管线，验证「自愈真的会按预期动」——
      ①用真决策 _sh_plan 跑护栏场景矩阵(驻留/回合/每场上限/冷却/去重/总开关 + 告警越阈/恢复清除)；
      ②用真聚合 _health_sessions/_health_gantt 对一段合成「坏态回合」复盘(丢脸→自动重启→恢复→收场)。
    供 acceptance --full 与 /ops「一键演练」调用，把「契约在」升级为「真的会自愈+如实留痕」。"""
    checks = []

    def ck(name, cond, detail=""):
        checks.append({"name": name, "ok": bool(cond), "detail": detail})

    T = 1_000_000.0                          # 固定时间基，护栏判定与真实时钟无关(可复现)
    thr = {"alert_svc": 12, "alert_noface": 25, "vram_dwell": 12, "vram_cooldown": 120,
           "restart_dwell": 30, "restart_cooldown": 90, "restart_max": 2, "restart_dedup": 25,
           "govern_noface_s": 1800, "govern_stalled_s": 600}   # Song-P6 空转直播治理

    def plan(state, dwell, **kw):
        base = dict(autoheal_on=True, alerts_on=True, alerted=False, episode=set(),
                    cooldown={}, restart_count=0, now=T, last_video_start_ts=T - 9999,
                    vram_level=None, thr=thr)
        base.update(kw)
        return _sh_plan(state, dwell, **base)

    # —— 破坏类「换源重连」护栏矩阵 ——
    ck("noface<驻留·不重启", plan("noface", thr["restart_dwell"] - 1)["restart"] is False)
    ck("noface≥驻留·触发重启", plan("noface", thr["restart_dwell"] + 5)["restart"] is True)
    ck("本回合已重启·去重", plan("noface", thr["restart_dwell"] + 5, episode={"restart"})["restart"] is False)
    ck("超每场上限·不重启", plan("noface", thr["restart_dwell"] + 5, restart_count=thr["restart_max"])["restart"] is False)
    ck("冷却内·不重启", plan("noface", thr["restart_dwell"] + 5, cooldown={"restart": T - 10})["restart"] is False)
    ck("管线刚起·去重让渡", plan("noface", thr["restart_dwell"] + 5, last_video_start_ts=T - 5)["restart"] is False)
    ck("自愈总开关关·不重启", plan("noface", thr["restart_dwell"] + 5, autoheal_on=False)["restart"] is False)
    # —— 告警越阈/恢复 ——
    ck("svc_down越阈·告警critical", plan("svc_down", thr["alert_svc"] + 1)["alert"] == "critical")
    ck("noface越阈·告警error", plan("noface", thr["alert_noface"] + 1)["alert"] == "error")
    ck("已告警+恢复·清除", plan("ok", 1, alerted=True)["clear_alert"] is True)
    ck("告警总开关关·不报", plan("svc_down", thr["alert_svc"] + 1, alerts_on=False)["alert"] is None)
    # —— 非破坏「腾显存」 ——
    ck("卡顿+显存紧·腾显存", plan("lag", thr["vram_dwell"] + 1, vram_level="high")["free_vram"] is True)
    ck("卡顿+显存松·不腾", plan("lag", thr["vram_dwell"] + 1, vram_level="low")["free_vram"] is False)
    ck("卡顿<驻留·不腾", plan("lag", thr["vram_dwell"] - 5, vram_level="high")["free_vram"] is False)
    # —— Song-P6 空转直播治理（僵尸直播自动下播）——
    ck("僵尸noface超阈·自动下播", plan("noface", thr["govern_noface_s"] + 1, govern_on=True)["stop_idle_live"] is True)
    ck("noface未超阈·不动", plan("noface", thr["govern_noface_s"] - 60, govern_on=True)["stop_idle_live"] is False)
    ck("stalled超阈·自动下播", plan("stalled", thr["govern_stalled_s"] + 1, govern_on=True)["stop_idle_live"] is True)
    ck("治理开关关·不动", plan("noface", thr["govern_noface_s"] + 999, govern_on=False)["stop_idle_live"] is False)
    ck("本回合已停播·去重", plan("noface", thr["govern_noface_s"] + 1, govern_on=True,
                                episode={"stop_idle_live"})["stop_idle_live"] is False)
    ck("治理独立于自愈开关", plan("stalled", thr["govern_stalled_s"] + 1, govern_on=True,
                                  autoheal_on=False)["stop_idle_live"] is True)

    # —— 复盘聚合：用真函数对合成「坏态回合」做场次/甘特复盘（临时文件，不碰生产时间线）——
    import tempfile
    tmp = None
    agg_detail = ""
    agg_ok = False
    try:
        base_ts = int(time.time()) - 600
        tmp = Path(tempfile.gettempdir()) / f"_sh_drill_{int(time.time())}_{os.getpid()}.jsonl"
        rows = [
            {"ts": base_ts,       "event": "transition", "from": "idle",   "to": "warmup", "dwell_s": 0,   "label": "开播·检测中"},
            {"ts": base_ts + 10,  "event": "transition", "from": "warmup", "to": "ok",     "dwell_s": 10,  "label": "首次出脸"},
            {"ts": base_ts + 120, "event": "transition", "from": "ok",     "to": "noface", "dwell_s": 110, "label": "中途丢脸"},
            {"ts": base_ts + 155, "event": "auto_heal",  "from": None,     "to": None,     "dwell_s": 35,  "label": "auto_restart#1"},
            {"ts": base_ts + 180, "event": "transition", "from": "noface", "to": "ok",     "dwell_s": 60,  "label": "已恢复·换脸生效"},
            {"ts": base_ts + 300, "event": "transition", "from": "ok",     "to": "idle",   "dwell_s": 120, "label": "停播"},
        ]
        tmp.write_text("\n".join(json.dumps(r, ensure_ascii=False) for r in rows) + "\n", encoding="utf-8")
        sess = _health_sessions(path=tmp)
        gnt = _health_gantt(path=tmp)
        s0 = sess[0] if sess else {}
        g0 = gnt[0] if gnt else {}
        agg_ok = (len(sess) >= 1 and s0.get("noface") == 1 and s0.get("restart") == 1
                  and s0.get("recovered") == 1 and s0.get("open") is False
                  and len(gnt) >= 1 and isinstance(g0.get("segments"), list) and len(g0.get("segments", [])) >= 3
                  and any(m.get("kind") == "auto_heal" for m in (g0.get("markers") or [])))
        agg_detail = ("sessions=%d noface=%s restart=%s recovered=%s open=%s segs=%d markers=%d" %
                      (len(sess), s0.get("noface"), s0.get("restart"), s0.get("recovered"),
                       s0.get("open"), len(g0.get("segments", [])), len(g0.get("markers", []))))
    except Exception as e:
        agg_detail = "异常 %s" % e
    finally:
        try:
            if tmp:
                tmp.unlink()
        except Exception:
            pass
    ck("复盘聚合·坏态回合如实留痕", agg_ok, agg_detail)

    npass = sum(1 for c in checks if c["ok"])
    n = len(checks)
    return {"ok": npass == n and n > 0, "pass": npass, "total": n, "checks": checks}

