_AUDIO_ENUM_CACHE = {"ts": 0.0, "ins": [], "outs": []}


def _local_audio_devices():
    """本地枚举音频输入/输出设备(不依赖 RVC 服务)。名字带 hostapi 后缀
    (如 'CABLE Input (VB-Audio Virtual Cable) (MME)')，与前端 .includes('MME')/'CABLE Input' 匹配一致。
    返回 (input_names, output_names)。
    P10：sounddevice 枚举会加载 DroidCam 等虚拟声卡驱动 DLL(原生崩溃带走过 Hub)，
    改走 dev_probe 子进程 + 20s 缓存（本函数只是 RVC 离线时的兜底路径，命中率低）。"""
    now = time.time()
    if now - _AUDIO_ENUM_CACHE["ts"] < 20 and (_AUDIO_ENUM_CACHE["ins"] or _AUDIO_ENUM_CACHE["outs"]):
        return _AUDIO_ENUM_CACHE["ins"], _AUDIO_ENUM_CACHE["outs"]
    r = _dev_probe(["audio_devices"], timeout=15.0)
    if not r.get("ok"):
        if _AUDIO_ENUM_CACHE["ins"] or _AUDIO_ENUM_CACHE["outs"]:   # 降级：旧名单好过报错
            return _AUDIO_ENUM_CACHE["ins"], _AUDIO_ENUM_CACHE["outs"]
        raise RuntimeError(r.get("detail") or "音频设备探测失败")
    _AUDIO_ENUM_CACHE.update(ts=now, ins=r.get("inputs") or [], outs=r.get("outputs") or [])
    return _AUDIO_ENUM_CACHE["ins"], _AUDIO_ENUM_CACHE["outs"]


def _as_name_list(x):
    """RVC /inputDevices 可能返回 list 或 {'devices':[...]} → 统一成字符串列表。"""
    if isinstance(x, list):
        return [d for d in x if isinstance(d, str)]
    if isinstance(x, dict):
        v = x.get("devices") or x.get("input_devices") or x.get("output_devices") or []
        return [d for d in v if isinstance(d, str)]
    return []


# ── P2-1 设备偏好持久化（后端单一真相，所有入口共享）────────────────────
#   用户在下拉里明确选过的设备 → audio_prefs.json（原始名字符串，RVC 按名精确匹配）。
#   语义：偏好是"粘性"的——设备拔掉时临时回退推荐但不改写偏好，插回来下次枚举自动恢复。
#   字段存在但为空串 = 用户明确选了「跟随系统默认」，同样要尊重（≠没保存过）。
_AUDIO_PREFS_FILE = Path(rf"{_BASE}\audio_prefs.json")
_AUDIO_PREFS_LOCK = threading.Lock()


def _audio_prefs_load() -> dict:
    try:
        d = json.loads(_AUDIO_PREFS_FILE.read_text(encoding="utf-8"))
        return d if isinstance(d, dict) else {}
    except Exception:
        return {}


def _audio_prefs_save(inp=None, out=None, src="") -> dict:
    """None=该项不动；字符串(含空串)=写入。返回保存后的完整偏好。
    P3-3 审计轨迹：每次「值真的变了」追加一条 history（最近 10 条），带来源(src)——
    排查『设备怎么自己变了』时能直接回答是谁在什么时候改的，而不是靠猜。"""
    with _AUDIO_PREFS_LOCK:
        d = _audio_prefs_load()
        hist = d.get("history") if isinstance(d.get("history"), list) else []
        now = round(time.time(), 2)
        for side, val in (("input", inp), ("output", out)):
            if val is None:
                continue
            new = str(val).strip()
            old = d.get(side)
            if old != new or side not in d:
                hist.append({"ts": now, "side": side,
                             "from": (old if isinstance(old, str) else None), "to": new,
                             "src": (str(src).strip()[:40] or "api")})
            d[side] = new
        d["history"] = hist[-10:]
        d["ts"] = now
        try:
            _AUDIO_PREFS_FILE.write_text(json.dumps(d, ensure_ascii=False, indent=1), encoding="utf-8")
        except Exception as e:
            d["_write_error"] = str(e)
        return d


def _pref_find_entry(pref: str, ex: dict):
    """偏好原始串 → 当前结构化枚举里的条目（value 或任一 hostapi 变体命中，忽略大小写/多空格）。"""
    if not pref:
        return None
    key = " ".join(pref.strip().lower().split())
    for e in (ex or {}).get("devices") or []:
        for c in [e.get("value")] + list(e.get("variants") or []):
            if isinstance(c, str) and " ".join(c.strip().lower().split()) == key:
                return e
    return None


def _merge_fresh_names(base: list, live: list):
    """P4-3 冻结表补洞（纯函数）：live(本地子进程即时枚举)有而 base(RVC 转换中冻结表)没有的名字
    追加到 base 末尾，并回传 fresh 名单。对比按规范化名（大小写/连续空格不敏感，同 _pref_find_entry）。
    只做 live-base 单向差：RVC 独有条目(LOOPBACK: 等)不受影响。"""
    def norm(s):
        return " ".join(str(s).strip().lower().split())
    seen = {norm(n) for n in (base or [])}
    fresh = [n for n in (live or [])
             if isinstance(n, str) and n.strip() and norm(n) not in seen]
    return list(base or []) + fresh, fresh


def _devices_payload(inp: list, out: list, source: str, note: str = "",
                     fresh_in: list = None, fresh_out: list = None) -> dict:
    """组装 /rvc/devices 响应：旧字段(原始名列表)原样保留(旧调用方零破坏)，
    附加 inputs_ex/outputs_ex 结构化人话层(device_enum 单一真相：去重/翻译/分组/推荐)
    + prefs(P2-1 已保存偏好及其在线状态，前端据此恢复选择/提示拔插)。
    fresh_in/out(P4-3)=转换运行中新插的设备名单 → 结构化条目标 fresh=True(前端 🆕 徽章)。
    结构化失败绝不影响旧字段(前端有旧渲染兜底)。
    P9 去重：PortAudio 会把长设备名截断，不同端点可能撞成同一字符串(如两个 WDM-KS 麦克风)——
    重名条目对「按名字选设备」的所有调用方(前端 select / RVC set_devices)本就只有第一个可达，
    保序去重零损失，且根治前端 x-for :key 重复导致的 Alpine 渲染崩溃(reading 'after')。"""
    inp = list(dict.fromkeys(inp or []))
    out = list(dict.fromkeys(out or []))
    res = {"ok": True, "input_devices": inp, "output_devices": out, "source": source}
    if note:
        res["rvc_note"] = note
    try:
        import device_enum
        ins_ex = device_enum.humanize_audio_devices(inp, "in")
        outs_ex = device_enum.humanize_audio_devices(out, "out")
        for ex, fresh in ((ins_ex, fresh_in), (outs_ex, fresh_out)):
            if not fresh:
                continue
            fs = {" ".join(str(n).strip().lower().split()) for n in fresh}
            for e in ex.get("devices") or []:
                cands = [e.get("value")] + list(e.get("variants") or [])
                if any(" ".join(str(c).strip().lower().split()) in fs for c in cands if c):
                    e["fresh"] = True
        if fresh_in or fresh_out:
            res["fresh_note"] = "检测到变声运行中新插的设备（🆕）——切换到它需重启变声，热切按钮可一键完成"
        ins_ex["pick"] = device_enum.pick_best(ins_ex["devices"], "in")
        outs_ex["pick"] = device_enum.pick_best(outs_ex["devices"], "out")
        res["inputs_ex"] = ins_ex
        res["outputs_ex"] = outs_ex
        p = _audio_prefs_load()
        pi, po = p.get("input"), p.get("output")
        ei = _pref_find_entry(pi or "", ins_ex)
        eo = _pref_find_entry(po or "", outs_ex)
        res["prefs"] = {
            "input": pi or "", "input_set": "input" in p,
            "input_present": bool(ei), "input_canon": (ei or {}).get("value") or "",
            "input_label": (ei or {}).get("label") or (device_enum.label_for(pi, "in") if pi else ""),
            "output": po or "", "output_set": "output" in p,
            "output_present": bool(eo), "output_canon": (eo or {}).get("value") or "",
            "output_label": (eo or {}).get("label") or (device_enum.label_for(po, "out") if po else ""),
        }
    except Exception as e:
        res["ex_note"] = f"humanize-failed:{e}"
    return res


@app.get("/rvc/devices")
def rvc_devices():
    """获取音频设备列表(供开播前置体检/自动选设备)。
    优先用 RVC 服务(其音频后端为准)；RVC 未启动/失败则本地 sounddevice 枚举兜底，
    确保 VB-Cable/手机麦在 RVC 离线时也能被检测到(修复"已装却显示未检测到虚拟声卡")。
    返回：旧字段 input_devices/output_devices + 结构化 inputs_ex/outputs_ex(人话层)。"""
    try:
        inp = _as_name_list(requests.get(f"{SERVICES['rvc']}/inputDevices",
                                         headers=_svc_req_headers(), timeout=5).json())
        out = _as_name_list(requests.get(f"{SERVICES['rvc']}/outputDevices",
                                         headers=_svc_req_headers(), timeout=5).json())
        if inp or out:
            fresh_in = fresh_out = None
            if _RVC_CONV.get("active"):
                # P4-3 转换中 RVC 设备表刻意冻结(防 PortAudio 重初始化炸流)——用本地子进程
                # 即时枚举补上「转换开始后新插」的设备；补进来的条目带 fresh 标(🆕,切换需重启变声)。
                try:
                    lins, louts = _local_audio_devices()
                    inp, fresh_in = _merge_fresh_names(inp, lins)
                    out, fresh_out = _merge_fresh_names(out, louts)
                except Exception:
                    pass
            return _devices_payload(inp, out, "rvc", fresh_in=fresh_in, fresh_out=fresh_out)
        raise RuntimeError("rvc returned empty")
    except Exception as e:
        try:
            ins, outs = _local_audio_devices()
            return _devices_payload(ins, outs, "local", note=str(e))
        except Exception as e2:
            return {"ok": False, "detail": f"rvc:{e} / local:{e2}"}

def _pick_audio_devices():
    """从当前可用设备(RVC优先,本地兜底)自动选最佳:输入=手机虚拟麦/普通麦(优先MME),
    输出=CABLE Input(虚拟麦, 优先MME)。返回 {input, output, inputs, outputs, source, *_label, *_reason}。
    P0: 首选 device_enum 结构化推荐(与 UI 同一真相)；结构化不可用时回退旧关键词链(行为兜底)。
    P2-1: 用户保存过的偏好(audio_prefs.json)最优先——在线就用它；不在线临时回退推荐并带
    *_pref_missing 标记(偏好本身不改写=粘性，设备插回来自动恢复)。"""
    dv = rvc_devices()
    inputs = dv.get("input_devices") or []
    outputs = dv.get("output_devices") or []
    ipick = (dv.get("inputs_ex") or {}).get("pick") or {}
    opick = (dv.get("outputs_ex") or {}).get("pick") or {}
    inp = ipick.get("value") or None
    out = opick.get("value") or None
    def first(cands, lst):
        for c in cands:
            for d in lst:
                if all(t.lower() in d.lower() for t in c):
                    return d
        return None
    if not inp:
        inp = first([["droid", "mme"], ["droid"], ["ivcam"], ["camo"], ["epoccam"],
                     ["蓝牙"], ["bluetooth"], ["hands-free"], ["麦克风", "mme"], ["麦克风"],
                     ["microphone", "mme"], ["mic"]], inputs) or (inputs[0] if inputs else None)
    if not out:
        out = first([["cable input", "mme"], ["cable input"], ["cable", "mme"], ["cable"]], outputs)
    res = {"input": inp, "output": out, "inputs": inputs, "outputs": outputs,
           "source": dv.get("source", ""),
           "input_label": ipick.get("label") or "", "input_reason": ipick.get("reason") or "",
           "output_label": opick.get("label") or "", "output_reason": opick.get("reason") or ""}
    # ── P2-1 偏好套用（在推荐之上）──
    pf = dv.get("prefs") or {}
    for side, key_dev in (("input", "in"), ("output", "out")):
        if not pf.get(f"{side}_set"):
            continue
        want = pf.get(side) or ""
        if not want:      # 显式选了「跟随系统默认」→ 不强塞推荐
            res[side] = None
            res[f"{side}_label"] = "跟随系统默认"
            res[f"{side}_reason"] = "你选择了跟随系统默认"
            continue
        if pf.get(f"{side}_present"):
            res[side] = pf.get(f"{side}_canon") or want
            res[f"{side}_label"] = pf.get(f"{side}_label") or want
            res[f"{side}_reason"] = "你上次选定的设备"
        else:             # 偏好设备当前不在线：临时回退推荐，并把缺席信息带出去
            res[f"{side}_pref_missing"] = {"value": want, "label": pf.get(f"{side}_label") or want}
    return res


@app.get("/api/audio/prefs")
def api_audio_prefs_get():
    """读取已保存的音频设备偏好（原始名 + 保存时间）。"""
    return {"ok": True, "prefs": _audio_prefs_load()}


@app.post("/api/audio/prefs")
def api_audio_prefs_set(body: dict = {}):
    """保存用户明确选择的音频设备（P2-1 持久化）。body 里出现哪个键就写哪个：
    input/output = 原始设备名；空串 = 用户选了「跟随系统默认」；键不出现 = 该项不动。
    src(可选) = 改动来源（如 ui-pick / phone-setup），进 P3-3 审计轨迹。"""
    inp = body.get("input") if "input" in (body or {}) else None
    out = body.get("output") if "output" in (body or {}) else None
    if inp is None and out is None:
        return {"ok": False, "detail": "input/output 至少给一个"}
    d = _audio_prefs_save(inp, out, src=str((body or {}).get("src") or ""))
    return {"ok": "_write_error" not in d, "prefs": d}


# ── P4-2 缺席→热切漏斗度量：验证「10 秒手工恢复压到 1 键」的真实达成率 ─────────────
# 曝光(缺席警告条带热切按钮亮出)→点击→成功/失败，按天分桶 + 总计 + 来源细分(strip/diag/back/fresh-pick)。
# 本地 JSON 落盘（离线可用、无外部依赖）；前端埋点 fire-and-forget，丢一两条不影响大盘。
_DEVFLOW_PATH = Path(rf"{_BASE}\data\devflow_stats.json")
_DEVFLOW_LOCK = threading.Lock()
_DEVFLOW_EVS = ("expose", "click", "ok", "fail")
# P8-2 建议条（P7-2「建议开启自动热切」）效果埋点：曝光/采纳/婉拒。刻意不复用 expose/click——
# 建议条不是设备缺席事件，混进主漏斗会污染达成率与 P7-2 裁决的「人工战绩」分母。
# 同一本账（同文件/同端点/同周报），但独立键（advice_* 不带 in/out 后缀）。
_DEVFLOW_ADVICE_EVS = ("advice_expose", "advice_enable", "advice_dismiss")


def _devflow_bump_core(doc: dict, ev: str, kind: str, src: str, day: str, max_days: int = 60) -> dict:
    """纯函数：一次漏斗事件记入 doc（days[day] 分桶 + total 总计 + 来源细分）。非法输入原样返回。
    主漏斗事件键=ev_kind；建议条事件（advice_*）不分 in/out，键=ev 本身。"""
    if ev in _DEVFLOW_ADVICE_EVS:
        key = ev
    elif ev in _DEVFLOW_EVS and kind in ("in", "out"):
        key = f"{ev}_{kind}"
    else:
        return doc
    doc = doc if isinstance(doc, dict) else {}
    days = doc.setdefault("days", {})
    if not isinstance(days, dict):
        days = doc["days"] = {}
    b = days.setdefault(day, {})
    b[key] = int(b.get(key) or 0) + 1
    s = str(src or "").strip()[:24]
    if s:
        srcs = b.setdefault("src", {})
        srcs[f"{ev}:{s}"] = int(srcs.get(f"{ev}:{s}") or 0) + 1
    if len(days) > max_days:                       # 只留最近 N 天，文件不长毛
        for k in sorted(days)[:len(days) - max_days]:
            days.pop(k, None)
    tot = doc.setdefault("total", {})
    tot[key] = int(tot.get(key) or 0) + 1
    return doc


def _devflow_funnel(doc: dict) -> dict:
    """总计漏斗速览：曝光→点击→成功 计数与转化率（除零安全）。"""
    t = (doc or {}).get("total") or {}
    def g(ev):
        return int(t.get(f"{ev}_in") or 0) + int(t.get(f"{ev}_out") or 0)
    ex, ck, ok, fl = g("expose"), g("click"), g("ok"), g("fail")
    return {"expose": ex, "click": ck, "ok": ok, "fail": fl,
            "click_rate": (round(ck / ex, 3) if ex else None),
            "success_rate": (round(ok / ck, 3) if ck else None)}


def _devflow_suggest_auto(doc: dict, enabled: bool,
                          min_expose: int = 3, min_click: int = 3, min_rate: float = 0.95) -> dict:
    """P7-2 「建议开启自动热切」裁决（纯函数）：只看**人工**热切的战绩（剔除 src=auto 的分量——
    自动切自己刷的数据不能当自己的开启依据）。
    计数与 src 扣减统一从 60 天分桶聚合（终身 total 与分桶窗口不一致会把久远历史算进「近期战绩」；
    推荐本来就该看当下环境，超窗旧账不作数）。
    建议条件：开关未开 + 人工缺席曝光≥3 + 人工点击≥3 + 人工成功率≥95%。
    返回 {suggest, reason, manual:{expose,click,ok,fail,rate}} —— reason 供前端直接展示人话。"""
    cnt, src_total = {}, {}
    for b in ((doc or {}).get("days") or {}).values():
        if not isinstance(b, dict):
            continue
        for k, n in b.items():
            if k == "src":
                for sk, sv in (n or {}).items():
                    src_total[sk] = src_total.get(sk, 0) + int(sv or 0)
            else:
                cnt[k] = cnt.get(k, 0) + int(n or 0)
    man = {}
    for ev in ("expose", "click", "ok", "fail"):
        total = cnt.get(f"{ev}_in", 0) + cnt.get(f"{ev}_out", 0)
        man[ev] = max(0, total - src_total.get(f"{ev}:auto", 0))
    rate = (man["ok"] / man["click"]) if man["click"] else None
    man["rate"] = (round(rate, 3) if rate is not None else None)
    if enabled:
        return {"suggest": False, "reason": "已开启", "manual": man}
    if man["expose"] < min_expose or man["click"] < min_click:
        return {"suggest": False, "reason": "样本不足", "manual": man}
    if rate is None or rate < min_rate:
        return {"suggest": False, "reason": "人工成功率未达标", "manual": man}
    return {"suggest": True,
            "reason": (f"你已手动热切 {man['click']} 次、成功率 {round(rate * 100)}%"
                       f"——环境适合开启自动热切（拔线约 25 秒后自动恢复，无需人在场）"),
            "manual": man}


def _devflow_bump_local(ev: str, kind: str, src: str = "") -> dict:
    """服务端直调的漏斗记账（P6-1 自动热切与前端埋点同一本账）：锁内读改写 devflow_stats.json。"""
    if not (ev in _DEVFLOW_ADVICE_EVS or (ev in _DEVFLOW_EVS and kind in ("in", "out"))):
        return {"ok": False, "detail": "ev/kind 非法"}
    with _DEVFLOW_LOCK:
        try:
            doc = json.loads(_DEVFLOW_PATH.read_text(encoding="utf-8"))
        except Exception:
            doc = {}
        doc = _devflow_bump_core(doc, ev, kind, src, time.strftime("%Y-%m-%d"))
        try:
            _DEVFLOW_PATH.parent.mkdir(parents=True, exist_ok=True)
            _DEVFLOW_PATH.write_text(json.dumps(doc, ensure_ascii=False, indent=1), encoding="utf-8")
        except Exception as e:
            return {"ok": False, "detail": f"写入失败:{e}"}
    return {"ok": True}


@app.post("/api/metrics/devflow")
def api_devflow_bump(body: dict = {}):
    """P4-2 漏斗埋点：ev=expose|click|ok|fail(kind=in|out, src 可选) 或 P8-2 建议条事件
    ev=advice_expose|advice_enable|advice_dismiss（不带 kind）。"""
    return _devflow_bump_local(str((body or {}).get("ev") or ""),
                               str((body or {}).get("kind") or ""),
                               str((body or {}).get("src") or ""))


def _devflow_advice_total(doc: dict) -> dict:
    """P8-2 建议条效果跨天聚合（纯函数）：曝光/采纳/婉拒 + 采纳率（除零安全）。"""
    agg = {ev: 0 for ev in _DEVFLOW_ADVICE_EVS}
    for b in ((doc or {}).get("days") or {}).values():
        if isinstance(b, dict):
            for ev in _DEVFLOW_ADVICE_EVS:
                agg[ev] += int(b.get(ev) or 0)
    ex = agg["advice_expose"]
    return {"expose": ex, "enable": agg["advice_enable"], "dismiss": agg["advice_dismiss"],
            "enable_rate": (round(agg["advice_enable"] / ex, 3) if ex else None)}


@app.get("/api/metrics/devflow")
def api_devflow_get():
    """漏斗读数：总计+今天+速览转化率+来源跨天聚合（ops「设备自愈漏斗」卡与验收用）。"""
    try:
        doc = json.loads(_DEVFLOW_PATH.read_text(encoding="utf-8"))
    except Exception:
        doc = {}
    day = time.strftime("%Y-%m-%d")
    src_total = {}                       # 跨天聚合来源细分（ev:src → n）：total 里没有，从分桶收
    for b in (doc.get("days") or {}).values():
        for k, n in (b.get("src") or {}).items():
            src_total[k] = src_total.get(k, 0) + int(n or 0)
    return {"ok": True, "funnel": _devflow_funnel(doc),
            "today": (doc.get("days") or {}).get(day) or {},
            "total": doc.get("total") or {}, "src_total": src_total,
            "auto_advice": _devflow_suggest_auto(doc, _DEV_AUTOSW_ON),   # P7-2 数据驱动的开启建议
            "advice": _devflow_advice_total(doc),                        # P8-2 建议条效果（曝光/采纳/婉拒）
            "days_kept": len(doc.get("days") or {})}


# ── P6-2 设备自愈漏斗周报：把达成率推进 alerts 通道，运营不开看板也看得见 ──────────
_DEVFLOW_WEEKLY_ON   = os.environ.get("HUB_DEVFLOW_WEEKLY", "1") == "1"
_DEVFLOW_WEEKLY_HOUR = int(os.environ.get("HUB_DEVFLOW_WEEKLY_HOUR", "9") or 9)   # 周一 ≥N 点发


def _devflow_week_report(doc: dict, today=None) -> dict:
    """上一自然周（周一~周日）漏斗聚合（纯函数，today 可注入供测试）：计数/转化率/来源/覆盖天数。"""
    import datetime as _dt
    today = today or _dt.date.today()
    monday_prev = today - _dt.timedelta(days=today.weekday() + 7)
    days = (doc or {}).get("days") or {}
    agg, src, n_days = {}, {}, 0
    for i in range(7):
        b = days.get((monday_prev + _dt.timedelta(days=i)).isoformat())
        if not isinstance(b, dict):
            continue
        n_days += 1
        for k, v in b.items():
            if k == "src":
                for sk, sv in (v or {}).items():
                    src[sk] = src.get(sk, 0) + int(sv or 0)
            else:
                agg[k] = agg.get(k, 0) + int(v or 0)
    def g(ev):
        return agg.get(f"{ev}_in", 0) + agg.get(f"{ev}_out", 0)
    ex, ck, ok, fl = g("expose"), g("click"), g("ok"), g("fail")
    return {"span": f"{monday_prev.isoformat()}~{(monday_prev + _dt.timedelta(days=6)).isoformat()}",
            "monday": monday_prev.isoformat(),
            "expose": ex, "click": ck, "ok": ok, "fail": fl,
            "click_rate": (round(ck / ex, 3) if ex else None),
            "success_rate": (round(ok / ck, 3) if ck else None),
            # P8-2 建议条效果（周窗）：数据说服的转化率——advice_* 键独立于主漏斗，不污染上面的率
            "advice": {"expose": agg.get("advice_expose", 0),
                       "enable": agg.get("advice_enable", 0),
                       "dismiss": agg.get("advice_dismiss", 0)},
            "src": src, "days_active": n_days}


def _devflow_week_text(rep: dict) -> str:
    """周报正文（人话）：一眼看到达成率；零事件周如实说「链路健康」而不是发一堆 0。"""
    def pct(v):
        return "—" if v is None else f"{round(v * 100)}%"
    lines = [f"统计窗 {rep['span']}"]
    adv = rep.get("advice") or {}
    adv_any = adv.get("expose") or adv.get("enable") or adv.get("dismiss")
    if not (rep["expose"] or rep["click"] or rep["ok"] or rep["fail"]):
        lines.append("本周设备从未缺席、零热切需求——设备链路健康")
    else:
        lines.append(f"曝光 {rep['expose']} → 点击 {rep['click']} → 成功 {rep['ok']}"
                     + (f"（失败 {rep['fail']}）" if rep["fail"] else ""))
        lines.append(f"点击率 {pct(rep['click_rate'])} · 成功率 {pct(rep['success_rate'])}")
        if rep.get("src"):
            top = sorted(rep["src"].items(), key=lambda kv: -kv[1])[:6]
            lines.append("来源: " + "  ".join(f"{k}×{v}" for k, v in top))
    if adv_any:   # P8-2 只有真发生过才占一行——多数周该行不出现
        lines.append(f"开启建议：曝光 {adv.get('expose', 0)} · 采纳 {adv.get('enable', 0)}"
                     f" · 婉拒 {adv.get('dismiss', 0)}")
    return "\n".join(lines)


def _devflow_weekly_send(force: bool = False) -> dict:
    """聚合上周漏斗并经 alerts 外发。自动路径（force=False）三道闸：本周已发过(标记在
    devflow 文件里,跨重启去重)/无 webhook 通道/正文构建失败——都只跳过不报错。
    force=True（手动端点）：跳过去重与通道闸真发一次，且不占用本周自动额度。"""
    try:
        import alerts as _al
    except Exception as e:
        return {"ok": False, "detail": f"alerts 不可用: {e}"}
    with _DEVFLOW_LOCK:
        try:
            doc = json.loads(_DEVFLOW_PATH.read_text(encoding="utf-8"))
        except Exception:
            doc = {}
    rep = _devflow_week_report(doc)
    if not force:
        if doc.get("weekly_sent") == rep["monday"]:
            return {"ok": True, "sent": 0, "skipped": "already_sent", "report": rep}
        if _al.channels().get("webhook_count", 0) <= 0:
            return {"ok": True, "sent": 0, "skipped": "no_webhook", "report": rep}
    sent = _al.notify_event("设备自愈漏斗周报", detail=_devflow_week_text(rep),
                            level="info", source="设备自愈")
    if not force:                    # 发送已发生（notify_event 不抛）→ 记「本周已发」，30min 后不重发
        with _DEVFLOW_LOCK:
            try:
                doc2 = json.loads(_DEVFLOW_PATH.read_text(encoding="utf-8"))
            except Exception:
                doc2 = {}
            doc2["weekly_sent"] = rep["monday"]
            try:
                _DEVFLOW_PATH.parent.mkdir(parents=True, exist_ok=True)
                _DEVFLOW_PATH.write_text(json.dumps(doc2, ensure_ascii=False, indent=1),
                                         encoding="utf-8")
            except Exception:
                pass
    return {"ok": True, "sent": sent, "report": rep}


@app.get("/api/metrics/devflow/weekly")
def api_devflow_weekly(send: int = 0):
    """上周设备自愈漏斗周报：默认只读（结构化报文+文本预览+自动发送状态）；
    send=1 立即真外发一次（走 webhook+本地弹窗，不占本周自动额度——测试/补发用）。"""
    if send:
        r = _devflow_weekly_send(force=True)
        if r.get("report"):
            r["text"] = _devflow_week_text(r["report"])
        return r
    with _DEVFLOW_LOCK:
        try:
            doc = json.loads(_DEVFLOW_PATH.read_text(encoding="utf-8"))
        except Exception:
            doc = {}
    rep = _devflow_week_report(doc)
    return {"ok": True, "report": rep, "text": _devflow_week_text(rep),
            "weekly_auto": {"enabled": _DEVFLOW_WEEKLY_ON, "hour": _DEVFLOW_WEEKLY_HOUR,
                            "alerts_on": _SH_ALERTS_ON,
                            "last_sent_week": str(doc.get("weekly_sent") or "")}}


async def _bg_devflow_weekly():
    """P6-2 周报守护：每 30min 看表，周一 ≥HUB_DEVFLOW_WEEKLY_HOUR 点后补发式触发
    （hub 周一 9 点不在线也不丢报：当天任意时刻起来都会补发；去重标记跨重启）。"""
    await asyncio.sleep(45.0)
    while True:
        try:
            if _DEVFLOW_WEEKLY_ON and _SH_ALERTS_ON:
                lt = time.localtime()
                if lt.tm_wday == 0 and lt.tm_hour >= _DEVFLOW_WEEKLY_HOUR:
                    r = await asyncio.to_thread(_devflow_weekly_send)
                    if r.get("sent"):
                        _logger.info(f"[DevflowWeekly] 周报已外发 {r.get('sent')} 通道 "
                                     f"({(r.get('report') or {}).get('span')})")
        except Exception as exc:
            _logger.warning(f"[DevflowWeekly] 异常: {exc}")
        await asyncio.sleep(1800)


