# ── P1 试音三件套：选完设备当场验证，告别「开播才知道翻车」──────────────────
#   ① mic_test：录选中麦 N 秒 → 电平/噪声底/SNR + 人话结论 + 可回放 wav
#   ② output_test：向选中输出播 1s 提示音（人耳确认前/后面板、耳机）；
#      目标是 CABLE 时人耳听不到 → 同时并行录 CABLE Output 自证回环（观众能听到✓），
#      不依赖"直播中才开"的 OBS 馈线探针，开播前就能验。
_AUDIO_TEST_LOCK = threading.Lock()


@app.get("/api/audio/mic_test")
async def api_audio_mic_test(device: str = "", secs: float = 3.0, wav: int = 1):
    """试音：录制选中(或默认)麦克风 secs 秒，返回电平指标 + 一句话结论 (+ 回放 wav_b64)。
    P10：录音走 dev_probe 子进程——正是这个端点诊断出的原生崩溃(PortAudio/虚拟声卡 DLL)
    曾带走整个 Hub、用户看到「Failed to fetch」。现在崩也只崩子进程，本端点返回人话错误。"""
    secs = max(1.0, min(6.0, float(secs)))
    if not _AUDIO_TEST_LOCK.acquire(blocking=False):
        return {"ok": False, "detail": "另一个试音/试听正在进行，稍候再试"}
    if not _CHECKUP_MIC_LOCK.acquire(blocking=False):   # 与设备体检抢同一只麦，互斥防互顶
        _AUDIO_TEST_LOCK.release()
        return {"ok": False, "detail": "设备体检录音进行中，稍候再试"}
    try:
        r = await asyncio.to_thread(
            _dev_probe, ["mic_rec", "--secs", secs, "--device", device, "--wav", int(bool(wav))],
            secs + 25.0)
        if not r.get("ok"):
            return {"ok": False, "detail": r.get("detail") or "录音探测失败(设备驱动异常)"}
        floor_db, speech_db = r["floor_dbfs"], r["speech_dbfs"]
        peak, snr = r["peak_dbfs"], r["snr_db"]
        if peak <= -70:
            level, verdict = "bad", "几乎没收到声音：确认这只麦没静音、也没选错设备"
        elif peak > -3:
            level, verdict = "warn", "电平太高容易破音：离麦远一点或调低增益"
        elif snr >= 12 and speech_db > -40:
            level, verdict = "good", "收音正常，人声清晰"
        elif speech_db > -45:
            level, verdict = "warn", "有声音但偏小：靠近麦克风或调大系统麦克风音量"
        else:
            level, verdict = "warn", "只收到环境底噪：对着它说句话再测一次"
        res = {"ok": True, "device": device or "系统默认输入",
               "resolved_index": r.get("resolved_index"),
               "floor_dbfs": floor_db, "speech_dbfs": speech_db,
               "peak_dbfs": peak, "snr_db": snr,
               "level": level, "verdict": verdict, "secs": secs}
        if wav and r.get("wav_b64"):
            res["wav_b64"] = r["wav_b64"]
        return res
    except Exception as e:
        return {"ok": False, "detail": str(e)[:200]}
    finally:
        _CHECKUP_MIC_LOCK.release()
        _AUDIO_TEST_LOCK.release()


@app.get("/api/audio/output_test")
async def api_audio_output_test(device: str = "", secs: float = 1.0):
    """试听：向选中(或默认)输出播放一段「叮」提示音。
    输出名含 cable 时并行录 CABLE Output 自证回环：probe.heard=True ⇒ 观众能听到。
    P10：播放+回环整段走 dev_probe 子进程(sd.play/InputStream 同属崩过的原生栈)。"""
    secs = max(0.4, min(2.0, float(secs)))
    if not _AUDIO_TEST_LOCK.acquire(blocking=False):
        return {"ok": False, "detail": "另一个试音/试听正在进行，稍候再试"}
    if not _CHECKUP_MIC_LOCK.acquire(blocking=False):   # 播放会顶掉体检录音，互斥
        _AUDIO_TEST_LOCK.release()
        return {"ok": False, "detail": "设备体检录音进行中，稍候再试"}
    try:
        want_probe = "cable" in (device or "").lower()
        r = await asyncio.to_thread(
            _dev_probe, ["output_test", "--secs", secs, "--device", device], secs + 25.0)
        if not r.get("ok"):
            return {"ok": False, "detail": r.get("detail") or "播放探测失败(设备驱动异常)"}
        res = {"ok": True, "device": device or "系统默认输出",
               "resolved_index": r.get("resolved_index"),
               "secs": secs, "samplerate": r.get("samplerate"),
               "hint": ("直播声卡走的是虚拟线路，人耳听不到；看 probe.heard 确认观众侧"
                        if want_probe else "听到「叮」= 就是这个设备；没听到就换一个再试")}
        if r.get("probe") is not None:
            res["probe"] = r["probe"]
        return res
    except Exception as e:
        return {"ok": False, "detail": str(e)[:200]}
    finally:
        _CHECKUP_MIC_LOCK.release()
        _AUDIO_TEST_LOCK.release()


# ── Phase 12 D-1 设备体检分：麦(噪声底/SNR) + 摄像头(活帧/脸占比) + CABLE → 开播总分 ──
#   复用现有信号源：sounddevice(已被 _pick_audio_devices 依赖)、realtime_status/camera_status
#   文件、realtime_stream /swap/quality、VB 向导的 CABLE 设备检测。quick=1 免录音(<1s,供
#   launcher 轮询)；完整模式录 mic_secs 秒算噪声底与说话电平。
_CHECKUP_MIC_LOCK = threading.Lock()


def _resolve_audio_device(name: str, kind: str = "in"):
    """RVC 风格设备名('基名 (MME)') → sounddevice 设备索引；空名/找不到返回 None(=系统默认)。
    匹配顺序：全名精确 → 基名精确/前缀(容 MME 31 字符截断)，hostapi 一致者优先，MME 次优。
    P10：设备名→索引解析需要 sounddevice 枚举(原生栈)，改经 dev_probe 子进程(逻辑在
    tools/dev_probe.py resolve 子命令，与此前 Hub 内实现同一套匹配规则)。"""
    if not name or name.startswith("LOOPBACK:"):
        return None
    r = _dev_probe(["resolve", "--name", name, "--kind", kind], timeout=15.0)
    return r.get("index") if r.get("ok") else None


def _checkup_mic_sample(secs: float, device_name: str = "") -> dict:
    """指定(或默认)输入设备录 secs 秒(16k 单声道)：噪声底(P20)/说话电平(P95)/峰值/估算 SNR。
    device_name: 设备名(探测子进程内解析)；空=系统默认。
    P10：录音走 dev_probe 子进程；失败抛 RuntimeError(调用方 except 分支语义不变)。"""
    r = _dev_probe(["mic_rec", "--secs", secs, "--device", device_name or ""],
                   timeout=float(secs) + 25.0)
    if not r.get("ok"):
        raise RuntimeError(r.get("detail") or "录音探测失败(设备驱动异常)")
    return r


def _checkup_item(key, label, score, max_pts, level, detail, advice="", measured=True):
    return {"key": key, "label": label, "score": score, "max": max_pts,
            "level": level, "detail": detail, "advice": advice, "measured": measured}


# ── 观察自动化 IV：体检结果留痕（量化「红灯误拦」）───────────────────────
#   痛点：体检结果只在浏览器里活一瞬，真人观察项「体检卡点有无误拦」全靠人记。留痕后与场次账本
#   (swap_sessions.jsonl)按时间联查：红灯 → 10 分钟内照样开播且场次健康 = 疑似误拦，机器可数。
_CHECKUP_LOG_PATH = Path(rf"{_BASE}\logs\device_checkups.jsonl")
_CHECKUP_LOG_MAX = 500
_checkup_log_lock = threading.Lock()


def _checkup_log_append(rec: dict) -> None:
    """best-effort 追加一条体检留痕；写多读少，超限截半。任何失败不影响体检响应。"""
    try:
        _CHECKUP_LOG_PATH.parent.mkdir(parents=True, exist_ok=True)
        with _checkup_log_lock:
            with open(_CHECKUP_LOG_PATH, "a", encoding="utf-8") as f:
                f.write(json.dumps(rec, ensure_ascii=False) + "\n")
            try:
                lines = _CHECKUP_LOG_PATH.read_text(encoding="utf-8").splitlines()
                if len(lines) > _CHECKUP_LOG_MAX + 100:
                    _CHECKUP_LOG_PATH.write_text(
                        "\n".join(lines[-_CHECKUP_LOG_MAX // 2:]) + "\n", encoding="utf-8")
            except Exception:
                pass
    except Exception:
        pass


@app.get("/api/device/checkup")
async def api_device_checkup(quick: int = 0, mic_secs: float = 3.0, src: str = "", device: str = ""):
    """D-1 设备体检分：麦 40 + 摄像头 40 + CABLE 20，按「可测项」归一成 0-100 总分。
    quick=1 免录音免画质探测(<1s)；总分 = Σ得分/Σ可测满分×100；不可测项标 measured:false 并给指引。
    src=gate/manual 时留痕到 device_checkups.jsonl（launcher 30s 轮询不带 src → 不落账,防刷屏/污染误拦分母）。
    device=用户选中的输入设备名（P0 修 bug：此前录音永远打系统默认麦，测的不是选中那只）。"""
    t0 = time.time()
    items = []
    mic_secs = max(1.0, min(8.0, float(mic_secs)))

    # ① 设备枚举(麦/CABLE 共用)：sounddevice 线程化，不卡事件循环
    try:
        picked = await asyncio.to_thread(_pick_audio_devices)
    except Exception as e:
        picked = {"inputs": [], "outputs": [], "error": str(e)[:100]}
    ins = picked.get("inputs") or []
    outs = picked.get("outputs") or []
    phys_ins = [d for d in ins if "cable output" not in (d or "").lower()]

    # ② 麦克风(40)：设备存在 10 + 采样活性 10 + 噪声底 20
    if not phys_ins:
        items.append(_checkup_item("mic", "麦克风", 0, 40, "bad",
                                   "未枚举到物理输入设备", "接上/启用麦克风后重测"))
    elif quick:
        items.append(_checkup_item("mic", "麦克风", 10, 10, "good",
                                   f"设备在位：{device or phys_ins[0]}", "", True))
    else:
        mic_pts, mic_lvl, mic_adv = 10, "good", ""
        det = f"设备：{device}" if device else "设备：系统默认输入"
        if not _CHECKUP_MIC_LOCK.acquire(blocking=False):
            items.append(_checkup_item("mic", "麦克风", 10, 10, "warn",
                                       det + " · 录音口被占用(另一体检进行中)", "稍后重测"))
        else:
            try:
                # P10：录音+设备名解析都在 dev_probe 子进程里完成(原生栈隔离)
                s = await asyncio.to_thread(_checkup_mic_sample, mic_secs, device)
                if device and s.get("resolved_index") is None:
                    det = "设备：系统默认输入"   # 名字没匹配上，实际录的是默认麦
                det += (f" · 噪声底 {s['floor_dbfs']}dBFS · 峰值 {s['peak_dbfs']}dBFS"
                        + (f" · 说话信噪比≈{s['snr_db']}dB" if s["snr_db"] >= 12 else ""))
                if s["peak_dbfs"] <= -70:
                    mic_lvl, mic_adv = "bad", "整段近乎数字静音：检查系统麦克风静音/权限/选错设备"
                else:
                    mic_pts += 10
                fl = s["floor_dbfs"]
                if fl <= -55:
                    mic_pts += 20
                elif fl <= -45:
                    mic_pts += 15
                    mic_lvl = "good" if mic_lvl == "good" else mic_lvl
                elif fl <= -38:
                    mic_pts += 8
                    mic_lvl, mic_adv = "warn", mic_adv or "环境噪声偏高：关空调/风扇或换指向性麦"
                else:
                    mic_pts += 4
                    mic_lvl, mic_adv = "warn", mic_adv or "环境噪声大：建议降噪耳麦或换安静环境"
                items.append(_checkup_item("mic", "麦克风", mic_pts, 40, mic_lvl, det, mic_adv))
            except Exception as e:
                items.append(_checkup_item("mic", "麦克风", 10, 40, "warn",
                                           det + f" · 录音失败: {str(e)[:80]}",
                                           "确认无独占占用后重测"))
            finally:
                _CHECKUP_MIC_LOCK.release()

    # ③ 摄像头(40)：开播活帧 20 + 脸占比 20(复用 /swap/quality)；未开播只可测配置在位
    streaming = bool(_realtime_proc and _realtime_proc.poll() is None)
    fps = 0.0
    fresh = False
    try:
        _p = Path(rf"{_BASE}\realtime_status.json")
        if _p.exists():
            _m = json.loads(_p.read_text(encoding="utf-8"))
            fps = float(_m.get("real_fps", _m.get("fps", 0)) or 0)
            fresh = (time.time() - float(_m.get("ts", 0) or 0)) < 10.0
    except Exception:
        pass
    if not streaming:
        items.append(_checkup_item("camera", "摄像头", 0, 0, "unknown",
                                   "未开播：活帧/脸占比需开播后可测",
                                   "点「一键开播」后重测得完整相机分", False))
    else:
        cam_pts, cam_lvl, cam_adv = 0, "good", ""
        det = f"真新帧 {fps:.1f}fps"
        if fresh and fps >= 10:
            cam_pts += 20
        elif fresh and fps >= 7:
            cam_pts += 15
            cam_lvl, cam_adv = "warn", "帧率偏低：降低分辨率/画质档或检查摄像头占用"
        elif fresh and fps > 0:
            cam_pts += 8
            cam_lvl, cam_adv = "warn", "帧率过低：画面会明显卡顿，先降档"
        else:
            cam_lvl, cam_adv = "bad", "画面停更：摄像头掉线/被占用，重选摄像头或重启开播"
        face_max = 0 if quick else 20
        if not quick:
            try:
                r = await http_pool.get(f"{_RT_SWAP_BASE}/swap/quality", timeout=4.5)
                q = r.json()
                if q.get("ok"):
                    fh = float(q.get("face_h") or 0)
                    frame_h = float(q.get("frame_h") or 720)
                    ratio = fh / frame_h if frame_h else 0
                    det += f" · 脸高占比 {ratio:.0%}"
                    if 0.22 <= ratio <= 0.80:
                        cam_pts += 20
                    elif ratio > 0:
                        cam_pts += 10
                        if cam_lvl == "good":
                            cam_lvl = "warn"
                        cam_adv = cam_adv or ("脸太小：拉近镜头到半身构图" if ratio < 0.22
                                              else "脸太大：稍微离远一点")
                else:
                    det += " · " + str(q.get("advice") or "近期未检出人脸")[:60]
                    cam_lvl = "warn" if cam_lvl == "good" else cam_lvl
                    cam_adv = cam_adv or "把脸对准镜头、光线打亮后重测"
            except Exception:
                face_max = 0
                det += " · 画质探针不可达(仅计活帧分)"
        items.append(_checkup_item("camera", "摄像头", cam_pts, 20 + face_max, cam_lvl, det, cam_adv))

    # ④ CABLE(20)：驱动在位 15 + 直播馈线有声 5(复用 /realtime/signal 的缓存口径)
    cable_out = any("cable" in (d or "").lower() for d in outs)
    cable_in = any("cable output" in (d or "").lower() for d in ins)
    cb_pts = (10 if cable_out else 0) + (5 if cable_in else 0)
    cb_lvl = "good" if cable_out else "bad"
    cb_det = ("CABLE Input 在位" if cable_out else "未检测到 VB-Cable") + \
             (" · 采集口(CABLE Output)在位" if cable_in else "")
    cb_adv = "" if cable_out else "装 VB-Cable 后变声/同传才能进直播：设置页有向导"
    cb_max = 15
    if streaming:
        cb_max = 20
        rms = float((_SIGNAL_CABLE_CACHE.get("data") or {}).get("rms") or 0)
        if rms > 0.008:
            cb_pts += 5
            cb_det += f" · 直播馈线有声(rms {rms:.3f})"
        else:
            cb_det += " · 直播馈线暂无声"
            if cb_lvl == "good":
                cb_lvl = "warn"
            cb_adv = cb_adv or "开播中但 CABLE 没声：确认变声输出指向 CABLE Input(说句话再测)"
    items.append(_checkup_item("cable", "虚拟声卡(CABLE)", cb_pts, cb_max, cb_lvl, cb_det, cb_adv))

    # ⑤ 声纹锁(10)：2026-07-15 哑播事故的根因(底座失真拦光主播语音)恰是体检盲区——补上。
    #    影子模式=bad(底座已失真在降级放行)；底座过老/换麦=warn；未注册/同传未跑=不计分(新用户自动注册属正常)。
    try:
        # timeout 1.5→4s：interp 配音中 /status 常超 1.5s，超时会把"已注册"误报成"未注册"
        _ij = (await http_pool.get(os.environ.get("INTERP_URL", "http://127.0.0.1:7900") + "/status",
                                   timeout=4.0)).json()
        _vl = _ij.get("voicelock") or {}
        if not _vl.get("enabled") or not _vl.get("enrolled"):
            items.append(_checkup_item("voicelock", "声纹锁", 0, 0, "unknown",
                                       "未注册(开口说 3 句自动注册)或未启用", "", False))
        elif _vl.get("shadow"):
            items.append(_checkup_item("voicelock", "声纹锁", 0, 10, "bad",
                                       f"影子模式运行中：底座疑似失真已临时放行(影子放行 {_vl.get('shadow_passes', 0)} 句)",
                                       "同传页点「重置声纹」后正常说 3 句重新注册"))
        else:
            _age_h = ((time.time() - float(_vl.get("base_ts") or 0)) / 3600.0
                      if _vl.get("base_ts") else None)
            if _age_h is not None and _age_h >= 72:
                items.append(_checkup_item("voicelock", "声纹锁", 5, 10, "warn",
                                           f"底座已 {_age_h / 24:.1f} 天未更新(环境/设备可能已变)",
                                           "若开口被拦请重置声纹重新注册"))
            else:
                items.append(_checkup_item("voicelock", "声纹锁", 10, 10, "good",
                                           f"底座正常(样本 {_vl.get('n', '?')} 段 · 放行 {_vl.get('accepts', 0)} "
                                           f"拦 {_vl.get('rejects', 0)})", ""))
    except Exception:
        items.append(_checkup_item("voicelock", "声纹锁", 0, 0, "unknown",
                                   "同传服务未运行(本项跳过)", "", False))

    measured_max = sum(i["max"] for i in items if i["measured"])
    got = sum(i["score"] for i in items if i["measured"])
    score = round(100.0 * got / measured_max) if measured_max else 0
    grade = "green" if score >= 80 else ("yellow" if score >= 60 else "red")
    verdict = {"green": "✅ 可开播", "yellow": "⚠ 可开播，建议先处理提示项",
               "red": "⛔ 建议处理后再开播"}[grade]
    # 留痕(观察自动化 IV)：只记「人触发」的体检(src=gate 开播卡点/manual 手动)。launcher 状态灯
    # 30s 轮询与 soak 探针不带 src → 不落账，否则误拦分母被机器刷爆、trim 又会把真卡点冲掉。
    if src in ("gate", "manual"):
        _checkup_log_append({
            "ts": round(time.time(), 1), "src": src, "quick": bool(quick), "streaming": streaming,
            "score": score, "grade": grade,
            "bad": [i["key"] for i in items if i["measured"] and i["level"] == "bad"],
            "warn": [i["key"] for i in items if i["measured"] and i["level"] == "warn"]})
    return {"ok": True, "score": score, "grade": grade, "verdict": verdict,
            "quick": bool(quick), "streaming": streaming, "items": items,
            "took_ms": int((time.time() - t0) * 1000)}


def _checkup_history_core(checkups: list, sessions: list) -> dict:
    """体检留痕 × 场次账本联查（纯函数,供端点与自检共用）：
    「quick 红灯体检」后 10 分钟内有场次开播、且该场跑得健康（≥120s 且 时延中位<650ms 且
    失败率<20%）→ 记一次 false_block_suspect（体检说不能播,实际播得好=疑似误拦）。
    输出误拦率 = suspects / quick 红灯数（分母为 0 → None,不装有数据）。"""
    reds = [c for c in checkups if c.get("quick") and c.get("grade") == "red"]
    suspects = []
    for c in reds:
        ts = float(c.get("ts") or 0)
        for s in sessions:
            st = float(s.get("start") or 0)
            if not (ts <= st <= ts + 600):
                continue
            lat = (s.get("latency_ms") or {}).get("med")
            fail = (s.get("swap") or {}).get("fail_pct")
            if (int(s.get("dur_s") or 0) >= 120 and isinstance(lat, (int, float)) and lat < 650
                    and (fail is None or fail < 20)):
                suspects.append({"checkup_ts": ts, "bad": c.get("bad") or [],
                                 "session_start": st, "dur_s": s.get("dur_s"),
                                 "lat_med": lat, "fail_pct": fail})
            break   # 只配最近的一场（红灯→开播的第一场才是"不听劝照播"的那场）
    return {"checkups": len(checkups), "red_quick": len(reds),
            "false_block_suspects": suspects,
            "false_block_rate": (round(len(suspects) / len(reds), 3) if reds else None)}


@app.get("/api/device/checkup/history")
def api_device_checkup_history(limit: int = 50):
    """体检留痕列表 + 误拦联查汇总（观察自动化 IV）：真人观察项「体检卡点有无误拦」从人记改机器数。"""
    recs = []
    try:
        if _CHECKUP_LOG_PATH.exists():
            for ln in _CHECKUP_LOG_PATH.read_text(encoding="utf-8").splitlines()[-max(1, min(int(limit or 50), 500)):]:
                try:
                    recs.append(json.loads(ln))
                except Exception:
                    pass
    except Exception as e:
        return {"ok": False, "detail": str(e)[:120]}
    sess = []
    try:
        if _SWAP_SESS_PATH.exists():
            sess = [json.loads(ln) for ln in
                    _SWAP_SESS_PATH.read_text(encoding="utf-8").splitlines() if ln.strip()]
    except Exception:
        pass
    out = _checkup_history_core(recs, sess)
    out.update({"ok": True, "recent": recs[::-1][:20]})
    return out


@app.get("/api/device/checkup/selftest")
def device_checkup_selftest():
    """误拦联查演练（真函数+合成输入,无需真开播/真红灯）：红灯后健康场=计入疑似、
    红灯后短场/高时延场=不计入、绿灯不进分母。"""
    checkups = [
        {"ts": 1000.0, "quick": True, "grade": "red", "bad": ["camera"]},     # → 健康场,应计误拦
        {"ts": 5000.0, "quick": True, "grade": "red", "bad": ["mic"]},        # → 短场,不计
        {"ts": 9000.0, "quick": True, "grade": "green", "bad": []},           # 绿灯,不进分母
        {"ts": 12000.0, "quick": False, "grade": "red", "bad": ["mic"]},      # 非 quick(手动全检),不进分母
    ]
    sessions = [
        {"start": 1120.0, "dur_s": 600, "latency_ms": {"med": 300}, "swap": {"fail_pct": 2}},
        {"start": 5060.0, "dur_s": 45,  "latency_ms": {"med": 280}, "swap": {"fail_pct": 1}},
        {"start": 9100.0, "dur_s": 900, "latency_ms": {"med": 250}, "swap": {"fail_pct": 0}},
    ]
    r = _checkup_history_core(checkups, sessions)
    sus = r.get("false_block_suspects") or []
    checks = {
        "红灯分母=2(quick 才算)": r.get("red_quick") == 2,
        "疑似误拦=1(健康场)": len(sus) == 1,
        "误拦配对到 1000 那次": bool(sus) and sus[0].get("checkup_ts") == 1000.0,
        "短场不计误拦": all(s.get("checkup_ts") != 5000.0 for s in sus),
        "误拦率=0.5": r.get("false_block_rate") == 0.5,
    }
    return {"ok": all(checks.values()), "checks": checks, "result": r}


# ── Phase 12 D-4 分机部署向导：cluster_map.json → env 片段 + 拓扑/显存 lint ──
def _load_topology_lint():
    """按文件路径加载 tools/topology_lint.py(tools 非包)，复用其 check()。"""
    import importlib.util as _ilu
    p = Path(_BASE) / "tools" / "topology_lint.py"
    spec = _ilu.spec_from_file_location("topology_lint", p)
    mod = _ilu.module_from_spec(spec)
    spec.loader.exec_module(mod)
    return mod


@app.get("/api/cluster/wizard")
def api_cluster_wizard():
    """分机部署向导：读 cluster_map.json(拓扑单一数据源) → 每机服务清单 + 可直接粘贴的
    env_config 片段 + 拓扑/显存 lint 结果(复用 tools/topology_lint.check,只读不动告警)。"""
    mp = Path(_BASE) / "cluster_map.json"
    if not mp.exists():
        return {"ok": False, "detail": "cluster_map.json 不存在（单机部署无需向导）"}
    try:
        cm = json.loads(mp.read_text(encoding="utf-8-sig"))
    except Exception as e:
        return {"ok": False, "detail": f"cluster_map.json 解析失败: {e}"}
    hosts, env_lines = [], []
    for host, hc in sorted((cm.get("hosts") or {}).items()):
        svcs = []
        for s in hc.get("svcs") or []:
            url = f"http://{host}:{s.get('port')}"
            ek = (s.get("env_key") or "").strip()
            if ek:
                env_lines.append(f'set "{ek}={url}"')
            svcs.append({"name": s.get("name", "?"), "server": s.get("server", ""),
                         "port": s.get("port"), "env_key": ek, "task": s.get("task", ""),
                         "url": url})
        hosts.append({"ip": host, "dir": hc.get("dir", ""), "py": hc.get("py", ""), "svcs": svcs})
    lint = {"ok": None, "drifts": [], "oks": 0}
    try:
        tl = _load_topology_lint()
        drifts, oks = tl.check(mp, Path(_BASE) / "env_config.bat")
        lint = {"ok": not drifts, "drifts": drifts, "oks": len(oks)}
    except Exception as e:
        lint = {"ok": None, "drifts": [f"lint 自身故障(不判漂移): {str(e)[:120]}"], "oks": 0}
    return {"ok": True, "hub": cm.get("hub") or {}, "hosts": hosts,
            "env_fragment": "\r\n".join(env_lines),
            "vram_budget": cm.get("vram_budget") or {}, "lint": lint}


# ── Phase 12 D-2 配套：前端体验指标回传(WebRTC/MJPEG 首帧耗时等) ──────────────
_client_metrics: dict = {}

@app.post("/api/client_metric")
async def api_client_metric(body: dict = Body(...)):
    """轻量客户端指标回传：{name:'webrtc_ttfv_ms', value:123}。滚动 count/avg/last/min/max。"""
    name = str(body.get("name") or "")[:48]
    if not re.fullmatch(r"[a-z][a-z0-9_]*", name):
        raise HTTPException(400, "name 须为小写字母/数字/下划线")
    try:
        val = float(body.get("value"))
    except Exception:
        raise HTTPException(400, "value 须为数值")
    m = _client_metrics.setdefault(name, {"count": 0, "avg": 0.0, "last": 0.0,
                                          "min": None, "max": None})
    m["count"] += 1
    m["last"] = round(val, 1)
    m["avg"] = round(m["avg"] + (val - m["avg"]) / m["count"], 1)
    m["min"] = round(val, 1) if m["min"] is None else min(m["min"], round(val, 1))
    m["max"] = round(val, 1) if m["max"] is None else max(m["max"], round(val, 1))
    return {"ok": True, "name": name, **m}

@app.get("/api/client_metric")
def api_client_metric_get():
    return {"ok": True, "metrics": _client_metrics}


def _svc_health_quick(key: str, timeout: float = 2.0) -> dict:
    """轻量探测可选 GPU 服务是否在线（不抛异常）。"""
    url = SERVICES.get(key, "")
    if not url:
        return {"key": key, "up": False, "detail": "未登记"}
    try:
        r = requests.get(f"{url.rstrip('/')}/health", headers=_svc_req_headers(), timeout=timeout)
        if r.status_code == 200:
            j = r.json() if r.headers.get("content-type", "").startswith("application/json") else {}
            return {"key": key, "up": True, "health": j}
        return {"key": key, "up": False, "detail": f"HTTP {r.status_code}"}
    except Exception as e:
        return {"key": key, "up": False, "detail": str(e)[:120]}


