class CloneEngineRecommendRequest(BaseModel):
    profile: str = ""
    wav_base64: str = ""
    text: str = "你好，这是音色测试。"
    language: str = "zh-cn"


@app.post("/api/clone_engine_recommend")
async def api_clone_engine_recommend(req: CloneEngineRecommendRequest):
    """克隆完成后：Fish(实时) vs Qwen3(高保真) 短句 A/B + 声纹分 → 推荐 tts_engine。"""
    ref_b64 = (req.wav_base64 or "").strip()
    prof_name = (req.profile or "").strip()
    if not ref_b64 and prof_name:
        p = _profiles.get(prof_name) or {}
        ref_b64 = p.get("voice_b64", "")
    if not ref_b64:
        raise HTTPException(400, "需要 wav_base64 或有效 profile")
    try:
        import clone_scorer
    except Exception as e:
        raise HTTPException(503, f"评分模块不可用: {e}")
    probe = (req.text or "你好，这是音色测试。").strip()
    base_prof = {"voice_b64": ref_b64, "name": prof_name or "probe"}
    engines = []
    for eng, label in (("fish_speech", "Fish · 实时对话"), ("qwen3_tts", "Qwen3 · 高保真")):
        h = _svc_health_quick("fish_tts" if eng == "fish_speech" else "qwen3_tts")
        if not h.get("up"):
            engines.append({"engine": eng, "label": label, "ok": False, "detail": "服务未启动"})
            continue
        prof = dict(base_prof)
        prof["tts_engine"] = eng
        t0 = time.time()
        try:
            audio = await _conv_synthesize(probe, prof, language=req.language, emotion="neutral",
                                           vc_engine="", watermark=None, _use_opener_cache=False)
        except Exception as e:
            engines.append({"engine": eng, "label": label, "ok": False, "detail": str(e)[:160]})
            continue
        elapsed = int((time.time() - t0) * 1000)
        if not audio:
            engines.append({"engine": eng, "label": label, "ok": False, "detail": "合成失败", "elapsed_ms": elapsed})
            continue
        sc = await asyncio.to_thread(clone_scorer.score_similarity, ref_b64, audio)
        cos = round(sc.get("cosine", 0.0), 4) if sc.get("ok") else None
        realtime = eng == "fish_speech" and elapsed < 3000
        engines.append({
            "engine": eng, "label": label, "ok": True,
            "cosine": cos, "elapsed_ms": elapsed, "realtime_ok": realtime,
        })
    ok_eng = [e for e in engines if e.get("ok")]
    recommend = "fish_speech"
    reason = "默认实时对话引擎"
    if len(ok_eng) >= 2:
        fish_e = next((e for e in ok_eng if e["engine"] == "fish_speech"), None)
        qwen_e = next((e for e in ok_eng if e["engine"] == "qwen3_tts"), None)
        if fish_e and qwen_e:
            fc, qc = fish_e.get("cosine") or 0, qwen_e.get("cosine") or 0
            if qc - fc >= 0.08 and (qwen_e.get("elapsed_ms") or 99999) < 8000:
                recommend = "qwen3_tts"
                reason = f"Qwen3 声纹相似度高 {qc:.2f} vs Fish {fc:.2f}，适合出片/商用"
            elif fish_e.get("realtime_ok"):
                recommend = "fish_speech"
                reason = f"Fish 延迟 {fish_e.get('elapsed_ms')}ms，适合直播/对话"
            else:
                recommend = "fish_speech"
                reason = "Fish 为实时默认；Qwen3 偏慢时可仅用于离线配音"
    elif len(ok_eng) == 1:
        recommend = ok_eng[0]["engine"]
        reason = "仅一个引擎可用"
    return {"ok": True, "recommend": recommend, "reason": reason, "engines": engines}


