@app.post("/rvc/config")
def rvc_config(body: dict):
    """配置 RVC 变声参数"""
    try:
        if body.get("pth_path"):
            # 前端下拉传的是相对 weights 根的 id(如 weights/xx.pth)，RVC 引擎按自身 CWD 解析会 FileNotFound
            body["pth_path"] = _rvc_resolve_pth(str(body["pth_path"]))
            if not Path(body["pth_path"]).is_file():
                # RVC 端 /config 不校验文件存在，坏路径会烂到 /start 才报难懂的 tgt_sr 错——此处提前拦成人话
                return {"ok": False, "detail": f"音色模型文件不存在：{body['pth_path']}（模型可能已改名/删除，请刷新后重新选择）"}
        if not body.get("index_path") and body.get("pth_path"):
            pth_stem = Path(body["pth_path"]).stem
            candidates = list(RVC_INDICES_DIR.rglob(f"*{pth_stem}*.index")) + list(RVC_LOGS_DIR.rglob(f"*{pth_stem}*.index"))
            if candidates:
                body["index_path"] = str(candidates[0])
            else:
                # 无 .index 是常态（本库/社区模型大多不带）：RVC 端 set_values 对空 index 自动关闭
                # 检索(index_rate=0)，不影响实时变声。此处放行而非拦截——历史上在这里硬报错，
                # 导致所有无 index 模型「应用变声配置」失败、变声无响应。
                body["index_path"] = ""
                body["index_rate"] = 0.0
                _logger.info(f"[rvc] {pth_stem} 无匹配 .index，关闭 index 检索后放行")
        r = requests.post(f"{SERVICES['rvc']}/config", json=body, headers=_svc_req_headers(), timeout=10)
        return r.json()
    except Exception as e:
        raise HTTPException(502, f"RVC 服务不可达: {e}")

@app.post("/rvc/start")
def rvc_start():
    """开始 RVC 实时变声"""
    try:
        r = requests.post(f"{SERVICES['rvc']}/start", headers=_svc_req_headers(), timeout=10)
        if r.status_code == 200 or (r.status_code == 400 and "already" in r.text.lower()):
            _rvc_conv_mark(True)       # P4-3 转换在跑：设备表进入冻结期
        return r.json()
    except Exception as e:
        raise HTTPException(502, f"RVC 服务不可达: {e}")

@app.post("/rvc/stop")
def rvc_stop():
    """停止 RVC 实时变声"""
    try:
        r = requests.post(f"{SERVICES['rvc']}/stop", headers=_svc_req_headers(), timeout=10)
        _rvc_conv_mark(False)          # 200=刚停 / 400=本来没跑，此刻都不在跑
        return r.json()
    except Exception as e:
        raise HTTPException(502, f"RVC 服务不可达: {e}")


# ── P3-1 开播中拔插热处理：一键把在跑的变声切到推荐/指定设备并重启拾音流 ──────────
_RVC_HOTSWITCH_LOCK = threading.Lock()
# P4-3 hub 视角的「变声转换在跑」旗标：/rvc/start·stop 代理与热切都会更新。
# 用途：转换中 RVC 设备表被刻意冻结(api_240604 防炸流修复)，此时 /rvc/devices 用本地子进程
# 即时枚举补上「转换开始后新插」的设备(🆕)。hub 重启丢旗标只是降级回冻结表行为，无害。
_RVC_CONV = {"active": False, "ts": 0.0}


def _rvc_conv_mark(active: bool):
    _RVC_CONV["active"] = bool(active)
    _RVC_CONV["ts"] = time.time()


def _hot_switch_ledger(res: dict, src: str = ""):
    """P4-1 热切事件入场次账本（timeline 单一来源，event=device）：何时切/从哪只切到哪只/耗时/成败，
    复盘「那场中间为什么哑了 2 秒」直接看甘特 🎚 标记。失败静默，绝不影响热切主流程。"""
    try:
        ok = bool(res.get("ok"))
        frm, to = res.get("from_input") or "", res.get("input") or ""
        try:
            import device_enum as _de
            f_lb = _de.label_for(frm, "in") if frm else ""
        except Exception:
            f_lb = frm
        t_lb = res.get("input_label") or to
        parts = []
        if ok:
            parts.append("热切成功" if res.get("was_running") else "热切(未在跑,仅换线路)")
        else:
            parts.append(f"热切失败@{res.get('step') or '?'}")
        if f_lb or t_lb:
            parts.append(f"{f_lb or '?'}→{t_lb or '?'}")
        o_lb = res.get("output_label") or res.get("output") or ""
        if o_lb:
            parts.append(f"出={o_lb}")
        if res.get("elapsed_s") is not None:
            parts.append(f"({res.get('elapsed_s')}s)")
        if not ok and res.get("detail"):
            parts.append(str(res.get("detail"))[:60])
        if src:
            parts.append(f"来源={src}")
        _stream_health_event("device", "device", {}, float(res.get("elapsed_s") or 0),
                             action=" ".join(parts)[:200], kind="device")
    except Exception:
        pass


@app.post("/rvc/hot_switch")
def rvc_hot_switch(body: dict = {}):
    """直播中麦克风/输出拔掉后的一键恢复（P3-1）：把实时变声切到「当前真实可用」的设备并重启拾音流。

    设备来源优先级：body 显式 input/output > 已存偏好(在线时) > 自动推荐——
    这正是 _pick_audio_devices 的既有语义，直接复用（偏好设备缺席时它自动回退推荐）。
    刻意不写偏好：缺席顶替是临时行为（P2-1 粘性语义），原设备插回后下次枚举自动恢复。

    顺序刻意为 config → stop → start：
      /config 会先校验设备在枚举里、模型存在（set_devices/set_values 抛 400），失败即整单不动，
      正在跑的转换毫发无损；校验过了再 stop→start，把新设备真正接进拾音流。
    运行配置的单一真相取 RVC 自己落盘的 configs/config.json（每次 /config 都会写），
    页面刷新/换浏览器/前端状态丢失都不影响——不依赖前端记得当时的模型与参数。
    P4-1：每次真正执行的热切（拿到锁的）都记进场次账本(timeline event=device)；并发排队拒绝不记。"""
    if not _RVC_HOTSWITCH_LOCK.acquire(blocking=False):
        return {"ok": False, "detail": "另一次线路切换正在进行，稍候再试"}
    t0 = time.time()
    try:
        res = _rvc_hot_switch_inner(body)
    finally:
        _RVC_HOTSWITCH_LOCK.release()
    res["elapsed_s"] = round(time.time() - t0, 2)
    _hot_switch_ledger(res, str((body or {}).get("src") or "").strip()[:24])
    return res


def _rvc_hot_switch_inner(body: dict) -> dict:
    """热切主链（锁内执行；见 rvc_hot_switch 文档）。返回结构化结果，永不抛（RVC 不可达除外）。"""
    # 1) 目标设备：显式 > 偏好(在线) > 推荐。拔插风暴瞬间枚举可能一过性失败(驱动重排设备表)，
    #    重试一次再判死——实弹演练实测过一次 1.5s 内的瞬时空枚举。
    pick = {}
    for attempt in (0, 1):
        try:
            pick = _pick_audio_devices()
        except Exception:
            pick = {}
        if pick.get("input") and pick.get("output"):
            break
        if attempt == 0:
            time.sleep(1.2)
    inp = str((body or {}).get("input") or "").strip() or (pick.get("input") or "")
    out = str((body or {}).get("output") or "").strip() or (pick.get("output") or "")
    if not inp or not out:
        return {"ok": False, "step": "pick",
                "detail": "找不到可用的麦克风/直播声卡（变声服务离线或设备全部缺席）"}
    # 2) 读运行配置（RVC 每次 /config 都落盘 configs/config.json）
    cfg_file = Path(rf"{_BASE}\Retrieval-based-Voice-Conversion-WebUI\configs\config.json")
    try:
        cfg = json.loads(cfg_file.read_text(encoding="utf-8"))
        assert isinstance(cfg, dict)
    except Exception as e:
        return {"ok": False, "step": "config_read",
                "detail": f"读不到变声运行配置(configs/config.json)：{e}"}
    if not str(cfg.get("pth_path") or "").strip():
        return {"ok": False, "step": "config_read",
                "detail": "变声还没配置过音色模型——先在「变声」区选模型并应用配置"}
    base = {"from_input": str(cfg.get("sg_input_device") or ""),     # P4-1 账本「从哪只切走」
            "from_output": str(cfg.get("sg_output_device") or "")}
    cfg["sg_input_device"] = inp
    cfg["sg_output_device"] = out
    cfg.pop("use_jit", None)   # config.json 落盘附加项，不属于 /config 的 ConfigData 契约

    def _post(path, timeout):
        try:
            return requests.post(f"{SERVICES['rvc']}{path}", json=(cfg if path == "/config" else None),
                                 headers=_svc_req_headers(), timeout=timeout)
        except Exception as e:
            raise HTTPException(502, f"RVC 服务不可达: {e}")

    # 3) config：先试「在跑直配」（校验+落盘，失败不伤转换）。转换中 RVC 的设备表被刻意冻结
    #    (api_240604 修复：转换中 sd._terminate 重枚举会炸死拾音流)，拔插后新出现的设备在冻结表里
    #    没有 → 400 not available。这正是热切的主场景，所以回退链：停转换(设备表解冻)→重配→再启。
    was_running = None            # None=还没 stop 过；True/False=stop 的裁决
    r = _post("/config", 15)
    if r.status_code != 200:
        first_err = r.text[:300]
        r_stop = _post("/stop", 10)
        was_running = (r_stop.status_code == 200)
        _rvc_conv_mark(False)     # 无论 200/400，此刻转换都不在跑
        if not was_running:       # 本来就没在跑，config 失败就是真失败（设备/模型不合法）
            return {**base, "ok": False, "step": "config", "detail": first_err, "input": inp, "output": out}
        time.sleep(0.8)           # 等拾音流真正退出，PortAudio 才能重枚举出新设备
        # 设备表解冻后重选一次：转换期间新插的替代设备(不在冻结表里)现在才可见。显式指定仍优先。
        try:
            pick2 = _pick_audio_devices()
            if not str((body or {}).get("input") or "").strip() and pick2.get("input"):
                inp = pick2["input"]
            if not str((body or {}).get("output") or "").strip() and pick2.get("output"):
                out = pick2["output"]
            cfg["sg_input_device"] = inp
            cfg["sg_output_device"] = out
        except Exception:
            pass
        r = _post("/config", 15)
        if r.status_code != 200:  # 停了还配不上：转换已停，如实报，别留「以为还在变声」的假象
            return {**base, "ok": False, "step": "config", "was_running": True, "started": False,
                    "detail": r.text[:300] + "（变声已停止，请检查设备后手动点「开始变声」）",
                    "input": inp, "output": out}
    # 4) stop：400=本来就没在跑（那就只换线路不重启，下次开始变声即用新设备）
    if was_running is None:
        r = _post("/stop", 10)
        was_running = (r.status_code == 200)
        _rvc_conv_mark(False)
        if was_running:
            # RVC 的拾音循环每 block_time(0.25s) 才检查一次停止标志；立刻 start 会把标志翻回 True，
            # 旧流永不退出 → 新旧两条流叠在同一设备上出「机器人音」。等旧流真正退出再起新流。
            time.sleep(0.8)
    started, start_detail = False, ""
    if was_running:
        # start 带重试：拾音流刚退 PortAudio 刚重初始化时偶发一过性 "Error querying device"
        # （P6 实弹实测：首发 start 失败、数秒后重打即 200）。400 already=流已在跑，同样算成功。
        for wait in (0, 1.5, 3.0):
            if wait:
                time.sleep(wait)
            try:
                r = requests.post(f"{SERVICES['rvc']}/start", headers=_svc_req_headers(), timeout=25)
                started = (r.status_code == 200) or (r.status_code == 400 and "already" in r.text.lower())
                start_detail = "" if started else r.text[:300]
            except Exception as e:
                start_detail = str(e)[:300]
            if started:
                break
        _rvc_conv_mark(started)
    # 人话标签（专家可看原始名）
    in_label = out_label = ""
    try:
        import device_enum as _de
        in_label = _de.label_for(inp, "in")
        out_label = _de.label_for(out, "out")
    except Exception:
        pass
    ok = (not was_running) or started
    return {**base, "ok": ok, "step": ("start" if (was_running and not started) else "done"),
            "was_running": was_running, "started": started,
            "input": inp, "input_label": in_label,
            "output": out, "output_label": out_label,
            "detail": start_detail if not ok else ""}


# ── P6-1 设备缺席自动热切（无人值守）────────────────────────────────────
#   变声转换在跑 + 运行设备(RVC 落盘 config 的 sg_input/output_device)从本地枚举里消失
#   → 守护自动执行与手动 CTA 完全同一条热切链(rvc_hot_switch, src=auto)：同一本账本、同一个漏斗。
#   默认关：自动切=一次未经同意的 ~1.5s 断声；漏斗数据显示人点成功率高后，主播自己决定打开。
_DEV_AUTOSW_TICK    = float(os.environ.get("HUB_DEV_AUTOSW_TICK", "10") or 10)
# 确认窗须 > _AUDIO_ENUM_CACHE 的 20s TTL：保证开火前至少隔着一次「新鲜」的子进程重枚举，
# 拔插风暴/驱动重排的一过性空窗(实测 1.5s 级)不会触发误切。
_DEV_AUTOSW_CONFIRM = float(os.environ.get("HUB_DEV_AUTOSW_CONFIRM", "25") or 25)
# P7-1 最近一次自动热切结果（挂 /realtime/status 顺风车 → 前端 4s 轮询即时感知并弹 toast，
# 无需新轮询/长连接）。仅守护自动切写入；手动热切用户在场自然有反馈，不占这块。
_DEV_AUTOSW_LAST = {"ts": 0.0, "ok": None, "to": "", "out": "", "detail": "", "n": 0}


def _dev_autosw_decide(st: dict, *, enabled: bool, conv_on: bool, dev_missing: bool,
                       now: float, confirm_s: float = 25.0,
                       cooldown: float = 90.0, max_n: int = 3) -> str:
    """纯决策（守护每 tick 调用，可离线断言）：返回 "fire"|"armed"|"idle"。
    st 可变状态: miss_since=首次发现缺席时刻 / last_ts=上次开火 / count=本转换会话已开火数
    / idle_ticks=连续观察到转换不在跑的 tick 数(≥2 才判定真收场→弹药恢复；热切链自身
    stop→start 的 1~2s 旗标空窗不会误清弹药)。
    护栏：确认窗(缺席须持续)、冷却、每会话上限；开关关/转换停/设备回来→立即撤防。"""
    if not conv_on:
        st["idle_ticks"] = int(st.get("idle_ticks") or 0) + 1
        if st["idle_ticks"] >= 2:
            st["count"] = 0
        st["miss_since"] = 0.0
        return "idle"
    st["idle_ticks"] = 0
    if not (enabled and dev_missing):
        st["miss_since"] = 0.0
        return "idle"
    if not st.get("miss_since"):
        st["miss_since"] = now
        return "armed"
    if now - st["miss_since"] < confirm_s:
        return "armed"
    if st.get("count", 0) >= max_n or (now - st.get("last_ts", 0.0)) < cooldown:
        return "armed"                       # 弹药耗尽/冷却中：保持关注不动手（无声告警会兜底叫人）
    return "fire"


def _dev_autosw_missing() -> tuple:
    """读 RVC 运行配置里的输入/输出设备名，对照本地即时枚举判缺席。
    返回 (in_missing, out_missing, running_in, running_out)；任何读取失败按「不缺席」处理（宁可不切）。"""
    try:
        cfg = json.loads(Path(rf"{_BASE}\Retrieval-based-Voice-Conversion-WebUI\configs\config.json")
                         .read_text(encoding="utf-8"))
        rin = str(cfg.get("sg_input_device") or "").strip()
        rout = str(cfg.get("sg_output_device") or "").strip()
    except Exception:
        return False, False, "", ""
    if not rin and not rout:
        return False, False, "", ""
    try:
        ins, outs = _local_audio_devices()
    except Exception:
        return False, False, rin, rout
    def norm(s):
        return " ".join(str(s).strip().lower().split())
    in_miss = bool(rin) and norm(rin) not in {norm(n) for n in (ins or [])}
    out_miss = bool(rout) and norm(rout) not in {norm(n) for n in (outs or [])}
    return in_miss, out_miss, rin, rout


async def _bg_dev_autoswitch():
    """P6-1 守护：不依赖浏览器在场（页面关了/无人值守照样切）。开销自限——
    仅在「开关开 + 转换在跑」时才做子进程枚举(且吃 _local_audio_devices 的 20s 缓存)。"""
    await asyncio.sleep(20.0)
    st = {"miss_since": 0.0, "last_ts": 0.0, "count": 0, "idle_ticks": 0}
    while True:
        await asyncio.sleep(_DEV_AUTOSW_TICK)
        try:
            conv_on = bool(_RVC_CONV.get("active"))
            in_miss = out_miss = False
            rin = ""
            if _DEV_AUTOSW_ON and conv_on:              # 关着/没在转换：零枚举开销
                in_miss, out_miss, rin, _rout = await asyncio.to_thread(_dev_autosw_missing)
            act = _dev_autosw_decide(st, enabled=_DEV_AUTOSW_ON, conv_on=conv_on,
                                     dev_missing=(in_miss or out_miss), now=time.time(),
                                     confirm_s=_DEV_AUTOSW_CONFIRM,
                                     cooldown=_DEV_AUTOSW_COOLDOWN, max_n=_DEV_AUTOSW_MAX)
            if act != "fire":
                continue
            if _RVC_HOTSWITCH_LOCK.locked():            # 手动热切正在跑：本 tick 让渡，别抢锁记假失败
                continue
            kind = "in" if in_miss else "out"
            st["count"] += 1; st["last_ts"] = time.time(); st["miss_since"] = 0.0
            _logger.warning(f"[DevAutoSwitch] 运行设备缺席(持续>{int(_DEV_AUTOSW_CONFIRM)}s, {kind}={rin!r})"
                            f"→自动热切 #{st['count']}/{_DEV_AUTOSW_MAX}")
            # 与手动 CTA 同一本漏斗账（src=auto）：曝光=守护发现缺席并决定动手，点击=自动化代点
            _devflow_bump_local("expose", kind, "auto")
            _devflow_bump_local("click", kind, "auto")
            try:
                res = await asyncio.to_thread(rvc_hot_switch, {"src": "auto"})
            except Exception as e:      # RVC 不可达等按「切换失败」入账，而不是当守护异常吞掉
                res = {"ok": False, "step": "unreachable", "detail": str(e)[:200]}
            ok = bool(res.get("ok"))
            _devflow_bump_local("ok" if ok else "fail", kind, "auto")
            _DEV_AUTOSW_LAST.update(ts=time.time(), ok=ok, n=st["count"],
                                    to=str(res.get("input_label") or res.get("input") or ""),
                                    out=str(res.get("output_label") or res.get("output") or ""),
                                    detail=("" if ok else str(res.get("detail") or res.get("step") or "")[:120]))
            try:
                import alerts as _al
                if ok:
                    _al.clear_alert("dev_autoswitch_fail", note="自动热切成功")
                    if _SH_ALERTS_ON:
                        _al.notify_event("设备缺席·已自动热切",
                                         detail=f"切到 {res.get('input_label') or res.get('input')}"
                                                f"（出={res.get('output_label') or res.get('output')}）"
                                                f" · 耗时{res.get('elapsed_s')}s · #{st['count']}/{_DEV_AUTOSW_MAX}",
                                         level="info", source="设备自愈")
                elif _SH_ALERTS_ON:
                    _al.raise_alert("dev_autoswitch_fail", "设备缺席·自动热切失败",
                                    detail=f"step={res.get('step')} {str(res.get('detail'))[:120]}"
                                           f" · 变声可能已无声，请人工介入",
                                    level="error", source="设备自愈")
            except Exception:
                pass
        except Exception as exc:
            _logger.warning(f"[DevAutoSwitch] watch 异常: {exc}")


# ── 路由：便捷转发 ─────────────────────────────────────────────────
# ── Phase 12 C-2 双人/多人 face_map：槽位(左→右)→角色 的映射配置 ─────────────
#   enabled 时 /faceswap 代理注入 source_map=[槽0脸,槽1脸,...]（空槽=当前激活角色脸）；
#   引擎按目标脸 x 排序对槽换脸，超出槽位的脸回退首个可用槽。默认关=行为与旧版逐字节一致(R12-02)。
#   2026-07-10 扩容：2 槽 → 至多 _FACE_MAP_MAX_SLOTS(4) 槽（三/四人同框各换各脸）；
#   同日修直连失效：槽位另经 /face_map/active 粘滞推送到引擎（见 _push_face_map_async）。
_FACE_MAP_FILE = Path(rf"{_BASE}\face_map.json")
_FACE_MAP_MAX_SLOTS = max(2, int(os.environ.get("FACE_MAP_MAX_SLOTS", "4")))
_face_map_state = {"enabled": False, "slots": ["", ""]}

def _face_map_load():
    try:
        if _FACE_MAP_FILE.exists():
            s = json.loads(_FACE_MAP_FILE.read_text(encoding="utf-8"))
            _face_map_state["enabled"] = bool(s.get("enabled"))
            sl = [(x if isinstance(x, str) else "").strip()
                  for x in list(s.get("slots") or [])[:_FACE_MAP_MAX_SLOTS]]
            _face_map_state["slots"] = (sl + ["", ""])[:max(2, len(sl))]
    except Exception:
        pass

_face_map_load()

def _profile_swap_face(p: dict) -> str:
    """换脸源脸取值：启用发型定妆(C-3)且有定妆脸 → 定妆脸；否则原始绑定脸。"""
    if p.get("use_styled_face") and p.get("face_styled_b64"):
        return p["face_styled_b64"]
    return p.get("face_b64", "")

def _profile_gallery_imgs(p: dict) -> list[str]:
    """多照片源脸平均的输入图集：主换脸源(定妆优先) + gallery 附图，去重去空。
    仅当 gallery 非空才返回 >1 张（否则空列表=不启用平均，走单照旧路，零回归）。"""
    gal = [g for g in (p.get("face_gallery_b64") or []) if g]
    if not gal:
        return []
    primary = _profile_swap_face(p)
    imgs, seen = [], set()
    for b in ([primary] + gal if primary else gal):
        key = (len(b), b[:64])          # 轻量去重键（避免整串比较开销）
        if b and key not in seen:
            seen.add(key)
            imgs.append(b)
    return imgs if len(imgs) > 1 else []

def _push_active_face_makeup_async(name: str):
    """激活脸 + 直播妆容推到主引擎（2026-07-09 直连补件）。
    /faceswap_raw 二进制直连不过 Hub 逐帧注入 → 引擎粘滞态(激活脸/active_makeup)即直连真相；
    激活角色与主引擎回切两处共用。妆容关=推空(清掉上一角色残留)；旧引擎无 /makeup/active=404 无害。"""
    p = _profiles.get(name) or {}
    img = _profile_swap_face(p)
    _lmk = dict(p.get("live_makeup") or {})
    mk = {k: v for k, v in _lmk.items() if k != "enabled"} if _lmk.get("enabled") else {}

    def _do():
        try:
            if img:
                requests.post(f"{SERVICES['faceswap']}/faces/switch",
                              json={"name": name, "image": img},
                              headers=_svc_req_headers(), timeout=8)
        except Exception:
            pass
        try:
            requests.post(f"{SERVICES['faceswap']}/makeup/active",
                          json={"makeup": mk},
                          headers=_svc_req_headers(), timeout=5)
        except Exception:
            pass
    threading.Thread(target=_do, daemon=True).start()
    _push_face_map_async()   # 双人/多人槽位同步补推(激活/回切两处入口共用；关=推空清残留)


def _register_avg_face_async(name: str):
    """把角色的多照片平均 embedding 预注册到换脸服务(/faces/register_avg)，
    直播链路随后用 source_key=<name> 每帧零额外传输地享用平均源脸。gallery 为空则清除该键。"""
    p = _profiles.get(name, {})
    imgs = _profile_gallery_imgs(p)
    def _do():
        try:
            requests.post(f"{SERVICES['faceswap']}/faces/register_avg",
                          json={"key": name, "images": imgs},
                          headers=_svc_req_headers(), timeout=8)
        except Exception:
            pass
    # imgs 为空也要发：引擎侧清除该键（否则清空 gallery 后引擎残留旧平均向量）
    threading.Thread(target=_do, daemon=True).start()


def _plan_hot_dfms(budget: int | None = None) -> list:
    """S4: 「本场热角色」DFM 清单：活动角色优先，其余按使用频次降序；去重。
    预算 = 引擎 lru_cap - 1（inswapper 基线常驻占 1 席；.104 循证 cap=4 → 3 个 DFM 同驻，
    4 DFM 同驻峰值 11821/12282MB 仅剩 461MB，故不再多）。引擎不可达 → 默认预算 3。"""
    try:
        if budget is None:
            try:
                r = requests.get(f"{SERVICES['faceswap']}/model", headers=_svc_req_headers(), timeout=5)
                budget = max(1, int(r.json().get("lru_cap") or 4) - 1)
            except Exception:
                budget = 3
        names = []
        if _active_profile and _active_profile in _profiles:
            names.append(_active_profile)
        names += sorted([n for n in _profiles if n not in names
                         and (_profiles[n].get("dfm_model") or "").strip()],
                        key=lambda n: -_usage_n(n))
        plan, seen = [], set()
        for n in names:
            mdl = (_profiles.get(n) or {}).get("dfm_model", "").strip()
            if mdl and mdl not in seen:
                plan.append(mdl); seen.add(mdl)
            if len(plan) >= budget:
                break
        return plan
    except Exception:
        return []


def _prewarm_dfm_list_async(plan: list, reason: str = ""):
    """S4: 后台串行预热给定 DFM 清单（/model/prewarm，不换绑不动画面）。
    串行打——加载在引擎侧本就串行占 GPU；单个失败（超时/旧版引擎）不断链。"""
    if not plan:
        return
    def _do(models=list(plan), why=reason):
        done = []
        for mdl in models:
            try:
                rr = requests.post(f"{SERVICES['faceswap']}/model/prewarm",
                                   json={"model": mdl}, headers=_svc_req_headers(), timeout=60)
                if rr.status_code == 200:
                    d = rr.json()
                    note = "已驻" if d.get("already") else str(d.get("load_ms")) + "ms"
                    done.append(mdl + "(" + note + ")")
            except Exception:
                pass
        if done:
            print(f"[Hub] S4 DFM 预热完成×{len(done)}: {done}（{why}）")
    threading.Thread(target=_do, daemon=True).start()


def _prewarm_hot_dfms_async(reason: str = ""):
    """S4: 「本场热角色」预热总入口——计划(查引擎 cap，最多 5s)+加载全在后台线程，调用方零阻塞。
    循证：冷加载热切阻塞 ~4.5s、并发帧卡 ~2.8s；已驻热切 ~20ms、流最大帧间隙 82ms。
    开播/激活前排队预热 → 场内切角色零冻结。"""
    def _bg(why=reason):
        try:
            _prewarm_dfm_list_async(_plan_hot_dfms(), why)
        except Exception:
            pass
    threading.Thread(target=_bg, daemon=True).start()


def _push_dfm_model_async(name: str, p: dict):
    """S2: 激活角色时把其 DFM 绑定热切到换脸引擎（/model/reload）。
    无绑定 → 显式切回 default（inswapper+源脸），防上一角色的 DFM 残留让本角色被换成别人。
    首次加载某 .dfm 引擎侧含预热 ~1-4s，故超时放宽；旧版引擎无此端点 → 静默跳过（零回归）。
    S5: 每次真实热切进场次账本（timeline event=dfm，🎭 标记）——在播中复盘「切角色那一下卡没卡」
    直接看载入耗时（load_ms>1000 = 冷加载=有感冻结；已驻 <100ms=无感）；404=绑定失效（库里没这模型）。"""
    model = (p.get("dfm_model") or "").strip()
    def _do(nm=name, mdl=model):
        prev = ""
        try:   # from 侧尽力取（失败不阻断主流程）
            pr = requests.get(f"{SERVICES['faceswap']}/model", headers=_svc_req_headers(), timeout=4)
            prev = (pr.json().get("active") or "") if pr.status_code == 200 else ""
        except Exception:
            pass
        t0 = time.time()
        try:
            r = requests.post(f"{SERVICES['faceswap']}/model/reload",
                              json={"model": mdl or "default"},
                              headers=_svc_req_headers(), timeout=30)
            el = round(time.time() - t0, 2)
            if r.status_code == 200:
                d = r.json()
                if d.get("warn"):
                    print(f"[Hub] ⚠ 角色 {nm} DFM={mdl}: {d['warn']}")
                else:
                    print(f"[Hub] 角色 {nm} 换脸模型 → {d.get('active')}"
                          f"{'（DFM 整脸换）' if d.get('is_dfm') else '（通用）'} {d.get('load_ms')}ms")
                _load = d.get("load_ms") or 0
                _cold = "冷加载" if _load > 800 else "已驻秒切"
                _stream_health_event("dfm", "dfm", {}, 0, kind="dfm",
                                     action=f"换脸角色热切 {prev or '?'}→{d.get('active')}"
                                            f" 载入{_load}ms({_cold}) 角色={nm}"[:200])
                try:   # 该角色此前若因绑定失效在告警 → 本次成功即自动报平安（clear 幂等，未 firing 则静默）
                    import alerts as _al
                    _al.clear_alert(f"dfm_missing_{nm}", note="绑定已恢复可用")
                except Exception:
                    pass
                # S6: 镜像推给本机容灾副本(在线时)——故障切换瞬间副本已就位，零加载间隙。
                #   副本 LRU=2(inswapper+1 DFM)恰好容纳"当前激活角色"这一个镜像；失败静默(副本关/未部署)。
                try:
                    _rep = _fs_replica_url()
                    if _rep:
                        requests.post(f"{_rep}/model/reload", json={"model": mdl or "default"},
                                      headers=_svc_req_headers(), timeout=30)
                except Exception:
                    pass
            elif r.status_code == 404:
                # S5: 绑定指向库里不存在的模型（本机库 112≠.104 库 46 的差集坑）。
                # 引擎 404 时**保持旧模型不动**——若不处理，上一角色的明星脸会一直挂在本角色上（张冠李戴）。
                # 故显式切回 default（=无绑定语义），宁可通用换脸也绝不顶着别人的脸。
                try:
                    requests.post(f"{SERVICES['faceswap']}/model/reload", json={"model": "default"},
                                  headers=_svc_req_headers(), timeout=15)
                except Exception:
                    pass
                _stream_health_event("dfm", "dfm", {}, 0, kind="dfm",
                                     action=f"换脸角色热切失败(绑定失效404) 角色={nm} 模型={mdl} → 已强制回退通用换脸"[:200])
                print(f"[Hub] ⚠ 角色 {nm} 绑定的 DFM 不在引擎库: {mdl}（已强制切回通用换脸；请在编辑器重绑或补推模型）")
                try:
                    import alerts as _al
                    _al.raise_alert(f"dfm_missing_{nm}", "换脸角色绑定失效",
                                    detail=f"角色「{nm}」绑定的 {mdl} 不在换脸引擎库（404）——"
                                           f"本次激活已强制回退通用换脸；请重绑或补推模型",
                                    level="warning", source="DFM对账")
                except Exception:
                    pass
        except Exception:
            pass                        # 引擎离线/旧版无端点：激活流程不受影响
    threading.Thread(target=_do, daemon=True).start()


def _push_id_anchor_async():
    """把「全体角色脸的平均 embedding」(人群中心)推给换脸服务作身份放大 anchor。
    引擎据此沿远离 anchor 方向外推源身份→抵消 inswapper 向目标脸回归、提升辨识度。
    角色数<3 时不推(anchor 不稳)。changes to 角色库时刷新。"""
    imgs = []
    for nm, p in list(_profiles.items()):
        face = _profile_swap_face(p)
        if face:
            imgs.append(face)
    def _do():
        try:
            requests.post(f"{SERVICES['faceswap']}/faces/set_anchor",
                          json={"images": imgs},
                          headers=_svc_req_headers(), timeout=15)
        except Exception:
            pass
    if len(imgs) >= 3:                    # 人群中心需足够样本才有意义
        threading.Thread(target=_do, daemon=True).start()

def _face_map_sources() -> list[str] | None:
    """启用时给出槽位源脸 b64 列表(空槽=空串,引擎侧回退激活角色脸)；无有效槽→None。"""
    if not _face_map_state["enabled"]:
        return None
    out = []
    for nm in _face_map_state["slots"]:
        nm = (nm or "").strip()
        out.append(_profile_swap_face(_profiles.get(nm, {})) if nm else "")
    return out if any(out) or _profile_swap_face(_profiles.get(_active_profile, {})) else None

def _push_face_map_async():
    """双人/多人档槽位源脸粘滞推送到主引擎(2026-07-10 直连补件)。
    /faceswap_raw 二进制直连不过 Hub 的逐帧 source_map 注入(07-09 直连上线后双人档因此
    静默失效——直连只剩激活单脸+锁主脸)；引擎粘滞态(/face_map/active)即直连真相。
    保存映射/激活角色/槽位角色定妆变更/主引擎回切四处共用；关闭或无有效槽=推空清除。
    旧引擎无此端点=404 无害(其时直连本就不支持双人,JSON 通道仍靠逐帧注入)。"""
    sm = _face_map_sources()
    def _do():
        try:
            requests.post(f"{SERVICES['faceswap']}/face_map/active",
                          json={"enabled": bool(sm), "slots": sm or []},
                          headers=_svc_req_headers(), timeout=8)
        except Exception:
            pass
    threading.Thread(target=_do, daemon=True).start()

# 启动对账：Hub 重启后把持久化槽位补推引擎（延迟等引擎起身；失败无害——
# 激活角色/保存映射/引擎回切都会再推。引擎自身重启由其落盘粘滞态恢复）。
try:
    _fm_boot_push = threading.Timer(12.0, _push_face_map_async)
    _fm_boot_push.daemon = True     # 工具脚本 import 本模块时不阻塞解释器退出
    _fm_boot_push.start()
except Exception:
    pass

@app.get("/api/face_map")
def api_face_map_get():
    """双人/多人换脸映射配置 + 槽位有效性(角色存在且有脸)。"""
    slots = []
    for i, nm in enumerate(_face_map_state["slots"]):
        nm = (nm or "").strip()
        p = _profiles.get(nm) if nm else None
        slots.append({"slot": i, "profile": nm,
                      "valid": bool(p and p.get("face_b64")) if nm else None,
                      "fallback_active": not nm})
    return {"ok": True, "enabled": _face_map_state["enabled"], "slots": slots,
            "max_slots": _FACE_MAP_MAX_SLOTS,
            "hint": "画面里的脸按从左到右依次对应槽0、槽1、…；空槽用当前激活角色；超出槽位的脸回退槽0"}

@app.post("/api/face_map")
def api_face_map_set(body: dict = Body(...)):
    """写映射：{enabled:bool, slots:[角色名|"",...]}。名字须存在且已绑脸(空=用激活角色)；
    2-4 槽(超出截断)。保存即粘滞推送引擎——直连通道立即生效，无需重启开播。"""
    slots = list(body.get("slots") or _face_map_state["slots"])[:_FACE_MAP_MAX_SLOTS]
    slots = [(s if isinstance(s, str) else "").strip() for s in slots]
    slots = (slots + ["", ""])[:max(2, len(slots))]
    for nm in slots:
        if not nm:
            continue
        if nm not in _profiles:
            raise HTTPException(404, f"角色不存在：{nm}")
        if not _profiles[nm].get("face_b64"):
            raise HTTPException(400, f"角色「{nm}」未绑定人脸图，无法入槽")
    _face_map_state["slots"] = slots
    if "enabled" in body:
        _face_map_state["enabled"] = bool(body.get("enabled"))
    try:
        _FACE_MAP_FILE.write_text(json.dumps(_face_map_state, ensure_ascii=False), encoding="utf-8")
    except Exception:
        pass
    _push_face_map_async()      # 直连通道(粘滞态)与 JSON 通道(逐帧注入)同步生效
    _logger.info(f"[FaceMap] enabled={_face_map_state['enabled']} slots={slots}")
    return api_face_map_get()


# ── Phase 12 C-3 发型场次定妆：开播前离线 HairFastGAN 生成「定妆脸」写进角色 ──
#   ADR-12-03：5-10s 模型 RT 不可实时；定妆结果作为换脸源脸(faces/switch + /faceswap 注入)，
#   实时链零新增开销——直播中每帧用的仍是静态源脸，只是这张脸提前换好了发型。
def _push_active_face_async(name: str):
    """角色为当前激活时，把(可能新的)换脸源脸推给 faceswap 服务，立即生效。"""
    if name in (_face_map_state.get("slots") or []):
        _push_face_map_async()          # 槽位角色定妆脸变更 → 直连粘滞槽位跟着换(JSON 通道本就逐帧现取)
    if name != _active_profile:
        return
    img = _profile_swap_face(_profiles.get(name, {}))
    if not img:
        return
    def _sw():
        try:
            requests.post(f"{SERVICES['faceswap']}/faces/switch",
                          json={"name": name, "image": img},
                          headers=_svc_req_headers(), timeout=5)
        except Exception:
            pass
    threading.Thread(target=_sw, daemon=True).start()

@app.post("/api/profiles/{name}/face_gallery")
async def api_profile_face_gallery(name: str, body: dict = Body(default={})):
    """管理角色的多照片源脸集（辨识度增强）。body:
      {images:[b64,...]}  整表替换；或 {add:[b64,...]} 追加；或 {clear:true} 清空。
    保存后若为当前激活角色，立即重注册平均 embedding 生效。返回当前附图数量。"""
    _check_profile_name(name)
    p = _profiles.get(name)
    if not p:
        raise HTTPException(404, "角色不存在")
    cur = list(p.get("face_gallery_b64") or [])
    if body.get("clear"):
        cur = []
    elif isinstance(body.get("images"), list):
        cur = [b for b in body["images"] if b]
    elif isinstance(body.get("add"), list):
        cur += [b for b in body["add"] if b]
    else:
        raise HTTPException(400, "需要 images / add / clear 之一")
    cur = cur[:8]                          # 上限 8 张：平均收益早已饱和，防库膨胀
    for b in cur:
        if len(b) > _B64_LIMIT:
            raise HTTPException(413, "单张附图超过 5MB 限制，请压缩")
    async with _PROFILES_LOCK:
        if name not in _profiles:
            raise HTTPException(404, "角色不存在")
        _profiles[name]["face_gallery_b64"] = cur
        if not _save_profile(name):
            raise HTTPException(500, "保存失败，请重试")
    if name == _active_profile:
        _register_avg_face_async(name)
    return {"ok": True, "profile": name, "gallery_count": len(cur),
            "averaging": len(cur) >= 1,
            "hint": "多张不同角度/光照照片可提升换脸辨识度；直播中已激活角色即时生效"}

