# ── 阶段10 出片历史（2026-07-08）────────────────────────────────────────────
# 痛点：face_styled_b64 每次定妆直接覆盖——试了 5 个妆想回到第 2 个只能重跑
# （发型 8s + 妆容 2s + 显存过闸，还未必复现同款）。tryon/idle 虽然留了文件，
# 但角色只指向最新一条，没有任何浏览/回滚入口。
# 方案：每次出片成功后旁路落一份 jpg + json 边车到 data/look_history/<角色>/，
# 列表按边车 glob（无中心索引=无索引损坏问题），恢复=把文件读回角色字段。
# 记录是尽力而为：历史写失败绝不影响主链出片结果。
_LOOK_HIST_ROOT = Path(_BASE) / "data" / "look_history"
_LOOK_HIST_KEEP = int(os.environ.get("LOOK_HISTORY_KEEP", "24"))   # 每角色条数上限
_LOOK_HIST_ID_RE = re.compile(r"^\d{10,17}_[a-z]+$")               # 防路径穿越
_LOOK_HIST_KINDS = ("hair", "makeup", "lookpack", "tryon", "idle", "facehair")


def _look_hist_dir(name: str) -> Path:
    d = _LOOK_HIST_ROOT / name
    d.mkdir(parents=True, exist_ok=True)
    return d


# ── 阶段13 出片即生效 ─────────────────────────────────────────────────────
# 事实核查（走查第二轮）：body_video 在口型链是内容寻址（sha1→vid_ 前缀 face_id），
# 换新视频下一句自动预计算新基底——**无需重新激活**，旧提示语误导运营多做一步。
# idle_video 仅 vcam 待机链消费：角色正激活且 vcam 启用时重推待机循环即即时生效。
def _repush_idle_if_active(name: str) -> bool:
    """出片角色正是激活角色且 vcam 启用 → 重推待机循环（真人半身优先）。
    返回是否真的推了（调用方据此写人话提示）。失败静默——提示语兜底为重新激活。"""
    if name != _active_profile or not _vcam_enabled:
        return False
    fb = (_profiles.get(name) or {}).get("face_b64", "")
    if not fb:
        return False
    try:
        _t = asyncio.create_task(_vcam_set_idle(base64.b64decode(fb)))
        _t.add_done_callback(lambda t: t.exception() if not t.cancelled() else None)
        return True
    except Exception:
        return False


def _video_effect_hint(name: str, field: str, repushed: bool) -> str:
    """出片后视频字段的生效方式人话提示（按真实链路行为写，不再一刀切喊重新激活）。"""
    if field == "body_video":
        return ("已激活：下一句口型自动换新底片（无需重新激活）" if name == _active_profile
                else "激活该角色后第一句口型即用新底片")
    if repushed:
        return "待机画面已即时推送更新"
    if not _vcam_enabled:   # vcam 关时重新激活也不会消费 idle_video——别让运营空等
        return "已入库（虚拟摄像头待机未启用；设 AVATARHUB_VCAM=1 后激活即生效）"
    return "重新激活角色后待机生效"


# ── 阶段12 全身照记忆：试衣的 person 照按角色存档，换装免重传 ────────────────
_BODY_PHOTO_DIR = Path(_BASE) / "data" / "body_photo"


def _body_photo_path(name: str) -> Path:
    return _BODY_PHOTO_DIR / f"{name}.jpg"


def _save_body_photo(name: str, b64s: str) -> None:
    """存档失败只打日志——存照是便利品，不反噬试衣主链。"""
    try:
        if "," in b64s:
            b64s = b64s.split(",", 1)[1]
        _BODY_PHOTO_DIR.mkdir(parents=True, exist_ok=True)
        _body_photo_path(name).write_bytes(base64.b64decode(b64s))
    except Exception as e:
        _logger.warning(f"[BodyPhoto] 存档失败(不影响试衣): {e}")


def _look_hist_entries(name: str) -> list[dict]:
    """按时间倒序读边车。坏边车跳过不炸。"""
    out = []
    d = _LOOK_HIST_ROOT / name
    if not d.is_dir():
        return out
    for f in d.glob("*.json"):
        try:
            e = json.loads(f.read_text(encoding="utf-8"))
            if _LOOK_HIST_ID_RE.match(str(e.get("id", ""))):
                out.append(e)
        except Exception:
            continue
    return sorted(out, key=lambda e: e.get("ts", 0), reverse=True)


def _look_hist_record(name: str, kind: str, image_b64: str = "",
                      image_bytes: bytes = b"", meta: dict | None = None) -> str:
    """出片成功后旁路记录一条历史。返回条目 id（失败/去重跳过返回 ""）。
    连续重复去重：同 kind 最新一条 md5 相同（同参数重跑/手滑连点）→ 不再落新条目。
    超上限剪枝最旧。任何异常只打日志——历史是增值品，绝不反噬主链。"""
    try:
        import hashlib as _hl
        raw = image_bytes or (base64.b64decode(image_b64) if image_b64 else b"")
        if not raw:
            return ""
        md5 = _hl.md5(raw).hexdigest()
        entries = _look_hist_entries(name)
        latest_same = next((e for e in entries if e.get("kind") == kind), None)
        if latest_same and latest_same.get("md5") == md5:
            return ""
        d = _look_hist_dir(name)
        hid = f"{int(time.time() * 1000)}_{kind}"
        (d / f"{hid}.jpg").write_bytes(raw)
        (d / f"{hid}.json").write_text(json.dumps(
            {"id": hid, "ts": time.time(), "kind": kind, "md5": md5,
             "meta": meta or {}}, ensure_ascii=False), encoding="utf-8")
        for e in entries[max(_LOOK_HIST_KEEP - 1, 1):]:      # 新条目占一格
            for suf in (".jpg", ".json", "_t.jpg"):
                (d / f"{e['id']}{suf}").unlink(missing_ok=True)
        return hid
    except Exception as e:
        _logger.warning(f"[LookHist] 记录失败(不影响出片): {e}")
        return ""


def _look_hist_paths(name: str, hid: str) -> tuple[Path, Path]:
    """(jpg, json) 路径；hid 不合法或不存在 → 404。"""
    if not _LOOK_HIST_ID_RE.match(hid or ""):
        raise HTTPException(400, "历史条目 id 不合法")
    d = _LOOK_HIST_ROOT / name
    jp, sp = d / f"{hid}.jpg", d / f"{hid}.json"
    if not jp.exists() or not sp.exists():
        raise HTTPException(404, "历史条目不存在（可能已被剪枝）")
    return jp, sp


@app.get("/api/profiles/{name}/look_history")
async def api_look_history(name: str):
    """出片历史列表（新→旧，≤LOOK_HISTORY_KEEP 条）。视频路径顺带回验存在性。"""
    _check_profile_name(name)
    entries = _look_hist_entries(name)
    for e in entries:
        e.pop("md5", None)
        v = (e.get("meta") or {}).get("video")
        if v:
            e["meta"]["video_exists"] = Path(v).exists()
    return {"ok": True, "profile": name, "entries": entries,
            "keep": _LOOK_HIST_KEEP}


@app.get("/api/profiles/{name}/look_history/{hid}/image")
async def api_look_history_image(name: str, hid: str, thumb: int = 0):
    """历史图（thumb=1 → 160px 缩略，磁盘缓存 <id>_t.jpg）。"""
    _check_profile_name(name)
    jp, _ = _look_hist_paths(name, hid)
    if thumb:
        tp = jp.with_name(f"{hid}_t.jpg")
        if not tp.exists():
            try:
                import cv2
                import numpy as np
                img = cv2.imdecode(np.frombuffer(jp.read_bytes(), np.uint8), cv2.IMREAD_COLOR)
                h, w = img.shape[:2]
                s = 160 / max(h, w)
                img = cv2.resize(img, (max(int(w * s), 1), max(int(h * s), 1)))
                ok, buf = cv2.imencode(".jpg", img, [cv2.IMWRITE_JPEG_QUALITY, 85])
                if ok:
                    tp.write_bytes(buf.tobytes())
            except Exception:
                tp = jp             # 缩略失败退原图
        return Response(content=tp.read_bytes(), media_type="image/jpeg",
                        headers={"Cache-Control": "max-age=3600"})
    return Response(content=jp.read_bytes(), media_type="image/jpeg",
                    headers={"Cache-Control": "max-age=3600"})


@app.post("/api/profiles/{name}/look_history/{hid}/restore")
async def api_look_history_restore(name: str, hid: str):
    """一键回滚：把历史条目写回角色。
    hair/makeup/lookpack → face_styled_b64(+use_styled_face)；hair 同步链式基底 face_hair_b64；
    tryon/idle → 角色视频字段指回旧 mp4（文件还在才行）+ tryon 静图。回滚本身也记历史？
    不记——回滚不产生新画面，避免历史被回滚操作刷屏。"""
    _check_profile_name(name)
    p = _profiles.get(name)
    if not p:
        raise HTTPException(404, "角色不存在")
    jp, sp = _look_hist_paths(name, hid)
    entry = json.loads(sp.read_text(encoding="utf-8"))
    kind = entry.get("kind", "")
    meta = entry.get("meta") or {}
    if kind not in _LOOK_HIST_KINDS:
        raise HTTPException(400, f"未知条目类型: {kind}")

    # facehair 是**出片合成图**（脸+发+目标身体/背景）——不回填定妆脸/视频字段；
    # 「用这版」= 设为角色底片(tryon_image 位)：待机微动(idle_motion source=auto 优先 tryon)
    # 即用这张 脸+发型 合成照驱动 → 数字人链路真正带上发型。
    if kind == "facehair":
        async with _PROFILES_LOCK:
            if name not in _profiles:
                raise HTTPException(404, "角色不存在")
            _profiles[name]["tryon_image"] = str(jp)
            _profiles[name]["tryon_at"] = time.time()
            if not _save_profile(name):
                raise HTTPException(500, "保存失败，请重试")
        return {"ok": True, "profile": name, "id": hid, "kind": kind,
                "applied": ["tryon_image"],
                "hint": "已设为角色底片——再跑一次「待机微动」，数字人就用这张 脸+发型 合成照"}

    applied: list[str] = []
    async with _PROFILES_LOCK:
        if name not in _profiles:
            raise HTTPException(404, "角色不存在")
        prof = _profiles[name]
        if kind in ("hair", "makeup", "lookpack"):
            b64img = base64.b64encode(jp.read_bytes()).decode()
            prof["face_styled_b64"] = b64img
            prof["use_styled_face"] = True
            applied.append("face_styled_b64")
            if kind == "hair":
                prof["face_hair_b64"] = b64img       # 链式基底一并回滚，妆容重跑不丢这头发
                applied.append("face_hair_b64")
            if meta.get("style"):
                prof["hair_style" if kind == "hair" else "makeup_style"] = meta["style"]
        else:                                        # tryon / idle：指回旧视频
            field = meta.get("field") or ("body_video" if kind == "tryon" else "idle_video")
            video = meta.get("video") or ""
            if video and Path(video).exists():
                prof[field] = video
                applied.append(field)
            elif kind == "idle":
                raise HTTPException(409, "该条目的视频文件已不存在，无法回滚")
            if kind == "tryon":
                prof["tryon_image"] = str(jp)        # 历史 jpg 本身就是试衣静图
                applied.append("tryon_image")
        if not applied:
            raise HTTPException(409, "没有可回滚的内容（视频文件缺失？）")
        if not _save_profile(name):
            raise HTTPException(500, "回滚保存失败，请重试")
    if kind in ("hair", "makeup", "lookpack"):
        _push_active_face_async(name)                # 正在播的角色立即换脸生效
        _hint = "定妆脸已回滚并推送"
    else:
        _f = next((f for f in applied if f.endswith("_video")), "")
        _rp = _repush_idle_if_active(name) if _f == "idle_video" else False
        _hint = ("视频字段已指回该版本——" + _video_effect_hint(name, _f, _rp)) if _f \
                else "试衣静图已指回该版本"
    return {"ok": True, "profile": name, "id": hid, "kind": kind,
            "applied": applied, "hint": _hint}


@app.post("/api/profiles/{name}/look_history/{hid}/delete")
async def api_look_history_delete(name: str, hid: str):
    """删单条历史（jpg+边车+缩略缓存）。不动角色当前字段。"""
    _check_profile_name(name)
    jp, sp = _look_hist_paths(name, hid)
    for f in (jp, sp, jp.with_name(f"{hid}_t.jpg")):
        f.unlink(missing_ok=True)
    return {"ok": True, "id": hid,
            "left": len(_look_hist_entries(name))}


@app.post("/api/profiles/{name}/hair_preset")
async def api_profile_hair_preset(name: str, body: dict = Body(default={})):
    """离线跑发型迁移(8001)得到「定妆脸」存入角色。body:{hair_style?, hair_image_b64?, apply?=true}。
    hair_style=已上传样式名(服务端激活后用)；hair_image_b64=直接给参考图；都空=用 8001 当前激活样式。"""
    _check_profile_name(name)
    p = _profiles.get(name)
    if not p:
        raise HTTPException(404, "角色不存在")
    if not p.get("face_b64"):
        raise HTTPException(400, "角色未绑定人脸图，先在角色库绑脸")
    style = (body.get("hair_style") or "").strip()
    hair_b64 = (body.get("hair_image_b64") or "").strip()
    if style and not hair_b64:
        try:                    # 具名样式：先激活成 8001 默认参考，再走空 hair_image 路径
            await http_pool.post(f"{SERVICES['hair']}/hair_styles/activate",
                                 json={"name": style}, timeout=5)
        except Exception as e:
            raise HTTPException(503, f"发型服务(8001)不可达：{str(e)[:120]}")
    try:                        # HairFastGAN 5-10s + 冷启动余量（闸抖动自带退避重试）
        r = await _hair_transfer_call({"source_image": p["face_b64"],
                                       "hair_image": hair_b64}, timeout=90)
        j = r.json()
    except Exception as e:
        raise HTTPException(503, f"发型迁移超时/不可达：{str(e)[:120]}")
    if r.status_code != 200 or not j.get("result_image"):
        raise HTTPException(502, f"发型迁移失败：{str(j.get('detail') or r.status_code)[:160]}")
    async with _PROFILES_LOCK:
        if name not in _profiles:
            raise HTTPException(404, "角色不存在")
        _profiles[name]["face_styled_b64"] = j["result_image"]
        _profiles[name]["face_hair_b64"] = j["result_image"]   # 妆容定妆的基底（链式重跑不丢发型）
        _profiles[name]["hair_style"] = style or "custom"
        _profiles[name]["hair_styled_at"] = time.time()
        if bool(body.get("apply", True)):
            _profiles[name]["use_styled_face"] = True
        if not _save_profile(name):
            raise HTTPException(500, "定妆结果保存失败，请重试")
    _push_active_face_async(name)
    _look_hist_record(name, "hair", image_b64=j["result_image"],
                      meta={"style": style or "custom"})
    return {"ok": True, "profile": name, "hair_style": style or "custom",
            "elapsed_ms": j.get("elapsed_ms"),
            "use_styled_face": bool(_profiles[name].get("use_styled_face")),
            "preview_image": j["result_image"]}

@app.post("/api/profiles/{name}/hair_preset/toggle")
async def api_profile_hair_preset_toggle(name: str, body: dict = Body(default={})):
    """启/停「定妆脸作为换脸源」。body:{use:bool}；缺省=取反。不删定妆结果。"""
    _check_profile_name(name)
    p = _profiles.get(name)
    if not p:
        raise HTTPException(404, "角色不存在")
    if not p.get("face_styled_b64"):
        raise HTTPException(400, "该角色还没有定妆脸，先跑一次发型定妆")
    async with _PROFILES_LOCK:
        cur = bool(_profiles[name].get("use_styled_face"))
        _profiles[name]["use_styled_face"] = bool(body["use"]) if "use" in body else (not cur)
        if not _save_profile(name):
            _profiles[name]["use_styled_face"] = cur
            raise HTTPException(500, "保存失败，请重试")
    _push_active_face_async(name)
    return {"ok": True, "profile": name,
            "use_styled_face": bool(_profiles[name]["use_styled_face"]),
            "hair_style": _profiles[name].get("hair_style", "")}


# ── 阶段15 动态试衣（CatV2TON 视频换装·作业制代理，8006）─────────────────────
#   分钟级作业：Hub 只做提交/轮询/取片/应用四件事 + 显存腾挪，不长阻塞。
#   峰值 ~17G 全机最大单体 → 提交前 Hub 主动腾挪（卸闲置模型 + 泊本模式闲引擎），
#   被泊引擎由 self-heal / 模式切换自动拉回，无需本模块善后。
_vtryon_jobs: dict = {}          # job_id -> {profile, field, cloth, ts, applied}
_VTRYON_JOBS_KEEP = 30


async def _videotryon_vram_rescue() -> tuple:
    """为动态试衣腾显存三板斧（沿用 matting 租约/free_unused 成例）：
    ① 卸闲置可回载模型：发型(≥6G)/高清口型(≥3G)/听写(~1G)——下次用时秒级懒加载；
    ② free_unused 内核泊掉「本开播模式用不到」的重引擎（如换脸模式的 lipsync）；
    ③ 被泊者登记 _PARK_SUSPEND 挂起自愈——三次冒烟实锤：不挂起的话 self-heal
      会在 6 分钟作业中途把 lipsync(+5G) 拉回来，物理显存被挤穿逼近整机冻结。
    绝不动直播关键链（faceswap/vcam/正在用的引擎）。返回 (动作清单, 被泊服务)。"""
    acts, parked = [], []
    for key, path in (("hair", "/unload"), ("latentsync", "/unload"),
                      ("stt", "/asr/unload")):
        try:
            r = await http_pool.post(f"{SERVICES[key]}{path}",
                                     headers=_svc_req_headers(), timeout=30)
            if r.status_code == 200:
                j = r.json()
                if j.get("was_loaded") or j.get("unloaded"):
                    acts.append(f"unload:{key}")
        except Exception:
            continue
    try:
        r2 = await _gpu_free_unused_core()
        for s in (r2 or {}).get("stopped", []):
            if s.get("ok") and s.get("service"):
                parked.append(s["service"])
                _PARK_SUSPEND.add(s["service"])
                acts.append(f"park:{s['service']}")
    except Exception:
        pass
    if acts:
        _logger.info(f"[VideoTryon] 显存腾挪: {' + '.join(acts)}")
    return acts, parked


def _vtryon_unpark(jid: str):
    """作业收尾（完成/失败/超时兜底）：解除被泊引擎的自愈挂起，self-heal 下一
    周期自动拉回。幂等，多处触发也只做一次。"""
    ctx = _vtryon_jobs.get(jid) or {}
    parked, ctx["parked"] = ctx.get("parked") or [], []
    for n in parked:
        _PARK_SUSPEND.discard(n)
    if parked:
        _logger.info(f"[VideoTryon] 作业 {jid} 收尾：解除泊车 {parked}（自愈将拉回）")


def _vtryon_is_vram_reject(status: int, j) -> bool:
    d = (j or {}).get("detail") if isinstance(j, dict) else None
    return status == 503 and (isinstance(d, dict) and d.get("error") == "vram"
                              or "显存" in str(d or ""))


@app.post("/api/videotryon/submit")
async def api_videotryon_submit(body: dict = Body(default={})):
    """动态试衣提交：角色的待机微动/底视频 + 服装 → CatV2TON 视频换装作业。
    body:{profile(必填), cloth_name?|cloth_b64?, cloth_type?=upper,
          field?=idle_video(完成后应用目标), source?=idle_video|body_video,
          max_frames?=48, steps?=15}
    显存不足 → 自动腾挪（卸闲置模型+泊闲置引擎）后重试一次；仍不足透传人话 503。
    返回 {job_id}，前端轮询 /api/videotryon/job/{id}。"""
    name = (body.get("profile") or "").strip()
    _check_profile_name(name)
    p = _profiles.get(name)
    if not p:
        raise HTTPException(404, "角色不存在")
    src = (body.get("source") or "").strip()
    fields = [src] if src in ("idle_video", "body_video") else ["idle_video", "body_video"]
    vp = ""
    for f in fields:
        v = p.get(f) or ""
        if v and Path(v).exists():
            vp = v
            break
    if not vp:
        raise HTTPException(400, "角色没有可用的待机微动/底视频——先在 C-4 生成「待机微动」再来")
    payload = {"person_video_path": vp,
               "cloth_type": (body.get("cloth_type") or "upper"),
               "max_frames": int(body.get("max_frames") or 48),
               "steps": int(body.get("steps") or 15)}
    if body.get("cloth_b64"):
        payload["cloth_image"] = body["cloth_b64"]
    elif body.get("cloth_name"):
        payload["cloth_name"] = body["cloth_name"]
    else:
        raise HTTPException(400, "请指定服装（cloth_name 或上传 cloth_b64）")

    # 服务未起 → supervisor 代拉（懒加载服务启动秒级，不用等模型）
    try:
        h = await http_pool.get(f"{SERVICES['videotryon']}/health",
                                headers=_svc_req_headers(), timeout=3)
        _ = h.json()
    except Exception:
        if _supervisor is not None:
            try:
                await asyncio.to_thread(_supervisor.ensure_up, "videotryon")
                await asyncio.sleep(6)
            except Exception:
                pass

    # 主动腾挪（E2E 实锤的设计课）：只在 503 被拒后才腾挪的话，「闸门擦边放行」
    # 的单子会带着 lipsync/ditto 同卡开跑——去噪勉强撑过，解码期配额被物理空闲
    # 卡死在 12G 直接 OOM。作业分钟级、被泊引擎完事自动回场，提交即腾挪才是对的。
    parked_now: list = []
    try:
        _, parked_now = await _videotryon_vram_rescue()
        if parked_now:
            await asyncio.sleep(3)              # 等驱动真正回收物理页
    except Exception:
        pass

    r = j = None
    for attempt in (1, 2):
        try:
            r = await http_pool.post(f"{SERVICES['videotryon']}/video_tryon",
                                     json=payload, headers=_svc_req_headers(), timeout=20)
        except Exception as e:
            for n in parked_now:                # 提交都没成，别把引擎晾在泊位
                _PARK_SUSPEND.discard(n)
            raise HTTPException(503, f"动态试衣服务不可达：{str(e)[:120]}")
        try:
            j = r.json()
        except Exception:
            j = {}
        if r.status_code == 200 and j.get("job_id"):
            jid = j["job_id"]
            _vtryon_jobs[jid] = {"profile": name, "ts": time.time(),
                                 "field": (body.get("field") or "idle_video"),
                                 "cloth": body.get("cloth_name") or "上传服装",
                                 "applied": False, "parked": parked_now}
            while len(_vtryon_jobs) > _VTRYON_JOBS_KEEP:
                old = min(_vtryon_jobs, key=lambda k: _vtryon_jobs[k]["ts"])
                _vtryon_unpark(old)
                _vtryon_jobs.pop(old, None)
            # 兜底解泊：作业最长 ~15 分钟，之后无论前端是否还在轮询都放引擎回来
            async def _unpark_deadline(j_id: str):
                await asyncio.sleep(15 * 60)
                _vtryon_unpark(j_id)
            asyncio.create_task(_unpark_deadline(jid))
            return {"ok": True, "job_id": jid,
                    "hint": "作业已提交（约 3-8 分钟）——完成后可一键应用为待机视频"}
        if attempt == 1 and _vtryon_is_vram_reject(r.status_code, j):
            acts, _p2 = await _videotryon_vram_rescue()   # 再挪一轮（如首轮后有引擎自启）
            parked_now = list({*parked_now, *_p2})
            if acts:
                await asyncio.sleep(3)          # 等驱动真正回收物理页
                continue
        break
    for n in parked_now:                        # 提交失败收尾：解除挂起，自愈拉回
        _PARK_SUSPEND.discard(n)
    detail = (j or {}).get("detail") or f"HTTP {r.status_code if r is not None else '?'}"
    if isinstance(detail, dict):
        detail = detail.get("msg") or str(detail)
    raise HTTPException(r.status_code if r is not None else 502, f"动态试衣提交失败：{detail}")


@app.get("/api/videotryon/job/{jid}")
async def api_videotryon_job(jid: str):
    """作业进度代理 + Hub 侧上下文（归属角色/目标字段/是否已应用）。"""
    try:
        r = await http_pool.get(f"{SERVICES['videotryon']}/job/{jid}",
                                headers=_svc_req_headers(), timeout=6)
        j = r.json()
    except Exception as e:
        raise HTTPException(503, f"动态试衣服务不可达：{str(e)[:100]}")
    if r.status_code != 200:
        raise HTTPException(r.status_code, str(j.get("detail") or "作业不存在")[:160])
    ctx = _vtryon_jobs.get(jid) or {}
    if j.get("state") in ("done", "error"):
        _vtryon_unpark(jid)                    # 终态即解泊（自愈拉回被泊引擎）
    j["profile"] = ctx.get("profile", "")
    j["field"] = ctx.get("field", "idle_video")
    j["applied"] = bool(ctx.get("applied"))
    j.pop("result_path", None)                 # 本机路径不外泄，取片走下面两个端点
    j.pop("preview_path", None)
    return j


