@app.post("/api/videotryon/job/{jid}/apply")
async def api_videotryon_apply(jid: str, body: dict = Body(default={})):
    """把完成的动态试衣视频应用到角色（默认写 idle_video 待机循环）。
    body:{profile?(缺省=提交时角色), field?=idle_video|body_video}
    落库到 data/video_tryon/applied/ + 记出片历史 + 激活角色即时重推待机。"""
    ctx = _vtryon_jobs.get(jid) or {}
    name = (body.get("profile") or ctx.get("profile") or "").strip()
    _check_profile_name(name)
    if name not in _profiles:
        raise HTTPException(404, "角色不存在")
    field = body.get("field") or ctx.get("field") or "idle_video"
    if field not in ("idle_video", "body_video"):
        raise HTTPException(400, "field 只能是 idle_video 或 body_video")
    try:
        r = await http_pool.get(f"{SERVICES['videotryon']}/job/{jid}",
                                headers=_svc_req_headers(), timeout=6)
        j = r.json()
    except Exception as e:
        raise HTTPException(503, f"动态试衣服务不可达：{str(e)[:100]}")
    if j.get("state") != "done":
        raise HTTPException(409, f"作业未完成（当前 {j.get('state')} {j.get('progress')}%）")
    # 取片：本机共盘直接拷文件；远端(SVC_VIDEOTRYON)则走 HTTP 下载
    out_dir = Path(rf"{_BASE}\data\video_tryon\applied\{name}")
    out_dir.mkdir(parents=True, exist_ok=True)
    dst = out_dir / f"{int(time.time())}_{jid}.mp4"
    src_path = j.get("result_path") or ""
    if src_path and Path(src_path).exists():
        import shutil
        shutil.copyfile(src_path, dst)
    else:
        rr = await http_pool.get(f"{SERVICES['videotryon']}/job/{jid}/result",
                                 headers=_svc_req_headers(), timeout=60)
        if rr.status_code != 200:
            raise HTTPException(502, "结果视频获取失败")
        dst.write_bytes(rr.content)
    async with _PROFILES_LOCK:
        if name not in _profiles:
            raise HTTPException(404, "角色不存在")
        _profiles[name][field] = str(dst)
        if not _save_profile(name):
            raise HTTPException(500, "保存失败，请重试")
    poster = b""
    try:
        pr = await http_pool.get(f"{SERVICES['videotryon']}/job/{jid}/preview",
                                 headers=_svc_req_headers(), timeout=10)
        if pr.status_code == 200:
            poster = pr.content
    except Exception:
        pass
    if poster:
        _look_hist_record(name, "vtryon", image_bytes=poster,
                          meta={"style": ctx.get("cloth") or "动态试衣", "field": field,
                                "video": str(dst), "meta": j.get("meta") or {}})
    if jid in _vtryon_jobs:
        _vtryon_jobs[jid]["applied"] = True
    _rp = _repush_idle_if_active(name) if field == "idle_video" else False
    return {"ok": True, "profile": name, "field": field, "video": str(dst),
            "hint": "动态试衣视频已应用——" + _video_effect_hint(name, field, _rp)}


# ── Phase 12+ C-5 妆容定妆 + Look Pack 一键定妆包（2026-07-08）──────────────
#   分层策略延续 ADR-12-03：慢操作离线烘焙进 face_styled_b64，实时链零新增开销。
#   链式基底约定：face_hair_b64(发型后) > face_b64(原脸)——妆容可独立重跑不丢发型。
def _live_makeup_suggest(p: dict, applied: dict) -> None:
    """定妆成功后把妆容色回写为角色 live_makeup 建议值（色彩单一真相：离线定妆与
    直播层同色）。只写颜色/强度，不动 enabled 开关——是否上直播由用户显式决定。
    直播层强度按 0.8 折减：输出端叠加在已换脸+增强的帧上，同强度观感更重。"""
    lmk = dict(p.get("live_makeup", {}))
    for key in ("lip", "blush", "eye"):
        info = (applied or {}).get(key) or {}
        if info.get("color"):
            lmk[f"{key}_color"] = [int(v) for v in info["color"]]
            try:
                lmk[key] = round(float(info.get("strength", 0.4)) * 0.8, 2)
            except Exception:
                lmk[key] = 0.35
    p["live_makeup"] = lmk


async def _makeup_call(source_b64: str, style: str = "", ref_b64: str = "",
                       params: dict | None = None) -> dict:
    """调用妆容服务(8004)。失败抛 HTTPException（调用方决定软降级或透传）。"""
    body = {"source_image": source_b64}
    if ref_b64:
        body["ref_image"] = ref_b64
    elif style:
        body["style"] = style
    if params:
        body["params"] = params
    try:                        # 区域颜色迁移 1~3s + 冷启动余量
        r = await http_pool.post(f"{SERVICES['makeup']}/makeup_transfer",
                                 json=body, headers=_svc_req_headers(), timeout=60)
        j = r.json()
    except Exception as e:
        raise HTTPException(503, f"妆容服务(8004)不可达：{str(e)[:120]}")
    if r.status_code != 200 or not j.get("result_image"):
        raise HTTPException(502, f"妆容迁移失败：{str(j.get('detail') or r.status_code)[:160]}")
    return j


@app.post("/api/profiles/{name}/makeup_preset")
async def api_profile_makeup_preset(name: str, body: dict = Body(default={})):
    """离线上妆得到「定妆脸」存入角色。body:{style?, ref_image_b64?, params?, apply?=true}。
    基底自动选 face_hair_b64(发型定妆结果) > face_b64——妆容重跑不丢发型。"""
    _check_profile_name(name)
    p = _profiles.get(name)
    if not p:
        raise HTTPException(404, "角色不存在")
    base = p.get("face_hair_b64") or p.get("face_b64", "")
    if not base:
        raise HTTPException(400, "角色未绑定人脸图，先在角色库绑脸")
    style = (body.get("style") or "").strip()
    j = await _makeup_call(base, style=style,
                           ref_b64=(body.get("ref_image_b64") or "").strip(),
                           params=body.get("params") or None)
    async with _PROFILES_LOCK:
        if name not in _profiles:
            raise HTTPException(404, "角色不存在")
        _profiles[name]["face_styled_b64"] = j["result_image"]
        _profiles[name]["makeup_style"] = j.get("style") or style or "custom"
        _profiles[name]["makeup_styled_at"] = time.time()
        _live_makeup_suggest(_profiles[name], j.get("applied"))
        if bool(body.get("apply", True)):
            _profiles[name]["use_styled_face"] = True
        if not _save_profile(name):
            raise HTTPException(500, "定妆结果保存失败，请重试")
    _push_active_face_async(name)
    _look_hist_record(name, "makeup", image_b64=j["result_image"],
                      meta={"style": _profiles[name]["makeup_style"]})
    return {"ok": True, "profile": name, "makeup_style": _profiles[name]["makeup_style"],
            "elapsed_ms": j.get("elapsed_ms"), "applied": j.get("applied"),
            "use_styled_face": bool(_profiles[name].get("use_styled_face")),
            "preview_image": j["result_image"]}


@app.post("/api/profiles/{name}/look_pack")
async def api_profile_look_pack(name: str, body: dict = Body(default={})):
    """一键定妆包：原脸 → 发型(可选) → 妆容(可选) 链式烘焙进 face_styled_b64。
    body:{hair_style?, hair_image_b64?, makeup_style?, makeup_ref_b64?, makeup_params?, apply?=true}
    单步失败软降级（跳过该步、记录原因），有一步成功即落库——与全栈软降级哲学一致。"""
    _check_profile_name(name)
    p = _profiles.get(name)
    if not p:
        raise HTTPException(404, "角色不存在")
    if not p.get("face_b64"):
        raise HTTPException(400, "角色未绑定人脸图，先在角色库绑脸")

    steps: dict = {}
    base = p["face_b64"]
    hair_result = ""

    want_hair = bool((body.get("hair_style") or "").strip() or (body.get("hair_image_b64") or "").strip()
                     or body.get("use_hair"))    # use_hair=true → 用 8001 当前激活发型
    if want_hair:
        _t = time.time()
        try:
            style = (body.get("hair_style") or "").strip()
            hair_b64 = (body.get("hair_image_b64") or "").strip()
            if style and not hair_b64:
                await http_pool.post(f"{SERVICES['hair']}/hair_styles/activate",
                                     json={"name": style}, headers=_svc_req_headers(), timeout=5)
            r = await _hair_transfer_call({"source_image": base,
                                           "hair_image": hair_b64}, timeout=90)
            j = r.json()
            if r.status_code != 200 or not j.get("result_image"):
                raise RuntimeError(str(j.get("detail") or r.status_code)[:160])
            base = hair_result = j["result_image"]
            steps["hair"] = {"ok": True, "ms": int((time.time() - _t) * 1000),
                             "style": style or "custom"}
        except Exception as e:
            steps["hair"] = {"ok": False, "error": f"发型步跳过：{str(e)[:160]}"}

    want_makeup = bool((body.get("makeup_style") or "").strip()
                       or (body.get("makeup_ref_b64") or "").strip()
                       or body.get("makeup_params"))
    _mk_applied: dict = {}
    if want_makeup:
        _t = time.time()
        try:
            j = await _makeup_call(base, style=(body.get("makeup_style") or "").strip(),
                                   ref_b64=(body.get("makeup_ref_b64") or "").strip(),
                                   params=body.get("makeup_params") or None)
            base = j["result_image"]
            _mk_applied = j.get("applied") or {}
            steps["makeup"] = {"ok": True, "ms": j.get("elapsed_ms"),
                               "style": j.get("style"), "applied": list((j.get("applied") or {}).keys())}
        except HTTPException as e:
            steps["makeup"] = {"ok": False, "error": f"妆容步跳过：{str(e.detail)[:160]}"}
        except Exception as e:
            steps["makeup"] = {"ok": False, "error": f"妆容步跳过：{str(e)[:160]}"}

    ok_any = any(s.get("ok") for s in steps.values())
    if not steps:
        raise HTTPException(400, "未指定任何定妆步骤（hair_style/makeup_style/makeup_ref_b64 至少给一个）")
    if ok_any:
        async with _PROFILES_LOCK:
            if name not in _profiles:
                raise HTTPException(404, "角色不存在")
            _profiles[name]["face_styled_b64"] = base
            if hair_result:
                _profiles[name]["face_hair_b64"] = hair_result
                _profiles[name]["hair_style"] = steps["hair"].get("style", "custom")
                _profiles[name]["hair_styled_at"] = time.time()
            if steps.get("makeup", {}).get("ok"):
                _profiles[name]["makeup_style"] = steps["makeup"].get("style") or "custom"
                _profiles[name]["makeup_styled_at"] = time.time()
                _live_makeup_suggest(_profiles[name], _mk_applied)
            if bool(body.get("apply", True)):
                _profiles[name]["use_styled_face"] = True
            if not _save_profile(name):
                raise HTTPException(500, "定妆包保存失败，请重试")
        _push_active_face_async(name)
        _look_hist_record(name, "lookpack", image_b64=base,
                          meta={"style": "+".join(
                                    s.get("style") or k for k, s in steps.items() if s.get("ok")),
                                "steps": {k: bool(s.get("ok")) for k, s in steps.items()}})
    return {"ok": ok_any, "profile": name, "steps": steps,
            "use_styled_face": bool(_profiles.get(name, {}).get("use_styled_face")),
            "preview_image": base if ok_any else ""}


