# ── 试衣间（2026-07-08 阶段4：开播页内嵌面板，FitDiT 后端）────────────────
async def _hair_vram_rescue() -> bool:
    """按需显存仲裁（阶段12 运营走查实锤）：定妆包发型步会把 HairFastGAN 驻留
    （~26G），紧随其后的试衣必撞 8002 显存闸（实测 free 4.4G<7G 拒单）。
    试衣是用户当下显式要的动作 → 值得把闲置的发型模型请下去（下次要发型再
    懒加载 ~25s，公平交换）。返回 True=真卸了，调用方应重试一次。"""
    try:
        h = await http_pool.get(f"{SERVICES['hair']}/health",
                                headers=_svc_req_headers(), timeout=3)
        if not h.json().get("model_loaded"):
            return False
        r = await http_pool.post(f"{SERVICES['hair']}/unload",
                                 headers=_svc_req_headers(), timeout=30)
        out = r.status_code == 200 and bool(r.json().get("was_loaded"))
        if out:
            _logger.info(f"[Tryon] 显存仲裁：发型模型已卸载腾显存 "
                         f"(free→{r.json().get('free_gb', '?')}G)，重试试衣")
        return out
    except Exception as e:
        _logger.warning(f"[Tryon] 显存仲裁失败(不重试): {e}")
        return False


def _is_vram_reject(status: int, j: dict) -> bool:
    """显存闸拒单特征（8001/8002 同款 vram_gate 文案）：503 + 提示带「显存」。"""
    return status == 503 and "显存" in str((j or {}).get("detail", ""))


_HAIR_RETRY_BACKOFFS = (3, 5, 8, 10, 15, 20)   # 渐进退避共 ~61s，盖住分钟级脉冲


async def _hair_transfer_call(payload: dict, timeout: float = 90):
    """8001 发型迁移 + 显存闸脉冲耐心重试（阶段13 走查2实锤）：模型已驻留时推理
    峰值仅 ~3G，但共卡的显存占用是脉冲式的——Hub 重启后激活角色的视频底预计算/
    Ditto 预热会把 free 从 ~6G 压到 <2G 达 1-2 分钟（实测 20:53 失败↔20:55 恢复）。
    拒单是快失败（<0.2s），渐进退避 3→20s 共 ~61s 等脉冲消退——发型侧没有可主动
    卸载的让路对象（它自己就是最大块），与试衣的显存仲裁（卸发型）方向相反，
    这里「等」比「抢」正确。等完仍不足 → 把 8001 的人话 503 透传给调用方。"""
    for i, backoff in enumerate((*_HAIR_RETRY_BACKOFFS, 0)):
        r = await http_pool.post(f"{SERVICES['hair']}/hair_transfer", json=payload,
                                 headers=_svc_req_headers(), timeout=timeout)
        if r.status_code != 503 or not backoff:
            return r
        try:
            j = r.json()
        except Exception:
            j = {}
        if not _is_vram_reject(r.status_code, j):
            return r
        _logger.info(f"[Hair] 显存闸脉冲拒单 → {backoff}s 退避重试 "
                     f"({i + 1}/{len(_HAIR_RETRY_BACKOFFS)})")
        await asyncio.sleep(backoff)
    return r


def _target_asset_bytes(name: str, key: str) -> bytes:
    """按 key 取角色的目标图字节：body=试衣全身照存照 / tryon=最新试衣静图 /
    hist:<id>=出片历史条目 jpg。要求 name 已在 _profiles（注册名=路径安全）。不存在 → b""。"""
    if name not in _profiles:
        return b""
    try:
        if key == "body":
            bp = _body_photo_path(name)
            return bp.read_bytes() if bp.exists() else b""
        if key == "tryon":
            tp = (_profiles.get(name) or {}).get("tryon_image") or ""
            return Path(tp).read_bytes() if tp and Path(tp).exists() else b""
        if key.startswith("hist:"):
            jp, _sp = _look_hist_paths(name, key.split(":", 1)[1])   # id 白名单正则防穿越
            return jp.read_bytes()
    except HTTPException:
        pass
    except Exception:
        pass
    return b""


@app.get("/api/profiles/{name}/target_assets")
async def api_profile_target_assets(name: str):
    """「换脸+发型」出片可直选的目标图资产清单（免每次上传）。
    body=试衣全身照存照；tryon=最新试衣静图；hist:*=出片历史里的试衣条目(最多 6 条)。"""
    _check_profile_name(name)
    if name not in _profiles:
        raise HTTPException(404, "角色不存在")
    items = []
    tp = (_profiles.get(name) or {}).get("tryon_image") or ""
    if tp and Path(tp).exists():
        items.append({"key": "tryon", "label": "试衣静图（最新）", "kind": "tryon"})
    if _body_photo_path(name).exists():
        items.append({"key": "body", "label": "全身照存照", "kind": "body"})
    n = 0
    for e in _look_hist_entries(name):
        if e.get("kind") != "tryon":     # 只放干净的试衣出片；facehair 二次当目标会叠 GAN 伪影
            continue
        ts = time.strftime("%m-%d %H:%M", time.localtime(e.get("ts") or 0))
        items.append({"key": f"hist:{e['id']}", "label": f"试衣出片 {ts}", "kind": "hist"})
        n += 1
        if n >= 6:
            break
    return {"ok": True, "profile": name, "items": items}


@app.get("/api/profiles/{name}/target_asset_thumb")
async def api_profile_target_asset_thumb(name: str, key: str):
    """目标图资产缩略（≤160px jpeg，<img> 直用）。hist:* 亦兼容（前端一般直用历史缩略端点）。"""
    _check_profile_name(name)
    raw = _target_asset_bytes(name, key)
    if not raw:
        raise HTTPException(404, "资产不存在")
    try:
        import cv2
        import numpy as np
        img = cv2.imdecode(np.frombuffer(raw, np.uint8), cv2.IMREAD_COLOR)
        h, w = img.shape[:2]
        s = 160 / max(h, w)
        img = cv2.resize(img, (max(int(w * s), 1), max(int(h * s), 1)))
        ok, buf = cv2.imencode(".jpg", img, [cv2.IMWRITE_JPEG_QUALITY, 85])
        if ok:
            raw = buf.tobytes()
    except Exception:
        pass                                     # 缩略失败退原图（只影响流量不影响可用）
    return Response(content=raw, media_type="image/jpeg",
                    headers={"Cache-Control": "max-age=120"})


async def _faceswap_with_hair_core(prof_name: str, body: dict) -> dict:
    """换脸+发型跟随核心管线（可复用）。失败抛 HTTPException；成功返回结果 dict。"""
    profile = _profiles.get(prof_name, {})
    target_b64 = (body.get("target_image") or "").strip()
    t_src = (body.get("target_source") or "").strip()
    if not target_b64 and t_src and t_src != "upload":
        raw = _target_asset_bytes(prof_name, t_src)
        if not raw:
            raise HTTPException(404, f"角色目标图资产不存在：{t_src}（试衣静图/全身照可能未生成）")
        target_b64 = base64.b64encode(raw).decode()
    if not target_b64:
        raise HTTPException(400, "缺少 target_image（目标图）——上传一张或用 target_source 直选角色资产")
    source_b64 = (body.get("source_image") or "").strip() or _profile_swap_face(profile)
    if not source_b64:
        raise HTTPException(400, "没有源人脸（未激活角色且未提供 source_image）")
    carry_hair = bool(body.get("carry_hair", True))
    paste_back = bool(body.get("paste_back", True))

    _fs_eng, _fs_svc, _fs_smooth = _faceswap_resolve(body.get("faceswap_engine", ""), profile)
    fs_body = {"source_image": source_b64, "target_image": target_b64}
    if _fs_smooth:
        fs_body["smooth_mode"] = _fs_smooth

    def _do_fs():
        if _fs_svc == "faceswap":
            return _fs_post_failover(fs_body)
        r = requests.post(f"{SERVICES[_fs_svc]}/faceswap", json=fs_body,
                          headers=_svc_req_headers(), timeout=30)
        return r.json()

    t0 = time.time()
    try:
        data = await asyncio.to_thread(_do_fs)
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(502, f"换脸服务不可达: {e}")
    swapped = (data or {}).get("result_image") if isinstance(data, dict) else ""
    if not swapped:
        raise HTTPException(422, "换脸未产出（目标图可能无人脸）："
                            + str((data or {}).get("detail", ""))[:160])
    fs_ms = int((time.time() - t0) * 1000)

    if not carry_hair:
        out_img = _maybe_embed_image_c2pa(swapped, model=_fs_eng, profile=prof_name, ai_generated=True)
        hid = _look_hist_record(prof_name, "facehair", image_b64=out_img,
                                meta={"engine": _fs_eng, "hair_ok": False, "pasted_back": False}) \
            if out_img and prof_name in _profiles else ""
        _track_event("huanyan", "huanyan.faceswap.completed", {   # P4：离线图片出片成功（仅换脸）
            "job_id": hid or f"fh_{int(t0)}", "media_type": "image", "elapsed_ms": fs_ms})
        return {"ok": True, "result_image": out_img, "hair_ok": False, "pasted_back": False,
                "faceswap_ms": fs_ms, "hair_ms": 0, "engine": _fs_eng, "profile": prof_name,
                "hist_id": hid, "stage": "faceswap_only"}

    hair_payload = {"source_image": swapped, "paste_back": paste_back,
                    "hair_image": (body.get("hair_image") or "").strip() or source_b64}
    hj = {}
    try:
        hr = await _hair_transfer_call(hair_payload, timeout=120)
        if hr.status_code == 200:
            hj = hr.json()
        else:
            _logger.warning(f"[FaceHair] 发型步 HTTP {hr.status_code}，回退仅换脸")
    except Exception as e:
        _logger.warning(f"[FaceHair] 发型步不可达，回退仅换脸: {e}")
    hair_ok = bool(hj.get("result_image"))
    out_img = hj.get("result_image") or swapped
    if out_img:
        out_img = _maybe_embed_image_c2pa(out_img, model=f"{_fs_eng}+hairfast",
                                          profile=prof_name, ai_generated=True)
    hid = ""
    if out_img and prof_name in _profiles:
        hid = _look_hist_record(prof_name, "facehair", image_b64=out_img,
                                meta={"engine": _fs_eng, "hair_ok": hair_ok,
                                      "pasted_back": bool(hj.get("pasted_back"))})
    _track_event("huanyan", "huanyan.faceswap.completed", {   # P4：离线图片出片成功（换脸+发型）
        "job_id": hid or f"fh_{int(t0)}", "media_type": "image",
        "elapsed_ms": fs_ms + int(hj.get("elapsed_ms") or 0)})
    return {"ok": True, "result_image": out_img, "hair_ok": hair_ok,
            "pasted_back": bool(hj.get("pasted_back")),
            "faceswap_ms": fs_ms, "hair_ms": hj.get("elapsed_ms"), "engine": _fs_eng,
            "profile": prof_name, "hist_id": hid,
            "stage": ("faceswap+hair" if hair_ok else "faceswap_only(hair_failed)")}


@app.post("/api/faceswap_with_hair")
async def api_faceswap_with_hair(body: dict = Body(default={})):
    """换脸 + 发型跟随源照片（离线出片，2026-07-10）。
    把源照片的脸换到目标图，并把**源照片自身的发型**一并带上——无需另传发型图。
    二连管线：faceswap(源→目标) → hair_transfer(换脸结果, 发型=源照片, paste_back 整图回贴)。
      body:{ target_image? 或 target_source?("tryon"|"body"|"hist:<id>"——服务端直读角色资产，免上传),
             source_image?(缺省=当前激活角色脸/定妆脸), hair_image?(缺省=源照片自身),
             carry_hair?=true, paste_back?=true, faceswap_engine?,
             profile?(缺省=当前激活；出片成功旁路存档到该角色出片历史) }
    软降级：发型步失败/不可达 → 只返回换脸结果(hair_ok=false)；换脸失败 → 502/422。
    注意：这是**离线出片**路径（HairFastGAN 5~10s，非实时）；实时直播帧路径 proxy_faceswap 不受影响。"""
    prof_name = (body.get("profile") or "").strip() or _active_profile
    return await _faceswap_with_hair_core(prof_name, body)


@app.post("/api/profiles/{name}/facehair_live")
async def api_profile_facehair_live(name: str, body: dict = Body(default={})):
    """全链一键：换脸+发型出片 → 设为角色底片(tryon) → Ditto 待机微动写入 idle_video。
    body: 同 /api/faceswap_with_hair 的目标/发型参数 + idle_secs?(默认6) field?(默认idle_video)。
    单步软降级：①换脸失败整链失败；②③底片/微动任一步失败记录原因，前面成功仍落库。
    Ditto 离线/人脸不可配准时自动回落 ffmpeg 静帧循环（与试衣定妆同源）。"""
    _check_profile_name(name)
    if name not in _profiles:
        raise HTTPException(404, "角色不存在")
    steps: dict = {}
    t_all = time.time()

    # ① 换脸+发型（硬依赖）
    try:
        fh = await _faceswap_with_hair_core(name, body)
        steps["facehair"] = {"ok": True, "hair_ok": fh.get("hair_ok"),
                             "ms": (fh.get("faceswap_ms") or 0) + (fh.get("hair_ms") or 0),
                             "stage": fh.get("stage")}
    except HTTPException as e:
        steps["facehair"] = {"ok": False, "error": str(e.detail)[:160]}
        raise
    except Exception as e:
        steps["facehair"] = {"ok": False, "error": str(e)[:160]}
        raise HTTPException(502, f"换脸+发型失败: {e}")

    out_b64 = fh.get("result_image") or ""
    if not out_b64:
        raise HTTPException(500, "出片无结果图")
    img_bytes = base64.b64decode(out_b64.split(",", 1)[-1] if "," in out_b64 else out_b64)

    # ② 写入角色底片 tryon_image（数字人/待机微动 source=auto 优先读它）
    out_dir = Path(rf"{_BASE}\data\tryon\{name}")
    out_dir.mkdir(parents=True, exist_ok=True)
    ts = int(time.time())
    img_path = out_dir / f"{ts}_facehair.jpg"
    img_path.write_bytes(img_bytes)
    async with _PROFILES_LOCK:
        if name not in _profiles:
            raise HTTPException(404, "角色不存在")
        _profiles[name]["tryon_image"] = str(img_path)
        _profiles[name]["tryon_at"] = time.time()
        if not _save_profile(name):
            raise HTTPException(500, "底片保存失败，请重试")
    steps["base"] = {"ok": True, "image": str(img_path)}

    # ③ 待机微动：Ditto 优先，失败回落静帧循环（软降级，与 tryon_preset 一致）
    field = body.get("field") or "idle_video"
    if field not in ("idle_video", "body_video"):
        raise HTTPException(400, "field 只能是 idle_video 或 body_video")
    secs = min(max(float(body.get("idle_secs") or 6), 2.0), 20.0)
    video_path = ""
    animated = False
    idle_dir = Path(rf"{_BASE}\data\idle_motion\{name}")
    idle_dir.mkdir(parents=True, exist_ok=True)
    vp_anim = idle_dir / f"{ts}_facehair.mp4"
    if await _tryon_animate_ditto(img_bytes, secs, vp_anim):
        video_path, animated = str(vp_anim), True
    else:
        try:
            import imageio_ffmpeg
            ffmpeg = imageio_ffmpeg.get_ffmpeg_exe()
            vp = idle_dir / f"{ts}_facehair_static.mp4"
            proc = await asyncio.to_thread(
                _subprocess.run,
                [ffmpeg, "-y", "-loop", "1", "-i", str(img_path), "-t", str(secs),
                 "-r", "25", "-vf", "scale=trunc(iw/2)*2:trunc(ih/2)*2",
                 "-c:v", "libx264", "-pix_fmt", "yuv420p", str(vp)],
                capture_output=True, timeout=60)
            if proc.returncode == 0 and vp.exists() and vp.stat().st_size > 0:
                video_path, animated = str(vp), False
        except Exception as e:
            _logger.warning(f"[FaceHairLive] 静帧回落失败: {e}")

    if video_path:
        async with _PROFILES_LOCK:
            if name not in _profiles:
                raise HTTPException(404, "角色不存在")
            _profiles[name][field] = video_path
            if not _save_profile(name):
                raise HTTPException(500, "视频保存失败，请重试")
        _look_hist_record(name, "idle", image_bytes=img_bytes,
                          meta={"style": "换脸+发型·微动", "field": field,
                                "video": video_path, "secs": secs, "animated": animated})
        steps["idle"] = {"ok": True, "animated": animated, "video": video_path, "field": field}
    else:
        steps["idle"] = {"ok": False, "error": "Ditto 与静帧回落均失败——底片静图已写入，可稍后手动跑「待机微动」"}

    _rp = _repush_idle_if_active(name) if video_path and field == "idle_video" else False
    hint = ("数字人底片就绪——" + ("Ditto 微动" if animated else "静帧循环") + f"已写入 {field}"
            if video_path else "底片静图已写入 tryon_image——请手动跑「待机微动」或检查 Ditto")
    if video_path and field == "idle_video":
        hint += "——" + _video_effect_hint(name, field, _rp)
    return {"ok": True, "profile": name, "result_image": out_b64,
            "image": str(img_path), "video": video_path, "field": field if video_path else "",
            "animated": animated, "hair_ok": fh.get("hair_ok"), "hist_id": fh.get("hist_id"),
            "steps": steps, "elapsed_ms": int((time.time() - t_all) * 1000), "hint": hint}


