@app.post("/api/tryon/preview")
async def api_tryon_preview(body: dict = Body(default={})):
    """试穿预览：只出图不落库（落库用 /api/profiles/{name}/tryon_preset）。
    body:{person_image_b64?, profile?, cloth_name?, cloth_b64?, resolution?, cloth_type?}
    阶段12：person_image_b64 缺省时给 profile 名可回退到该角色的存照（全身照记忆）。
    resolution: 768x1024(默认·~9s) / 1152x1536(高清·~20s) / 1536x2048(超清·更慢)
    cloth_type: upper(默认)/lower/dress——决定 FitDiT 掩码部位，下装/连衣裙必传"""
    person_b64 = (body.get("person_image_b64") or "").strip()
    prof = (body.get("profile") or "").strip()
    if not person_b64 and prof:
        bp = _body_photo_path(prof)
        if bp.exists():
            person_b64 = base64.b64encode(bp.read_bytes()).decode()
    if not person_b64:
        raise HTTPException(400, "需要 person_image_b64（全身/半身照）——该角色暂无存照，先传一次")
    if body.get("person_image_b64") and prof:     # 预览传新照也顺手存档（与定妆端一致）
        _save_body_photo(prof, person_b64)
    req_body: dict = {"person_image": person_b64}
    if body.get("cloth_b64"):
        req_body["cloth_image"] = body["cloth_b64"]
    elif body.get("cloth_name"):
        try:
            await http_pool.post(f"{SERVICES['tryon']}/clothes/switch",
                                 json={"name": body["cloth_name"]},
                                 headers=_svc_req_headers(), timeout=5)
        except Exception as e:
            raise HTTPException(503, f"试衣服务(8002)不可达：{str(e)[:120]}")
    res = (body.get("resolution") or "").strip()
    if res in ("768x1024", "1152x1536", "1536x2048"):
        req_body["resolution"] = res
    ct = (body.get("cloth_type") or "").strip().lower()   # 阶段7收尾：预览端漏透传的补齐
    if ct in ("upper", "lower", "dress", "full"):
        req_body["cloth_type"] = ct
    try:   # 高清档一张可到 ~30s+，冷启动/排队再加余量
        r = await http_pool.post(f"{SERVICES['tryon']}/tryon", json=req_body,
                                 headers=_svc_req_headers(), timeout=300)
        j = r.json()
        if _is_vram_reject(r.status_code, j) and await _hair_vram_rescue():
            r = await http_pool.post(f"{SERVICES['tryon']}/tryon", json=req_body,
                                     headers=_svc_req_headers(), timeout=300)
            j = r.json()
    except Exception as e:
        raise HTTPException(503, f"试衣超时/不可达：{str(e)[:120]}")
    if r.status_code != 200 or not j.get("result_image"):
        raise HTTPException(502, f"试衣失败：{str(j.get('detail') or r.status_code)[:160]}")
    return {"ok": True, "result_image": j["result_image"],
            "elapsed_ms": j.get("elapsed_ms")}


@app.post("/api/profiles/{name}/idle_motion")
async def api_profile_idle_motion(name: str, body: dict = Body(default={})):
    """待机微动独立入口（阶段4）：任意角色照片 → Ditto 静默驱动(二段策略) →
    呼吸/眨眼级微动视频写入 idle_video/body_video——替代静态照片待机。
    body:{source?="auto"|"tryon"|"styled"|"face", image_b64?, secs?=6, field?="idle_video"}
    source=auto: 显式 image_b64 > 试衣照(全身) > 定妆脸 > 原脸。Ditto 离线/全失败→ 409。"""
    _check_profile_name(name)
    p = _profiles.get(name)
    if not p:
        raise HTTPException(404, "角色不存在")
    field = body.get("field") or "idle_video"
    if field not in ("idle_video", "body_video"):
        raise HTTPException(400, "field 只能是 idle_video 或 body_video")
    secs = min(max(float(body.get("secs") or 6), 2.0), 20.0)

    src_req = (body.get("source") or "auto").lower()
    img_bytes, src_used = b"", ""
    if body.get("image_b64"):
        b64s = body["image_b64"]
        if "," in b64s:
            b64s = b64s.split(",", 1)[1]
        img_bytes, src_used = base64.b64decode(b64s), "image_b64"
    else:
        candidates = {
            "tryon": lambda: Path(p["tryon_image"]).read_bytes()
                     if p.get("tryon_image") and Path(p["tryon_image"]).exists() else b"",
            "styled": lambda: base64.b64decode(p["face_styled_b64"])
                      if p.get("face_styled_b64") else b"",
            "face": lambda: base64.b64decode(p["face_b64"]) if p.get("face_b64") else b"",
        }
        order = [src_req] if src_req in candidates else ["tryon", "styled", "face"]
        for key in order:
            try:
                img_bytes = candidates[key]()
            except Exception:
                img_bytes = b""
            if img_bytes:
                src_used = key
                break
    if not img_bytes:
        raise HTTPException(400, f"角色没有可用照片（source={src_req}）")

    out_dir = Path(rf"{_BASE}\data\idle_motion\{name}")
    out_dir.mkdir(parents=True, exist_ok=True)
    vp = out_dir / f"{int(time.time())}.mp4"
    if not await _tryon_animate_ditto(img_bytes, secs, vp):
        raise HTTPException(409, "Ditto 离线或人脸不可配准（两段均失败）——保持原待机不变")

    async with _PROFILES_LOCK:
        if name not in _profiles:
            raise HTTPException(404, "角色不存在")
        _profiles[name][field] = str(vp)
        if not _save_profile(name):
            raise HTTPException(500, "保存失败，请重试")
    _look_hist_record(name, "idle", image_bytes=img_bytes,   # 驱动源图当海报帧
                      meta={"style": f"微动·{src_used}", "field": field,
                            "video": str(vp), "secs": secs})
    _rp = _repush_idle_if_active(name) if field == "idle_video" else False
    return {"ok": True, "profile": name, "video": str(vp), "field": field,
            "source": src_used, "secs": secs,
            "hint": f"微动待机视频已写入 {field}（来源:{src_used}）——"
                    + _video_effect_hint(name, field, _rp)}


def _silence_wav(secs: float, rate: int = 16000) -> bytes:
    """内存生成"静音"WAV（Ditto 静默驱动待机微动用）。
    实测(2026-07-08 tools/_ditto_idle_ab*.py)：纯零输入会让 HuBERT 特征落在
    分布外，Ditto 反而幻觉出说话嘴型（嘴部动作分 2.05）；掺 -80dB 高斯底噪
    后嘴部虚假动作降一半(0.99)、唇形基本闭合，呼吸/眨眼级全局微动不受影响。
    固定种子保证同 secs 输出字节级可复现（利于缓存/回归）。"""
    import io as _io
    import wave as _wave
    import numpy as _np
    n = int(rate * secs)
    noise = (_np.random.default_rng(7).standard_normal(n) * 1e-4 * 32767).astype(_np.int16)
    buf = _io.BytesIO()
    w = _wave.open(buf, "wb")
    w.setnchannels(1); w.setsampwidth(2); w.setframerate(rate)
    w.writeframes(noise.tobytes())
    w.close()
    return buf.getvalue()


async def _ditto_silent_gen(base: str, img_bytes: bytes, secs: float, out_path: Path) -> bool:
    """单次 Ditto 静默驱动调用：静音 wav + 图 → mp4。失败返回 False 不抛。"""
    try:
        async with _aclient(timeout=240.0) as _cli:
            r = await _cli.post(
                f"{base}/ditto/generate",
                files={"audio": ("idle.wav", _silence_wav(secs), "audio/wav"),
                       "face": ("tryon.jpg", img_bytes, "image/jpeg")},
                data={"sampling_timesteps": 25, "crop_scale": 2.8})
        if r.status_code == 200 and r.content[:100].find(b"ftyp") >= 0:
            out_path.write_bytes(r.content)
            return out_path.stat().st_size > 0
    except Exception as e:
        _logger.warning(f"[TryonPreset] Ditto 静默驱动请求失败: {e}")
    return False


async def _tryon_animate_ditto(img_bytes: bytes, secs: float, out_path: Path) -> bool:
    """试衣静图 → Ditto 静默驱动 → 呼吸/眨眼级待机微动视频。
    实测(2026-07-08)：时装全身照人脸仅 ~100px 时 Ditto 检测失败(crop 返回 None)。
    二段策略：①原图直跑；②失败则裁上半身(顶部45%×中央70%)×2 放大重跑，
    动画帧经 ffmpeg overlay 贴回静图原位——身体不动、头部微动，正是待机观感。
    脸被画幅裁断(时装图常见)则两段都失败 → 调用方回落静帧循环，软降级不变。"""
    base = SERVICES.get("ditto", "http://127.0.0.1:8096").rstrip("/")
    try:
        r = await http_pool.get(f"{base}/health", timeout=2)
        if r.status_code != 200:
            return False
    except Exception:
        return False

    if await _ditto_silent_gen(base, img_bytes, secs, out_path):
        return True

    # ── 二段：上半身放大重试 ──
    try:
        import cv2
        import numpy as np
        img = cv2.imdecode(np.frombuffer(img_bytes, np.uint8), cv2.IMREAD_COLOR)
        if img is None:
            return False
        h, w = img.shape[:2]
        ch, cw = int(h * 0.45), int(w * 0.70)
        x0 = (w - cw) // 2
        crop = img[0:ch, x0:x0 + cw]
        crop2 = cv2.resize(crop, (cw * 2, ch * 2), interpolation=cv2.INTER_CUBIC)
        okb, buf = cv2.imencode(".jpg", crop2, [cv2.IMWRITE_JPEG_QUALITY, 92])
        if not okb:
            return False
        anim_crop = out_path.with_name(out_path.stem + "_crop.mp4")
        if not await _ditto_silent_gen(base, buf.tobytes(), secs, anim_crop):
            return False
        okj, jbuf = cv2.imencode(".jpg", img, [cv2.IMWRITE_JPEG_QUALITY, 95])
        full_jpg = out_path.with_name(out_path.stem + "_full.jpg")
        full_jpg.write_bytes(jbuf.tobytes())
        import imageio_ffmpeg
        ffmpeg = imageio_ffmpeg.get_ffmpeg_exe()
        # 动画缩回原裁剪尺寸贴回原位；总画幅取偶避免 yuv420p 报错
        vf = (f"[1:v]scale={cw}:{ch}[a];[0:v][a]overlay={x0}:0:shortest=1,"
              f"scale=trunc(iw/2)*2:trunc(ih/2)*2")
        proc = await asyncio.to_thread(
            _subprocess.run,
            [ffmpeg, "-y", "-loop", "1", "-i", str(full_jpg), "-i", str(anim_crop),
             "-filter_complex", vf, "-c:v", "libx264", "-pix_fmt", "yuv420p",
             "-r", "25", str(out_path)],
            capture_output=True, timeout=120)
        try:
            anim_crop.unlink(missing_ok=True); full_jpg.unlink(missing_ok=True)
        except Exception:
            pass
        if proc.returncode == 0 and out_path.exists() and out_path.stat().st_size > 0:
            _logger.info("[TryonPreset] Ditto 二段(上半身放大)动化成功")
            return True
        _logger.warning(f"[TryonPreset] 贴回合成失败: "
                        f"{proc.stderr[-200:] if proc.stderr else proc.returncode}")
    except Exception as e:
        _logger.warning(f"[TryonPreset] Ditto 二段动化失败(回落静帧): {e}")
    return False


@app.post("/api/profiles/{name}/tryon_preset")
async def api_profile_tryon_preset(name: str, body: dict = Body(default={})):
    """试衣定妆：全身照 + 服装 → tryon(8002) → 结果图存 data/tryon/<name>/ →
    Ditto 静默驱动待机微动(在线时) 或 ffmpeg 静帧循环 mp4 → 写入角色 body_video/idle_video。
    body:{person_image_b64(必填), cloth_name?, cloth_b64?, field?=body_video,
          video_secs?=4, animate?="auto"|"off"}"""
    _check_profile_name(name)
    p = _profiles.get(name)
    if not p:
        raise HTTPException(404, "角色不存在")
    person_b64 = (body.get("person_image_b64") or "").strip()
    # 阶段12 全身照记忆（运营走查第一痛点：换件衣服还要重传同一张全身照）：
    # 本次没传 → 用该角色上次存照；传了 → 顺手存档，下次免传。文件存储不进 DB
    # （3MB 级 b64 塞 profiles 库徒增每次 _save_profile 的序列化开销）。
    bp_path = _body_photo_path(name)
    if not person_b64:
        if not bp_path.exists():
            raise HTTPException(400, "需要 person_image_b64（全身/半身照）——该角色还没有存照，先传一次")
        person_b64 = base64.b64encode(bp_path.read_bytes()).decode()
    else:
        _save_body_photo(name, person_b64)
    field = body.get("field") or "body_video"
    if field not in ("body_video", "idle_video"):
        raise HTTPException(400, "field 只能是 body_video 或 idle_video")

    req_body = {"person_image": person_b64}
    cloth_b64 = (body.get("cloth_b64") or "").strip()
    cloth_name = (body.get("cloth_name") or "").strip()
    if cloth_b64:
        req_body["cloth_image"] = cloth_b64
    elif cloth_name:
        try:
            await http_pool.post(f"{SERVICES['tryon']}/clothes/switch",
                                 json={"name": cloth_name}, headers=_svc_req_headers(), timeout=5)
        except Exception as e:
            raise HTTPException(503, f"试衣服务(8002)不可达：{str(e)[:120]}")
    _res = (body.get("resolution") or "").strip()
    if _res in ("768x1024", "1152x1536", "1536x2048"):   # FitDiT 清晰度档位透传
        req_body["resolution"] = _res
    _ct = (body.get("cloth_type") or "").strip().lower()  # 阶段7：部位透传（下装/连衣裙）
    if _ct in ("upper", "lower", "dress", "full"):
        req_body["cloth_type"] = _ct
    try:                       # FitDiT ~9s(标清)~60s(超清) + 排队/冷启动余量
        r = await http_pool.post(f"{SERVICES['tryon']}/tryon",
                                 json=req_body, headers=_svc_req_headers(), timeout=300)
        j = r.json()
        if _is_vram_reject(r.status_code, j) and await _hair_vram_rescue():
            r = await http_pool.post(f"{SERVICES['tryon']}/tryon",
                                     json=req_body, headers=_svc_req_headers(), timeout=300)
            j = r.json()
    except Exception as e:
        raise HTTPException(503, f"试衣超时/不可达：{str(e)[:120]}")
    if r.status_code != 200 or not j.get("result_image"):
        raise HTTPException(502, f"试衣失败：{str(j.get('detail') or r.status_code)[:160]}")

    out_dir = Path(rf"{_BASE}\data\tryon\{name}")
    out_dir.mkdir(parents=True, exist_ok=True)
    ts = int(time.time())
    img_path = out_dir / f"{ts}.jpg"
    img_path.write_bytes(base64.b64decode(j["result_image"]))

    video_path = ""
    animated = False
    secs = max(2, min(10, int(body.get("video_secs") or 4)))
    if (body.get("animate") or "auto").lower() != "off":   # 先试 Ditto 待机微动（在线才试）
        vp_anim = out_dir / f"{ts}_idle.mp4"
        if await _tryon_animate_ditto(base64.b64decode(j["result_image"]), secs, vp_anim):
            video_path = str(vp_anim)
            animated = True
    if not video_path:
        try:                   # 静帧循环视频（yuv420p 偶数边，兼容 OBS/浏览器）
            import imageio_ffmpeg
            ffmpeg = imageio_ffmpeg.get_ffmpeg_exe()
            vp = out_dir / f"{ts}.mp4"
            proc = await asyncio.to_thread(
                _subprocess.run,
                [ffmpeg, "-y", "-loop", "1", "-i", str(img_path), "-t", str(secs),
                 "-r", "25", "-vf", "scale=trunc(iw/2)*2:trunc(ih/2)*2",
                 "-c:v", "libx264", "-pix_fmt", "yuv420p", str(vp)],
                capture_output=True, timeout=60)
            if proc.returncode == 0 and vp.exists() and vp.stat().st_size > 0:
                video_path = str(vp)
            else:
                _logger.warning(f"[TryonPreset] ffmpeg 失败: {proc.stderr[-300:] if proc.stderr else ''}")
        except Exception as e:
            _logger.warning(f"[TryonPreset] 循环视频生成失败(仍保留静图): {e}")

    async with _PROFILES_LOCK:
        if name not in _profiles:
            raise HTTPException(404, "角色不存在")
        _profiles[name]["tryon_image"] = str(img_path)
        if video_path:
            _profiles[name][field] = video_path
        _profiles[name]["tryon_at"] = time.time()
        if not _save_profile(name):
            raise HTTPException(500, "试衣结果保存失败，请重试")
    _look_hist_record(name, "tryon", image_b64=j["result_image"],
                      meta={"style": cloth_name or "上传服装", "field": field,
                            "video": video_path, "animated": animated})
    _rp = _repush_idle_if_active(name) if video_path and field == "idle_video" else False
    return {"ok": True, "profile": name, "image": str(img_path),
            "video": video_path, "field": field if video_path else "",
            "animated": animated, "elapsed_ms": j.get("elapsed_ms"),
            "hint": (("Ditto 待机微动" if animated else "静帧循环") + "视频已写入 "
                     + field + "——" + _video_effect_hint(name, field, _rp))
                    if video_path else "视频生成失败，仅保留试衣静图"}


# ── S6 换脸容灾故障切换：primary(.104 生产) ⇄ replica(本机 8003 瘦身副本) ─────────
#   循证：.104 是换脸唯一节点，看门狗自愈实测 33s——直播中 33s 黑脸仍是事故。
#   方案：/faceswap 逐帧热路径加熔断器——主引擎连续 2 帧失败(连接/超时/5xx) → 开闸改道本机副本，
#   同时异步把「当前角色的 DFM 绑定」推给副本（副本 LRU=2，1~2s 冷加载后画面完全一致；
#   加载期间副本用 inswapper+源脸顶上，观众看到的是通用换脸而非黑脸/裂口）。
#   熔断期间后台探针盯主引擎 /healthz，恢复即回切 + 补推当前绑定（副本期间的激活推送主引擎收不到）。
#   4xx(如目标无脸 400)不算故障——那是业务语义，透传照旧。副本未部署/也挂 → 行为=改造前(502)。
_FS_FAILOVER_ON = os.environ.get("HUB_FACESWAP_FAILOVER", "1").strip().lower() not in ("0", "false", "no", "off")
_FS_CB = {"fails": 0, "down_until": 0.0, "on_replica": False,
          "probe_ts": 0.0, "probing": False, "engaged_ts": 0.0, "served_by_replica": 0,
          "degrade_reason": ""}   # S8-2: 副本无 GFPGAN → replica_no_enhance
_FS_CB_LOCK = threading.Lock()
_FS_FAIL_THRESH = max(1, int(os.environ.get("HUB_FS_FAIL_THRESH", "2")))
_FS_PROBE_GAP = 3.0        # 熔断期主引擎探活间隔(s)；探活在后台线程，不占帧时延


def _fs_replica_url() -> str:
    """副本地址（未配/与主地址相同/总开关关 → 空=无副本可用）。"""
    if not _FS_FAILOVER_ON:
        return ""
    rep = (SERVICES.get("faceswap2") or "").rstrip("/")
    pri = (SERVICES.get("faceswap") or "").rstrip("/")
    return rep if (rep and rep != pri) else ""


def _fs_failover_view():
    """容灾态对外视图（api/dfm/current、ops 看板、演练断言共用）。"""
    with _FS_CB_LOCK:
        on = bool(_FS_CB["on_replica"])
        return {"enabled": bool(_fs_replica_url()), "on_replica": on,
                "served_by_replica": _FS_CB["served_by_replica"], "fails": _FS_CB["fails"],
                "degraded": on,   # S8-2: 副本刻意不加载 GFPGAN，接管期画质必然降级
                "degrade_reason": (_FS_CB.get("degrade_reason") or "replica_no_enhance") if on else "",
                "degrade_hint": ("换脸锐化增强暂不可用（容灾副本省显存）；画面仍可播，主引擎恢复后自动回切"
                                 if on else "")}


def _fs_mark_engage():
    """开闸瞬间（每次故障切换只触发一次）：留痕 + 告警 + 异步把当前角色绑定推给副本。"""
    with _FS_CB_LOCK:
        _FS_CB["degrade_reason"] = "replica_no_enhance"
    _stream_health_event("dfm", "dfm", {}, 0, kind="auto_heal",
                         action="换脸引擎故障切换→本机副本（主引擎连续失败，观众画面由副本接管·画质降级）")
    print("[Hub] ⚠ S6 换脸主引擎失联 → 已改道本机副本 8003；后台探针等主引擎回来（副本无锐化增强）")
    try:
        import alerts as _al
        _ops = f"{_dash_public_base()}/static/ops.html"
        _al.raise_alert("faceswap_failover", "换脸主引擎失联·已切副本",
                        detail="生产换脸(.104)连续失败，直播画面已由本机容灾副本接管（无 GFPGAN 锐化，画质略降）；"
                               "主引擎看门狗通常 ~40s 内自愈后自动回切，无需手动操作。",
                        level="critical", source="换脸容灾",
                        links=[("运维看板", _ops), ("直播控制台", f"{_dash_public_base()}/static/ui.html")])
    except Exception:
        pass

    def _sync_model():
        try:
            p = _profiles.get(_active_profile) or {}
            mdl = (p.get("dfm_model") or "").strip() or "default"
            requests.post(f"{_fs_replica_url()}/model/reload", json={"model": mdl},
                          headers=_svc_req_headers(), timeout=30)
            print(f"[Hub] S6 副本模型已同步 → {mdl}")
        except Exception:
            pass
    threading.Thread(target=_sync_model, daemon=True).start()


def _fs_mark_recover():
    """主引擎复活回切：清告警 + 留痕 + 把当前绑定补推主引擎（副本期主引擎错过的激活）。
    S7: 留痕带上「接管时长 + 副本顶的帧数」——演练/事故复盘直接从 timeline 读数，不用翻日志对表。"""
    with _FS_CB_LOCK:
        _dur = time.time() - _FS_CB["engaged_ts"] if _FS_CB["engaged_ts"] else 0.0
        _srv = _FS_CB["served_by_replica"] - _FS_CB.get("_srv_at_engage", 0)
        _FS_CB["engaged_ts"] = 0.0
        _FS_CB["degrade_reason"] = ""
    _msg = f"换脸主引擎已恢复→回切生产（副本接管 {_dur:.0f}s / 顶了 {_srv} 帧；角色绑定已补推）"
    _stream_health_event("dfm", "dfm", {}, 0, kind="auto_heal", action=_msg)
    print(f"[Hub] S6 换脸主引擎恢复 → 已回切生产引擎（副本接管 {_dur:.0f}s/{_srv} 帧）")
    try:
        import alerts as _al
        _al.clear_alert("faceswap_failover", note=f"主引擎恢复，已自动回切（副本接管 {_dur:.0f}s）")
    except Exception:
        pass
    try:
        if _active_profile and _active_profile in _profiles:
            _push_dfm_model_async(_active_profile, _profiles[_active_profile])
            # 2026-07-09: 直连通道依赖引擎粘滞态——回切时激活脸/妆容/平均源脸一并补推
            _push_active_face_makeup_async(_active_profile)
            _register_avg_face_async(_active_profile)
    except Exception:
        pass


_FS_WARMUP_B64 = {"v": None}


def _fs_warmup_b64() -> str:
    """回切预检用的探测脸（捆绑 _warmup_face.jpg，进程内缓存一次）。"""
    if _FS_WARMUP_B64["v"] is None:
        try:
            _p = Path(_BASE) / "_warmup_face.jpg"
            _FS_WARMUP_B64["v"] = base64.b64encode(_p.read_bytes()).decode() if _p.exists() else ""
        except Exception:
            _FS_WARMUP_B64["v"] = ""
    return _FS_WARMUP_B64["v"]


def _fs_probe_primary_async():
    """熔断期后台探活主引擎（限频 + 单飞）：/healthz 通 → 推回当前模型 → 真帧预检跑通 → 关闸回切。
    三关全过才回切（全部发生在闸内，观众始终看副本）——回切瞬间即满速出正确的脸，杜绝反复开闸。"""
    now = time.time()
    with _FS_CB_LOCK:
        if _FS_CB["probing"] or now - _FS_CB["probe_ts"] < _FS_PROBE_GAP:
            return
        _FS_CB["probing"] = True
        _FS_CB["probe_ts"] = now

    def _probe():
        ok = False
        try:
            ok = requests.get(f"{SERVICES['faceswap']}/healthz",
                              headers=_svc_req_headers(), timeout=3).status_code == 200
        except Exception:
            ok = False
        if ok:
            # E2E 循证(2026-07-09)：healthz 通≠能出正确画面——刚重启的主引擎活动模型是 inswapper 基线，
            # 关闸后帧打过去=错模型/无源脸 400，观众冻结到补推完成(实测 18.6s)。
            # 故「模型推回主引擎」是关闸前置条件：冷加载在闸内完成(观众仍看副本)，推成才回切=无缝。
            try:
                p = _profiles.get(_active_profile) or {}
                mdl = (p.get("dfm_model") or "").strip() or "default"
                rr = requests.post(f"{SERVICES['faceswap']}/model/reload", json={"model": mdl},
                                   headers=_svc_req_headers(), timeout=60)
                ok = rr.status_code == 200
            except Exception:
                ok = False                  # 模型没推上 → 本轮不回切，下轮探针再试
        if ok:
            # E2E 二轮循证：模型推上仍可能抖——冷启引擎对「直播帧的具体分辨率」要现场做 cuDNN
            # EXHAUSTIVE 调优（按卷积形状缓存，预热脸≠直播帧形状），首真帧可 >12s 超时 →
            # 刚回切又二次开闸(画面来回跳,flap)。故金丝雀预检用**副本期缓存的真直播帧**打真 /faceswap
            # （观众仍在副本上，不占直播路径）：首发把调优咽在闸内；若首发慢(>3s)再补发一帧，
            # 快了才算过关 → 回切即满速。无缓存帧(非直播期)退预热脸。
            with _FS_CB_LOCK:
                _payload = _FS_CB.get("last_body")
            if not _payload:
                wb = _fs_warmup_b64()
                _payload = {"target_image": wb, "source_image": wb} if wb else None
            if _payload:
                try:
                    _t0 = time.time()
                    rr2 = requests.post(f"{SERVICES['faceswap']}/faceswap", json=_payload,
                                        headers=_svc_req_headers(), timeout=(3, 60))
                    ok = rr2.status_code == 200 and bool(rr2.json().get("result_image"))
                    if ok and time.time() - _t0 > 3.0:   # 首发慢=调优刚做完 → 验证已满速
                        _t1 = time.time()
                        rr3 = requests.post(f"{SERVICES['faceswap']}/faceswap", json=_payload,
                                            headers=_svc_req_headers(), timeout=(3, 20))
                        ok = (rr3.status_code == 200 and bool(rr3.json().get("result_image"))
                              and time.time() - _t1 <= 3.0)
                except Exception:
                    ok = False
        recovered = False
        with _FS_CB_LOCK:
            _FS_CB["probing"] = False
            if ok and _FS_CB["on_replica"]:
                _FS_CB.update(fails=0, down_until=0.0, on_replica=False)
                recovered = True
        if recovered:
            _fs_mark_recover()
    threading.Thread(target=_probe, daemon=True).start()


def _fs_post_failover(body: dict) -> dict:
    """/faceswap 帧转发（容灾版）：主引擎正常=零额外开销的直通；失败计数熔断改道副本。
    返回 dict（4xx 业务响应原样透传，与旧行为一致）；主副全灭 → HTTPException 502。"""
    rep = _fs_replica_url()
    now = time.time()
    with _FS_CB_LOCK:
        use_primary = now >= _FS_CB["down_until"]
    if use_primary:
        try:
            r = requests.post(f"{SERVICES['faceswap']}/faceswap", json=body,
                              headers=_svc_req_headers(), timeout=(2, 12))
            if r.status_code < 500:
                recovered = False
                with _FS_CB_LOCK:
                    _FS_CB["fails"] = 0
                    if _FS_CB["on_replica"]:
                        _FS_CB.update(down_until=0.0, on_replica=False)
                        recovered = True
                if recovered:
                    _fs_mark_recover()
                return r.json()
            raise RuntimeError(f"HTTP{r.status_code}")
        except Exception as e:
            if not rep:                     # 无副本：保持改造前语义
                raise HTTPException(502, f"faceswap 服务不可达: {e}")
            engage = False
            with _FS_CB_LOCK:
                _FS_CB["fails"] += 1
                if _FS_CB["fails"] >= _FS_FAIL_THRESH and not _FS_CB["on_replica"]:
                    _FS_CB.update(on_replica=True, engaged_ts=now,
                                  down_until=now + 3600,   # 由探针关闸，不靠时钟盲开
                                  _srv_at_engage=_FS_CB["served_by_replica"])  # S7: 本次接管帧数基点
                    engage = True
                elif not _FS_CB["on_replica"]:
                    # 未达阈值：本帧直接试副本顶一帧，主引擎下帧再试
                    pass
            if engage:
                _fs_mark_engage()
    else:
        _fs_probe_primary_async()           # 熔断中：后台限频探活主引擎
    if not rep:
        raise HTTPException(502, "faceswap 主引擎不可达且未部署副本")
    try:
        r2 = requests.post(f"{rep}/faceswap", json=body,
                           headers=_svc_req_headers(), timeout=(2, 15))
        with _FS_CB_LOCK:
            _FS_CB["served_by_replica"] += 1
            _FS_CB["last_body"] = body     # 缓存真直播帧：回切金丝雀预检用(同分辨率=同 cuDNN 调优形状)
        d = r2.json()
        if isinstance(d, dict):
            d["failover"] = True            # 观测标记（realtime_stream 忽略未知字段）
            d["degraded"] = True            # S8-2: 副本无 GFPGAN，接管期画质降级（stream 侧会加锐化补偿）
            d["degrade_reason"] = "replica_no_enhance"
        return d
    except Exception as e2:
        raise HTTPException(502, f"faceswap 主/副引擎均不可达: {e2}")


@app.post("/faceswap")
def proxy_faceswap(body: dict):
    """透传给 faceswap 服务，自动注入激活角色的人脸(定妆脸优先,C-3)"""
    profile = _profiles.get(_active_profile, {})
    _pface = _profile_swap_face(profile)
    if "source_image" not in body and _pface:
        body["source_image"] = _pface
    # 多照片源脸平均：角色有 gallery 附图 → 注入 source_key(=激活角色名)，引擎用预注册的平均 embedding；
    # 未注册/引擎重启丢失时，引擎自动回退到同帧携带的 source_image（上面已注入）→ 绝不掉脸。
    if ("source_key" not in body and "source_map" not in body
            and _profile_gallery_imgs(profile)):
        body["source_key"] = _active_profile
    # C-2 双人映射：调用方未显式给 source_map 时按 Hub 配置注入(默认关=不注入,行为不变)
    if "source_map" not in body:
        _sm = _face_map_sources()
        if _sm:
            body["source_map"] = _sm
    # C-5 直播妆容层：角色开启 live_makeup 时逐帧注入 makeup 规范（换脸输出端上妆，
    # 引擎侧 ~1-3ms；默认关=不注入零回归）。调用方显式给 makeup 时尊重调用方。
    if "makeup" not in body:
        _lmk = dict(profile.get("live_makeup") or {})
        if _lmk.get("enabled"):
            body["makeup"] = {k: v for k, v in _lmk.items() if k != "enabled"}
    # 换脸引擎解析（body 覆盖 > 角色配置 > 默认 inswapper）→ 服务键 + 平滑模式
    _fs_eng, _fs_svc, _fs_smooth = _faceswap_resolve(body.pop("faceswap_engine", ""), profile)
    if _fs_smooth and "smooth_mode" not in body:
        body["smooth_mode"] = _fs_smooth
    if _fs_svc == "faceswap":
        data = _fs_post_failover(body)     # S6: 主引擎(.104)失联自动改道本机副本，恢复自动回切
    else:
        try:
            r = requests.post(f"{SERVICES[_fs_svc]}/faceswap",
                json=body, headers=_svc_req_headers(), timeout=30)
            data = r.json()
        except Exception as e:
            raise HTTPException(502, f"faceswap 服务不可达: {e}")
    # 图片换脸产出也进入可验真闭环：在结果图上叠加标准 C2PA（软降级，标注真实换脸引擎）
    if isinstance(data, dict) and data.get("result_image"):
        data["result_image"] = _maybe_embed_image_c2pa(
            data["result_image"], model=_fs_eng,
            profile=_active_profile, ai_generated=True)
    return data

# ── 流式 TTS 转发（P11-1: 异步 + 每句 RVC）────────────────────────
@app.post("/tts/stream_sse")
async def proxy_tts_stream_sse(body: dict):
    """流式TTS SSE转发（异步），若角色配置了 rvc_model 则对每句自动变声。
    原同步阻塞实现已改为 httpx 异步流，修复事件循环卡顿问题。"""
    _metrics["stream_sse_total"] += 1          # P13-4: 调用计数
    profile_name = (body.pop("profile", None) or "").strip() or _active_profile
    async with _PROFILES_LOCK:
        profile = dict(_profiles.get(profile_name, {}))
    voice_name  = profile.get("voice_name", "") or body.get("voice", "female_01.wav")
    lang        = body.get("language", "zh-cn")
    text        = body.get("text", "")
    # UI-P2-1: 流式吃情感——手动情感/语气指令逐句改走情感引擎（与 /avatar/speak/stream 同款路由）。
    #   此前前端照发 emotion/instruct 而这里静默丢弃（P1 只能诚实提示"不生效"）。
    # UI-P3-1: auto 也吃——整文检测一次（与标准路径同一 detect_emotion 口径，纯关键词打分微秒级），
    #   全程按检出情感路由，句间零跳变；检出 neutral 则保持克隆快路径（缓存/子块加速全保留）。
    _emo_req    = (body.get("emotion") or "").strip()
    _instruct   = (body.get("instruct") or "").strip()
    _emo_use    = _emo_req if _emo_req not in ("", "auto") else "neutral"
    _detected_stream = ""
    if _emo_req == "auto":
        _metrics["speak_emotion_auto"] += 1   # 决策①数据：两种模式的 auto 使用都计入
        try:
            from emotion_detector import detect_emotion as _det
            _detected_stream = _det(text) or "neutral"
            if _detected_stream != "neutral":
                _emo_use = _detected_stream
        except Exception:
            _detected_stream = ""
    _emo_stream = bool(_emo_use != "neutral" or _instruct)
    if _emo_stream:
        _metrics["stream_sse_emotion"] += 1
    rvc_model   = profile.get("rvc_model", "")
    rvc_settings= profile.get("rvc_settings", {})
    strict_mode = profile.get("rvc_strict_mode", True)
    # Phase6-6: 变声引擎解析（body 覆盖 > 角色配置 > 默认 rvc）
    sel_vc_engine = (body.get("vc_engine") or profile.get("vc_engine", "")
                     or _default_engine("vc"))

    def _sse_line(data: dict) -> str:
        return f"data: {json.dumps(data, ensure_ascii=False)}\n\n"

    voice_b64 = profile.get("voice_b64", "")  # P17-3: 克隆模式用 voice_b64
    # 按角色 tts_engine 路由逐句合成（修复：原流式恒走 XTTS，fish_speech 角色每句静默失败→0 段音频）
    _sel_tts_eng = (body.get("tts_engine") or profile.get("tts_engine", "")).strip()
    _fish_svc = _fish_compat_svc(_sel_tts_eng)   # fish_speech / qwen3_tts… → 服务键
    _use_fish = bool(_fish_svc)
    _fish_params = profile.get("fish_tts_params") or {}

    async def _synth_sentence(sent: str) -> str:
        """按角色引擎逐句合成，返回 audio_base64（与 /avatar/speak 的 fish 路径一致）。
        UI-P2-1: 手动情感/指令 → 情感引擎(emotion_tts)，payload 与标准路径逐字段一致；
        否则 fish-兼容引擎(fish_speech/qwen3_tts…) → 克隆/合成；其余 → XTTS(_call_tts)。"""
        if _emo_stream:
            epay = {"text": sent, "emotion": _emo_use,
                    "speed": 1.0, "return_base64": True}
            if _instruct:
                epay["instruct"] = _instruct
                ep = f"{SERVICES['emotion_tts']}/v1/tts/instruct"
            elif voice_b64:
                ep = f"{SERVICES['emotion_tts']}/v1/tts/clone"
                epay["reference_audio_b64"] = voice_b64
            else:
                ep = f"{SERVICES['emotion_tts']}/v1/tts"
            r = await http_pool.post(ep, json=epay, timeout=90)
            return r.json().get("audio_base64", "") if r.status_code == 200 else ""
        if _use_fish:
            payload = {"text": sent, "language": lang or "zh", "return_base64": True}
            if voice_b64:
                ep = f"{SERVICES[_fish_svc]}/v1/tts/clone"
                payload["reference_audio_b64"] = voice_b64
                payload["reference_text"] = _fish_params.get("reference_text", "") if _fish_params else ""
                if _fish_params:
                    payload.update({k: _fish_params[k] for k in
                                    ("temperature", "top_p", "repetition_penalty", "chunk_length", "seed")
                                    if k in _fish_params})
            else:
                ep = f"{SERVICES[_fish_svc]}/v1/tts"
            r = await http_pool.post(ep, json=payload, timeout=90)
            return r.json().get("audio_base64", "") if r.status_code == 200 else ""
        r = await _call_tts(voice_b64, voice_name, sent, lang)
        if r.status_code != 200:
            return ""
        return r.json().get("audio_base64", "") if voice_b64 else base64.b64encode(r.content).decode()

    # P22-1: fish 首句子块流式——把首句改用服务端流式 /v1/tts/clone/stream，按合并档
    #   (首块~300ms)边生成边吐，TTFA=首块生成时间(远小于整句生成)。任一块产出即拉低首音；
    #   非200/异常/零产出 → 不 yield，由调用方落整句兜底(绝不劣化、不静音)。
    #   UI-P2-1: 情感路由无子块流式能力 → 关闭（TTFA 升到整句水平，前端已标注代价）。
    _fish_substream = (not _emo_stream) and _use_fish and bool(voice_b64) and _STREAM_SSE_FISH_SUBCHUNK

    async def _fish_stream_chunks(sent: str):
        import struct as _struct
        payload = {"reference_audio_b64": voice_b64,
                   "reference_text": _fish_params.get("reference_text", "") if _fish_params else "",
                   "text": sent, "language": lang or "zh", "return_base64": True}
        if _fish_params:
            for _k in ("temperature", "top_p", "repetition_penalty", "chunk_length", "seed"):
                if _k in _fish_params:
                    payload[_k] = _fish_params[_k]
        # 流式首句用更小的 chunk_length：AR 更快产出首个 token 块 → 首帧更早 → 压 TTFA 尾分位
        if _STREAM_SSE_FISH_CHUNK_LEN > 0:
            payload["chunk_length"] = min(payload.get("chunk_length", 200),
                                          _STREAM_SSE_FISH_CHUNK_LEN)
        async with _svc_lease(_fish_svc) as _base:
            async with http_pool.stream("POST", f"{_base}/v1/tts/clone/stream",
                                        json=payload, timeout=90) as resp:
                if resp.status_code != 200:
                    _logger.warning(f"[stream_sse] fish 流式 HTTP {resp.status_code} → 整句兜底")
                    return
                try:
                    sr = int(resp.headers.get("X-Sample-Rate", "44100"))
                except Exception:
                    sr = 44100

                async def _frames():
                    buf = b""
                    async for data in resp.aiter_bytes():
                        buf += data
                        while len(buf) >= 4:
                            n = _struct.unpack("<I", buf[:4])[0]
                            if n == 0:
                                return
                            if len(buf) < 4 + n:
                                break
                            pcm, buf = buf[4:4 + n], buf[4 + n:]
                            if pcm:
                                yield pcm

                _cf, _cc, _cm = _pick_coalesce_params(False, False)
                if _STREAM_SSE_COALESCE_FIRST_MS > 0:
                    _cf = _STREAM_SSE_COALESCE_FIRST_MS     # 首块更小 → 更早起播
                async for _blk in _coalesce_pcm_stream(_frames(), sr=sr,
                                                       first_ms=_cf, chunk_ms=_cc, max_ms=_cm):
                    yield _pcm16_to_wav_b64(_blk, sr)

    async def _gen():
        # P17-3: 用智能分句替换 AllTalk stream_sse，获得小数/缩写保护+短句合并
        sentences = _smart_split_text(text)
        if body.get("low_latency", _STREAM_SSE_LOW_LATENCY_DEFAULT):  # Phase7: 首块加速灰度默认开（缩短首句降 TTFA；请求可覆盖）
            sentences = _split_first_for_ttfa(sentences)
        t_global = time.time()   # P18-1: 全局起始时间
        _ttfa_state = {"done": False}
        def _rec_ttfa():
            """首音延迟只记一次(开场白缓存/垫词/流式首块/整句，任一最先到达者记)。"""
            if _ttfa_state["done"]:
                return
            _ttfa_state["done"] = True
            _t = int((time.time() - t_global) * 1000)
            _metrics["stream_sse_first_ms_sum"] += _t
            _metrics["stream_sse_first_count"]  += 1
            _metrics["stream_first_ms"].append(_t)
        # P19-1: 预告总句数；UI-P2-1: 附本次实际路由（情感引擎/克隆），前端据此显示真话；
        # UI-P3-1: auto 附整文检出情感（前端 banner/结果卡取真值，与本地防抖检测竞态无关）
        _prelude = {"total_sentences": len(sentences),
                    "tts_route": "emotion" if _emo_stream else "clone"}
        if _detected_stream:
            _prelude["detected_emotion"] = _detected_stream
        yield _sse_line(_prelude)
        # UI-P1-2: 按序收集所有已播段(开场白缓存/子块/整句；垫词除外——它不属于朗读文本)，
        #   完播后拼整段落历史，走与标准模式同一条 saved 回执链路。中途断开→不落（部分音频无保存价值）。
        _wav_parts: list = []
        _any_rvc = False
        try:
            for sent_idx, sent in enumerate(sentences, 1):
                if not sent:
                    continue
                t_sent = time.time()
                # P22-2: 直播开场白缓存——首句精确命中预合成开场白(已含RVC/水印) → 感知 TTFA≈0(仅网络)。
                #   低延迟档 _split_first_for_ttfa 会把「你好，今天…」切出首块「你好，」正好命中。
                #   UI-P2-1: 情感路由下整块跳过——缓存/垫词都是中性音，混进情感句会"变脸"。
                if sent_idx == 1 and not _emo_stream:
                    _op_hit = _opener_cache_get(profile_name, sent, "neutral")
                    if _op_hit:
                        _rec_ttfa()
                        _metrics["stream_sse_sentences"] += 1
                        _wav_parts.append(_op_hit); _any_rvc = _any_rvc or bool(rvc_model)
                        yield _sse_line({
                            "audio_base64": _op_hit,
                            "elapsed_ms":   int((time.time() - t_sent) * 1000),
                            "sentence_idx": 1, "sent_idx": 1,
                            "cached_opener": True,
                            "rvc_applied":  bool(rvc_model),  # 缓存音频已含 RVC
                        })
                        continue
                    # 最长前缀命中：首块以缓存开场白起头(如「你好，今天…」)→先秒回开场白，
                    #   再把剩余文本作为后续块现合成，让感知 TTFA≈0 覆盖更广的首句。
                    _pre_audio, _rem = _opener_prefix_hit(profile_name, profile, sent)
                    if _pre_audio and _rem:
                        _rec_ttfa()
                        _wav_parts.append(_pre_audio); _any_rvc = _any_rvc or bool(rvc_model)
                        yield _sse_line({
                            "audio_base64": _pre_audio,
                            "elapsed_ms":   int((time.time() - t_sent) * 1000),
                            "sentence_idx": 1, "sent_idx": 1,
                            "cached_opener": True,
                            "rvc_applied":  bool(rvc_model),
                        })
                        sent = _rem          # 余下部分继续走下方合成(作为后续块)
                    # 可选：仍未命中时先吐预合成垫词(感知 TTFA~150ms)，再合成真实首句。
                    #   仅 body.prepend_filler=true 时启用(会在首句前加「嗯，」类语气词，改变内容)，
                    #   默认关，保持「精确朗读给定文本」语义不变。
                    elif body.get("prepend_filler"):
                        _fill = _pick_filler(profile_name, reply_lang=(lang or "zh-cn"))
                        if _fill:
                            _rec_ttfa()
                            yield _sse_line({
                                "audio_base64": _fill,
                                "elapsed_ms":   int((time.time() - t_sent) * 1000),
                                "sentence_idx": 1, "sent_idx": 1,
                                "filler": True,
                                "rvc_applied":  bool(rvc_model),
                            })
                            # 不 continue：继续合成真实首句(作为后续块流式吐出)
                # P22-1: 首句子块流式（fish）——抢出首块压 TTFA；零产出则落整句兜底
                if sent_idx == 1 and _fish_substream:
                    _emitted = 0
                    try:
                        async for _wav in _fish_stream_chunks(sent):
                            if not _wav:
                                continue
                            _rvc_applied = False
                            if rvc_model:
                                try:
                                    async with _STREAM_RVC_SEM:
                                        _rr = await _vc_dispatch(sel_vc_engine, _wav, rvc_model, rvc_settings)
                                    if _rr.status_code == 200:
                                        _wav = _rr.audio_b64 or _wav
                                        _rvc_applied = True
                                        _metrics["stream_sse_rvc_applied"] += 1
                                except Exception:
                                    pass
                            if _emitted == 0:                       # 首块即记 TTFA（若垫词已记则跳过）
                                _rec_ttfa()
                            _emitted += 1
                            _wav_parts.append(_wav); _any_rvc = _any_rvc or _rvc_applied
                            yield _sse_line({
                                "audio_base64": _wav,
                                "elapsed_ms":   int((time.time() - t_sent) * 1000),
                                "sentence_idx": 1,
                                "sent_idx":     1,
                                "chunk_idx":    _emitted,
                                "rvc_applied":  _rvc_applied,
                            })
                    except Exception as e:
                        _logger.warning(f"[stream_sse] 首句流式异常: {e} → 整句兜底")
                        _emitted = 0
                    if _emitted:
                        _metrics["stream_sse_sentences"] += 1
                        continue                                    # 首句已流式吐出 → 下一句
                    # 零产出：落入下方整句路径（仍按首句记 TTFA）
                _eng_label = "emotion_tts" if _emo_stream else (_sel_tts_eng or "xtts")
                try:
                    audio_b64 = await _synth_sentence(sent)
                except Exception as e:
                    _logger.warning(f"[stream_sse] 第{sent_idx}句 TTS 失败(引擎={_eng_label}): {e}")
                    continue
                if not audio_b64:
                    _logger.warning(f"[stream_sse] 第{sent_idx}句 无音频(引擎={_eng_label})")
                    continue
                elapsed_ms = int((time.time() - t_sent) * 1000)
                _metrics["stream_sse_sentences"] += 1  # P13-4
                if sent_idx == 1:                         # P18-1: 首句延迟（统一收口）
                    _rec_ttfa()
                # Phase7: 句级 TTS 延迟记入引擎注册表（情感路由归 cosyvoice，fish-兼容归其引擎名）
                if _engine_registry is not None:
                    try: _engine_registry.record_latency(
                        "cosyvoice" if _emo_stream else (_sel_tts_eng if _use_fish else "xtts"), elapsed_ms)
                    except Exception: pass
                rvc_applied = False
                if audio_b64 and rvc_model:
                    try:
                        async with _STREAM_RVC_SEM:  # P12-2: 限制全局并发
                            rvc_r = await _vc_dispatch(sel_vc_engine, audio_b64, rvc_model, rvc_settings)
                        if rvc_r.status_code == 200:
                            audio_b64 = rvc_r.audio_b64 or audio_b64
                            rvc_applied = True
                            _metrics["stream_sse_rvc_applied"] += 1  # P13-4
                    except Exception:
                        pass  # 降级：使用原音频
                _wav_parts.append(audio_b64); _any_rvc = _any_rvc or rvc_applied
                yield _sse_line({
                    "audio_base64": audio_b64,
                    "elapsed_ms":   elapsed_ms,
                    "sentence_idx": sent_idx,
                    "sent_idx":     sent_idx,   # P21-1: 别名兼容前端重试去重
                    "rvc_applied":  rvc_applied,
                })
            # UI-P1-2: 完播→整段拼接落历史，saved 先于 done 发出（前端收到 done 即停读，
            #   放后面会丢）。拼接放线程池防长文阻塞事件循环；落库失败只记日志不影响播放。
            if _wav_parts and text.strip():
                try:
                    _full_b64 = await asyncio.to_thread(_concat_wav_b64, _wav_parts)
                    # UI-P3-4: 整段落库前补内容凭证（C2PA manifest + 不可见水印），与标准路径同权
                    #   （尊重 AVATARHUB_WATERMARK 总开关与请求级 watermark 覆盖）。
                    #   只给耐久产物（历史整段）附加；实时逐句块不动，不碰 TTFA。线程池执行防阻塞事件循环。
                    _wm_on = (PROVENANCE_ENABLED if body.get("watermark") is None
                              else bool(body.get("watermark")))
                    if _full_b64 and _wm_on and _provenance is not None:
                        try:
                            _pres = await asyncio.to_thread(
                                _provenance.attach_credentials,
                                base64.b64decode(_full_b64),
                                model=("cosyvoice" if _emo_stream else
                                       (_sel_tts_eng if _use_fish else "xtts")),
                                profile=profile_name, ai_generated=True,
                                extra={"rvc_applied": _any_rvc, "stream": True,
                                       "emotion": (_emo_use if _emo_stream else "neutral")})
                            if _pres.get("ok"):
                                _full_b64 = base64.b64encode(_pres["audio_bytes"]).decode()
                        except Exception as _pe:
                            _logger.warning(f"[stream_sse] 整段凭证附加失败(不影响落库): {_pe}")
                    if _full_b64:
                        _inc = bool(body.get("incognito"))
                        hist_id = await asyncio.get_running_loop().run_in_executor(
                            _history_executor, _write_history,
                            profile_name, text, lang, _full_b64,
                            int((time.time() - t_global) * 1000), _any_rvc, _inc,
                            # UI-P2-1/P3-1: 按真实路由情感落库（auto→检出值；instruct-only 记 neutral，与标准一致）
                            (_emo_use if _emo_stream else "neutral"))
                        if hist_id is not None and not _inc:
                            yield _sse_line({"saved": True, "history_id": hist_id})
                            try:
                                asyncio.ensure_future(broadcast({"event": "history_updated"}))
                            except Exception:
                                pass
                except Exception as _he:
                    _logger.warning(f"[stream_sse] 整段落历史失败(不影响播放): {_he}")
            yield _sse_line({"done": True})
        except Exception as e:
            yield _sse_line({"error": str(e), "done": True})

    return StreamingResponse(
        _gen(), media_type="text/event-stream",
        headers={"Cache-Control": "no-cache", "X-Accel-Buffering": "no"})

# ── P17-3: 智能分句（保护小数点/缩写，合并过短句）────────────────
# P18-5: 英文常见缩写（保护其点号不被当作句末分割）
_ABBREV_RE = None  # lazy-init
def _get_abbrev_re():
    global _ABBREV_RE
    if _ABBREV_RE is None:
        import re as _r
        _ABBREV_RE = _r.compile(r'\b(Dr|Mr|Mrs|Ms|Prof|No|vs|etc|Fig|Vol|Eq|St|Jr|Sr)\.')
    return _ABBREV_RE


def _smart_split_text(text: str, min_chars: int = 4) -> list:
    """P17-3+P18-5: 中英文智能分句
    - 中文: 按 [。！？!?…] 分句（re.findall，保护小数点）
    - 英文: 按 '. ' + 大写字母 分句（保护 Dr./Mr. 等缩写）
    - min_chars=4: 少于 4 字的碎句合并到下一句
    """
    import re as _re
    if not text.strip():
        return []
    abbrev_re = _get_abbrev_re()
    paragraphs = [p.strip() for p in _re.split(r'\n+', text) if p.strip()]
    sentences: list = []
    for para in paragraphs:
        # Step1: 中文标点分句（findall 不含英文 .，天然保护小数）
        cn_parts = _re.findall(r'[^。！？!?…]+[。！？!?…]+|[^。！？!?…\n]+', para)
        for part in cn_parts:
            if '. ' in part:  # P18-5: 含英文句号时尝试进一步拆分
                prot = abbrev_re.sub(lambda m: m.group(1) + '\x00', part)  # 保护缩写
                en_parts = _re.split(r'(?<=\.)(?=\s+[A-Z\u4e00-\u9fff])', prot)
                sentences.extend(ep.replace('\x00', '.').strip()
                                 for ep in en_parts if ep.strip())
            else:
                sentences.append(part)
    # 合并过短碎句（< min_chars 字符）
    merged: list = []
    for s in sentences:
        if merged and len(merged[-1]) < min_chars:
            merged[-1] += s
        else:
            merged.append(s)
    return merged if merged else [text.strip()]


def _split_first_for_ttfa(sentences: list, max_head_chars: int = 16) -> list:
    """Phase7 低延迟首块：把过长首句在首个子句标点(，,、；;)处切出更短首块，
    直接降低流式 TTFA（首句越短，第一段音频越快返回）。仅影响首段，后续句不变；
    无合适切点则原样返回，保证不劣化。"""
    if not sentences:
        return sentences
    head = sentences[0]
    if len(head) <= max_head_chars:
        return sentences
    import re as _r
    cut = 0
    for _mt in _r.finditer(r'[，,、；;]', head):
        if _mt.end() <= max_head_chars + 4:
            cut = _mt.end()
        else:
            break
    if cut <= 0:
        return sentences
    first, rest = head[:cut].strip(), head[cut:].strip()
    if not first or not rest:
        return sentences
    return [first, rest] + sentences[1:]


# ── 一键开播 ──────────────────────────────────────────────────────
@app.post("/api/one_click_start")
def one_click_start(body: dict = {}):
    """一键开播：检查服务 → 激活角色 → 启动换脸 → 启动变声"""
    global _active_profile
    steps = []
    profile_name = body.get("profile", _active_profile)
    video_source = body.get("source", "auto")
    camera_idx   = str(body.get("camera", "")).strip()

    # 可选视频/换脸参数
    video_width  = int(body.get("video_width", 0) or 0)
    video_height = int(body.get("video_height", 0) or 0)
    video_fps    = int(body.get("video_fps", 0) or 0)
    swap_fps     = int(body.get("swap_fps", 0) or 0)
    mjpeg_fps    = int(body.get("mjpeg_fps", 0) or 0)
    jpeg_quality = int(body.get("jpeg_quality", 0) or 0)
    crossfade    = float(body.get("crossfade", 0) or 0)

    # 可选换脸效果参数
    face_blend     = float(body.get("face_blend", 0) or 0)
    face_threshold = float(body.get("face_threshold", 0) or 0)
    face_smooth    = float(body.get("face_smooth", 0) or 0)
    face_enhance   = str(body.get("face_enhance", "")).strip()
    swap_preset    = str(body.get("swap_preset", "")).strip().lower()   # 画质目标档(UI 预设按钮引擎侧联动)
    output_aspect  = str(body.get("aspect", "")).strip().lower()        # 输出画面比例(竖屏/横屏)；空=用 effect_cfg 默认

    # 开播模式（真人换脸 real_faceswap / 数字人 avatar_lipsync）：显式单一真相。
    #   前端下发 mode → 持久化；随后 _compute_broadcast 即据此裁决(不再靠 realtime 是否在跑反推)。
    #   dual=True 且系统装了 Unity Capture → 双路同开(真人→OBS，数字人→Unity)；否则严格互斥。
    #   force=True → 跳过真人换脸的摄像头活源门禁(允许空跑)。
    _req_mode = str(body.get("mode", "")).strip()
    if _req_mode in _VALID_BROADCAST_MODES:
        _set_broadcast_mode(_req_mode)
    _dual  = bool(body.get("dual", False))
    _force = bool(body.get("force", False))

    # Step 1: 检查核心服务（P5-1: 使用缓存版，避免重复阻塞）
    #   诚实信号：本步 ok 反映"本开播模式主引擎是否在线"(换脸模式=faceswap / 数字人模式=lipsync)，
    #   不再恒 True 谎报；仅作标记不阻断(缺主引擎→画面失败会在"开播健康"里显形)。
    svc = check_services_cached()
    _bprof = _compute_broadcast(svc)
    _need_svc = "faceswap" if _bprof["mode"] == "real_faceswap" else "lipsync"
    steps.append({"step": "check_services", "ok": bool(svc.get(_need_svc)), "detail": svc})

    # Step 2: 确认角色已激活
    if profile_name and profile_name in _profiles:
        _active_profile = profile_name
        steps.append({"step": "activate_profile", "ok": True, "detail": profile_name})
    else:
        steps.append({"step": "activate_profile", "ok": True, "detail": "未选择角色，跳过激活"})

    # Step 2.5: 主动泊车（先释放后加载）——开播前，若显存已偏紧且本模式有「用不到却在线」的重型引擎
    #   (真人换脸模式下的 ditto/lipsync/latentsync/echomimic 等)，先停掉它们，从源头压低显存基线，
    #   减少重新开播时的吃紧/OOM。与手动「腾显存」、服务端自愈同口径(候选∩在线∩非核心, 双保险排除 NEVER)，
    #   安全且幂等；stop_any 自身保护 hub、跳过已迁远端。仅在确有可停者且 med/high 压力时才动手并计入步骤(不制造噪音)。
    #   失败绝不阻断开播。可用 HUB_AUTO_PARK_UNUSED=0 关闭。
    if _AUTO_PARK_UNUSED_ON and _supervisor is not None:
        try:
            _park_core = set(_bprof.get("core") or [])
            _park_cand = _FREE_UNUSED_CAND.get(_bprof.get("mode"), [])
            _park_sup = set(getattr(_supervisor, "SUPERVISED", {}) or {})
            # 按模式重建「挂起自愈」集：本模式用不到、且被常驻自愈钉住的引擎(如换脸模式的 ditto) → 挂起，
            # 让 self-heal 不再把它拉回(泊车才停得住、省下 ~4.7G)；用新集合覆盖旧的 → 切模式自动解除
            # (如切回口型模式，本模式候选不含 ditto → 其不在新挂起集 → 恢复守护、随时可用)。
            _new_suspend = {n for n in _park_cand
                            if n not in _FREE_UNUSED_NEVER and n not in _park_core and n in _park_sup}
            _PARK_SUSPEND.clear()
            _PARK_SUSPEND.update(_new_suspend)
            # 真正要停的：本模式用不到 ∩ 当前在线(含被挂起者一并停)。停完由上面的挂起保证不被自愈复活。
            _park_targets = [n for n in _park_cand
                             if n not in _FREE_UNUSED_NEVER and n not in _park_core and svc.get(n)]
            _park_ok = 0
            for _pn in _park_targets:
                try:
                    if _supervisor.stop_any(_pn).get("ok"):
                        _park_ok += 1
                except Exception:
                    pass
            if _park_ok:
                _park_names = "、".join(_CAND_CN.get(n, n) for n in _park_targets)
                _susp_note = "，并暂停其自愈以保持显存基线" if _new_suspend else "，降低显存基线"
                steps.append({"step": "park_unused", "ok": True,
                              "detail": f"已腾出 {_park_ok} 个未用引擎（{_park_names}）{_susp_note}"})
        except Exception:
            pass

    # Step 2.6: 双链路 OBS 设备互斥编排（hybrid）——把两条链路隔离到不同设备或严格互斥，
    #   根治 vcam 与 realtime_stream 争抢同一个 OBS 虚拟摄像头导致的画面停更(real_fps=0)/黑屏。
    try:
        if _bprof["mode"] == "real_faceswap":
            if _dual and _unitycapture_available():
                _apply_vcam_backend("unitycapture")
                steps.append({"step": "obs_mutex", "ok": True,
                              "detail": "双路同开：真人换脸→OBS 虚拟摄像头，数字人→Unity Capture（互不抢设备）"})
            else:
                _fr = _free_obs_from_vcam()
                steps.append({"step": "obs_mutex", "ok": True,
                              "detail": ("真人换脸独占 OBS 虚拟摄像头（已让数字人广播中枢让位）"
                                         if _fr.get("stopped") else "真人换脸独占 OBS（数字人中枢未在运行）")})
        else:
            _stop_realtime_free_obs()
            _ensure_vcam_obs()
            steps.append({"step": "obs_mutex", "ok": True,
                          "detail": "数字人独占 OBS 虚拟摄像头（已停真人换脸链路，画面由 vcam 广播）"})
    except Exception as e:
        steps.append({"step": "obs_mutex", "ok": True, "detail": f"OBS 编排忽略: {e}"})

    # Step 3: 启动视频链路（按模式分流：真人换脸=起 realtime_stream 独占 OBS；
    #         数字人=不起 realtime，画面由数字人广播中枢(vcam)输出）。
    if _bprof["mode"] != "real_faceswap":
        steps.append({"step": "start_video", "ok": True,
                      "detail": "数字人模式：画面由数字人广播中枢(vcam)输出，未启动真人换脸链路"})
    else:
        # 3.0 摄像头活源门禁：auto/未指定源且非强制 → 无真实源直接拦截，杜绝空转黑屏(real_fps=0)。
        if (not camera_idx) and video_source in ("", "auto") and not _force:
            _cam = _camera_live_source()
            if not _cam.get("live"):
                steps.append({"step": "camera_preflight", "ok": False,
                              "detail": "未检测到可用摄像头画面源：请①手机USB调试连接 或 ②扫码用手机摄像头 "
                                        "或 ③插摄像头/开 DroidCam 后重试。确认要空跑可传 force=true。"})
                return {"ok": False, "steps": steps, "mode": _bprof["mode"],
                        "need": "camera", "camera_probe": _cam, "audio": {}}
        # restart=True 时真重启：先停旧管线再起，否则 realtime_start 判定 already running 而空转。
        restart = bool(body.get("restart", False))
        try:
            _rt_alive = bool(_realtime_proc) and (_realtime_proc.poll() is None)
            if _rt_alive and not restart:
                steps.append({"step": "start_video", "ok": True,
                              "detail": "已在运行（改了画质/设备想生效，请点「重新开播」）"})
            else:
                if _rt_alive and restart:
                    # 终止旧 realtime_stream + 残留 scrcpy，并等其退出，确保 realtime_start 不会空转
                    try:
                        if _realtime_proc and _realtime_proc.poll() is None:
                            _realtime_proc.terminate()
                    except Exception:
                        pass
                    try:
                        _subprocess.run(
                            ["powershell", "-NoProfile", "-Command",
                             "Get-CimInstance Win32_Process | Where-Object { $_.CommandLine -like '*realtime_stream.py*' -or $_.CommandLine -like '*scrcpy.exe*' } | ForEach-Object { Stop-Process -Id $_.ProcessId -Force }"],
                            capture_output=True, text=True, timeout=10,
                            creationflags=getattr(_subprocess, "CREATE_NO_WINDOW", 0))
                    except Exception:
                        pass
                    for _ in range(15):                       # 最多等 ~3s 让端口/摄像头释放
                        if not (_realtime_proc and _realtime_proc.poll() is None):
                            break
                        time.sleep(0.2)
                # 如果传入 camera 索引则写入持久化文件，方便后续默认摄像头
                if camera_idx.isdigit():
                    try:
                        _CAMERA_IDX_FILE.write_text(camera_idx)
                    except Exception:
                        pass
                rt_body = {"source": camera_idx if camera_idx else video_source}
                if video_width > 0:  rt_body["width"]  = video_width
                if video_height > 0: rt_body["height"] = video_height
                if video_fps > 0:    rt_body["fps"]    = video_fps
                if swap_fps > 0:     rt_body["swap_fps"] = swap_fps
                if mjpeg_fps > 0:    rt_body["mjpeg_fps"] = mjpeg_fps
                if jpeg_quality > 0: rt_body["jpeg_quality"] = jpeg_quality
                if crossfade > 0:    rt_body["crossfade"] = crossfade
                if face_blend > 0:       rt_body["face_blend"] = face_blend
                if face_threshold > 0:   rt_body["face_threshold"] = face_threshold
                if face_smooth > 0:      rt_body["face_smooth"] = face_smooth
                if face_enhance:         rt_body["face_enhance"] = face_enhance
                if swap_preset:          rt_body["swap_preset"] = swap_preset
                if output_aspect:        rt_body["aspect"] = output_aspect
                result = realtime_start(rt_body)
                steps.append({"step": "start_video", "ok": result.get("ok", False),
                              "detail": result.get("detail", ""), "camera": result.get("camera", ""),
                              "auto_reason": result.get("auto_reason", ""),
                              "lic_note": result.get("lic_note", "")})
        except Exception as e:
            steps.append({"step": "start_video", "ok": False, "detail": str(e)})

    # Step 4: 启动 RVC (如果 rvc 服务未运行则启动 API 模式)
    if not svc.get("rvc"):
        try:
            result = realtime_start_rvc_api()
            steps.append({"step": "start_rvc", "ok": result.get("ok", False),
                          "detail": result.get("detail", "")})
        except Exception as e:
            steps.append({"step": "start_rvc", "ok": False, "detail": str(e)})
    else:
        steps.append({"step": "start_rvc", "ok": True, "detail": "已在运行"})

    # Step 5: 适配音频设备并回传前端。优先级：界面明确下发(audio_in/out) > 已存偏好 > 自动推荐
    # （P2-4 修复：此前无条件回传自动挑选，前端直接套用会顶掉用户刚选好的设备）。
    # 不计入 all_ok 硬门(缺 CABLE 仅告警，不阻断换脸出画)。明细说人话标签，原始名保留在 detail_raw。
    audio_pick = {}
    try:
        audio_pick = _pick_audio_devices()
        try:
            import device_enum as _de
            req_in = str(body.get("audio_in", "") or "").strip()
            req_out = str(body.get("audio_out", "") or "").strip()
            if req_in:
                audio_pick.update(input=req_in, input_label=_de.label_for(req_in, "in"),
                                  input_reason="你在界面上选定的麦克风")
            if req_out:
                audio_pick.update(output=req_out, output_label=_de.label_for(req_out, "out"),
                                  output_reason="你在界面上选定的输出")
        except Exception:
            pass
        ilbl = audio_pick.get("input_label") or audio_pick.get("input") or "—"
        olbl = audio_pick.get("output_label") or audio_pick.get("output") or "未找到直播声卡(检查 VB-Cable)"
        _why = audio_pick.get("input_reason") or ""
        steps.append({"step": "auto_audio", "ok": True,
                      "detail": f"麦克风={ilbl} · 输出={olbl}" + (f"（{_why}）" if _why else ""),
                      "detail_raw": f"输入={audio_pick.get('input') or '—'} · "
                                    f"输出={audio_pick.get('output') or '未找到 CABLE(检查 VB-Cable)'}"})
    except Exception as e:
        steps.append({"step": "auto_audio", "ok": True, "detail": f"设备枚举失败(忽略): {e}"})

    all_ok = all(s["ok"] for s in steps)
    return {"ok": all_ok, "steps": steps, "audio": audio_pick}

@app.post("/api/one_click_stop")
def one_click_stop():
    """一键停播"""
    _sched_note_stop()   # P14-A1: 排班场次内人工停播→记本场豁免，不再自动重开（排班自己的下播带旗标豁免）
    results = []
    # 停视频
    if _realtime_proc and _realtime_proc.poll() is None:
        _realtime_proc.terminate()
        results.append("video stopped")
        _matting_drain_soon()      # 一键停播同样触发队列接力
    try:
        ps = _subprocess.run(
            ["powershell", "-NoProfile", "-Command",
             "Get-CimInstance Win32_Process | Where-Object { $_.CommandLine -like '*realtime_stream.py*' -or $_.CommandLine -like '*scrcpy.exe*' } | ForEach-Object { Stop-Process -Id $_.ProcessId -Force }"],
            capture_output=True, text=True, timeout=10,
            creationflags=getattr(_subprocess, "CREATE_NO_WINDOW", 0))
        if ps.returncode == 0:
            results.append("stale video processes cleaned")
    except Exception:
        pass
    # 停 RVC
    if _rvc_proc and _rvc_proc.poll() is None:
        _rvc_proc.terminate()
        results.append("rvc stopped")
    # 停播→解除「按模式挂起自愈」：被泊的常驻引擎(如换脸模式挂起的 ditto)恢复守护，
    # 数字人/口型模式随时可用(self-heal 下一周期即把它拉回)。
    try:
        if _PARK_SUSPEND:
            _PARK_SUSPEND.clear()
            results.append("resume parked engines self-heal")
    except Exception:
        pass
    return {"ok": True, "detail": ", ".join(results) if results else "nothing to stop"}

# ── 开播模式（真人换脸 / 数字人）：前端读/写单一真相 ─────────────────────────
@app.get("/api/broadcast_mode")
def get_broadcast_mode():
    """当前开播模式 + 是否显式设置 + 是否可双路同开（装了 Unity Capture）。"""
    _m = _get_broadcast_mode()
    return {"ok": True,
            "mode": _m or _compute_broadcast(check_services_cached()).get("mode"),
            "explicit": bool(_m),
            "dual_available": _unitycapture_available()}

@app.post("/api/broadcast_mode")
def set_broadcast_mode(body: dict = {}):
    """设置开播模式（real_faceswap / avatar_lipsync）。仅落库，不动链路——真正切换在开播时编排。"""
    _m = _set_broadcast_mode(str(body.get("mode", "")))
    if not _m:
        return {"ok": False, "detail": "mode 必须是 real_faceswap 或 avatar_lipsync"}
    return {"ok": True, "mode": _m, "dual_available": _unitycapture_available()}

# ── 系统信息 ──────────────────────────────────────────────────────
@app.get("/api/system_info")
def system_info():
    """返回系统信息：GPU、内存、磁盘"""
    info = {"gpu": "unknown", "gpu_mem": "unknown", "ram": "unknown", "disk": "unknown"}
    try:
        import subprocess
        r = subprocess.run(["nvidia-smi", "--query-gpu=name,memory.total,memory.used",
                            "--format=csv,noheader,nounits"],
                           capture_output=True, text=True, timeout=5,
                           creationflags=getattr(subprocess, "CREATE_NO_WINDOW", 0))
        if r.returncode == 0:
            parts = r.stdout.strip().split(", ")
            if len(parts) >= 3:
                info["gpu"] = parts[0]
                info["gpu_mem"] = f"{parts[2]}/{parts[1]} MB"
    except Exception:
        pass
    try:
        import psutil
        mem = psutil.virtual_memory()
        info["ram"] = f"{mem.used // (1024**3)}/{mem.total // (1024**3)} GB ({mem.percent}%)"
        disk = psutil.disk_usage("C:")
        info["disk"] = f"{disk.used // (1024**3)}/{disk.total // (1024**3)} GB"
    except Exception:
        pass
    info["profiles"] = len(_profiles)
    info["voices"] = len(list(VOICES_DIR.glob("*.wav"))) if VOICES_DIR.exists() else 0
    return info


