    _metrics["speak_rvc_applied"]   = 0
    _metrics["speak_rvc_failed"]    = 0
    _metrics["tts_error"]           = 0   # P9-4
    _metrics["rvc_error"]           = 0   # P9-4
    _metrics["batch_item_failed"]   = 0   # P11-C2
    _metrics["speak_slow_total"]     = 0   # P12-C1
    _metrics["tts_retry_total"]      = 0   # P13-C1
    _metrics["rvc_retry_total"]      = 0   # P13-C1
    _metrics["stream_sse_total"]       = 0   # P13-4
    _metrics["stream_sse_sentences"]   = 0   # P13-4
    _metrics["stream_sse_rvc_applied"] = 0   # P13-4
    _metrics["stream_sse_first_ms_sum"] = 0   # P18-1
    _metrics["stream_sse_first_count"]  = 0   # P18-1
    _metrics["speak_latency_ms"].clear()
    _metrics["stream_first_ms"].clear()   # Phase7
    _metrics["conv_stream_first_ms"].clear()
    _metrics["conv_whole_first_ms"].clear()
    _metrics["audience_first_ms"].clear()
    _metrics["audience_stream_first_ms"].clear()
