@app.get("/metrics")
def get_metrics():
    """运行指标：延迟分布 / RVC命中率 / 吞吐量 / 运行时长"""
    lats = sorted(_metrics["speak_latency_ms"]) if _metrics["speak_latency_ms"] else []
    n    = len(lats)
    p50  = lats[n // 2]         if n else 0
    p95  = lats[int(n * 0.95)]  if n else 0
    p99  = lats[int(n * 0.99)]  if n else 0
    total = _metrics["speak_total"]
    rvc_rate = round(_metrics["speak_rvc_applied"] / total, 3) if total else 0
    uptime_h = round((time.time() - _metrics["uptime_start"]) / 3600, 2)
    try:
        with _db_conn() as conn:
            hist_count = conn.execute("SELECT COUNT(*) FROM speak_history").fetchone()[0]
    except Exception:
        hist_count = -1
    return {
        "speak_total":          total,
        "speak_rvc_rate":       rvc_rate,
        "speak_rvc_failed":     _metrics["speak_rvc_failed"],
        "tts_error":            _metrics["tts_error"],          # P9-4
        "rvc_error":            _metrics["rvc_error"],          # P9-4
        "tts_retry_total":      _metrics["tts_retry_total"],    # P13-C1
        "rvc_retry_total":      _metrics["rvc_retry_total"],    # P13-C1
        "batch_item_failed":    _metrics["batch_item_failed"],  # P11-C2
        "speak_slow_total":      _metrics["speak_slow_total"],    # P12-C1: >5s慢请求总数
        "speak_latency_p50ms":  p50,
        "speak_latency_p95ms":  p95,
        "speak_latency_p99ms":  p99,
        "speak_latency_samples": n,
        "batch_dub_total":      _metrics["batch_dub_total"],
        "batch_dub_lines":      _metrics["batch_dub_lines_total"],
        "video_submitted":      _metrics["video_submitted"],
        "clone_total":          _metrics["clone_total"],
        "clone_rejected":       _metrics["clone_rejected"],
        "history_records":      hist_count,
        "uptime_hours":         uptime_h,
        "cors_origins":         _CORS_ORIGINS,
        "ws_active":            len(ws_clients),
        "profiles_count":       len(_profiles),
        "stream_sse_total":      _metrics["stream_sse_total"],       # P13-4
        "stream_sse_sentences":  _metrics["stream_sse_sentences"],   # P13-4
        "stream_sse_rvc_applied":_metrics["stream_sse_rvc_applied"], # P13-4
        "stream_sse_rvc_rate":   round(
            _metrics["stream_sse_rvc_applied"] / _metrics["stream_sse_sentences"], 3
        ) if _metrics["stream_sse_sentences"] else 0,               # P13-4
        "stream_sse_avg_first_ms": round(                           # P18-1
            _metrics["stream_sse_first_ms_sum"] / _metrics["stream_sse_first_count"], 1
        ) if _metrics["stream_sse_first_count"] else 0,
        "speak_emotion_auto":    _metrics["speak_emotion_auto"],    # UI-P5-1: 决策①数据
        "emotion_auto_miss":     _metrics["emotion_auto_miss"],     # UI-P7: 「情感不对？」反馈数
        "stream_sse_emotion":    _metrics["stream_sse_emotion"],    # UI-P5-1: 流式情感路由次数
        "emotion_auto_rate":     round(                             # 终身口径（看板沿用；决策①勿用——分母含 auto 上线前历史）
            _metrics["speak_emotion_auto"] / max(total + _metrics["stream_sse_total"], 1), 3
        ),
        "decision1":             _d1_block(),                       # UD1: 决策①唯一口径（基线以来增量+verdict）
        "latency_histogram":    {
            "<500ms":     _metrics["latency_buckets"][0],
            "500-1000ms": _metrics["latency_buckets"][1],
            "1000-3000ms":_metrics["latency_buckets"][2],
            ">3000ms":    _metrics["latency_buckets"][3],
        },
    }


@app.get("/api/engines")
def get_engines(kind: str = ""):
    """Phase5/8: 列出已注册的 TTS/VC/LipSync/FaceSwap 引擎及其可用性与滚动延迟。
    kind 可选 tts/vc/lipsync/faceswap 过滤；available 依据子服务健康表实时同步。"""
    if _engine_registry is None:
        raise HTTPException(503, "engine_registry 未加载")
