@app.get("/api/capacity")
def api_capacity():
    """P-Conc1: 实时会话容量/排队快照——自托管交付时用于看「这台机器还能接几路、排了几个」。
    enabled=false 表示未启用准入(行为同改造前)；启用后 active≤max，waiting 为排队数。"""
    snap = _conv_capacity_snapshot()
    snap["ok"] = (not snap["enabled"]) or (snap["waiting"] == 0)
    return snap


# ── 观众提问链路 (P-Conc7) ─────────────────────────────────────────
# 观众/弹幕提问入列→主播侧择优回答。安全核心：观众输入【不直接发声】，回答时复用现有
# /api/converse(priority=0)，主播自己说话 priority 高→自动插队(复用已实现优先级准入)。
# 深度内容安全由对话管线的输入安全闸门在回答时兜底；本层只轻量校验+限流+去重(见 audience.py)。
# 默认关闭(AVATARHUB_AUDIENCE=1 开)，零回归。
AUDIENCE_ON = os.environ.get("AVATARHUB_AUDIENCE", "0") == "1"
try:
    import audience as _audience_mod
    _audience = _audience_mod.AudienceQueue(
        max_q=int(os.environ.get("AUDIENCE_MAX_Q", "200")),
        per_ip_sec=float(os.environ.get("AUDIENCE_RATE_SEC", "3")),
        max_len=int(os.environ.get("AUDIENCE_MAX_LEN", "200")),
        hot_halflife=float(os.environ.get("AUDIENCE_HOT_HALFLIFE", "600")),
        drop_policy=os.environ.get("AUDIENCE_DROP_POLICY", "reject"))
except Exception as _ae:
    _audience = None
    print(f"[Hub] 观众提问模块加载失败(降级): {_ae}")

# ── P0-3 弹幕/评论实时互动网关：平台弹幕(B站直连/通用WS转发/Webhook直推)→观众队列 ──
#   数字人"接住弹幕"开口回答走既有 自动应答→converse→克隆音+口型 链路(见 danmaku_gateway.py)。
#   软降级：模块缺失只损失弹幕接入,不影响 Hub。路由常注册,未 start 时返回"网关未运行"。
try:
    import danmaku_gateway as _danmaku_mod
    _danmaku_gw = _danmaku_mod.attach(app, lambda: (_audience if AUDIENCE_ON else None),
                                      log=_logger)
except Exception as _de:
    _danmaku_gw = None
    print(f"[Hub] 弹幕网关模块加载失败(降级): {_de}")


class AudienceAsk(BaseModel):
    text: str
    name: str = ""

class AudienceId(BaseModel):
    id: int


@app.post("/api/audience/ask")
async def api_audience_ask(req: AudienceAsk, request: Request):
    """观众提问入口（公开）。限流/去重/长度由 audience 模块兜，超限返回 429。
    Song-P2/F1: 「点歌 歌名」格式的弹幕在点歌台开启时改道点歌队列（不进提问队列）。"""
    if (_station.get("enabled") and _station.get("chat_enabled")
            and _station_parse_chat(req.text)):
        return await api_station_chat(StationChatBody(text=req.text, name=req.name))
    if not AUDIENCE_ON:
        raise HTTPException(503, "观众提问未开启")
    if _audience is None:
        raise HTTPException(503, "观众提问模块未加载")
    ip = (request.client.host if request.client else "") or ""
    r = _audience.submit(req.text, name=req.name, ip=ip)
    if not r.get("ok"):
        raise HTTPException(429, r.get("reason", "提交失败"))
    return r


