# ── 自动应答 worker (P-Conc8) ──────────────────────────────────────
# 把观众链路从「主播全程手动」升级为「可无人值守」：后台单飞循环→取最早未答问题→
# 以 priority=0 走【创作者同一条】/api/converse/stream（服务端自消费 body_iterator，
# vcam 推流/准入/安全闸门全部复用，无需任何客户端）。主播随时说话(priority 高)即插队，
# 或一键暂停。默认关(AUDIENCE_AUTO_ANSWER=1 开)；循环常驻但 off 时纯空转，零回归。
_AUDIENCE_AUTO_SESSION  = os.environ.get("AUDIENCE_AUTO_SESSION", "audience_auto")
_AUDIENCE_AUTO_POLL     = max(0.5, float(os.environ.get("AUDIENCE_AUTO_POLL", "3")))   # 取题轮询(s)
_AUDIENCE_AUTO_COOLDOWN = max(0.0, float(os.environ.get("AUDIENCE_AUTO_COOLDOWN", "2")))  # 两答间隔(s)
_AUDIENCE_AUTO_LIPSYNC  = os.environ.get("AUDIENCE_AUTO_LIPSYNC", "1") == "1"
# 观众自动应答篇幅约束：单数字人串行作答，简短=更高吞吐+更少积压(压测验证)。仅作用于
# 观众自动应答链路，绝不影响创作者自己说话。BREVITY 置空可关闭；MAXTOK=0 不硬截(靠提示)。
_AUDIENCE_AUTO_BREVITY  = os.environ.get(
    "AUDIENCE_AUTO_BREVITY",
    "【观众提问·简答】用1~2句话、口语化直接给结论，别展开、别铺垫，控制在40字以内。")
_AUDIENCE_AUTO_MAXTOK   = int(os.environ.get("AUDIENCE_AUTO_MAXTOK", "0"))   # 0=不硬截
_audience_auto = {"on": os.environ.get("AUDIENCE_AUTO_ANSWER", "0") == "1",
                  "inflight": False, "answered": 0, "errors": 0, "last": ""}
_audience_auto_task = None

# ── 观众墙公屏「正在作答」状态 (P-Conc9) ──────────────────────────
# /wall 大屏的「正在作答」卡片数据源。自动应答时字幕由 worker 解析 SSE 逐句填充；
# 手动采纳时 hub 看不到逐句→只显示问题 + manual 标记，靠 TTL 兜底过期。纯内存。
# caption=当前句(大屏显示)；answer=本轮逐句拼成的完整回答(供「精彩问答」高光落档)。
_WALL_NOW_TTL = float(os.environ.get("WALL_NOW_TTL", "45"))
_audience_now = {"name": "", "text": "", "caption": "", "answer": "",
                 "manual": False, "likes": 0, "qid": None, "since": 0.0, "saved": False}

# ── 本场精彩问答高光 (P-Conc11/12)：每轮答完落一条 {问题+完整回答+赞+时刻}，
# 可看/导出/截图/图片卡。SQLite 持久化(重启不丢、按场次回看) + 内存 deque 跑热路径。──
import itertools as _itertools_hl
_HIGHLIGHTS_MAX = int(os.environ.get("HIGHLIGHTS_MAX", "100"))
_highlights = deque(maxlen=max(1, _HIGHLIGHTS_MAX))
_hl_ids = _itertools_hl.count(1)              # 仅 DB 不可用时的兜底自增 id
_HIGHLIGHTS_DB = Path(os.environ.get("AVATARHUB_HIGHLIGHTS_DB", "").strip()
                      or rf"{_BASE}\highlights.db")
# 场次 = 启动批次时间戳；同一进程内所有高光归到一场，便于「本场/历史」切换
_HL_SESSION = time.strftime("%Y-%m-%d %H:%M")
_hl_lock = threading.Lock()


def _hl_conn():
    conn = _sqlite3.connect(str(_HIGHLIGHTS_DB), check_same_thread=False)
    conn.row_factory = _sqlite3.Row
    conn.execute("PRAGMA journal_mode=WAL")
    conn.execute("PRAGMA synchronous=NORMAL")
    return conn


def _init_highlights_db():
    try:
        with _hl_conn() as conn:
            conn.execute("""
            CREATE TABLE IF NOT EXISTS highlights (
                id       INTEGER PRIMARY KEY AUTOINCREMENT,
                ts       INTEGER NOT NULL,
                session  TEXT    NOT NULL,
                profile  TEXT    DEFAULT '',
                qid      INTEGER,
                name     TEXT    DEFAULT '观众',
                question TEXT    NOT NULL,
                answer   TEXT    NOT NULL,
                likes    INTEGER DEFAULT 0
            )""")
            conn.execute("CREATE INDEX IF NOT EXISTS idx_hl_session ON highlights(session, id DESC)")
            conn.execute("CREATE INDEX IF NOT EXISTS idx_hl_ts      ON highlights(ts DESC)")
    except Exception as _e:
        _logger.warning(f"[Highlights] DB 初始化失败(退回纯内存): {_e}")


def _hl_backfill():
    """启动时把本场(同启动时间戳)已存高光载回内存，重启后 /highlights 不空。"""
    try:
        with _hl_conn() as conn:
            rows = conn.execute(
                "SELECT id,qid,name,question,answer,ts,likes FROM highlights "
                "WHERE session=? ORDER BY id DESC LIMIT ?",
                (_HL_SESSION, _HIGHLIGHTS_MAX)).fetchall()
        for r in reversed(rows):
            _highlights.append({"id": r["id"], "qid": r["qid"], "name": r["name"],
                                "question": r["question"], "answer": r["answer"],
                                "ts": r["ts"], "likes": r["likes"]})
    except Exception as _e:
        _logger.warning(f"[Highlights] 回填失败: {_e}")


_init_highlights_db()
_hl_backfill()


# ── 观众提问 + 公屏「正在作答」卡 现场状态持久化 (P-Conc13) ─────────────────
# 目标：直播中途 hub 重启/崩溃，不丢「未答队列 + 正在作答卡」这份易逝的现场。
# 与 highlights(SQLite 按场次存「答完的高光」) 互补——这里存「活跃现场」。
# 方案：把「队列 + 正在作答卡」整体镜像成一个 JSON，周期【脏检查】原子落盘（空闲零写）、
#       关机前兜底写；启动仅回填【近 RESTORE_TTL 内】的快照（过旧视作新场，不复活隔夜队列）。
# 仅在观众功能开启(AVATARHUB_AUDIENCE=1)时生效：默认关 → 零新文件、零行为变化，完全向后兼容。
_AUDIENCE_STATE_FILE = Path(os.environ.get("AVATARHUB_AUDIENCE_STATE", "").strip()
                            or str(_LOG_DIR / "audience_state.json"))
_AUDIENCE_RESTORE_TTL = float(os.environ.get("AUDIENCE_RESTORE_TTL", "1800"))   # 快照多旧仍回填(s)，默认 30min
_AUDIENCE_FLUSH_SEC   = max(1.0, float(os.environ.get("AUDIENCE_FLUSH_SEC", "3")))  # 脏检查周期(s)
_AUDIENCE_PERSIST_ACTIVE = AUDIENCE_ON and os.environ.get("AUDIENCE_PERSIST", "1") != "0"
_audience_persist_task = None
_audience_last_blob = ""          # 上次落盘的载荷(不含写盘时刻)——脏检查用，避免无变化重复写
_audience_last_save_ts = 0.0      # 上次真正写盘时刻——供「仍有现场→心跳刷新 saved_ts」判定
_AUDIENCE_HEARTBEAT = max(30.0, float(os.environ.get("AUDIENCE_HEARTBEAT", "300")))  # 现场心跳(s)
_AUDIENCE_CARD_KEYS = ("name", "text", "caption", "answer", "manual",
                       "likes", "qid", "since", "saved")


def _audience_state_payload() -> dict:
    """「现场」可持久化载荷（不含写盘时刻，供脏检查稳定比较）：队列问题 + 正在作答卡。"""
    queue = _audience.export_state() if _audience is not None else {}
    card = {k: _audience_now.get(k) for k in _AUDIENCE_CARD_KEYS}
    return {"v": 1, "queue": queue, "now": card}


def _audience_has_live_state() -> bool:
    """是否仍有「活跃现场」：有待答问题，或正在作答卡未过期。用于心跳保鲜 saved_ts。"""
    try:
        if _audience is not None and _audience.pending_count() > 0:
            return True
    except Exception:
        pass
    since = _audience_now.get("since") or 0
    return bool(since) and (time.time() - float(since)) <= _WALL_NOW_TTL


def _audience_state_save(force: bool = False) -> bool:
    """原子落盘现场快照。空闲(载荷无变化)零写；但仍有活跃现场时每 _AUDIENCE_HEARTBEAT
    刷新一次 saved_ts，让慢直播的待答队列也始终落在 RESTORE_TTL 内(重启必恢复)。返回是否写了。"""
    global _audience_last_blob, _audience_last_save_ts
    if not _AUDIENCE_PERSIST_ACTIVE or _audience is None:
        return False
    try:
        payload = _audience_state_payload()
        blob = json.dumps(payload, ensure_ascii=False, sort_keys=True, separators=(",", ":"))
    except Exception as _e:
        _logger.debug(f"[AudiencePersist] 序列化失败: {_e}")
        return False
    if not force and blob == _audience_last_blob:
        # 内容未变：仅当仍有活跃现场 + 距上次写盘超心跳间隔，才刷新 saved_ts 维持 TTL 新鲜
        if not (_audience_has_live_state()
                and (time.time() - _audience_last_save_ts) > _AUDIENCE_HEARTBEAT):
            return False
    try:
        _AUDIENCE_STATE_FILE.parent.mkdir(parents=True, exist_ok=True)
        payload["saved_ts"] = time.time()   # 写盘时刻仅入文件（供 TTL 判定），不参与脏检查
        tmp = _AUDIENCE_STATE_FILE.parent / (_AUDIENCE_STATE_FILE.name + ".tmp")
        tmp.write_text(json.dumps(payload, ensure_ascii=False, separators=(",", ":")),
                       encoding="utf-8")
        os.replace(str(tmp), str(_AUDIENCE_STATE_FILE))   # 原子替换，防半写损坏
        _audience_last_blob = blob
        _audience_last_save_ts = time.time()
        return True
    except Exception as _e:
        _logger.debug(f"[AudiencePersist] 写盘失败: {_e}")
        return False


def _audience_state_load():
    """启动回填：仅恢复近 RESTORE_TTL 内的快照（队列 + 正在作答卡）；过旧视作新场不复活。"""
    global _audience_last_blob
    if not _AUDIENCE_PERSIST_ACTIVE or _audience is None:
        return
    try:
        if not _AUDIENCE_STATE_FILE.exists():
            return
        data = json.loads(_AUDIENCE_STATE_FILE.read_text(encoding="utf-8"))
    except Exception as _e:
        _logger.warning(f"[AudiencePersist] 读取快照失败(忽略): {_e}")
        return
    if not isinstance(data, dict) or data.get("v") != 1:
        return
    age = time.time() - float(data.get("saved_ts") or 0)
    if age < 0 or age > _AUDIENCE_RESTORE_TTL:
        _logger.info(f"[AudiencePersist] 快照 {int(age)}s 前 > TTL({int(_AUDIENCE_RESTORE_TTL)}s)，不回填(视作新场)")
        return
    try:
        n = _audience.restore_state(data.get("queue") or {})
    except Exception as _e:
        _logger.warning(f"[AudiencePersist] 队列回填失败: {_e}")
        n = 0
    card = data.get("now")
    if isinstance(card, dict) and card.get("since"):   # 只在卡确有内容时回填（TTL 再兜一层）
        for k in _AUDIENCE_CARD_KEYS:
            if k in card:
                _audience_now[k] = card[k]
    if n:
        _logger.info(f"[AudiencePersist] 重启回填 {n} 条待答问题（快照 {int(age)}s 前）")


async def _audience_persist_loop():
    """周期脏检查落盘：空闲(载荷无变化)零写；有活动时最多每 _AUDIENCE_FLUSH_SEC 落一次。"""
    while True:
        try:
            await asyncio.sleep(_AUDIENCE_FLUSH_SEC)
            await asyncio.to_thread(_audience_state_save)
        except asyncio.CancelledError:
            break
        except Exception as _e:
            _logger.debug(f"[AudiencePersist] 周期落盘异常: {_e}")


def _wall_finalize():
    """把当前「正在作答」凝固成一条高光（仅当问题+回答俱在且未存过）→ 落 DB + 内存。"""
    n = _audience_now
    if not (n.get("since") and n.get("text") and n.get("answer") and not n.get("saved")):
        return
    rec = {"qid": n.get("qid"), "name": n.get("name") or "观众",
           "question": n.get("text"), "answer": n.get("answer"),
           "ts": int(n.get("since")), "likes": int(n.get("likes") or 0)}
    hid = None
    try:                                   # 先持久化拿 DB 自增 id 作为权威 id（图片卡按 id 取）
        with _hl_lock, _hl_conn() as conn:
            cur = conn.execute(
                "INSERT INTO highlights(ts,session,profile,qid,name,question,answer,likes)"
                " VALUES(?,?,?,?,?,?,?,?)",
                (rec["ts"], _HL_SESSION, _active_profile or "", rec["qid"],
                 rec["name"], rec["question"], rec["answer"], rec["likes"]))
            hid = cur.lastrowid
    except Exception as _e:
        _logger.warning(f"[Highlights] 落库失败(仅内存): {_e}")
    rec["id"] = hid if hid is not None else next(_hl_ids)
    _highlights.append(rec)
    n["saved"] = True


def _wall_begin(q: dict, manual: bool = False):
    _wall_finalize()   # 开新一轮前，先把上一轮（手动路径可能没显式结束）落档
    _audience_now.update(name=q.get("name", ""), text=q.get("text", ""), caption="",
                         answer="", manual=manual, likes=int(q.get("likes") or 0),
                         qid=q.get("id"), since=time.time(), saved=False)


def _wall_caption(t: str):
    if t:
        _audience_now["caption"] = t
        a = _audience_now.get("answer", "")
        _audience_now["answer"] = ((a + " " + t).strip())[:2000]   # 完整回答有界拼接


def _wall_end():
    _wall_finalize()
    _audience_now.update(name="", text="", caption="", answer="", manual=False,
                         likes=0, qid=None, since=0.0, saved=False)


def _wall_now_snapshot():
    since = _audience_now["since"]
    if not since or (time.time() - since) > _WALL_NOW_TTL:   # 兜底过期(主给无显式结束的手动采纳)
        return None
    return {"name": _audience_now["name"], "text": _audience_now["text"],
            "caption": _audience_now["caption"], "manual": _audience_now["manual"],
            "elapsed": int(time.time() - since)}


def _audience_auto_status() -> dict:
    st = _streaming_tts_ready()
    return {"on": bool(_audience_auto["on"]), "inflight": bool(_audience_auto["inflight"]),
            "answered": int(_audience_auto["answered"]), "errors": int(_audience_auto["errors"]),
            "last": _audience_auto["last"],
            "available": _audience is not None and _audience_auto_task is not None,
            "streaming": {"enabled": st["enabled"], "eligible": st["eligible"],
                          "profile": st["profile"]}}


async def _audience_fire(text: str):
    """以 priority=0 把一条观众问题走完整对话流(含 vcam 广播)。复用创作者同一路径，
    服务端自行消费 SSE（丢弃字节，副作用即推流/落库），故无需任何客户端。"""
    req = ConverseRequest(text=text, session_id=_AUDIENCE_AUTO_SESSION,
                          profile=(_active_profile or ""), speak=True,
                          generate_lipsync=_AUDIENCE_AUTO_LIPSYNC, priority=0,
                          brevity_hint=_AUDIENCE_AUTO_BREVITY,
                          max_tokens=(_AUDIENCE_AUTO_MAXTOK or None))
    resp = await api_converse_stream(req)
    bi = getattr(resp, "body_iterator", None)
    if bi is None:
        return
    # 顺手解析 SSE 逐句 text → 公屏实时字幕（核心链路零改动；解析失败静默跳过）
    buf = ""
    async for chunk in bi:
        if isinstance(chunk, (bytes, bytearray)):
            chunk = chunk.decode("utf-8", "replace")
        buf += chunk
        while "\n\n" in buf:
            raw, buf = buf.split("\n\n", 1)
            raw = raw.strip()
            if not raw.startswith("data:"):
                continue
            try:
                ev = json.loads(raw[5:].strip())
            except Exception:
                continue
            if ev.get("phase") == "sentence":
                _wall_caption(ev.get("text", ""))


async def _audience_auto_loop():
    """后台单飞循环：on 且有未答→取最早一条→标记已答(一次性，杜绝毒题死循环)→开口。"""
    if _audience is None:
        return
    _logger.info("[Audience] 自动应答循环已就绪（默认%s）", "开" if _audience_auto["on"] else "关")
    while True:
        try:
            await asyncio.sleep(_AUDIENCE_AUTO_POLL)
            if not _audience_auto["on"] or _audience_auto["inflight"]:
                continue
            q = _audience.next_pending()
            if not q:
                continue
            ans = _audience.answer(q["id"])   # 先标记已答：失败也不再重取(避免毒题循环)
            if not ans:
                continue
            _audience_auto["inflight"] = True
            _wall_begin(ans, manual=False)        # 公屏「正在作答」+ 实时字幕
            try:
                await _audience_fire(ans["text"])
                _audience_auto["answered"] += 1
                _audience_auto["last"] = ans["text"][:60]
            except asyncio.CancelledError:
                raise
            except Exception as e:
                _audience_auto["errors"] += 1
                _logger.warning(f"[Audience] 自动应答开口失败: {e}")
            finally:
                _audience_auto["inflight"] = False
                _wall_end()
            if _AUDIENCE_AUTO_COOLDOWN > 0:
                await asyncio.sleep(_AUDIENCE_AUTO_COOLDOWN)
        except asyncio.CancelledError:
            _logger.info("[Audience] 自动应答循环已停止")
            break
        except Exception as e:
            _audience_auto["inflight"] = False
            _logger.warning(f"[Audience] 自动应答循环异常: {e}")


class AudienceAuto(BaseModel):
    on: bool


@app.post("/api/audience/auto")
def api_audience_auto(req: AudienceAuto):
    """主播一键开/关无人值守自动应答（运行时切换，不需重启）。"""
    if _audience is None:
        raise HTTPException(503, "观众提问模块未加载")
    _audience_auto["on"] = bool(req.on)
    _logger.info("[Audience] 自动应答 → %s", "开" if _audience_auto["on"] else "关")
    return {"ok": True, "auto": _audience_auto_status()}


@app.get("/api/audience/auto")
def api_audience_auto_status():
    return {"auto": _audience_auto_status()}


def _wall_state_payload(pending: int = 8, answered: int = 6) -> dict:
    if _audience is None:
        return {"enabled": False, "profile": _active_profile, "now": None,
                "pending": [], "answered": [], "stats": {}}
    ans = list(reversed(_audience.list("answered", 200)))[:max(1, answered)]
    snap = _audience.snapshot()
    return {"enabled": AUDIENCE_ON, "profile": _active_profile,
            "now": _wall_now_snapshot(),
            "pending": _audience.list("pending", max(1, pending), order="likes"),
            "answered": ans,
            "stats": {"pending": snap.get("pending", 0),
                      "answered": (snap.get("stats") or {}).get("answered", 0),
                      "top_likes": snap.get("top_likes", 0),
                      "auto_on": bool(_audience_auto["on"])}}


@app.get("/api/wall/state")
def api_wall_state(pending: int = 8, answered: int = 6):
    """观众墙公屏数据：正在作答(含实时字幕) + 排队 + 刚答 + 统计。轮询备用；实时走 /ws/wall。"""
    return _wall_state_payload(pending, answered)


# ── 公屏实时推送 (P-Conc9b)：专用 WS 通道(不污染 ops/心跳)，差分门控按需推 ──
wall_clients: set = set()
_wall_ws_task = None
_WALL_WS_SEC = max(0.1, float(os.environ.get("WALL_WS_INTERVAL_MS", "350")) / 1000.0)


def _wall_sig(state: dict):
    now = state.get("now") or {}
    pend = tuple((q.get("id"), q.get("likes", 0)) for q in state.get("pending", []))
    ans = tuple(q.get("id") for q in state.get("answered", []))
    st = state.get("stats", {})
    return (now.get("text", ""), now.get("caption", ""), now.get("manual"),
            pend, ans, st.get("auto_on"), state.get("enabled"))


async def _wall_ws_loop():
    """差分门控推送：每 ~350ms 算一次公屏快照，仅在内容变化时广播给 /ws/wall 客户端。
    无客户端时空转。字幕(逐句)变化 → 350ms 内到达，远比 1.2s 轮询跟手。"""
    last = None
    while True:
        try:
            await asyncio.sleep(_WALL_WS_SEC)
            if not wall_clients:
                last = None
                continue
            state = _wall_state_payload()
            sig = _wall_sig(state)
            if sig == last:
                continue
            last = sig
            dead = []
            for ws in list(wall_clients):
                try:
                    await asyncio.wait_for(ws.send_json(state), timeout=2.0)
                except Exception:
                    dead.append(ws)
            for ws in dead:
                wall_clients.discard(ws)
        except asyncio.CancelledError:
            break
        except Exception as e:
            _logger.debug(f"[Wall] ws loop: {e}")


@app.websocket("/ws/wall")
async def ws_wall(ws: WebSocket):
    await ws.accept()
    wall_clients.add(ws)
    try:
        await ws.send_json(_wall_state_payload())   # 连上即给整帧，无需等下一次差分
        while True:
            await ws.receive_text()                  # 客户端不发数据，仅借此感知断开
    except Exception:
        pass
    finally:
        wall_clients.discard(ws)


def _audience_ops_snapshot():
    """运维全景的观众块：队列 + 点赞热度 + 自动应答成功率 + 公屏在线端数。"""
    if _audience is None:
        return None
    snap = _audience.snapshot()
    auto = _audience_auto_status()
    snap["auto"] = auto
    snap["wall_clients"] = len(wall_clients)
    snap["highlights"] = len(_highlights)
    done, err = auto.get("answered", 0), auto.get("errors", 0)
    snap["auto_success_rate"] = round(done / (done + err), 3) if (done + err) else None
    st = _streaming_tts_snapshot()
    snap["streaming_tts"] = {"enabled": st["enabled"], "eligible": st["eligible"],
                             "metrics": st["metrics"].get("audience_stream", {})}
    # P0-3 弹幕网关：平台弹幕接入状态并入观众块(/ops 一处看全)。未运行 → running=False。
    if _danmaku_gw is not None:
        try:
            dm = _danmaku_gw.status()
            dm.pop("recent", None)                    # 看板只要计数,最近列表走 /api/danmaku/status
            snap["danmaku"] = dm
        except Exception:
            pass
    return snap


class WallCaption(BaseModel):
    text: str


@app.post("/api/wall/caption")
def api_wall_caption(req: WallCaption):
    """主播手动应答时前端把逐句字幕上报公屏（手动路径也有实时字幕）。仅在「正在作答」期间
    生效→防止无人作答时被任意刷屏。文本走 _clean 截断。"""
    if _audience_now["since"]:
        _wall_caption((req.text or "")[:200])
    return {"ok": True}


@app.post("/api/wall/finalize")
def api_wall_finalize():
    """手动应答结束时由控制台调用，把本轮问答凝固为一条高光（自动路径在 worker 内自结）。"""
    _wall_finalize()
    return {"ok": True}


@app.get("/api/highlights")
def api_highlights(limit: int = 50):
    """本场精彩问答（最新在前，来自内存热缓冲）。供回看页 / 导出 / 短视频取材。"""
    items = list(_highlights)[-max(1, limit):][::-1]
    return {"count": len(_highlights), "highlights": items,
            "profile": _active_profile, "session": _HL_SESSION}


def _hl_get(hid: int):
    """按 id 取一条高光：先内存(本场)，再回查 DB(历史场次)。"""
    for h in _highlights:
        if h.get("id") == hid:
            return h
    try:
        with _hl_conn() as conn:
            r = conn.execute("SELECT id,qid,name,question,answer,ts,likes,profile "
                             "FROM highlights WHERE id=?", (hid,)).fetchone()
        if r:
            return {"id": r["id"], "qid": r["qid"], "name": r["name"],
                    "question": r["question"], "answer": r["answer"],
                    "ts": r["ts"], "likes": r["likes"], "profile": r["profile"]}
    except Exception:
        pass
    return None


@app.get("/api/highlights/sessions")
def api_highlights_sessions():
    """历史场次列表（按场次聚合数量/起止时间），供回看页切换往期直播。"""
    try:
        with _hl_conn() as conn:
            rows = conn.execute(
                "SELECT session, COUNT(*) n, MIN(ts) t0, MAX(ts) t1, MAX(likes) top "
                "FROM highlights GROUP BY session ORDER BY t1 DESC LIMIT 60").fetchall()
        return {"current": _HL_SESSION,
                "sessions": [{"session": r["session"], "count": r["n"],
                              "from": r["t0"], "to": r["t1"], "top_likes": r["top"]}
                             for r in rows]}
    except Exception as e:
        return {"current": _HL_SESSION, "sessions": [], "error": str(e)}


@app.get("/api/highlights/archive")
def api_highlights_archive(session: str = "", limit: int = 200):
    """读取某历史场次的全部问答（默认本场）。回看页切换场次时调用。"""
    sess = session or _HL_SESSION
    try:
        with _hl_conn() as conn:
            rows = conn.execute(
                "SELECT id,qid,name,question,answer,ts,likes,profile FROM highlights "
                "WHERE session=? ORDER BY id DESC LIMIT ?",
                (sess, max(1, min(limit, 1000)))).fetchall()
        items = [{"id": r["id"], "qid": r["qid"], "name": r["name"],
                  "question": r["question"], "answer": r["answer"], "ts": r["ts"],
                  "likes": r["likes"], "profile": r["profile"]} for r in rows]
        return {"session": sess, "count": len(items), "highlights": items,
                "profile": (items[0]["profile"] if items else _active_profile)}
    except Exception as e:
        return {"session": sess, "count": 0, "highlights": [], "error": str(e)}


@app.delete("/api/highlights")
def api_highlights_clear(all: bool = False):
    """清空：默认仅本场（内存 + 本场 DB 行）；?all=1 抹掉全部历史场次。"""
    n = len(_highlights)
    _highlights.clear()
    purged = 0
    try:
        with _hl_lock, _hl_conn() as conn:
            cur = (conn.execute("DELETE FROM highlights") if all
                   else conn.execute("DELETE FROM highlights WHERE session=?", (_HL_SESSION,)))
            purged = cur.rowcount
    except Exception as e:
        _logger.warning(f"[Highlights] 清空失败: {e}")
    return {"ok": True, "cleared": n, "purged": purged, "scope": "all" if all else "session"}


@app.get("/api/highlights/export")
def api_highlights_export(session: str = ""):
    """导出某场问答为可读 .txt（默认本场；直接下载，便于复盘/做短视频字幕稿）。"""
    if session:
        with _hl_conn() as conn:
            rows = conn.execute("SELECT name,question,answer,ts,likes FROM highlights "
                                "WHERE session=? ORDER BY id ASC", (session,)).fetchall()
        items = [dict(r) for r in rows]
        title = session
    else:
        items = list(_highlights)
        title = _HL_SESSION
    lines = [f"# 精彩问答 · {_active_profile or '数字人'} · {title}",
             f"# 导出时间 {time.strftime('%Y-%m-%d %H:%M:%S')} · 共 {len(items)} 条", ""]
    for h in items:
        ts = time.strftime("%H:%M", time.localtime(h.get("ts", 0)))
        like = f" ♥{h['likes']}" if h.get("likes") else ""
        lines.append(f"[{ts}]{like} {h.get('name','观众')} 问：{h.get('question','')}")
        lines.append(f"答：{h.get('answer','')}")
        lines.append("")
    body = "\r\n".join(lines)
    fn = f"highlights_{time.strftime('%Y%m%d_%H%M%S')}.txt"
    return Response(content=body, media_type="text/plain; charset=utf-8",
                    headers={"Content-Disposition": f'attachment; filename="{fn}"'})


# ── 图片卡渲染 (P-Conc12)：把一条问答渲成竖图，直接做短视频/图文素材 ────────────
_HL_RATIOS = {"4x5": (1080, 1350), "9x16": (1080, 1920), "1x1": (1080, 1080)}
_HL_FONT = os.environ.get("HIGHLIGHTS_FONT", r"C:\Windows\Fonts\msyh.ttc")
_HL_FONT_BOLD = os.environ.get("HIGHLIGHTS_FONT_BOLD", r"C:\Windows\Fonts\msyhbd.ttc")
_hl_card_cache: "dict[tuple, bytes]" = {}     # (id,ratio) → png bytes，小缓存


def _hl_wrap(draw, text, font, max_w):
    """按像素宽逐字折行（中英混排通用）。"""
    lines, cur = [], ""
    for ch in (text or ""):
        if ch == "\n":
            lines.append(cur); cur = ""; continue
        if draw.textlength(cur + ch, font=font) <= max_w:
            cur += ch
        else:
            lines.append(cur); cur = ch
    if cur:
        lines.append(cur)
    return lines


def _hl_render_png(h: dict, ratio: str) -> bytes:
    from PIL import Image, ImageDraw, ImageFont
    W, H = _HL_RATIOS.get(ratio, _HL_RATIOS["4x5"])
    img = Image.new("RGB", (W, H), (11, 17, 32))
    d = ImageDraw.Draw(img)
    # 顶部品牌光晕带
    for y in range(0, 240):
        a = int(40 * (1 - y / 240))
        d.line([(0, y), (W, y)], fill=(11 + a // 3, 17 + a // 2, 32 + a))
    PAD = 84
    def F(path, sz):
        try:    return ImageFont.truetype(path, sz)
        except Exception: return ImageFont.load_default()
    f_meta = F(_HL_FONT, 30)
    f_badge = F(_HL_FONT_BOLD, 34)
    f_q = F(_HL_FONT_BOLD, 56)
    f_a = F(_HL_FONT, 42)
    f_brand = F(_HL_FONT, 28)
    prof = h.get("profile") or _active_profile or "数字人"
    ts = time.strftime("%Y-%m-%d %H:%M", time.localtime(h.get("ts", 0)))
    # 头部：角色 · 时间（左） + ♥赞（右）
    d.text((PAD, 70), prof, font=f_badge, fill=(122, 240, 200))
    d.text((PAD, 118), ts, font=f_meta, fill=(159, 176, 204))
    if h.get("likes"):
        pink = (255, 107, 139)
        num = str(h["likes"]); nw = d.textlength(num, font=f_badge)
        hs, gap = 36, 12
        x0 = W - PAD - (hs + gap + nw)
        hy = 82
        # 画心形(两圆+下三角)——雅黑无 U+2665，自绘最稳
        r = hs * 0.27
        d.ellipse([x0, hy, x0 + 2 * r, hy + 2 * r], fill=pink)
        d.ellipse([x0 + hs - 2 * r, hy, x0 + hs, hy + 2 * r], fill=pink)
        d.polygon([(x0, hy + r), (x0 + hs, hy + r), (x0 + hs / 2, hy + hs)], fill=pink)
        d.text((x0 + hs + gap, 78), num, font=f_badge, fill=pink)
    y = 210
    # 问
    d.rounded_rectangle([PAD, y, PAD + 70, y + 56], 14, fill=(91, 140, 255))
    d.text((PAD + 22, y + 8), "问", font=f_badge, fill=(255, 255, 255))
    qx = PAD + 92
    for ln in _hl_wrap(d, h.get("question", ""), f_q, W - qx - PAD)[:3]:
        d.text((qx, y), ln, font=f_q, fill=(234, 241, 251)); y += 70
    y += 24
    d.line([(PAD, y), (W - PAD, y)], fill=(38, 50, 74), width=2); y += 34
    # 答
    d.rounded_rectangle([PAD, y, PAD + 70, y + 56], 14, fill=(34, 50, 74))
    d.text((PAD + 22, y + 8), "答", font=f_badge, fill=(122, 240, 200))
    ax = PAD + 92
    max_lines = (H - y - 160) // 58
    a_lines = _hl_wrap(d, h.get("answer", ""), f_a, W - ax - PAD)
    for i, ln in enumerate(a_lines[:max_lines]):
        if i == max_lines - 1 and len(a_lines) > max_lines:
            while d.textlength(ln + "…", font=f_a) > (W - ax - PAD) and ln:
                ln = ln[:-1]
            ln += "…"
        d.text((ax, y), ln, font=f_a, fill=(205, 217, 238)); y += 58
    # 底部水印
    d.text((PAD, H - 70), f"{prof} · AvatarHub 直播精彩问答", font=f_brand, fill=(120, 135, 170))
    out = io.BytesIO(); img.save(out, "PNG"); return out.getvalue()


@app.get("/api/highlights/{hid}/card.png")
def api_highlights_card(hid: int, ratio: str = "4x5"):
    """把一条问答渲成竖图(默认 4:5；?ratio=9x16|1x1)。URL 可取、可脚本批量。"""
    h = _hl_get(hid)
    if not h:
        return Response(content="not found", status_code=404)
    ratio = ratio if ratio in _HL_RATIOS else "4x5"
    key = (hid, ratio)
    png = _hl_card_cache.get(key)
    if png is None:
        try:
            png = _hl_render_png(h, ratio)
        except Exception as e:
            return Response(content=f"render failed: {e}", status_code=503)
        if len(_hl_card_cache) > 60:
            _hl_card_cache.clear()
        _hl_card_cache[key] = png
    return Response(content=png, media_type="image/png",
                    headers={"Content-Disposition": f'inline; filename="hl_{hid}_{ratio}.png"'})


