# ── 环境检测 ──────────────────────────────────────────────────────
#   P1-3 人话化：每项带 cn(用户名称)/why(它管什么)/fix(修复入口)。旧字段 item/ok/path 不动。
#   fix.type: wizard=前端拉 VB-Cable 安装向导；url=下载链接；support=联系交付；tab=站内跳转。
_ENV_CHECK_META = {
    "py_facefusion": {"cn": "换脸引擎运行环境", "why": "缺了换脸/画面处理起不来",
                      "fix": {"type": "support", "label": "联系交付重装"}},
    "py_rvc":        {"cn": "变声引擎运行环境", "why": "缺了变声服务起不来",
                      "fix": {"type": "support", "label": "联系交付重装"}},
    "voices":        {"cn": "音色库", "why": "存放克隆音色，缺了没法配音",
                      "fix": {"type": "tab", "to": "clone", "label": "去声音克隆"}},
    "faces":         {"cn": "人脸库", "why": "存放出镜角色的脸，缺了没法换脸",
                      "fix": {"type": "tab", "to": "profiles", "label": "去角色库"}},
    "rvc_dir":       {"cn": "变声引擎程序", "why": "实时变声的本体程序目录",
                      "fix": {"type": "support", "label": "联系交付重装"}},
    "obs":           {"cn": "OBS 推流软件", "why": "把画面/声音推到直播平台",
                      "fix": {"type": "url", "to": "https://obsproject.com/download",
                              "label": "去官网下载"}},
    "vbcable":       {"cn": "直播虚拟声卡驱动 (VB-Cable)", "why": "变声后的声音靠它进 OBS，缺了观众听不到",
                      "fix": {"type": "wizard", "label": "安装向导"}},
    "scrcpy":        {"cn": "手机投屏工具 (scrcpy)", "why": "USB 线连手机当摄像头用",
                      "fix": {"type": "support", "label": "联系交付补装"}},
}


@app.get("/api/env_check")
def env_check():
    """检测运行环境：Python路径、模型文件、依赖。带人话名称与修复入口(P1-3)。"""
    checks = []

    def add(key, item, ok, path):
        meta = _ENV_CHECK_META.get(key, {})
        checks.append({"item": item, "ok": ok, "path": path, "key": key,
                       "cn": meta.get("cn", item), "why": meta.get("why", ""),
                       "fix": meta.get("fix", {})})

    # Python 环境
    for env_name, py_path in [
        ("facefusion", app_config.conda_python("facefusion")),
        ("rvc", app_config.conda_python("rvc")),
    ]:
        add(f"py_{env_name}", f"Python ({env_name})", Path(py_path).exists(), py_path)
    # 关键目录
    for key, label, dirp in [
        ("voices", "voices 音色库", VOICES_DIR),
        ("faces", "faces 人脸库", Path(rf"{_BASE}\faces")),
        ("rvc_dir", "RVC 工程", Path(rf"{_BASE}\Retrieval-based-Voice-Conversion-WebUI")),
    ]:
        add(key, label, dirp.exists(), str(dirp))
    # OBS Virtual Camera
    obs_path = Path(r"C:\Program Files\obs-studio\bin\64bit\obs64.exe")
    add("obs", "OBS Studio", obs_path.exists(), str(obs_path))
    # VB-Cable (优先通过PnP检测，避免文件名差异)
    vb_ok = False
    vb_path = r"Get-PnpDevice -FriendlyName '*VB-Audio*'"
    try:
        ps = _subprocess.run([
            "powershell", "-NoProfile", "-Command",
            "(Get-PnpDevice -FriendlyName '*VB-Audio*' -ErrorAction SilentlyContinue | Measure).Count"
        ], capture_output=True, text=True, timeout=5,
            creationflags=getattr(_subprocess, "CREATE_NO_WINDOW", 0))
        count = int(ps.stdout.strip()) if ps.returncode == 0 and ps.stdout.strip().isdigit() else 0
        vb_ok = count > 0
    except Exception:
        vb_ok = False
    if not vb_ok:
        vb_drivers = list(Path(r"C:\Windows\System32\drivers").glob("vbaudio_cable*.sys"))
        vb_ok = len(vb_drivers) > 0
        vb_path = str(vb_drivers[0]) if vb_ok else r"C:\Windows\System32\drivers\vbaudio_cable*.sys (未找到)"
    add("vbcable", "VB-Cable", vb_ok, vb_path)
    # scrcpy (手机投屏摄像头)
    scrcpy_exe = Path(rf"{_BASE}\scrcpy\scrcpy-win64-v3.1\scrcpy.exe")
    add("scrcpy", "scrcpy 手机投屏", scrcpy_exe.exists(), str(scrcpy_exe))

    all_ok = all(c["ok"] for c in checks)
    return {"ok": all_ok, "checks": checks}

def _alert_audience(key: str, source: str) -> str:
    """告警受众分流：运维/安全类(鉴权回归、自愈失败、火警演习、加固命令)→'ops'，
    仅在'系统状态'弹层对运维可见；其余面向最终用户(对话/服务可用性等)→'user'，
    才进首屏横幅。目的：避免把 harden_remote.ps1 等内部命令原文抛给主播/客户。"""
    s = (str(key or "") + " " + str(source or "")).lower()
    ops_markers = ("svc_auth", "harden", "drill", "鉴权", "裸奔", "令牌", "token", "security", "演习")
    return "ops" if any(m in s for m in ops_markers) else "user"


def _active_alerts_payload(audience: str = "user"):
    """当前活动告警 → 紧凑列表。audience='user' 只返回面向用户的(脱敏：不带内部命令)；
    'ops' 返回运维/安全类(带完整修复指引)；'all' 全返回(含 audience 字段供前端分流)。
    读 alerts 模块，失败返回 []。"""
    try:
        import alerts as _alerts
        out = []
        for k, v in _alerts.active_alerts().items():
            aud = _alert_audience(k, v.get("source", ""))
            if audience != "all" and aud != audience:
                continue
            detail = v.get("detail", "")
            if aud == "user":
                # 用户面脱敏：剥掉命令行/管道后的运维指引，只留人话
                for sep in (" | 修复:", " | 请手动", "powershell", "harden_remote"):
                    idx = detail.find(sep)
                    if idx >= 0:
                        detail = detail[:idx].rstrip(" |：:")
                        break
            out.append({
                "key": k,
                "title": v.get("title", ""),
                "detail": detail,
                "level": v.get("level", "error"),
                "source": v.get("source", ""),
                "since_str": v.get("since_str", ""),
                "audience": aud,
            })
        return out
    except Exception:
        return []


def _watchdog_status_payload():
    """看门狗运行态 → 供 UI 显性化：巡检健康/自愈统计/守护最近复活。失败返回 None。"""
    try:
        import json as _json
        from pathlib import Path as _P
        base = _P(__file__).resolve().parent
        sf = base / "logs" / "watchdog_status.json"
        if not sf.exists():
            return None
        data = _json.loads(sf.read_text(encoding="utf-8"))
        # 守护最近复活时间（从 guard 日志尾行取）
        gl = base / "logs" / "watchdog_guard.log"
        last_revive = ""
        try:
            if gl.exists():
                lines = [x for x in gl.read_text(encoding="utf-8").splitlines() if x.strip()]
                if lines:
                    last_revive = lines[-1][1:20]   # 取 "[yyyy-mm-dd HH:MM:SS"
        except Exception:
            pass
        audit = data.get("audit", {})
        heal = data.get("heal", {})
        return {
            "ts": data.get("ts", ""),
            "pid": data.get("pid", 0),
            "healthy": audit.get("healthy", True),
            "fast_mode": audit.get("fast_mode", False),
            "audit_last_ok": audit.get("last_ok", ""),
            "audit_last_fail": audit.get("last_fail", ""),
            "heal_attempts": heal.get("attempts", 0),
            "heal_successes": heal.get("successes", 0),
            "heal_failures": heal.get("failures", 0),
            "heal_consec_failures": heal.get("consec_failures", 0),
            "heal_last_success": heal.get("last_success", ""),
            "heal_last_scope": heal.get("last_scope", ""),
            "guard_last_revive": last_revive,
        }
    except Exception:
        return None


def _last_drill_payload():
    """最近一次火警演习结果（logs/drill_result.json）。失败返回 None。"""
    try:
        import json as _json
        from pathlib import Path as _P
        f = _P(__file__).resolve().parent / "logs" / "drill_result.json"
        if not f.exists():
            return None
        d = _json.loads(f.read_text(encoding="utf-8-sig"))
        return {
            "result": d.get("result", ""),
            "target": d.get("target", ""),
            "detail": d.get("detail", ""),
            "ts": d.get("ts", ""),
        }
    except Exception:
        return None


def _next_drill_payload():
    """下次演习预告：与 harden_remote.ps1 的周轮转同公式——下次运行日(周日04:00,
    AvatarHubAuthDrill)的 ISO 周号 % 目标数，目标序=cluster_map hosts 字典序展开。
    公式两边必须一致，预告才不会骗人；PS 侧已改为同款 Thursday 规则 ISO 周。"""
    try:
        import json as _json
        import datetime as _dt
        from pathlib import Path as _P
        cm = _json.loads((_P(__file__).resolve().parent / "cluster_map.json")
                         .read_text(encoding="utf-8-sig"))
        pairs = []
        for host in sorted((cm.get("hosts") or {}).keys()):
            for s in cm["hosts"][host].get("svcs") or []:
                pairs.append((host, s.get("name", "?")))
        if not pairs:
            return None
        now = _dt.datetime.now()
        days_ahead = (6 - now.weekday()) % 7          # Monday=0..Sunday=6
        run = (now + _dt.timedelta(days=days_ahead)).replace(
            hour=4, minute=0, second=0, microsecond=0)
        if run <= now:
            run += _dt.timedelta(days=7)
        week = run.date().isocalendar()[1]
        host, name = pairs[week % len(pairs)]
        return {"target": "%s/%s" % (host, name),
                "at": run.strftime("%Y-%m-%d %H:%M"), "iso_week": week}
    except Exception:
        return None


def _token_age_payload():
    """服务令牌年龄（secrets/service_token.txt 的 mtime，rotate 会重写该文件）。
    >90 天黄牌提醒轮换；文件缺失返回 None（未加固态，posture 另有告警）。"""
    try:
        import time as _t
        from pathlib import Path as _P
        f = _P(__file__).resolve().parent / "secrets" / "service_token.txt"
        if not f.exists():
            return None
        age = int((_t.time() - f.stat().st_mtime) / 86400)
        return {"age_days": age, "stale": age > 90, "stale_after_days": 90}
    except Exception:
        return None


def _topology_lint_payload():
    """最近一次拓扑一致性巡检结果（logs/topology_lint.json，由 tools/topology_lint.py
    在 harden_remote verify 全量模式里落盘；看门狗每 30min 巡检顺带刷新）。"""
    try:
        import json as _json
        from pathlib import Path as _P
        f = _P(__file__).resolve().parent / "logs" / "topology_lint.json"
        if not f.exists():
            return None
        return _json.loads(f.read_text(encoding="utf-8-sig"))
    except Exception:
        return None


def _fs_drill_payload():
    """S7: 最近一次换脸容灾演练（_logs/faceswap_drill.jsonl 末行）→ ops 看板芯片。
    与鉴权演习(last_drill)并列展示；缺账本/解析失败返回 None（前端显示"尚无记录"）。"""
    try:
        p = Path(_BASE) / "_logs" / "faceswap_drill.jsonl"
        ln = p.read_text(encoding="utf-8").strip().splitlines()[-1]
        j = json.loads(ln)
        out = {"result": "PASS" if j.get("pass") else "FAIL",
               "recover_s": j.get("recover_s"),
               "ts": time.strftime("%Y-%m-%d %H:%M", time.localtime(j.get("ts", 0)))}
        if isinstance(j.get("failover"), dict):
            out["takeover"] = f"{j['failover'].get('served', 0)}/{j['failover'].get('probed', 0)}帧"
        if isinstance(j.get("switchback"), dict):
            out["switchback_s"] = j["switchback"].get("total_s")
        return out
    except Exception:
        return None


_STT_FO_CACHE = {"ts": 0.0, "data": None}


def _stt_failover_payload():
    """S8-3: 同传 STT 单点容灾态（代理 interpreter /metrics 的 stt_failover）→ ops 看板芯片。
    带 5s 缓存，避免每次 ops 轮询都打 interpreter；interpreter 离线/未开→返回上次或 None。"""
    now = time.time()
    if _STT_FO_CACHE["data"] is not None and now - _STT_FO_CACHE["ts"] < 5.0:
        return _STT_FO_CACHE["data"]
    try:
        r = requests.get(f"{_INTERP_BASE}/metrics", timeout=1.5)
        sf = (r.json() or {}).get("stt_failover")
        _STT_FO_CACHE.update(ts=now, data=sf)
        return sf
    except Exception:
        _STT_FO_CACHE.update(ts=now)         # 记时避免离线时每轮都超时等待
        return _STT_FO_CACHE["data"]


# S9-1 单点保护全景：把散落的容灾事实(换脸副本/STT主备/池多副本/降级/远端自愈)聚成
#   一张「核心依赖→保护方式」地图，一眼看出还有哪些远端单点在裸奔。
#   刻意从**实时配置**推导(SVC_* 池长度、_fs_replica_url、interpreter 端点数)，不硬编码地址，
#   避免重蹈 2026-07-05「拓扑存两份」的漂移覆辙。degrade 列是已核实的降级事实(人读注解)。
_SP_CATALOG = [
    # key,          label,         hard,  degrade_note(降级注解),                 survives(降级能否脱离本依赖存活), heal(远端*_Boot自愈)
    ("stt",         "语音转写 STT", True,  "流式↔分段（两模式都依赖它，全宕转写停）", False, True),
    ("faceswap",    "换脸引擎",     True,  "",                                        False, True),
    ("lipsync",     "口型同步",     True,  "异常→配音/字幕（可脱离口型出画）",         True,  False),
    ("fish_tts",    "克隆音 TTS",   True,  "引擎失败→Google 兜底",                    True,  True),
    ("emotion_tts", "情感 TTS",     False, "失败→回退 Fish",                          True,  True),
    ("qwen3_tts",   "低延迟 TTS",   False, "失败→回退 Fish",                          True,  True),
    ("nemo_stt",    "流式转写",     False, "不可达→回退分段 Whisper",                 True,  True),
]


def _single_point_map():
    """核心依赖单点保护地图（配置实时推导）。grade: ok=有冗余/真降级兜底 · soft=仅远端自愈有窗口 · bare=裸单点。
    关键辨析：降级注解只有在「能脱离本依赖存活」(survives)时才算冗余——STT 的流式↔分段两模式都要 STT，
    全宕即停，故 survives=False：它只有配了主备端点(SVC_STT_FALLBACK)才真正脱离单点。"""
    import urllib.parse as _up
    sf = _stt_failover_payload() or {}
    stt_eps = sf.get("endpoints") or 0
    fs_replica = bool(_fs_replica_url())
    deps, n_bare, n_soft = [], 0, 0
    for key, label, hard, degrade, survives, heal_cap in _SP_CATALOG:
        urls = _svc_url_list(key, SERVICES.get(key, f"http://127.0.0.1:0"))
        hosts, local = [], False
        for u in urls:
            h = _up.urlparse(u).hostname or ""
            hosts.append(h)
            if h in ("127.0.0.1", "localhost", "::1", ""):
                local = True
        pool = len(urls)
        remote = not local
        prot = []
        if local:
            prot.append("本机·supervisor自愈")
        if pool > 1:
            prot.append(f"多副本池×{pool}")
        if key == "stt" and stt_eps > 1:
            prot.append(f"主备端点×{stt_eps}")
        if key == "faceswap" and fs_replica:
            prot.append("本机副本容灾")
        if degrade:
            prot.append(("降级兜底:" if survives else "降级(不脱离本依赖):") + degrade)
        if remote and heal_cap:
            prot.append("远端自愈(有窗口)")
        # 冗余 = 本机 / 多副本 / STT专属主备 / 换脸副本 / 能脱离本依赖存活的真降级
        redundant = (local or pool > 1
                     or (key == "stt" and stt_eps > 1)
                     or (key == "faceswap" and fs_replica)
                     or survives)
        soft = (not redundant) and remote and heal_cap      # 只有远端 SSH 自愈=有窗口空档
        bare = (not redundant) and (not soft)
        grade = "ok" if redundant else ("soft" if soft else "bare")
        if grade == "bare":
            n_bare += 1
        elif grade == "soft":
            n_soft += 1
        deps.append({"key": key, "label": label, "hard": hard, "hosts": hosts,
                     "local": local, "pool": pool, "protections": prot, "grade": grade})
    return {"deps": deps, "n": len(deps), "n_bare": n_bare, "n_soft": n_soft,
            "ok": n_bare == 0}


_TRAIN_MAT_CACHE = {"ts": 0.0, "data": None}


def _train_material_payload():
    """S9-2 自训素材就绪度（读 _s9_material_state.json；训练守候每次评估时刷新它）。10s 缓存。
    辨识度北极星的「料」环节：练之前先知道哪个角色料够(ready)/偏少(thin)/不足被拦(starved)。"""
    now = time.time()
    if now - _TRAIN_MAT_CACHE["ts"] < 10 and _TRAIN_MAT_CACHE["data"] is not None:
        return _TRAIN_MAT_CACHE["data"]
    data = {}
    try:
        p = Path(__file__).resolve().parent / "dfm_workspace" / "_s9_material_state.json"
        if p.is_file():
            data = json.loads(p.read_text(encoding="utf-8"))
    except Exception:
        data = {}
    _TRAIN_MAT_CACHE.update(ts=now, data=data)
    return data


def _security_panorama():
    """安全面全景：鉴权守护 + 活动告警 + 演习(上次/下次) + 令牌年龄 + 拓扑一致性。
    一处收口供 ops 看板/外部巡检。"""
    alerts_list = _active_alerts_payload("all")
    wd = _watchdog_status_payload()
    drill = _last_drill_payload()
    topo = _topology_lint_payload()
    # 总体判定：有活动告警 / 巡检不健康 / 最近演习失败 / 拓扑漂移 → not ok
    # （令牌超龄只是黄牌提醒，不翻 ok——轮换是计划动作，不是失守）
    ok = True
    if alerts_list:
        ok = False
    if wd and not wd.get("healthy", True):
        ok = False
    if drill and str(drill.get("result", "")).upper() == "FAIL":
        ok = False
    if topo and not topo.get("ok", True):
        ok = False
    return {
        "ok": ok,
        "alerts": alerts_list,
        "alerts_count": len(alerts_list),
        "watchdog": wd,
        "last_drill": drill,
        "next_drill": _next_drill_payload(),
        "faceswap_drill": _fs_drill_payload(),   # S7: 换脸容灾演练台账（周日 04:30 FaceSwap_Drill）
        "faceswap_failover": _fs_failover_view(),  # S8-2: 实时容灾态（副本接管/画质降级）
        "stt_failover": _stt_failover_payload(),   # S8-3: 同传 STT 单点容灾态（主转写节点失联→备用接管）
        "single_point_map": _single_point_map(),   # S9-1: 核心依赖单点保护地图（裸单点一眼可见）
        "train_material": _train_material_payload(),  # S9-2: 自训素材就绪度（辨识度闭环的「料」环节）
        "token": _token_age_payload(),
        "topology": topo,
        # 一键轮换进行态/上次结果（内存态，hub 重启即清——轮换本身幂等，可放心重试）
        "rotate": {"running": _ROTATE_STATE["running"], "result": _ROTATE_STATE["result"],
                   "detail": _ROTATE_STATE["detail"], "ended_at": _ROTATE_STATE["ended_at"]},
    }


# ── WebSocket：实时状态推送 ───────────────────────────────────────
@app.websocket("/ws/status")
async def ws_status(ws: WebSocket):
    if not _ws_auth_ok(ws):                     # 控制面遥测(服务/角色名册/告警)——非回环且无令牌拒握手
        await ws.close(code=1008)
        return
    await ws.accept()
    ws_clients.add(ws)
    # 立即推送当前状态（P5-1: run_in_executor防止init阶段阻塞事件循环）
    svc = await asyncio.get_running_loop().run_in_executor(None, check_services_cached)
    await ws.send_json({
        "event": "init",
        "active_profile":   _active_profile,
        "profiles":         list(_profiles.keys()),
        "profiles_version": _profiles_version,
        "services": svc,
        "broadcast": _compute_broadcast(svc),
        "stream_health": _stream_health_now(),
        "alerts": _active_alerts_payload("all"),
        "watchdog": _watchdog_status_payload(),
    })
    try:
        while True:
            await asyncio.sleep(5)
            # run_in_executor 防止 check_services 阻塞事件循环（P5-1: 用cached版减少重复调用）
            svc = await asyncio.get_running_loop().run_in_executor(None, check_services_cached)
            perf = _get_perf_metrics()
            # P8-3: 发送心跳也加超时，慢/僵死客户端不阻塞心跳循环
            try:
                await asyncio.wait_for(ws.send_json({
                    "event":            "heartbeat",
                    "services":         svc,
                    "broadcast":        _compute_broadcast(svc),
                    "stream_health":    _stream_health_now(),
                    "active_profile":   _active_profile,
                    "profiles_version": _profiles_version,
                    "perf":             perf,
                    "ws_count":         len(ws_clients),
                    "alerts":           _active_alerts_payload("all"),
                    "watchdog":         _watchdog_status_payload(),
                }), timeout=5.0)
            except asyncio.TimeoutError:
                _logger.debug("[WS] 心跳发送超时，主动断开僵死客户端")
                break
    except WebSocketDisconnect:
        pass
    finally:
        ws_clients.discard(ws)

