# ── 拼音检索索引（后端单一真源；供 home / ui 侧栏 / 命令面板 / 移动端复用）──────────────
# 优先 pypinyin（装了即自动覆盖任意新增汉字，零改代码）；未装则用内置目录字表（多音字按语境取音）。
try:
    from pypinyin import lazy_pinyin as _lazy_pinyin, Style as _py_style   # 可选依赖，缺失回退内置表
    def _han_syllables(s):
        return [x for x in _lazy_pinyin(s or "", style=_py_style.NORMAL, errors="ignore") if x and x[0].isalpha()]
    _PY_ENGINE = "pypinyin"
except Exception:
    _PY_MAP = {
        "角": "jiao", "色": "se", "库": "ku", "声": "sheng", "音": "yin", "克": "ke", "隆": "long",
        "语": "yu", "合": "he", "成": "cheng", "唱": "chang", "歌": "ge", "批": "pi", "量": "liang", "配": "pei",
        "实": "shi", "时": "shi", "对": "dui", "话": "hua", "测": "ce", "试": "shi", "台": "tai",
        "开": "kai", "播": "bo", "中": "zhong", "枢": "shu", "同": "tong", "传": "chuan",
        "数": "shu", "据": "ju", "看": "kan", "板": "ban", "运": "yun", "维": "wei", "监": "jian", "控": "kong",
        "历": "li", "史": "shi", "记": "ji", "录": "lu", "交": "jiao", "付": "fu", "体": "ti", "检": "jian",
        "日": "ri", "志": "zhi", "设": "she", "置": "zhi", "白": "bai", "标": "biao", "内": "nei", "容": "rong",
        "验": "yan", "真": "zhen", "知": "zhi", "识": "shi", "问": "wen", "答": "da", "首": "shou", "启": "qi",
        "向": "xiang", "导": "dao", "直": "zhi", "营": "ying", "规": "gui", "可": "ke", "信": "xin",
    }
    def _han_syllables(s):
        return [_PY_MAP[c] for c in (s or "") if c in _PY_MAP]
    _PY_ENGINE = "builtin"


def _py_fields(text):
    """→ (全拼, 首字母)：仅取汉字音节；字母/数字/·/空格自然跳过。"""
    syl = _han_syllables(text)
    return "".join(syl), "".join(s[0] for s in syl if s)


def _augment_registry_pinyin():
    """加载时为每项预计算 pysearch（名称+产品线的全拼&首字母），前端一次并入 data-search 即可。
    内置表下若遇未覆盖汉字则告警一次——把"字表漂移"从静默变可见（装 pypinyin 则永不触发）。"""
    missing = set()
    for f in FEATURE_REGISTRY:
        nf, ni = _py_fields(f.get("name", ""))
        lf, li = _py_fields(f.get("line", ""))
        f["pysearch"] = " ".join(x for x in (nf, ni, lf, li) if x)
        if _PY_ENGINE == "builtin":
            for c in (f.get("name", "") + f.get("line", "")):
                if "\u4e00" <= c <= "\u9fff" and c not in _PY_MAP:
                    missing.add(c)
    if missing:
        try:
            print(f"[Hub] 拼音字表未覆盖 {len(missing)} 字：{''.join(sorted(missing))}"
                  f"（新增功能请补 _PY_MAP，或 pip install pypinyin 自动覆盖）")
        except Exception:
            pass


_augment_registry_pinyin()


