# ── 免提对话：流式语义打断桥接（WS /api/converse/listen）─────────────────────
# 设计见「开发文档_首页功能入口统一与技术升级_v1.md」P0-2。
# 前端契约（static/phone.html / converse.html，不改前端）：连接 ?session_id=&language=；
#   上行二进制 PCM16/16k/mono；上行文本 {event:'reset'}（清窗口）/{event:'close'}；
#   下行期望 {barge_in:true}（AI 说话时用户真开口→立即打断）。仅在前端选 Nemotron 流式 STT 时启用。
# 本端职责：把麦克风音频桥接到 Nemotron 流式 STT(/ws/transcribe)，命中非空 partial 即回 {barge_in}；
#   上游不可达 → 立即关闭，前端 onclose 置空 → 自动回退能量打断（零体验倒退，符合"优雅降级"铁律）。
@app.websocket("/api/converse/listen")
async def converse_listen(ws: WebSocket):
    await ws.accept()
    language = ws.query_params.get("language", "zh")
    base = _svc_url("nemo_stt", "http://127.0.0.1:7857").rstrip("/")   # SVC_NEMO_STT 可覆盖
    # 探活：上游不可达即关闭，让前端回退能量打断（避免"假就绪"吞掉打断）
    try:
        async with httpx.AsyncClient(timeout=1.5) as _c:
            r = await _c.get(base + "/health")
            if r.status_code != 200:
                raise RuntimeError(f"nemo_stt health {r.status_code}")
    except Exception:
        try:
            await ws.close()
        except Exception:
            pass
        return
    ws_uri = (("ws" + base[4:]) if base.startswith("http") else base) + f"/ws/transcribe?language={language}"
    headers = {}
    try:
        import app_config as _ac
        _tok = _ac.service_token()
        if _tok:
            headers["X-AH-Svc"] = _tok          # 多机部署需令牌；本机回环免令牌
    except Exception:
        pass

    import websockets
    try:
        try:
            up = await websockets.connect(ws_uri, max_size=None, ping_interval=20, additional_headers=headers)
        except TypeError:   # 旧版 websockets 形参名不同
            up = await websockets.connect(ws_uri, max_size=None, ping_interval=20, extra_headers=headers)
    except Exception as e:
        _logger.warning(f"[listen] 连接 Nemotron 失败({e})，前端将回退能量打断")
        try:
            await ws.close()
        except Exception:
            pass
        return

    barged = {"v": False}   # 每个 reset 窗口至多打断一次（防抖动/重复触发）

    async def _client_to_up():
        while True:
            msg = await ws.receive()
            if msg.get("type") == "websocket.disconnect":
                break
            b = msg.get("bytes")
            if b:
                await up.send(b)               # 透传 PCM16/16k/mono
                continue
            t = msg.get("text")
            if t:
                try:
                    evt = json.loads(t).get("event", "")
                except Exception:
                    evt = (t or "").strip()
                if evt == "reset":
                    barged["v"] = False
                    try:
                        await up.send(json.dumps({"event": "reset"}))
                    except Exception:
                        pass
                elif evt == "close":
                    break

    async def _up_to_client():
        async for raw in up:
            if not isinstance(raw, str):
                continue
            try:
                m = json.loads(raw)
            except Exception:
                continue
            txt = (m.get("partial") or m.get("final") or "").strip()
            if txt and not barged["v"]:        # 命中真实语音（非空假设）→ 语义打断
                barged["v"] = True
                await ws.send_text(json.dumps({"barge_in": True}))

    t1 = asyncio.create_task(_client_to_up())
    t2 = asyncio.create_task(_up_to_client())
    try:
        _done, pending = await asyncio.wait({t1, t2}, return_when=asyncio.FIRST_COMPLETED)
        for p in pending:
            p.cancel()
    except Exception as e:
        _logger.warning(f"[listen] 桥接异常: {e}")
    finally:
        try:
            await up.close()
        except Exception:
            pass
        try:
            await ws.close()
        except Exception:
            pass


