@app.get("/help", response_class=HTMLResponse)
def help_center(doc: str = ""):
    """图文教程中心（白标随 brand.css/brand.js 联动）。doc 为空=目录；否则按白名单把对应 .md 渲染成网页。"""
    nav = "".join(
        f'<a href="/help?doc={k}"{" class=cur" if k == doc else ""}>{t}</a>'
        for k, (fn, t) in _HELP_DOCS.items())
    home_cur = "" if doc in _HELP_DOCS else " class=cur"
    if doc in _HELP_DOCS:
        fn, title = _HELP_DOCS[doc]
        p = Path(_BASE) / fn
        raw = p.read_text(encoding="utf-8") if p.exists() else f"# 未找到教程文件：{fn}"
        try:
            import markdown as _md
            body = _md.markdown(raw, extensions=["tables", "fenced_code", "sane_lists"])
        except Exception:
            import html as _h
            body = "<pre>" + _h.escape(raw) + "</pre>"
        try:
            upd = time.strftime("%Y-%m-%d", time.localtime(p.stat().st_mtime)) if p.exists() else "—"
        except Exception:
            upd = "—"
        foot = f"源文件：<code>{fn}</code> · 最后更新：{upd} · 本页内容随产品更新，以本页为准。"
    else:
        title = "使用教程"
        cards = "".join(
            f'<a class="hcard" href="/help?doc={k}"><b>{t}</b><span>{fn}</span></a>'
            for k, (fn, t) in _HELP_DOCS.items())
        body = ('<h1>📖 使用教程</h1><p>装机、日常使用、手机同传扫码授权——选一份开始。</p>'
                f'<div class="cards">{cards}</div>')
        foot = "本教程中心把仓库内图文文档渲染为网页，随产品更新。"
    html = (_HELP_TMPL.replace("__TITLE__", title).replace("__NAV__", nav)
            .replace("__HOMECUR__", home_cur).replace("__BODY__", body).replace("__FOOT__", foot))
    return HTMLResponse(html,
                        headers={"Cache-Control": "no-store, no-cache, must-revalidate", "Pragma": "no-cache"})

