# M3-A: 分享落地页（扫码/链接访客的拉新入口；打开即播一句克隆音 + "我也做一个"）
_LANDING_FILE = Path(rf"{_BASE}\static\landing.html")

@app.get("/s", response_class=HTMLResponse)
def share_landing(request: Request, profile: str = ""):
    if not _LANDING_FILE.exists():
        return HTMLResponse(content='<h1>static/landing.html not found</h1>', status_code=404)
    html = _LANDING_FILE.read_text(encoding='utf-8')
    # M3-②：服务端注入 og/twitter meta（爬虫不执行 JS，必须 SSR）
    name = (profile or "").strip()
    p = _profiles.get(name)
    if p:
        import html as _h
        import urllib.parse
        origin = str(request.base_url).rstrip("/")
        enc = urllib.parse.quote(name)
        title = _h.escape(f"{name} · 听我说一句")
        desc = _h.escape(p.get("description") or "真人音色克隆，点开听 TA 说一句")
        cover = f"{origin}/api/share/cover?profile={enc}"
        url = f"{origin}/s?profile={enc}"
        meta = (
            f'<meta property="og:type" content="website"/>'
            f'<meta property="og:title" content="{title}"/>'
            f'<meta property="og:description" content="{desc}"/>'
            f'<meta property="og:image" content="{cover}"/>'
            f'<meta property="og:url" content="{url}"/>'
            f'<meta name="twitter:card" content="summary_large_image"/>'
            f'<meta name="twitter:title" content="{title}"/>'
            f'<meta name="twitter:description" content="{desc}"/>'
            f'<meta name="twitter:image" content="{cover}"/>'
        )
        html = html.replace("<!--OG_META-->", meta)
    else:
        # ⑮：站点级 OG（无 profile 橱窗页），封面用金标角色代表
        import html as _h, urllib.parse
        origin = str(request.base_url).rstrip("/")
        best = max(_profiles.items(),
                   key=lambda kv: (kv[1].get("quality_axes") or {}).get("cosine", 0),
                   default=(None, None))
        site_title = "AvatarHub · 真人音色克隆橱窗"
        site_desc  = "多个真人音色克隆，点开听 TA 说一句，以假乱真"
        if best[0]:
            enc_best = urllib.parse.quote(best[0])
            cover_url = f"{origin}/api/share/cover?profile={enc_best}"
        else:
            cover_url = ""
        meta = (
            f'<meta property="og:type" content="website"/>'
            f'<meta property="og:title" content="{_h.escape(site_title)}"/>'
            f'<meta property="og:description" content="{_h.escape(site_desc)}"/>'
            + (f'<meta property="og:image" content="{cover_url}"/>' if cover_url else '')
            + f'<meta property="og:url" content="{origin}/s"/>'
            f'<meta name="twitter:card" content="summary_large_image"/>'
            f'<meta name="twitter:title" content="{_h.escape(site_title)}"/>'
            f'<meta name="twitter:description" content="{_h.escape(site_desc)}"/>'
            + (f'<meta name="twitter:image" content="{cover_url}"/>' if cover_url else '')
        )
        html = html.replace("<!--OG_META-->", meta)
    return HTMLResponse(content=html,
                        headers={"Cache-Control": "no-store, no-cache, must-revalidate", "Pragma": "no-cache"})


