@app.post("/api/order/create")
async def order_create(request: Request):
    """创建订单（落盘 secrets/orders_web.jsonl，供客服核对到账后签发 license）。
    不接触链上——收款确认仍人工/半自动，最小可用即可（沿用兑换码交付模型）。"""
    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"ok": False, "error": "invalid json"}, status_code=400)
    plan = str(body.get("plan", "")).strip()
    contact = str(body.get("contact", "")).strip()
    if not plan or not contact:
        return JSONResponse({"ok": False, "error": "缺少 plan / contact"}, status_code=400)
    import time as _t
    import random as _r
    oid = _t.strftime("BL%y%m%d") + "-" + ("%04d" % _r.randint(0, 9999))
    rec = {"order_id": oid, "ts": _t.time(),
           "plan": plan, "edition": str(body.get("edition", "")),
           "period": str(body.get("period", "")), "amount": body.get("amount"),
           "currency": str(body.get("currency", "USDT")),
           "contact": contact, "fingerprint": str(body.get("fingerprint", "")),
           "status": "pending", "ip": (request.client.host if request.client else "")}
    try:
        _PRICING_FILE.parent.mkdir(parents=True, exist_ok=True)
        with open(_PRICING_FILE.parent / "orders_web.jsonl", "a", encoding="utf-8") as f:
            f.write(json.dumps(rec, ensure_ascii=False) + "\n")
    except Exception as e:
        _logger.warning(f"[order] 订单落盘失败：{e}")
    return {"ok": True, "order_id": oid, "status": "pending"}


