# ── 性能指标缓存（避免频繁调用 nvidia-smi）────────────────────────
_perf_cache: dict = {}
_perf_cache_ts: float = 0.0
_PERF_TTL = 4.0  # 秒

def _get_perf_metrics() -> dict:
    global _perf_cache, _perf_cache_ts
    now = time.time()
    if now - _perf_cache_ts < _PERF_TTL:
        return _perf_cache
    metrics = {"gpu_util": -1, "gpu_mem_used": -1, "gpu_mem_total": -1,
               "ram_percent": -1, "streaming": False, "rvc_running": False}
    try:
        r = _subprocess.run(
            ["nvidia-smi", "--query-gpu=utilization.gpu,memory.used,memory.total",
             "--format=csv,noheader,nounits"],
            capture_output=True, text=True, timeout=3,
            creationflags=getattr(_subprocess, "CREATE_NO_WINDOW", 0))
        if r.returncode == 0:
            parts = [x.strip() for x in r.stdout.strip().split(",")]
            if len(parts) >= 3:
                metrics["gpu_util"] = int(parts[0])
                metrics["gpu_mem_used"] = int(parts[1])
                metrics["gpu_mem_total"] = int(parts[2])
    except Exception:
        pass
    try:
        import psutil as _ps
        metrics["ram_percent"] = _ps.virtual_memory().percent
    except Exception:
        pass
    metrics["streaming"] = bool(_realtime_proc and _realtime_proc.poll() is None)
    metrics["rvc_running"] = bool(_rvc_proc and _rvc_proc.poll() is None)
    # 读取 realtime_stream.py 写入的 FPS 状态文件
    _fps_file = Path(rf"{_BASE}\realtime_status.json")
    if _fps_file.exists() and metrics["streaming"]:
        try:
            fps_data = json.loads(_fps_file.read_text(encoding="utf-8"))
            # 超过 10s 未更新视为失效
            if now - fps_data.get("ts", 0) < 10:
                metrics["fps"] = fps_data.get("fps", 0)
                metrics["swap_ok"] = fps_data.get("swap_ok", 0)
        except Exception:
            pass
    _perf_cache = metrics
    _perf_cache_ts = now
    return metrics


def _perf_cache_bust():
    """使 GPU 指标缓存失效，下次 _get_perf_metrics 强制重读 nvidia-smi。"""
    global _perf_cache_ts
    _perf_cache_ts = 0.0


def _vram_pressure() -> dict:
    """显存水位 → 背压等级。high=逼近 OOM，med=偏紧，low=宽裕，unknown=无 nvidia-smi。"""
    m = _get_perf_metrics()
    used, total = m.get("gpu_mem_used", -1), m.get("gpu_mem_total", -1)
    if used < 0 or total <= 0:
        return {"level": "unknown", "ratio": -1.0, "free_mb": -1}
    ratio = used / total
    free = total - used
    if ratio >= 0.92 or free < 1500:
        level = "high"
    elif ratio >= 0.80 or free < 3000:
        level = "med"
    else:
        level = "low"
    return {"level": level, "ratio": round(ratio, 3), "free_mb": int(free),
            "used_mb": int(used), "total_mb": int(total)}


def _synthesis_plan(requested_n: int) -> dict:
    """L4-2 背压：据显存水位决定 best_of 候选数与并发度，单卡防 OOM。
    high → 串行且候选≤2；med → 并发2；low/unknown → 放开。"""
    p = _vram_pressure()
    lv = p["level"]
    free = p.get("free_mb", -1)
    if lv == "high":
        # 显存极紧(<1.5G)：单卡上即便串行，多候选 + 评分模型也可能压垮，退回单次
        if 0 <= free < 1500:
            return {"n": 1, "concurrency": 1, "pressure": lv,
                    "reason": f"显存极紧(空闲{free}MB)→单次合成防OOM", "vram": p}
        n = max(1, min(requested_n, 2))
        return {"n": n, "concurrency": 1, "pressure": lv,
                "reason": f"显存吃紧(空闲{free}MB)→串行防OOM", "vram": p}
    if lv == "med":
        return {"n": requested_n, "concurrency": min(requested_n, 2), "pressure": lv,
                "reason": "显存偏紧→并发限2", "vram": p}
    return {"n": requested_n, "concurrency": requested_n, "pressure": lv,
            "reason": "", "vram": p}


async def _gather_bounded(coro_factories, concurrency: int):
    """以受限并发执行一组 0 参协程工厂，返回结果列表（保持顺序）。"""
    sem = asyncio.Semaphore(max(1, concurrency))

    async def _run(factory):
        async with sem:
            return await factory()

    return await asyncio.gather(*[_run(f) for f in coro_factories])


