# ── P2-9 声音克隆+伦理保护 ────────────────────────────────────────
class VoiceCloneRequest(BaseModel):
    wav_base64:   str
    name:         str            # 克隆后的声音名称
    agreed_terms: bool = False   # 必须勾选合规声明
    user_id:      str  = "local"


@app.post("/api/voice_clone")
def api_voice_clone(req: VoiceCloneRequest):
    """
    声音克隆：WAV录音 → 质量检测 → 声纹检测 → 水印 → 保存参考音频
    agreed_terms=true 表示用户同意'我拥有该声音的合法使用权'
    """
    try:
        import voice_clone as _vc
        result = _vc.clone_voice(
            wav_b64=req.wav_base64, name=req.name,
            agreed_terms=req.agreed_terms, user_id=req.user_id,
        )
        _metrics["clone_total"] += 1
        if not result["ok"]:
            _metrics["clone_rejected"] += 1
            raise HTTPException(400, result["reason"])
        _track_event("huansheng", "huansheng.voice.clone_completed", {   # P4：音色资产可用
            "voice_id": Path(result.get("voice_file", "")).stem or req.name,
            "sample_seconds": round(float(result.get("quality", {}).get("duration_sec") or 0), 2)})
        return result
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(500, str(e))


@app.post("/api/voice_clone/verify_watermark")
def api_verify_watermark(req: dict):
    """验证音频是否含AvatarHub水印"""
    try:
        import voice_clone as _vc
        wav_bytes = base64.b64decode(req.get("wav_base64", ""))
        return _vc.verify_watermark(wav_bytes)
    except Exception as e:
        raise HTTPException(400, str(e))


@app.post("/api/voice_clone/check_quality")
def api_check_quality(req: dict):
    """仅检测音频质量（不执行克隆）"""
    try:
        import voice_clone as _vc
        wav_bytes = base64.b64decode(req.get("wav_base64", ""))
        return _vc.check_audio_quality(wav_bytes)
    except Exception as e:
        raise HTTPException(400, str(e))


# ── P20-5: /api/config 热重载 ────────────────────────────────────────
HUB_CONFIG_FILE = Path(rf"{_BASE}\hub_config.json")
_CONFIGURABLE_KEYS = set(SERVICES.keys())  # 允许通过 PATCH 修改的 key

def _load_hub_config():
    """启动时从 hub_config.json 覆盖 SERVICES 默认值"""
    if HUB_CONFIG_FILE.exists():
        try:
            cfg = json.loads(HUB_CONFIG_FILE.read_text(encoding="utf-8"))
            for k, v in cfg.items():
                if k in _CONFIGURABLE_KEYS and isinstance(v, str):
                    SERVICES[k] = v
            _logger.info(f"[config] 加载 hub_config.json: {cfg}")
        except Exception as e:
            _logger.warning(f"[config] 加载失败: {e}")

_load_hub_config()  # 启动时立即执行

@app.get("/api/config")
def get_config():
    """P20-5: 获取当前可热重载的服务 URL 配置"""
    return {"ok": True, "services": dict(SERVICES), "config_file": str(HUB_CONFIG_FILE)}

class ConfigPatchRequest(BaseModel):
    key:   str
    value: str

@app.patch("/api/config")
def patch_config(req: ConfigPatchRequest):
    """P20-5: 热更新服务 URL（无需重启），持久化到 hub_config.json"""
    if req.key not in _CONFIGURABLE_KEYS:
        raise HTTPException(400, f"key '{req.key}' 不可配置，允许: {sorted(_CONFIGURABLE_KEYS)}")
    if not req.value.startswith(("http://", "https://")):
        raise HTTPException(400, "value 必须是 http:// 或 https:// 开头的 URL")
    old = SERVICES[req.key]
    SERVICES[req.key] = req.value
    # 持久化
    cfg = {}
    if HUB_CONFIG_FILE.exists():
        try: cfg = json.loads(HUB_CONFIG_FILE.read_text(encoding="utf-8"))
        except: pass
    cfg[req.key] = req.value
    HUB_CONFIG_FILE.write_text(json.dumps(cfg, ensure_ascii=False, indent=2), encoding="utf-8")
    _logger.info(f"[config] {req.key}: {old} → {req.value}")
    return {"ok": True, "key": req.key, "old": old, "new": req.value}


# ── Phase 4: 智能情感检测端点 ────────────────────────────────────────
@app.get("/api/emotion_detect")
def api_emotion_detect(text: str, detail: bool = False):
    """
    Phase 4: 文本情感自动检测。
    ?text=你好世界  →  {"emotion":"happy","confidence":0.5,...}
    ?text=...&detail=true  →  返回各情感得分
    """
    try:
        from emotion_detector import detect_emotion as _det, detect_emotion_detail as _det_d
        if detail:
            return _det_d(text)
        return {"emotion": _det(text), "text": text}
    except Exception as e:
        raise HTTPException(500, f"emotion_detector error: {e}")


# ── P2-8 手机端遥控 ───────────────────────────────────────────────
import secrets as _secrets

_mobile_tokens: dict = {}   # token -> {created_at, expires_at}
MOBILE_TOKEN_TTL = 6 * 3600  # 6小时有效


def _new_mobile_token() -> str:
    token = _secrets.token_urlsafe(24)
    now   = time.time()
    _mobile_tokens[token] = {"created_at": now, "expires_at": now + MOBILE_TOKEN_TTL}
    # 清理过期token
    expired = [t for t, v in _mobile_tokens.items() if v["expires_at"] < now]
    for t in expired:
        del _mobile_tokens[t]
    return token


def _check_mobile_token(token: str) -> bool:
    v = _mobile_tokens.get(token)
    if not v:
        return False
    if time.time() > v["expires_at"]:
        del _mobile_tokens[token]
        return False
    return True


# Token 速率限制：同 IP 每分钟最多 5 次
_token_rate: dict = {}   # ip -> [timestamp, ...]

def _check_token_rate(ip: str, max_per_min: int = 5) -> bool:
    now   = time.time()
    times = [t for t in _token_rate.get(ip, []) if now - t < 60]
    _token_rate[ip] = times
    if len(times) >= max_per_min:
        return False
    _token_rate[ip].append(now)
    return True


@app.post("/mobile/token")
def mobile_gen_token(request: Request):
    """生成手机遥控Token（含二维码）。同IP每分钟限5次。"""
    client_ip = request.client.host if request.client else "unknown"
    if not _check_token_rate(client_ip):
        raise HTTPException(429, "请求过于频繁，请稍后再试")
    try:
        import socket
        hostname = socket.gethostname()
        local_ip = socket.gethostbyname(hostname)
    except Exception:
        local_ip = "127.0.0.1"

    token    = _new_mobile_token()
    base_url = f"http://{local_ip}:{PORT}"
    ctrl_url = f"{base_url}/mobile/ui?token={token}"

    # 生成二维码
    qr_b64 = ""
    try:
        import qrcode, io as _io
        img = qrcode.make(ctrl_url)
        buf = _io.BytesIO()
        img.save(buf, format="PNG")
        qr_b64 = base64.b64encode(buf.getvalue()).decode()
    except ImportError:
        pass   # qrcode 未安装，仅返回URL

    return {
        "ok":        True,
        "token":     token,
        "ctrl_url":  ctrl_url,
        "local_ip":  local_ip,
        "expires_in": MOBILE_TOKEN_TTL,
        "qr_base64": qr_b64,
    }


