@app.get("/mobile/qr")
def mobile_qr():
    """返回当前有效的二维码（用于UI展示）"""
    valid = {t: v for t, v in _mobile_tokens.items() if v["expires_at"] > time.time()}
    if not valid:
        return {"ok": False, "detail": "无有效Token，请先 POST /mobile/token"}
    token = max(valid, key=lambda t: valid[t]["created_at"])
    try:
        import socket
        local_ip = socket.gethostbyname(socket.gethostname())
    except Exception:
        local_ip = "127.0.0.1"
    ctrl_url = f"http://{local_ip}:{PORT}/mobile/ui?token={token}"
    qr_b64   = ""
    try:
        import qrcode, io as _io
        buf = _io.BytesIO()
        qrcode.make(ctrl_url).save(buf, format="PNG")
        qr_b64 = base64.b64encode(buf.getvalue()).decode()
    except ImportError:
        pass
    return {"ok": True, "ctrl_url": ctrl_url, "qr_base64": qr_b64,
            "expires_at": valid[token]["expires_at"]}


def _log_boot_provenance():
    """启动溯源(2026-07-06p 发现C)：hub 一天内被 4 个主体重启过(用户关窗/守护拉活/部署/验证脚本)，
    排障全靠猜。开机记一行「谁拉起的我」——父进程 pid+命令行。后台线程查,不拖启动。"""
    def _q():
        try:
            ppid = os.getppid()
            r = _subprocess.run(
                ["powershell", "-NoProfile", "-Command",
                 f"(Get-CimInstance Win32_Process -Filter 'ProcessId={ppid}' | "
                 "Select-Object -First 1 Name,CommandLine | ForEach-Object { $_.Name + ' :: ' + $_.CommandLine })"],
                capture_output=True, text=True, timeout=10,
                creationflags=getattr(_subprocess, "CREATE_NO_WINDOW", 0))
            parent = (r.stdout or "").strip() or "(已退出/未知)"
        except Exception as e:
            parent = f"(查询失败:{e})"
        _logger.info(f"[Boot] pid={os.getpid()} ppid={os.getppid()} 由谁拉起 → {parent}")
        print(f"[Boot] pid={os.getpid()} ppid={os.getppid()} parent → {parent}", flush=True)
        # P12 补强：boot 记录落专用 JSONL——经 start_avatar_hub.bat 等直启时 stdout 不进
        # hub_console.log，[Boot] 溯源会丢(2026-07-06 19:37 实证)。专用账页不依赖启动方式，
        # stability_report 以它为主源、控制台解析为兜底。
        try:
            with open(Path(_BASE) / "logs" / "hub_boots.jsonl", "a", encoding="utf-8") as f:
                f.write(json.dumps({"ts": time.time(), "pid": os.getpid(),
                                    "ppid": os.getppid(), "parent": parent[:160]},
                                   ensure_ascii=False) + "\n")
        except Exception as e:
            _logger.warning(f"[Boot] 溯源账页写入失败: {e}")
    threading.Thread(target=_q, daemon=True).start()


if __name__ == "__main__":
    # 双开预检(06o)：uvicorn 默认 SO_REUSEADDR,Windows 下第二个 hub 会静默双绑 9000 → 请求串线。
    # 旧实例在跑则 fail-fast 退出(TIME_WAIT 不误伤,实证 tools/_tw_bind_probe.py)。
    import port_guard
    port_guard.ensure_port_free(PORT, "avatar_hub", host=_BIND_HOST)
    _log_boot_provenance()
    if _SECRETS_HEALED:   # 06y：裸启(未经 env_config 链)时密钥自愈，只记名不记值
        _logger.info(f"[Boot] secrets 自愈补齐环境变量: {_SECRETS_HEALED}（启动链未注入，已从 secrets.bat 兜底）")
        print(f"[Boot] secrets 自愈: {_SECRETS_HEALED}", flush=True)
